pub fn ensureLocalsCapacity(ctx: *core.Context, frame: *frame_mod.Frame, idx: usize) !void {
    if (idx < frame.locals.len and idx < frame.locals_uninit.len) return;
    const next_len = @max(idx + 1, @max(frame.locals.len, frame.locals_uninit.len));

    const next_locals = try ctx.runtime.memory.alloc(core.Value, next_len);
    errdefer ctx.runtime.memory.free(core.Value, next_locals);
    const next_uninit = try ctx.runtime.memory.alloc(bool, next_len);
    errdefer ctx.runtime.memory.free(bool, next_uninit);

    for (frame.locals, 0..) |value, i| next_locals[i] = value;
    if (next_len > frame.locals.len) @memset(next_locals[frame.locals.len..next_len], core.Value.undefinedValue());
    for (frame.locals_uninit, 0..) |value, i| next_uninit[i] = value;
    if (next_len > frame.locals_uninit.len) @memset(next_uninit[frame.locals_uninit.len..next_len], false);

    const old_locals = frame.locals;
    const old_locals_uninit = frame.locals_uninit;
    frame.locals = next_locals;
    frame.locals_uninit = next_uninit;
    if (old_locals.len != 0) ctx.runtime.memory.free(core.Value, old_locals);
    if (old_locals_uninit.len != 0) ctx.runtime.memory.free(bool, old_locals_uninit);
}

pub fn ensureVarRefsCapacity(ctx: *core.Context, frame: *frame_mod.Frame, idx: usize) !void {
    if (idx < frame.var_refs.len) return;
    const next_len = idx + 1;
    const next = try ctx.runtime.memory.alloc(core.Value, next_len);
    errdefer ctx.runtime.memory.free(core.Value, next);
    for (frame.var_refs, 0..) |value, i| next[i] = value;
    @memset(next[frame.var_refs.len..next_len], core.Value.undefinedValue());
    const old_var_refs = frame.var_refs;
    frame.var_refs = next;
    if (old_var_refs.len != 0) ctx.runtime.memory.free(core.Value, old_var_refs);
}

test "ensureLocalsCapacity OOM preserves existing frame buffers" {
    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
    const rt = try core.Runtime.create(failing.allocator());
    const ctx = try core.Context.create(rt);

    var function = bytecode.Bytecode.init(&rt.memory, &rt.atoms, core.atom.ids.empty_string);
    var frame = frame_mod.Frame.init(&function);
    frame.locals = try rt.memory.alloc(core.Value, 1);
    frame.locals[0] = core.Value.int32(7);
    frame.locals_uninit = try rt.memory.alloc(bool, 1);
    frame.locals_uninit[0] = true;
    frame.locals_uninit_count = 1;

    const original_locals = frame.locals;
    const original_uninit = frame.locals_uninit;
    defer {
        if (frame.locals.ptr != original_locals.ptr) frame.locals = &.{};
        frame.deinit(&rt.memory, rt);
        function.deinit(rt);
        ctx.destroy();
        rt.destroy();
    }

    failing.fail_index = failing.alloc_index + 1;
    try std.testing.expectError(error.OutOfMemory, ensureLocalsCapacity(ctx, &frame, 1));
    failing.fail_index = std.math.maxInt(usize);

    try std.testing.expect(frame.locals.ptr == original_locals.ptr);
    try std.testing.expectEqual(@as(usize, 1), frame.locals.len);
    try std.testing.expectEqual(@as(?i32, 7), frame.locals[0].asInt32());
    try std.testing.expect(frame.locals_uninit.ptr == original_uninit.ptr);
    try std.testing.expectEqual(@as(usize, 1), frame.locals_uninit.len);
    try std.testing.expect(frame.localIsUninitialized(0));
}

pub fn catchTargetFromMarker(marker: core.Value) ?usize {
    const previous = marker.asCatchOffset() orelse -1;
    if (previous < 0) return null;
    return @intCast(previous);
}

pub fn popCatchMarker(rt: *core.Runtime, stack: *stack_mod.Stack) !??usize {
    while (stack.peek()) |marker| {
        defer marker.free(rt);
        if (marker.isCatchOffset() and stack.values.len >= 3) {
            const maybe_next = stack.values[stack.values.len - 2];
            const maybe_iterator = stack.values[stack.values.len - 3];
            if (isCallableValue(maybe_next) and isIteratorLikeValue(rt, maybe_iterator)) {
                const record_marker = try stack.pop();
                record_marker.free(rt);
                const next_method = try stack.pop();
                next_method.free(rt);
                const iterator_value = try stack.pop();
                iterator_value.free(rt);
                continue;
            }
        }
        const popped = try stack.pop();
        if (marker.isCatchOffset()) return catchTargetFromMarker(popped);
        popped.free(rt);
    }
    return null;
}

pub fn saveGeneratorExecutionState(
    ctx: *core.Context,
    stack: *stack_mod.Stack,
    frame: *frame_mod.Frame,
    generator: *core.Object,
    pc: usize,
) void {
    generator.generatorPcSlot().* = pc;
    const old_stack = generator.generatorStack();
    const old_stack_capacity = generator.generatorStackCapacity();
    const old_frame_locals = generator.generatorFrameLocals();
    const old_frame_args = generator.generatorFrameArgs();
    const old_frame_var_refs = generator.generatorFrameVarRefs();
    const old_frame_locals_uninit = generator.generatorFrameLocalsUninit();
    generator.generatorStackSlot().* = stack.values;
    generator.generatorStackCapacitySlot().* = stack.capacity;
    generator.generatorFrameLocalsSlot().* = frame.locals;
    generator.generatorFrameArgsSlot().* = frame.args;
    generator.generatorFrameVarRefsSlot().* = frame.var_refs;
    generator.generatorFrameLocalsUninitSlot().* = frame.locals_uninit;
    stack.values = &.{};
    stack.capacity = 0;
    frame.locals = &.{};
    frame.args = &.{};
    frame.var_refs = &.{};
    frame.locals_uninit = &.{};
    frame.locals_uninit_count = 0;

    for (old_stack) |stored| stored.free(ctx.runtime);
    if (old_stack_capacity != 0) {
        ctx.runtime.memory.free(core.Value, old_stack.ptr[0..old_stack_capacity]);
    } else if (old_stack.len != 0) {
        ctx.runtime.memory.free(core.Value, old_stack);
    }
    freeValueSlice(ctx.runtime, old_frame_locals);
    freeValueSlice(ctx.runtime, old_frame_args);
    freeValueSlice(ctx.runtime, old_frame_var_refs);
    if (old_frame_locals_uninit.len != 0) ctx.runtime.memory.free(bool, old_frame_locals_uninit);
}

pub fn createForInIterator(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object_value: core.Value,
) !core.Value {
    const rt = ctx.runtime;
    if (try createSimpleForInIterator(rt, object_value)) |simple| return simple;

    var iterator_val = core.Value.undefinedValue();
    var source_val = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &iterator_val },
        .{ .value = &source_val },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;
    defer source_val.free(rt);

    const iterator = try core.Object.create(rt, core.class.ids.for_in_iterator, null);
    errdefer core.Object.destroyFromHeader(rt, &iterator.header);
    iterator_val = iterator.value();

    var out_index: u32 = 0;

    if (!object_value.isNull() and !object_value.isUndefined()) {
        source_val = if (object_value.isObject()) object_value.dup() else try primitiveObjectForAccess(rt, global, object_value);
        var seen: []core.Atom = &.{};
        defer freeAtomList(rt, seen);
        var current: ?*core.Object = try property_ops.expectObject(source_val);
        const root = current;
        while (current) |object| {
            if (root != null and object == root.? and builtins.buffer.isTypedArrayObject(object)) {
                const length = builtins.buffer.typedArrayLength(rt, object) catch 0;
                var index: u32 = 0;
                while (index < length) : (index += 1) {
                    const key = core.atom.atomFromUInt32(index);
                    try appendAtom(rt, &seen, key);
                    const key_value = try rt.atoms.toStringValue(rt, key);
                    defer key_value.free(rt);
                    try iterator.defineOwnProperty(rt, core.atom.atomFromUInt32(out_index), core.Descriptor.data(key_value, true, true, true));
                    out_index += 1;
                }
            }
            const keys = try objectRestOwnKeys(ctx, output, global, object);
            defer core.Object.freeKeys(rt, keys);

            for (keys) |key| {
                if (rt.atoms.kind(key) == .symbol) continue;
                if (atomListContains(seen, key)) continue;
                try appendAtom(rt, &seen, key);
                if (object.moduleNamespaceOwnBindingValue(key)) |binding_value| {
                    defer binding_value.free(rt);
                    if (binding_value.isUninitialized()) return error.ReferenceError;
                }
                const desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, object, key, null, null) orelse continue;
                defer desc.destroy(rt);
                if (!(desc.enumerable orelse false)) continue;
                const key_value = try rt.atoms.toStringValue(rt, key);
                defer key_value.free(rt);
                try iterator.defineOwnProperty(rt, core.atom.atomFromUInt32(out_index), core.Descriptor.data(key_value, true, true, true));
                out_index += 1;
            }

            current = try qjsObjectGetPrototypeOfStep(ctx, output, global, object, null, null);
        }

        const source_key = try rt.internAtom("__source");
        defer rt.atoms.free(source_key);
        try iterator.defineOwnProperty(rt, source_key, core.Descriptor.data(source_val, true, false, true));
    }
    iterator.length = out_index;

    const index_key = try rt.internAtom("__index");
    defer rt.atoms.free(index_key);
    try iterator.defineOwnProperty(rt, index_key, core.Descriptor.data(core.Value.int32(0), true, true, true));
    return iterator.value();
}

fn createSimpleForInIterator(rt: *core.Runtime, object_value: core.Value) !?core.Value {
    if (object_value.isNull() or object_value.isUndefined()) return null;
    if (!object_value.isObject()) return null;
    const source = objectFromValue(object_value) orelse return null;
    if (!simpleForInRootCanUseFastPath(rt, source)) return null;

    const iterator = try core.Object.create(rt, core.class.ids.for_in_iterator, null);
    errdefer core.Object.destroyFromHeader(rt, &iterator.header);
    var out_index: u32 = 0;
    for (source.properties) |entry| {
        if (entry.flags.deleted or !entry.flags.enumerable) continue;
        if (rt.atoms.kind(entry.atom_id) != .string) continue;
        const key_value = try rt.atoms.toStringValue(rt, entry.atom_id);
        defer key_value.free(rt);
        try iterator.defineOwnProperty(rt, core.atom.atomFromUInt32(out_index), core.Descriptor.data(key_value, true, true, true));
        out_index += 1;
    }
    iterator.length = out_index;

    iterator.iteratorKindSlot().* = iter_vm.simple_for_in_iterator_kind;
    iterator.iteratorIndexSlot().* = 0;
    iterator.iteratorTargetSlot().* = object_value.dup();
    return iterator.value();
}

fn simpleForInRootCanUseFastPath(rt: *core.Runtime, source: *core.Object) bool {
    if (source.class_id != core.class.ids.object or source.is_proxy or source.exotic != null or source.is_array) return false;
    if (builtins.buffer.isTypedArrayObject(source)) return false;
    if (source.arrayElements().len != 0) return false;
    for (source.properties) |entry| {
        if (entry.flags.deleted) continue;
        if (core.array.arrayIndexFromAtom(&rt.atoms, entry.atom_id) != null) return false;
        const kind = rt.atoms.kind(entry.atom_id);
        if (kind != .string and kind != .symbol and kind != .private) return false;
    }

    var proto = source.getPrototype();
    while (proto) |object| : (proto = object.getPrototype()) {
        if (object.is_proxy or object.exotic != null) return false;
        if (builtins.buffer.isTypedArrayObject(object)) return false;
        if (object.arrayElements().len != 0) return false;
        for (object.properties) |entry| {
            if (entry.flags.deleted or !entry.flags.enumerable) continue;
            if (rt.atoms.kind(entry.atom_id) == .symbol or rt.atoms.kind(entry.atom_id) == .private) continue;
            return false;
        }
    }
    return true;
}

pub fn atomListContains(list: []const core.Atom, needle: core.Atom) bool {
    for (list) |atom_id| {
        if (atom_id == needle) return true;
    }
    return false;
}

pub fn appendAtom(rt: *core.Runtime, list: *[]core.Atom, atom_id: core.Atom) !void {
    const next = try rt.memory.alloc(core.Atom, list.len + 1);
    errdefer rt.memory.free(core.Atom, next);
    @memcpy(next[0..list.len], list.*);
    next[list.len] = rt.atoms.dup(atom_id);
    const old = list.*;
    list.* = next;
    if (old.len != 0) rt.memory.free(core.Atom, old);
}

pub fn freeAtomList(rt: *core.Runtime, list: []core.Atom) void {
    for (list) |atom_id| rt.atoms.free(atom_id);
    if (list.len != 0) rt.memory.free(core.Atom, list);
}

pub fn findForOfIteratorIndex(rt: *core.Runtime, stack: *const stack_mod.Stack) !usize {
    var index = stack.values.len;
    while (index > 0) {
        index -= 1;
        const value = stack.values[index];
        if (isIteratorLikeValue(rt, value)) return index;
    }
    return error.StackUnderflow;
}

pub fn isIteratorLikeValue(rt: *core.Runtime, value: core.Value) bool {
    const object = property_ops.expectObject(value) catch return false;
    if (object.cachedIteratorNext() != null) return true;
    const next_key = rt.internAtom("next") catch return false;
    defer rt.atoms.free(next_key);
    const next_value = object.getProperty(next_key);
    defer next_value.free(rt);
    return isCallableValue(next_value);
}

pub fn closeStackTopForOfIteratorForPendingError(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *const stack_mod.Stack,
) !void {
    return closeStackTopForOfIteratorForPendingErrorInternal(ctx, output, global, stack, null);
}

pub fn closeStackTopForOfIteratorForPendingErrorWithFrame(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *const stack_mod.Stack,
    frame: *const frame_mod.Frame,
) !void {
    return closeStackTopForOfIteratorForPendingErrorInternal(ctx, output, global, stack, frame);
}

fn closeStackTopForOfIteratorForPendingErrorInternal(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *const stack_mod.Stack,
    frame: ?*const frame_mod.Frame,
) !void {
    const record_index = findTopClosableForOfRecordIndex(stack) orelse return;
    const iterator_value = stack.values[record_index].dup();
    defer iterator_value.free(ctx.runtime);
    if (property_ops.expectObject(iterator_value)) |object| {
        if (isDestructuringIteratorState(object)) return;
    } else |_| {}
    if (frame) |active_frame| {
        if (activeDestructuringStateTargetsIterator(stack.values, active_frame, iterator_value)) return;
    }

    const pending_exception = if (ctx.hasException()) ctx.takeException() else null;
    defer if (pending_exception) |value| value.free(ctx.runtime);
    closeIteratorFromVm(ctx, output, global, iterator_value) catch {};
    if (ctx.hasException()) ctx.clearException();
    if (pending_exception) |value| _ = ctx.throwValue(value.dup());
}

fn findTopClosableForOfRecordIndex(stack: *const stack_mod.Stack) ?usize {
    if (stack.values.len < 3) return null;
    var index = stack.values.len - 3;
    while (true) {
        if (isForOfRecordAt(stack, index) and !hasCatchMarkerAboveForOfRecord(stack, index)) {
            return index;
        }
        if (index == 0) break;
        index -= 1;
    }
    return null;
}

fn isForOfRecordAt(stack: *const stack_mod.Stack, index: usize) bool {
    if (index + 2 >= stack.values.len) return false;
    return stack.values[index].isObject() and
        isCallableValue(stack.values[index + 1]) and
        stack.values[index + 2].isCatchOffset();
}

fn hasCatchMarkerAboveForOfRecord(stack: *const stack_mod.Stack, record_index: usize) bool {
    var index = record_index + 3;
    while (index < stack.values.len) : (index += 1) {
        if (stack.values[index].isCatchOffset()) return true;
    }
    return false;
}

fn activeDestructuringStateTargetsIterator(
    stack_values: []const core.Value,
    frame: *const frame_mod.Frame,
    iterator_value: core.Value,
) bool {
    return destructuringStateTargetsIteratorInValues(stack_values, iterator_value) or
        destructuringStateTargetsIteratorInValues(frame.locals, iterator_value) or
        destructuringStateTargetsIteratorInValues(frame.args, iterator_value) or
        destructuringStateTargetsIteratorInValues(frame.var_refs, iterator_value);
}

fn destructuringStateTargetsIteratorInValues(values: []const core.Value, iterator_value: core.Value) bool {
    for (values) |value| {
        const object = property_ops.expectObject(value) catch continue;
        if (!isDestructuringIteratorState(object)) continue;
        const target = (object.iteratorTargetSlot().*) orelse continue;
        if (sameObjectIdentity(target, iterator_value)) return true;
    }
    return false;
}

pub fn closeForAwaitIteratorForPendingError(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *const stack_mod.Stack,
) !void {
    const index = findForOfIteratorIndex(ctx.runtime, stack) catch return;
    const iterator_value = stack.values[index].dup();
    defer iterator_value.free(ctx.runtime);
    _ = property_ops.expectObject(iterator_value) catch return;

    const pending_exception = if (ctx.hasException()) ctx.takeException() else null;
    defer if (pending_exception) |value| value.free(ctx.runtime);
    closeIteratorFromVm(ctx, output, global, iterator_value) catch {};
    if (ctx.hasException()) ctx.clearException();
    if (pending_exception) |value| _ = ctx.throwValue(value.dup());
}

pub fn objectPrototypeFromGlobal(rt: *core.Runtime, global: *core.Object) ?*core.Object {
    return constructorPrototypeFromGlobalAtom(rt, global, core.atom.ids.Object);
}

pub fn constructorPrototypeFromGlobal(rt: *core.Runtime, global: *core.Object, constructor_name: []const u8) ?*core.Object {
    const ctor_key = rt.internAtom(constructor_name) catch return null;
    defer rt.atoms.free(ctor_key);
    return constructorPrototypeFromGlobalAtom(rt, global, ctor_key);
}

pub fn constructorPrototypeFromGlobalAtom(rt: *core.Runtime, global: *core.Object, constructor_atom: core.Atom) ?*core.Object {
    if (global.getOwnDataObjectBorrowed(constructor_atom)) |constructor| {
        if (constructor.getOwnDataObjectBorrowed(core.atom.ids.prototype)) |prototype| return prototype;
    }
    const constructor_value = global.getProperty(constructor_atom);
    defer constructor_value.free(rt);
    const object_constructor = property_ops.expectObject(constructor_value) catch return null;
    if (object_constructor.getOwnDataObjectBorrowed(core.atom.ids.prototype)) |prototype| return prototype;
    const prototype_value = object_constructor.getProperty(core.atom.ids.prototype);
    defer prototype_value.free(rt);
    return property_ops.expectObject(prototype_value) catch null;
}

pub fn arrayPrototypeFromGlobal(rt: *core.Runtime, global: *core.Object) ?*core.Object {
    if (global.getOwnDataObjectBorrowed(core.atom.ids.Array)) |constructor| {
        if (constructor.getOwnDataObjectBorrowed(core.atom.ids.prototype)) |prototype| return prototype;
    }
    const array_value = global.getProperty(core.atom.ids.Array);
    defer array_value.free(rt);
    const array_constructor = property_ops.expectObject(array_value) catch return null;
    if (array_constructor.getOwnDataObjectBorrowed(core.atom.ids.prototype)) |prototype| return prototype;
    const prototype_value = array_constructor.getProperty(core.atom.ids.prototype);
    defer prototype_value.free(rt);
    return property_ops.expectObject(prototype_value) catch null;
}

pub fn functionPrototypeFromGlobal(rt: *core.Runtime, global: *core.Object) ?*core.Object {
    if (global.getOwnDataObjectBorrowed(core.atom.ids.Function)) |constructor| {
        if (constructor.getOwnDataObjectBorrowed(core.atom.ids.prototype)) |prototype| return prototype;
    }
    const function_value = global.getProperty(core.atom.ids.Function);
    defer function_value.free(rt);
    const function_constructor = property_ops.expectObject(function_value) catch return null;
    if (function_constructor.getOwnDataObjectBorrowed(core.atom.ids.prototype)) |prototype| return prototype;
    const prototype_value = function_constructor.getProperty(core.atom.ids.prototype);
    defer prototype_value.free(rt);
    return property_ops.expectObject(prototype_value) catch null;
}

pub fn functionConstructorFromGlobal(rt: *core.Runtime, global: *core.Object) ?*core.Object {
    if (global.getOwnDataObjectBorrowed(core.atom.ids.Function)) |constructor| return constructor;
    const function_value = global.getProperty(core.atom.ids.Function);
    defer function_value.free(rt);
    return property_ops.expectObject(function_value) catch null;
}

fn cachedRealmObject(global: *core.Object, slot: core.object.RealmValueSlot) ?*core.Object {
    const stored = global.cachedRealmValue(slot) orelse return null;
    return property_ops.expectObject(stored) catch null;
}

fn storeRealmValue(rt: *core.Runtime, global: *core.Object, slot: core.object.RealmValueSlot, value: core.Value) !void {
    const cached = try global.cachedRealmValueSlot(rt, slot);
    const next_value = value.dup();
    const old_value = cached.*;
    cached.* = next_value;
    if (old_value) |stored| stored.free(rt);
}

pub fn promisePrototypeFromGlobal(rt: *core.Runtime, global: *core.Object) ?*core.Object {
    if (global.cachedPromiseProto()) |prototype| return prototype;
    const promise_atom = rt.internAtom("Promise") catch return null;
    defer rt.atoms.free(promise_atom);
    const promise_value = global.getProperty(promise_atom);
    defer promise_value.free(rt);
    const promise_constructor = property_ops.expectObject(promise_value) catch return null;
    const prototype_value = promise_constructor.getProperty(core.atom.ids.prototype);
