        defer bigint.deinit();
        return value_ops.createBigIntValue(rt, bigint);
    }
    return error.TypeError;
}

pub fn qjsGlobalIsNaNOrFinite(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
