            if (is_nan) return core.Value.boolean(value.isNumber() and std.math.isNan(number orelse std.math.nan(f64)));
            return core.Value.boolean(value.isNumber() and std.math.isFinite(number orelse std.math.nan(f64)));
        }
    }
    const input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const primitive = try toPrimitiveForNumber(ctx, output, global, input);
    defer primitive.free(ctx.runtime);
    if (primitive.isSymbol() or primitive.isBigInt()) return error.TypeError;
    const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
    defer number_value.free(ctx.runtime);
    const number = value_ops.numberValue(number_value) orelse std.math.nan(f64);
    return core.Value.boolean(if (is_nan) std.math.isNan(number) else std.math.isFinite(number));
}

pub fn qjsStringConcat(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) {
        return throwTypeErrorMessage(ctx, global, "null or undefined are forbidden");
    }

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(ctx.runtime.memory.allocator);

    const receiver_string = try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer receiver_string.free(ctx.runtime);
    try value_ops.appendRawString(ctx.runtime, &bytes, receiver_string);

    for (args) |arg| {
        const arg_string = try toStringForAnnexB(ctx, output, global, arg, caller_function, caller_frame);
        defer arg_string.free(ctx.runtime);
        try value_ops.appendRawString(ctx.runtime, &bytes, arg_string);
    }

    return value_ops.createStringValue(ctx.runtime, bytes.items);
}

pub fn qjsStringReplace(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) {
        return throwTypeErrorMessage(ctx, global, "null or undefined are forbidden");
    }
    const search_input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const replacement_input = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    if (try qjsStringReplaceFastRegExp(ctx, output, global, this_value, search_input, replacement_input, caller_function, caller_frame)) |value| return value;
    if (try callStringReplaceMethod(ctx, output, global, this_value, search_input, replacement_input, caller_function, caller_frame)) |value| return value;

    const source_value = try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer source_value.free(ctx.runtime);
    const search_value = try toStringForAnnexB(ctx, output, global, search_input, caller_function, caller_frame);
    defer search_value.free(ctx.runtime);

    var source_units = std.ArrayList(u16).empty;
    defer source_units.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &source_units, source_value);

    var search_units = std.ArrayList(u16).empty;
    defer search_units.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &search_units, search_value);

    const functional_replace = isCallableValue(replacement_input);
    const replacement_text = if (functional_replace)
        core.Value.undefinedValue()
    else
        try toStringForAnnexB(ctx, output, global, replacement_input, caller_function, caller_frame);
    defer if (!functional_replace) replacement_text.free(ctx.runtime);

    const match_index = std.mem.indexOf(u16, source_units.items, search_units.items) orelse
        return source_value.dup();
    const replacement_value = if (functional_replace) blk: {
        break :blk try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), replacement_input, &.{ search_value, core.Value.int32(@intCast(match_index)), source_value }, caller_function, caller_frame);
    } else replacement_text;
    defer if (functional_replace) replacement_value.free(ctx.runtime);

    const replacement_string = try toStringForAnnexB(ctx, output, global, replacement_value, caller_function, caller_frame);
    defer replacement_string.free(ctx.runtime);

    const replacement = if (functional_replace) replacement_string else blk: {
        const match = ReplaceMatch{
            .result = core.Value.undefinedValue(),
            .matched = search_value,
            .index = match_index,
            .captures = &.{},
            .groups = core.Value.undefinedValue(),
        };
        break :blk try getSubstitutionString(ctx, output, global, match, source_value, replacement_string, caller_function, caller_frame);
    };
    defer if (!functional_replace) replacement.free(ctx.runtime);

    var out = std.ArrayList(u16).empty;
    defer out.deinit(ctx.runtime.memory.allocator);
    try out.appendSlice(ctx.runtime.memory.allocator, source_units.items[0..match_index]);
    try appendStringValueUnits(ctx.runtime, &out, replacement);
    try out.appendSlice(ctx.runtime.memory.allocator, source_units.items[match_index + search_units.items.len ..]);
    return (try core.string.String.createUtf16(ctx.runtime, out.items)).value();
}

pub fn qjsStringReplaceFastRegExp(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    search_value: core.Value,
    replace_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (isCallableValue(replace_value)) return null;
    const regexp_object = objectFromValue(search_value) orelse return null;
    if (regexp_object.class_id != core.class.ids.regexp) return null;
    const replace_atom = core.atom.predefinedId("Symbol.replace", .symbol) orelse return null;
    if (regexp_object.hasOwnProperty(replace_atom)) return null;

    if (regexpInternalFlagsContain(regexp_object, 'g')) {
        if (regexpInternalSimpleQuantifiedClassSource(regexp_object)) |fast_source| {
            try setRegExpLastIndexZero(ctx.runtime, regexp_object);
            const string_value = if (this_value.isString())
                this_value.dup()
            else
                try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
            defer string_value.free(ctx.runtime);
            const replacement_string = if (replace_value.isString())
                replace_value.dup()
            else
                try toStringForAnnexB(ctx, output, global, replace_value, caller_function, caller_frame);
            defer replacement_string.free(ctx.runtime);
            if (replaceSingleUnitGlobalSimpleClassEscape(string_value, replacement_string, fast_source)) |fast| return fast;
            return try replaceGlobalSimpleClassEscape(ctx.runtime, string_value, replacement_string, fast_source);
        }
    }

    var flags = std.ArrayList(u8).empty;
    defer flags.deinit(ctx.runtime.memory.allocator);
    if (!try appendRegExpFlags(ctx.runtime, regexp_object, &flags)) return null;
    if (std.mem.indexOfScalar(u8, flags.items, 'g') == null) return null;

    var source = std.ArrayList(u8).empty;
    defer source.deinit(ctx.runtime.memory.allocator);
    if (!try appendRegExpSource(ctx.runtime, regexp_object, &source)) return null;
    if (!classEscapeIsQuantified(source.items) or !isSimpleStringClassEscapeSource(source.items)) return null;

    try setRegExpLastIndexZero(ctx.runtime, regexp_object);
    const string_value = if (this_value.isString())
        this_value.dup()
    else
        try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);
    const replacement_string = if (replace_value.isString())
        replace_value.dup()
    else
        try toStringForAnnexB(ctx, output, global, replace_value, caller_function, caller_frame);
    defer replacement_string.free(ctx.runtime);
    if (replaceSingleUnitGlobalSimpleClassEscape(string_value, replacement_string, source.items)) |fast| return fast;
    return try replaceGlobalSimpleClassEscape(ctx.runtime, string_value, replacement_string, source.items);
}

pub fn callStringReplaceMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    search_value: core.Value,
    replace_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!search_value.isObject()) return null;
    const replace_atom = core.atom.predefinedId("Symbol.replace", .symbol) orelse return error.TypeError;
    const replacer = try getValueProperty(ctx, output, global, search_value, replace_atom, caller_function, caller_frame);
    defer replacer.free(ctx.runtime);
    if (replacer.isUndefined() or replacer.isNull()) return null;
    if (!isCallableValue(replacer)) return error.TypeError;
    const replace_args = [_]core.Value{ this_value, replace_value };
    return try callValueOrBytecode(ctx, output, global, search_value, replacer, &replace_args, caller_function, caller_frame);
}

pub fn isArrayMethodReceiver(value: core.Value) bool {
    const object = objectFromValue(value) orelse return false;
    return object.is_array;
}

pub fn valueTruthy(value: core.Value) bool {
    return value_ops.isTruthy(value);
}

/// Shared helper for `get_loc` / `get_loc8` / `get_loc0..3`. `consume`
/// is the operand byte width (0 for short, 1 for u8, 2 for u16); the
/// caller has already decoded the index, so we only need to advance pc.
pub fn execGetLoc(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
) !void {
    frame.pc += consume;
    _ = ctx;
    _ = opc;
    if (idx >= frame.locals.len) return error.InvalidBytecode;
    try pushSlotValue(stack, frame.locals[idx]);
}

pub fn execPutLoc(
    ctx: *core.Context,
    function: *const bytecode.Bytecode,
    global: *core.Object,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
    sync_global_lexical_locals: bool,
) !void {
    frame.pc += consume;
    _ = opc;
    if (idx >= frame.locals.len) return error.InvalidBytecode;
    const value = try stack.pop();
    setSlotValue(ctx, &frame.locals[idx], value);
    if (idx < frame.locals_uninit.len and idx < function.var_is_lexical.len and function.var_is_lexical[idx]) {
        frame.clearLocalUninitialized(idx);
    }
    try syncTopLevelGlobalLexicalLocal(ctx, function, global, frame, idx, sync_global_lexical_locals);
}

pub fn execSetLoc(
    ctx: *core.Context,
    function: *const bytecode.Bytecode,
    global: *core.Object,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
    sync_global_lexical_locals: bool,
) !void {
    frame.pc += consume;
    _ = opc;
    if (idx >= frame.locals.len) return error.InvalidBytecode;
    const value = stack.peek() orelse return error.StackUnderflow;
    defer value.free(ctx.runtime);
    setSlotValue(ctx, &frame.locals[idx], value.dup());
    if (idx < frame.locals_uninit.len and idx < function.var_is_lexical.len and function.var_is_lexical[idx]) {
        frame.clearLocalUninitialized(idx);
    }
    try syncTopLevelGlobalLexicalLocal(ctx, function, global, frame, idx, sync_global_lexical_locals);
}

pub fn syncTopLevelGlobalLexicalLocal(
    ctx: *core.Context,
    function: *const bytecode.Bytecode,
    global: *core.Object,
    frame: *frame_mod.Frame,
    idx: usize,
    enabled: bool,
) !void {
    if (!enabled) return;
    if (!try ensureGlobalLexicalSyncSlots(ctx, function, global, frame)) return;
    if (idx >= frame.global_lexical_sync_slots.len or !frame.global_lexical_sync_slots[idx]) return;
    const atom_id = function.var_names[idx];
    if (idx < frame.global_lexical_sync_indices.len) {
        const property_index = frame.global_lexical_sync_indices[idx];
        if (property_index != frame_mod.no_global_lexical_sync_index) {
            const env = frame.global_lexical_sync_env orelse existingGlobalLexicalEnv(ctx.runtime, global) orelse return;
            if (env.setOwnDataPropertyAtForLexicalSync(ctx.runtime, property_index, atom_id, slotValueBorrow(frame.locals[idx]))) return;
        }
    }
    const value = slotValueDup(frame.locals[idx]);
    defer value.free(ctx.runtime);
    _ = try setGlobalLexicalValue(ctx.runtime, global, atom_id, value);
}

fn ensureGlobalLexicalSyncSlots(
    ctx: *core.Context,
    function: *const bytecode.Bytecode,
    global: *core.Object,
    frame: *frame_mod.Frame,
) !bool {
    if (frame.global_lexical_sync_checked) return frame.global_lexical_sync_slots.len != 0;
    const env = existingGlobalLexicalEnv(ctx.runtime, global) orelse return false;
    frame.global_lexical_sync_env = env;
    const count = @min(function.var_names.len, function.var_is_lexical.len);
    if (count == 0) {
        frame.global_lexical_sync_checked = true;
        return false;
    }
    const slots = try ctx.runtime.memory.alloc(bool, count);
    errdefer ctx.runtime.memory.free(bool, slots);
    @memset(slots, false);
    const indices = try ctx.runtime.memory.alloc(usize, count);
    errdefer ctx.runtime.memory.free(usize, indices);
    @memset(indices, frame_mod.no_global_lexical_sync_index);
    var has_sync_slot = false;
    for (function.var_names[0..count], 0..) |atom_id, idx| {
        if (!function.var_is_lexical[idx]) continue;
        if (!env.hasOwnProperty(atom_id)) continue;
        if (env.getOwnDataPropertyLookup(atom_id)) |lookup| {
            indices[idx] = lookup.index;
            lookup.value.free(ctx.runtime);
        }
        var duplicate_prior = false;
        var prior_idx: usize = 0;
        while (prior_idx < idx) : (prior_idx += 1) {
            if (atomIdOrNameEql(ctx.runtime, function.var_names[prior_idx], atom_id)) {
                duplicate_prior = true;
                break;
            }
        }
        if (duplicate_prior) continue;
        slots[idx] = true;
        has_sync_slot = true;
    }
    frame.global_lexical_sync_checked = true;
    if (!has_sync_slot) {
        ctx.runtime.memory.free(bool, slots);
        ctx.runtime.memory.free(usize, indices);
        return false;
    }
    frame.global_lexical_sync_slots = slots;
    frame.global_lexical_sync_indices = indices;
    return true;
}

pub fn execGetArg(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
) !void {
    frame.pc += consume;
    _ = ctx;
    _ = opc;
    if (idx >= frame.args.len) {
        try stack.pushOwned(core.Value.undefinedValue());
        return;
    }
    try pushSlotValue(stack, frame.args[idx]);
}

pub fn execPutArg(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
) !void {
    frame.pc += consume;
    _ = opc;
    if (idx >= frame.args.len) return error.InvalidBytecode;
    const value = try stack.pop();
    setSlotValue(ctx, &frame.args[idx], value);
}

pub fn execSetArg(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
) !void {
    frame.pc += consume;
    _ = opc;
    if (idx >= frame.args.len) return error.InvalidBytecode;
    const value = stack.peek() orelse return error.StackUnderflow;
    defer value.free(ctx.runtime);
    setSlotValue(ctx, &frame.args[idx], value.dup());
}

pub fn execGetVarRef(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
) !void {
    frame.pc += consume;
    _ = opc;
    if (idx >= frame.var_refs.len) try ensureVarRefsCapacity(ctx, frame, idx);
    try pushSlotValue(stack, frame.var_refs[idx]);
}

pub fn execGetVarRefMaybeTdz(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    catch_target: *?usize,
    global: *core.Object,
) !bool {
    frame.pc += consume;
    if (idx >= frame.var_refs.len) try ensureVarRefsCapacity(ctx, frame, idx);
    const slot = frame.var_refs[idx];
    if (varRefCellFromValue(slot)) |cell| {
        if (cell.varRefIsDeletedSlot().*) {
            if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, error.ReferenceError)) {
                return true;
            }
            return error.ReferenceError;
        }
        const value = slotValueBorrow(slot);
        if (value.isUninitialized()) {
            const err = throwTdzReference(ctx);
            if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, err)) {
                return true;
            }
            return err;
        }
        try stack.push(value);
        return false;
    }
    if (slot.isUninitialized()) {
        const err = throwTdzReference(ctx);
        if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, err)) {
            return true;
        }
        return err;
    }
    try stack.push(slot);
    return false;
}

pub fn execPutVarRef(
    ctx: *core.Context,
    function: *const bytecode.Bytecode,
    global: *core.Object,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
    eval_global_var_bindings: bool,
    is_eval_code: bool,
) !void {
    frame.pc += consume;
    if (idx >= frame.var_refs.len) try ensureVarRefsCapacity(ctx, frame, idx);
    const value = try stack.pop();
    const slot = frame.var_refs[idx];
    if (varRefCellFromValue(slot)) |cell| {
        if (opc == op.put_var_ref_check_init) {
            const current = cell.varRefValueSlot().* orelse core.Value.undefinedValue();
            if (!current.isUninitialized()) {
                value.free(ctx.runtime);
                return error.ReferenceError;
            }
        }
        if (opc == op.put_var_ref_check) {
            const current = cell.varRefValueSlot().* orelse core.Value.undefinedValue();
            if (current.isUninitialized()) {
                value.free(ctx.runtime);
                return throwTdzReference(ctx);
            }
        }
        if (cell.varRefIsFunctionNameSlot().*) {
            value.free(ctx.runtime);
            if (function.flags.is_strict) return error.TypeError;
            return;
        }
        if (cell.varRefIsConstSlot().* and !constVarRefWriteAllowed(cell, opc)) {
            value.free(ctx.runtime);
            _ = throwTypeErrorMessage(ctx, global, "invalid assignment to const variable") catch |err| return err;
            return error.TypeError;
        }
        try publishTopLevelFunctionVarRef(ctx.runtime, function, global, frame, idx, value, eval_global_var_bindings, is_eval_code);
        var assigned = value;
        if (varRefCellFromValue(value) != null) {
            assigned = slotValueDup(value);
            value.free(ctx.runtime);
        }
        cell.varRefIsDeletedSlot().* = false;
        const old_value = cell.varRefValueSlot().*;
        cell.varRefValueSlot().* = assigned;
        if (old_value) |stored| stored.free(ctx.runtime);
        return;
    }
    if (opc == op.put_var_ref_check_init and !slot.isUninitialized()) {
        value.free(ctx.runtime);
        return error.ReferenceError;
    }
    if (opc == op.put_var_ref_check and slot.isUninitialized()) {
        value.free(ctx.runtime);
        return throwTdzReference(ctx);
    }
    if (opc == op.put_var_ref_check and idx < function.var_ref_names.len) {
        const atom_id = function.var_ref_names[idx];
        if (globalLexicalHas(ctx.runtime, global, atom_id)) {
            _ = setGlobalLexicalValue(ctx.runtime, global, atom_id, value) catch |err| {
                value.free(ctx.runtime);
                return err;
            };
            return;
        }
    }
    if (opc == op.put_var_ref_check and idx < function.var_ref_is_const.len and function.var_ref_is_const[idx]) {
        value.free(ctx.runtime);
        _ = throwTypeErrorMessage(ctx, global, "invalid assignment to const variable") catch |err| return err;
        return error.TypeError;
    }
    try publishTopLevelFunctionVarRef(ctx.runtime, function, global, frame, idx, value, eval_global_var_bindings, is_eval_code);
    setSlotValue(ctx, &frame.var_refs[idx], value);
}

fn isVarRefInitOpcode(opc: u8) bool {
    return opc == op.put_var_ref or
        opc == op.put_var_ref_check_init or
        opc == op.put_var_ref0 or
        opc == op.put_var_ref1 or
        opc == op.put_var_ref2 or
        opc == op.put_var_ref3;
}

fn constVarRefWriteAllowed(cell: *core.Object, opc: u8) bool {
    _ = cell;
    return isVarRefInitOpcode(opc);
}

pub fn publishTopLevelFunctionVarRef(
    rt: *core.Runtime,
    function: *const bytecode.Bytecode,
    global: *core.Object,
    frame: *frame_mod.Frame,
    idx: u16,
    value: core.Value,
    eval_global_var_bindings: bool,
    is_eval_code: bool,
) !void {
    if (idx >= function.var_ref_names.len) return;
    if (!value.isObject()) return;
    if (function.flags.is_module) return;
    if (is_eval_code and !eval_global_var_bindings) return;
    if (!sameObjectIdentity(frame.this_value, global.value())) return;
    const object = property_ops.expectObject(value) catch return;
    if (!isFunctionLikeClass(object.class_id)) return;
    try defineGlobalFunctionBindingValue(rt, global, function.var_ref_names[idx], value, is_eval_code);
}

pub fn defineGlobalFunctionBindingValue(
    rt: *core.Runtime,
    global: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    configurable: bool,
) !void {
    const desc = if (global.getOwnProperty(atom_id)) |current| blk: {
        defer current.destroy(rt);
        if (current.configurable == true) {
            break :blk core.Descriptor.data(value, true, true, configurable);
        }
        break :blk core.Descriptor{
            .kind = .data,
            .value = value,
            .value_present = true,
        };
    } else core.Descriptor.data(value, true, true, configurable);

    global.defineOwnProperty(rt, atom_id, desc) catch |err| switch (err) {
        error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
        else => return err,
    };
}

pub fn execSetVarRef(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    idx: u16,
    consume: u8,
    opc: u8,
) !void {
    frame.pc += consume;
    if (idx >= frame.var_refs.len) try ensureVarRefsCapacity(ctx, frame, idx);
    _ = opc;
    const value = stack.peek() orelse return error.StackUnderflow;
    defer value.free(ctx.runtime);
    setSlotValue(ctx, &frame.var_refs[idx], value.dup());
}

pub fn pushSlotValue(stack: *stack_mod.Stack, slot: core.Value) !void {
    if (!slot.requiresRefCount()) return stack.pushOwned(slot);
    try stack.push(slotValueBorrow(slot));
}

pub fn slotValueDup(slot: core.Value) core.Value {
    return slotValueBorrow(slot).dup();
}

pub fn slotValueBorrow(slot: core.Value) core.Value {
    var current = slot;
    var depth: usize = 0;
    while (depth < 16) : (depth += 1) {
        const cell = varRefCellFromValue(current) orelse return current;
        current = cell.varRefValueSlot().* orelse return core.Value.undefinedValue();
    }
    return current;
}

pub fn varRefSlotIsUninitialized(slot: core.Value) bool {
    return slotValueBorrow(slot).tag == core.Tag.uninitialized;
}

pub fn varRefSlotIsDeleted(slot: core.Value) bool {
    const cell = varRefCellFromValue(slot) orelse return false;
    return cell.varRefIsDeletedSlot().*;
}

pub fn evalLocalSlotIsEvalVarCell(slot: core.Value) bool {
    const cell = varRefCellFromValue(slot) orelse return false;
    return cell.varRefIsDeletableSlot().*;
}

pub fn setSlotValue(ctx: *core.Context, slot: *core.Value, value: core.Value) void {
    if (!slot.requiresRefCount() and !value.requiresRefCount()) {
        slot.* = value;
        return;
    }
    var assigned = value;
    if (varRefCellFromValue(value) != null) {
        assigned = slotValueDup(value);
        value.free(ctx.runtime);
    }
    if (varRefCellFromValue(slot.*)) |cell| {
        cell.varRefIsDeletedSlot().* = false;
        if (cell.varRefValueSlot().*) |stored| {
            cell.varRefValueSlot().* = null;
            stored.free(ctx.runtime);
        }
        cell.varRefValueSlot().* = assigned;
        return;
    }
    const old_value = slot.*;
    slot.* = assigned;
    old_value.free(ctx.runtime);
}

fn derivedConstructorThisLocalSlot(frame: *frame_mod.Frame) ?*core.Value {
    if (!frame.function.flags.is_derived_class_constructor) return null;
    for (frame.function.var_names, 0..) |name, idx| {
        if (name == 8 and idx < frame.locals.len) return &frame.locals[idx];
    }
    return null;
}

pub fn closeLocalVarRef(ctx: *core.Context, frame: *frame_mod.Frame, idx: u16) !void {
    if (idx >= frame.locals.len) return error.InvalidBytecode;
    const cell = varRefCellFromValue(frame.locals[idx]) orelse return;
    const value = if (cell.varRefValueSlot().*) |stored| stored.dup() else core.Value.undefinedValue();
    const old_value = frame.locals[idx];
    frame.locals[idx] = value;
    old_value.free(ctx.runtime);
}

pub fn pushFunctionClosure(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    stack: *stack_mod.Stack,
    function: *const bytecode.Bytecode,
    global: *core.Object,
    index: usize,
    opc: u8,
    eval_local_names: []const core.Atom,
    eval_local_slots: []core.Value,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
) !void {
    const value = function.constants.get(index) orelse return error.InvalidBytecode;
    defer value.free(ctx.runtime);
    const object_value = try createBytecodeFunctionObject(ctx, frame, function, global, value, function.name, opc, true, eval_local_names, eval_local_slots, eval_var_ref_names, eval_var_refs, stack.values);
    defer object_value.free(ctx.runtime);
    try stack.push(object_value);
}

pub fn createBytecodeFunctionObject(
    ctx: *core.Context,
    frame: *frame_mod.Frame,
    caller_function: *const bytecode.Bytecode,
    global: *core.Object,
    value: core.Value,
    name_atom: core.Atom,
    opc: u8,
    create_prototype: bool,
    eval_local_names: []const core.Atom,
    eval_local_slots: []core.Value,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    skip_direct_eval_capture_values: []const core.Value,
) !core.Value {
    if (!value.isFunctionBytecode()) return error.InvalidBytecode;
    var rooted_value = value;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_value },
    };
    var root_slices = [_]core.runtime.ValueRootSlice{
        .{ .constant = &eval_local_slots },
        .{ .constant = &eval_var_refs },
        .{ .constant = &skip_direct_eval_capture_values },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
        .slices = &root_slices,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    const fb = functionBytecodeFromValue(rooted_value) orelse return error.InvalidBytecode;
    const object = try core.Object.create(ctx.runtime, core.class.ids.bytecode_function, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
    const function_prototype = if (fb.func_kind == .async_generator)
        try asyncGeneratorFunctionPrototypeFromGlobal(ctx.runtime, global)
    else if (fb.func_kind == .generator)
        try generatorFunctionPrototypeFromGlobal(ctx.runtime, global)
    else if (fb.func_kind == .async)
        try asyncFunctionPrototypeFromGlobal(ctx.runtime, global)
    else
        functionPrototypeFromGlobal(ctx.runtime, global);
    if (function_prototype) |prototype| {
        try object.setPrototype(ctx.runtime, prototype);
    }
    try object.setFunctionRealmGlobalPtr(ctx.runtime, global);
    object.functionBytecodeSlot().* = rooted_value.dup();
    if (objectFromValue(frame.current_function)) |parent_function_object| {
        if (parent_function_object.functionEvalLocalNamesSlot().*.len != 0) {
            object.functionEvalParentFunctionSlot().* = frame.current_function.dup();
        }
        if (parent_function_object.functionImportMeta()) |import_meta| {
            object.functionImportMetaSlot().* = import_meta.dup();
        }
    } else if (caller_function.flags.is_module and functionBytecodeUsesImportMeta(fb)) {
        const import_meta = try importMetaObject(ctx, global, caller_function, frame);
        defer import_meta.free(ctx.runtime);
        object.functionImportMetaSlot().* = import_meta.dup();
    }
    try installLexicalPrivateNameRemap(ctx.runtime, object, frame, fb.private_bound_names);
    if (fb.class_fields_init) |init_bytecode| {
        const init_value = try createBytecodeFunctionObject(ctx, frame, caller_function, global, init_bytecode, core.atom.ids.empty_string, opc, false, eval_local_names, eval_local_slots, eval_var_ref_names, eval_var_refs, &.{});
        object.functionClassFieldsInitSlot().* = init_value;
    }
    if (fb.is_arrow_function) {
        const lexical_this_slot = derivedConstructorThisLocalSlot(frame) orelse &frame.this_value;
        object.functionLexicalThisSlot().* = if (frame.function.flags.is_derived_class_constructor or varRefCellFromValue(lexical_this_slot.*) != null)
            try ensureVarRefCell(ctx, lexical_this_slot)
        else
            lexical_this_slot.*.dup();
        if (property_ops.expectObject(frame.current_function)) |function_object| {
            object.setFunctionHomeObject(ctx.runtime, function_object.functionHomeObject());
            if (function_object.functionSuperConstructor()) |super_constructor| object.functionSuperConstructorSlot().* = super_constructor.dup();
            if (function_object.functionArrowConstructorThis()) |constructor_this| object.functionArrowConstructorThisSlot().* = constructor_this.dup();
        } else |_| {}
        if (frame.function.flags.is_derived_class_constructor) {
            object.functionArrowConstructorThisSlot().* = frame.constructor_this_value.dup();
        }
        if (!frame.new_target.isUndefined()) {
            object.functionArrowNewTargetSlot().* = frame.new_target.dup();
        }
        if (functionBytecodeUsesAtom(fb, core.atom.ids.arguments) or functionBytecodeUsesArgumentsSpecialObject(fb)) {
            const arguments_value = lookupFrameFirstEvalBindingValue(ctx.runtime, eval_local_names, eval_local_slots, eval_var_ref_names, eval_var_refs, frame, core.atom.ids.arguments) orelse
                try frameArgumentsObject(ctx, global, frame);
            defer arguments_value.free(ctx.runtime);
            try appendFunctionEvalLocal(ctx, object, core.atom.ids.arguments, arguments_value);
        }
    }
    const effective_name = if (fb.func_name != core.atom.ids.empty_string and ctx.runtime.atoms.kind(fb.func_name) != null)
        fb.func_name
    else if (fb.is_class_constructor)
        name_atom
    else
        fb.func_name;
    try object.defineOwnProperty(ctx.runtime, core.atom.ids.length, core.Descriptor.data(core.Value.int32(fb.defined_arg_count), false, false, true));
    if (ctx.runtime.atoms.kind(effective_name) != null) {
        const name_value = try functionNameValueFromAtom(ctx.runtime, effective_name, null);
        defer name_value.free(ctx.runtime);
        try object.defineOwnProperty(ctx.runtime, core.atom.ids.name, core.Descriptor.data(name_value, false, false, true));
    }
    if (fb.closure_var.len > 0) {
        const captures = try ctx.runtime.memory.alloc(core.Value, fb.closure_var.len);
        var captures_transferred = false;
        errdefer if (!captures_transferred) ctx.runtime.memory.free(core.Value, captures);
        var initialized: usize = 0;
        errdefer if (!captures_transferred) {
            for (captures[0..initialized]) |stored| stored.free(ctx.runtime);
        };
        for (fb.closure_var, 0..) |cv, idx| {
            captures[idx] = switch (cv.closure_type) {
                .local => blk: {
                    if (cv.var_idx >= frame.locals.len) return error.InvalidBytecode;
                    break :blk try ensureLocalVarRefCell(ctx, frame, cv.var_idx, cv.is_lexical);
                },
                .arg => blk: {
                    if (cv.var_idx >= frame.args.len) return error.InvalidBytecode;
                    break :blk try ensureVarRefCell(ctx, &frame.args[cv.var_idx]);
                },
                .ref => blk: {
                    try ensureVarRefsCapacity(ctx, frame, cv.var_idx);
                    break :blk try ensureVarRefCell(ctx, &frame.var_refs[cv.var_idx]);
                },
                .module_decl, .module_import => blk: {
                    try ensureVarRefsCapacity(ctx, frame, cv.var_idx);
                    break :blk try ensureVarRefCell(ctx, &frame.var_refs[cv.var_idx]);
                },
                else => return error.InvalidBytecode,
            };
            if (varRefCellFromValue(captures[idx])) |cell| {
                const captured_const = cv.is_const or switch (cv.closure_type) {
                    .local => cv.var_idx < caller_function.var_is_const.len and caller_function.var_is_const[cv.var_idx],
                    .ref, .module_decl, .module_import => cv.var_idx < caller_function.var_ref_is_const.len and caller_function.var_ref_is_const[cv.var_idx],
                    else => false,
                };
                cell.varRefIsConstSlot().* = cell.varRefIsConstSlot().* or captured_const or cv.var_kind == .function_name;
                cell.varRefIsFunctionNameSlot().* = cell.varRefIsFunctionNameSlot().* or cv.var_kind == .function_name;
            }
            initialized += 1;
        }
        object.functionCapturesSlot().* = captures;
        captures_transferred = true;
    }
    const function_has_direct_eval = functionBytecodeHasDirectEval(fb, ctx.runtime);
    const captures_eval_var_scope =
        value_ops.atomNameEql(ctx.runtime, caller_function.name, "<eval>") and
        !frame.current_function.isUndefined() and
        fb.func_name == core.atom.ids.empty_string and
        evalBytecodeHasVarDeclarations(ctx.runtime, caller_function);
    const captures_direct_eval_scope = function_has_direct_eval or captures_eval_var_scope;
    const captures_eval_frame_scope = captures_direct_eval_scope;
    if (eval_local_names.len > 0 or eval_var_ref_names.len > 0 or
        (captures_eval_frame_scope and caller_function.var_names.len > 0) or
        (captures_eval_frame_scope and caller_function.arg_names.len > 0) or
        (captures_direct_eval_scope and caller_function.var_ref_names.len > 0))
    {
        var used_count: usize = 0;
        for (eval_local_names, 0..) |atom_id, idx| {
            if (shouldSkipDirectEvalScopeCaptureName(ctx.runtime, captures_direct_eval_scope, fb, atom_id)) continue;
            if (functionBytecodeHasClosureVarName(fb, atom_id)) continue;
            const capture_eval_var_cell = captures_eval_var_scope and idx < eval_local_slots.len and evalLocalSlotIsEvalVarCell(eval_local_slots[idx]);
            if (captures_direct_eval_scope or capture_eval_var_cell or functionBytecodeUsesAtom(fb, atom_id)) used_count += 1;
        }
        for (eval_var_ref_names) |atom_id| {
            if (shouldSkipDirectEvalScopeCaptureName(ctx.runtime, captures_direct_eval_scope, fb, atom_id)) continue;
            if (functionBytecodeHasClosureVarName(fb, atom_id)) continue;
            if (captures_direct_eval_scope or captures_eval_var_scope or functionBytecodeUsesAtom(fb, atom_id)) used_count += 1;
        }
        if (captures_eval_frame_scope) {
            const local_count = @min(caller_function.var_names.len, frame.locals.len);
            for (frame.locals[0..local_count], 0..) |slot, idx| {
                if (idx < caller_function.var_is_lexical.len and caller_function.var_is_lexical[idx]) continue;
                if (idx < frame.locals_uninit.len and frame.localIsUninitialized(idx)) continue;
                if (shouldSkipDirectEvalLocalCapture(fb, slot, skip_direct_eval_capture_values)) continue;
                used_count += 1;
            }
            const arg_count = @min(caller_function.arg_names.len, frame.args.len);
            for (caller_function.arg_names[0..arg_count], 0..) |atom_id, idx| {
                if (atom_id == core.atom.null_atom) continue;
                if (functionBytecodeHasClosureVarName(fb, atom_id)) continue;
                if (shouldSkipDirectEvalLocalCapture(fb, frame.args[idx], skip_direct_eval_capture_values)) continue;
                used_count += 1;
            }
            if (captures_direct_eval_scope) used_count += @min(caller_function.var_ref_names.len, frame.var_refs.len);
        }
        if (used_count > 0) {
            const names = try ctx.runtime.memory.alloc(core.Atom, used_count);
            var eval_bindings_transferred = false;
            errdefer if (!eval_bindings_transferred) ctx.runtime.memory.free(core.Atom, names);
            const refs = try ctx.runtime.memory.alloc(core.Value, used_count);
            errdefer if (!eval_bindings_transferred) ctx.runtime.memory.free(core.Value, refs);
            var initialized: usize = 0;
            var initialized_names: usize = 0;
            errdefer if (!eval_bindings_transferred) {
                for (names[0..initialized_names]) |atom_id| ctx.runtime.atoms.free(atom_id);
            };
            errdefer if (!eval_bindings_transferred) {
                for (refs[0..initialized]) |stored| stored.free(ctx.runtime);
            };
            for (eval_local_names, 0..) |atom_id, idx| {
                if (shouldSkipDirectEvalScopeCaptureName(ctx.runtime, captures_direct_eval_scope, fb, atom_id)) continue;
                if (functionBytecodeHasClosureVarName(fb, atom_id)) continue;
                const capture_eval_var_cell = captures_eval_var_scope and idx < eval_local_slots.len and evalLocalSlotIsEvalVarCell(eval_local_slots[idx]);
                if (!captures_direct_eval_scope and !capture_eval_var_cell and !functionBytecodeUsesAtom(fb, atom_id)) continue;
                names[initialized] = ctx.runtime.atoms.dup(atom_id);
                initialized_names += 1;
                refs[initialized] = if (idx < eval_local_slots.len)
                    try ensureVarRefCell(ctx, &eval_local_slots[idx])
                else
                    core.Value.undefinedValue();
                initialized += 1;
            }
            for (eval_var_ref_names, 0..) |atom_id, idx| {
                if (shouldSkipDirectEvalScopeCaptureName(ctx.runtime, captures_direct_eval_scope, fb, atom_id)) continue;
                if (functionBytecodeHasClosureVarName(fb, atom_id)) continue;
                if (!captures_direct_eval_scope and !captures_eval_var_scope and !functionBytecodeUsesAtom(fb, atom_id)) continue;
                names[initialized] = ctx.runtime.atoms.dup(atom_id);
                initialized_names += 1;
                refs[initialized] = if (idx < eval_var_refs.len)
                    eval_var_refs[idx].dup()
                else
                    core.Value.undefinedValue();
                initialized += 1;
            }
            if (captures_eval_frame_scope) {
                const local_count = @min(caller_function.var_names.len, frame.locals.len);
                for (caller_function.var_names[0..local_count], 0..) |atom_id, idx| {
                    if (idx < caller_function.var_is_lexical.len and caller_function.var_is_lexical[idx]) continue;
                    if (idx < frame.locals_uninit.len and frame.localIsUninitialized(idx)) continue;
                    if (shouldSkipDirectEvalLocalCapture(fb, frame.locals[idx], skip_direct_eval_capture_values)) continue;
                    names[initialized] = ctx.runtime.atoms.dup(atom_id);
                    initialized_names += 1;
                    refs[initialized] = try ensureVarRefCell(ctx, &frame.locals[idx]);
                    initialized += 1;
                }
                const arg_count = @min(caller_function.arg_names.len, frame.args.len);
                for (caller_function.arg_names[0..arg_count], 0..) |atom_id, idx| {
                    if (atom_id == core.atom.null_atom) continue;
                    if (functionBytecodeHasClosureVarName(fb, atom_id)) continue;
                    if (shouldSkipDirectEvalLocalCapture(fb, frame.args[idx], skip_direct_eval_capture_values)) continue;
                    names[initialized] = ctx.runtime.atoms.dup(atom_id);
                    initialized_names += 1;
                    refs[initialized] = try ensureVarRefCell(ctx, &frame.args[idx]);
                    initialized += 1;
                }
            }
            if (captures_direct_eval_scope) {
                const ref_count = @min(caller_function.var_ref_names.len, frame.var_refs.len);
                for (caller_function.var_ref_names[0..ref_count], 0..) |atom_id, idx| {
                    names[initialized] = ctx.runtime.atoms.dup(atom_id);
                    initialized_names += 1;
                    refs[initialized] = try ensureVarRefCell(ctx, &frame.var_refs[idx]);
                    initialized += 1;
                }
            }
            object.functionEvalLocalNamesSlot().* = names;
            object.functionEvalLocalRefsSlot().* = refs;
            eval_bindings_transferred = true;
        }
    }
    if (create_prototype and fb.has_prototype) {
        const generator_prototype = if (fb.func_kind == .async_generator)
            try asyncGeneratorPrototypeFromGlobal(ctx.runtime, global)
        else if (fb.func_kind == .generator)
            try generatorPrototypeFromGlobal(ctx.runtime, global)
        else
            objectPrototypeFromGlobal(ctx.runtime, global);
        const prototype = try core.Object.create(ctx.runtime, core.class.ids.object, generator_prototype);
        var prototype_raw_owned = true;
        errdefer if (prototype_raw_owned) core.Object.destroyFromHeader(ctx.runtime, &prototype.header);
        if (fb.func_kind != .generator and fb.func_kind != .async_generator) {
            try prototype.defineOwnProperty(ctx.runtime, core.atom.ids.constructor, core.Descriptor.data(object.value(), true, false, true));
        }
        const prototype_value = prototype.value();
        prototype_raw_owned = false;
        defer prototype_value.free(ctx.runtime);
        try object.defineOwnProperty(ctx.runtime, core.atom.ids.prototype, core.Descriptor.data(prototype_value, true, false, false));
    }
    return object.value();
}

pub fn functionBytecodeHasDirectEval(fb: *const bytecode.FunctionBytecode, rt: *core.Runtime) bool {
    _ = rt;
    var pc: usize = 0;
    while (pc < fb.byte_code.len) {
        const opc = fb.byte_code[pc];
        if (opc == op.eval or opc == op.apply_eval) return true;
        const size = bytecode.opcode.sizeOf(opc);
        pc += if (size == 0) 1 else size;
    }
    return false;
}

pub fn functionBytecodeUsesImportMeta(fb: *const bytecode.FunctionBytecode) bool {
    var pc: usize = 0;
    while (pc < fb.byte_code.len) {
        const opc = fb.byte_code[pc];
        if (opc == op.special_object and pc + 1 < fb.byte_code.len and fb.byte_code[pc + 1] == 4) return true;
        const size = bytecode.opcode.sizeOf(opc);
        pc += if (size == 0) 1 else size;
    }
    return false;
}

pub fn evalBytecodeHasVarDeclarations(rt: *core.Runtime, function: *const bytecode.Bytecode) bool {
    if (!value_ops.atomNameEql(rt, function.name, "<eval>")) return false;
    for (function.var_names) |atom_id| {
        if (!value_ops.atomNameEql(rt, atom_id, "<ret>")) return true;
    }
    return false;
}

pub fn shouldSkipDirectEvalLocalCapture(
    fb: *const bytecode.FunctionBytecode,
    slot: core.Value,
    skip_values: []const core.Value,
) bool {
    const value = if (varRefCellFromValue(slot)) |cell|
        cell.varRefValueSlot().* orelse core.Value.undefinedValue()
    else
        slot;
    if (value.isUninitialized()) return true;
    if (!fb.super_allowed) return false;
    if (!value.isObject()) return false;
    for (skip_values) |skip_value| {
        if (skip_value.same(value)) return true;
    }
    return false;
}

pub fn functionBytecodeUsesAtom(fb: *const bytecode.FunctionBytecode, atom_id: core.Atom) bool {
    for (fb.atom_operands) |operand| {
        if (operand == atom_id) return true;
    }
    for (fb.var_ref_names) |name| {
        if (name == atom_id) return true;
    }
    return false;
}

pub fn functionBytecodeHasClosureVarName(fb: *const bytecode.FunctionBytecode, atom_id: core.Atom) bool {
    for (fb.closure_var) |cv| {
        if (cv.var_name == atom_id) return true;
    }
    return false;
}

pub fn functionBytecodeUsesArgumentsSpecialObject(fb: *const bytecode.FunctionBytecode) bool {
    var index: usize = 0;
    while (index + 1 < fb.byte_code.len) : (index += 1) {
        if (fb.byte_code[index] == op.special_object and (fb.byte_code[index + 1] == 0 or fb.byte_code[index + 1] == 1)) return true;
    }
    return false;
}

test "direct eval capture OOM releases retained eval-local atoms" {
    var saw_oom = false;
    var saw_success = false;

    var fail_offset: usize = 0;
    while (fail_offset < 220) : (fail_offset += 1) {
        var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
        const rt = try core.Runtime.create(failing.allocator());
        const ctx = try core.Context.create(rt);
        const global = try core.Object.create(rt, core.class.ids.object, null);

        const eval_name = try rt.internAtom("<eval>");
        const child_name = try rt.internAtom("captureChild");
        const captured_name = try rt.internAtom("capturedLocal");

        var caller = bytecode.Bytecode.init(&rt.memory, &rt.atoms, eval_name);
        var frame = frame_mod.Frame.init(&caller);
        var eval_local_names = [_]core.Atom{captured_name};
        var eval_local_slots = [_]core.Value{core.Value.int32(7)};

        const fb_slice = try rt.memory.alloc(bytecode.FunctionBytecode, 1);
        const fb = &fb_slice[0];
        fb.* = bytecode.FunctionBytecode.init(&rt.memory, &rt.atoms, child_name);
        fb.has_prototype = true;
        try rt.gc.add(&fb.header);
        fb.header.destroy_fn = bytecode.function.destroyFunctionBytecode;
        fb.header.destroy_ctx = @ptrCast(rt);
        fb.byte_code = try rt.memory.alloc(u8, 1);
        fb.byte_code[0] = op.eval;
        fb.byte_code_len = 1;

        failing.fail_index = failing.alloc_index + fail_offset;
        const result = createBytecodeFunctionObject(
            ctx,
            &frame,
            &caller,
            global,
            core.Value.functionBytecode(&fb.header),
            child_name,
            op.fclosure8,
            true,
            eval_local_names[0..],
            eval_local_slots[0..],
            &.{},
            &.{},
            &.{},
        );
        failing.fail_index = std.math.maxInt(usize);

        if (result) |value| {
            saw_success = true;
            value.free(rt);
        } else |err| switch (err) {
            error.OutOfMemory => saw_oom = true,
            else => |unexpected| {
                eval_local_slots[0].free(rt);
                core.Value.functionBytecode(&fb.header).free(rt);
                frame.deinit(&rt.memory, rt);
                caller.deinit(rt);
                rt.atoms.free(captured_name);
                rt.atoms.free(child_name);
                rt.atoms.free(eval_name);
                global.value().free(rt);
                ctx.destroy();
                rt.destroy();
                return unexpected;
            },
        }

        eval_local_slots[0].free(rt);
        core.Value.functionBytecode(&fb.header).free(rt);
        frame.deinit(&rt.memory, rt);
        caller.deinit(rt);
        rt.atoms.free(captured_name);
        rt.atoms.free(child_name);
        rt.atoms.free(eval_name);

        _ = rt.runObjectCycleRemoval();
        const captured_released = rt.atoms.name(captured_name) == null;

        global.value().free(rt);
        ctx.destroy();
        rt.destroy();

        try std.testing.expect(captured_released);

        if (saw_oom and saw_success) return;
    }

    try std.testing.expect(saw_oom);
    try std.testing.expect(saw_success);
}

test "closure capture OOM after transfer releases captures once" {
    var saw_oom = false;
    var saw_success = false;

    var fail_offset: usize = 0;
    while (fail_offset < 220) : (fail_offset += 1) {
