            error.OutOfMemory => saw_oom = true,
            else => |unexpected| {
                core.Value.functionBytecode(&fb.header).free(rt);
                frame.deinit(&rt.memory, rt);
                caller.deinit(rt);
                rt.atoms.free(captured_name);
                rt.atoms.free(child_name);
                rt.atoms.free(caller_name);
                global.value().free(rt);
                ctx.destroy();
                rt.destroy();
                return unexpected;
            },
        }

        core.Value.functionBytecode(&fb.header).free(rt);
        frame.deinit(&rt.memory, rt);
        caller.deinit(rt);
        rt.atoms.free(captured_name);
        rt.atoms.free(child_name);
        rt.atoms.free(caller_name);

        global.value().free(rt);
        ctx.destroy();
        rt.destroy();

        if (saw_oom and saw_success) return;
    }

    try std.testing.expect(saw_oom);
    try std.testing.expect(saw_success);
}

test "direct eval visible local OOM releases pending binding atom" {
    var saw_oom = false;
    var saw_success = false;

    var fail_offset: usize = 0;
    while (fail_offset < 96) : (fail_offset += 1) {
        var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
        const rt = try core.Runtime.create(failing.allocator());
        const ctx = try core.Context.create(rt);
        const global = try core.Object.create(rt, core.class.ids.object, null);

        const caller_name = try rt.internAtom("visibleCaller");
        const visible_name = try rt.internAtom("visibleLocal");

        var caller = bytecode.Bytecode.init(&rt.memory, &rt.atoms, caller_name);
        caller.var_names = try rt.memory.alloc(core.Atom, 1);
        caller.var_names[0] = rt.atoms.dup(visible_name);

        var frame = frame_mod.Frame.init(&caller);
        frame.locals = try rt.memory.alloc(core.Value, 1);
        frame.locals[0] = core.Value.int32(11);

        failing.fail_index = failing.alloc_index + fail_offset;
        const result = createDirectEvalVisibleLocalBindings(ctx, global, &caller, &frame, false, false);
        failing.fail_index = std.math.maxInt(usize);

        if (result) |bindings| {
            saw_success = true;
            freeAtomSlice(rt, bindings.names);
            freeValueSlice(rt, bindings.slots);
        } else |err| switch (err) {
            error.OutOfMemory => saw_oom = true,
            else => |unexpected| {
                frame.deinit(&rt.memory, rt);
                caller.deinit(rt);
                rt.atoms.free(visible_name);
                rt.atoms.free(caller_name);
                global.value().free(rt);
                ctx.destroy();
                rt.destroy();
                return unexpected;
            },
        }

        frame.deinit(&rt.memory, rt);
        caller.deinit(rt);
        rt.atoms.free(visible_name);
        rt.atoms.free(caller_name);
        const visible_released = rt.atoms.name(visible_name) == null;

        global.value().free(rt);
        ctx.destroy();
        rt.destroy();

        try std.testing.expect(visible_released);
        if (saw_oom and saw_success) return;
    }

    try std.testing.expect(saw_oom);
    try std.testing.expect(saw_success);
}

test "bytecode call eval-var merge OOM releases copied names once" {
    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
    const rt = try core.Runtime.create(failing.allocator());
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try core.Object.create(rt, core.class.ids.object, null);
    defer global.value().free(rt);

    const function_name = try rt.internAtom("evalVarMergeOOM");
    defer rt.atoms.free(function_name);
    const eval_ref_name = try rt.internAtom("evalVarMergeRef");
    var eval_ref_name_owned = true;
    defer if (eval_ref_name_owned) rt.atoms.free(eval_ref_name);

    const fb_slice = try rt.memory.alloc(bytecode.FunctionBytecode, 1);
    const fb = &fb_slice[0];
    fb.* = bytecode.FunctionBytecode.init(&rt.memory, &rt.atoms, function_name);
    try rt.gc.add(&fb.header);
    fb.header.destroy_fn = bytecode.function.destroyFunctionBytecode;
    fb.header.destroy_ctx = @ptrCast(rt);
    fb.byte_code = try rt.memory.alloc(u8, 1);
    fb.byte_code[0] = op.return_undef;
    fb.byte_code_len = 1;
    defer core.Value.functionBytecode(&fb.header).free(rt);

    const eval_var_ref_names = [_]core.Atom{eval_ref_name};
    const eval_var_refs = [_]core.Value{core.Value.undefinedValue()};

    failing.fail_index = failing.alloc_index + 1;
    const merge_result = callFunctionBytecodeModeState(
        ctx,
        core.Value.functionBytecode(&fb.header),
        core.Value.functionBytecode(&fb.header),
        core.Value.undefinedValue(),
        &.{},
        &.{},
        null,
        global,
        eval_var_ref_names[0..],
        eval_var_refs[0..],
        false,
        null,
        null,
        null,
        core.Value.undefinedValue(),
        core.Value.undefinedValue(),
    );
    failing.fail_index = std.math.maxInt(usize);
    try std.testing.expectError(error.OutOfMemory, merge_result);

    rt.atoms.free(eval_ref_name);
    eval_ref_name_owned = false;
    try std.testing.expect(rt.atoms.name(eval_ref_name) == null);
}

pub fn shouldSkipDirectEvalScopeCaptureName(
    rt: *core.Runtime,
    captures_direct_eval_scope: bool,
    fb: *const bytecode.FunctionBytecode,
    atom_id: core.Atom,
) bool {
    if (!captures_direct_eval_scope) return false;
    if (fb.func_name == core.atom.ids.empty_string) return false;
    return atomIdOrNameEql(rt, fb.func_name, atom_id);
}

pub fn appendFunctionEvalLocal(ctx: *core.Context, object: *core.Object, atom_id: core.Atom, value: core.Value) !void {
    for (object.functionEvalLocalNamesSlot().*, 0..) |name, idx| {
        if (!atomIdOrNameEql(ctx.runtime, name, atom_id) or idx >= object.functionEvalLocalRefsSlot().*.len) continue;
        const next = value.dup();
        const old_value = object.functionEvalLocalRefsSlot().*[idx];
        object.functionEvalLocalRefsSlot().*[idx] = next;
        old_value.free(ctx.runtime);
        return;
    }

    const old_len = object.functionEvalLocalNamesSlot().*.len;
    const names = try ctx.runtime.memory.alloc(core.Atom, old_len + 1);
    errdefer ctx.runtime.memory.free(core.Atom, names);
    const refs = try ctx.runtime.memory.alloc(core.Value, old_len + 1);
    errdefer ctx.runtime.memory.free(core.Value, refs);

    for (object.functionEvalLocalNamesSlot().*, 0..) |name, idx| names[idx] = name;
    for (object.functionEvalLocalRefsSlot().*, 0..) |stored, idx| refs[idx] = stored;
    names[old_len] = ctx.runtime.atoms.dup(atom_id);
    refs[old_len] = value.dup();

    const old_names = object.functionEvalLocalNamesSlot().*;
    const old_refs = object.functionEvalLocalRefsSlot().*;
    object.functionEvalLocalNamesSlot().* = names;
    object.functionEvalLocalRefsSlot().* = refs;
    if (old_names.len != 0) ctx.runtime.memory.free(core.Atom, old_names);
    if (old_refs.len != 0) ctx.runtime.memory.free(core.Value, old_refs);
}

pub fn execCall(
    ctx: *core.Context,
    stack: *stack_mod.Stack,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    catch_target: *?usize,
    argc: u16,
    output: ?*std.Io.Writer,
    global: *core.Object,
) !void {
    var inline_args: [4]core.Value = undefined;
    const args: []core.Value = if (argc <= inline_args.len)
        inline_args[0..argc]
    else
        try ctx.runtime.memory.alloc(core.Value, argc);
    defer if (argc > inline_args.len) ctx.runtime.memory.free(core.Value, args);

    var filled_start: usize = args.len;
    errdefer {
        var i = filled_start;
        while (i < args.len) : (i += 1) args[i].free(ctx.runtime);
    }
    var remaining: usize = argc;
    while (remaining > 0) {
        remaining -= 1;
        args[remaining] = try stack.pop();
        filled_start = remaining;
    }
    filled_start = args.len;
    defer {
        for (args) |arg| arg.free(ctx.runtime);
    }

    const func = try stack.pop();
    defer func.free(ctx.runtime);
    if (try fastHostOutputCall(ctx.runtime, output, func, args)) {
        try stack.pushOwned(core.Value.undefinedValue());
        return;
    }
    const is_super_constructor = isCurrentSuperConstructor(ctx, frame, func);
    const arrow_super_this = if (is_super_constructor and !frame.function.flags.is_derived_class_constructor)
        currentArrowLexicalSuperThis(ctx.runtime, frame)
    else
        null;
    defer if (arrow_super_this) |value| value.free(ctx.runtime);
    const arrow_constructor_this = if (is_super_constructor and !frame.function.flags.is_derived_class_constructor)
        currentArrowConstructorThis(ctx.runtime, frame)
    else
        null;
    defer if (arrow_constructor_this) |value| value.free(ctx.runtime);
    const is_arrow_super_constructor = is_super_constructor and arrow_super_this != null;
    const super_this = if (is_super_constructor and frame.function.flags.is_derived_class_constructor)
        frame.constructor_this_value
    else if (arrow_constructor_this) |value|
        value
    else if (arrow_super_this) |value|
        value
    else
        core.Value.undefinedValue();
    const result = callValueOrBytecodeClassMode(ctx, output, global, super_this, func, args, function, frame, is_super_constructor) catch |err| {
        try closeStackTopForOfIteratorForPendingError(ctx, output, global, stack);
        if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, err)) {
            return;
        }
        return err;
    };
    if (is_super_constructor and frame.function.flags.is_derived_class_constructor) {
        defer result.free(ctx.runtime);
        if (varRefSlotIsUninitialized(frame.this_value)) {
            const next_this = if (result.isObject()) result else frame.constructor_this_value;
            setSlotValue(ctx, &frame.this_value, next_this.dup());
            initializeCurrentConstructorClassInstanceElements(ctx, output, global, function, frame) catch |err| {
                if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, err)) {
                    return;
                }
                return err;
            };
        } else {
            if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, error.ReferenceError)) {
                return;
            }
            return error.ReferenceError;
        }
        try pushSlotValue(stack, frame.this_value);
        return;
    }
    if (is_arrow_super_constructor) {
        defer result.free(ctx.runtime);
        if (arrow_super_this) |this_value_for_arrow| {
            if (!this_value_for_arrow.isUninitialized()) {
                if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, error.ReferenceError)) {
                    return;
                }
                return error.ReferenceError;
            }
        }
        const next_this = if (result.isObject())
            result
        else if (arrow_constructor_this) |value|
            value
        else
            result;
        setCurrentArrowLexicalThis(ctx, frame, next_this.dup());
        try stack.push(next_this);
        return;
    }
    stack.pushOwned(result) catch |err| {
        result.free(ctx.runtime);
        return err;
    };
}

fn fastHostOutputCall(rt: *core.Runtime, output: ?*std.Io.Writer, func: core.Value, args: []const core.Value) !bool {
    const object = objectFromValue(func) orelse return false;
    if (object.hostFunctionKind() != core.host_function.ids.output) return false;
    try printHostOutputArgs(rt, output, args);
    return true;
}

pub fn printHostOutputArgs(rt: *core.Runtime, output: ?*std.Io.Writer, args: []const core.Value) !void {
    if (output) |writer| {
        for (args, 0..) |arg, idx| {
            if (idx != 0) try writer.writeByte(' ');
            try call_mod.printValue(rt, writer, arg);
        }
        try writer.writeByte('\n');
    }
}

pub fn execDirectEval(
    ctx: *core.Context,
    stack: *stack_mod.Stack,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    catch_target: *?usize,
    argc: u16,
    output: ?*std.Io.Writer,
    global: *core.Object,
    eval_in_class_field_initializer: bool,
    eval_in_parameter_initializer: bool,
) !void {
    var args: []core.Value = &.{};
    if (argc != 0) args = try ctx.runtime.memory.alloc(core.Value, argc);
    defer if (args.len != 0) ctx.runtime.memory.free(core.Value, args);

    var filled_start: usize = args.len;
    errdefer {
        var i = filled_start;
        while (i < args.len) : (i += 1) args[i].free(ctx.runtime);
    }
    var remaining: usize = argc;
    while (remaining > 0) {
        remaining -= 1;
        args[remaining] = try stack.pop();
        filled_start = remaining;
    }
    filled_start = args.len;
    defer {
        for (args) |arg| arg.free(ctx.runtime);
    }

    const func = try stack.pop();
    defer func.free(ctx.runtime);
    const result = if (isContextIntrinsicEval(ctx, func))
        directEval(ctx, output, global, args, function, frame, eval_in_class_field_initializer, eval_in_parameter_initializer) catch |err| {
            const eval_err = normalizeEvalRuntimeError(err);
            if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, eval_err)) {
                return;
            }
            return eval_err;
        }
    else
        callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), func, args, function, frame) catch |err| {
            if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, err)) {
                return;
            }
            return err;
        };
    defer result.free(ctx.runtime);
    try stack.push(result);
}

fn isContextIntrinsicEval(ctx: *core.Context, func: core.Value) bool {
    return func.isObject() and func.same(ctx.intrinsic_eval);
}

pub fn execApplyEval(
    ctx: *core.Context,
    stack: *stack_mod.Stack,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    catch_target: *?usize,
    output: ?*std.Io.Writer,
    global: *core.Object,
    eval_in_class_field_initializer: bool,
    eval_in_parameter_initializer: bool,
) !void {
    const arg_array = try stack.pop();
    defer arg_array.free(ctx.runtime);
    const func = try stack.pop();
    defer func.free(ctx.runtime);

    const args = try argsFromArray(ctx.runtime, arg_array);
    defer freeArgs(ctx.runtime, args);
    const result = if (isContextIntrinsicEval(ctx, func))
        directEval(ctx, output, global, args, function, frame, eval_in_class_field_initializer, eval_in_parameter_initializer) catch |err| {
            const eval_err = normalizeEvalRuntimeError(err);
            if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, eval_err)) {
                return;
            }
            return eval_err;
        }
    else
        callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), func, args, function, frame) catch |err| {
            if (try handleCatchableRuntimeError(ctx, stack, frame, catch_target, global, err)) {
                return;
            }
            return err;
        };
    defer result.free(ctx.runtime);
    try stack.push(result);
}

pub fn qjsArrayMethodFastCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (callableObjectFromValue(func)) |function_object| {
        if (core.function.decodeNativeBuiltinId(function_object.nativeFunctionIdSlot().*)) |native_ref| {
            if (native_ref.domain == .iterator) {
                if (try qjsIteratorCallForNativeRecord(ctx, output, global, receiver, native_ref.id, args, caller_function, caller_frame)) |value| return value;
            }
        }
    }
    if (try qjsArrayIterationCall(ctx, output, global, receiver, func, args, caller_function, caller_frame)) |value| return value;
    if (try qjsArrayAtCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsArrayReduceCall(ctx, output, global, receiver, func, args, false)) |value| return value;
    if (try qjsArrayReduceCall(ctx, output, global, receiver, func, args, true)) |value| return value;
    if (try qjsArraySearchCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsArrayCopyWithinCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsArrayFillCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsArrayPushCall(ctx, output, global, receiver, func, args, caller_function, caller_frame)) |value| return value;
    if (try qjsArrayPopCall(ctx, output, global, receiver, func, caller_function, caller_frame)) |value| return value;
    if (try qjsArrayShiftCall(ctx, output, global, receiver, func)) |value| return value;
    if (try qjsArrayUnshiftCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsArrayReverseCall(ctx, output, global, receiver, func, caller_function, caller_frame)) |value| return value;
    if (try qjsArraySpliceCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsTypedArraySliceSubarrayCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsArraySliceCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsArrayMapCall(ctx, output, global, receiver, func, args)) |value| return value;
    if (try qjsArrayFlatCall(ctx, output, global, receiver, func, args, caller_function, caller_frame)) |value| return value;
    if (try qjsArraySortCall(ctx, output, global, receiver, func, args, caller_function, caller_frame)) |value| return value;
    if (try qjsArrayByCopyCall(ctx, output, global, receiver, func, args, caller_function, caller_frame)) |value| return value;
    if (try qjsArrayConcatCall(ctx, output, global, receiver, func, args, caller_function, caller_frame)) |value| return value;
    return null;
}

pub fn qjsArrayPrototypeNativeRecord(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    function_object: *core.Object,
    id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const array_mod = builtins.array;
    return switch (id) {
        @intFromEnum(array_mod.PrototypeMethod.to_string) => qjsArrayToStringCall(ctx, output, global, receiver, function_object, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.to_locale_string) => qjsArrayToLocaleStringCall(ctx, output, global, receiver, function_object, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.map),
        @intFromEnum(array_mod.PrototypeMethod.filter),
        @intFromEnum(array_mod.PrototypeMethod.for_each),
        @intFromEnum(array_mod.PrototypeMethod.some),
        @intFromEnum(array_mod.PrototypeMethod.every),
        @intFromEnum(array_mod.PrototypeMethod.find),
        @intFromEnum(array_mod.PrototypeMethod.find_index),
        @intFromEnum(array_mod.PrototypeMethod.find_last),
        @intFromEnum(array_mod.PrototypeMethod.find_last_index),
        => qjsArrayIterationCall(ctx, output, global, receiver, function_object.value(), args, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.reduce) => qjsArrayReduceCall(ctx, output, global, receiver, function_object.value(), args, false),
        @intFromEnum(array_mod.PrototypeMethod.reduce_right) => qjsArrayReduceCall(ctx, output, global, receiver, function_object.value(), args, true),
        @intFromEnum(array_mod.PrototypeMethod.at) => qjsArrayAtCall(ctx, output, global, receiver, function_object.value(), args),
        @intFromEnum(array_mod.PrototypeMethod.includes),
        @intFromEnum(array_mod.PrototypeMethod.index_of),
        @intFromEnum(array_mod.PrototypeMethod.last_index_of),
        => qjsArraySearchCall(ctx, output, global, receiver, function_object.value(), args),
        @intFromEnum(array_mod.PrototypeMethod.copy_within) => qjsArrayCopyWithinCall(ctx, output, global, receiver, function_object.value(), args),
        @intFromEnum(array_mod.PrototypeMethod.fill) => qjsArrayFillCall(ctx, output, global, receiver, function_object.value(), args),
        @intFromEnum(array_mod.PrototypeMethod.push) => qjsArrayPushCall(ctx, output, global, receiver, function_object.value(), args, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.pop) => qjsArrayPopCall(ctx, output, global, receiver, function_object.value(), caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.shift) => qjsArrayShiftCall(ctx, output, global, receiver, function_object.value()),
        @intFromEnum(array_mod.PrototypeMethod.unshift) => qjsArrayUnshiftCall(ctx, output, global, receiver, function_object.value(), args),
        @intFromEnum(array_mod.PrototypeMethod.reverse) => qjsArrayReverseCall(ctx, output, global, receiver, function_object.value(), caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.splice) => qjsArraySpliceCall(ctx, output, global, receiver, function_object.value(), args),
        @intFromEnum(array_mod.PrototypeMethod.slice) => qjsArraySliceCall(ctx, output, global, receiver, function_object.value(), args),
        @intFromEnum(array_mod.PrototypeMethod.join) => qjsArrayJoinCall(ctx, output, global, receiver, function_object, args, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.concat) => qjsArrayConcatCall(ctx, output, global, receiver, function_object.value(), args, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.sort) => qjsArraySortCall(ctx, output, global, receiver, function_object.value(), args, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.flat),
        @intFromEnum(array_mod.PrototypeMethod.flat_map),
        => qjsArrayFlatCall(ctx, output, global, receiver, function_object.value(), args, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.to_reversed),
        @intFromEnum(array_mod.PrototypeMethod.to_sorted),
        @intFromEnum(array_mod.PrototypeMethod.to_spliced),
        @intFromEnum(array_mod.PrototypeMethod.with_),
        => qjsArrayByCopyCall(ctx, output, global, receiver, function_object.value(), args, caller_function, caller_frame),
        @intFromEnum(array_mod.PrototypeMethod.keys),
        @intFromEnum(array_mod.PrototypeMethod.values),
        @intFromEnum(array_mod.PrototypeMethod.entries),
        => qjsArrayIteratorMethodRecord(ctx, global, receiver, function_object, id),
        else => null,
    };
}

