fn simpleInlineIntConstant(code: []const u8, pc: *usize) ?i32 {
    if (pc.* >= code.len) return null;
    const opcode_id = code[pc.*];
    pc.* += 1;
    return switch (opcode_id) {
        op.push_minus1 => -1,
        op.push_0 => 0,
        op.push_1 => 1,
        op.push_2 => 2,
        op.push_3 => 3,
        op.push_4 => 4,
        op.push_5 => 5,
        op.push_6 => 6,
        op.push_7 => 7,
        op.push_i8 => blk: {
            if (pc.* >= code.len) return null;
            const value: i8 = @bitCast(code[pc.*]);
            pc.* += 1;
            break :blk @as(i32, value);
