}

fn simpleNumericBinary(rt: *core.Runtime, binop: u8, lhs: core.Value, rhs: core.Value) !core.Value {
    if (lhs.asInt32()) |lhs_int| {
        if (rhs.asInt32()) |rhs_int| {
            return switch (binop) {
                op.add => simpleInt32Add(lhs_int, rhs_int),
                op.sub => simpleInt32Sub(lhs_int, rhs_int),
                op.mul => simpleInt32Mul(lhs_int, rhs_int),
                else => try value_ops.binary(rt, binop, lhs, rhs),
            };
        }
    }
    return try value_ops.binary(rt, binop, lhs, rhs);
}

fn simpleInt32Add(lhs: i32, rhs: i32) core.Value {
    const result = @addWithOverflow(lhs, rhs);
    if (result[1] == 0) return core.Value.int32(result[0]);
    return value_ops.numberToValue(@as(f64, @floatFromInt(lhs)) + @as(f64, @floatFromInt(rhs)));
}

fn simpleInt32Sub(lhs: i32, rhs: i32) core.Value {
    const result = @subWithOverflow(lhs, rhs);
    if (result[1] == 0) return core.Value.int32(result[0]);
    return value_ops.numberToValue(@as(f64, @floatFromInt(lhs)) - @as(f64, @floatFromInt(rhs)));
}

fn simpleInt32Mul(lhs: i32, rhs: i32) core.Value {
    const result = @mulWithOverflow(lhs, rhs);
    if (result[1] == 0) return core.Value.int32(result[0]);
    return value_ops.numberToValue(@as(f64, @floatFromInt(lhs)) * @as(f64, @floatFromInt(rhs)));
}

pub fn classConstructorNewTarget(func: core.Value, caller_frame: ?*frame_mod.Frame) core.Value {
    if (caller_frame) |frame| {
        if (!frame.new_target.isUndefined()) return frame.new_target;
    }
    return func;
}

pub fn constructBuiltinSuperConstructor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    name: []const u8,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
    explicit_new_target: ?core.Value,
) !?core.Value {
    if (std.mem.eql(u8, name, "Symbol") or std.mem.eql(u8, name, "BigInt")) return error.TypeError;

    const new_target = explicit_new_target orelse classConstructorNewTarget(constructor, caller_frame);

    if (std.mem.eql(u8, name, "Promise")) {
        const executor = if (args.len >= 1) args[0] else return error.TypeError;
        if (!isCallableValue(executor)) return error.TypeError;
    }
    if (std.mem.eql(u8, name, "Iterator")) {
        if (builtins.object.sameValue(new_target, constructor)) return error.TypeError;
        const prototype = try reflectConstructPrototypeVm(ctx, output, global, name, new_target, caller_function, caller_frame);
        const instance = try core.Object.create(ctx.runtime, core.class.ids.object, prototype);
        return instance.value();
    }

    if (std.mem.eql(u8, name, "Function")) return try constructDynamicFunctionFromSource(ctx, output, global, constructor, new_target, args, .normal, caller_function, caller_frame);
    if (std.mem.eql(u8, name, "AsyncFunction")) return try constructDynamicFunctionFromSource(ctx, output, global, constructor, new_target, args, .async_function, caller_function, caller_frame);
    if (std.mem.eql(u8, name, "GeneratorFunction")) return try constructDynamicFunctionFromSource(ctx, output, global, constructor, new_target, args, .generator, caller_function, caller_frame);
    if (std.mem.eql(u8, name, "AsyncGeneratorFunction")) return try constructDynamicFunctionFromSource(ctx, output, global, constructor, new_target, args, .async_generator, caller_function, caller_frame);

    if (std.mem.eql(u8, name, "ArrayBuffer") or std.mem.eql(u8, name, "SharedArrayBuffer")) {
        const byte_length = if (args.len >= 1)
            try qjsTypedArrayConstructToIndex(ctx, output, global, args[0])
        else
            @as(usize, 0);
        const max_byte_length = try qjsArrayBufferMaxByteLengthOption(ctx, output, global, args, byte_length);
        const prototype = try reflectConstructPrototypeVm(ctx, output, global, name, new_target, caller_function, caller_frame);
        if (std.mem.eql(u8, name, "SharedArrayBuffer")) {
            return try builtins.buffer.sharedArrayBufferConstructLength(ctx.runtime, byte_length, max_byte_length, prototype);
        }
        return try builtins.buffer.arrayBufferConstructLength(ctx.runtime, byte_length, max_byte_length, prototype);
    }

    if (std.mem.eql(u8, name, "DataView")) {
        const coerced = try qjsDataViewConstructorArgs(ctx, output, global, args);
        const prototype = try reflectConstructPrototypeVm(ctx, output, global, name, new_target, caller_function, caller_frame);
        return try qjsDataViewConstructWithPrototype(ctx.runtime, args[0], coerced, prototype);
    }

    if (std.mem.eql(u8, name, "RegExp")) {
        return try qjsRegExpConstructCall(ctx, output, global, new_target, args, caller_function, caller_frame);
    }

    const prototype = try reflectConstructPrototypeVm(ctx, output, global, name, new_target, caller_function, caller_frame);
    if (std.mem.eql(u8, name, "Object")) {
        if (builtins.object.sameValue(new_target, constructor) and args.len >= 1 and args[0].isObject()) return args[0].dup();
        const instance = try core.Object.create(ctx.runtime, core.class.ids.object, prototype);
        return instance.value();
    }
    if (std.mem.eql(u8, name, "Array")) return builtins.array.constructConstructorWithPrototype(ctx.runtime, args, prototype) catch |err| switch (err) {
        error.RangeError => return @as(?core.Value, try throwRangeErrorMessage(ctx, global, "invalid array length")),
        else => err,
    };
    if (std.mem.eql(u8, name, "String")) return try qjsStringConstructWithPrototype(ctx, output, global, prototype, args, caller_function, caller_frame);
    if (std.mem.eql(u8, name, "Number")) {
        if (args.len >= 1 and args[0].isSymbol()) return error.TypeError;
        const primitive = if (args.len >= 1) try value_ops.toNumberValue(ctx.runtime, args[0]) else core.Value.int32(0);
        return try constructPrimitiveWrapperWithPrototype(ctx.runtime, core.class.ids.number, prototype, primitive);
    }
    if (std.mem.eql(u8, name, "Boolean")) {
        return try constructPrimitiveWrapperWithPrototype(ctx.runtime, core.class.ids.boolean, prototype, core.Value.boolean(args.len >= 1 and valueTruthy(args[0])));
    }
    if (std.mem.eql(u8, name, "Date")) return try date_vm.qjsDateConstructWithPrototype(ctx, output, global, prototype, args);
    if (std.mem.eql(u8, name, "AggregateError")) {
        const constructor_global = if (objectFromValue(constructor)) |constructor_object|
            objectRealmGlobal(constructor_object) orelse global
        else
            global;
        return try qjsAggregateErrorConstructWithPrototype(ctx, output, constructor_global, prototype, args, caller_function, caller_frame);
    }
    if (std.mem.eql(u8, name, "SuppressedError")) return try qjsSuppressedErrorConstructWithPrototype(ctx, output, global, prototype, args, caller_function, caller_frame);
    if (isErrorConstructorName(name)) return try qjsErrorConstructWithPrototype(ctx, output, global, name, prototype, args, caller_function, caller_frame);
    if (std.mem.eql(u8, name, "Promise")) return try qjsPromiseConstructWithPrototype(ctx, output, global, prototype, args, caller_function, caller_frame);
    if (std.mem.eql(u8, name, "WeakRef")) {
        const target = if (args.len >= 1) args[0] else return error.TypeError;
        if (!qjsCanBeHeldWeakly(ctx.runtime, target)) return error.TypeError;
        return try qjsConstructWeakRefWithPrototype(ctx.runtime, target, prototype);
    }
    if (std.mem.eql(u8, name, "FinalizationRegistry")) {
        const cleanup_callback = if (args.len >= 1) args[0] else return error.TypeError;
        if (!isCallableValue(cleanup_callback)) return error.TypeError;
        return try qjsConstructFinalizationRegistryWithPrototype(ctx.runtime, cleanup_callback, prototype);
    }
    if (std.mem.eql(u8, name, "DisposableStack")) return try qjsDisposableStackConstructWithPrototype(ctx, global, prototype);
    if (std.mem.eql(u8, name, "AsyncDisposableStack")) return try qjsAsyncDisposableStackConstructWithPrototype(ctx, global, prototype);
    if (collectionConstructorId(name)) |kind| return try constructCollectionWithPrototypeFromVm(ctx, output, global, kind, args, prototype);
    if (std.mem.eql(u8, name, "DataView")) return try builtins.buffer.dataViewConstruct(ctx.runtime, args, prototype);
    if (construct_mod.typedArrayElement(name)) |element| return try construct_mod.constructTypedArrayValue(ctx.runtime, prototype, element, args, global);

    return null;
}

pub fn constructPrimitiveWrapperWithPrototype(
    rt: *core.Runtime,
    class_id: core.class.ClassId,
    prototype: ?*core.Object,
    primitive: core.Value,
) !core.Value {
    var rooted_primitive = primitive;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_primitive },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    const object = try core.Object.create(rt, class_id, prototype);
    errdefer core.Object.destroyFromHeader(rt, &object.header);
    object.objectDataSlot().* = rooted_primitive.dup();
    return object.value();
}

test "constructPrimitiveWrapperWithPrototype roots direct symbol while creating wrapper" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const symbol_atom = try rt.atoms.newValueSymbol("gc-construct-primitive-wrapper-symbol");
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const wrapper_value = try constructPrimitiveWrapperWithPrototype(rt, core.class.ids.symbol, null, core.Value.symbol(symbol_atom));
    var wrapper_alive = true;
    defer if (wrapper_alive) wrapper_value.free(rt);
    const wrapper = objectFromValue(wrapper_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    const stored = wrapper.objectDataSlot().* orelse return error.TypeError;
    try std.testing.expect(stored.same(core.Value.symbol(symbol_atom)));

    wrapper_value.free(rt);
    wrapper_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

pub fn qjsAggregateErrorConstructWithPrototype(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    prototype: ?*core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const rt = ctx.runtime;
    var cause_val = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &cause_val },
    };
    const rooted_args = args;
    var root_slices = [_]core.runtime.ValueRootSlice{
        .{ .constant = &rooted_args },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
        .slices = &root_slices,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    defer cause_val.free(rt);

    const instance = try core.Object.create(rt, core.class.ids.error_, prototype);
    const instance_value = instance.value();
    errdefer instance_value.free(rt);

    const name_value = try value_ops.createStringValue(rt, "AggregateError");
    defer name_value.free(rt);
    try defineDataProperty(rt, instance, "name", name_value, true, false, true);

    if (rooted_args.len >= 2 and !rooted_args[1].isUndefined()) {
        const message = try toStringForAnnexB(ctx, output, global, rooted_args[1], caller_function, caller_frame);
        defer message.free(rt);
        try defineDataProperty(rt, instance, "message", message, true, false, true);
    }

    if (rooted_args.len >= 3 and rooted_args[2].isObject()) {
        const cause_key = try rt.internAtom("cause");
        defer rt.atoms.free(cause_key);
        const options = try property_ops.expectObject(rooted_args[2]);
        if (try hasValueProperty(ctx, output, global, rooted_args[2], options, cause_key, caller_function, caller_frame)) {
            cause_val = try getValueProperty(ctx, output, global, rooted_args[2], cause_key, caller_function, caller_frame);
            try defineDataProperty(rt, instance, "cause", cause_val, true, false, true);
            cause_val.free(rt);
            cause_val = core.Value.undefinedValue();
        }
    }

    const errors_value = if (rooted_args.len >= 1) rooted_args[0] else core.Value.undefinedValue();
    const errors_array = try aggregateErrorsIterableToArray(ctx, output, global, errors_value, caller_function, caller_frame);
    const errors_array_value = errors_array.value();
    defer errors_array_value.free(rt);
    try defineDataProperty(rt, instance, "errors", errors_array_value, true, false, true);

    try captureErrorStack(ctx, output, global, instance);

    return instance_value;
}

test "qjsAggregateErrorConstructWithPrototype preserves direct symbol errors and cause" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try qjs_vm.ensureContextGlobal(ctx);

    const errors_source = try core.Object.createArray(rt, arrayPrototypeFromGlobal(rt, global));
    var errors_source_alive = true;
    defer if (errors_source_alive) errors_source.value().free(rt);
    const options = try core.Object.create(rt, core.class.ids.object, objectPrototypeFromGlobal(rt, global));
    var options_alive = true;
    defer if (options_alive) options.value().free(rt);

    const error_atom = try rt.atoms.newValueSymbol("gc-aggregate-error-item-symbol");
    const cause_atom = try rt.atoms.newValueSymbol("gc-aggregate-error-cause-symbol");
    try errors_source.defineOwnProperty(rt, core.atom.atomFromUInt32(0), core.Descriptor.data(core.Value.symbol(error_atom), true, true, true));
    errors_source.length = 1;
    try errors_source.defineOwnProperty(rt, core.atom.ids.length, core.Descriptor.data(core.Value.int32(1), true, false, false));
    try defineDataProperty(rt, options, "cause", core.Value.symbol(cause_atom), true, false, true);

    const args = [_]core.Value{
        errors_source.value(),
        core.Value.undefinedValue(),
        options.value(),
    };
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);
    ctx.formatting_error_stack = true;
    defer ctx.formatting_error_stack = false;

    const aggregate_value = try qjsAggregateErrorConstructWithPrototype(ctx, null, global, null, &args, null, null);
    var aggregate_alive = true;
    defer if (aggregate_alive) aggregate_value.free(rt);
    const aggregate = objectFromValue(aggregate_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(error_atom) != null);
    try std.testing.expect(rt.atoms.name(cause_atom) != null);
    const errors_key = try rt.internAtom("errors");
    defer rt.atoms.free(errors_key);
    const cause_key = try rt.internAtom("cause");
    defer rt.atoms.free(cause_key);
    {
        const stored_errors_value = aggregate.getProperty(errors_key);
        defer stored_errors_value.free(rt);
        const stored_errors = objectFromValue(stored_errors_value) orelse return error.TypeError;
        const stored_error = stored_errors.getProperty(core.atom.atomFromUInt32(0));
        defer stored_error.free(rt);
        try std.testing.expect(stored_error.same(core.Value.symbol(error_atom)));

        const stored_cause = aggregate.getProperty(cause_key);
        defer stored_cause.free(rt);
        try std.testing.expect(stored_cause.same(core.Value.symbol(cause_atom)));
    }

    aggregate_value.free(rt);
    aggregate_alive = false;
    errors_source.value().free(rt);
    errors_source_alive = false;
    options.value().free(rt);
    options_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(error_atom) == null);
    try std.testing.expect(rt.atoms.name(cause_atom) == null);
}

pub fn qjsSuppressedErrorConstructWithPrototype(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    prototype: ?*core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const rt = ctx.runtime;
    const rooted_args = args;
    var root_slices = [_]core.runtime.ValueRootSlice{
        .{ .constant = &rooted_args },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .slices = &root_slices,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    const instance = try core.Object.create(rt, core.class.ids.error_, prototype);
    const instance_value = instance.value();
    errdefer instance_value.free(rt);

    if (rooted_args.len >= 3 and !rooted_args[2].isUndefined()) {
        const message = try toStringForAnnexB(ctx, output, global, rooted_args[2], caller_function, caller_frame);
        defer message.free(rt);
        try defineDataProperty(rt, instance, "message", message, true, false, true);
    }

    const error_value = if (rooted_args.len >= 1) rooted_args[0] else core.Value.undefinedValue();
    try defineDataProperty(rt, instance, "error", error_value, true, false, true);

    const suppressed_value = if (rooted_args.len >= 2) rooted_args[1] else core.Value.undefinedValue();
    try defineDataProperty(rt, instance, "suppressed", suppressed_value, true, false, true);

    try captureErrorStack(ctx, output, global, instance);

    return instance_value;
}

test "qjsSuppressedErrorConstructWithPrototype roots direct symbol args while creating error" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try core.Object.create(rt, core.class.ids.object, null);
    defer global.value().free(rt);

    const error_atom = try rt.atoms.newValueSymbol("gc-suppressed-error-value-symbol");
    const suppressed_atom = try rt.atoms.newValueSymbol("gc-suppressed-error-suppressed-symbol");
    const args = [_]core.Value{
        core.Value.symbol(error_atom),
        core.Value.symbol(suppressed_atom),
    };

    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const error_value = try qjsSuppressedErrorConstructWithPrototype(ctx, null, global, null, &args, null, null);
    var error_alive = true;
    defer if (error_alive) error_value.free(rt);
    const object = objectFromValue(error_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(error_atom) != null);
    try std.testing.expect(rt.atoms.name(suppressed_atom) != null);
    const error_key = try rt.internAtom("error");
    defer rt.atoms.free(error_key);
    const suppressed_key = try rt.internAtom("suppressed");
    defer rt.atoms.free(suppressed_key);
    const stored_error = object.getProperty(error_key);
    defer stored_error.free(rt);
    const stored_suppressed = object.getProperty(suppressed_key);
    defer stored_suppressed.free(rt);
    try std.testing.expect(stored_error.same(core.Value.symbol(error_atom)));
    try std.testing.expect(stored_suppressed.same(core.Value.symbol(suppressed_atom)));

    error_value.free(rt);
    error_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(error_atom) == null);
    try std.testing.expect(rt.atoms.name(suppressed_atom) == null);
}

const DisposableStackMethod = enum(u8) {
    use = 1,
    adopt = 2,
    defer_ = 3,
    dispose = 4,
    move = 5,
    disposed_get = 6,
};

fn disposableStackMethodFromMarker(marker: u8) ?DisposableStackMethod {
    return switch (marker) {
        @intFromEnum(DisposableStackMethod.use) => .use,
        @intFromEnum(DisposableStackMethod.adopt) => .adopt,
        @intFromEnum(DisposableStackMethod.defer_) => .defer_,
        @intFromEnum(DisposableStackMethod.dispose) => .dispose,
        @intFromEnum(DisposableStackMethod.move) => .move,
        @intFromEnum(DisposableStackMethod.disposed_get) => .disposed_get,
        else => null,
    };
}

pub fn qjsDisposableStackConstructWithPrototype(
    ctx: *core.Context,
    global: *core.Object,
    prototype: ?*core.Object,
) !core.Value {
    const stack = try core.Object.create(ctx.runtime, core.class.ids.disposable_stack, prototype);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &stack.header);
    try stack.setFunctionRealmGlobalPtr(ctx.runtime, global);
    return stack.value();
}

fn disposableStackReceiver(receiver: core.Value) !*core.Object {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.disposable_stack) return error.TypeError;
    return object;
}

fn parserDisposableStackReceiver(receiver: core.Value) !*core.Object {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.disposable_stack and
        object.class_id != core.class.ids.async_disposable_stack) return error.TypeError;
    return object;
}

fn qjsDisposableStackMethodCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    function_object: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const marker = function_object.disposableStackMethod();
    if (marker == 0) return null;
    const method = disposableStackMethodFromMarker(marker) orelse return error.TypeError;
    const stack = try disposableStackReceiver(receiver);
    return switch (method) {
        .use => try qjsDisposableStackUse(ctx, output, global, stack, args, caller_function, caller_frame),
        .adopt => try qjsDisposableStackAdopt(ctx.runtime, stack, args),
        .defer_ => try qjsDisposableStackDefer(ctx.runtime, stack, args),
        .dispose => try qjsDisposableStackDispose(ctx, output, global, stack, caller_function, caller_frame),
        .move => try qjsDisposableStackMove(ctx, global, stack),
        .disposed_get => core.Value.boolean(stack.disposableStackDisposed()),
    };
}

fn qjsDisposableStackUse(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    if (value.isNull() or value.isUndefined()) return value.dup();
    if (!value.isObject()) return error.TypeError;

    const dispose_method = try getValueProperty(ctx, output, global, value, core.atom.ids.Symbol_dispose, caller_function, caller_frame);
    defer dispose_method.free(ctx.runtime);
    if (dispose_method.isNull() or dispose_method.isUndefined() or !isCallableValue(dispose_method)) return error.TypeError;
    try stack.appendDisposableResource(ctx.runtime, value, dispose_method, .use, false);
    return value.dup();
}

fn qjsDisposableStackAdopt(
    rt: *core.Runtime,
    stack: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const on_dispose = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    if (!isCallableValue(on_dispose)) return error.TypeError;
    try stack.appendDisposableResource(rt, value, on_dispose, .adopt, false);
    return value.dup();
}

fn qjsDisposableStackDefer(
    rt: *core.Runtime,
    stack: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const on_dispose = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    if (!isCallableValue(on_dispose)) return error.TypeError;
    try stack.appendDisposableResource(rt, core.Value.undefinedValue(), on_dispose, .defer_, false);
    return core.Value.undefinedValue();
}

fn qjsDisposableStackDispose(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    return qjsDisposeDisposableStackResources(ctx, output, global, stack, null, caller_function, caller_frame);
}

fn qjsDisposableStackRecordDisposeError(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    pending_error: *?core.Value,
    thrown: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    if (pending_error.*) |suppressed| {
        var thrown_owned = true;
        errdefer if (thrown_owned) thrown.free(ctx.runtime);

        const combined = try qjsSuppressedErrorForDispose(ctx, output, global, thrown, suppressed, caller_function, caller_frame);
        thrown_owned = false;
        pending_error.* = combined;
        thrown.free(ctx.runtime);
        suppressed.free(ctx.runtime);
    } else {
        pending_error.* = thrown;
    }
}

fn qjsDisposeDisposableStackResources(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    initial_error: ?core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (stack.disposableStackDisposed()) {
        if (initial_error) |value| {
            _ = ctx.throwValue(value.dup());
            return error.Test262Error;
        }
        return core.Value.undefinedValue();
    }
    stack.disposableStackDisposedSlot().* = true;

    var pending_error: ?core.Value = if (initial_error) |value| value.dup() else null;
    errdefer if (pending_error) |value| value.free(ctx.runtime);

    while (stack.popDisposableResource()) |resource| {
        defer resource.destroy(ctx.runtime);
        qjsDisposeResource(ctx, output, global, resource, caller_function, caller_frame) catch |err| {
            const thrown = try runtimeErrorValueForDisposableDispose(ctx, global, err);
            try qjsDisposableStackRecordDisposeError(ctx, output, global, &pending_error, thrown, caller_function, caller_frame);
        };
    }

    if (pending_error) |value| {
        pending_error = null;
        _ = ctx.throwValue(value);
        return error.Test262Error;
    }
    return core.Value.undefinedValue();
}

test "DisposableStack pending error merge OOM releases disposal error value" {
    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
    const rt = try core.Runtime.create(failing.allocator());
    const ctx = try core.Context.create(rt);
    const global = try core.Object.create(rt, core.class.ids.object, null);

    var pending_error: ?core.Value = core.Value.int32(9);
    defer {
        failing.fail_index = std.math.maxInt(usize);
        if (pending_error) |value| value.free(rt);
        global.value().free(rt);
        ctx.destroy();
        rt.destroy();
    }

    const thrown = try createNamedError(rt, global, "TypeError", "dispose failed");
    failing.fail_index = failing.alloc_index;
    try std.testing.expectError(
        error.OutOfMemory,
        qjsDisposableStackRecordDisposeError(ctx, null, global, &pending_error, thrown, null, null),
    );
}

pub fn qjsUsingCreateDisposableStack(
    ctx: *core.Context,
    global: *core.Object,
) !core.Value {
    const prototype = constructorPrototypeFromGlobal(ctx.runtime, global, "DisposableStack");
    return qjsDisposableStackConstructWithPrototype(ctx, global, prototype);
}

pub fn qjsUsingAddSyncResource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 2) return error.TypeError;
    const stack = try parserDisposableStackReceiver(args[0]);
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const value = args[1];
    if (value.isNull() or value.isUndefined()) return core.Value.undefinedValue();
    if (!value.isObject()) return error.TypeError;

    const dispose_method = try getValueProperty(ctx, output, global, value, core.atom.ids.Symbol_dispose, null, null);
    defer dispose_method.free(ctx.runtime);
    if (dispose_method.isNull() or dispose_method.isUndefined() or !isCallableValue(dispose_method)) return error.TypeError;
    try stack.appendDisposableResource(ctx.runtime, value, dispose_method, .use, false);
    return core.Value.undefinedValue();
}

pub fn qjsUsingDisposeSyncStack(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 1) return error.TypeError;
    const stack = try disposableStackReceiver(args[0]);
    return qjsDisposeDisposableStackResources(ctx, output, global, stack, null, null, null);
}

pub fn qjsUsingDisposeSyncStackForThrow(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 2) return error.TypeError;
    const stack = try disposableStackReceiver(args[0]);
    return qjsDisposeDisposableStackResources(ctx, output, global, stack, args[1], null, null);
}

pub fn qjsUsingCreateAsyncDisposableStack(
    ctx: *core.Context,
    global: *core.Object,
) !core.Value {
    const prototype = constructorPrototypeFromGlobal(ctx.runtime, global, "AsyncDisposableStack");
    return qjsAsyncDisposableStackConstructWithPrototype(ctx, global, prototype);
}

pub fn qjsUsingAddAsyncResource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 2) return error.TypeError;
    const stack = try asyncDisposableStackReceiver(args[0]);
    return qjsAsyncDisposableStackUse(ctx, output, global, stack, args[1..2], null, null);
}

pub fn qjsUsingDisposeAsyncStack(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 1) return error.TypeError;
    _ = try asyncDisposableStackReceiver(args[0]);
    return qjsAsyncDisposableStackDisposeAsync(ctx, output, global, args[0], null, null);
}

pub fn qjsUsingDisposeAsyncStackForThrow(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 2) return error.TypeError;
    var capability = try qjsDefaultPromiseCapability(ctx, output, global, null, null);
    errdefer capability.deinit(ctx.runtime);

    const stack = try asyncDisposableStackReceiver(args[0]);
    if (stack.disposableStackDisposed()) {
        try qjsPromiseRejectCapability(ctx, output, global, capability.reject, args[1], null, null);
        return capability.releaseCallbacks(ctx.runtime);
    }

    stack.disposableStackDisposedSlot().* = true;
    qjsAsyncDisposableStackStoreCapability(stack, ctx.runtime, capability);
    try qjsAsyncDisposableStackContinueOrReject(ctx, output, global, stack, args[1], null, null);
    return capability.releaseCallbacks(ctx.runtime);
}

fn qjsDisposeResource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    resource: core.object.DisposableResource,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const result = switch (resource.kind) {
        .use => try callValueOrBytecode(ctx, output, global, resource.value, resource.method, &.{}, caller_function, caller_frame),
        .adopt => try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), resource.method, &.{resource.value}, caller_function, caller_frame),
        .defer_ => try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), resource.method, &.{}, caller_function, caller_frame),
    };
    result.free(ctx.runtime);
}

fn runtimeErrorValueForDisposableDispose(
    ctx: *core.Context,
    global: *core.Object,
    err: anytype,
) !core.Value {
    if (exception_ops.pendingExceptionMatchesError(ctx, err)) return ctx.takeException();
    if (ctx.hasException()) ctx.clearException();
    const error_info = exception_ops.runtimeErrorInfo(err) orelse return err;
    return createNamedError(ctx.runtime, global, error_info.name, error_info.message);
}

fn qjsSuppressedErrorForDispose(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    error_value: core.Value,
    suppressed_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const prototype = constructorPrototypeFromGlobal(ctx.runtime, global, "SuppressedError");
    const args = [_]core.Value{ error_value, suppressed_value };
    return qjsSuppressedErrorConstructWithPrototype(ctx, output, global, prototype, &args, caller_function, caller_frame);
}

fn qjsDisposableStackMove(
    ctx: *core.Context,
    global: *core.Object,
    stack: *core.Object,
) !core.Value {
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const prototype = constructorPrototypeFromGlobal(ctx.runtime, global, "DisposableStack");
    const moved = try core.Object.create(ctx.runtime, core.class.ids.disposable_stack, prototype);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &moved.header);
    try moved.setFunctionRealmGlobalPtr(ctx.runtime, global);
    stack.moveDisposableResourcesTo(moved);
    stack.disposableStackDisposedSlot().* = true;
    return moved.value();
}

const AsyncDisposableStackMethod = enum(u8) {
    use = 1,
    adopt = 2,
    defer_ = 3,
    dispose_async = 4,
    move = 5,
    disposed_get = 6,
};

fn asyncDisposableStackMethodFromMarker(marker: u8) ?AsyncDisposableStackMethod {
    return switch (marker) {
        @intFromEnum(AsyncDisposableStackMethod.use) => .use,
        @intFromEnum(AsyncDisposableStackMethod.adopt) => .adopt,
        @intFromEnum(AsyncDisposableStackMethod.defer_) => .defer_,
        @intFromEnum(AsyncDisposableStackMethod.dispose_async) => .dispose_async,
        @intFromEnum(AsyncDisposableStackMethod.move) => .move,
        @intFromEnum(AsyncDisposableStackMethod.disposed_get) => .disposed_get,
        else => null,
    };
}

pub fn qjsAsyncDisposableStackConstructWithPrototype(
    ctx: *core.Context,
    global: *core.Object,
    prototype: ?*core.Object,
) !core.Value {
    const stack = try core.Object.create(ctx.runtime, core.class.ids.async_disposable_stack, prototype);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &stack.header);
    try stack.setFunctionRealmGlobalPtr(ctx.runtime, global);
    return stack.value();
}

fn asyncDisposableStackReceiver(receiver: core.Value) !*core.Object {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.async_disposable_stack) return error.TypeError;
    return object;
}

fn qjsAsyncDisposableStackMethodCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    function_object: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const marker = function_object.asyncDisposableStackMethod();
    if (marker == 0) return null;
    const method = asyncDisposableStackMethodFromMarker(marker) orelse return error.TypeError;
    if (method == .dispose_async) return try qjsAsyncDisposableStackDisposeAsync(ctx, output, global, receiver, caller_function, caller_frame);
    const stack = try asyncDisposableStackReceiver(receiver);
    return switch (method) {
        .use => try qjsAsyncDisposableStackUse(ctx, output, global, stack, args, caller_function, caller_frame),
        .adopt => try qjsAsyncDisposableStackAdopt(ctx.runtime, stack, args),
        .defer_ => try qjsAsyncDisposableStackDefer(ctx.runtime, stack, args),
        .move => try qjsAsyncDisposableStackMove(ctx, global, stack),
        .disposed_get => core.Value.boolean(stack.disposableStackDisposed()),
        .dispose_async => unreachable,
    };
}

fn qjsAsyncDisposableStackUse(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    if (value.isNull() or value.isUndefined()) {
        try stack.appendDisposableResource(ctx.runtime, core.Value.undefinedValue(), core.Value.undefinedValue(), .use, true);
        return value.dup();
    }
    if (!value.isObject()) return error.TypeError;

    const async_dispose_method = try getValueProperty(ctx, output, global, value, core.atom.ids.Symbol_asyncDispose, caller_function, caller_frame);
    defer async_dispose_method.free(ctx.runtime);
    if (!async_dispose_method.isNull() and !async_dispose_method.isUndefined()) {
        if (!isCallableValue(async_dispose_method)) return error.TypeError;
        try stack.appendDisposableResource(ctx.runtime, value, async_dispose_method, .use, true);
        return value.dup();
    }

    const dispose_method = try getValueProperty(ctx, output, global, value, core.atom.ids.Symbol_dispose, caller_function, caller_frame);
    defer dispose_method.free(ctx.runtime);
    if (dispose_method.isNull() or dispose_method.isUndefined() or !isCallableValue(dispose_method)) return error.TypeError;
    try stack.appendDisposableResource(ctx.runtime, value, dispose_method, .use, false);
    return value.dup();
}

fn qjsAsyncDisposableStackAdopt(
    rt: *core.Runtime,
    stack: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const on_dispose = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    if (!isCallableValue(on_dispose)) return error.TypeError;
    try stack.appendDisposableResource(rt, value, on_dispose, .adopt, true);
    return value.dup();
}

fn qjsAsyncDisposableStackDefer(
    rt: *core.Runtime,
    stack: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const on_dispose = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    if (!isCallableValue(on_dispose)) return error.TypeError;
    try stack.appendDisposableResource(rt, core.Value.undefinedValue(), on_dispose, .defer_, true);
    return core.Value.undefinedValue();
}

fn qjsAsyncDisposableStackMove(
    ctx: *core.Context,
    global: *core.Object,
    stack: *core.Object,
) !core.Value {
    if (stack.disposableStackDisposed()) return error.ReferenceError;
    const prototype = constructorPrototypeFromGlobal(ctx.runtime, global, "AsyncDisposableStack");
    const moved = try core.Object.create(ctx.runtime, core.class.ids.async_disposable_stack, prototype);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &moved.header);
    try moved.setFunctionRealmGlobalPtr(ctx.runtime, global);
    stack.moveDisposableResourcesTo(moved);
    stack.disposableStackDisposedSlot().* = true;
    return moved.value();
}

fn qjsDefaultPromiseCapability(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !PromiseCapabilityVm {
    const promise_constructor = try qjsPromiseDefaultConstructor(ctx, global);
    defer promise_constructor.free(ctx.runtime);
    return qjsPromiseCapability(ctx, output, global, promise_constructor, caller_function, caller_frame);
}

fn qjsPromiseResolveCapability(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    resolve_value: core.Value,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), resolve_value, &.{value}, caller_function, caller_frame);
    result.free(ctx.runtime);
}

fn qjsAsyncDisposableStackStoreCapability(stack: *core.Object, rt: *core.Runtime, capability: PromiseCapabilityVm) void {
    stack.clearDisposableStackAsyncCapability(rt);
    stack.disposableStackAsyncResolveSlot().* = capability.resolve.dup();
    stack.disposableStackAsyncRejectSlot().* = capability.reject.dup();
}

fn qjsAsyncDisposableStackDisposeAsync(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    var capability = try qjsDefaultPromiseCapability(ctx, output, global, caller_function, caller_frame);
    errdefer capability.deinit(ctx.runtime);

    const stack = asyncDisposableStackReceiver(receiver) catch {
        const reason = try qjsPromiseErrorValue(ctx, global, error.TypeError);
        defer reason.free(ctx.runtime);
        try qjsPromiseRejectCapability(ctx, output, global, capability.reject, reason, caller_function, caller_frame);
        return capability.releaseCallbacks(ctx.runtime);
    };
    if (stack.disposableStackDisposed()) {
        try qjsPromiseResolveCapability(ctx, output, global, capability.resolve, core.Value.undefinedValue(), caller_function, caller_frame);
        return capability.releaseCallbacks(ctx.runtime);
    }

    stack.disposableStackDisposedSlot().* = true;
    qjsAsyncDisposableStackStoreCapability(stack, ctx.runtime, capability);
    try qjsAsyncDisposableStackContinueOrReject(ctx, output, global, stack, null, caller_function, caller_frame);
    return capability.releaseCallbacks(ctx.runtime);
}

fn qjsAsyncDisposableStackContinuation(
    rt: *core.Runtime,
    global: *core.Object,
    stack: *core.Object,
    rejected: bool,
) !core.Value {
    const callback = try qjsCreateBuiltinFunction(rt, global, "", 1);
    errdefer callback.free(rt);
    const callback_object = objectFromValue(callback) orelse return error.TypeError;
    callback_object.functionAsyncDisposeStackSlot().* = stack.value().dup();
    callback_object.functionAsyncDisposeRejectedSlot().* = rejected;
    return callback;
}

fn qjsAsyncDisposableStackContinuationCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    function_object: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const stack_value = function_object.functionAsyncDisposeStack() orelse return null;
    const stack = objectFromValue(stack_value) orelse return error.TypeError;
    if (stack.class_id != core.class.ids.async_disposable_stack) return error.TypeError;
    const rejected = function_object.functionAsyncDisposeRejected();
    const rejection = if (rejected) (if (args.len >= 1) args[0] else core.Value.undefinedValue()) else null;
    try qjsAsyncDisposableStackContinueOrReject(ctx, output, global, stack, rejection, caller_function, caller_frame);
    return core.Value.undefinedValue();
}

fn qjsAsyncDisposableStackContinueOrReject(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    awaited_rejection: ?core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    qjsAsyncDisposableStackContinue(ctx, output, global, stack, awaited_rejection, caller_function, caller_frame) catch |err| {
        const reason = try qjsPromiseErrorValue(ctx, global, err);
        defer reason.free(ctx.runtime);
        try qjsAsyncDisposableStackRejectStored(ctx, output, global, stack, reason, caller_function, caller_frame);
    };
}

fn qjsAsyncDisposableStackContinue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    awaited_rejection: ?core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    if (awaited_rejection) |reason| {
        try qjsAsyncDisposableStackRecordError(ctx, output, global, stack, reason, caller_function, caller_frame);
    }

    while (stack.popDisposableResource()) |resource| {
        defer resource.destroy(ctx.runtime);
        const result = qjsAsyncDisposeResource(ctx, output, global, resource, caller_function, caller_frame) catch |err| {
            const thrown = try runtimeErrorValueForDisposableDispose(ctx, global, err);
            defer thrown.free(ctx.runtime);
            try qjsAsyncDisposableStackRecordError(ctx, output, global, stack, thrown, caller_function, caller_frame);
            continue;
        };
        defer result.free(ctx.runtime);
        if (resource.await_result) {
            try qjsAsyncDisposableStackAwaitValue(ctx, output, global, stack, result, caller_function, caller_frame);
            return;
        }
    }

    const pending_error_slot = stack.disposableStackAsyncErrorSlot();
    if (pending_error_slot.*) |reason| {
        try qjsAsyncDisposableStackRejectStored(ctx, output, global, stack, reason, caller_function, caller_frame);
        return;
    }
    try qjsAsyncDisposableStackResolveStored(ctx, output, global, stack, core.Value.undefinedValue(), caller_function, caller_frame);
}

test "AsyncDisposableStack keeps pending error if reject job preparation fails" {
    var saw_oom = false;
    var saw_success = false;

    var fail_offset: usize = 0;
    while (fail_offset < 180) : (fail_offset += 1) {
        var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
        const rt = try core.Runtime.create(failing.allocator());
        const ctx = try core.Context.create(rt);
        const global = try core.Object.create(rt, core.class.ids.object, null);
        const stack = try core.Object.create(rt, core.class.ids.async_disposable_stack, null);
        const promise = try core.Object.create(rt, core.class.ids.promise, null);

        const reaction = try qjsPromiseReactionRecord(rt, core.Value.undefinedValue(), core.Value.undefinedValue(), core.Value.undefinedValue(), core.Value.undefinedValue());
        try qjsAppendPromiseReaction(rt, promise, reaction);
        reaction.free(rt);

        const state = try createPromiseResolvingState(rt);
        const reject = try createPromiseResolvingFunction(rt, global, promise.value(), true, state);

        stack.disposableStackAsyncRejectSlot().* = reject.dup();
        stack.disposableStackAsyncErrorSlot().* = core.Value.int32(7);

        failing.fail_index = failing.alloc_index + fail_offset;
        const result = qjsAsyncDisposableStackContinue(ctx, null, global, stack, null, null, null);
        failing.fail_index = std.math.maxInt(usize);

        if (result) {
            saw_success = true;
            try std.testing.expectEqual(@as(?core.Value, null), stack.disposableStackAsyncErrorSlot().*);
            try std.testing.expectEqual(@as(usize, 0), promise.promiseReactions().len);
            try std.testing.expectEqual(@as(usize, 1), ctx.pending_promise_jobs.len);
        } else |err| switch (err) {
            error.OutOfMemory => {
                saw_oom = true;
                try std.testing.expect(stack.disposableStackAsyncErrorSlot().* != null);
                try std.testing.expectEqual(@as(usize, 1), promise.promiseReactions().len);
                try std.testing.expectEqual(@as(usize, 0), ctx.pending_promise_jobs.len);
            },
            else => |unexpected| {
                reject.free(rt);
                state.value().free(rt);
                stack.value().free(rt);
                promise.value().free(rt);
                global.value().free(rt);
                ctx.destroy();
                rt.destroy();
                return unexpected;
            },
        }

        reject.free(rt);
        state.value().free(rt);
        stack.value().free(rt);
        promise.value().free(rt);
        global.value().free(rt);
        ctx.destroy();
        rt.destroy();

        if (saw_oom and saw_success) break;
    }

    try std.testing.expect(saw_oom);
    try std.testing.expect(saw_success);
}

fn qjsAsyncDisposeResource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    resource: core.object.DisposableResource,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (resource.method.isUndefined()) return core.Value.undefinedValue();
    return switch (resource.kind) {
        .use => try callValueOrBytecode(ctx, output, global, resource.value, resource.method, &.{}, caller_function, caller_frame),
        .adopt => try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), resource.method, &.{resource.value}, caller_function, caller_frame),
        .defer_ => try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), resource.method, &.{}, caller_function, caller_frame),
    };
}

fn qjsAsyncDisposableStackAwaitValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const promise_constructor = try qjsPromiseDefaultConstructor(ctx, global);
    defer promise_constructor.free(ctx.runtime);
    const awaited = try qjsPromiseStaticCall(ctx, output, global, promise_constructor, &.{value}, .resolve, caller_function, caller_frame);
    defer awaited.free(ctx.runtime);

    const on_fulfilled = try qjsAsyncDisposableStackContinuation(ctx.runtime, global, stack, false);
    defer on_fulfilled.free(ctx.runtime);
    const on_rejected = try qjsAsyncDisposableStackContinuation(ctx.runtime, global, stack, true);
    defer on_rejected.free(ctx.runtime);

    const then_atom = try ctx.runtime.internAtom("then");
    defer ctx.runtime.atoms.free(then_atom);
    const then_value = try getValueProperty(ctx, output, global, awaited, then_atom, caller_function, caller_frame);
    defer then_value.free(ctx.runtime);
    if (!isCallableValue(then_value)) return error.TypeError;
    const then_result = try callValueOrBytecode(ctx, output, global, awaited, then_value, &.{ on_fulfilled, on_rejected }, caller_function, caller_frame);
    then_result.free(ctx.runtime);
}

fn qjsAsyncDisposableStackRecordError(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    error_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const slot = stack.disposableStackAsyncErrorSlot();
    if (slot.*) |suppressed| {
        const combined = try qjsSuppressedErrorForDispose(ctx, output, global, error_value, suppressed, caller_function, caller_frame);
        slot.* = combined;
        suppressed.free(ctx.runtime);
    } else {
        slot.* = error_value.dup();
    }
}

fn qjsAsyncDisposableStackResolveStored(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const resolve_value = (stack.disposableStackAsyncResolveSlot().*) orelse return;
    const resolve = resolve_value.dup();
    defer resolve.free(ctx.runtime);
    try qjsPromiseResolveCapability(ctx, output, global, resolve, value, caller_function, caller_frame);
    stack.clearDisposableStackAsyncCapability(ctx.runtime);
}

fn qjsAsyncDisposableStackRejectStored(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    stack: *core.Object,
    reason: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const reject_value = (stack.disposableStackAsyncRejectSlot().*) orelse return;
    const reject = reject_value.dup();
    defer reject.free(ctx.runtime);
    try qjsPromiseRejectCapability(ctx, output, global, reject, reason, caller_function, caller_frame);
    stack.clearDisposableStackAsyncCapability(ctx.runtime);
}
pub fn qjsErrorConstructWithPrototype(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    name: []const u8,
    prototype: ?*core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const rt = ctx.runtime;
    var cause_val = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &cause_val },
    };
    const rooted_args = args;
    var root_slices = [_]core.runtime.ValueRootSlice{
        .{ .constant = &rooted_args },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
        .slices = &root_slices,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    defer cause_val.free(rt);

    const instance = try core.Object.create(rt, core.class.ids.error_, prototype);
    const instance_value = instance.value();
    errdefer instance_value.free(rt);

    const name_value = try value_ops.createStringValue(rt, name);
    defer name_value.free(rt);
    try defineDataProperty(rt, instance, "name", name_value, true, false, true);

    if (rooted_args.len >= 1 and !rooted_args[0].isUndefined()) {
        const message = try toStringForAnnexB(ctx, output, global, rooted_args[0], caller_function, caller_frame);
        defer message.free(rt);
        try defineDataProperty(rt, instance, "message", message, true, false, true);
    }

    if (rooted_args.len >= 2 and rooted_args[1].isObject()) {
        const cause_key = try rt.internAtom("cause");
        defer rt.atoms.free(cause_key);
        const options = try property_ops.expectObject(rooted_args[1]);
        if (try hasValueProperty(ctx, output, global, rooted_args[1], options, cause_key, caller_function, caller_frame)) {
            cause_val = try getValueProperty(ctx, output, global, rooted_args[1], cause_key, caller_function, caller_frame);
            try defineDataProperty(rt, instance, "cause", cause_val, true, false, true);
            cause_val.free(rt);
            cause_val = core.Value.undefinedValue();
        }
    }

    try captureErrorStack(ctx, output, global, instance);

    return instance_value;
}

test "qjsErrorConstructWithPrototype preserves direct symbol cause" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try qjs_vm.ensureContextGlobal(ctx);

    const options = try core.Object.create(rt, core.class.ids.object, objectPrototypeFromGlobal(rt, global));
    var options_alive = true;
    defer if (options_alive) options.value().free(rt);

    const cause_atom = try rt.atoms.newValueSymbol("gc-error-cause-symbol");
    try defineDataProperty(rt, options, "cause", core.Value.symbol(cause_atom), true, false, true);
    const args = [_]core.Value{
        core.Value.undefinedValue(),
        options.value(),
    };
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);
    ctx.formatting_error_stack = true;
    defer ctx.formatting_error_stack = false;

    const error_value = try qjsErrorConstructWithPrototype(ctx, null, global, "Error", null, &args, null, null);
    var error_alive = true;
    defer if (error_alive) error_value.free(rt);
    const object = objectFromValue(error_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(cause_atom) != null);
    const cause_key = try rt.internAtom("cause");
    defer rt.atoms.free(cause_key);
    {
        const stored_cause = object.getProperty(cause_key);
        defer stored_cause.free(rt);
        try std.testing.expect(stored_cause.same(core.Value.symbol(cause_atom)));
    }

    error_value.free(rt);
    error_alive = false;
    options.value().free(rt);
    options_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(cause_atom) == null);
}

fn defineErrorStack(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, instance: *core.Object) !void {
    const stack_value = try buildErrorStackValue(ctx, output, global, instance.value(), null);
    defer stack_value.free(ctx.runtime);
    try defineDataProperty(ctx.runtime, instance, "stack", stack_value, true, false, true);
}

fn captureErrorStack(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, instance: *core.Object) !void {
    _ = output;
    const sites = try buildCallSiteArray(ctx, global, null);
    defer sites.free(ctx.runtime);
    try instance.setErrorStackSites(ctx.runtime, sites);
}

fn buildErrorStackValue(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, error_value: core.Value, skip_name: ?[]const u8) !core.Value {
    if (ctx.formatting_error_stack) return buildErrorStackStringValue(ctx, global, skip_name);

    if (try errorPrepareStackTrace(ctx.runtime, global)) |prepare| {
        defer prepare.free(ctx.runtime);
        const sites = try buildCallSiteArray(ctx, global, skip_name);
        defer sites.free(ctx.runtime);
        ctx.formatting_error_stack = true;
        defer ctx.formatting_error_stack = false;
        return callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), prepare, &.{ error_value, sites }, null, null) catch |err| {
            if (exception_ops.pendingExceptionMatchesError(ctx, err)) {
                const thrown_value = ctx.takeException();
                thrown_value.free(ctx.runtime);
                return core.Value.nullValue();
            }
            if (ctx.hasException()) ctx.clearException();
            if (exception_ops.runtimeErrorInfo(err) != null) return core.Value.nullValue();
            return err;
        };
    }
    return buildErrorStackStringValue(ctx, global, skip_name);
}

fn formatCapturedErrorStackValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    error_value: core.Value,
    sites_value: core.Value,
    site_count: usize,
) !core.Value {
    if (ctx.formatting_error_stack) return formatCapturedErrorStackStringValue(ctx, sites_value, site_count);

    if (try errorPrepareStackTrace(ctx.runtime, global)) |prepare| {
        defer prepare.free(ctx.runtime);
        const sites_arg = sites_value.dup();
        defer sites_arg.free(ctx.runtime);
        ctx.formatting_error_stack = true;
        defer ctx.formatting_error_stack = false;
        return callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), prepare, &.{ error_value, sites_arg }, null, null) catch |err| {
            if (exception_ops.pendingExceptionMatchesError(ctx, err)) {
                const thrown_value = ctx.takeException();
                thrown_value.free(ctx.runtime);
                return core.Value.nullValue();
            }
            if (ctx.hasException()) ctx.clearException();
            if (exception_ops.runtimeErrorInfo(err) != null) return core.Value.nullValue();
            return err;
        };
    }
    return formatCapturedErrorStackStringValue(ctx, sites_value, site_count);
}

fn buildErrorStackStringValue(ctx: *core.Context, global: *core.Object, skip_name: ?[]const u8) !core.Value {
    var bytes: std.ArrayList(u8) = .empty;
    defer bytes.deinit(ctx.runtime.memory.allocator);

    const limit = errorStackTraceLimit(ctx.runtime, global);
    if (limit == 0) return value_ops.createStringValue(ctx.runtime, "");

    var idx = ctx.backtrace_frames.len;
    var emitted: usize = 0;
    var skipping = skip_name != null;
    while (idx > 0) {
        idx -= 1;
        if (skipping) {
            if (backtraceFunctionNameEql(ctx, ctx.backtrace_frames[idx], skip_name.?)) skipping = false;
            continue;
        }
        if (emitted >= limit) break;
        const entry = ctx.backtrace_frames[idx];
        if (bytes.items.len != 0) try bytes.append(ctx.runtime.memory.allocator, '\n');
        try bytes.appendSlice(ctx.runtime.memory.allocator, "    at ");
        try appendBacktraceFunctionName(ctx, &bytes, entry.function_name, entry.filename);
        const filename = ctx.runtime.atoms.name(entry.filename) orelse "<anonymous>";
        const location = entry.location();
        const line_num = if (location.line_num > 0) location.line_num else 1;
        const col_num = if (location.col_num > 0) location.col_num else 1;
        const suffix = try std.fmt.allocPrint(ctx.runtime.memory.allocator, " ({s}:{}:{})", .{ filename, line_num, col_num });
        defer ctx.runtime.memory.allocator.free(suffix);
        try bytes.appendSlice(ctx.runtime.memory.allocator, suffix);
        emitted += 1;
    }
    if (emitted != 0) try bytes.append(ctx.runtime.memory.allocator, '\n');

    return value_ops.createStringValue(ctx.runtime, bytes.items);
}

fn formatCapturedErrorStackStringValue(ctx: *core.Context, sites_value: core.Value, site_count: usize) !core.Value {
    const sites = objectFromValue(sites_value) orelse return value_ops.createStringValue(ctx.runtime, "");
    var bytes: std.ArrayList(u8) = .empty;
    defer bytes.deinit(ctx.runtime.memory.allocator);

    const current_length: usize = if (sites.is_array) @intCast(sites.length) else 0;
    const length = @min(current_length, site_count);
    var index: usize = 0;
    var emitted: usize = 0;
    while (index < length) : (index += 1) {
        if (index > std.math.maxInt(u32)) break;
        const site_value = sites.getProperty(core.atom.atomFromUInt32(@intCast(index)));
        defer site_value.free(ctx.runtime);
        const site = objectFromValue(site_value) orelse continue;
        if (!site.isCallSite()) continue;
        if (bytes.items.len != 0) try bytes.append(ctx.runtime.memory.allocator, '\n');
        try bytes.appendSlice(ctx.runtime.memory.allocator, "    at ");
        try appendCallSiteFunctionName(ctx.runtime, &bytes, site);

        var filename_bytes: std.ArrayList(u8) = .empty;
        defer filename_bytes.deinit(ctx.runtime.memory.allocator);
        try appendCallSiteFileName(ctx.runtime, &filename_bytes, site);
        const suffix = try std.fmt.allocPrint(
            ctx.runtime.memory.allocator,
            " ({s}:{}:{})",
            .{ filename_bytes.items, site.callSiteLine(), site.callSiteColumn() },
        );
        defer ctx.runtime.memory.allocator.free(suffix);
        try bytes.appendSlice(ctx.runtime.memory.allocator, suffix);
        emitted += 1;
    }
    if (emitted != 0) try bytes.append(ctx.runtime.memory.allocator, '\n');
    return value_ops.createStringValue(ctx.runtime, bytes.items);
}

fn buildCallSiteArray(ctx: *core.Context, global: *core.Object, skip_name: ?[]const u8) !core.Value {
    const array = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
    errdefer core.Object.destroyFromHeader(ctx.runtime, &array.header);
    const limit = errorStackTraceLimit(ctx.runtime, global);
    var idx = ctx.backtrace_frames.len;
    var emitted: usize = 0;
    var skipping = skip_name != null;
    while (idx > 0) {
        idx -= 1;
        if (skipping) {
            if (backtraceFunctionNameEql(ctx, ctx.backtrace_frames[idx], skip_name.?)) skipping = false;
            continue;
        }
        if (emitted >= limit) break;
        const site = try createCallSiteObject(ctx, global, ctx.backtrace_frames[idx]);
        defer site.free(ctx.runtime);
        try array.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(@intCast(emitted)), core.Descriptor.data(site, true, true, true));
        emitted += 1;
    }
    array.length = @intCast(emitted);
    try array.defineOwnProperty(ctx.runtime, core.atom.ids.length, core.Descriptor.data(core.Value.int32(@intCast(emitted)), true, false, false));
    return array.value();
}

fn createCallSiteObject(ctx: *core.Context, global: *core.Object, entry: core.BacktraceFrame) !core.Value {
    const object = try core.Object.create(ctx.runtime, core.class.ids.object, try callSitePrototypeFromGlobal(ctx.runtime, global));
    errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
    const location = entry.location();
    const filename = try value_ops.createStringValue(ctx.runtime, ctx.runtime.atoms.name(entry.filename) orelse "<anonymous>");
    defer filename.free(ctx.runtime);
    const function_name_value = try callSiteFunctionNameValue(ctx, entry);
    defer function_name_value.free(ctx.runtime);
    try object.setCallSiteMetadata(
        ctx.runtime,
        filename,
        function_name_value,
        if (location.line_num > 0) location.line_num else 1,
        if (location.col_num > 0) location.col_num else 1,
    );

    return object.value();
}

fn callSitePrototypeFromGlobal(rt: *core.Runtime, global: *core.Object) !*core.Object {
    if (cachedRealmObject(global, .callsite_prototype)) |stored| return stored;
    const prototype = try core.Object.create(rt, core.class.ids.object, objectPrototypeFromGlobal(rt, global));
    var prototype_raw_owned = true;
    errdefer if (prototype_raw_owned) core.Object.destroyFromHeader(rt, &prototype.header);

    const methods = [_][]const u8{
        "getFunction",
        "getFunctionName",
        "getFileName",
        "getLineNumber",
        "getColumnNumber",
        "isNative",
    };
    for (methods) |method_name| {
        try defineNativeDataMethod(rt, prototype, method_name, 0);
    }
    try qjsDefineToStringTag(rt, prototype, "CallSite");

    const prototype_value = prototype.value();
    prototype_raw_owned = false;
    defer prototype_value.free(rt);
    try storeRealmValue(rt, global, .callsite_prototype, prototype_value);
    return prototype;
}

fn errorPrepareStackTrace(rt: *core.Runtime, global: *core.Object) !?core.Value {
    const error_key = try rt.internAtom("Error");
    defer rt.atoms.free(error_key);
    const error_value = global.getProperty(error_key);
    defer error_value.free(rt);
    const error_object = property_ops.expectObject(error_value) catch return null;
    const prepare_key = try rt.internAtom("prepareStackTrace");
    defer rt.atoms.free(prepare_key);
    const prepare = error_object.getProperty(prepare_key);
    if (!isCallableValue(prepare)) {
        prepare.free(rt);
        return null;
    }
    return prepare;
}

fn backtraceFunctionNameEql(ctx: *core.Context, entry: core.BacktraceFrame, expected: []const u8) bool {
    return std.mem.eql(u8, callSiteFunctionName(ctx, entry), expected);
}

fn callSiteFunctionName(ctx: *core.Context, entry: core.BacktraceFrame) []const u8 {
    const name = ctx.runtime.atoms.name(entry.function_name) orelse "";
    const file = ctx.runtime.atoms.name(entry.filename) orelse "";
    if (name.len == 0 or std.mem.eql(u8, name, file)) return "<anonymous>";
    return name;
}

fn callSiteFunctionNameValue(ctx: *core.Context, entry: core.BacktraceFrame) !core.Value {
    const name = ctx.runtime.atoms.name(entry.function_name) orelse "";
    const file = ctx.runtime.atoms.name(entry.filename) orelse "";
    if (name.len == 0 or std.mem.eql(u8, name, file)) return core.Value.nullValue();
    return value_ops.createStringValue(ctx.runtime, name);
}

fn errorStackTraceLimit(rt: *core.Runtime, global: *core.Object) usize {
    const error_key = rt.internAtom("Error") catch return 10;
    defer rt.atoms.free(error_key);
    const error_value = global.getProperty(error_key);
    defer error_value.free(rt);
    const error_object = property_ops.expectObject(error_value) catch return 10;
    const limit_key = rt.internAtom("stackTraceLimit") catch return 10;
    defer rt.atoms.free(limit_key);
    const limit_value = error_object.getProperty(limit_key);
    defer limit_value.free(rt);
    if (limit_value.isUndefined() or limit_value.isNull()) return 0;
    const number = value_ops.numberValue(limit_value) orelse return 10;
    if (!std.math.isFinite(number) or number <= 0) return 0;
    const truncated = @floor(number);
    if (truncated > @as(f64, @floatFromInt(std.math.maxInt(usize)))) return std.math.maxInt(usize);
    return @intFromFloat(truncated);
}

fn appendBacktraceFunctionName(
    ctx: *core.Context,
    bytes: *std.ArrayList(u8),
    function_name: core.Atom,
    filename: core.Atom,
) !void {
    const name = ctx.runtime.atoms.name(function_name) orelse "";
    const file = ctx.runtime.atoms.name(filename) orelse "";
    if (name.len == 0 or std.mem.eql(u8, name, file)) {
        try bytes.appendSlice(ctx.runtime.memory.allocator, "<anonymous>");
    } else {
        try bytes.appendSlice(ctx.runtime.memory.allocator, name);
    }
}

fn appendCallSiteFunctionName(rt: *core.Runtime, bytes: *std.ArrayList(u8), site: *core.Object) !void {
    const name_value = site.callSiteFunctionName() orelse {
        try bytes.appendSlice(rt.memory.allocator, "<anonymous>");
        return;
    };
    if (!name_value.isString()) {
        try bytes.appendSlice(rt.memory.allocator, "<anonymous>");
        return;
    }
    try value_ops.appendRawString(rt, bytes, name_value);
}

fn appendCallSiteFileName(rt: *core.Runtime, bytes: *std.ArrayList(u8), site: *core.Object) !void {
    const file_value = site.callSiteFile() orelse {
        try bytes.appendSlice(rt.memory.allocator, "<anonymous>");
        return;
    };
    if (!file_value.isString()) {
        try bytes.appendSlice(rt.memory.allocator, "<anonymous>");
        return;
    }
    try value_ops.appendRawString(rt, bytes, file_value);
}

fn aggregateErrorsIterableToArray(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterable: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !*core.Object {
    var rooted_iterable = iterable;
    var iterator_method = core.Value.undefinedValue();
    var iterator_value = core.Value.undefinedValue();
    var next_method = core.Value.undefinedValue();
    var out_value = core.Value.undefinedValue();
    var next_result_value = core.Value.undefinedValue();
    var done = core.Value.undefinedValue();
    var item = core.Value.undefinedValue();

    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_iterable },
        .{ .value = &iterator_method },
        .{ .value = &iterator_value },
        .{ .value = &next_method },
        .{ .value = &out_value },
        .{ .value = &next_result_value },
        .{ .value = &done },
        .{ .value = &item },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    defer iterator_method.free(ctx.runtime);
    defer iterator_value.free(ctx.runtime);
    defer next_method.free(ctx.runtime);
    errdefer out_value.free(ctx.runtime);
    defer next_result_value.free(ctx.runtime);
    defer done.free(ctx.runtime);
    defer item.free(ctx.runtime);

    iterator_method = try getIteratorMethod(ctx, output, global, rooted_iterable);
    if (iterator_method.isUndefined() or iterator_method.isNull() or !isCallableValue(iterator_method)) return error.TypeError;

    iterator_value = try callValueOrBytecode(ctx, output, global, rooted_iterable, iterator_method, &.{}, caller_function, caller_frame);
    const iterator = objectFromValue(iterator_value) orelse return error.TypeError;

    const next_key = try ctx.runtime.internAtom("next");
    defer ctx.runtime.atoms.free(next_key);
    next_method = try getValueProperty(ctx, output, global, iterator.value(), next_key, caller_function, caller_frame);
    if (!isCallableValue(next_method)) return error.TypeError;

    const done_key = core.atom.predefinedId("done", .string) orelse return error.TypeError;
    const value_key = core.atom.predefinedId("value", .string) orelse return error.TypeError;
    const out = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
    out_value = out.value();

    var index: u32 = 0;
    while (true) : (index += 1) {
        next_result_value.free(ctx.runtime);
        next_result_value = core.Value.undefinedValue();
        done.free(ctx.runtime);
        done = core.Value.undefinedValue();
        item.free(ctx.runtime);
        item = core.Value.undefinedValue();

        next_result_value = try callValueOrBytecode(ctx, output, global, iterator.value(), next_method, &.{}, caller_function, caller_frame);
        const next_result = objectFromValue(next_result_value) orelse return error.TypeError;
        done = try getValueProperty(ctx, output, global, next_result.value(), done_key, caller_function, caller_frame);
        if (valueTruthy(done)) break;
        item = try getValueProperty(ctx, output, global, next_result.value(), value_key, caller_function, caller_frame);
        try out.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(index), core.Descriptor.data(item, true, true, true));
    }
    out.length = index;
    try out.defineOwnProperty(ctx.runtime, core.atom.ids.length, core.Descriptor.data(core.Value.int32(@intCast(index)), true, false, false));
    return out;
}

fn defineDataProperty(
    rt: *core.Runtime,
    object: *core.Object,
    name: []const u8,
    value: core.Value,
    writable: bool,
    enumerable: bool,
    configurable: bool,
) !void {
    const key = try rt.internAtom(name);
    defer rt.atoms.free(key);
    try object.defineOwnProperty(rt, key, core.Descriptor.data(value, writable, enumerable, configurable));
}

pub fn currentArrowFunctionObject(frame: *frame_mod.Frame) ?*core.Object {
    const current_object = objectFromValue(frame.current_function) orelse return null;
    const function_value = current_object.functionBytecodeSlot().* orelse return null;
    const fb = functionBytecodeFromValue(function_value) orelse return null;
    if (!fb.is_arrow_function) return null;
    return current_object;
}

pub fn currentArrowLexicalSuperThis(rt: *core.Runtime, frame: *frame_mod.Frame) ?core.Value {
    const current_object = currentArrowFunctionObject(frame) orelse return null;
    if (current_object.functionLexicalThisSlot().*) |this_value| return slotValueDup(this_value);
    _ = rt;
    return null;
}

pub fn currentArrowConstructorThis(rt: *core.Runtime, frame: *frame_mod.Frame) ?core.Value {
    const current_object = currentArrowFunctionObject(frame) orelse return null;
    _ = rt;
    const stored = current_object.functionArrowConstructorThis() orelse return null;
    return stored.dup();
}

pub fn setCurrentArrowLexicalThis(ctx: *core.Context, frame: *frame_mod.Frame, value: core.Value) void {
    const current_object = currentArrowFunctionObject(frame) orelse {
        value.free(ctx.runtime);
        return;
    };
    if (current_object.functionLexicalThisSlot().*) |slot| {
        if (varRefCellFromValue(slot)) |cell| {
            const old_value = cell.varRefValueSlot().*;
            cell.varRefValueSlot().* = value;
            if (old_value) |stored| stored.free(ctx.runtime);
            return;
        }
        current_object.functionLexicalThisSlot().* = value;
        slot.free(ctx.runtime);
        return;
    }
    current_object.functionLexicalThisSlot().* = value;
}

pub fn isCurrentSuperConstructor(ctx: *core.Context, frame: *frame_mod.Frame, func: core.Value) bool {
    _ = ctx;
    if (!frame.current_function.isObject()) return false;
    const current_object = property_ops.expectObject(frame.current_function) catch return false;
    const super_constructor = current_object.functionSuperConstructor() orelse return false;
    if (current_object.functionLexicalThisSlot().* == null) {
        if (current_object.getPrototype()) |prototype| {
            if (sameObjectIdentity(prototype.value(), func)) return true;
        }
    }
    return sameObjectIdentity(super_constructor, func);
}

pub fn qjsUriCallId(name: []const u8) ?u32 {
    return builtins.uri.methodId(name);
}

pub fn qjsUriCallForNativeRecord(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    mode: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    if (input.isString()) {
        return builtins.uri.call(ctx.runtime, mode, input) catch |err| switch (err) {
            error.TypeError, error.URIError => err,
            else => err,
        };
    }
    const string_value = try toStringForAnnexB(ctx, output, global, input, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);
    return builtins.uri.call(ctx.runtime, mode, string_value) catch |err| switch (err) {
        error.TypeError, error.URIError => err,
        else => err,
    };
}

pub fn qjsJsonCallForNativeRecord(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const json_mod = builtins.json;
    return switch (id) {
        @intFromEnum(json_mod.StaticMethod.is_raw_json) => core.Value.boolean(args.len >= 1 and json_mod.isRawJSON(args[0])),
        @intFromEnum(json_mod.StaticMethod.raw_json) => {
            const value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            return json_mod.rawJSON(ctx.runtime, value) catch |err| switch (err) {
                error.SyntaxError, error.TypeError => err,
                else => err,
            };
        },
        @intFromEnum(json_mod.StaticMethod.parse) => {
            if (try json_vm.qjsJsonParseCall(ctx, output, global, args, caller_function, caller_frame)) |value| return value;
            return error.TypeError;
        },
        @intFromEnum(json_mod.StaticMethod.stringify) => {
            if (try json_vm.qjsJsonStringifyCall(ctx, output, global, args, caller_function, caller_frame)) |value| return value;
            return error.TypeError;
        },
        else => error.TypeError,
    };
}

pub fn qjsStringFromCodePoint(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    var units = std.ArrayList(u16).empty;
    defer units.deinit(ctx.runtime.memory.allocator);
    for (args) |value| {
        const primitive = try toPrimitiveForNumber(ctx, output, global, value);
        defer primitive.free(ctx.runtime);
        const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
        defer number_value.free(ctx.runtime);
        const number = value_ops.numberValue(number_value) orelse std.math.nan(f64);
        if (std.math.isNan(number) or !std.math.isFinite(number) or number < 0 or number > 0x10ffff or @trunc(number) != number) {
            return error.RangeError;
        }
        const code_point: u32 = @intFromFloat(number);
        if (code_point <= 0xffff) {
            try units.append(ctx.runtime.memory.allocator, @intCast(code_point));
        } else {
            const adjusted = code_point - 0x10000;
            try units.append(ctx.runtime.memory.allocator, @intCast(0xd800 + (adjusted >> 10)));
            try units.append(ctx.runtime.memory.allocator, @intCast(0xdc00 + (adjusted & 0x3ff)));
        }
    }
    return (try core.string.String.createUtf16(ctx.runtime, units.items)).value();
}

pub fn qjsStringRaw(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const template_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const cooked = try toObjectForStringRaw(ctx, global, template_value);
    defer cooked.free(ctx.runtime);

    const raw_atom = try ctx.runtime.internAtom("raw");
    defer ctx.runtime.atoms.free(raw_atom);
    const raw_candidate = try getValueProperty(ctx, output, global, cooked, raw_atom, caller_function, caller_frame);
    defer raw_candidate.free(ctx.runtime);
    const raw = try toObjectForStringRaw(ctx, global, raw_candidate);
    defer raw.free(ctx.runtime);

    const length_value = try getValueProperty(ctx, output, global, raw, core.atom.ids.length, caller_function, caller_frame);
    defer length_value.free(ctx.runtime);
    const length = try toLengthIndex(ctx, output, global, length_value);

    var out = std.ArrayList(u16).empty;
    defer out.deinit(ctx.runtime.memory.allocator);

    var index: usize = 0;
    while (index < length) : (index += 1) {
        if (index > std.math.maxInt(u32)) return error.RangeError;
        const raw_part = try getValueProperty(ctx, output, global, raw, core.atom.atomFromUInt32(@intCast(index)), caller_function, caller_frame);
        defer raw_part.free(ctx.runtime);
        const raw_string = try toStringForAnnexB(ctx, output, global, raw_part, caller_function, caller_frame);
        defer raw_string.free(ctx.runtime);
        try appendStringValueUnits(ctx.runtime, &out, raw_string);

        if (index + 1 < length and index + 1 < args.len) {
            const substitution = try toStringForAnnexB(ctx, output, global, args[index + 1], caller_function, caller_frame);
            defer substitution.free(ctx.runtime);
            try appendStringValueUnits(ctx.runtime, &out, substitution);
        }
    }

    return (try core.string.String.createUtf16(ctx.runtime, out.items)).value();
}

fn toObjectForStringRaw(ctx: *core.Context, global: *core.Object, value: core.Value) !core.Value {
    if (value.isNull() or value.isUndefined()) return error.TypeError;
    if (objectFromValue(value)) |_| return value.dup();
    return primitiveObjectForAccess(ctx.runtime, global, value);
}

pub fn qjsStringFromCodePointArray(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    array_value: core.Value,
) !core.Value {
    const array = try property_ops.expectObject(array_value);
    if (!array.is_array) return error.TypeError;
    if (try qjsStringFromCodePointDenseArray(ctx.runtime, array)) |value| return value;
    var units = std.ArrayList(u16).empty;
    defer units.deinit(ctx.runtime.memory.allocator);
    var index: u32 = 0;
    while (index < array.length) : (index += 1) {
        const value = array.getProperty(core.atom.atomFromUInt32(index));
        defer value.free(ctx.runtime);
        const primitive = try toPrimitiveForNumber(ctx, output, global, value);
        defer primitive.free(ctx.runtime);
        const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
        defer number_value.free(ctx.runtime);
        const number = value_ops.numberValue(number_value) orelse std.math.nan(f64);
        if (std.math.isNan(number) or !std.math.isFinite(number) or number < 0 or number > 0x10ffff or @trunc(number) != number) {
            return error.RangeError;
        }
        const code_point: u32 = @intFromFloat(number);
        if (code_point <= 0xffff) {
            try units.append(ctx.runtime.memory.allocator, @intCast(code_point));
        } else {
            const adjusted = code_point - 0x10000;
            try units.append(ctx.runtime.memory.allocator, @intCast(0xd800 + (adjusted >> 10)));
            try units.append(ctx.runtime.memory.allocator, @intCast(0xdc00 + (adjusted & 0x3ff)));
        }
    }
    return (try core.string.String.createUtf16(ctx.runtime, units.items)).value();
}

pub fn qjsStringFromCodePointDenseArray(rt: *core.Runtime, array: *core.Object) !?core.Value {
    if (array.arrayElementStorageMode() != .dense) return null;
    const length: usize = @intCast(array.length);
    if (array.arrayElements().len >= length) {
        if (length == 0) return (try core.string.String.createAscii(rt, "")).value();
        const max_units = try std.math.mul(usize, length, 2);
        const units = try rt.memory.alloc(u16, max_units);
        var consumed_units = false;
        defer if (!consumed_units) rt.memory.free(u16, units);

        var unit_count: usize = 0;
        var index: usize = 0;
        while (index < length) : (index += 1) {
            const value = array.arrayElements()[index] orelse return null;
            const number = value_ops.numberValue(value) orelse return null;
            const code_point = validStringCodePoint(number) orelse return error.RangeError;
            if (code_point <= 0xffff) {
                units[unit_count] = @intCast(code_point);
                unit_count += 1;
            } else {
                const adjusted = code_point - 0x10000;
                units[unit_count] = @intCast(0xd800 + (adjusted >> 10));
                units[unit_count + 1] = @intCast(0xdc00 + (adjusted & 0x3ff));
                unit_count += 2;
            }
        }
        const string = try core.string.String.createUtf16Owned(rt, units[0..unit_count], max_units);
        consumed_units = true;
        return string.value();
    }

    var code_points = try rt.memory.alloc(?u32, length);
    defer rt.memory.free(?u32, code_points);
    @memset(code_points, null);

    var seen: usize = 0;
    for (array.properties) |entry| {
        if (entry.flags.deleted) continue;
        const index = core.array.arrayIndexFromAtom(&rt.atoms, entry.atom_id) orelse continue;
        if (index >= array.length) continue;
        if (entry.flags.accessor) return null;
        const value = switch (entry.slot) {
            .data => |stored| stored,
            // Array elements never carry `auto_init` placeholders --
            // those only appear for builtin method tables installed via
            // `defineAutoInitProperty` -- but the switch must be
            // exhaustive after the auto-init slot variant was added.
            .accessor, .auto_init, .deleted => return null,
        };
        const number = value_ops.numberValue(value) orelse return null;
        const code_point = validStringCodePoint(number) orelse return error.RangeError;
        if (code_points[index] == null) seen += 1;
        code_points[index] = code_point;
    }
    if (seen != length) return null;

    var units = std.ArrayList(u16).empty;
    defer units.deinit(rt.memory.allocator);
    try units.ensureTotalCapacity(rt.memory.allocator, length * 2);
    for (code_points) |maybe_code_point| {
        appendCodePointUnits(&units, maybe_code_point.?);
    }
    return (try core.string.String.createUtf16(rt, units.items)).value();
}

pub fn validStringCodePoint(number: f64) ?u32 {
    if (std.math.isNan(number) or !std.math.isFinite(number) or number < 0 or number > 0x10ffff or @trunc(number) != number) {
        return null;
    }
    return @intFromFloat(number);
}

pub fn appendCodePointUnits(units: *std.ArrayList(u16), code_point: u32) void {
    if (code_point <= 0xffff) {
        units.appendAssumeCapacity(@intCast(code_point));
    } else {
        const adjusted = code_point - 0x10000;
        units.appendAssumeCapacity(@intCast(0xd800 + (adjusted >> 10)));
        units.appendAssumeCapacity(@intCast(0xdc00 + (adjusted & 0x3ff)));
    }
}

pub fn qjsStringFromCharCode(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len == 1) {
        if (args[0].asInt32()) |code| {
            const unit: u16 = @intCast(@as(u32, @bitCast(code)) & 0xffff);
            if (unit <= 0xff) {
                const byte: u8 = @intCast(unit);
                if (try ctx.runtime.singleByteString(byte)) |cached| return cached.value().dup();
                return (try core.string.String.createAscii(ctx.runtime, &.{byte})).value();
            }
            return (try core.string.String.createUtf16(ctx.runtime, &.{unit})).value();
        }
    }
    if (args.len == 2) {
        if (args[0].asInt32()) |first_code| {
            if (args[1].asInt32()) |second_code| {
                const cached = try ctx.runtime.recentTwoUnitString(
                    @intCast(@as(u32, @bitCast(first_code)) & 0xffff),
                    @intCast(@as(u32, @bitCast(second_code)) & 0xffff),
                );
                return cached.value().dup();
            }
        }
    }
    var units: []u16 = &.{};
    if (args.len != 0) units = try ctx.runtime.memory.alloc(u16, args.len);
    defer if (units.len != 0) ctx.runtime.memory.free(u16, units);
    for (args, 0..) |value, index| {
        const primitive = try toPrimitiveForNumber(ctx, output, global, value);
        defer primitive.free(ctx.runtime);
        if (primitive.isBigInt()) return error.TypeError;
        const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
        defer number_value.free(ctx.runtime);
        const number = value_ops.numberValue(number_value) orelse std.math.nan(f64);
        units[index] = toUint16CodeUnit(number);
    }
    return (try core.string.String.createUtf16(ctx.runtime, units)).value();
}

pub fn toUint16CodeUnit(number: f64) u16 {
    if (std.math.isNan(number) or !std.math.isFinite(number) or number == 0) return 0;
    const int = if (number < 0) -@floor(@abs(number)) else @floor(number);
    const modulo = @mod(int, 65536.0);
    return @intFromFloat(modulo);
}

pub fn qjsRegExpFunctionCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const input_pattern = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const input_flags = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const pattern_is_regexp = try isRegExpObservable(ctx, output, global, input_pattern, caller_function, caller_frame);
    if (pattern_is_regexp and input_flags.isUndefined()) {
        const ctor_key = try ctx.runtime.internAtom("constructor");
        defer ctx.runtime.atoms.free(ctor_key);
        const pattern_constructor = try getValueProperty(ctx, output, global, input_pattern, ctor_key, caller_function, caller_frame);
        defer pattern_constructor.free(ctx.runtime);
        const regexp_key = try ctx.runtime.internAtom("RegExp");
        defer ctx.runtime.atoms.free(regexp_key);
        const regexp_ctor = global.getProperty(regexp_key);
        defer regexp_ctor.free(ctx.runtime);
        if (sameObjectIdentity(pattern_constructor, regexp_ctor)) return input_pattern.dup();
    }

    var owned_source: ?core.Value = null;
    defer if (owned_source) |value| value.free(ctx.runtime);
    var owned_pattern: ?core.Value = null;
    defer if (owned_pattern) |value| value.free(ctx.runtime);
    var pattern = if (args.len >= 1) args[0] else blk: {
        const empty = try value_ops.createStringValue(ctx.runtime, "");
        owned_pattern = empty;
        break :blk empty;
    };
    if (pattern_is_regexp) {
        if (objectFromValue(pattern)) |pattern_object| {
            if (pattern_object.class_id != core.class.ids.regexp) {
                const source = try getValueProperty(ctx, output, global, pattern, core.atom.ids.source, caller_function, caller_frame);
                owned_source = source;
                pattern = source;
            }
        }
    }
    if (pattern.isObject() and !pattern_is_regexp) {
        const pattern_object = objectFromValue(pattern) orelse return error.TypeError;
        if (pattern_object.class_id != core.class.ids.regexp) {
            const string_value = try toStringForAnnexB(ctx, output, global, pattern, caller_function, caller_frame);
            owned_pattern = string_value;
            pattern = string_value;
        }
    }

    var owned_flags: ?core.Value = null;
    defer if (owned_flags) |value| value.free(ctx.runtime);
    var flags = if (!input_flags.isUndefined())
        input_flags
    else if (pattern_is_regexp) blk: {
        const pattern_object = objectFromValue(input_pattern) orelse break :blk input_flags;
        if (pattern_object.class_id == core.class.ids.regexp) break :blk input_flags;
        const flags_key = try ctx.runtime.internAtom("flags");
        defer ctx.runtime.atoms.free(flags_key);
        const pattern_flags = try getValueProperty(ctx, output, global, input_pattern, flags_key, caller_function, caller_frame);
        owned_flags = pattern_flags;
        break :blk pattern_flags;
    } else blk: {
        const empty = try value_ops.createStringValue(ctx.runtime, "");
        owned_flags = empty;
        break :blk empty;
    };
    if (!flags.isUndefined() and flags.isObject()) {
        const string_value = try toStringForAnnexB(ctx, output, global, flags, caller_function, caller_frame);
        if (owned_flags) |old| old.free(ctx.runtime);
        owned_flags = string_value;
        flags = string_value;
    }

    return builtins.regexp.constructWithPrototype(ctx.runtime, pattern, flags, constructorPrototypeFromGlobal(ctx.runtime, global, "RegExp"));
}

pub fn qjsRegExpConstructCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    new_target: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const input_pattern = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const input_flags = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    if ((input_pattern.isString() or input_pattern.isUndefined()) and
        (input_flags.isString() or input_flags.isUndefined()))
    {
        if (input_pattern.isString()) {
            if (latin1StringSlice(input_pattern)) |pattern_bytes| {
                const flag_bytes: ?[]const u8 = if (input_flags.isUndefined()) "" else latin1StringSlice(input_flags);
                if (flag_bytes) |flags| {
                    if (canConstructRegExpFromBorrowedLatin1(pattern_bytes)) {
                        const prototype = try reflectConstructPrototypeVm(ctx, output, global, "RegExp", new_target, caller_function, caller_frame);
                        return builtins.regexp.constructLiteral(ctx.runtime, pattern_bytes, flags, prototype);
                    }
                }
            }
        }
        const prototype = try reflectConstructPrototypeVm(ctx, output, global, "RegExp", new_target, caller_function, caller_frame);
        return builtins.regexp.constructWithPrototype(ctx.runtime, input_pattern, input_flags, prototype);
    }
    const pattern_is_regexp = try isRegExpObservable(ctx, output, global, input_pattern, caller_function, caller_frame);

    var owned_source: ?core.Value = null;
    defer if (owned_source) |value| value.free(ctx.runtime);
    var owned_pattern: ?core.Value = null;
    defer if (owned_pattern) |value| value.free(ctx.runtime);
    var pattern = if (args.len >= 1) args[0] else blk: {
        const empty = try value_ops.createStringValue(ctx.runtime, "");
        owned_pattern = empty;
        break :blk empty;
    };
    if (pattern.isUndefined()) {
        const empty = try value_ops.createStringValue(ctx.runtime, "");
        owned_pattern = empty;
        pattern = empty;
    } else if (pattern_is_regexp) {
        if (objectFromValue(pattern)) |pattern_object| {
            if (pattern_object.class_id == core.class.ids.regexp) {
                const source = try regexpInternalStringValue(pattern_object, true);
                owned_source = source;
                pattern = source;
            } else {
                const source = try getValueProperty(ctx, output, global, pattern, core.atom.ids.source, caller_function, caller_frame);
                owned_source = source;
                pattern = source;
            }
        }
    } else if (pattern.isObject()) {
        const pattern_object = objectFromValue(pattern) orelse return error.TypeError;
        if (pattern_object.class_id != core.class.ids.regexp) {
            const string_value = try toStringForAnnexB(ctx, output, global, pattern, caller_function, caller_frame);
            owned_pattern = string_value;
            pattern = string_value;
        }
    }

    var owned_flags: ?core.Value = null;
    defer if (owned_flags) |value| value.free(ctx.runtime);
    var flags = if (!input_flags.isUndefined())
        input_flags
    else if (pattern_is_regexp) blk: {
        const pattern_object = objectFromValue(input_pattern) orelse break :blk core.Value.undefinedValue();
        if (pattern_object.class_id == core.class.ids.regexp) {
            const pattern_flags = try regexpInternalStringValue(pattern_object, false);
            owned_flags = pattern_flags;
            break :blk pattern_flags;
        }
        const flags_key = try ctx.runtime.internAtom("flags");
        defer ctx.runtime.atoms.free(flags_key);
        const pattern_flags = try getValueProperty(ctx, output, global, input_pattern, flags_key, caller_function, caller_frame);
        owned_flags = pattern_flags;
        break :blk pattern_flags;
    } else core.Value.undefinedValue();
    if (!flags.isUndefined() and flags.isObject()) {
        const string_value = try toStringForAnnexB(ctx, output, global, flags, caller_function, caller_frame);
        if (owned_flags) |old| old.free(ctx.runtime);
        owned_flags = string_value;
        flags = string_value;
    }

    const prototype = try reflectConstructPrototypeVm(ctx, output, global, "RegExp", new_target, caller_function, caller_frame);
    return builtins.regexp.constructWithPrototype(ctx.runtime, pattern, flags, prototype);
}

pub fn qjsRegExpExecMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const regexp_object = property_ops.expectObject(this_value) catch {
        return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "RegExp object expected"));
    };
    if (regexp_object.class_id != core.class.ids.regexp) {
        return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "RegExp object expected"));
    }
    const input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    var owned_string: ?core.Value = null;
    defer if (owned_string) |value| value.free(ctx.runtime);
    const string_value = if (input.isString()) input else blk: {
        const value = try toStringForAnnexB(ctx, output, global, input, caller_function, caller_frame);
        owned_string = value;
        break :blk value;
    };
    return qjsRegExpExecResult(ctx, output, global, this_value, regexp_object, string_value, true, caller_function, caller_frame);
}

pub fn qjsRegExpTestMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const receiver_object = property_ops.expectObject(this_value) catch {
        return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "RegExp object expected"));
    };
    const input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    var owned_string: ?core.Value = null;
    defer if (owned_string) |value| value.free(ctx.runtime);
    const string_value = if (input.isString()) input else blk: {
        const value = try toStringForAnnexB(ctx, output, global, input, caller_function, caller_frame);
        owned_string = value;
        break :blk value;
    };
    const exec_atom = core.atom.predefinedId("exec", .string) orelse return error.TypeError;
    if (qjsRegExpPrototypeMethodIsDefault(receiver_object, exec_atom, @intFromEnum(builtins.regexp.PrototypeMethod.exec))) {
        if (try qjsRegExpTestFastNoResult(ctx, receiver_object, string_value)) |matched| {
            return core.Value.boolean(matched);
        }
        const result = try qjsRegExpExecResult(ctx, output, global, this_value, receiver_object, string_value, true, caller_function, caller_frame) orelse return core.Value.boolean(false);
        defer result.free(ctx.runtime);
        return core.Value.boolean(!result.isNull());
    }

    const result = try qjsRegExpExecGeneric(ctx, output, global, this_value, string_value, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    return core.Value.boolean(!result.isNull());
}

fn qjsRegExpPrototypeMethodIsDefault(object: *core.Object, atom_id: core.Atom, expected_id: u32) bool {
    if (object.class_id != core.class.ids.regexp) return false;
    if (object.hasOwnProperty(atom_id)) return false;
    const proto = object.getPrototype() orelse return false;
    if (proto.exotic != null) return false;
    for (proto.properties) |entry| {
        if (entry.flags.deleted or entry.atom_id != atom_id) continue;
        if (entry.flags.accessor) return false;
        return switch (entry.slot) {
            .data => |method| qjsRegExpNativeBuiltinMatches(method, expected_id),
            .auto_init => |info| qjsRegExpAutoInitBuiltinMatches(info, expected_id),
            .accessor, .deleted => false,
        };
    }
    return false;
}

fn qjsRegExpNativeBuiltinMatches(value: core.Value, expected_id: u32) bool {
    const function_object = objectFromValue(value) orelse return false;
    const native_ref = core.function.decodeNativeBuiltinId(function_object.nativeFunctionIdSlot().*) orelse return false;
    return native_ref.domain == .regexp and native_ref.id == expected_id;
}

fn qjsRegExpAutoInitBuiltinMatches(info: core.property.AutoInit, expected_id: u32) bool {
    if (info.kind != .native_function) return false;
    const native_ref = core.function.decodeNativeBuiltinId(info.native_builtin_id) orelse return false;
    return native_ref.domain == .regexp and native_ref.id == expected_id;
}

pub fn qjsRegExpToString(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (!this_value.isObject()) return error.TypeError;

    const source_atom = try ctx.runtime.internAtom("source");
    defer ctx.runtime.atoms.free(source_atom);
    const source_value = try getValueProperty(ctx, output, global, this_value, source_atom, caller_function, caller_frame);
    defer source_value.free(ctx.runtime);
    const source_string = try toStringForAnnexB(ctx, output, global, source_value, caller_function, caller_frame);
    defer source_string.free(ctx.runtime);

    const flags_atom = try ctx.runtime.internAtom("flags");
    defer ctx.runtime.atoms.free(flags_atom);
    const flags_value = try getValueProperty(ctx, output, global, this_value, flags_atom, caller_function, caller_frame);
    defer flags_value.free(ctx.runtime);
    const flags_string = try toStringForAnnexB(ctx, output, global, flags_value, caller_function, caller_frame);
    defer flags_string.free(ctx.runtime);

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(ctx.runtime.memory.allocator);
    try bytes.append(ctx.runtime.memory.allocator, '/');
    try value_ops.appendRawString(ctx.runtime, &bytes, source_string);
    try bytes.append(ctx.runtime.memory.allocator, '/');
    try value_ops.appendRawString(ctx.runtime, &bytes, flags_string);
    return value_ops.createStringValue(ctx.runtime, bytes.items);
}

fn qjsRegExpNativeCallById(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    func: core.Value,
    this_value: core.Value,
    native_id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    return switch (native_id) {
        @intFromEnum(builtins.regexp.StaticMethod.escape) => try builtins.regexp.escape(ctx.runtime, args),
        @intFromEnum(builtins.regexp.PrototypeMethod.to_string) => try qjsRegExpToString(ctx, output, global, this_value, caller_function, caller_frame),
        @intFromEnum(builtins.regexp.PrototypeMethod.exec) => try qjsRegExpExecMethod(ctx, output, global, this_value, args, caller_function, caller_frame),
        @intFromEnum(builtins.regexp.PrototypeMethod.test_) => try qjsRegExpTestMethod(ctx, output, global, this_value, args, caller_function, caller_frame),
        @intFromEnum(builtins.regexp.PrototypeMethod.compile) => blk: {
            const function_object = objectFromValue(func) orelse break :blk try qjsRegExpCompile(ctx, output, global, this_value, args, caller_function, caller_frame);
            const compile_global = objectRealmGlobal(function_object) orelse global;
            break :blk try qjsRegExpCompile(ctx, output, compile_global, this_value, args, caller_function, caller_frame);
        },
        @intFromEnum(builtins.regexp.PrototypeMethod.symbol_search) => try qjsRegExpSymbolSearch(ctx, output, global, this_value, args, caller_function, caller_frame),
        @intFromEnum(builtins.regexp.PrototypeMethod.symbol_match) => try qjsRegExpSymbolMatch(ctx, output, global, this_value, args, caller_function, caller_frame),
        @intFromEnum(builtins.regexp.PrototypeMethod.symbol_match_all) => try qjsRegExpSymbolMatchAll(ctx, output, global, this_value, args, caller_function, caller_frame),
        @intFromEnum(builtins.regexp.PrototypeMethod.symbol_replace) => try qjsRegExpSymbolReplace(ctx, output, global, this_value, args, caller_function, caller_frame),
        @intFromEnum(builtins.regexp.PrototypeMethod.symbol_split) => try qjsRegExpSymbolSplit(ctx, output, global, this_value, args, caller_function, caller_frame),
        else => blk: {
            if (builtins.regexp.legacyAccessorMethodFromId(native_id)) |method| {
                const function_object = objectFromValue(func) orelse return error.TypeError;
                break :blk try qjsRegExpLegacyAccessor(ctx, output, global, this_value, function_object, method, args, caller_function, caller_frame);
            }
            if (builtins.regexp.accessorNameFromId(native_id)) |accessor_name| {
                if (try qjsRegExpAccessor(ctx, output, global, this_value, func, accessor_name, caller_function, caller_frame)) |value| break :blk value;
                break :blk builtins.regexp.accessor(ctx.runtime, this_value, accessor_name) catch |err| switch (err) {
                    error.TypeError => error.TypeError,
                    else => err,
                };
            }
            break :blk null;
        },
    };
}

const RegExpBorrowedSourceFlags = struct {
    source: []const u8,
    flags: []const u8,
};

pub fn qjsRegExpTestFastNoResult(
    ctx: *core.Context,
    regexp_object: *core.Object,
    string_value: core.Value,
) !?bool {
    if (!regExpLastIndexCanSkipCoercion(regexp_object)) return null;

    const borrowed_source_flags = regexpBorrowedLatin1SourceFlags(regexp_object);
    if (borrowed_source_flags) |borrowed| {
        const flags = borrowed.flags;
        const is_global = std.mem.indexOfScalar(u8, flags, 'g') != null;
        const is_sticky = std.mem.indexOfScalar(u8, flags, 'y') != null;
        if (is_global or is_sticky) return null;

        if (!regexpSourceUsesZigPropertyFallback(borrowed.source, flags)) {
            if (simpleAsciiLiteralPlusLiteralMatch(borrowed.source, flags, string_value)) |matched| {
                return matched;
            }
            if (nativeFunctionMatcherUnicodeClassAsciiResult(borrowed.source, flags, string_value, 0)) |matched| {
                return matched;
            }
            const full_unicode = regExpFlagsContain(flags, 'u') or regExpFlagsContain(flags, 'v');
            if (full_unicode and parseUnicodeAstralSpecialSource(borrowed.source) != null) {
                return unicodeAstralSpecialMatch(borrowed.source, string_value, 0, false, true) != null;
            }
            if (full_unicode and std.mem.eql(u8, borrowed.source, "^\\S$")) {
                return anchoredSingleNonWhitespaceMatches(string_value, true);
            }
            if (full_unicode and singleLowSurrogateLiteralSource(borrowed.source) != null) {
                return unicodeLowSurrogateLiteralMatch(borrowed.source, string_value, 0, false) != null;
            }
            if (full_unicode) {
                if (simpleUnicodePropertyRunTestFast(borrowed.source, flags, string_value)) |matched| {
                    return matched;
                }
            }
            if (simpleClassEscapeTestFast(borrowed.source, flags, string_value)) |matched| {
                return matched;
            }
            if (simpleAsciiLiteralTestFast(borrowed.source, flags, string_value)) |matched| {
                return matched;
            }
            if (simpleAsciiLiteralClassPlusLiteralTestFast(borrowed.source, flags, string_value)) |matched| {
                return matched;
            }
            if (isSimpleUnicodeLiteralSource(borrowed.source)) {
                return simpleUnicodeLiteralMatch(borrowed.source, string_value, 0, false, flags) != null;
            }
            if (parseSimpleClassSequenceSource(borrowed.source, flags)) |pattern| {
                return simpleClassSequenceMatchPattern(pattern, string_value, 0, false, flags) != null;
            }
            if (parseSimpleCaptureSequenceSource(borrowed.source, flags)) |pattern| {
                return simpleCaptureSequenceMatchPattern(pattern, string_value, 0, false, flags) != null;
            }
        }
    }

    const cached_bytecode = regexp_object.regexpCompiledBytecode();
    if (cached_bytecode.len != 0) {
        const compiled = quickjs_regexp.Compiled{ .bytecode = @constCast(cached_bytecode) };
        const flag_bits = compiled.flagBits();
        if ((flag_bits & (quickjs_regexp.flag_bits.global | quickjs_regexp.flag_bits.sticky)) != 0) return null;
        return quickjs_regexp.testOnStringFromIndex(compiled, string_value, 0) catch |err| switch (err) {
            error.BytecodeCorrupt, error.Timeout => return null,
            else => return err,
        };
    }

    const borrowed = borrowed_source_flags orelse return null;
    const flags = borrowed.flags;
    const is_global = std.mem.indexOfScalar(u8, flags, 'g') != null;
    const is_sticky = std.mem.indexOfScalar(u8, flags, 'y') != null;
    if (is_global or is_sticky) return null;
    if (regexpSourceUsesZigPropertyFallback(borrowed.source, flags)) return null;
    if (!bytesAreAscii(borrowed.source)) return null;

    if (regexp_object.regexpCompiledBytecode().len == 0) {
        var compiled = quickjs_regexp.compile(ctx.runtime.memory.allocator, borrowed.source, flags) catch |err| switch (err) {
            error.InvalidPattern, error.Unsupported => return null,
            else => |other| return other,
        };
        defer compiled.deinit(ctx.runtime.memory.allocator);
        try regexp_object.setRegexpCompiledBytecode(ctx.runtime, compiled.bytecode);
    }
    const compiled = quickjs_regexp.Compiled{ .bytecode = @constCast(regexp_object.regexpCompiledBytecode()) };

    return quickjs_regexp.testOnStringFromIndex(compiled, string_value, 0) catch |err| switch (err) {
        error.BytecodeCorrupt, error.Timeout => return null,
        else => return err,
    };
}

fn simpleClassEscapeTestFast(source: []const u8, flags: []const u8, string_value: core.Value) ?bool {
    if (!isSimpleStringClassEscapeSource(source)) return null;
    if (regExpFlagsContain(flags, 'i')) return null;
    return findStringClassEscapeMatch(string_value, source, 0) != null;
}

pub fn qjsRegExpTestFastNoResultLatin1(
    ctx: *core.Context,
    regexp_object: *core.Object,
    input: []const u8,
) !?bool {
    const borrowed = regexpBorrowedLatin1SourceFlags(regexp_object) orelse return null;
    const flags = borrowed.flags;
    const is_global = std.mem.indexOfScalar(u8, flags, 'g') != null;
    const is_sticky = std.mem.indexOfScalar(u8, flags, 'y') != null;
    if (is_global or is_sticky) return null;
    if (!regExpLastIndexCanSkipCoercion(regexp_object)) return null;
    if (regexpSourceUsesZigPropertyFallback(borrowed.source, flags)) return null;

    _ = ctx;
    if (simpleAsciiLiteralPlusLiteralMatchBytes(borrowed.source, flags, input)) |matched| {
        return matched;
    }
    return null;
}

fn simpleAsciiLiteralPlusLiteralMatch(source: []const u8, flags: []const u8, string_value: core.Value) ?bool {
    const input = latin1StringSlice(string_value) orelse return null;
    return simpleAsciiLiteralPlusLiteralMatchBytes(source, flags, input);
}

fn simpleAsciiLiteralPlusLiteralMatchBytes(source: []const u8, flags: []const u8, input: []const u8) ?bool {
    if (flags.len != 0 or source.len < 2 or source[1] != '+') return null;
    const repeat = source[0];
    if (!isPlainAsciiRegExpLiteral(repeat)) return null;

    if (source.len == 2) {
        return std.mem.indexOfScalar(u8, input, repeat) != null;
    }

    if (source.len != 3) return null;
    const tail = source[2];
    if (!isPlainAsciiRegExpLiteral(tail)) return null;

    var i: usize = 0;
    while (i < input.len) : (i += 1) {
        if (input[i] != repeat) continue;
        var j = i + 1;
        while (j < input.len and input[j] == repeat) : (j += 1) {}
        if (j < input.len and input[j] == tail) return true;
    }
    return false;
}

fn simpleAsciiLiteralTestFast(source: []const u8, flags: []const u8, string_value: core.Value) ?bool {
    if (flags.len != 0 or source.len == 0) return null;
    for (source) |byte| {
        if (!isPlainAsciiRegExpLiteral(byte)) return null;
    }
    const input = latin1StringSlice(string_value) orelse return null;
    return std.mem.indexOf(u8, input, source) != null;
}

const SimpleAsciiLiteralClassPlusLiteral = struct {
    prefix: []const u8,
    class_source: []const u8,
    suffix: []const u8,
};

fn simpleAsciiLiteralClassPlusLiteralTestFast(source: []const u8, flags: []const u8, string_value: core.Value) ?bool {
    if (flags.len != 0) return null;
    const pattern = parseSimpleAsciiLiteralClassPlusLiteral(source) orelse return null;
    const input = latin1StringSlice(string_value) orelse return null;
    return simpleAsciiLiteralClassPlusLiteralMatchBytes(pattern, input);
}

fn parseSimpleAsciiLiteralClassPlusLiteral(source: []const u8) ?SimpleAsciiLiteralClassPlusLiteral {
    if (source.len < 3) return null;

    var index: usize = 0;
    while (index < source.len and isPlainAsciiRegExpLiteral(source[index])) : (index += 1) {}

    const class_start = index;
    const class_end = blk: {
        if (index + 2 < source.len and source[index] == '\\' and isSimpleClassEscapeByte(source[index + 1]) and source[index + 2] == '+') {
            index += 3;
            break :blk class_start + 2;
        }
        if (index + 3 < source.len and source[index] == '\\' and source[index + 1] == '\\' and isSimpleClassEscapeByte(source[index + 2]) and source[index + 3] == '+') {
            index += 4;
            break :blk class_start + 3;
        }
        return null;
    };

    const suffix_start = index;
    while (index < source.len and isPlainAsciiRegExpLiteral(source[index])) : (index += 1) {}
    if (index != source.len) return null;
    if (class_start == 0 and suffix_start == source.len) return null;

    return .{
        .prefix = source[0..class_start],
        .class_source = source[class_end - 2 .. class_end],
        .suffix = source[suffix_start..],
    };
}

fn simpleAsciiLiteralClassPlusLiteralMatchBytes(pattern: SimpleAsciiLiteralClassPlusLiteral, input: []const u8) bool {
    var search_start: usize = 0;
    while (search_start <= input.len) {
        const start = if (pattern.prefix.len == 0) search_start else blk: {
            const relative = std.mem.indexOf(u8, input[search_start..], pattern.prefix) orelse return false;
            break :blk search_start + relative;
        };

        var class_end = start + pattern.prefix.len;
        const class_min_end = class_end + 1;
        while (class_end < input.len and builtins.regexp.classMatchesUtf16Unit(pattern.class_source, input[class_end])) : (class_end += 1) {}
        if (class_end >= class_min_end) {
            if (pattern.suffix.len == 0) return true;

            var suffix_start = class_end;
            while (suffix_start >= class_min_end) {
                if (suffix_start + pattern.suffix.len <= input.len and std.mem.eql(u8, input[suffix_start .. suffix_start + pattern.suffix.len], pattern.suffix)) {
                    return true;
                }
                if (suffix_start == class_min_end) break;
                suffix_start -= 1;
            }
        }

        search_start = start + 1;
    }
    return false;
}

fn isPlainAsciiRegExpLiteral(ch: u8) bool {
    if (ch >= '0' and ch <= '9') return true;
    if (ch >= 'A' and ch <= 'Z') return true;
    if (ch >= 'a' and ch <= 'z') return true;
    return switch (ch) {
        '_', ' ' => true,
        else => false,
    };
}

fn regexpBorrowedLatin1SourceFlags(object: *core.Object) ?RegExpBorrowedSourceFlags {
    const source_value = object.regexpSource() orelse return null;
    const flags_value = object.regexpFlags() orelse return null;
    const source = latin1StringSlice(source_value) orelse return null;
    const flags = latin1StringSlice(flags_value) orelse return null;
    return .{ .source = source, .flags = flags };
}

fn latin1StringSlice(value: core.Value) ?[]const u8 {
    const header = value.refHeader() orelse return null;
    if (!value.isString()) return null;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    return switch (string_object.resolveData()) {
        .latin1 => |bytes| bytes,
        .utf16 => null,
    };
}

fn canConstructRegExpFromBorrowedLatin1(pattern: []const u8) bool {
    if (pattern.len == 0) return false;
    for (pattern) |byte| {
        switch (byte) {
            '/', '\n', '\r' => return false,
            else => {},
        }
        if (!byteIsAscii(byte)) return false;
    }
    return true;
}

fn bytesAreAscii(bytes: []const u8) bool {
    for (bytes) |byte| {
        if (!byteIsAscii(byte)) return false;
    }
    return true;
}

fn byteIsAscii(byte: u8) bool {
    return byte < 0x80;
}

fn regExpLastIndexCanSkipCoercion(object: *core.Object) bool {
    const value = object.regexpLastIndex() orelse return false;
    if (value.isObject() or value.isBigInt() or value.isSymbol()) return false;
    return true;
}

pub fn qjsRegExpCompile(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const regexp_object = property_ops.expectObject(this_value) catch return null;
    if (regexp_object.class_id != core.class.ids.regexp) return null;
    const expected_prototype = regExpPrototypeFromGlobal(ctx.runtime, global) orelse
        return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "RegExp object expected"));
    if (regexp_object.getPrototype() != expected_prototype) {
        return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "RegExp object expected"));
    }

    const pattern = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const flags = if (args.len >= 2) args[1] else core.Value.undefinedValue();

    const source_value = blk: {
        if (objectFromValue(pattern)) |pattern_object| {
            if (pattern_object.class_id == core.class.ids.regexp) {
                if (!flags.isUndefined()) return error.TypeError;
                break :blk try regexpInternalStringValue(pattern_object, true);
            }
        }
        if (pattern.isUndefined()) break :blk try value_ops.createStringValue(ctx.runtime, "");
        break :blk try toStringForAnnexB(ctx, output, global, pattern, caller_function, caller_frame);
    };
    defer source_value.free(ctx.runtime);

    const flags_value = blk: {
        if (objectFromValue(pattern)) |pattern_object| {
            if (pattern_object.class_id == core.class.ids.regexp) {
                break :blk try regexpInternalStringValue(pattern_object, false);
            }
        }
        if (flags.isUndefined()) break :blk try value_ops.createStringValue(ctx.runtime, "");
        break :blk try toStringForAnnexB(ctx, output, global, flags, caller_function, caller_frame);
    };
    defer flags_value.free(ctx.runtime);

    var source_bytes = std.ArrayList(u8).empty;
    defer source_bytes.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendValueString(ctx.runtime, &source_bytes, source_value);
    var flag_bytes = std.ArrayList(u8).empty;
    defer flag_bytes.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendValueString(ctx.runtime, &flag_bytes, flags_value);
    if (!builtins.regexp.validatePatternAndFlags(source_bytes.items, flag_bytes.items)) return error.SyntaxError;

    const old_source = regexp_object.regexpSourceSlot().*;
    const old_flags = regexp_object.regexpFlagsSlot().*;
    regexp_object.regexpSourceSlot().* = source_value.dup();
    regexp_object.regexpFlagsSlot().* = flags_value.dup();
    if (old_source) |value| value.free(ctx.runtime);
    if (old_flags) |value| value.free(ctx.runtime);
    regexp_object.clearRegexpCompiledBytecode(ctx.runtime);

    try setValuePropertyStrict(ctx, output, global, this_value, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
    return this_value.dup();
}

fn regexpInternalStringValue(object: *core.Object, source: bool) !core.Value {
    if (source) {
        return (object.regexpSource() orelse return error.TypeError).dup();
    }
    return (object.regexpFlags() orelse return error.TypeError).dup();
}

pub fn qjsRegExpSymbolSearch(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!this_value.isObject()) return error.TypeError;
    const string_input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const string_value = try toStringForAnnexB(ctx, output, global, string_input, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);
    return try qjsRegExpSymbolSearchGeneric(ctx, output, global, this_value, string_value, caller_function, caller_frame);
}

pub fn qjsRegExpSymbolMatch(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!this_value.isObject()) return error.TypeError;
    const string_input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const string_value = try toStringForAnnexB(ctx, output, global, string_input, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);
    return try qjsRegExpSymbolMatchGeneric(ctx, output, global, this_value, string_value, caller_function, caller_frame);
}

pub fn qjsRegExpSymbolMatchAll(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!this_value.isObject()) return error.TypeError;
    const string_input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const string_value = try toStringForAnnexB(ctx, output, global, string_input, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);

    const constructor_value = try qjsRegExpSpeciesConstructor(ctx, output, global, this_value, caller_function, caller_frame);
    defer constructor_value.free(ctx.runtime);

    const flags_atom = core.atom.predefinedId("flags", .string) orelse return error.TypeError;
    const flags_value = try getValueProperty(ctx, output, global, this_value, flags_atom, caller_function, caller_frame);
    defer flags_value.free(ctx.runtime);
    const flags_string = try toStringForAnnexB(ctx, output, global, flags_value, caller_function, caller_frame);
    defer flags_string.free(ctx.runtime);

    const construct_args = [_]core.Value{ this_value, flags_string };
    const matcher = try constructValueOrBytecode(ctx, output, global, constructor_value, &construct_args, caller_function, caller_frame);
    var matcher_owned = true;
    errdefer if (matcher_owned) matcher.free(ctx.runtime);

    const last_index_value = try getValueProperty(ctx, output, global, this_value, core.atom.ids.lastIndex, caller_function, caller_frame);
    defer last_index_value.free(ctx.runtime);
    const last_index = try toLengthIndex(ctx, output, global, last_index_value);
    try setValuePropertyStrict(ctx, output, global, matcher, core.atom.ids.lastIndex, uint32NumberValue(toUint32Number(@floatFromInt(last_index))), caller_function, caller_frame);

    const prototype = try qjsRegExpStringIteratorPrototype(ctx.runtime, global);
    var prototype_owned = true;
    errdefer if (prototype_owned) prototype.value().free(ctx.runtime);
    const iterator = try core.Object.create(ctx.runtime, core.class.ids.regexp_string_iterator, prototype);
    prototype.value().free(ctx.runtime);
    prototype_owned = false;
    errdefer core.Object.destroyFromHeader(ctx.runtime, &iterator.header);
    iterator.iteratorTargetSlot().* = matcher;
    matcher_owned = false;
    iterator.iteratorDataSlot().* = string_value.dup();
    const global_flag = try qjsStringValueContainsByte(ctx.runtime, flags_string, 'g');
    const unicode_flag = try regExpFlagsAreFullUnicode(ctx.runtime, flags_string);
    iterator.iteratorKindSlot().* = (if (global_flag) @as(u8, 1) else 0) | (if (unicode_flag) @as(u8, 2) else 0);
    iterator.iteratorIndexSlot().* = 0;
    return iterator.value();
}

pub fn qjsStringMatchAll(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return throwTypeErrorMessage(ctx, global, "null or undefined are forbidden");
    const string_value = try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);

    const regexp = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const match_all_atom = core.atom.predefinedId("Symbol.matchAll", .symbol) orelse return error.TypeError;
    if (!regexp.isUndefined() and !regexp.isNull() and regexp.isObject()) {
        const matcher = try getValueProperty(ctx, output, global, regexp, match_all_atom, caller_function, caller_frame);
        defer matcher.free(ctx.runtime);
        if (try isRegExpObservable(ctx, output, global, regexp, caller_function, caller_frame)) {
            const flags_atom = core.atom.predefinedId("flags", .string) orelse return error.TypeError;
            const flags_value = try getValueProperty(ctx, output, global, regexp, flags_atom, caller_function, caller_frame);
            defer flags_value.free(ctx.runtime);
            if (flags_value.isUndefined() or flags_value.isNull()) return error.TypeError;
            const flags_string = try toStringForAnnexB(ctx, output, global, flags_value, caller_function, caller_frame);
            defer flags_string.free(ctx.runtime);
            if (!try qjsStringValueContainsByte(ctx.runtime, flags_string, 'g')) return error.TypeError;
        }
        if (!matcher.isUndefined() and !matcher.isNull()) {
            return callValueOrBytecode(ctx, output, global, regexp, matcher, &.{string_value}, caller_function, caller_frame);
        }
    }

    const flags = try value_ops.createStringValue(ctx.runtime, "g");
    defer flags.free(ctx.runtime);
    const matcher = try builtins.regexp.constructWithPrototype(ctx.runtime, regexp, flags, constructorPrototypeFromGlobal(ctx.runtime, global, "RegExp"));
    defer matcher.free(ctx.runtime);
    const match_all = try getValueProperty(ctx, output, global, matcher, match_all_atom, caller_function, caller_frame);
    defer match_all.free(ctx.runtime);
    if (match_all.isUndefined() or match_all.isNull()) return error.TypeError;
    return callValueOrBytecode(ctx, output, global, matcher, match_all, &.{string_value}, caller_function, caller_frame);
}

pub fn qjsRegExpStringIteratorPrototype(rt: *core.Runtime, global: *core.Object) !*core.Object {
    const proto = try qjsIteratorPrototype(rt, global, "RegExp String Iterator");
    errdefer core.Object.destroyFromHeader(rt, &proto.header);
    const next = try builtins.function.nativeFunction(rt, "next", 0);
    defer next.free(rt);
    try proto.defineOwnProperty(rt, core.atom.predefinedId("next", .string).?, core.Descriptor.data(next, true, false, true));
    return proto;
}

pub fn qjsRegExpSymbolReplace(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!this_value.isObject()) return error.TypeError;
    const string_input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const string_value = try toStringForAnnexB(ctx, output, global, string_input, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);
    const replace_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    return try qjsRegExpSymbolReplaceGeneric(ctx, output, global, this_value, string_value, replace_value, caller_function, caller_frame);
}

pub fn qjsRegExpSymbolSplit(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!this_value.isObject()) return error.TypeError;
    const string_input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const string_value = try toStringForAnnexB(ctx, output, global, string_input, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);

    const constructor_value = try qjsRegExpSpeciesConstructor(ctx, output, global, this_value, caller_function, caller_frame);
    defer constructor_value.free(ctx.runtime);
    const flags_string = try qjsRegExpSplitFlags(ctx, output, global, this_value, caller_function, caller_frame);
    defer flags_string.free(ctx.runtime);
    const construct_args = [_]core.Value{ this_value, flags_string };
    const splitter = try constructValueOrBytecode(ctx, output, global, constructor_value, &construct_args, caller_function, caller_frame);
    defer splitter.free(ctx.runtime);

    var limit_value = core.Value.undefinedValue();
    if (args.len >= 2 and !args[1].isUndefined()) {
        const primitive = try toPrimitiveForNumber(ctx, output, global, args[1]);
        defer primitive.free(ctx.runtime);
        if (primitive.isBigInt()) return error.TypeError;
        const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
        defer number_value.free(ctx.runtime);
        const number = value_ops.numberValue(number_value) orelse std.math.nan(f64);
        limit_value = uint32NumberValue(toUint32Number(number));
    }
    const limit = if (limit_value.isUndefined()) std.math.maxInt(u32) else toUint32Number(value_ops.numberValue(limit_value) orelse std.math.nan(f64));
    if (limit == 0) {
        const out = try core.Object.createArray(ctx.runtime, null);
        return out.value();
    }
    const unicode_matching = try regExpFlagsAreFullUnicode(ctx.runtime, flags_string);
    if (try qjsRegExpSymbolSplitGeneric(ctx, output, global, splitter, string_value, limit, unicode_matching, caller_function, caller_frame)) |result| return result;
    if (try qjsRegExpSplit(ctx.runtime, this_value, string_value, limit_value)) |result| return result;
    return try qjsRegExpSplitWholeString(ctx.runtime, string_value);
}

pub fn qjsRegExpSpeciesConstructor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const regexp_atom = try ctx.runtime.internAtom("RegExp");
    defer ctx.runtime.atoms.free(regexp_atom);
    const default_constructor = global.getProperty(regexp_atom);

    const constructor_value = try getValueProperty(ctx, output, global, rx, core.atom.ids.constructor, caller_function, caller_frame);
    defer constructor_value.free(ctx.runtime);
    if (constructor_value.isUndefined()) return default_constructor;
    if (!constructor_value.isObject()) {
        default_constructor.free(ctx.runtime);
        return error.TypeError;
    }

    const species_atom = core.atom.predefinedId("Symbol.species", .symbol) orelse {
        default_constructor.free(ctx.runtime);
        return error.TypeError;
    };
    const species_value = try getValueProperty(ctx, output, global, constructor_value, species_atom, caller_function, caller_frame);
    defer species_value.free(ctx.runtime);
    if (species_value.isUndefined() or species_value.isNull()) return default_constructor;
    default_constructor.free(ctx.runtime);
    return species_value.dup();
}

pub fn isDefaultRegExpConstructor(rt: *core.Runtime, global: *core.Object, value: core.Value) bool {
    const regexp_atom = rt.internAtom("RegExp") catch return false;
    defer rt.atoms.free(regexp_atom);
    const default_constructor = global.getProperty(regexp_atom);
    defer default_constructor.free(rt);
    return sameObjectIdentity(default_constructor, value);
}

pub fn qjsRegExpSplitFlags(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const flags_string = try getRegExpFlagsString(ctx, output, global, rx, caller_function, caller_frame);
    defer flags_string.free(ctx.runtime);

    var flags = std.ArrayList(u8).empty;
    defer flags.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendRawString(ctx.runtime, &flags, flags_string);
    if (std.mem.indexOfScalar(u8, flags.items, 'y') == null) {
        try flags.append(ctx.runtime.memory.allocator, 'y');
    }
    return value_ops.createStringValue(ctx.runtime, flags.items);
}

pub fn qjsStringValueContainsByte(rt: *core.Runtime, string_value: core.Value, needle: u8) !bool {
    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(rt.memory.allocator);
    try value_ops.appendRawString(rt, &bytes, string_value);
    return std.mem.indexOfScalar(u8, bytes.items, needle) != null;
}

fn regExpFlagsAreFullUnicode(rt: *core.Runtime, flags_string: core.Value) !bool {
    return try qjsStringValueContainsByte(rt, flags_string, 'u') or
        try qjsStringValueContainsByte(rt, flags_string, 'v');
}

pub fn qjsRegExpSymbolSplitGeneric(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    splitter: core.Value,
    string_value: core.Value,
    limit: u32,
    unicode_matching: bool,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    var units = std.ArrayList(u16).empty;
    defer units.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &units, string_value);

    const out = try core.Object.createArray(ctx.runtime, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    var out_index: u32 = 0;

    if (units.items.len == 0) {
        const result = qjsRegExpExecGeneric(ctx, output, global, splitter, string_value, caller_function, caller_frame) catch |err| switch (err) {
            error.TypeError => {
                core.Object.destroyFromHeader(ctx.runtime, &out.header);
                return null;
            },
            else => return err,
        };
        defer result.free(ctx.runtime);
        if (result.isNull()) try defineSplitUnitsElement(ctx.runtime, out, out_index, units.items);
        return out.value();
    }

    var start: usize = 0;
    var pos: usize = 0;
    while (pos < units.items.len) {
        try setValuePropertyStrict(ctx, output, global, splitter, core.atom.ids.lastIndex, core.Value.int32(@intCast(pos)), caller_function, caller_frame);
        const result = qjsRegExpExecGeneric(ctx, output, global, splitter, string_value, caller_function, caller_frame) catch |err| switch (err) {
            error.TypeError => {
                core.Object.destroyFromHeader(ctx.runtime, &out.header);
                return null;
            },
            else => return err,
        };
        defer result.free(ctx.runtime);
        if (result.isNull()) {
            pos = advanceStringIndexUnits(units.items, pos, unicode_matching);
            continue;
        }

        const end_value = try getValueProperty(ctx, output, global, splitter, core.atom.ids.lastIndex, caller_function, caller_frame);
        defer end_value.free(ctx.runtime);
        var end = try toLengthIndex(ctx, output, global, end_value);
        if (end > units.items.len) end = units.items.len;
        if (end == start) {
            pos = advanceStringIndexUnits(units.items, pos, unicode_matching);
            continue;
        }

        try defineSplitUnitsElement(ctx.runtime, out, out_index, units.items[start..pos]);
        out_index += 1;
        if (out_index >= limit) return out.value();
        start = end;

        const length_value = try getValueProperty(ctx, output, global, result, core.atom.ids.length, caller_function, caller_frame);
        defer length_value.free(ctx.runtime);
        const capture_limit = try toLengthIndex(ctx, output, global, length_value);
        var capture_index: usize = 1;
        while (capture_index < capture_limit) : (capture_index += 1) {
            const capture = try getValueProperty(ctx, output, global, result, core.atom.atomFromUInt32(@intCast(capture_index)), caller_function, caller_frame);
            defer capture.free(ctx.runtime);
            if (capture.isUndefined()) {
                try defineSplitValueElement(ctx.runtime, out, out_index, core.Value.undefinedValue());
            } else {
                const capture_string = try toStringForAnnexB(ctx, output, global, capture, caller_function, caller_frame);
                defer capture_string.free(ctx.runtime);
                try defineSplitValueElement(ctx.runtime, out, out_index, capture_string);
            }
            out_index += 1;
            if (out_index >= limit) return out.value();
        }
        pos = start;
    }

    const tail_start = @min(start, units.items.len);
    try defineSplitUnitsElement(ctx.runtime, out, out_index, units.items[tail_start..]);
    return out.value();
}

pub fn toLengthIndex(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, value: core.Value) !usize {
    const length = try toLengthNumber(ctx, output, global, value);
    if (length >= @as(f64, @floatFromInt(std.math.maxInt(usize)))) return std.math.maxInt(usize);
    return @intFromFloat(length);
}

pub fn toLengthNumber(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, value: core.Value) !f64 {
    const primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer primitive.free(ctx.runtime);
    if (primitive.isBigInt()) return error.TypeError;
    const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
    defer number_value.free(ctx.runtime);
    const number = value_ops.numberValue(number_value) orelse std.math.nan(f64);
    if (std.math.isNan(number) or number <= 0) return 0;
    const max_length = 9007199254740991.0;
    if (number >= max_length) return max_length;
    return @floor(number);
}

pub fn advanceStringIndexUnits(units: []const u16, index: usize, unicode: bool) usize {
    if (!unicode or index + 1 >= units.len) return index + 1;
    const first = units[index];
    if (first < 0xd800 or first > 0xdbff) return index + 1;
    const second = units[index + 1];
    return if (second >= 0xdc00 and second <= 0xdfff) index + 2 else index + 1;
}

pub fn qjsRegExpSymbolSearchGeneric(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    string_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const previous = try getValueProperty(ctx, output, global, rx, core.atom.ids.lastIndex, caller_function, caller_frame);
    defer previous.free(ctx.runtime);
    if (!builtins.object.sameValue(previous, core.Value.int32(0))) {
        try setValuePropertyStrict(ctx, output, global, rx, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
    }

    const result = if (try qjsRegExpExecSimpleUnicodeLiteral(ctx, output, global, rx, string_value, caller_function, caller_frame)) |value|
        value
    else
        try qjsRegExpExecGeneric(ctx, output, global, rx, string_value, caller_function, caller_frame);
    defer result.free(ctx.runtime);

    const current = try getValueProperty(ctx, output, global, rx, core.atom.ids.lastIndex, caller_function, caller_frame);
    defer current.free(ctx.runtime);
    if (!builtins.object.sameValue(current, previous)) {
        try setValuePropertyStrict(ctx, output, global, rx, core.atom.ids.lastIndex, previous, caller_function, caller_frame);
    }

    if (result.isNull()) return core.Value.int32(-1);
    if (!result.isObject()) return error.TypeError;
    const index_atom = core.atom.predefinedId("index", .string) orelse return error.TypeError;
    return getValueProperty(ctx, output, global, result, index_atom, caller_function, caller_frame);
}

pub fn qjsRegExpSymbolMatchGeneric(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    string_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const flags_string = try getRegExpFlagsString(ctx, output, global, rx, caller_function, caller_frame);
    defer flags_string.free(ctx.runtime);

    var flags = std.ArrayList(u8).empty;
    defer flags.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendRawString(ctx.runtime, &flags, flags_string);
    if (std.mem.indexOfScalar(u8, flags.items, 'g') == null) {
        if (try qjsRegExpExecSimpleUnicodeLiteral(ctx, output, global, rx, string_value, caller_function, caller_frame)) |value| return value;
        return qjsRegExpExecGeneric(ctx, output, global, rx, string_value, caller_function, caller_frame);
    }

    const full_unicode = try regExpFlagsAreFullUnicode(ctx.runtime, flags_string);
    try setValuePropertyStrict(ctx, output, global, rx, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);

    const out = try core.Object.createArray(ctx.runtime, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    var count: u32 = 0;
    while (true) {
        const result = try qjsRegExpExecGeneric(ctx, output, global, rx, string_value, caller_function, caller_frame);
        defer result.free(ctx.runtime);
        if (result.isNull()) break;
        const zero_value = try getValueProperty(ctx, output, global, result, core.atom.atomFromUInt32(0), caller_function, caller_frame);
        defer zero_value.free(ctx.runtime);
        const match_string = try toStringForAnnexB(ctx, output, global, zero_value, caller_function, caller_frame);
        defer match_string.free(ctx.runtime);
        try out.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(count), core.Descriptor.data(match_string, true, true, true));
        count += 1;
        if (isEmptyStringValue(ctx.runtime, match_string)) {
            const last_index = try getValueProperty(ctx, output, global, rx, core.atom.ids.lastIndex, caller_function, caller_frame);
            defer last_index.free(ctx.runtime);
            const next = try advanceStringIndexNumber(ctx, output, global, string_value, last_index, full_unicode);
            try setValuePropertyStrict(ctx, output, global, rx, core.atom.ids.lastIndex, next, caller_function, caller_frame);
        }
    }
    if (count == 0) return core.Value.nullValue();
    return out.value();
}

pub fn qjsRegExpExecSimpleUnicodeLiteral(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    string_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const regexp_object = property_ops.expectObject(rx) catch return null;
    if (regexp_object.class_id != core.class.ids.regexp) return null;
    var source = std.ArrayList(u8).empty;
    defer source.deinit(ctx.runtime.memory.allocator);
    if (!try appendRegExpSource(ctx.runtime, regexp_object, &source)) return null;
    if (!isSimpleUnicodeLiteralSource(source.items)) return null;
    return (try qjsRegExpExecResult(ctx, output, global, rx, regexp_object, string_value, true, caller_function, caller_frame)) orelse null;
}

const ReplaceMatch = struct {
    result: core.Value,
    matched: core.Value,
    index: usize,
    captures: []core.Value,
    groups: core.Value,
};

pub fn qjsRegExpSymbolReplaceGeneric(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    string_value: core.Value,
    replace_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const functional_replace = isCallableValue(replace_value);
    const replacement_string = if (functional_replace)
        core.Value.undefinedValue()
    else
        try toStringForAnnexB(ctx, output, global, replace_value, caller_function, caller_frame);
    defer if (!functional_replace) replacement_string.free(ctx.runtime);

    const flags_string = try getRegExpFlagsStringForReplace(ctx, output, global, rx, caller_function, caller_frame);
    defer flags_string.free(ctx.runtime);
    const is_global = try qjsStringValueContainsByte(ctx.runtime, flags_string, 'g');
    const full_unicode = try regExpFlagsAreFullUnicode(ctx.runtime, flags_string);
    if (is_global) {
        try setValuePropertyStrict(ctx, output, global, rx, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
    }
    if (is_global and !functional_replace) {
        if (objectFromValue(rx)) |regexp_object| {
            var source = std.ArrayList(u8).empty;
            defer source.deinit(ctx.runtime.memory.allocator);
            if (try appendRegExpSource(ctx.runtime, regexp_object, &source)) {
                if (replaceSingleUnitGlobalSimpleClassEscape(string_value, replacement_string, source.items)) |fast| return fast;
                if (try replaceGlobalSimpleClassEscape(ctx.runtime, string_value, replacement_string, source.items)) |fast| return fast;
            }
            if (try replaceGlobalSimpleCaptureSequence(ctx, output, global, rx, regexp_object, string_value, replacement_string, flags_string, caller_function, caller_frame)) |fast| return fast;
        }
    }

    var matches = std.ArrayList(ReplaceMatch).empty;
    defer matches.deinit(ctx.runtime.memory.allocator);
    defer {
        freeReplaceMatches(ctx.runtime, matches.items);
    }

    while (true) {
        const result = try qjsRegExpExecGeneric(ctx, output, global, rx, string_value, caller_function, caller_frame);
        if (result.isNull()) {
            result.free(ctx.runtime);
            break;
        }
        if (!result.isObject()) {
            result.free(ctx.runtime);
            return error.TypeError;
        }
        const match = try captureReplaceMatch(ctx, output, global, result, string_value, caller_function, caller_frame);
        try matches.append(ctx.runtime.memory.allocator, match);
        if (!is_global) break;
        if (isEmptyStringValue(ctx.runtime, match.matched)) {
            const last_index = try getValueProperty(ctx, output, global, rx, core.atom.ids.lastIndex, caller_function, caller_frame);
            defer last_index.free(ctx.runtime);
            const next = try advanceStringIndexNumber(ctx, output, global, string_value, last_index, full_unicode);
            try setValuePropertyStrict(ctx, output, global, rx, core.atom.ids.lastIndex, next, caller_function, caller_frame);
        }
    }
    if (matches.items.len == 0) return string_value.dup();

    var source_units = std.ArrayList(u16).empty;
    defer source_units.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &source_units, string_value);

    var out = std.ArrayList(u16).empty;
    defer out.deinit(ctx.runtime.memory.allocator);
    var next_source_position: usize = 0;
    for (matches.items) |match| {
        const matched_len = try stringLengthIndex(ctx.runtime, match.matched);
        const position = @min(match.index, source_units.items.len);
        if (position < next_source_position) continue;
        try out.appendSlice(ctx.runtime.memory.allocator, source_units.items[next_source_position..position]);

        const replacement = if (functional_replace)
            try callReplaceFunction(ctx, output, global, replace_value, match, string_value, caller_function, caller_frame)
        else
            try getSubstitutionString(ctx, output, global, match, string_value, replacement_string, caller_function, caller_frame);
        defer replacement.free(ctx.runtime);
        try appendStringValueUnits(ctx.runtime, &out, replacement);
        next_source_position = @min(source_units.items.len, position + matched_len);
    }
    try out.appendSlice(ctx.runtime.memory.allocator, source_units.items[next_source_position..]);
    return (try core.string.String.createUtf16(ctx.runtime, out.items)).value();
}

pub fn replaceSingleUnitGlobalSimpleClassEscape(
    string_value: core.Value,
    replacement_string: core.Value,
    source: []const u8,
) ?core.Value {
    if (!classEscapeIsQuantified(source) or !isSimpleStringClassEscapeSource(source)) return null;
    const header = string_value.refHeader() orelse return null;
    if (!string_value.isString()) return null;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    const unit = switch (string_object.resolveData()) {
        .latin1 => |bytes| blk: {
            if (bytes.len != 1) return null;
            break :blk @as(u16, bytes[0]);
        },
        .utf16 => |units| blk: {
            if (units.len != 1) return null;
            break :blk units[0];
        },
    };
    return if (classEscapeUnitMatches(source, unit)) replacement_string.dup() else string_value.dup();
}

pub fn replaceGlobalSimpleClassEscape(
    rt: *core.Runtime,
    string_value: core.Value,
    replacement_string: core.Value,
    source: []const u8,
) !?core.Value {
    if (!classEscapeIsQuantified(source) or !isSimpleStringClassEscapeSource(source)) return null;
    const header = string_value.refHeader() orelse return null;
    if (!string_value.isString()) return null;
    const string_object: *core.string.String = @fieldParentPtr("header", header);

    var replacement_units = std.ArrayList(u16).empty;
    defer replacement_units.deinit(rt.memory.allocator);
    try appendStringValueUnits(rt, &replacement_units, replacement_string);

    var out = std.ArrayList(u16).empty;
    defer out.deinit(rt.memory.allocator);
    switch (string_object.resolveData()) {
        .latin1 => |bytes| {
            var index: usize = 0;
            while (index < bytes.len) {
                const unit: u16 = bytes[index];
                if (classEscapeUnitMatches(source, unit)) {
                    try out.appendSlice(rt.memory.allocator, replacement_units.items);
                    index += classEscapeRunLengthLatin1(source, bytes, index);
                } else {
                    try out.append(rt.memory.allocator, unit);
                    index += 1;
                }
            }
        },
        .utf16 => |units| {
            var index: usize = 0;
            while (index < units.len) {
                const unit = units[index];
                if (classEscapeUnitMatches(source, unit)) {
                    try out.appendSlice(rt.memory.allocator, replacement_units.items);
                    index += classEscapeRunLengthUtf16(source, units, index);
                } else {
                    try out.append(rt.memory.allocator, unit);
                    index += 1;
                }
            }
        },
    }
    return (try core.string.String.createUtf16(rt, out.items)).value();
}

const FastReplacementPart = union(enum) {
    literal: []const u8,
    capture: usize,
    dollar,
};

const FastReplacementPattern = struct {
    parts: [32]FastReplacementPart = undefined,
    len: usize = 0,

    fn append(self: *FastReplacementPattern, part: FastReplacementPart) bool {
        if (self.len >= self.parts.len) return false;
        self.parts[self.len] = part;
        self.len += 1;
        return true;
    }
};

fn replaceGlobalSimpleCaptureSequence(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    regexp_object: *core.Object,
    string_value: core.Value,
    replacement_string: core.Value,
    flags_string: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const borrowed = regexpBorrowedLatin1SourceFlags(regexp_object) orelse return null;
    const observed_flags = latin1StringSlice(flags_string) orelse return null;
    if (!std.mem.eql(u8, observed_flags, borrowed.flags)) return null;
    if (std.mem.indexOfScalar(u8, borrowed.flags, 'g') == null) return null;
    if (std.mem.indexOfScalar(u8, borrowed.flags, 'y') != null) return null;
    if (!try regExpExecPropertyIsDefault(ctx, output, global, rx, caller_function, caller_frame)) return null;

    const pattern = regexpSimpleCaptureSequencePattern(regexp_object, borrowed.source, borrowed.flags) orelse return null;
    const input = latin1StringSlice(string_value) orelse return null;
    const replacement = latin1StringSlice(replacement_string) orelse return null;
    const replacement_pattern = parseFastReplacementPattern(replacement, pattern.capture_count) orelse return null;

    var out = std.ArrayList(u8).empty;
    defer out.deinit(ctx.runtime.memory.allocator);
    var next_source_position: usize = 0;
    var search_start: usize = 0;
    var last_match: ?RegExpMatch = null;

    while (search_start <= input.len) {
        const found = simpleCaptureSequenceMatchLatin1(pattern, input, search_start, false, borrowed.flags) orelse break;
        if (found.index < next_source_position) break;
        try out.appendSlice(ctx.runtime.memory.allocator, input[next_source_position..found.index]);
        try appendFastReplacement(ctx.runtime, &out, input, found, replacement_pattern);
        next_source_position = found.index + found.len;
        last_match = found;
        search_start = if (found.len == 0) @min(input.len + 1, found.index + 1) else next_source_position;
    }

    const final_match = last_match orelse return string_value.dup();
    try out.appendSlice(ctx.runtime.memory.allocator, input[next_source_position..]);
    try updateRegExpLegacyStaticsForMatch(ctx.runtime, global, string_value, final_match);
    return (try core.string.String.createLatin1(ctx.runtime, out.items)).value();
}

fn regExpExecPropertyIsDefault(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    const exec_atom = core.atom.predefinedId("exec", .string) orelse return false;
    const exec_value = try getValueProperty(ctx, output, global, rx, exec_atom, caller_function, caller_frame);
    defer exec_value.free(ctx.runtime);
    const exec_object = objectFromValue(exec_value) orelse return false;
    const native_ref = core.function.decodeNativeBuiltinId(exec_object.nativeFunctionId()) orelse return false;
    return native_ref.domain == .regexp and native_ref.id == @intFromEnum(builtins.regexp.PrototypeMethod.exec);
}

fn parseFastReplacementPattern(replacement: []const u8, capture_count: usize) ?FastReplacementPattern {
    var pattern = FastReplacementPattern{};
    var literal_start: usize = 0;
    var index: usize = 0;
    while (index < replacement.len) {
        if (replacement[index] != '$') {
            index += 1;
            continue;
        }
        if (index + 1 >= replacement.len) return null;
        const next = replacement[index + 1];
        switch (next) {
            '$' => {
                if (literal_start < index and !pattern.append(.{ .literal = replacement[literal_start..index] })) return null;
                if (!pattern.append(.dollar)) return null;
                index += 2;
                literal_start = index;
            },
            '1'...'9' => {
                var capture_index: usize = next - '0';
                var consumed: usize = 1;
                if (index + 2 < replacement.len and std.ascii.isDigit(replacement[index + 2])) {
                    const two_digit = capture_index * 10 + (replacement[index + 2] - '0');
                    if (two_digit >= 1 and two_digit <= capture_count) {
                        capture_index = two_digit;
                        consumed = 2;
                    }
                }
                if (capture_index == 0 or capture_index > capture_count) return null;
                if (literal_start < index and !pattern.append(.{ .literal = replacement[literal_start..index] })) return null;
                if (!pattern.append(.{ .capture = capture_index - 1 })) return null;
                index += 1 + consumed;
                literal_start = index;
            },
            else => return null,
        }
    }
    if (literal_start < replacement.len and !pattern.append(.{ .literal = replacement[literal_start..] })) return null;
    return pattern;
}

fn appendFastReplacement(rt: *core.Runtime, out: *std.ArrayList(u8), input: []const u8, found: RegExpMatch, replacement: FastReplacementPattern) !void {
    for (replacement.parts[0..replacement.len]) |part| {
        switch (part) {
            .literal => |bytes| try out.appendSlice(rt.memory.allocator, bytes),
            .dollar => try out.append(rt.memory.allocator, '$'),
            .capture => |capture_index| {
                if (capture_index >= found.capture_count) continue;
                const capture = found.captures[capture_index];
                if (capture.undefined) continue;
                try out.appendSlice(rt.memory.allocator, input[capture.start .. capture.start + capture.len]);
            },
        }
    }
}

pub fn appendStringValueUnits(rt: *core.Runtime, out: *std.ArrayList(u16), value: core.Value) !void {
    const header = value.refHeader() orelse {
        var bytes = std.ArrayList(u8).empty;
        defer bytes.deinit(rt.memory.allocator);
        try value_ops.appendRawString(rt, &bytes, value);
        for (bytes.items) |byte| try out.append(rt.memory.allocator, byte);
        return;
    };
    if (!value.isString()) {
        var bytes = std.ArrayList(u8).empty;
        defer bytes.deinit(rt.memory.allocator);
        try value_ops.appendRawString(rt, &bytes, value);
        for (bytes.items) |byte| try out.append(rt.memory.allocator, byte);
        return;
    }
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    switch (string_object.resolveData()) {
        .latin1 => |bytes| for (bytes) |byte| try out.append(rt.memory.allocator, byte),
        .utf16 => |units| try out.appendSlice(rt.memory.allocator, units),
    }
}

fn regexpInternalFlagsContain(regexp_object: *core.Object, needle: u8) bool {
    if (regexp_object.regexpFlags()) |flags_value| return stringValueContainsUnitByte(flags_value, needle);
    return false;
}

fn regexpInternalSimpleQuantifiedClassSource(regexp_object: *core.Object) ?[]const u8 {
    if (regexp_object.regexpSource()) |source_value| return simpleQuantifiedClassSourceFromValue(source_value);
    return null;
}

pub fn simpleQuantifiedClassSourceFromValue(source_value: core.Value) ?[]const u8 {
    const sources = [_][]const u8{
        "\\d+",   "\\D+",   "\\s+",   "\\S+",   "\\w+",   "\\W+",
        "\\\\d+", "\\\\D+", "\\\\s+", "\\\\S+", "\\\\w+", "\\\\W+",
    };
    for (sources) |source| {
        if (stringValueUnitsEqualBytes(source_value, source)) return source;
    }
    return null;
}

pub fn stringValueContainsUnitByte(value: core.Value, needle: u8) bool {
    if (!value.isString()) return false;
    const header = value.refHeader() orelse return false;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    return switch (string_object.resolveData()) {
        .latin1 => |bytes| std.mem.indexOfScalar(u8, bytes, needle) != null,
        .utf16 => |units| blk: {
            for (units) |unit| {
                if (unit == needle) break :blk true;
            }
            break :blk false;
        },
    };
}

pub fn stringValueUnitsEqualBytes(value: core.Value, expected: []const u8) bool {
    if (!value.isString()) return false;
    const header = value.refHeader() orelse return false;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    return switch (string_object.resolveData()) {
        .latin1 => |bytes| std.mem.eql(u8, bytes, expected),
        .utf16 => |units| blk: {
            if (units.len != expected.len) break :blk false;
            for (units, expected) |unit, byte| {
                if (unit != byte) break :blk false;
            }
            break :blk true;
        },
    };
}

pub fn setRegExpLastIndexZero(rt: *core.Runtime, regexp_object: *core.Object) !void {
    regexp_object.setProperty(rt, core.atom.ids.lastIndex, core.Value.int32(0)) catch |err| switch (err) {
        error.ReadOnly, error.AccessorWithoutSetter, error.NotExtensible => return error.TypeError,
        else => return err,
    };
}

pub fn getRegExpFlagsStringForReplace(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    return getRegExpFlagsString(ctx, output, global, rx, caller_function, caller_frame);
}

pub fn getRegExpFlagsString(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const flags_atom = try ctx.runtime.internAtom("flags");
    defer ctx.runtime.atoms.free(flags_atom);
    const flags_value = try getValueProperty(ctx, output, global, rx, flags_atom, caller_function, caller_frame);
    defer flags_value.free(ctx.runtime);
    return toStringForAnnexB(ctx, output, global, flags_value, caller_function, caller_frame);
}

pub fn captureReplaceMatch(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    result: core.Value,
    string_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !ReplaceMatch {
    errdefer result.free(ctx.runtime);
    const matched_value = try getValueProperty(ctx, output, global, result, core.atom.atomFromUInt32(0), caller_function, caller_frame);
    errdefer matched_value.free(ctx.runtime);
    const matched = try toStringForAnnexB(ctx, output, global, matched_value, caller_function, caller_frame);
    matched_value.free(ctx.runtime);
    errdefer matched.free(ctx.runtime);

    const index_atom = core.atom.predefinedId("index", .string) orelse return error.TypeError;
    const index_value = try getValueProperty(ctx, output, global, result, index_atom, caller_function, caller_frame);
    defer index_value.free(ctx.runtime);
    const string_len = try stringLengthIndex(ctx.runtime, string_value);
    const index = @min(try toLengthIndex(ctx, output, global, index_value), string_len);

    const length_value = try getValueProperty(ctx, output, global, result, core.atom.ids.length, caller_function, caller_frame);
    defer length_value.free(ctx.runtime);
    const length = try toLengthIndex(ctx, output, global, length_value);
    const capture_count = if (length == 0) 0 else length - 1;
    var captures: []core.Value = &.{};
    if (capture_count != 0) {
        captures = try ctx.runtime.memory.alloc(core.Value, capture_count);
        errdefer ctx.runtime.memory.free(core.Value, captures);
        var initialized: usize = 0;
        errdefer {
            for (captures[0..initialized]) |capture| capture.free(ctx.runtime);
        }
        while (initialized < capture_count) : (initialized += 1) {
            const capture = try getValueProperty(ctx, output, global, result, core.atom.atomFromUInt32(@intCast(initialized + 1)), caller_function, caller_frame);
            if (capture.isUndefined()) {
                captures[initialized] = capture;
            } else {
                const capture_string = try toStringForAnnexB(ctx, output, global, capture, caller_function, caller_frame);
                capture.free(ctx.runtime);
                captures[initialized] = capture_string;
            }
        }
    }

    const groups_atom = core.atom.predefinedId("groups", .string) orelse return error.TypeError;
    const groups = try getValueProperty(ctx, output, global, result, groups_atom, caller_function, caller_frame);
    errdefer groups.free(ctx.runtime);
    return .{ .result = result, .matched = matched, .index = index, .captures = captures, .groups = groups };
}

pub fn freeReplaceMatches(rt: *core.Runtime, matches: []ReplaceMatch) void {
    for (matches) |match| {
        match.result.free(rt);
        match.matched.free(rt);
        for (match.captures) |capture| capture.free(rt);
        if (match.captures.len != 0) rt.memory.free(core.Value, match.captures);
        match.groups.free(rt);
    }
}

pub fn callReplaceFunction(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    replacer: core.Value,
    match: ReplaceMatch,
    string_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const extra: usize = if (match.groups.isUndefined()) 2 else 3;
    const arg_count = 1 + match.captures.len + extra;
    const args = try ctx.runtime.memory.alloc(core.Value, arg_count);
    defer ctx.runtime.memory.free(core.Value, args);
    args[0] = match.matched;
    for (match.captures, 0..) |capture, index| args[index + 1] = capture;
    args[1 + match.captures.len] = core.Value.int32(@intCast(match.index));
    args[2 + match.captures.len] = string_value;
    if (!match.groups.isUndefined()) args[3 + match.captures.len] = match.groups;
    const result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), replacer, args, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    return toStringForAnnexB(ctx, output, global, result, caller_function, caller_frame);
}

pub fn getSubstitutionString(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    match: ReplaceMatch,
    string_value: core.Value,
    replacement_string: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const named_captures = if (match.groups.isUndefined())
        core.Value.undefinedValue()
    else if (match.groups.isNull())
        return error.TypeError
    else if (match.groups.isObject())
        match.groups.dup()
    else
        try primitiveObjectForAccess(ctx.runtime, global, match.groups);
    defer if (!named_captures.isUndefined()) named_captures.free(ctx.runtime);

    var source = std.ArrayList(u16).empty;
    defer source.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &source, string_value);
    var matched = std.ArrayList(u16).empty;
    defer matched.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &matched, match.matched);
    var replacement = std.ArrayList(u16).empty;
    defer replacement.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &replacement, replacement_string);

    var out = std.ArrayList(u16).empty;
    defer out.deinit(ctx.runtime.memory.allocator);
    var index: usize = 0;
    while (index < replacement.items.len) : (index += 1) {
        if (replacement.items[index] != '$' or index + 1 >= replacement.items.len) {
            try out.append(ctx.runtime.memory.allocator, replacement.items[index]);
            continue;
        }
        const next = replacement.items[index + 1];
        switch (next) {
            '$' => {
                try out.append(ctx.runtime.memory.allocator, '$');
                index += 1;
            },
            '&' => {
                try out.appendSlice(ctx.runtime.memory.allocator, matched.items);
                index += 1;
            },
            '`' => {
                try out.appendSlice(ctx.runtime.memory.allocator, source.items[0..@min(match.index, source.items.len)]);
                index += 1;
            },
            '\'' => {
                const tail_start = @min(source.items.len, match.index + matched.items.len);
                try out.appendSlice(ctx.runtime.memory.allocator, source.items[tail_start..]);
                index += 1;
            },
            '0'...'9' => {
                const capture = replacementCaptureUnits(match, replacement.items, &index) orelse {
                    try out.append(ctx.runtime.memory.allocator, '$');
                    continue;
                };
                if (!capture.isUndefined()) try appendStringValueUnits(ctx.runtime, &out, capture);
            },
            '<' => {
                if (try appendNamedCaptureSubstitution(ctx, output, global, named_captures, replacement.items, &index, &out, caller_function, caller_frame)) continue;
                try out.append(ctx.runtime.memory.allocator, '$');
            },
            else => try out.append(ctx.runtime.memory.allocator, '$'),
        }
    }
    return (try core.string.String.createUtf16(ctx.runtime, out.items)).value();
}

pub fn appendNamedCaptureSubstitution(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    named_captures: core.Value,
    replacement: []const u16,
    index: *usize,
    out: *std.ArrayList(u16),
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    if (named_captures.isUndefined()) return false;
    const name_start = index.* + 2;
    const name_end = std.mem.indexOfScalarPos(u16, replacement, name_start, '>') orelse return false;
    var name = std.ArrayList(u8).empty;
    defer name.deinit(ctx.runtime.memory.allocator);
    try appendUtf16UnitsAsUtf8(ctx.runtime, &name, replacement[name_start..name_end]);
    const atom = try ctx.runtime.internAtom(name.items);
    defer ctx.runtime.atoms.free(atom);
    const capture = try getValueProperty(ctx, output, global, named_captures, atom, caller_function, caller_frame);
    defer capture.free(ctx.runtime);
    if (!capture.isUndefined()) {
        const capture_string = try toStringForAnnexB(ctx, output, global, capture, caller_function, caller_frame);
        defer capture_string.free(ctx.runtime);
        try appendStringValueUnits(ctx.runtime, out, capture_string);
    }
    index.* = name_end;
    return true;
}

fn appendUtf16UnitsAsUtf8(rt: *core.Runtime, buffer: *std.ArrayList(u8), units: []const u16) !void {
    var index: usize = 0;
    while (index < units.len) : (index += 1) {
        const unit = units[index];
        if (unit >= 0xd800 and unit <= 0xdbff and index + 1 < units.len) {
            const next = units[index + 1];
            if (next >= 0xdc00 and next <= 0xdfff) {
                try appendCodepointUtf8(rt, buffer, codePointFromSurrogatePair(unit, next));
                index += 1;
                continue;
            }
        }
        try appendCodepointUtf8(rt, buffer, @intCast(unit));
    }
}

pub fn replacementCaptureUnits(match: ReplaceMatch, replacement: []const u16, index: *usize) ?core.Value {
    const first = replacement[index.* + 1];
    if (!isAsciiDigitUnit(first)) return null;
    if (first == '0') {
        if (index.* + 2 >= replacement.len or !isAsciiDigitUnit(replacement[index.* + 2])) return null;
        const two_digit: usize = @intCast(replacement[index.* + 2] - '0');
        if (two_digit == 0 or two_digit > match.captures.len) return null;
        index.* += 2;
        return match.captures[two_digit - 1];
    }
    var capture_index: usize = @intCast(first - '0');
    var consumed: usize = 1;
    if (index.* + 2 < replacement.len and isAsciiDigitUnit(replacement[index.* + 2])) {
        const two_digit = capture_index * 10 + @as(usize, @intCast(replacement[index.* + 2] - '0'));
        if (two_digit >= 1 and two_digit <= match.captures.len) {
            capture_index = two_digit;
            consumed = 2;
        }
    }
    if (capture_index == 0 or capture_index > match.captures.len) return null;
    index.* += consumed;
    return match.captures[capture_index - 1];
}

pub fn stringLengthIndex(rt: *core.Runtime, string_value: core.Value) !usize {
    const header = string_value.refHeader() orelse return 0;
    if (!string_value.isString()) return 0;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    _ = rt;
    return string_object.len();
}

pub fn isEmptyStringValue(rt: *core.Runtime, value: core.Value) bool {
    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(rt.memory.allocator);
    value_ops.appendRawString(rt, &bytes, value) catch return false;
    return bytes.items.len == 0;
}

pub fn advanceStringIndexNumber(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    string_value: core.Value,
    index_value: core.Value,
    unicode: bool,
) !core.Value {
    const index_number = try toLengthNumber(ctx, output, global, index_value);
    if (!unicode or index_number >= @as(f64, @floatFromInt(std.math.maxInt(usize)))) {
        return value_ops.numberToValue(index_number + 1);
    }
    const index: usize = @intFromFloat(index_number);
    const header = string_value.refHeader() orelse return value_ops.numberToValue(index_number + 1);
    if (!string_value.isString()) return value_ops.numberToValue(index_number + 1);
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    if (index + 1 >= string_object.len()) return value_ops.numberToValue(index_number + 1);
    const first = string_object.codeUnitAt(index);
    const second = string_object.codeUnitAt(index + 1);
    if (isHighSurrogateUnit(first) and isLowSurrogateUnit(second)) {
        return value_ops.numberToValue(index_number + 2);
    }
    return value_ops.numberToValue(index_number + 1);
}

pub fn qjsRegExpExecGeneric(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    rx: core.Value,
    string_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const exec_atom = core.atom.predefinedId("exec", .string) orelse return error.TypeError;
    const exec_method = try getValueProperty(ctx, output, global, rx, exec_atom, caller_function, caller_frame);
    defer exec_method.free(ctx.runtime);
    if (!exec_method.isUndefined() and !exec_method.isNull()) {
        if (isCallableValue(exec_method)) {
            const result = try callValueOrBytecode(ctx, output, global, rx, exec_method, &.{string_value}, caller_function, caller_frame);
            if (!result.isNull() and !result.isObject()) {
                result.free(ctx.runtime);
                return error.TypeError;
            }
            return result;
        }
        const rx_object = objectFromValue(rx) orelse return error.TypeError;
        if (rx_object.class_id != core.class.ids.regexp) return error.TypeError;
    }
    return (try qjsRegExpExecMethod(ctx, output, global, rx, &.{string_value}, caller_function, caller_frame)) orelse error.TypeError;
}

pub fn setValuePropertyStrict(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object_value: core.Value,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const object = try property_ops.expectObject(object_value);
    const value_to_set = try arrayLengthAssignmentValue(ctx, output, global, object, atom_id, value, caller_function, caller_frame);
    defer if (!value_to_set.same(value)) value_to_set.free(ctx.runtime);
    if (builtins.buffer.isTypedArrayObject(object)) {
        if (try typedArrayCanonicalSet(ctx, output, global, object, atom_id, value_to_set)) return;
    }
    const called_setter = callAccessorSetter(ctx, output, global, object_value, object, atom_id, value, caller_function, caller_frame) catch |err| switch (err) {
        error.AccessorWithoutSetter => return error.TypeError,
        else => return err,
    };
    if (called_setter) return;
    object.setProperty(ctx.runtime, atom_id, value_to_set) catch |err| switch (err) {
        error.ReadOnly, error.AccessorWithoutSetter, error.NotExtensible => return error.TypeError,
        error.InvalidLength => return error.RangeError,
        else => return err,
    };
}

pub fn qjsRegExpAccessor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    getter_value: core.Value,
    name: []const u8,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (std.mem.eql(u8, name, "flags")) {
        if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
        if (!this_value.isObject()) return error.TypeError;
        var flags = std.ArrayList(u8).empty;
        defer flags.deinit(ctx.runtime.memory.allocator);
        const names = [_][]const u8{ "hasIndices", "global", "ignoreCase", "multiline", "dotAll", "unicode", "unicodeSets", "sticky" };
        const chars = [_]u8{ 'd', 'g', 'i', 'm', 's', 'u', 'v', 'y' };
        for (names, chars) |prop_name, flag_char| {
            const atom = try ctx.runtime.internAtom(prop_name);
            defer ctx.runtime.atoms.free(atom);
            const value = try getValueProperty(ctx, output, global, this_value, atom, caller_function, caller_frame);
            defer value.free(ctx.runtime);
            if (valueTruthy(value)) try flags.append(ctx.runtime.memory.allocator, flag_char);
        }
        return (try core.string.String.createUtf8(ctx.runtime, flags.items)).value();
    }
    const object = property_ops.expectObject(this_value) catch return null;
    if (std.mem.eql(u8, name, "source")) {
        if (try isSameRealmRegExpPrototypeGetter(ctx.runtime, global, object, name, getter_value)) return try value_ops.createStringValue(ctx.runtime, "(?:)");
        if (!objectHasRegExpInternalSlots(object)) return throwRegExpAccessorTypeError(ctx, global, getter_value);
        return null;
    }
    if (!std.mem.eql(u8, name, "source")) {
        if (try isSameRealmRegExpPrototypeGetter(ctx.runtime, global, object, name, getter_value)) return core.Value.undefinedValue();
        if (!objectHasRegExpInternalSlots(object)) return throwRegExpAccessorTypeError(ctx, global, getter_value);
    }
    return null;
}

pub fn qjsRegExpLegacyAccessor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    function_object: *core.Object,
    method: builtins.regexp.LegacyAccessorMethod,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const owner_global = function_object.functionRealmGlobalPtr() orelse global;
    const regexp_ctor = try regExpConstructorFromGlobal(ctx.runtime, owner_global);
    const receiver = objectFromValue(this_value) orelse return throwTypeErrorMessage(ctx, owner_global, "RegExp legacy accessor receiver mismatch");
    if (receiver != regexp_ctor) return throwTypeErrorMessage(ctx, owner_global, "RegExp legacy accessor receiver mismatch");

    const legacy = try regexp_ctor.ensureRegExpLegacyStatics(ctx.runtime);
    switch (method) {
        .set_input => {
            try materializeRegExpLegacyNoCaptureSlots(ctx.runtime, legacy);
            const input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            const string_value = try toStringForAnnexB(ctx, output, owner_global, input, caller_function, caller_frame);
            defer string_value.free(ctx.runtime);
            replaceRegExpLegacySlot(ctx.runtime, &legacy.input, string_value);
            return core.Value.undefinedValue();
        },
        .get_input => return regExpLegacySlotValue(ctx.runtime, legacy.input),
        .get_last_match => return regExpLegacyNoCaptureSliceValue(ctx.runtime, legacy, .match) orelse regExpLegacySlotValue(ctx.runtime, legacy.last_match),
        .get_last_paren => return regExpLegacySlotValue(ctx.runtime, legacy.last_paren),
        .get_left_context => return regExpLegacyNoCaptureSliceValue(ctx.runtime, legacy, .left) orelse regExpLegacySlotValue(ctx.runtime, legacy.left_context),
        .get_right_context => return regExpLegacyNoCaptureSliceValue(ctx.runtime, legacy, .right) orelse regExpLegacySlotValue(ctx.runtime, legacy.right_context),
        else => {
            const capture_index = builtins.regexp.legacyCaptureIndex(method) orelse return error.TypeError;
            return regExpLegacySlotValue(ctx.runtime, legacy.captures[capture_index]);
        },
    }
}

fn regExpConstructorFromGlobal(rt: *core.Runtime, global: *core.Object) !*core.Object {
    if (global.cachedRealmValue(.regexp_constructor)) |stored| {
        return objectFromValue(stored) orelse error.TypeError;
    }
    const key = try rt.internAtom("RegExp");
    defer rt.atoms.free(key);
    const value = global.getProperty(key);
    defer value.free(rt);
    return objectFromValue(value) orelse error.TypeError;
}

fn regExpPrototypeFromGlobal(rt: *core.Runtime, global: *core.Object) ?*core.Object {
    const constructor = regExpConstructorFromGlobal(rt, global) catch return null;
    if (constructor.getOwnDataObjectBorrowed(core.atom.ids.prototype)) |prototype| return prototype;
    const prototype_value = constructor.getProperty(core.atom.ids.prototype);
    defer prototype_value.free(rt);
    return objectFromValue(prototype_value);
}

fn regExpLegacySlotValue(rt: *core.Runtime, slot: ?core.Value) !core.Value {
    if (slot) |stored| return stored.dup();
    return value_ops.createStringValue(rt, "");
}

const RegExpLegacyNoCaptureSlice = enum {
    match,
    left,
    right,
};

fn regExpLegacyNoCaptureSliceValue(rt: *core.Runtime, legacy: anytype, kind: RegExpLegacyNoCaptureSlice) ?core.Value {
    if (!legacy.lazy_no_capture_match) return null;
    const input = legacy.input orelse return null;
    return switch (kind) {
        .match => stringSliceValue(rt, input, legacy.lazy_match_index, legacy.lazy_match_len) catch null,
        .left => if (legacy.lazy_match_index == 0)
            value_ops.createStringValue(rt, "") catch null
        else
            stringSliceValue(rt, input, 0, legacy.lazy_match_index) catch null,
        .right => blk: {
            const right_start = @min(legacy.lazy_match_index + legacy.lazy_match_len, legacy.lazy_input_len);
            if (right_start >= legacy.lazy_input_len) break :blk value_ops.createStringValue(rt, "") catch null;
            break :blk stringSliceValue(rt, input, right_start, legacy.lazy_input_len - right_start) catch null;
        },
    };
}

fn materializeRegExpLegacyNoCaptureSlots(rt: *core.Runtime, legacy: anytype) !void {
    if (!legacy.lazy_no_capture_match) return;
    const input = legacy.input orelse {
        legacy.lazy_no_capture_match = false;
        return;
    };

    const matched = try stringSliceValue(rt, input, legacy.lazy_match_index, legacy.lazy_match_len);
    defer matched.free(rt);
    replaceRegExpLegacySlot(rt, &legacy.last_match, matched);

    if (legacy.lazy_match_index == 0) {
        clearRegExpLegacySlot(rt, &legacy.left_context);
    } else {
        const left = try stringSliceValue(rt, input, 0, legacy.lazy_match_index);
        defer left.free(rt);
        replaceRegExpLegacySlot(rt, &legacy.left_context, left);
    }

    const right_start = @min(legacy.lazy_match_index + legacy.lazy_match_len, legacy.lazy_input_len);
    if (right_start >= legacy.lazy_input_len) {
        clearRegExpLegacySlot(rt, &legacy.right_context);
    } else {
        const right = try stringSliceValue(rt, input, right_start, legacy.lazy_input_len - right_start);
        defer right.free(rt);
        replaceRegExpLegacySlot(rt, &legacy.right_context, right);
    }
    legacy.lazy_no_capture_match = false;
}

fn replaceRegExpLegacySlot(rt: *core.Runtime, slot: *?core.Value, value: core.Value) void {
    if (slot.*) |old| {
        if (old.same(value)) return;
    }
    const old_value = slot.*;
    const next_value = value.dup();
    slot.* = next_value;
    if (old_value) |old| old.free(rt);
}

fn clearRegExpLegacySlot(rt: *core.Runtime, slot: *?core.Value) void {
    const old_value = slot.*;
    slot.* = null;
    if (old_value) |old| old.free(rt);
}

pub fn throwRegExpAccessorTypeError(ctx: *core.Context, global: *core.Object, getter_value: core.Value) !?core.Value {
    const error_value = if (objectFromValue(getter_value)) |getter_object| blk: {
        const ctor_value = getter_object.functionRealmTypeErrorConstructor() orelse break :blk try createNamedError(ctx.runtime, global, "TypeError", "not a Date object");
        break :blk try createNamedErrorWithConstructor(ctx.runtime, ctor_value, "TypeError", "not a Date object");
    } else try createNamedError(ctx.runtime, global, "TypeError", "not a Date object");
    _ = ctx.throwValue(error_value);
    return error.Test262Error;
}

pub fn isSameRealmRegExpPrototypeGetter(rt: *core.Runtime, global: *core.Object, object: *core.Object, name: []const u8, getter_value: core.Value) !bool {
    const regexp_proto = regExpPrototypeFromGlobal(rt, global) orelse return false;
    if (object != regexp_proto) return false;
    const key = try rt.internAtom(name);
    defer rt.atoms.free(key);
    const desc = regexp_proto.getOwnProperty(key) orelse return false;
    defer desc.destroy(rt);
    if (desc.kind != .accessor) return false;
    return sameObjectIdentity(desc.getter, getter_value);
}

fn objectHasRegExpInternalSlots(object: *core.Object) bool {
    if (object.class_id != core.class.ids.regexp) return false;
    return object.regexpSource() != null and object.regexpFlags() != null;
}

fn fastToLengthIndex(value: core.Value) ?usize {
    if (value.asInt32()) |int_value| {
        if (int_value <= 0) return 0;
        return @intCast(int_value);
    }
    if (value.asFloat64()) |number| {
        if (std.math.isNan(number) or number <= 0) return 0;
        const max_length = 9007199254740991.0;
        const clamped = if (number >= max_length) max_length else @floor(number);
        if (clamped >= @as(f64, @floatFromInt(std.math.maxInt(usize)))) return std.math.maxInt(usize);
        return @intFromFloat(clamped);
    }
    return null;
}

fn getRegExpLastIndexLength(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    regexp_value: core.Value,
    regexp_object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !usize {
    if (objectFromValue(regexp_value) == regexp_object) {
        if (regexp_object.regexpLastIndex()) |stored| {
            if (fastToLengthIndex(stored)) |index| return index;
        }
    }
    const last_index_value = try getValueProperty(ctx, output, global, regexp_value, core.atom.ids.lastIndex, caller_function, caller_frame);
    defer last_index_value.free(ctx.runtime);
    return try toLengthIndex(ctx, output, global, last_index_value);
}

fn setRegExpLastIndexStrict(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    regexp_value: core.Value,
    regexp_object: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    if (objectFromValue(regexp_value) == regexp_object and regexp_object.regexpLastIndex() != null) {
        if (!regexp_object.regexpLastIndexWritable()) return error.TypeError;
        const slot = regexp_object.regexpLastIndexSlot();
        const next_value = value.dup();
        const old_value = slot.*.?;
        slot.* = next_value;
        old_value.free(ctx.runtime);
        return;
    }
    try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, value, caller_function, caller_frame);
}

pub fn qjsRegExpExecResult(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    regexp_value: core.Value,
    regexp_object: *core.Object,
    string_value: core.Value,
    use_last_index: bool,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const rt = ctx.runtime;
    const input_len = try stringLengthIndex(rt, string_value);
    const initial_last_index = if (use_last_index)
        try getRegExpLastIndexLength(ctx, output, global, regexp_value, regexp_object, caller_function, caller_frame)
    else
        0;

    switch (try qjsRegExpExecSimpleCaptureSequenceResult(ctx, output, global, regexp_value, regexp_object, string_value, use_last_index, input_len, initial_last_index, caller_function, caller_frame)) {
        .unsupported => {},
        .value => |value| return value,
    }

    switch (try qjsRegExpExecSimpleClassAlternationResult(ctx, output, global, regexp_value, regexp_object, string_value, use_last_index, input_len, initial_last_index, caller_function, caller_frame)) {
        .unsupported => {},
        .value => |value| return value,
    }

    const cached_bytecode = regexp_object.regexpCompiledBytecode();
    if (cached_bytecode.len != 0) {
        const compiled = quickjs_regexp.Compiled{ .bytecode = @constCast(cached_bytecode) };
        const bits = compiled.flagBits();
        const is_global = (bits & quickjs_regexp.flag_bits.global) != 0;
        const is_sticky = (bits & quickjs_regexp.flag_bits.sticky) != 0;
        const has_indices = (bits & quickjs_regexp.flag_bits.indices) != 0;
        const start_index = if (use_last_index and (is_global or is_sticky)) initial_last_index else 0;
        if (start_index > input_len) {
            if (use_last_index and (is_global or is_sticky)) {
                try setRegExpLastIndexStrict(ctx, output, global, regexp_value, regexp_object, core.Value.int32(0), caller_function, caller_frame);
            }
            return core.Value.nullValue();
        }
        return try qjsRegExpExecCompiledResult(ctx, output, global, regexp_value, regexp_object, string_value, compiled, use_last_index, is_global, is_sticky, has_indices, start_index, caller_function, caller_frame);
    }

    var source = std.ArrayList(u8).empty;
    defer source.deinit(rt.memory.allocator);
    if (!try appendRegExpSource(rt, regexp_object, &source)) return null;

    var flags = std.ArrayList(u8).empty;
    defer flags.deinit(rt.memory.allocator);
    if (!try appendRegExpFlags(rt, regexp_object, &flags)) return null;

    const is_global = std.mem.indexOfScalar(u8, flags.items, 'g') != null;
    const is_sticky = std.mem.indexOfScalar(u8, flags.items, 'y') != null;
    const has_indices = std.mem.indexOfScalar(u8, flags.items, 'd') != null;
    const start_index = if (use_last_index and (is_global or is_sticky)) initial_last_index else 0;

    if (start_index > input_len) {
        if (use_last_index and (is_global or is_sticky)) {
            try setRegExpLastIndexStrict(ctx, output, global, regexp_value, regexp_object, core.Value.int32(0), caller_function, caller_frame);
        }
        return core.Value.nullValue();
    }

    if (regexpSourceUsesZigPropertyFallback(source.items, flags.items)) {
        return try qjsRegExpExecPropertyFallback(ctx, output, global, regexp_value, source.items, flags.items, string_value, use_last_index, is_global, is_sticky, has_indices, input_len, start_index, caller_function, caller_frame);
    }
    const full_unicode = regExpFlagsContain(flags.items, 'u') or regExpFlagsContain(flags.items, 'v');
    if (nativeFunctionMatcherUnicodeClassAsciiResult(source.items, flags.items, string_value, start_index)) |matched| {
        if (!matched) return core.Value.nullValue();
        const found = RegExpMatch{
            .index = start_index,
            .len = 1,
            .capture_count = 0,
        };
        return try createRegExpMatchArrayFromValue(rt, global, string_value, found, has_indices);
    }
    if (full_unicode and parseUnicodeAstralSpecialSource(source.items) != null) {
        if (unicodeAstralSpecialMatch(source.items, string_value, start_index, is_sticky, true)) |found| {
            if (use_last_index and (is_global or is_sticky)) {
                const next_index = found.index + found.len;
                const next_value = if (next_index <= @as(usize, @intCast(std.math.maxInt(i32))))
                    core.Value.int32(@intCast(next_index))
                else
                    core.Value.float64(@floatFromInt(next_index));
                try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, next_value, caller_function, caller_frame);
            }
            return try createRegExpMatchArrayFromValue(rt, global, string_value, found, has_indices);
        }
        if (use_last_index and (is_global or is_sticky)) {
            try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
        }
        return core.Value.nullValue();
    }
    if (full_unicode and std.mem.eql(u8, source.items, "^\\S$")) {
        if (start_index == 0 and anchoredSingleNonWhitespaceMatches(string_value, true)) {
            const found = RegExpMatch{ .index = 0, .len = input_len, .capture_count = 0 };
            if (use_last_index and (is_global or is_sticky)) {
                const next_value = if (input_len <= @as(usize, @intCast(std.math.maxInt(i32))))
                    core.Value.int32(@intCast(input_len))
                else
                    core.Value.float64(@floatFromInt(input_len));
                try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, next_value, caller_function, caller_frame);
            }
            return try createRegExpMatchArrayFromValue(rt, global, string_value, found, has_indices);
        }
        if (use_last_index and (is_global or is_sticky)) {
            try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
        }
        return core.Value.nullValue();
    }
    if (full_unicode and singleLowSurrogateLiteralSource(source.items) != null) {
        if (unicodeLowSurrogateLiteralMatch(source.items, string_value, start_index, is_sticky)) |found| {
            if (use_last_index and (is_global or is_sticky)) {
                const next_index = found.index + found.len;
                const next_value = if (next_index <= @as(usize, @intCast(std.math.maxInt(i32))))
                    core.Value.int32(@intCast(next_index))
                else
                    core.Value.float64(@floatFromInt(next_index));
                try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, next_value, caller_function, caller_frame);
            }
            return try createRegExpMatchArrayFromValue(rt, global, string_value, found, has_indices);
        }
        if (use_last_index and (is_global or is_sticky)) {
            try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
        }
        return core.Value.nullValue();
    }
    if (parseSimpleClassAlternationSource(source.items, flags.items)) |pattern| {
        if (simpleClassAlternationMatchPattern(pattern, string_value, start_index, is_sticky, flags.items)) |found| {
            if (use_last_index and (is_global or is_sticky)) {
                const next_index = found.index + found.len;
                const next_value = if (next_index <= @as(usize, @intCast(std.math.maxInt(i32))))
                    core.Value.int32(@intCast(next_index))
                else
                    core.Value.float64(@floatFromInt(next_index));
                try setRegExpLastIndexStrict(ctx, output, global, regexp_value, regexp_object, next_value, caller_function, caller_frame);
            }
            return try createRegExpMatchArrayFromValue(rt, global, string_value, found, has_indices);
        }
        if (use_last_index and (is_global or is_sticky)) {
            try setRegExpLastIndexStrict(ctx, output, global, regexp_value, regexp_object, core.Value.int32(0), caller_function, caller_frame);
        }
        return core.Value.nullValue();
    }
    if (regexp_object.regexpCompiledBytecode().len == 0) {
        var compiled = quickjs_regexp.compile(rt.memory.allocator, source.items, flags.items) catch |err| switch (err) {
            error.InvalidPattern, error.Unsupported => return try qjsRegExpExecPropertyFallback(ctx, output, global, regexp_value, source.items, flags.items, string_value, use_last_index, is_global, is_sticky, has_indices, input_len, start_index, caller_function, caller_frame),
            else => |other| return other,
        };
        defer compiled.deinit(rt.memory.allocator);
        try regexp_object.setRegexpCompiledBytecode(rt, compiled.bytecode);
    }
    const compiled = quickjs_regexp.Compiled{ .bytecode = @constCast(regexp_object.regexpCompiledBytecode()) };

    return try qjsRegExpExecCompiledResult(ctx, output, global, regexp_value, regexp_object, string_value, compiled, use_last_index, is_global, is_sticky, has_indices, start_index, caller_function, caller_frame);
}

fn qjsRegExpExecCompiledResult(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    regexp_value: core.Value,
    regexp_object: *core.Object,
    string_value: core.Value,
    compiled: quickjs_regexp.Compiled,
    use_last_index: bool,
    is_global: bool,
    is_sticky: bool,
    has_indices: bool,
    start_index: usize,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const rt = ctx.runtime;
    const status = quickjs_regexp.execOnStringFromIndex(compiled, string_value, start_index) catch |err| switch (err) {
        error.BytecodeCorrupt, error.Timeout => return null,
        else => return err,
    };

    switch (status.result) {
        .match => {
            const match = status.match;
