    const is_id_start = std.mem.startsWith(u8, source, "(?:[A-Za-z");
    const is_id_continue = std.mem.startsWith(u8, source, "(?:[0-9A-Z_a-z");
    if (!is_id_start and !is_id_continue) return null;
    const header = string_value.refHeader() orelse return null;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    if (string_object.len() != 1) return null;
    const unit = string_object.codeUnitAt(0);
    if (unit > 0x7f) return null;
    const byte: u8 = @intCast(unit);
    if (byte >= 'A' and byte <= 'Z') return true;
    if (byte >= 'a' and byte <= 'z') return true;
    if (is_id_continue and byte >= '0' and byte <= '9') return true;
    if (is_id_continue and byte == '_') return true;
    return false;
}

fn qjsRegExpExecPropertyFallback(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    regexp_value: core.Value,
    source: []const u8,
    flags: []const u8,
    string_value: core.Value,
    use_last_index: bool,
    is_global: bool,
    is_sticky: bool,
    has_indices: bool,
    input_len: usize,
    start_index: usize,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (isAnchoredRgiEmojiSource(source) and regExpFlagsContain(flags, 'v')) {
        return try qjsRegExpExecAnchoredRgiEmojiFallback(ctx, output, global, regexp_value, string_value, use_last_index, is_global, is_sticky, has_indices, input_len, start_index, caller_function, caller_frame);
    }
    if (isAnchoredBinaryPropertySource(source)) {
        return try qjsRegExpExecAnchoredPropertyFallback(ctx, output, global, regexp_value, source, string_value, use_last_index, is_global, is_sticky, has_indices, input_len, start_index, caller_function, caller_frame);
    }
    if (regExpFlagsContain(flags, 'v')) {
        if (findStringPropertyEscapeMatch(source, string_value, start_index, is_sticky)) |match| {
            const update_last_index = use_last_index and (is_global or is_sticky);
            if (update_last_index) {
                const next_value = if (match.index + match.len <= @as(usize, @intCast(std.math.maxInt(i32))))
                    core.Value.int32(@intCast(match.index + match.len))
                else
                    core.Value.float64(@floatFromInt(match.index + match.len));
                try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, next_value, caller_function, caller_frame);
            }
            return try createRegExpMatchArrayFromValue(ctx.runtime, global, string_value, match, has_indices);
        }
    }
    if (regExpFlagsContain(flags, 'u') or regExpFlagsContain(flags, 'v')) {
        if (findUnicodePropertyOnlyClassMatch(source, string_value, start_index, is_sticky)) |match| {
            const update_last_index = use_last_index and (is_global or is_sticky);
            if (update_last_index) {
                const next_value = if (match.index + match.len <= @as(usize, @intCast(std.math.maxInt(i32))))
                    core.Value.int32(@intCast(match.index + match.len))
                else
                    core.Value.float64(@floatFromInt(match.index + match.len));
                try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, next_value, caller_function, caller_frame);
            }
            return try createRegExpMatchArrayFromValue(ctx.runtime, global, string_value, match, has_indices);
        }
    }
    if (findPropertyEscapeMatch(source, string_value, start_index, is_sticky)) |match| {
        const update_last_index = use_last_index and (is_global or is_sticky);
        if (update_last_index) {
            const next_value = if (match.index + match.len <= @as(usize, @intCast(std.math.maxInt(i32))))
                core.Value.int32(@intCast(match.index + match.len))
            else
                core.Value.float64(@floatFromInt(match.index + match.len));
            try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, next_value, caller_function, caller_frame);
        }
        return try createRegExpMatchArrayFromValue(ctx.runtime, global, string_value, match, has_indices);
    }
    const update_last_index = use_last_index and (is_global or is_sticky);
    if (update_last_index) {
        try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
    }
    return core.Value.nullValue();
}

fn qjsRegExpExecAnchoredPropertyFallback(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    regexp_value: core.Value,
    source: []const u8,
    string_value: core.Value,
    use_last_index: bool,
    is_global: bool,
    is_sticky: bool,
    has_indices: bool,
    input_len: usize,
    start_index: usize,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const update_last_index = use_last_index and (is_global or is_sticky);
    if (start_index != 0 or !anchoredBinaryPropertyMatches(source, string_value)) {
        if (update_last_index) try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
        return core.Value.nullValue();
    }

    if (update_last_index) {
        const next_value = if (input_len <= @as(usize, @intCast(std.math.maxInt(i32))))
            core.Value.int32(@intCast(input_len))
        else
            core.Value.float64(@floatFromInt(input_len));
        try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, next_value, caller_function, caller_frame);
    }

    return try createRegExpMatchArrayFromValue(ctx.runtime, global, string_value, .{
        .index = 0,
        .len = input_len,
        .capture_count = 0,
    }, has_indices);
}

fn qjsRegExpExecAnchoredRgiEmojiFallback(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    regexp_value: core.Value,
    string_value: core.Value,
    use_last_index: bool,
    is_global: bool,
    is_sticky: bool,
    has_indices: bool,
    input_len: usize,
    start_index: usize,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const update_last_index = use_last_index and (is_global or is_sticky);
    if (start_index != 0 or !anchoredRgiEmojiMatches(string_value)) {
        if (update_last_index) try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, core.Value.int32(0), caller_function, caller_frame);
        return core.Value.nullValue();
    }

    if (update_last_index) {
        const next_value = if (input_len <= @as(usize, @intCast(std.math.maxInt(i32))))
            core.Value.int32(@intCast(input_len))
        else
            core.Value.float64(@floatFromInt(input_len));
        try setValuePropertyStrict(ctx, output, global, regexp_value, core.atom.ids.lastIndex, next_value, caller_function, caller_frame);
    }

    return try createRegExpMatchArrayFromValue(ctx.runtime, global, string_value, .{
        .index = 0,
        .len = input_len,
        .capture_count = 0,
    }, has_indices);
}

fn findStringPropertyEscapeMatch(source: []const u8, string_value: core.Value, start_index: usize, sticky: bool) ?RegExpMatch {
    const name = stringPropertyEscapePattern(source) orelse return null;
    if (!std.mem.eql(u8, name, "RGI_Emoji")) return null;
    const units = stringValueUnits(string_value) orelse return null;
    const match = unicode_tables.findRgiEmojiMatch(units, start_index, sticky) orelse return null;
    return .{ .index = match.index, .len = match.len };
}

fn anchoredRgiEmojiMatches(string_value: core.Value) bool {
    const units = stringValueUnits(string_value) orelse return false;
    return unicode_tables.rgiEmojiSequencesCover(units);
}

fn stringValueUnits(string_value: core.Value) ?unicode_tables.StringUnits {
    const header = string_value.refHeader() orelse return null;
    if (!string_value.isString()) return null;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    switch (string_object.resolveData()) {
        .latin1 => |bytes| {
            return .{ .latin1 = bytes };
        },
        .utf16 => |units| {
            return .{ .utf16 = units };
        },
    }
}

fn findPropertyEscapeMatch(source: []const u8, string_value: core.Value, start_index: usize, sticky: bool) ?RegExpMatch {
    const parsed = propertyEscapePattern(source) orelse return null;
    const header = string_value.refHeader() orelse return null;
    if (!string_value.isString()) return null;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    switch (string_object.resolveData()) {
        .latin1 => |bytes| {
            var index = start_index;
            while (index < bytes.len) {
                const code_point: u21 = bytes[index];
                if (binaryPropertyCodePointMatches(parsed.name, code_point) == parsed.positive) return .{ .index = index, .len = 1 };
                if (sticky) break;
                index += 1;
            }
        },
        .utf16 => |units| {
            var index = start_index;
            while (index < units.len) {
                var next = index;
                const code_point = readUtf16CodePoint(units, &next);
                if (binaryPropertyCodePointMatches(parsed.name, code_point) == parsed.positive) return .{ .index = index, .len = next - index };
                if (sticky) break;
                index = next;
            }
        },
    }
    return null;
}

fn regexpSourceUsesZigPropertyFallback(source: []const u8, flags: []const u8) bool {
    if (regExpFlagsContain(flags, 'v')) {
        if (isAnchoredRgiEmojiSource(source)) return true;
        if (stringPropertyEscapePattern(source)) |name| return std.mem.eql(u8, name, "RGI_Emoji");
    }
    if ((regExpFlagsContain(flags, 'u') or regExpFlagsContain(flags, 'v')) and unicodePropertyOnlyClassSource(source)) return true;
    if (anchoredBinaryPropertyName(source)) |name| return isUnknownScriptName(name);
    if (propertyEscapePattern(source)) |parsed| return isUnknownScriptName(parsed.name);
    return false;
}

fn regExpFlagsContain(flags: []const u8, needle: u8) bool {
    return std.mem.indexOfScalar(u8, flags, needle) != null;
}

fn isAnchoredRgiEmojiSource(source: []const u8) bool {
    const name = anchoredStringPropertyName(source) orelse return false;
    return std.mem.eql(u8, name, "RGI_Emoji");
}

fn anchoredStringPropertyName(source: []const u8) ?[]const u8 {
    const positive_prefix = "^\\p{";
    const suffix = "}+$";
    if (!std.mem.startsWith(u8, source, positive_prefix)) return null;
    if (!std.mem.endsWith(u8, source, suffix)) return null;
    if (source.len <= positive_prefix.len + suffix.len) return null;
    return source[positive_prefix.len .. source.len - suffix.len];
}

fn stringPropertyEscapePattern(source: []const u8) ?[]const u8 {
    const positive_prefix = "\\p{";
    if (!std.mem.startsWith(u8, source, positive_prefix)) return null;
    if (source.len <= positive_prefix.len or source[source.len - 1] != '}') return null;
    const name = source[positive_prefix.len .. source.len - 1];
    return if (std.mem.eql(u8, name, "RGI_Emoji")) name else null;
}

const PropertyEscapePattern = struct {
    name: []const u8,
    positive: bool,
};

const UnicodePropertyRunPattern = struct {
    name: []const u8,
    positive: bool,
    predicate: FastUnicodePropertyPredicate = .generic,
};

const FastUnicodePropertyPredicate = enum {
    generic,
    greek_script,
};

fn simpleUnicodePropertyRunTestFast(source: []const u8, flags: []const u8, string_value: core.Value) ?bool {
    const parsed = unicodePropertyRunPattern(source, flags) orelse return null;
    const header = string_value.refHeader() orelse return null;
    if (!string_value.isString()) return null;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    switch (string_object.resolveData()) {
        .latin1 => |bytes| {
            for (bytes) |byte| {
                if (unicodePropertyRunCodePointMatches(parsed, byte)) return true;
            }
        },
        .utf16 => |units| {
            var index: usize = 0;
            while (index < units.len) {
                const code_point = readUtf16CodePoint(units, &index);
                if (unicodePropertyRunCodePointMatches(parsed, code_point)) return true;
            }
        },
    }
    return false;
}

fn unicodePropertyRunPattern(source: []const u8, flags: []const u8) ?UnicodePropertyRunPattern {
    if (flags.len != 1 or flags[0] != 'u') return null;
    const positive_prefix = "\\p{";
    const negative_prefix = "\\P{";
    var prefix_len: usize = undefined;
    var positive: bool = undefined;
    if (std.mem.startsWith(u8, source, positive_prefix)) {
        prefix_len = positive_prefix.len;
        positive = true;
    } else if (std.mem.startsWith(u8, source, negative_prefix)) {
        prefix_len = negative_prefix.len;
        positive = false;
    } else {
        return null;
    }

    var scan = prefix_len;
    while (scan < source.len and source[scan] != '}') : (scan += 1) {}
    if (scan == prefix_len or scan >= source.len or source[scan] != '}') return null;
    const name = source[prefix_len..scan];
    if (!isRuntimeSupportedBinaryPropertyName(name)) return null;
    const predicate = fastUnicodePropertyPredicate(name);
    scan += 1;
    if (scan >= source.len or source[scan] != '+') return null;
    scan += 1;
    if (scan == source.len) return .{ .name = name, .positive = positive, .predicate = predicate };
    if (std.mem.eql(u8, source[scan..], "[0-9]?")) return .{ .name = name, .positive = positive, .predicate = predicate };
    return null;
}

fn fastUnicodePropertyPredicate(name: []const u8) FastUnicodePropertyPredicate {
    if (std.mem.eql(u8, name, "Script=Greek") or
        std.mem.eql(u8, name, "Script=Grek") or
        std.mem.eql(u8, name, "sc=Greek") or
        std.mem.eql(u8, name, "sc=Grek"))
    {
        return .greek_script;
    }
    return .generic;
}

fn unicodePropertyRunCodePointMatches(pattern: UnicodePropertyRunPattern, code_point: u21) bool {
    const matched = switch (pattern.predicate) {
        .generic => binaryPropertyCodePointMatches(pattern.name, code_point),
        .greek_script => isUnicodeGreekScriptCodePoint(code_point),
    };
    return matched == pattern.positive;
}

fn isUnicodeGreekScriptCodePoint(code_point: u21) bool {
    return code_point == 0x00037f or
        code_point == 0x000384 or
        code_point == 0x000386 or
        code_point == 0x00038c or
        code_point == 0x001dbf or
        code_point == 0x001f59 or
        code_point == 0x001f5b or
        code_point == 0x001f5d or
        code_point == 0x002126 or
        code_point == 0x00ab65 or
        code_point == 0x0101a0 or
        (code_point >= 0x000370 and code_point <= 0x000373) or
        (code_point >= 0x000375 and code_point <= 0x000377) or
        (code_point >= 0x00037a and code_point <= 0x00037d) or
        (code_point >= 0x000388 and code_point <= 0x00038a) or
        (code_point >= 0x00038e and code_point <= 0x0003a1) or
        (code_point >= 0x0003a3 and code_point <= 0x0003e1) or
        (code_point >= 0x0003f0 and code_point <= 0x0003ff) or
        (code_point >= 0x001d26 and code_point <= 0x001d2a) or
        (code_point >= 0x001d5d and code_point <= 0x001d61) or
        (code_point >= 0x001d66 and code_point <= 0x001d6a) or
        (code_point >= 0x001f00 and code_point <= 0x001f15) or
        (code_point >= 0x001f18 and code_point <= 0x001f1d) or
        (code_point >= 0x001f20 and code_point <= 0x001f45) or
        (code_point >= 0x001f48 and code_point <= 0x001f4d) or
        (code_point >= 0x001f50 and code_point <= 0x001f57) or
        (code_point >= 0x001f5f and code_point <= 0x001f7d) or
        (code_point >= 0x001f80 and code_point <= 0x001fb4) or
        (code_point >= 0x001fb6 and code_point <= 0x001fc4) or
        (code_point >= 0x001fc6 and code_point <= 0x001fd3) or
        (code_point >= 0x001fd6 and code_point <= 0x001fdb) or
        (code_point >= 0x001fdd and code_point <= 0x001fef) or
        (code_point >= 0x001ff2 and code_point <= 0x001ff4) or
        (code_point >= 0x001ff6 and code_point <= 0x001ffe) or
        (code_point >= 0x010140 and code_point <= 0x01018e) or
        (code_point >= 0x01d200 and code_point <= 0x01d245);
}

fn propertyEscapePattern(source: []const u8) ?PropertyEscapePattern {
    const positive_prefix = "\\p{";
    const negative_prefix = "\\P{";
    var prefix_len: usize = undefined;
    var positive: bool = undefined;
    if (std.mem.startsWith(u8, source, positive_prefix)) {
        prefix_len = positive_prefix.len;
        positive = true;
    } else if (std.mem.startsWith(u8, source, negative_prefix)) {
        prefix_len = negative_prefix.len;
        positive = false;
    } else {
        return null;
    }
    if (source.len <= prefix_len or source[source.len - 1] != '}') return null;
    const name = source[prefix_len .. source.len - 1];
    if (!isRuntimeSupportedBinaryPropertyName(name)) return null;
    return .{ .name = name, .positive = positive };
}

fn unicodePropertyOnlyClassSource(source: []const u8) bool {
    const body = unicodePropertyOnlyClassBody(source) orelse return false;
    var index: usize = 0;
    var saw_escape = false;
    while (index < body.len) {
        _ = readUnicodePropertyClassEscape(body, &index) orelse return false;
        saw_escape = true;
    }
    return saw_escape;
}

fn unicodePropertyOnlyClassBody(source: []const u8) ?[]const u8 {
    if (source.len < 3 or source[0] != '[' or source[source.len - 1] != ']') return null;
    const body = source[1 .. source.len - 1];
    if (body.len == 0 or body[0] == '^') return null;
    return body;
}

fn readUnicodePropertyClassEscape(body: []const u8, index: *usize) ?PropertyEscapePattern {
    if (index.* >= body.len or body[index.*] != '\\') return null;
    const start = index.*;
    index.* += 1;
    if (index.* >= body.len or (body[index.*] != 'p' and body[index.*] != 'P')) return null;
    index.* += 1;
    if (index.* >= body.len or body[index.*] != '{') return null;
    index.* += 1;
    while (index.* < body.len and body[index.*] != '}') : (index.* += 1) {}
    if (index.* >= body.len or body[index.*] != '}') return null;
    index.* += 1;
    return propertyEscapePattern(body[start..index.*]);
}

fn findUnicodePropertyOnlyClassMatch(source: []const u8, string_value: core.Value, start_index: usize, sticky: bool) ?RegExpMatch {
    if (!unicodePropertyOnlyClassSource(source)) return null;
    const header = string_value.refHeader() orelse return null;
    if (!string_value.isString()) return null;
    const string_object: *core.string.String = @fieldParentPtr("header", header);
    switch (string_object.resolveData()) {
        .latin1 => |bytes| {
            var index = start_index;
            while (index < bytes.len) : (index += 1) {
                if (unicodePropertyOnlyClassCodePointMatches(source, bytes[index])) return .{ .index = index, .len = 1 };
                if (sticky) break;
            }
        },
        .utf16 => |units| {
            var index = start_index;
            while (index < units.len) {
                const match_start = index;
                const code_point = readUtf16CodePoint(units, &index);
                if (unicodePropertyOnlyClassCodePointMatches(source, code_point)) return .{ .index = match_start, .len = index - match_start };
                if (sticky) break;
            }
        },
    }
    return null;
}

fn unicodePropertyOnlyClassCodePointMatches(source: []const u8, code_point: u21) bool {
    const body = unicodePropertyOnlyClassBody(source) orelse return false;
    var index: usize = 0;
    while (index < body.len) {
        const parsed = readUnicodePropertyClassEscape(body, &index) orelse return false;
        if (binaryPropertyCodePointMatches(parsed.name, code_point) == parsed.positive) return true;
    }
    return false;
}

pub fn qjsStringTrim(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    method_id: u32,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const string_value = try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);
    return builtins.string.methodCall(ctx.runtime, string_value, method_id, &.{});
}

pub fn qjsStringPrototypeMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    method_id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return throwTypeErrorMessage(ctx, global, "null or undefined are forbidden");
    if (method_id == 10) {
        return qjsStringConcat(ctx, output, global, this_value, args, caller_function, caller_frame);
    }
    if (method_id == 27) {
        return qjsStringSplit(ctx, output, global, this_value, args, caller_function, caller_frame);
    }
    if (method_id == 40) {
        return qjsStringSearch(ctx, output, global, this_value, args, caller_function, caller_frame);
    }
    if (method_id == 41) {
        return qjsStringMatch(ctx, output, global, this_value, args, caller_function, caller_frame);
    }
    if (method_id == 42) {
        return qjsStringReplaceAll(ctx, output, global, this_value, args, caller_function, caller_frame);
    }
    if (method_id == 43) {
        return qjsStringMatchAll(ctx, output, global, this_value, args, caller_function, caller_frame);
    }
    if (method_id == 34 or method_id == 35) {
        return qjsStringPad(ctx, output, global, this_value, method_id, args, caller_function, caller_frame);
    }
    if (method_id == 11 or method_id == 12 or method_id == 13 or method_id == 14 or method_id == 15 or
        method_id == 16 or method_id == 17 or method_id == 18 or method_id == 19 or method_id == 20 or
        method_id == 23 or method_id == 24 or method_id == 26)
    {
        return qjsStringHtmlMethod(ctx, output, global, this_value, method_id, args, caller_function, caller_frame);
    }
    if (method_id == 37) {
        return qjsStringNormalize(ctx, output, global, this_value, args, caller_function, caller_frame);
    }
    if (method_id == 36) {
        return qjsStringLocaleCompare(ctx, output, global, this_value, args, caller_function, caller_frame);
    }
    if (method_id == 4 or method_id == 5 or method_id == 6 or method_id == 7 or method_id == 28) {
        return qjsStringSearchPositionMethod(ctx, output, global, this_value, method_id, args, caller_function, caller_frame);
    }
    if (method_id == 0 or method_id == 1 or method_id == 25 or method_id == 29 or method_id == 30 or method_id == 31 or method_id == 32 or method_id == 33) {
        return qjsStringNumericArgsMethod(ctx, output, global, this_value, method_id, args, caller_function, caller_frame);
    }
    const string_value = try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);
    return builtins.string.methodCall(ctx.runtime, string_value, method_id, args) catch |err| switch (err) {
        error.RangeError => return throwRangeErrorMessage(ctx, global, "invalid repeat count"),
        else => err,
    };
}

fn qjsStringPad(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    method_id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return throwTypeErrorMessage(ctx, global, "null or undefined are forbidden");
    const string_value = try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);

    var source_units = std.ArrayList(u16).empty;
    defer source_units.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &source_units, string_value);

    const max_length_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const target_length = try toLengthIndex(ctx, output, global, max_length_value);
    if (target_length <= source_units.items.len) return string_value.dup();

    const fill_value = if (args.len >= 2 and !args[1].isUndefined()) blk: {
        break :blk try toStringForAnnexB(ctx, output, global, args[1], caller_function, caller_frame);
    } else try value_ops.createStringValue(ctx.runtime, " ");
    defer fill_value.free(ctx.runtime);

    var fill_units = std.ArrayList(u16).empty;
    defer fill_units.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &fill_units, fill_value);
    if (fill_units.items.len == 0) return string_value.dup();

    const fill_length = target_length - source_units.items.len;
    var out = std.ArrayList(u16).empty;
    defer out.deinit(ctx.runtime.memory.allocator);
    if (method_id == 34) {
        try appendRepeatedFillUnits(ctx.runtime, &out, fill_units.items, fill_length);
        try out.appendSlice(ctx.runtime.memory.allocator, source_units.items);
    } else {
        try out.appendSlice(ctx.runtime.memory.allocator, source_units.items);
        try appendRepeatedFillUnits(ctx.runtime, &out, fill_units.items, fill_length);
    }
    return (try core.string.String.createUtf16(ctx.runtime, out.items)).value();
}

fn appendRepeatedFillUnits(rt: *core.Runtime, out: *std.ArrayList(u16), fill: []const u16, length: usize) !void {
    var index: usize = 0;
    while (index < length) : (index += 1) {
