    return value_ops.numberToValue(number);
}

fn mathArg(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, args: []const core.Value, index: usize) !f64 {
    if (index >= args.len) return std.math.nan(f64);
    return toMathNumber(ctx, output, global, args[index]);
}

fn toMathNumber(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, value: core.Value) !f64 {
    const primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer primitive.free(ctx.runtime);
    if (primitive.isBigInt()) return error.TypeError;
    const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
    defer number_value.free(ctx.runtime);
    return value_ops.numberValue(number_value) orelse std.math.nan(f64);
}

fn qjsMathMinMax(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, args: []const core.Value, is_max: bool) !f64 {
    if (args.len == 0) return if (is_max) -std.math.inf(f64) else std.math.inf(f64);
    if (qjsMathMinMaxPrimitiveFast(args, is_max)) |fast| return fast;
    var result = try toMathNumber(ctx, output, global, args[0]);
    for (args[1..]) |arg| {
        const number = try toMathNumber(ctx, output, global, arg);
        if (!std.math.isNan(result)) {
            result = if (std.math.isNan(number))
                number
            else if (is_max)
                qjsFmax(result, number)
            else
                qjsFmin(result, number);
        }
    }
    return result;
}

fn qjsMathMinMaxPrimitiveFast(args: []const core.Value, is_max: bool) ?f64 {
    var result = if (is_max) -std.math.inf(f64) else std.math.inf(f64);
    for (args) |arg| {
        const number = qjsPrimitiveMathNumber(arg) orelse return null;
        if (!std.math.isNan(result)) {
            result = if (std.math.isNan(number))
                number
            else if (is_max)
                qjsFmax(result, number)
            else
                qjsFmin(result, number);
        }
    }
    return result;
}

fn qjsPrimitiveMathNumber(value: core.Value) ?f64 {
    if (value.tag == core.Tag.int) return @floatFromInt(value.asInt32().?);
    if (value.tag == core.Tag.float64) return value.asFloat64().?;
    if (value.asBool()) |bool_value| return if (bool_value) 1 else 0;
    if (value.isNull()) return 0;
    if (value.isUndefined()) return std.math.nan(f64);
    return null;
}

fn qjsFmin(a: f64, b: f64) f64 {
    if (a == 0 and b == 0) return @bitCast(@as(u64, @bitCast(a)) | @as(u64, @bitCast(b)));
    return if (a < b) a else b;
}

fn qjsFmax(a: f64, b: f64) f64 {
    if (a == 0 and b == 0) return @bitCast(@as(u64, @bitCast(a)) & @as(u64, @bitCast(b)));
    return if (a < b) b else a;
}

fn qjsMathPow(a: f64, b: f64) f64 {
    if (!std.math.isFinite(b) and @abs(a) == 1) return std.math.nan(f64);
    return std.math.pow(f64, a, b);
}

fn qjsMathRound(a: f64) f64 {
    var bits: u64 = @bitCast(a);
    const exponent = (bits >> 52) & 0x7ff;
    if (exponent < 1023) {
        if (exponent == 1022 and bits != 0xbfe0000000000000) {
            bits = (bits & (@as(u64, 1) << 63)) | (@as(u64, 1023) << 52);
        } else {
            bits &= @as(u64, 1) << 63;
        }
    } else if (exponent < 1075) {
        const sign = bits >> 63;
        const one = @as(u64, 1) << @intCast(52 - (exponent - 1023));
        const frac_mask = one - 1;
        bits +%= (one >> 1) -% sign;
        bits &= ~frac_mask;
    }
    return @bitCast(bits);
}

fn qjsMathHypot(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, args: []const core.Value) !f64 {
    if (args.len == 0) return 0;
    var result = try toMathNumber(ctx, output, global, args[0]);
    if (args.len == 1) return @abs(result);
    for (args[1..]) |arg| {
        const number = try toMathNumber(ctx, output, global, arg);
        result = std.math.hypot(result, number);
    }
    return result;
}

fn qjsMathImul(lhs: f64, rhs: f64) i32 {
    const product = toUint32Number(lhs) *% toUint32Number(rhs);
    return @bitCast(product);
}

fn qjsMathSign(value: f64) f64 {
    if (std.math.isNan(value) or value == 0) return value;
    return if (value < 0) -1 else 1;
}

fn qjsStringHtmlMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    method_id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const string_value = try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);

    var string_units = std.ArrayList(u16).empty;
    defer string_units.deinit(ctx.runtime.memory.allocator);
    try appendStringValueUnits(ctx.runtime, &string_units, string_value);

    switch (method_id) {
        11 => return qjsStringCreateHtml(ctx, string_units.items, "a", "name", if (args.len >= 1) args[0] else core.Value.undefinedValue(), true, output, global, caller_function, caller_frame),
        12 => return qjsStringCreateHtml(ctx, string_units.items, "big", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        13 => return qjsStringCreateHtml(ctx, string_units.items, "blink", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        14 => return qjsStringCreateHtml(ctx, string_units.items, "b", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        15 => return qjsStringCreateHtml(ctx, string_units.items, "tt", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        16 => return qjsStringCreateHtml(ctx, string_units.items, "font", "color", if (args.len >= 1) args[0] else core.Value.undefinedValue(), true, output, global, caller_function, caller_frame),
        17 => return qjsStringCreateHtml(ctx, string_units.items, "font", "size", if (args.len >= 1) args[0] else core.Value.undefinedValue(), true, output, global, caller_function, caller_frame),
        18 => return qjsStringCreateHtml(ctx, string_units.items, "i", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        19 => return qjsStringCreateHtml(ctx, string_units.items, "a", "href", if (args.len >= 1) args[0] else core.Value.undefinedValue(), true, output, global, caller_function, caller_frame),
        20 => return qjsStringCreateHtml(ctx, string_units.items, "small", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        23 => return qjsStringCreateHtml(ctx, string_units.items, "strike", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        24 => return qjsStringCreateHtml(ctx, string_units.items, "sub", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        26 => return qjsStringCreateHtml(ctx, string_units.items, "sup", "", core.Value.undefinedValue(), false, output, global, caller_function, caller_frame),
        else => return error.TypeError,
    }
}

fn qjsStringCreateHtml(
    ctx: *core.Context,
    string_units: []const u16,
    tag: []const u8,
    attr: []const u8,
    attr_value: core.Value,
    has_attr: bool,
    output: ?*std.Io.Writer,
    global: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    var out = std.ArrayList(u16).empty;
    defer out.deinit(ctx.runtime.memory.allocator);
    try appendAsciiUnits(ctx.runtime, &out, "<");
    try appendAsciiUnits(ctx.runtime, &out, tag);
    if (has_attr) {
        const value = try toStringForAnnexB(ctx, output, global, attr_value, caller_function, caller_frame);
        defer value.free(ctx.runtime);
        var attr_units = std.ArrayList(u16).empty;
        defer attr_units.deinit(ctx.runtime.memory.allocator);
        try appendStringValueUnits(ctx.runtime, &attr_units, value);

        try appendAsciiUnits(ctx.runtime, &out, " ");
        try appendAsciiUnits(ctx.runtime, &out, attr);
        try appendAsciiUnits(ctx.runtime, &out, "=\"");
        for (attr_units.items) |unit| {
            if (unit == '"') {
                try appendAsciiUnits(ctx.runtime, &out, "&quot;");
            } else {
                try out.append(ctx.runtime.memory.allocator, unit);
            }
        }
        try appendAsciiUnits(ctx.runtime, &out, "\"");
    }
    try appendAsciiUnits(ctx.runtime, &out, ">");
    try out.appendSlice(ctx.runtime.memory.allocator, string_units);
    try appendAsciiUnits(ctx.runtime, &out, "</");
    try appendAsciiUnits(ctx.runtime, &out, tag);
    try appendAsciiUnits(ctx.runtime, &out, ">");
    return (try core.string.String.createUtf16(ctx.runtime, out.items)).value();
}

fn appendAsciiUnits(rt: *core.Runtime, out: *std.ArrayList(u16), bytes: []const u8) !void {
    for (bytes) |byte| try out.append(rt.memory.allocator, byte);
}

pub fn qjsStringSearchPositionMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    method_id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const string_value = try toStringForAnnexB(ctx, output, global, this_value, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);

    const search_input = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    if (method_id == 5 or method_id == 6 or method_id == 7) {
        if (try isRegExpForStringSearch(ctx, output, global, search_input, caller_function, caller_frame)) return error.TypeError;
    }
    const search_value = try toStringForAnnexB(ctx, output, global, search_input, caller_function, caller_frame);
    defer search_value.free(ctx.runtime);

    var coerced: [2]core.Value = .{ search_value, core.Value.undefinedValue() };
    var count: usize = 1;
    if (args.len >= 2) {
        if (args[1].isUndefined()) {
            coerced[1] = core.Value.undefinedValue();
        } else {
            const primitive = try toPrimitiveForNumber(ctx, output, global, args[1]);
            defer primitive.free(ctx.runtime);
            if (primitive.isBigInt()) return error.TypeError;
            const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
            defer number_value.free(ctx.runtime);
            coerced[1] = value_ops.numberToValue(value_ops.numberValue(number_value) orelse std.math.nan(f64));
        }
        count = 2;
    }

    return builtins.string.methodCall(ctx.runtime, string_value, method_id, coerced[0..count]);
}

pub fn isRegExpValue(value: core.Value) bool {
    const object = property_ops.expectObject(value) catch return false;
    return object.class_id == core.class.ids.regexp;
}

pub fn isRegExpObservable(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    if (!value.isObject()) return false;
    const match_atom = core.atom.predefinedId("Symbol.match", .symbol) orelse return isRegExpValue(value);
    const matcher = try getValueProperty(ctx, output, global, value, match_atom, caller_function, caller_frame);
    defer matcher.free(ctx.runtime);
    if (!matcher.isUndefined()) return valueTruthy(matcher);
    return isRegExpValue(value);
}

pub fn isRegExpForStringSearch(
