            const split_limit = if (args.len >= 2) args[1] else core.Value.undefinedValue();
            const split_args = [_]core.Value{ this_value, split_limit };
            return callValueOrBytecode(ctx, output, global, separator, splitter, &split_args, caller_function, caller_frame);
