    return result;
}

pub fn qjsRegExpSplit(rt: *core.Runtime, separator: core.Value, string_value: core.Value, limit_value: core.Value) !?core.Value {
    const separator_object = property_ops.expectObject(separator) catch return null;
    if (separator_object.class_id != core.class.ids.regexp) return null;
    var source = std.ArrayList(u8).empty;
    defer source.deinit(rt.memory.allocator);
    if (!try appendRegExpSource(rt, separator_object, &source)) return null;

    var flags = std.ArrayList(u8).empty;
    defer flags.deinit(rt.memory.allocator);
    if (!try appendRegExpFlags(rt, separator_object, &flags)) return null;
    // Use sticky flag for split iteration
    var split_flags = std.ArrayList(u8).empty;
    defer split_flags.deinit(rt.memory.allocator);
    try split_flags.appendSlice(rt.memory.allocator, flags.items);
    if (std.mem.indexOfScalar(u8, split_flags.items, 'y') == null) {
        try split_flags.append(rt.memory.allocator, 'y');
    }

    const limit = if (limit_value.isUndefined()) std.math.maxInt(u32) else toUint32Number(value_ops.numberValue(limit_value) orelse std.math.nan(f64));
    const out = try core.Object.createArray(rt, null);
    errdefer core.Object.destroyFromHeader(rt, &out.header);
    if (limit == 0) return out.value();

    var compiled = quickjs_regexp.compile(rt.memory.allocator, source.items, split_flags.items) catch |err| switch (err) {
        error.InvalidPattern, error.Unsupported => return null,
        else => |other| return other,
    };
    defer compiled.deinit(rt.memory.allocator);

    const input_len = try stringLengthIndex(rt, string_value);

    if (input_len == 0) {
        const status = quickjs_regexp.execOnStringFromIndex(compiled, string_value, 0) catch |err| switch (err) {
            error.BytecodeCorrupt, error.Timeout => return null,
            else => return err,
        };
        if (status.result == .match) return out.value();
        const slice = try stringSliceValue(rt, string_value, 0, 0);
        defer slice.free(rt);
        try defineSplitValueElement(rt, out, 0, slice);
        return out.value();
    }
    if (std.mem.eql(u8, source.items, "(?:)")) {
        var index: u32 = 0;
        while (index < input_len) : (index += 1) {
            const ch = try stringSliceValue(rt, string_value, index, 1);
            defer ch.free(rt);
            try defineSplitValueElement(rt, out, index, ch);
            if (index + 1 >= limit) return out.value();
        }
        return out.value();
    }

    var start: usize = 0;
    var pos: usize = 0;
    var out_index: u32 = 0;
    while (pos <= input_len) {
        const status = quickjs_regexp.execOnStringFromIndex(compiled, string_value, pos) catch |err| switch (err) {
            error.BytecodeCorrupt, error.Timeout => return null,
            else => return err,
        };
        switch (status.result) {
            .match => {
                const match = status.match;
                const match_len = match.end - match.start;
                if (match_len == 0) {
                    pos += 1;
                    continue;
                }
                const before = try stringSliceValue(rt, string_value, start, pos - start);
                defer before.free(rt);
                try defineSplitValueElement(rt, out, out_index, before);
                out_index += 1;
                if (out_index >= limit) return out.value();
                // Append captures
                var ci: usize = 0;
                while (ci < match.capture_count) : (ci += 1) {
                    const capture = match.captures[ci];
                    if (capture.start) |cs| {
                        const cap_str = try stringSliceValue(rt, string_value, cs, capture.end.? - cs);
                        defer cap_str.free(rt);
                        try defineSplitValueElement(rt, out, out_index, cap_str);
                    } else {
                        try defineSplitValueElement(rt, out, out_index, core.Value.undefinedValue());
                    }
                    out_index += 1;
                    if (out_index >= limit) return out.value();
                }
                pos += match_len;
                start = pos;
            },
            .no_match, .out_of_range, .not_available => {
                pos += 1;
            },
        }
    }
    const tail = try stringSliceValue(rt, string_value, start, input_len - start);
    defer tail.free(rt);
    try defineSplitValueElement(rt, out, out_index, tail);
    return out.value();
}

pub fn qjsRegExpSplitWholeString(rt: *core.Runtime, string_value: core.Value) !core.Value {
    const out = try core.Object.createArray(rt, null);
    errdefer core.Object.destroyFromHeader(rt, &out.header);
    try defineSplitValueElement(rt, out, 0, string_value);
    return out.value();
}

pub fn qjsRegExpSearch(rt: *core.Runtime, regexp: core.Value, string_value: core.Value) !?core.Value {
    const regexp_object = property_ops.expectObject(regexp) catch return null;
    if (regexp_object.class_id != core.class.ids.regexp) return null;
    var source = std.ArrayList(u8).empty;
    defer source.deinit(rt.memory.allocator);
    if (!try appendRegExpSource(rt, regexp_object, &source)) return null;

    var flags = std.ArrayList(u8).empty;
    defer flags.deinit(rt.memory.allocator);
    if (!try appendRegExpFlags(rt, regexp_object, &flags)) return null;

    var compiled = quickjs_regexp.compile(rt.memory.allocator, source.items, flags.items) catch |err| switch (err) {
        error.InvalidPattern, error.Unsupported => return null,
        else => |other| return other,
    };
    defer compiled.deinit(rt.memory.allocator);

    const input_len = try stringLengthIndex(rt, string_value);
    const status = quickjs_regexp.execOnStringFromIndex(compiled, string_value, 0) catch |err| switch (err) {
        error.BytecodeCorrupt, error.Timeout => return null,
        else => return err,
    };
    switch (status.result) {
        .match => {
            if (status.match.start > input_len) return core.Value.int32(-1);
            return core.Value.int32(@intCast(status.match.start));
        },
        .no_match, .out_of_range => return core.Value.int32(-1),
        .not_available => return null,
    }
}

pub fn qjsRegExpMatch(rt: *core.Runtime, global: *core.Object, regexp: core.Value, string_value: core.Value) !?core.Value {
    const regexp_object = property_ops.expectObject(regexp) catch return null;
    if (regexp_object.class_id != core.class.ids.regexp) return null;
    var source = std.ArrayList(u8).empty;
    defer source.deinit(rt.memory.allocator);
    if (!try appendRegExpSource(rt, regexp_object, &source)) return null;

    var flags = std.ArrayList(u8).empty;
    defer flags.deinit(rt.memory.allocator);
    if (!try appendRegExpFlags(rt, regexp_object, &flags)) return null;
    const is_global = std.mem.indexOfScalar(u8, flags.items, 'g') != null;
    const has_indices = std.mem.indexOfScalar(u8, flags.items, 'd') != null;

    if (!is_global) {
        // Non-global: single LRE match.
        var compiled = quickjs_regexp.compile(rt.memory.allocator, source.items, flags.items) catch |err| switch (err) {
            error.InvalidPattern, error.Unsupported => return null,
            else => |other| return other,
        };
        defer compiled.deinit(rt.memory.allocator);
        const input_len = try stringLengthIndex(rt, string_value);
        const status = quickjs_regexp.execOnStringFromIndex(compiled, string_value, 0) catch |err| switch (err) {
            error.BytecodeCorrupt, error.Timeout => return null,
            else => return err,
        };
        switch (status.result) {
            .match => {
                if (status.match.start > input_len) return core.Value.nullValue();
                var found = RegExpMatch{
                    .index = status.match.start,
                    .len = status.match.end - status.match.start,
                    .capture_count = status.match.capture_count,
                };
                var ci: usize = 0;
                while (ci < status.match.capture_count) : (ci += 1) {
                    const capture = status.match.captures[ci];
                    if (capture.start) |cs| {
                        found.captures[ci] = .{ .start = cs, .len = capture.end.? - cs, .undefined = false, .name = capture.name };
                    } else {
                        found.captures[ci] = .{ .start = 0, .len = 0, .undefined = true, .name = capture.name };
                    }
                }
                return try createRegExpMatchArrayFromValue(rt, global, string_value, found, has_indices);
            },
            .no_match, .out_of_range, .not_available => return null,
        }
    }

    // Global: iterate through all matches
    var compiled = quickjs_regexp.compile(rt.memory.allocator, source.items, flags.items) catch |err| switch (err) {
        error.InvalidPattern, error.Unsupported => return null,
        else => |other| return other,
    };
    defer compiled.deinit(rt.memory.allocator);
    const input_len = try stringLengthIndex(rt, string_value);

    const out = try core.Object.createArray(rt, null);
    errdefer core.Object.destroyFromHeader(rt, &out.header);
    var out_index: u32 = 0;
    var search_pos: usize = 0;
    while (search_pos <= input_len) {
        const status = quickjs_regexp.execOnStringFromIndex(compiled, string_value, search_pos) catch |err| switch (err) {
            error.BytecodeCorrupt, error.Timeout => return null,
            else => return err,
        };
        switch (status.result) {
            .match => {
                const match = status.match;
                if (match.start > input_len) break;
                const match_str = try stringSliceValue(rt, string_value, match.start, match.end - match.start);
                defer match_str.free(rt);
                try out.defineOwnProperty(rt, core.atom.atomFromUInt32(out_index), core.Descriptor.data(match_str, true, true, true));
                out_index += 1;
                if (match.end == search_pos) {
                    // Advance past zero-length match
                    search_pos = match.end + 1;
                } else {
                    search_pos = match.end;
                }
            },
            .no_match, .out_of_range, .not_available => break,
        }
    }
    if (out_index == 0) {
        core.Object.destroyFromHeader(rt, &out.header);
        return core.Value.nullValue();
    }
    return out.value();
}

pub fn appendRegExpSource(rt: *core.Runtime, object: *core.Object, out: *std.ArrayList(u8)) !bool {
    if (object.regexpSource()) |source_value| {
        try value_ops.appendValueString(rt, out, source_value);
        return true;
    }
    return false;
}

pub fn appendRegExpFlags(rt: *core.Runtime, object: *core.Object, out: *std.ArrayList(u8)) !bool {
    if (object.regexpFlags()) |flags_value| {
        try value_ops.appendRawString(rt, out, flags_value);
        return true;
    }
    return false;
}

pub fn appendRegExpInputUnits(rt: *core.Runtime, out: *std.ArrayList(u8), value: core.Value) !void {
    const header = value.refHeader() orelse return value_ops.appendRawString(rt, out, value);
    if (!value.isString()) return value_ops.appendRawString(rt, out, value);
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    switch (string_value.resolveData()) {
        .latin1 => |bytes| try out.appendSlice(rt.memory.allocator, bytes),
        .utf16 => |units| {
            for (units) |unit| {
                const tag: u8 = if (unit <= 0xff) @intCast(unit) else @intCast(unit >> 8);
                try out.append(rt.memory.allocator, tag);
            }
        },
    }
}

pub fn singleUnicodeEscapeUnit(source: []const u8) ?u16 {
    if (source.len != 6 or source[0] != '\\' or source[1] != 'u') return null;
    var value: u16 = 0;
    var index: usize = 2;
    while (index < source.len) : (index += 1) {
        const digit = std.fmt.charToDigit(source[index], 16) catch return null;
        value = value * 16 + @as(u16, @intCast(digit));
    }
    return value;
}

pub fn singleLowSurrogateLiteralSource(source: []const u8) ?u16 {
    const unit = singleUnicodeEscapeUnit(source) orelse return null;
    return if (isLowSurrogateUnit(unit)) unit else null;
}

pub fn unicodeLowSurrogateLiteralMatch(source: []const u8, value: core.Value, start: usize, sticky: bool) ?RegExpMatch {
    const unit = singleLowSurrogateLiteralSource(source) orelse return null;
    const header = value.refHeader() orelse return null;
    if (!value.isString()) return null;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    if (start > string_value.len()) return null;
    if (sticky) return lowSurrogateLiteralAt(unit, string_value.*, start);
    var index = start;
    while (index < string_value.len()) {
        if (lowSurrogateLiteralAt(unit, string_value.*, index)) |found| return found;
        index = advanceStringIndexStringValue(string_value.*, index, true);
    }
    return null;
}

fn lowSurrogateLiteralAt(unit: u16, string_value: core.string.String, pos: usize) ?RegExpMatch {
    if (pos >= string_value.len() or string_value.codeUnitAt(pos) != unit) return null;
    return .{ .index = pos, .len = 1 };
}

fn advanceStringIndexStringValue(string_value: core.string.String, index: usize, unicode: bool) usize {
    if (!unicode or index + 1 >= string_value.len()) return index + 1;
    const first = string_value.codeUnitAt(index);
    const second = string_value.codeUnitAt(index + 1);
    return index + if (isHighSurrogateUnit(first) and isLowSurrogateUnit(second)) @as(usize, 2) else 1;
}

pub fn singleUnicodeClassEscapeUnit(source: []const u8) ?u16 {
    if (source.len != 8 or source[0] != '[' or source[1] != '\\' or source[2] != 'u' or source[7] != ']') return null;
    var value: u16 = 0;
    var index: usize = 3;
    while (index < 7) : (index += 1) {
        const digit = std.fmt.charToDigit(source[index], 16) catch return null;
        value = value * 16 + @as(u16, @intCast(digit));
    }
    return value;
}

pub fn findCharacterClassEnd(source: []const u8, class_start: usize) ?usize {
    if (class_start >= source.len or source[class_start] != '[') return null;
    var index = class_start + 1;
    var at_start = true;
    while (index < source.len) : (index += 1) {
        if (source[index] == '\\') {
            if (index + 1 >= source.len) return null;
            index += 1;
            at_start = false;
            continue;
        }
        if (source[index] == ']' and !at_start) return index;
        at_start = false;
    }
    return null;
}

pub fn standaloneCharacterClassSource(source: []const u8) ?[]const u8 {
    if (source.len < 2 or source[0] != '[') return null;
    const class_end = findCharacterClassEnd(source, 0) orelse return null;
    if (class_end + 1 != source.len) return null;
    return source;
}

pub fn leadingAlternationCharacterClassSource(source: []const u8) ?[]const u8 {
    if (!std.mem.startsWith(u8, source, "(?:[")) return null;
    const class_end = findCharacterClassEnd(source, 3) orelse return null;
    if (class_end + 1 >= source.len or source[class_end + 1] != '|') return null;
    return source[3 .. class_end + 1];
}

pub fn findCharacterClassSourceMatch(value: core.Value, source: []const u8, start: usize, sticky: bool) ?RegExpMatch {
    const header = value.refHeader() orelse return null;
    if (!value.isString()) return null;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    switch (string_value.resolveData()) {
        .latin1 => |bytes| {
            if (sticky) {
                if (start >= bytes.len or !builtins.regexp.classMatchesUtf16Unit(source, bytes[start])) return null;
                return RegExpMatch{ .index = start, .len = 1 };
            }
            var index = start;
            while (index < bytes.len) : (index += 1) {
                if (!builtins.regexp.classMatchesUtf16Unit(source, bytes[index])) continue;
                return RegExpMatch{ .index = index, .len = 1 };
            }
        },
        .utf16 => |units| {
            if (sticky) {
                if (start >= units.len or !builtins.regexp.classMatchesUtf16Unit(source, units[start])) return null;
                return RegExpMatch{ .index = start, .len = 1 };
            }
            var index = start;
            while (index < units.len) : (index += 1) {
                if (!builtins.regexp.classMatchesUtf16Unit(source, units[index])) continue;
                return RegExpMatch{ .index = index, .len = 1 };
            }
        },
    }
    return null;
}

pub fn findStandaloneCharacterClassMatch(value: core.Value, source: []const u8, start: usize, sticky: bool) ?RegExpMatch {
    const class_source = standaloneCharacterClassSource(source) orelse return null;
    return findCharacterClassSourceMatch(value, class_source, start, sticky);
}

pub fn findLeadingAlternationCharacterClassSingleUnitMatch(rt: *core.Runtime, value: core.Value, source: []const u8, start: usize, sticky: bool) ?RegExpMatch {
    const class_source = leadingAlternationCharacterClassSource(source) orelse return null;
    const input_len = stringLengthIndex(rt, value) catch return null;
    if (input_len != 1) return null;
    return findCharacterClassSourceMatch(value, class_source, start, sticky);
}

pub fn findStringUnitMatch(value: core.Value, unit: u16, start: usize) ?usize {
    const header = value.refHeader() orelse return null;
    if (!value.isString()) return null;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    switch (string_value.resolveData()) {
        .latin1 => |bytes| {
            if (unit > 0xff) return null;
            var index = start;
            while (index < bytes.len) : (index += 1) {
                if (bytes[index] == @as(u8, @intCast(unit))) return index;
            }
        },
        .utf16 => |units| {
            var index = start;
            while (index < units.len) : (index += 1) {
                if (units[index] == unit) return index;
            }
        },
    }
    return null;
}

const SimpleUnicodeLiteralPattern = struct {
    units: [64]u16 = undefined,
    len: usize = 0,
    anchor_start: bool = false,
    anchor_end: bool = false,
};

const SimpleClassSequenceAtom = core.object.RegExpSimpleClassSequenceAtom;

const SimpleCaptureSequenceAtom = core.object.RegExpSimpleCaptureSequenceAtom;

const SimpleClassPredicate = core.object.RegExpSimpleClassPredicate;

const SimpleCaptureSequencePattern = core.object.RegExpSimpleCaptureSequencePattern;

const SimpleClassSequencePattern = core.object.RegExpSimpleClassSequencePattern;
const SimpleClassAlternationPattern = core.object.RegExpSimpleClassAlternationPattern;

pub fn isSimpleUnicodeLiteralSource(source: []const u8) bool {
    return parseSimpleUnicodeLiteralSource(source) != null;
}

pub fn isSimpleClassSequenceSource(source: []const u8, flags: []const u8) bool {
    return parseSimpleClassSequenceSource(source, flags) != null;
}

pub fn parseSimpleCaptureSequenceSource(source: []const u8, flags: []const u8) ?SimpleCaptureSequencePattern {
    if (source.len == 0 or hasFlag(flags, 'i') or hasFlag(flags, 'u') or hasFlag(flags, 'v') or hasFlag(flags, 's')) return null;
    var pattern = SimpleCaptureSequencePattern{};
    var index: usize = 0;
    if (source[index] == '^') {
        pattern.anchor_start = true;
        index += 1;
    }
    const end_limit = if (source.len > index and source[source.len - 1] == '$') blk: {
        pattern.anchor_end = true;
        break :blk source.len - 1;
    } else source.len;
    while (index < end_limit) {
        if (pattern.len >= pattern.atoms.len) return null;
        var capture_index: ?usize = null;
        var atom: SimpleCaptureSequenceAtom = undefined;
        if (source[index] == '(') {
            if (index + 1 >= end_limit or source[index + 1] == '?') return null;
            index += 1;
            pattern.capture_count += 1;
            if (pattern.capture_count > 255) return null;
            capture_index = pattern.capture_count;
            atom = parseSimpleCaptureSequenceAtom(source, &index, end_limit, capture_index) orelse return null;
            if (index >= end_limit or source[index] != ')') return null;
            index += 1;
            if (index < end_limit) {
                switch (source[index]) {
                    '*', '+', '?', '{' => return null,
                    else => {},
                }
            }
        } else {
            atom = parseSimpleCaptureSequenceAtom(source, &index, end_limit, null) orelse return null;
        }
        pattern.atoms[pattern.len] = atom;
        pattern.len += 1;
    }
    if (pattern.len == 0 or pattern.capture_count == 0) return null;
    return pattern;
}

fn parseSimpleCaptureSequenceAtom(source: []const u8, index: *usize, end_limit: usize, capture_index: ?usize) ?SimpleCaptureSequenceAtom {
    var atom = SimpleCaptureSequenceAtom{ .capture_index = capture_index };
    if (index.* >= end_limit) return null;
    if (source[index.*] == '[') {
        const class_end = findCharacterClassEnd(source, index.*) orelse return null;
        if (class_end >= end_limit) return null;
        atom.kind = .class;
        atom.class_source = source[index.* .. class_end + 1];
        atom.class_predicate = simpleClassPredicateFromSource(atom.class_source);
        index.* = class_end + 1;
    } else if (source[index.*] == '\\') {
        if (index.* + 1 >= end_limit) return null;
        if (index.* + 2 < end_limit and source[index.* + 1] == '\\' and isSimpleClassEscapeByte(source[index.* + 2])) {
            atom.kind = .class;
            atom.class_source = source[index.* + 1 .. index.* + 3];
            atom.class_predicate = simpleClassPredicateFromSource(atom.class_source);
            index.* += 3;
            return parseSimpleCaptureSequenceAtomQuantifier(source, index, end_limit, capture_index, atom);
        }
        switch (source[index.* + 1]) {
            'd', 'D', 's', 'S', 'w', 'W' => {
                atom.kind = .class;
                atom.class_source = source[index.* .. index.* + 2];
                atom.class_predicate = simpleClassPredicateFromSource(atom.class_source);
                index.* += 2;
            },
            else => {
                atom.kind = .literal;
                atom.literal = parseSimpleClassSequenceEscapedLiteral(source, index, end_limit) orelse return null;
            },
        }
    } else {
        atom.kind = .literal;
        atom.literal = parseSimpleClassSequenceLiteral(source, index, end_limit) orelse return null;
    }

    return parseSimpleCaptureSequenceAtomQuantifier(source, index, end_limit, capture_index, atom);
}

fn parseSimpleCaptureSequenceAtomQuantifier(source: []const u8, index: *usize, end_limit: usize, capture_index: ?usize, initial_atom: SimpleCaptureSequenceAtom) ?SimpleCaptureSequenceAtom {
    var atom = initial_atom;
    if (index.* < end_limit) {
        switch (source[index.*]) {
            '*' => {
                if (capture_index != null) return null;
                atom.min_repeat = 0;
                atom.max_repeat = std.math.maxInt(usize);
                index.* += 1;
            },
            '+' => {
                atom.max_repeat = std.math.maxInt(usize);
                index.* += 1;
            },
            '?' => {
                if (capture_index != null) return null;
                atom.min_repeat = 0;
                atom.max_repeat = 1;
                index.* += 1;
            },
            '{', '|', ')' => {},
            else => {},
        }
    }
    return atom;
}

pub fn simpleUnicodeLiteralMatch(source: []const u8, value: core.Value, start: usize, sticky: bool, flags: []const u8) ?RegExpMatch {
    const pattern = parseSimpleUnicodeLiteralSource(source) orelse return null;
    const header = value.refHeader() orelse return null;
    if (!value.isString()) return null;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    if (start > string_value.len()) return null;
    if (sticky) return simpleUnicodeLiteralAt(pattern, string_value.*, start, flags);
    var index = start;
    while (index <= string_value.len()) : (index += 1) {
        if (simpleUnicodeLiteralAt(pattern, string_value.*, index, flags)) |found| return found;
    }
    return null;
}

pub fn simpleClassSequenceMatch(source: []const u8, value: core.Value, start: usize, sticky: bool, flags: []const u8) ?RegExpMatch {
    const pattern = parseSimpleClassSequenceSource(source, flags) orelse return null;
    return simpleClassSequenceMatchPattern(pattern, value, start, sticky, flags);
}

const SimpleClassSequenceLengthLoopResult = struct {
    total_len: usize,
    match_count: usize,
    last_found: ?RegExpMatch,
};

const SimpleClassAlternationLengthLoopResult = struct {
    total_len: usize,
    match_count: usize,
    last_found: ?RegExpMatch,
};

fn simpleClassSequenceSingleUnitLengthLoop(pattern: SimpleClassSequencePattern, value: core.Value, start: usize, sticky: bool) ?SimpleClassSequenceLengthLoopResult {
    if (pattern.len != 1 or pattern.anchor_start or pattern.anchor_end) return null;
    const atom = pattern.atoms[0];
    if (atom.min_repeat != 1 or atom.max_repeat != 1) return null;
    const header = value.refHeader() orelse return null;
    if (!value.isString()) return null;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    return switch (string_value.resolveData()) {
        .latin1 => |bytes| simpleClassSequenceSingleUnitLengthLoopLatin1(atom, bytes, start, sticky),
        .utf16 => |units| simpleClassSequenceSingleUnitLengthLoopUtf16(atom, units, start, sticky),
    };
}

fn simpleClassAlternationSingleAtomRunLengthLoop(pattern: SimpleClassAlternationPattern, value: core.Value, start: usize, sticky: bool) ?SimpleClassAlternationLengthLoopResult {
    if (pattern.len < 2) return null;
    for (pattern.alternatives[0..pattern.len]) |alternative| {
        if (alternative.len != 1 or alternative.anchor_start or alternative.anchor_end) return null;
        const atom = alternative.atoms[0];
        if (atom.min_repeat != 1) return null;
        if (atom.max_repeat != 1 and atom.max_repeat != std.math.maxInt(usize)) return null;
    }

    const header = value.refHeader() orelse return null;
    if (!value.isString()) return null;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    return switch (string_value.resolveData()) {
        .latin1 => |bytes| simpleClassAlternationSingleAtomRunLengthLoopLatin1(pattern, bytes, start, sticky),
        .utf16 => |units| simpleClassAlternationSingleAtomRunLengthLoopUtf16(pattern, units, start, sticky),
    };
}

fn simpleClassAlternationLengthLoop(pattern: SimpleClassAlternationPattern, value: core.Value, start: usize, sticky: bool, flags: []const u8) ?SimpleClassAlternationLengthLoopResult {
