fn simpleClassAlternationLengthLoopLatin1(pattern: SimpleClassAlternationPattern, bytes: []const u8, start: usize, sticky: bool, flags: []const u8) ?SimpleClassAlternationLengthLoopResult {
    if (simpleClassAlternationLiteralLengthLoopLatin1(pattern, bytes, start, sticky)) |result| return result;
    var total_len: usize = 0;
