pub fn appendDecodedRegExpGroupName(rt: *core.Runtime, out: *std.ArrayList(u8), name: []const u8) !void {
    var index: usize = 0;
    while (index < name.len) {
        if (name[index] == '\\' and index + 1 < name.len and name[index + 1] == 'u') {
            if (readRegExpGroupNameEscape(name, &index)) |cp| {
                var code_point = cp;
                if (isHighSurrogateCodePoint(cp)) {
                    const saved = index;
                    if (readRegExpGroupNameEscape(name, &index)) |low| {
                        if (isLowSurrogateCodePoint(low)) {
                            code_point = combinedSurrogateCodePoint(@intCast(cp), @intCast(low));
                        } else {
                            index = saved;
                        }
                    } else {
                        index = saved;
                    }
                }
                try appendUtf8CodePointForRegExpName(rt, out, code_point);
                continue;
            }
        }
        try out.append(rt.memory.allocator, name[index]);
        index += 1;
    }
}

pub fn readRegExpGroupNameEscape(name: []const u8, index: *usize) ?u21 {
    if (index.* + 2 > name.len or name[index.*] != '\\' or name[index.* + 1] != 'u') return null;
    var pos = index.* + 2;
    if (pos < name.len and name[pos] == '{') {
        pos += 1;
        var value: u32 = 0;
        var saw_digit = false;
        while (pos < name.len and name[pos] != '}') : (pos += 1) {
            const digit = std.fmt.charToDigit(name[pos], 16) catch return null;
            saw_digit = true;
            value = value * 16 + digit;
            if (value > 0x10ffff) return null;
        }
        if (!saw_digit or pos >= name.len or name[pos] != '}') return null;
        index.* = pos + 1;
        return @intCast(value);
    }
    if (pos >= name.len or !std.ascii.isHex(name[pos])) return null;
    var available_hex: usize = 0;
    while (pos + available_hex < name.len and available_hex < 4 and std.ascii.isHex(name[pos + available_hex])) : (available_hex += 1) {}
    const digit_count: usize = if (available_hex >= 4) 4 else available_hex;
    var value: u32 = 0;
    var count: usize = 0;
    while (count < digit_count) : (count += 1) {
        const digit = std.fmt.charToDigit(name[pos + count], 16) catch return null;
        value = value * 16 + digit;
    }
    index.* = pos + digit_count;
    return @intCast(value);
}

pub fn appendUtf8CodePointForRegExpName(rt: *core.Runtime, out: *std.ArrayList(u8), cp: u21) !void {
    if (cp <= 0x7f) {
        try out.append(rt.memory.allocator, @intCast(cp));
    } else if (cp <= 0x7ff) {
        try out.append(rt.memory.allocator, @intCast(0xc0 | (cp >> 6)));
        try out.append(rt.memory.allocator, @intCast(0x80 | (cp & 0x3f)));
    } else if (cp <= 0xffff) {
        try out.append(rt.memory.allocator, @intCast(0xe0 | (cp >> 12)));
        try out.append(rt.memory.allocator, @intCast(0x80 | ((cp >> 6) & 0x3f)));
        try out.append(rt.memory.allocator, @intCast(0x80 | (cp & 0x3f)));
    } else {
        try out.append(rt.memory.allocator, @intCast(0xf0 | (cp >> 18)));
        try out.append(rt.memory.allocator, @intCast(0x80 | ((cp >> 12) & 0x3f)));
        try out.append(rt.memory.allocator, @intCast(0x80 | ((cp >> 6) & 0x3f)));
        try out.append(rt.memory.allocator, @intCast(0x80 | (cp & 0x3f)));
    }
}

pub fn isHighSurrogateCodePoint(cp: u21) bool {
    return cp >= 0xd800 and cp <= 0xdbff;
}

pub fn isLowSurrogateCodePoint(cp: u21) bool {
    return cp >= 0xdc00 and cp <= 0xdfff;
}

pub fn combinedSurrogateCodePoint(high: u16, low: u16) u21 {
    return 0x10000 + ((@as(u21, high) - 0xd800) << 10) + (@as(u21, low) - 0xdc00);
}

pub fn createRegExpMatchArrayFromStringValue(rt: *core.Runtime, input_value: core.Value, found: RegExpMatch) !core.Value {
    const out = try core.Object.createArray(rt, null);
    errdefer core.Object.destroyFromHeader(rt, &out.header);
    try defineSplitValueElement(rt, out, 0, input_value);
    try out.defineOwnProperty(rt, core.atom.predefinedId("index", .string).?, core.Descriptor.data(core.Value.int32(@intCast(found.index)), true, true, true));
    try out.defineOwnProperty(rt, core.atom.predefinedId("input", .string).?, core.Descriptor.data(input_value, true, true, true));
    return out.value();
}

pub fn createRegExpMatchArrayFromStringSliceValue(rt: *core.Runtime, input_value: core.Value, start: usize, len: usize) !core.Value {
    const out = try core.Object.createArray(rt, null);
    errdefer core.Object.destroyFromHeader(rt, &out.header);
    const match_value = try stringSliceValue(rt, input_value, start, len);
    defer match_value.free(rt);
    try defineSplitValueElement(rt, out, 0, match_value);
    try out.defineOwnProperty(rt, core.atom.predefinedId("index", .string).?, core.Descriptor.data(core.Value.int32(@intCast(start)), true, true, true));
    try out.defineOwnProperty(rt, core.atom.predefinedId("input", .string).?, core.Descriptor.data(input_value, true, true, true));
    return out.value();
}

pub fn stringSliceValue(rt: *core.Runtime, value: core.Value, start: usize, len: usize) !core.Value {
    const header = value.refHeader() orelse return value.dup();
    if (!value.isString()) return value.dup();
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    const input_len = string_value.len();
    const slice_start = @min(start, input_len);
    const slice_end = @min(input_len, slice_start + len);
    const slice_len = slice_end - slice_start;
    if (slice_start == 0 and slice_len == input_len) return value.dup();
    if (slice_len == 0) return (try rt.emptyString()).value().dup();
    if (slice_len == 1) {
        const unit = string_value.codeUnitAt(slice_start);
        if (unit <= 0x7f) {
            const cached = (try rt.singleByteString(@intCast(unit))) orelse unreachable;
            return cached.value().dup();
        }
    }
    return (try core.string.String.createSlice(rt, string_value, slice_start, slice_len)).value();
}

pub fn toUint32Number(number: f64) u32 {
    if (std.math.isNan(number) or !std.math.isFinite(number) or number == 0) return 0;
    const integer = if (number < 0) -@floor(@abs(number)) else @floor(number);
    const modulo = @mod(integer, 4294967296.0);
    return @intFromFloat(modulo);
}

pub fn uint32NumberValue(value: u32) core.Value {
    if (value <= @as(u32, @intCast(std.math.maxInt(i32)))) return core.Value.int32(@intCast(value));
    return core.Value.float64(@floatFromInt(value));
}

pub fn getStringPrototypeMethodId(rt: *core.Runtime, function_object: *core.Object) ?u32 {
    _ = rt;
    const native_ref = core.function.decodeNativeBuiltinId(function_object.nativeFunctionId()) orelse return null;
    if (native_ref.domain != .string) return null;
    return builtins.string.decodePrototypeMethodId(native_ref.id);
}

pub fn qjsPrimitivePrototypeMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    function_object: *core.Object,
    this_value: core.Value,
    id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const rt = ctx.runtime;
    const tag: i32 = @intCast(id);
    const class_tag = @divTrunc(tag, 10);
    const method_tag = @mod(tag, 10);
    const primitive = primitivePrototypeThisValue(rt, this_value, class_tag) catch return throwPrimitivePrototypeTypeError(ctx, global, function_object);
    defer primitive.free(rt);
    return switch (method_tag) {
        1 => if (class_tag == 1)
            builtins.number.toStringMethod(rt, primitive, args)
        else if (class_tag == 3)
            qjsBigIntPrototypeToString(ctx, output, global, primitive, args, caller_function, caller_frame)
        else
            value_ops.toStringValue(rt, primitive),
        2 => primitive.dup(),
        else => error.TypeError,
    };
}

fn throwPrimitivePrototypeTypeError(
    ctx: *core.Context,
    global: *core.Object,
    function_object: *core.Object,
) !core.Value {
    const error_global = objectRealmGlobal(function_object) orelse global;
    const error_value = try createNamedError(ctx.runtime, error_global, "TypeError", "");
    _ = ctx.throwValue(error_value);
    return error.Test262Error;
}

fn qjsBigIntPrototypeToString(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    primitive: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    _ = caller_function;
    _ = caller_frame;
    const radix: u8 = if (args.len == 0 or args[0].isUndefined())
        10
    else blk: {
        const radix_primitive = try toPrimitiveForNumber(ctx, output, global, args[0]);
        defer radix_primitive.free(ctx.runtime);
        if (radix_primitive.isBigInt() or radix_primitive.isSymbol()) return error.TypeError;
        const radix_value = try value_ops.toNumberValue(ctx.runtime, radix_primitive);
        defer radix_value.free(ctx.runtime);
        const radix_number = value_ops.numberValue(radix_value) orelse return error.RangeError;
        if (std.math.isNan(radix_number) or !std.math.isFinite(radix_number)) return error.RangeError;
        const integer = @trunc(radix_number);
        if (integer < 2 or integer > 36) return error.RangeError;
        break :blk @intFromFloat(integer);
    };
    var bigint = try value_ops.cloneBigIntValue(ctx.runtime, primitive);
    defer bigint.deinit();
    const text = try bigint.formatBaseAlloc(ctx.runtime.memory.allocator, radix);
    defer ctx.runtime.memory.allocator.free(text);
    return value_ops.createStringValue(ctx.runtime, text);
}

pub fn getNumberPrototypeMethodId(rt: *core.Runtime, function_object: *core.Object) ?u32 {
    _ = rt;
    const native_ref = core.function.decodeNativeBuiltinId(function_object.nativeFunctionId()) orelse return null;
    if (native_ref.domain != .number) return null;
    return switch (native_ref.id) {
        @intFromEnum(builtins.number.PrototypeMethod.to_string),
        @intFromEnum(builtins.number.PrototypeMethod.to_locale_string),
        @intFromEnum(builtins.number.PrototypeMethod.to_fixed),
        @intFromEnum(builtins.number.PrototypeMethod.to_exponential),
        @intFromEnum(builtins.number.PrototypeMethod.to_precision),
        => native_ref.id,
        else => null,
    };
}

pub fn qjsNumberPrototypeMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    method_id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const primitive = primitivePrototypeThisValue(ctx.runtime, this_value, 1) catch |err| switch (err) {
        error.TypeError => return throwTypeErrorMessage(ctx, global, "not a number"),
    };
    defer primitive.free(ctx.runtime);
    const coerced_arg: ?core.Value = try coerceOptionalNumberMethodArgument(ctx, output, global, args, true);
    defer if (coerced_arg) |value| value.free(ctx.runtime);
    var coerced_storage: [1]core.Value = undefined;
    const method_args = if (coerced_arg) |value| blk: {
        coerced_storage[0] = value;
        break :blk coerced_storage[0..];
    } else args;
    _ = caller_function;
    _ = caller_frame;
    return (switch (method_id) {
        1, @intFromEnum(builtins.number.PrototypeMethod.to_string) => builtins.number.toStringMethod(ctx.runtime, primitive, method_args),
        2, @intFromEnum(builtins.number.PrototypeMethod.to_locale_string) => builtins.number.toStringMethod(ctx.runtime, primitive, &.{}),
        3, @intFromEnum(builtins.number.PrototypeMethod.to_fixed) => builtins.number.toFixed(ctx.runtime, primitive, method_args),
        4, @intFromEnum(builtins.number.PrototypeMethod.to_exponential) => builtins.number.toExponential(ctx.runtime, primitive, method_args),
        5, @intFromEnum(builtins.number.PrototypeMethod.to_precision) => builtins.number.toPrecision(ctx.runtime, primitive, method_args),
        else => error.TypeError,
    }) catch |err| switch (err) {
        error.TypeError => return throwTypeErrorMessage(ctx, global, "not a number"),
        error.RangeError => return throwRangeErrorMessage(ctx, global, "invalid number of digits"),
        else => err,
    };
}

pub fn coerceOptionalNumberMethodArgument(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    preserve_undefined: bool,
) !?core.Value {
    if (args.len == 0) return null;
    if (preserve_undefined and args[0].isUndefined()) return null;
    const primitive = try toPrimitiveForNumber(ctx, output, global, args[0]);
    defer primitive.free(ctx.runtime);
    if (primitive.isBigInt()) return error.TypeError;
    return try value_ops.toNumberValue(ctx.runtime, primitive);
}

pub fn primitivePrototypeThisValue(rt: *core.Runtime, value: core.Value, class_tag: i32) !core.Value {
    if (class_tag == 1 and value.isNumber()) return value.dup();
    if (class_tag == 2 and value.asBool() != null) return value.dup();
    if (class_tag == 3 and value.isBigInt()) return value.dup();
    if (class_tag == 4 and value.isSymbol()) return value.dup();
    if (class_tag == 5 and value.isString()) return value.dup();
    if (!value.isObject()) return error.TypeError;
    const object = try property_ops.expectObject(value);
    const matches = switch (class_tag) {
        1 => object.class_id == core.class.ids.number,
        2 => object.class_id == core.class.ids.boolean,
        3 => object.class_id == core.class.ids.big_int,
        4 => object.class_id == core.class.ids.symbol,
        5 => object.class_id == core.class.ids.string,
        else => false,
    };
    if (!matches) return error.TypeError;
    if (class_tag == 5) return (object.objectData() orelse return error.TypeError).dup();
    _ = rt;
    return (object.objectData() orelse return error.TypeError).dup();
}

pub fn primitiveWrapperStoredValue(rt: *core.Runtime, value: core.Value) ?core.Value {
    _ = rt;
    if (!value.isObject()) return null;
    const object = property_ops.expectObject(value) catch return null;
    switch (object.class_id) {
        core.class.ids.number,
        core.class.ids.boolean,
        core.class.ids.big_int,
        core.class.ids.symbol,
        => if (object.objectData()) |stored| return stored.dup() else return null,
        else => return null,
    }
}

pub fn standardStringMethodId(name: []const u8) ?u32 {
    if (std.mem.eql(u8, name, "substring")) return 1;
    if (std.mem.eql(u8, name, "toUpperCase")) return 2;
    if (std.mem.eql(u8, name, "toLocaleUpperCase")) return 2;
    if (std.mem.eql(u8, name, "toLowerCase")) return 3;
    if (std.mem.eql(u8, name, "toLocaleLowerCase")) return 3;
    if (std.mem.eql(u8, name, "indexOf")) return 4;
    if (std.mem.eql(u8, name, "includes")) return 5;
    if (std.mem.eql(u8, name, "startsWith")) return 6;
    if (std.mem.eql(u8, name, "endsWith")) return 7;
    if (std.mem.eql(u8, name, "trim")) return 8;
    if (std.mem.eql(u8, name, "lastIndexOf")) return 28;
    if (std.mem.eql(u8, name, "charCodeAt")) return 29;
    if (std.mem.eql(u8, name, "at")) return 30;
    if (std.mem.eql(u8, name, "codePointAt")) return 31;
    if (std.mem.eql(u8, name, "slice")) return 32;
    if (std.mem.eql(u8, name, "repeat")) return 33;
    if (std.mem.eql(u8, name, "padStart")) return 34;
    if (std.mem.eql(u8, name, "padEnd")) return 35;
    if (std.mem.eql(u8, name, "localeCompare")) return 36;
    if (std.mem.eql(u8, name, "normalize")) return 37;
    if (std.mem.eql(u8, name, "isWellFormed")) return 38;
    if (std.mem.eql(u8, name, "toWellFormed")) return 39;
    if (std.mem.eql(u8, name, "search")) return 40;
    if (std.mem.eql(u8, name, "match")) return 41;
    if (std.mem.eql(u8, name, "replaceAll")) return 42;
    if (std.mem.eql(u8, name, "matchAll")) return 43;
    return null;
}

pub fn genericTrimStringMethodId(name: []const u8) ?u32 {
    if (std.mem.eql(u8, name, "trim")) return 8;
    if (std.mem.eql(u8, name, "trimStart")) return 21;
    if (std.mem.eql(u8, name, "trimEnd")) return 22;
    if (std.mem.eql(u8, name, "trimLeft")) return 21;
    if (std.mem.eql(u8, name, "trimRight")) return 22;
    return null;
}

pub fn isStringMethodReceiver(value: core.Value) bool {
    if (value.isString()) return true;
    if (!value.isObject()) return !value.isNull() and !value.isUndefined();
    const object = objectFromValue(value) orelse return false;
    return object.class_id == core.class.ids.string;
}

pub fn regexpAccessorName(name: []const u8) ?[]const u8 {
    if (!std.mem.startsWith(u8, name, "get ")) return null;
    const accessor = name["get ".len..];
    if (std.mem.eql(u8, accessor, "source") or
        std.mem.eql(u8, accessor, "flags") or
        std.mem.eql(u8, accessor, "global") or
        std.mem.eql(u8, accessor, "ignoreCase") or
        std.mem.eql(u8, accessor, "multiline") or
        std.mem.eql(u8, accessor, "dotAll") or
        std.mem.eql(u8, accessor, "unicode") or
        std.mem.eql(u8, accessor, "sticky") or
        std.mem.eql(u8, accessor, "hasIndices") or
        std.mem.eql(u8, accessor, "unicodeSets")) return accessor;
    return null;
}

pub fn annexBStringMethodId(name: []const u8) ?u32 {
