    }
    try initializeClassInstanceFields(ctx.runtime, instance, fb.class_instance_fields, remap_object);
    const init_function = if (constructor_object) |object|
        object.functionClassFieldsInitSlot().*
    else
        fb.class_fields_init;
    if (init_function) |initializer| {
        const result = try callValueOrBytecode(ctx, output, global, instance, initializer, &.{}, caller_function, caller_frame);
        result.free(ctx.runtime);
    }
}

pub fn initializeCurrentConstructorClassInstanceElements(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: *frame_mod.Frame,
) !void {
    if (caller_frame.this_value.isUninitialized()) return;
    if (functionObjectFromValue(caller_frame.current_function)) |function_object| {
        const function_value = function_object.functionBytecodeSlot().* orelse return;
        const fb = functionBytecodeFromValue(function_value) orelse return;
        try initializeClassInstanceElements(ctx, output, global, caller_frame.current_function, caller_frame.this_value, fb, caller_function, caller_frame);
        return;
    }
    if (functionBytecodeFromValue(caller_frame.current_function)) |fb| {
        try initializeClassInstanceElements(ctx, output, global, caller_frame.current_function, caller_frame.this_value, fb, caller_function, caller_frame);
    }
}

pub fn initializeClassPrivateMethods(rt: *core.Runtime, instance: *core.Object, home_object: *core.Object) !void {
    for (home_object.properties) |entry| {
        if (rt.atoms.kind(entry.atom_id) != .private) continue;
        if (instance.hasOwnProperty(entry.atom_id)) return error.TypeError;
        if (home_object.getOwnProperty(entry.atom_id)) |desc| {
            defer desc.destroy(rt);
            instance.defineOwnProperty(rt, entry.atom_id, desc) catch |err| switch (err) {
                error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
                else => return err,
            };
        }
    }
}

pub fn initializeClassInstanceFields(rt: *core.Runtime, instance: core.Value, fields: []const core.Atom, remap_object: ?*const core.Object) !void {
    if (fields.len == 0) return;
    const object = try property_ops.expectObject(instance);
    for (fields) |atom_id| {
        const effective_atom = remapPrivateAtomForOperation(rt, null, remap_object, atom_id);
        try defineClassFieldDataProperty(rt, object, effective_atom, core.Value.undefinedValue());
    }
}

pub fn defineClassFieldDataProperty(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom, value: core.Value) !void {
    if (rt.atoms.kind(atom_id) == .private and object.hasOwnProperty(atom_id)) return error.TypeError;
    object.defineOwnProperty(rt, atom_id, core.Descriptor.data(value, true, true, true)) catch |err| switch (err) {
        error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
        else => return err,
    };
}

pub fn qjsTypedArrayConstructFromIterable(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1 or !args[0].isObject()) return null;
    const source_object = objectFromValue(args[0]) orelse return null;
    if (builtins.buffer.isTypedArrayObject(source_object) or source_object.class_id == core.class.ids.array_buffer or source_object.class_id == core.class.ids.shared_array_buffer) return null;
    const iterator_method = try getIteratorMethod(ctx, output, global, args[0]);
    defer iterator_method.free(ctx.runtime);
    if (iterator_method.isUndefined() or iterator_method.isNull()) return null;
    if (!isCallableValue(iterator_method)) return error.TypeError;

    var iterator = core.Value.undefinedValue();
    var values_value = core.Value.undefinedValue();
    var next_method = core.Value.undefinedValue();
    var next = core.Value.undefinedValue();
    var done = core.Value.undefinedValue();
    var item = core.Value.undefinedValue();

    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &iterator },
        .{ .value = &values_value },
        .{ .value = &next_method },
        .{ .value = &next },
        .{ .value = &done },
        .{ .value = &item },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    defer iterator.free(ctx.runtime);
    defer values_value.free(ctx.runtime);
    defer next_method.free(ctx.runtime);
    defer next.free(ctx.runtime);
    defer done.free(ctx.runtime);
    defer item.free(ctx.runtime);

    iterator = try callValueOrBytecode(ctx, output, global, args[0], iterator_method, &.{}, caller_function, caller_frame);

    const values = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
    values_value = values.value();
    const iterator_object = objectFromValue(iterator) orelse return error.TypeError;
    const next_key = try ctx.runtime.internAtom("next");
    defer ctx.runtime.atoms.free(next_key);
    next_method = try getValueProperty(ctx, output, global, iterator_object.value(), next_key, caller_function, caller_frame);
    if (!isCallableValue(next_method)) return error.TypeError;
    const done_key = core.atom.predefinedId("done", .string) orelse return error.TypeError;
    const value_key = core.atom.predefinedId("value", .string) orelse return error.TypeError;

    var index: u32 = 0;
    while (true) : (index += 1) {
        next.free(ctx.runtime);
        next = core.Value.undefinedValue();
        next = callValueOrBytecode(ctx, output, global, iterator_object.value(), next_method, &.{}, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator_object.value(), caller_function, caller_frame);
            return err;
        };
        const next_object = objectFromValue(next) orelse {
            try qjsIteratorClose(ctx, output, global, iterator_object.value(), caller_function, caller_frame);
            return error.TypeError;
        };

        done.free(ctx.runtime);
        done = core.Value.undefinedValue();
        done = getValueProperty(ctx, output, global, next_object.value(), done_key, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator_object.value(), caller_function, caller_frame);
            return err;
        };
        if (valueTruthy(done)) break;

        item.free(ctx.runtime);
        item = core.Value.undefinedValue();
        item = getValueProperty(ctx, output, global, next_object.value(), value_key, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator_object.value(), caller_function, caller_frame);
            return err;
        };
        try values.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(index), core.Descriptor.data(item, true, true, true));
    }
    values.length = index;
    if (callableObjectFromValue(constructor)) |function_object| {
        if (function_object.typedArrayElementSize() != 0 and function_object.typedArrayKind() != 0) {
            const element = construct_mod.TypedArrayElement{
                .size = function_object.typedArrayElementSize(),
                .kind = function_object.typedArrayKind(),
            };
            const prototype = try qjsTypedArrayConstructorPrototypeVm(ctx, output, global, constructor, function_object, caller_function, caller_frame);
            const constructor_global = objectRealmGlobal(function_object) orelse global;
            return try qjsTypedArrayConstructArrayLikeVm(
                ctx,
                output,
                global,
                constructor_global,
                prototype,
                element,
                values_value,
                caller_function,
                caller_frame,
            );
        }
    }
    return try construct_mod.constructValue(ctx.runtime, constructor, &.{values_value}, &.{});
}

pub fn qjsTypedArrayConstructorName(name: []const u8) bool {
    return std.mem.eql(u8, name, "Int8Array") or
        std.mem.eql(u8, name, "Uint8Array") or
        std.mem.eql(u8, name, "Uint8ClampedArray") or
        std.mem.eql(u8, name, "Int16Array") or
        std.mem.eql(u8, name, "Uint16Array") or
        std.mem.eql(u8, name, "Int32Array") or
        std.mem.eql(u8, name, "Uint32Array") or
        std.mem.eql(u8, name, "Float16Array") or
        std.mem.eql(u8, name, "Float32Array") or
        std.mem.eql(u8, name, "Float64Array") or
        std.mem.eql(u8, name, "BigInt64Array") or
        std.mem.eql(u8, name, "BigUint64Array");
}

pub fn qjsDataViewAccessor(ctx: *core.Context, receiver: core.Value, accessor: []const u8) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.dataview) return error.TypeError;
    if (std.mem.eql(u8, accessor, "buffer")) {
        return (object.typedArrayBuffer() orelse return error.TypeError).dup();
    }
    if (std.mem.eql(u8, accessor, "byteLength")) {
        return core.Value.int32(@intCast(try builtins.buffer.dataViewByteLength(ctx.runtime, object)));
    }
    if (std.mem.eql(u8, accessor, "byteOffset")) {
        return core.Value.int32(@intCast(try builtins.buffer.dataViewByteOffset(ctx.runtime, object)));
    }
    return error.TypeError;
}

fn qjsDataViewGet(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    method_id: u32,
    args: []const core.Value,
) !core.Value {
    try builtins.buffer.dataViewRequire(receiver);
    const index_arg = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const index = try qjsTypedArrayConstructToIndex(ctx, output, global, index_arg);
    const little_endian = args.len >= 2 and value_ops.isTruthy(args[1]);
    const call_args = [_]core.Value{ lengthIndexValue(index), core.Value.boolean(little_endian) };
    return builtins.buffer.dataViewGet(ctx.runtime, receiver, method_id, call_args[0..]);
}

fn qjsDataViewSet(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    method_id: u32,
    args: []const core.Value,
) !core.Value {
    try builtins.buffer.dataViewRejectImmutable(ctx.runtime, receiver);
    const index_arg = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const index = try qjsTypedArrayConstructToIndex(ctx, output, global, index_arg);
    const value_arg = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const coerced_value = try qjsDataViewSetCoerceValue(ctx, output, global, method_id, value_arg);
    defer coerced_value.free(ctx.runtime);
    const little_endian = args.len >= 3 and value_ops.isTruthy(args[2]);
    const call_args = [_]core.Value{ lengthIndexValue(index), coerced_value, core.Value.boolean(little_endian) };
    return builtins.buffer.dataViewSet(ctx.runtime, receiver, method_id, call_args[0..]);
}

fn qjsDataViewSetCoerceValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    method_id: u32,
    value: core.Value,
) !core.Value {
    const primitive = try toPrimitiveForNumber(ctx, output, global, value);
    errdefer primitive.free(ctx.runtime);
    if (method_id == 9 or method_id == 10) return primitive;
    if (primitive.isBigInt()) return error.TypeError;
    const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
    primitive.free(ctx.runtime);
    return number_value;
}

pub fn dataViewGetId(name: []const u8) ?u32 {
    if (std.mem.eql(u8, name, "getInt8")) return 1;
    if (std.mem.eql(u8, name, "getUint8")) return 2;
    if (std.mem.eql(u8, name, "getInt16")) return 3;
    if (std.mem.eql(u8, name, "getUint16")) return 4;
    if (std.mem.eql(u8, name, "getInt32")) return 5;
    if (std.mem.eql(u8, name, "getUint32")) return 6;
    if (std.mem.eql(u8, name, "getFloat16")) return 11;
    if (std.mem.eql(u8, name, "getFloat32")) return 7;
    if (std.mem.eql(u8, name, "getFloat64")) return 8;
    if (std.mem.eql(u8, name, "getBigInt64")) return 9;
    if (std.mem.eql(u8, name, "getBigUint64")) return 10;
    return null;
}

pub fn dataViewSetId(name: []const u8) ?u32 {
    if (std.mem.eql(u8, name, "setInt8")) return 1;
    if (std.mem.eql(u8, name, "setUint8")) return 2;
    if (std.mem.eql(u8, name, "setInt16")) return 3;
    if (std.mem.eql(u8, name, "setUint16")) return 4;
    if (std.mem.eql(u8, name, "setInt32")) return 5;
    if (std.mem.eql(u8, name, "setUint32")) return 6;
    if (std.mem.eql(u8, name, "setFloat16")) return 11;
    if (std.mem.eql(u8, name, "setFloat32")) return 7;
    if (std.mem.eql(u8, name, "setFloat64")) return 8;
    if (std.mem.eql(u8, name, "setBigInt64")) return 9;
    if (std.mem.eql(u8, name, "setBigUint64")) return 10;
    return null;
}

pub fn bigIntStaticUnsigned(name: []const u8) ?bool {
    if (std.mem.eql(u8, name, "asIntN")) return false;
    if (std.mem.eql(u8, name, "asUintN")) return true;
    return null;
}

pub fn qjsArrayBufferAccessor(ctx: *core.Context, receiver: core.Value, accessor: []const u8) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.array_buffer) return error.TypeError;
    if (std.mem.eql(u8, accessor, "byteLength")) {
        return lengthIndexValue(if (object.arrayBufferDetached()) 0 else object.byteStorage().len);
    }
    if (std.mem.eql(u8, accessor, "detached")) {
        return core.Value.boolean(object.arrayBufferDetached());
    }
    if (std.mem.eql(u8, accessor, "maxByteLength")) {
        if (object.arrayBufferDetached()) return lengthIndexValue(0);
        return lengthIndexValue(object.arrayBufferMaxByteLength() orelse object.byteStorage().len);
    }
    if (std.mem.eql(u8, accessor, "resizable")) {
        return core.Value.boolean(object.arrayBufferMaxByteLength() != null);
    }
    if (std.mem.eql(u8, accessor, "immutable")) {
        return core.Value.boolean(builtins.buffer.arrayBufferIsImmutable(ctx.runtime, object));
    }
    return error.TypeError;
}

pub fn qjsSharedArrayBufferAccessor(ctx: *core.Context, receiver: core.Value, accessor: []const u8) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.shared_array_buffer) return error.TypeError;
    if (std.mem.eql(u8, accessor, "byteLength")) {
        return lengthIndexValue(object.byteStorage().len);
    }
    if (std.mem.eql(u8, accessor, "maxByteLength")) {
        return lengthIndexValue(object.arrayBufferMaxByteLength() orelse object.byteStorage().len);
    }
    if (std.mem.eql(u8, accessor, "growable")) {
        return core.Value.boolean(object.arrayBufferMaxByteLength() != null);
    }
    _ = ctx;
    return error.TypeError;
}

pub fn qjsArrayBufferIsView(args: []const core.Value) core.Value {
    if (args.len < 1) return core.Value.boolean(false);
    const object = objectFromValue(args[0]) orelse return core.Value.boolean(false);
    return core.Value.boolean(builtins.buffer.isTypedArrayObject(object) or object.class_id == core.class.ids.dataview);
}

pub fn qjsErrorIsError(args: []const core.Value) core.Value {
    if (args.len < 1) return core.Value.boolean(false);
    const object = objectFromValue(args[0]) orelse return core.Value.boolean(false);
    return core.Value.boolean(object.class_id == core.class.ids.error_);
}

pub fn qjsWeakRefDeref(rt: *core.Runtime, receiver: core.Value) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.weak_ref) return error.TypeError;
    return object.weakRefDeref(rt);
}

fn qjsConstructWeakRefWithPrototype(rt: *core.Runtime, target: core.Value, prototype: ?*core.Object) !core.Value {
    return construct_mod.weakRefWithPrototype(rt, target, prototype);
}

fn qjsConstructFinalizationRegistryWithPrototype(rt: *core.Runtime, cleanup_callback: core.Value, prototype: ?*core.Object) !core.Value {
    var rooted_cleanup_callback = cleanup_callback;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_cleanup_callback },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    const instance = try core.Object.create(rt, core.class.ids.finalization_registry, prototype);
    errdefer core.Object.destroyFromHeader(rt, &instance.header);
    instance.finalizationRegistryCleanupCallbackSlot().* = rooted_cleanup_callback.dup();
    return instance.value();
}

pub fn qjsFinalizationRegistryRegister(ctx: *core.Context, receiver: core.Value, args: []const core.Value) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.finalization_registry) return error.TypeError;
    const target = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const held_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const unregister_token = if (args.len >= 3) args[2] else core.Value.undefinedValue();
    if (!qjsCanBeHeldWeakly(ctx.runtime, target)) return error.TypeError;
    if (builtins.object.sameValue(target, held_value)) return error.TypeError;
    if (!unregister_token.isUndefined() and !qjsCanBeHeldWeakly(ctx.runtime, unregister_token)) return error.TypeError;
    if (builtins.object.sameValue(target, receiver)) return core.Value.undefinedValue();
    try qjsFinalizationRegistryAppendCell(ctx.runtime, object, target, held_value, unregister_token);
    return core.Value.undefinedValue();
}

pub fn qjsFinalizationRegistryUnregister(ctx: *core.Context, receiver: core.Value, args: []const core.Value) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.finalization_registry) return error.TypeError;
    const token = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    if (!qjsCanBeHeldWeakly(ctx.runtime, token)) return error.TypeError;
    return core.Value.boolean(object.unregisterFinalizationRegistryCells(ctx.runtime, token));
}

fn qjsFinalizationRegistryAppendCell(
    rt: *core.Runtime,
    object: *core.Object,
    target: core.Value,
    held_value: core.Value,
    unregister_token: core.Value,
) !void {
    try object.appendFinalizationRegistryCell(rt, target, held_value, unregister_token);
}

pub fn qjsCanBeHeldWeakly(rt: *core.Runtime, value: core.Value) bool {
    if (value.isObject()) return true;
    if (value.asSymbolAtom()) |atom_id| {
        return rt.atoms.kind(atom_id) == .symbol and builtins.symbol.registryKey(&rt.atoms, atom_id) == null;
    }
    return false;
}

test "qjsConstructWeakRefWithPrototype roots direct symbol target while creating weak ref" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const symbol_atom = try rt.atoms.newValueSymbol("gc-qjs-weak-ref-symbol");
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const weak_ref_value = try qjsConstructWeakRefWithPrototype(rt, core.Value.symbol(symbol_atom), null);
    var weak_ref_alive = true;
    defer if (weak_ref_alive) weak_ref_value.free(rt);
    const weak_ref = objectFromValue(weak_ref_value) orelse return error.TypeError;

    const live = weak_ref.weakRefDeref(rt);
    try std.testing.expect(live.same(core.Value.symbol(symbol_atom)));
    try std.testing.expect(rt.atoms.name(symbol_atom) != null);

    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
    try std.testing.expect(weak_ref.weakRefDeref(rt).isUndefined());

    weak_ref_value.free(rt);
    weak_ref_alive = false;
}

test "qjsConstructFinalizationRegistryWithPrototype roots function bytecode cleanup while creating registry" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const fb_slice = try rt.memory.alloc(bytecode.FunctionBytecode, 1);
    const fb = &fb_slice[0];
    fb.* = bytecode.FunctionBytecode.init(&rt.memory, &rt.atoms, core.atom.ids.empty_string);
    fb.func_kind = .generator;
    try rt.gc.add(&fb.header);
    fb.header.destroy_fn = bytecode.function.destroyFunctionBytecode;
    fb.header.destroy_ctx = @ptrCast(rt);

    const symbol_atom = try rt.atoms.newValueSymbol("gc-finalization-cleanup-bytecode-symbol");
    fb.cpool = try rt.memory.alloc(core.Value, 1);
    fb.cpool[0] = core.Value.symbol(symbol_atom);
    fb.cpool_count = 1;

    var cleanup_callback = core.Value.functionBytecode(&fb.header);
    var cleanup_callback_alive = true;
    defer if (cleanup_callback_alive) cleanup_callback.free(rt);

    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const registry_value = try qjsConstructFinalizationRegistryWithPrototype(rt, cleanup_callback, null);
    var registry_alive = true;
    defer if (registry_alive) registry_value.free(rt);
    const registry = objectFromValue(registry_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    const stored = registry.finalizationRegistryCleanupCallback() orelse return error.TypeError;
    try std.testing.expect(stored.same(cleanup_callback));

    registry_value.free(rt);
    registry_alive = false;
    cleanup_callback.free(rt);
    cleanup_callback_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

test "qjsFinalizationRegistryAppendCell roots direct symbol fields while allocating cell" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const registry = try core.Object.create(rt, core.class.ids.finalization_registry, null);
    var registry_alive = true;
    defer if (registry_alive) registry.value().free(rt);
    const target_atom = try rt.atoms.newValueSymbol("gc-finalization-target-symbol");
    const held_atom = try rt.atoms.newValueSymbol("gc-finalization-held-symbol");
    const token_atom = try rt.atoms.newValueSymbol("gc-finalization-token-symbol");
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    try qjsFinalizationRegistryAppendCell(
        rt,
        registry,
        core.Value.symbol(target_atom),
        core.Value.symbol(held_atom),
        core.Value.symbol(token_atom),
    );

    try std.testing.expect(rt.atoms.name(target_atom) != null);
    try std.testing.expect(rt.atoms.name(held_atom) != null);
    try std.testing.expect(rt.atoms.name(token_atom) != null);
    try std.testing.expectEqual(@as(usize, 1), registry.finalizationRegistryCells().len);
    const cell = registry.finalizationRegistryCells()[0];
    try std.testing.expect(cell.held_value.same(core.Value.symbol(held_atom)));
    try std.testing.expect(cell.unregister_token.same(core.Value.symbol(token_atom)));

    registry.value().free(rt);
    registry_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(target_atom) == null);
    try std.testing.expect(rt.atoms.name(held_atom) == null);
    try std.testing.expect(rt.atoms.name(token_atom) == null);
}

fn qjsSymbolFor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const key = if (args.len >= 1)
        try toStringBytesForSymbol(ctx, output, global, args[0], caller_function, caller_frame)
    else
        try ctx.runtime.memory.allocator.dupe(u8, "undefined");
    defer ctx.runtime.memory.allocator.free(key);

    const registered = try std.fmt.allocPrint(ctx.runtime.memory.allocator, "{s}{s}", .{ builtins.symbol.registry_prefix, key });
    defer ctx.runtime.memory.allocator.free(registered);
    const atom_id = try ctx.runtime.atoms.internRegisteredValueSymbol(registered);
    return core.Value.symbol(atom_id);
}

fn qjsSymbolKeyFor(rt: *core.Runtime, args: []const core.Value) !core.Value {
    const value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const atom_id = value.asSymbolAtom() orelse return error.TypeError;
    const key = builtins.symbol.registryKey(&rt.atoms, atom_id) orelse return core.Value.undefinedValue();
    return value_ops.createStringValue(rt, key);
}

fn toStringBytesForSymbol(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) ![]u8 {
    if (value.isSymbol()) return error.TypeError;
    const string_value = if (value.isString())
        value.dup()
    else
        try toStringForAnnexB(ctx, output, global, value, caller_function, caller_frame);
    defer string_value.free(ctx.runtime);

    var buffer = std.ArrayList(u8).empty;
    errdefer buffer.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendRawString(ctx.runtime, &buffer, string_value);
    return buffer.toOwnedSlice(ctx.runtime.memory.allocator);
}

pub fn qjsArrayBufferPrototypeNativeRecord(ctx: *core.Context, receiver: core.Value, id: u32, args: []const core.Value) !?core.Value {
    const object = objectFromValue(receiver) orelse return null;
    if (object.class_id == core.class.ids.shared_array_buffer) {
        return switch (id) {
            @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.slice),
            @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.resize),
            @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.transfer),
            @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.transfer_to_fixed_length),
            @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.slice_to_immutable),
            @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.transfer_to_immutable),
            => error.TypeError,
            @intFromEnum(builtins.buffer.SharedArrayBufferPrototypeMethod.slice) => {
                const start = if (args.len >= 1) args[0] else core.Value.int32(0);
                const end = if (args.len >= 2) args[1] else core.Value.undefinedValue();
                return try qjsArrayBufferSlice(ctx, receiver, object, start, end, true);
            },
            @intFromEnum(builtins.buffer.SharedArrayBufferPrototypeMethod.grow) => {
                const new_length = if (args.len >= 1) args[0] else core.Value.int32(0);
                return try qjsSharedArrayBufferGrow(ctx, receiver, new_length);
            },
            else => null,
        };
    }
    if (object.class_id != core.class.ids.array_buffer) return null;
    return switch (id) {
        @intFromEnum(builtins.buffer.SharedArrayBufferPrototypeMethod.slice),
        @intFromEnum(builtins.buffer.SharedArrayBufferPrototypeMethod.grow),
        => error.TypeError,
        @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.slice) => {
            const start = if (args.len >= 1) args[0] else core.Value.int32(0);
            const end = if (args.len >= 2) args[1] else core.Value.undefinedValue();
            return try qjsArrayBufferSlice(ctx, receiver, object, start, end, false);
        },
        @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.slice_to_immutable) => {
            const start = if (args.len >= 1) args[0] else core.Value.int32(0);
            const end = if (args.len >= 2) args[1] else core.Value.undefinedValue();
            return try qjsArrayBufferSliceToImmutable(ctx, receiver, object, start, end);
        },
        @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.resize) => {
            const new_length = if (args.len >= 1) args[0] else core.Value.int32(0);
            return try qjsArrayBufferResize(ctx, receiver, new_length);
        },
        @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.transfer) => {
            const new_length = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            return try qjsArrayBufferTransfer(ctx, receiver, new_length, false);
        },
        @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.transfer_to_fixed_length) => {
            const new_length = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            return try qjsArrayBufferTransfer(ctx, receiver, new_length, true);
        },
        @intFromEnum(builtins.buffer.ArrayBufferPrototypeMethod.transfer_to_immutable) => {
            const new_length = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            return try qjsArrayBufferTransferToImmutable(ctx, receiver, new_length);
        },
        else => null,
    };
}

fn qjsArrayBufferSlice(
    ctx: *core.Context,
    receiver: core.Value,
    object: *core.Object,
    start_value: core.Value,
    end_value: core.Value,
    shared: bool,
) !core.Value {
    const global = ctx.cached_global orelse {
        if (shared) return builtins.buffer.sharedArrayBufferSlice(ctx.runtime, receiver, start_value, end_value);
        return builtins.buffer.arrayBufferSlice(ctx.runtime, receiver, start_value, end_value);
    };
    if (object.arrayBufferDetached()) return error.TypeError;
    if (!shared and builtins.buffer.arrayBufferIsImmutable(ctx.runtime, object)) return error.TypeError;
    const source_length = object.byteStorage().len;
    const start = try qjsRelativeSliceIndex(ctx, null, global, start_value, source_length, false);
    const end = try qjsRelativeSliceIndex(ctx, null, global, end_value, source_length, true);
    const length = if (end > start) end - start else 0;
    const constructor = try qjsArrayBufferSpeciesConstructor(ctx, null, global, receiver, shared);
    defer constructor.free(ctx.runtime);
    const out_value = try constructValueOrBytecode(ctx, null, global, constructor, &.{lengthIndexValue(length)}, null, null);
    errdefer out_value.free(ctx.runtime);
    const out_object = objectFromValue(out_value) orelse return error.TypeError;
    if (shared) {
        if (out_object.class_id != core.class.ids.shared_array_buffer) return error.TypeError;
    } else {
        if (out_object.class_id != core.class.ids.array_buffer) return error.TypeError;
    }
    if (!shared and builtins.buffer.arrayBufferIsImmutable(ctx.runtime, out_object)) return error.TypeError;
    if (builtins.object.sameValue(out_value, receiver)) return error.TypeError;
    if (out_object.arrayBufferDetached()) return error.TypeError;
    if (out_object.byteStorage().len < length) return error.TypeError;
    if (object.arrayBufferDetached() or object.byteStorage().len < start + length) return error.TypeError;
    if (length != 0) @memcpy(out_object.byteStorage()[0..length], object.byteStorage()[start..end]);
    return out_value;
}

fn qjsArrayBufferSpeciesConstructor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    shared: bool,
) !core.Value {
    const default_name = if (shared) "SharedArrayBuffer" else "ArrayBuffer";
    const default_atom = try ctx.runtime.internAtom(default_name);
    defer ctx.runtime.atoms.free(default_atom);
    const default_constructor = global.getProperty(default_atom);
    var default_owned = true;
    errdefer if (default_owned) default_constructor.free(ctx.runtime);
    const constructor_value = try getValueProperty(ctx, output, global, receiver, core.atom.ids.constructor, null, null);
    defer constructor_value.free(ctx.runtime);
    if (constructor_value.isUndefined()) {
        default_owned = false;
        return default_constructor;
    }
    if (!constructor_value.isObject()) return error.TypeError;
    const species_atom = core.atom.predefinedId("Symbol.species", .symbol) orelse return error.TypeError;
    const species_value = try getValueProperty(ctx, output, global, constructor_value, species_atom, null, null);
    if (species_value.isUndefined() or species_value.isNull()) {
        species_value.free(ctx.runtime);
        default_owned = false;
        return default_constructor;
    }
    default_constructor.free(ctx.runtime);
    default_owned = false;
    if (!isConstructorLike(ctx, species_value)) {
        species_value.free(ctx.runtime);
        return error.TypeError;
    }
    return species_value;
}

fn qjsArrayBufferSliceToImmutable(
    ctx: *core.Context,
    receiver: core.Value,
    object: *core.Object,
    start_value: core.Value,
    end_value: core.Value,
) !core.Value {
    const global = ctx.cached_global orelse return builtins.buffer.arrayBufferSliceToImmutable(ctx.runtime, receiver, start_value, end_value);
    if (object.arrayBufferDetached()) return error.TypeError;
    if (builtins.buffer.arrayBufferIsImmutable(ctx.runtime, object)) return error.TypeError;
    const source_length = object.byteStorage().len;
    const start = try qjsRelativeSliceIndex(ctx, null, global, start_value, source_length, false);
    const end = try qjsRelativeSliceIndex(ctx, null, global, end_value, source_length, true);
    return builtins.buffer.arrayBufferSliceToImmutableRange(ctx.runtime, receiver, start, end);
}

fn qjsArrayBufferResize(ctx: *core.Context, receiver: core.Value, new_length_value: core.Value) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.array_buffer) return error.TypeError;
    if (builtins.buffer.arrayBufferIsImmutable(ctx.runtime, object)) return error.TypeError;
    const new_length = try qjsArrayBufferLengthArgument(ctx, new_length_value, null);
    if (object.arrayBufferDetached()) return error.TypeError;
    return builtins.buffer.arrayBufferResizeLength(ctx.runtime, receiver, new_length);
}

fn qjsSharedArrayBufferGrow(ctx: *core.Context, receiver: core.Value, new_length_value: core.Value) !core.Value {
    const new_length = try qjsArrayBufferLengthArgument(ctx, new_length_value, null);
    return builtins.buffer.sharedArrayBufferGrowLength(ctx.runtime, receiver, new_length);
}

fn qjsArrayBufferTransfer(ctx: *core.Context, receiver: core.Value, new_length_value: core.Value, fixed_length: bool) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    const fallback = if (object.class_id == core.class.ids.array_buffer) object.byteStorage().len else @as(usize, 0);
    const new_length = try qjsArrayBufferLengthArgument(ctx, new_length_value, fallback);
    return builtins.buffer.arrayBufferTransferLength(ctx.runtime, receiver, new_length, fixed_length);
}

fn qjsArrayBufferTransferToImmutable(ctx: *core.Context, receiver: core.Value, new_length_value: core.Value) !core.Value {
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (object.class_id != core.class.ids.array_buffer) return error.TypeError;
    const new_length = try qjsArrayBufferLengthArgument(ctx, new_length_value, object.byteStorage().len);
    return builtins.buffer.arrayBufferTransferToImmutableLength(ctx.runtime, receiver, new_length);
}

fn qjsArrayBufferLengthArgument(ctx: *core.Context, value: core.Value, undefined_length: ?usize) !usize {
    if (value.isUndefined()) return undefined_length orelse 0;
    const global = ctx.cached_global orelse return value_ops.toIndexUsize(ctx.runtime, value);
    return qjsTypedArrayConstructToIndex(ctx, null, global, value);
}

fn qjsRelativeSliceIndex(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    len: usize,
    undefined_is_len: bool,
) !usize {
    if (undefined_is_len and value.isUndefined()) return len;

    const primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer primitive.free(ctx.runtime);
    if (primitive.isBigInt()) return error.TypeError;
    const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
    defer number_value.free(ctx.runtime);
    const relative = value_ops.numberValue(number_value) orelse std.math.nan(f64);
    if (std.math.isNan(relative)) return 0;
    if (std.math.isNegativeInf(relative)) return 0;
    if (std.math.isPositiveInf(relative)) return len;

    const truncated = @trunc(relative);
    if (truncated < 0) {
        const len_float: f64 = @floatFromInt(len);
        const from_end = len_float + truncated;
        if (from_end <= 0) return 0;
        if (from_end >= len_float) return len;
        return @intFromFloat(from_end);
    }
    if (truncated == 0) return 0;

    const len_float: f64 = @floatFromInt(len);
    if (truncated >= len_float) return len;
    return @intFromFloat(truncated);
}

pub fn qjsTypedArrayAccessor(ctx: *core.Context, receiver: core.Value, accessor: []const u8) !core.Value {
    if (std.mem.eql(u8, accessor, "[Symbol.toStringTag]")) {
        const object = objectFromValue(receiver) orelse return core.Value.undefinedValue();
        if (!builtins.buffer.isTypedArrayObject(object)) return core.Value.undefinedValue();
        const name = typedArrayNameFromKind(object.typedArrayKind()) orelse return core.Value.undefinedValue();
        return value_ops.createStringValue(ctx.runtime, name);
    }
    const object = objectFromValue(receiver) orelse return error.TypeError;
    if (!builtins.buffer.isTypedArrayObject(object)) return error.TypeError;
    if (std.mem.eql(u8, accessor, "buffer")) {
        return (object.typedArrayBuffer() orelse return error.TypeError).dup();
    }
    if (std.mem.eql(u8, accessor, "byteLength")) {
        const byte_length = try builtins.buffer.typedArrayByteLength(ctx.runtime, object);
        return lengthIndexValue(byte_length);
    }
    if (std.mem.eql(u8, accessor, "byteOffset")) {
        return lengthIndexValue(try builtins.buffer.typedArrayByteOffset(object));
    }
    if (std.mem.eql(u8, accessor, "length")) {
        return lengthIndexValue(@intCast(try builtins.buffer.typedArrayLength(ctx.runtime, object)));
    }
    return error.TypeError;
}

pub fn typedArrayNameFromKind(kind: u8) ?[]const u8 {
    return switch (kind) {
        1 => "Int8Array",
        2 => "Uint8Array",
        3 => "Uint8ClampedArray",
        4 => "Int16Array",
        5 => "Uint16Array",
        6 => "Int32Array",
        7 => "Uint32Array",
        8 => "Float16Array",
        9 => "Float32Array",
        10 => "Float64Array",
        11 => "BigInt64Array",
        12 => "BigUint64Array",
        else => null,
    };
}

pub fn qjsTypedArraySetCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    function_object: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    const target = objectFromValue(receiver) orelse return if (is_typed_method) error.TypeError else null;
    if (!builtins.buffer.isTypedArrayObject(target)) return if (is_typed_method) error.TypeError else null;
    if (try builtins.buffer.typedArrayDetached(target)) return error.TypeError;
    if (try builtins.buffer.typedArrayOutOfBounds(target)) return error.TypeError;
    try builtins.buffer.typedArrayRejectImmutableBuffer(ctx.runtime, target);
    const source = if (args.len >= 1) args[0] else return error.TypeError;
    const offset_value = if (args.len >= 2) args[1] else core.Value.int32(0);
    const offset_number = try toIntegerOrInfinityForArrayByCopy(ctx, output, global, offset_value);
    if (offset_number < 0 or !std.math.isFinite(offset_number)) return error.RangeError;
    if (offset_number >= @as(f64, @floatFromInt(std.math.maxInt(usize)))) return error.RangeError;
    const offset: usize = @intFromFloat(offset_number);

    // Offset coercion can detach or resize either view, so revalidate after it runs.
    if (try builtins.buffer.typedArrayDetached(target)) return error.TypeError;
    if (try builtins.buffer.typedArrayOutOfBounds(target)) return error.TypeError;
    const target_length: usize = @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, target));

    if (objectFromValue(source)) |source_object| {
        if (builtins.buffer.isTypedArrayObject(source_object)) {
            if (try builtins.buffer.typedArrayDetached(source_object)) return error.TypeError;
            if (try builtins.buffer.typedArrayOutOfBounds(source_object)) return error.TypeError;
            const source_length: usize = @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, source_object));
            if (offset > target_length or source_length > target_length - offset) return error.RangeError;

            const values = try ctx.runtime.memory.alloc(core.Value, source_length);
            var filled: usize = 0;
            defer {
                var free_index: usize = 0;
                while (free_index < filled) : (free_index += 1) values[free_index].free(ctx.runtime);
                if (values.len != 0) ctx.runtime.memory.free(core.Value, values);
            }

            var snapshot_index: usize = 0;
            while (snapshot_index < source_length) : (snapshot_index += 1) {
                values[snapshot_index] = try builtins.buffer.typedArrayGetIndex(ctx.runtime, source_object, @intCast(snapshot_index));
                filled += 1;
            }

            var write_index: usize = 0;
            while (write_index < source_length) : (write_index += 1) {
                _ = try builtins.buffer.typedArraySetIndex(ctx.runtime, target, @intCast(offset + write_index), values[write_index]);
            }
            return core.Value.undefinedValue();
        }
    }

    const source_object_value = if (source.isObject()) source.dup() else try primitiveObjectForAccess(ctx.runtime, global, source);
    defer source_object_value.free(ctx.runtime);
    _ = property_ops.expectObject(source_object_value) catch return error.TypeError;

    const length_value = try getValueProperty(ctx, output, global, source_object_value, core.atom.ids.length, caller_function, caller_frame);
    defer length_value.free(ctx.runtime);
    const source_length = try toLengthIndex(ctx, output, global, length_value);
    if (offset > target_length or source_length > target_length - offset) return error.RangeError;

    var index: usize = 0;
    while (index < source_length) : (index += 1) {
        const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
        defer key.deinit(ctx.runtime);
        const value = try getValueProperty(ctx, output, global, source_object_value, key.atom, caller_function, caller_frame);
        defer value.free(ctx.runtime);
        try qjsTypedArraySetElementValue(ctx, output, global, target, offset + index, value);
    }
    return core.Value.undefinedValue();
}

fn qjsTypedArraySetElementValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target: *core.Object,
    index: usize,
    value: core.Value,
) !void {
    const coerced = if (value.isObject())
        try toPrimitiveForNumber(ctx, output, global, value)
    else
        value.dup();
    defer coerced.free(ctx.runtime);
    _ = try builtins.buffer.typedArraySetIndex(ctx.runtime, target, @intCast(index), coerced);
}

pub fn qjsPromiseConstruct(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const executor = if (args.len >= 1) args[0] else return throwTypeErrorMessage(ctx, global, "not a function");
    if (!isCallableValue(executor)) return throwTypeErrorMessage(ctx, global, "not a function");
    const fallback_global = if (objectFromValue(constructor)) |constructor_object|
        objectRealmGlobal(constructor_object) orelse global
    else
        global;
    const prototype = (try constructorPrototypeObject(ctx.runtime, constructor)) orelse promisePrototypeFromGlobal(ctx.runtime, fallback_global);
    return qjsPromiseConstructWithPrototype(ctx, output, global, prototype, args, caller_function, caller_frame);
}

pub fn qjsPromiseConstructWithPrototype(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    prototype: ?*core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const executor = if (args.len >= 1) args[0] else return throwTypeErrorMessage(ctx, global, "not a function");
    if (!isCallableValue(executor)) return throwTypeErrorMessage(ctx, global, "not a function");
    const promise = try builtins.promise.constructWithPrototype(ctx.runtime, prototype);
    errdefer promise.free(ctx.runtime);

    const resolving = try createPromiseResolvingPair(ctx.runtime, global, promise);
    const resolve = resolving.resolve;
    defer resolve.free(ctx.runtime);
    const reject = resolving.reject;
    defer reject.free(ctx.runtime);
    const result = callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), executor, &.{ resolve, reject }, caller_function, caller_frame) catch |err| {
        const promise_object = objectFromValue(promise) orelse return err;
        var reason = promiseRejectionReason(ctx, global, err);
        defer reason.deinit(ctx.runtime);
        try qjsPromiseSettleValue(ctx, global, promise_object, reason.value, true);
        reason.commit(ctx);
        return promise;
    };
    result.free(ctx.runtime);
    return promise;
}

const PromiseResolvingPairVm = struct {
    resolve: core.Value,
    reject: core.Value,
};

fn createPromiseResolvingState(rt: *core.Runtime) !*core.Object {
    var state_val = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &state_val },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    const state = try core.Object.create(rt, core.class.ids.object, null);
    state_val = state.value();
    errdefer state_val.free(rt);
    (try state.promiseAlreadyResolvedSlot(rt)).* = false;
    return state;
}

fn createPromiseResolvingPair(rt: *core.Runtime, global: *core.Object, promise: core.Value) !PromiseResolvingPairVm {
    var state_val = core.Value.undefinedValue();
    var resolve_val = core.Value.undefinedValue();
    var reject_val = core.Value.undefinedValue();

    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &state_val },
        .{ .value = &resolve_val },
        .{ .value = &reject_val },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    defer state_val.free(rt);
    defer resolve_val.free(rt);
    defer reject_val.free(rt);

    const state = try createPromiseResolvingState(rt);
    state_val = state.value();

    resolve_val = try createPromiseResolvingFunction(rt, global, promise, false, state);
    reject_val = try createPromiseResolvingFunction(rt, global, promise, true, state);

    return .{
        .resolve = resolve_val.dup(),
        .reject = reject_val.dup(),
    };
}

pub fn createPromiseResolvingFunction(rt: *core.Runtime, global: *core.Object, promise: core.Value, reject: bool, state: *core.Object) !core.Value {
    var rooted_promise = promise;
    var state_val = state.value();
    var function_val = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_promise },
        .{ .value = &state_val },
        .{ .value = &function_val },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    function_val = try builtins.function.nativeFunction(rt, "", 1);
    errdefer function_val.free(rt);
    const object = objectFromValue(function_val) orelse return error.TypeError;
    try object.setFunctionRealmGlobalPtr(rt, global);
    if (functionPrototypeFromGlobal(rt, global)) |function_proto| {
        try object.setPrototype(rt, function_proto);
    }
    object.functionPromiseResolvingTargetSlot().* = rooted_promise.dup();
    object.functionPromiseResolvingStateSlot().* = state_val.dup();
    object.functionPromiseResolvingRejectSlot().* = reject;
    return function_val;
}

test "createPromiseResolvingFunction roots promise and state while allocating function" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try qjs_vm.ensureContextGlobal(ctx);

    const state = try createPromiseResolvingState(rt);
    var state_alive = true;
    defer if (state_alive) state.value().free(rt);
    const marker_key = try rt.internAtom("marker");
    defer rt.atoms.free(marker_key);
    const state_symbol = try rt.atoms.newValueSymbol("gc-qjs-promise-resolving-state-symbol");
    try state.defineOwnProperty(rt, marker_key, core.Descriptor.data(core.Value.symbol(state_symbol), true, true, true));

    const promise_symbol = try rt.atoms.newValueSymbol("gc-qjs-promise-resolving-target-symbol");
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const function_value = try createPromiseResolvingFunction(rt, global, core.Value.symbol(promise_symbol), true, state);
    var function_alive = true;
    defer if (function_alive) function_value.free(rt);
    const function_object = objectFromValue(function_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(promise_symbol) != null);
    try std.testing.expect(rt.atoms.name(state_symbol) != null);
    try std.testing.expect(function_object.functionPromiseResolvingTarget().?.same(core.Value.symbol(promise_symbol)));
    try std.testing.expect(function_object.functionPromiseResolvingRejectSlot().*);

    state.value().free(rt);
    state_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(promise_symbol) != null);
    try std.testing.expect(rt.atoms.name(state_symbol) != null);
    const stored_state_value = function_object.functionPromiseResolvingState() orelse return error.TypeError;
    const stored_state = objectFromValue(stored_state_value) orelse return error.TypeError;
    {
        const marker_value = stored_state.getProperty(marker_key);
        defer marker_value.free(rt);
        try std.testing.expect(marker_value.same(core.Value.symbol(state_symbol)));
    }

    function_value.free(rt);
    function_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(promise_symbol) == null);
    try std.testing.expect(rt.atoms.name(state_symbol) == null);
}

fn qjsAppendPromiseReaction(rt: *core.Runtime, promise: *core.Object, reaction: core.Value) !void {
    const current = promise.promiseReactions();
    const next = try rt.memory.alloc(core.Value, current.len + 1);
    errdefer rt.memory.free(core.Value, next);
    @memcpy(next[0..current.len], current);
    next[current.len] = reaction.dup();
    promise.promiseReactionsSlot().* = next;
    if (current.len != 0) rt.memory.free(core.Value, current);
}

fn qjsPromiseReactionRecord(
    rt: *core.Runtime,
    on_fulfilled: core.Value,
    on_rejected: core.Value,
    resolve: core.Value,
    reject: core.Value,
) !core.Value {
    var rooted_on_fulfilled = on_fulfilled;
    var rooted_on_rejected = on_rejected;
    var rooted_resolve = resolve;
    var rooted_reject = reject;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_on_fulfilled },
        .{ .value = &rooted_on_rejected },
        .{ .value = &rooted_resolve },
        .{ .value = &rooted_reject },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    const record = try core.Object.create(rt, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(rt, &record.header);
    (try record.promiseReactionOnFulfilledSlot(rt)).* = rooted_on_fulfilled.dup();
    (try record.promiseReactionOnRejectedSlot(rt)).* = rooted_on_rejected.dup();
    (try record.promiseReactionResolveSlot(rt)).* = rooted_resolve.dup();
    (try record.promiseReactionRejectSlot(rt)).* = rooted_reject.dup();
    return record.value();
}

