fn qjsPromiseReactionJob(
    rt: *core.Runtime,
    global: *core.Object,
    reaction: *core.Object,
    value: core.Value,
    rejected: bool,
) !core.Value {
    var reaction_value = reaction.value();
    var rooted_value = value;
    var job_val = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &reaction_value },
        .{ .value = &rooted_value },
        .{ .value = &job_val },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    job_val = try qjsCreateBuiltinFunction(rt, global, "", 0);
    errdefer job_val.free(rt);
    const job_object = objectFromValue(job_val) orelse return error.TypeError;
    job_object.functionPromiseReactionRecordSlot().* = reaction_value.dup();
    job_object.functionPromiseReactionValueSlot().* = rooted_value.dup();
    job_object.functionPromiseReactionIsRejectedSlot().* = rejected;
    return job_val;
}

