        const then_key = try ctx.runtime.internAtom("then");
        defer ctx.runtime.atoms.free(then_key);
        const then_value = getValueProperty(ctx, output, global, next_promise, then_key, caller_function, caller_frame) catch |err| {
            const reason = try qjsPromiseErrorValue(ctx, global, err);
            defer reason.free(ctx.runtime);
            try qjsPromiseRejectCapability(ctx, output, global, capability.reject, reason, caller_function, caller_frame);
            return capability.releaseCallbacks(ctx.runtime);
        };
        defer then_value.free(ctx.runtime);
        if (!isCallableValue(then_value)) {
            const reason = try qjsPromiseErrorValue(ctx, global, error.TypeError);
            defer reason.free(ctx.runtime);
            try qjsPromiseRejectCapability(ctx, output, global, capability.reject, reason, caller_function, caller_frame);
            return capability.releaseCallbacks(ctx.runtime);
        }

        const on_fulfilled = if (all_settled)
            try qjsPromiseCombinatorCallback(ctx.runtime, global, .all_settled_keyed_fulfill, state, index)
        else
            try qjsPromiseCombinatorCallback(ctx.runtime, global, .all_keyed_resolve, state, index);
        defer on_fulfilled.free(ctx.runtime);
        const on_rejected = if (all_settled)
            try qjsPromiseCombinatorCallback(ctx.runtime, global, .all_settled_keyed_reject, state, index)
        else
            capability.reject.dup();
        defer on_rejected.free(ctx.runtime);

        const then_result = callValueOrBytecode(ctx, output, global, next_promise, then_value, &.{ on_fulfilled, on_rejected }, caller_function, caller_frame) catch |err| {
            const reason = try qjsPromiseErrorValue(ctx, global, err);
            defer reason.free(ctx.runtime);
            try qjsPromiseRejectCapability(ctx, output, global, capability.reject, reason, caller_function, caller_frame);
            return capability.releaseCallbacks(ctx.runtime);
        };
        then_result.free(ctx.runtime);
        index += 1;
    }

    const remaining = state.promiseCombinatorRemaining();
    const next_remaining = remaining - 1;
    (try state.promiseCombinatorRemainingSlot(ctx.runtime)).* = next_remaining;
    if (next_remaining == 0) {
        const keyed_result = try qjsPromiseKeyedResult(ctx.runtime, keys, values);
        defer keyed_result.free(ctx.runtime);
        const result = callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), capability.resolve, &.{keyed_result}, caller_function, caller_frame) catch |err| {
            const reason = try qjsPromiseErrorValue(ctx, global, err);
            defer reason.free(ctx.runtime);
            try qjsPromiseRejectCapability(ctx, output, global, capability.reject, reason, caller_function, caller_frame);
            return capability.releaseCallbacks(ctx.runtime);
        };
        result.free(ctx.runtime);
    }

    return capability.releaseCallbacks(ctx.runtime);
}

fn qjsPromiseStaticCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor_value: core.Value,
    args: []const core.Value,
    mode: PromiseStaticMode,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (!constructor_value.isObject()) return error.TypeError;
    if (!isConstructorLike(ctx, constructor_value)) return error.TypeError;

    switch (mode) {
        .all => return qjsPromiseCombinatorCall(ctx, output, global, constructor_value, args, .all, caller_function, caller_frame),
        .all_keyed => return qjsPromiseKeyedCombinatorCall(ctx, output, global, constructor_value, args, false, caller_function, caller_frame),
        .race => return qjsPromiseCombinatorCall(ctx, output, global, constructor_value, args, .race, caller_function, caller_frame),
        .all_settled => return qjsPromiseCombinatorCall(ctx, output, global, constructor_value, args, .all_settled, caller_function, caller_frame),
        .all_settled_keyed => return qjsPromiseKeyedCombinatorCall(ctx, output, global, constructor_value, args, true, caller_function, caller_frame),
        .any => return qjsPromiseCombinatorCall(ctx, output, global, constructor_value, args, .any, caller_function, caller_frame),
        else => {},
    }

    switch (mode) {
        .resolve => {
            const payload = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            if (try qjsPromiseResolveIdentity(ctx, output, global, constructor_value, payload, caller_function, caller_frame)) |same_promise| {
                return same_promise;
            }
            var capability = try qjsPromiseCapability(ctx, output, global, constructor_value, caller_function, caller_frame);
            errdefer capability.deinit(ctx.runtime);
            const resolve_result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), capability.resolve, &.{payload}, caller_function, caller_frame);
            resolve_result.free(ctx.runtime);
            return capability.releaseCallbacks(ctx.runtime);
        },
        .reject => {
            const reason = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            var capability = try qjsPromiseCapability(ctx, output, global, constructor_value, caller_function, caller_frame);
            errdefer capability.deinit(ctx.runtime);
            const reject_result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), capability.reject, &.{reason}, caller_function, caller_frame);
            reject_result.free(ctx.runtime);
            return capability.releaseCallbacks(ctx.runtime);
        },
        .try_ => {
            const callback = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            const callback_args = if (args.len >= 1) args[1..] else args[0..0];
            var capability = try qjsPromiseCapability(ctx, output, global, constructor_value, caller_function, caller_frame);
            errdefer capability.deinit(ctx.runtime);
            const callback_result = callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), callback, callback_args, caller_function, caller_frame) catch |err| {
                const reason = try qjsPromiseErrorValue(ctx, global, err);
                defer reason.free(ctx.runtime);
                const reject_result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), capability.reject, &.{reason}, caller_function, caller_frame);
                reject_result.free(ctx.runtime);
                return capability.releaseCallbacks(ctx.runtime);
            };
            defer callback_result.free(ctx.runtime);
            const resolve_result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), capability.resolve, &.{callback_result}, caller_function, caller_frame);
            resolve_result.free(ctx.runtime);
            return capability.releaseCallbacks(ctx.runtime);
        },
        .with_resolvers => {
            var capability = try qjsPromiseCapability(ctx, output, global, constructor_value, caller_function, caller_frame);
            defer capability.deinit(ctx.runtime);
            const result = try core.Object.create(ctx.runtime, core.class.ids.object, objectPrototypeFromGlobal(ctx.runtime, global));
            errdefer core.Object.destroyFromHeader(ctx.runtime, &result.header);
            try defineValueProperty(ctx.runtime, result, "promise", capability.promise);
            try defineValueProperty(ctx.runtime, result, "resolve", capability.resolve);
            try defineValueProperty(ctx.runtime, result, "reject", capability.reject);
            return result.value();
        },
        else => unreachable,
    }
}

const PromiseRejectionReason = struct {
    value: core.Value,
    from_exception: bool,

    fn deinit(self: *PromiseRejectionReason, rt: *core.Runtime) void {
        self.value.free(rt);
        self.value = core.Value.undefinedValue();
        self.from_exception = false;
    }

    fn commit(self: *PromiseRejectionReason, ctx: *core.Context) void {
        if (self.from_exception and ctx.hasException()) ctx.clearException();
    }
};

pub fn promiseRejectionReason(ctx: *core.Context, global: *core.Object, err: anytype) PromiseRejectionReason {
    if (ctx.hasException()) {
        return .{
            .value = ctx.exception_slot.value.dup(),
            .from_exception = true,
        };
    }
    return .{
        .value = createNamedError(ctx.runtime, global, if (err == error.TypeError) "TypeError" else "Error", "") catch core.Value.undefinedValue(),
        .from_exception = false,
    };
}

test "promise rejection reason keeps pending exception if settle fails" {
    var saw_oom = false;
    var saw_success = false;

    var fail_offset: usize = 0;
    while (fail_offset < 180) : (fail_offset += 1) {
        var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
        const rt = try core.Runtime.create(failing.allocator());
        const ctx = try core.Context.create(rt);
        const global = try core.Object.create(rt, core.class.ids.object, null);
        const promise = try core.Object.create(rt, core.class.ids.promise, null);
        const reaction = try qjsPromiseReactionRecord(rt, core.Value.undefinedValue(), core.Value.undefinedValue(), core.Value.undefinedValue(), core.Value.undefinedValue());
        try qjsAppendPromiseReaction(rt, promise, reaction);
        reaction.free(rt);
        const thrown = try core.Object.create(rt, core.class.ids.object, null);
        _ = ctx.throwValue(thrown.value().dup());
        thrown.value().free(rt);

        var reason = promiseRejectionReason(ctx, global, error.TypeError);
        failing.fail_index = failing.alloc_index + fail_offset;
        const result = qjsPromiseSettleValue(ctx, global, promise, reason.value, true);
        failing.fail_index = std.math.maxInt(usize);

        if (result) {
            reason.commit(ctx);
            saw_success = true;
            try std.testing.expect(!ctx.hasException());
            try std.testing.expect(promise.promiseResult() != null);
        } else |settle_err| switch (settle_err) {
            error.OutOfMemory => {
                saw_oom = true;
                try std.testing.expect(ctx.hasException());
                try std.testing.expectEqual(@as(?core.Value, null), promise.promiseResult());
            },
            else => |unexpected| {
                reason.deinit(rt);
                promise.value().free(rt);
                global.value().free(rt);
                ctx.destroy();
                rt.destroy();
                return unexpected;
            },
        }

        reason.deinit(rt);
        promise.value().free(rt);
        global.value().free(rt);
        ctx.destroy();
        rt.destroy();

        if (saw_oom and saw_success) break;
    }

    try std.testing.expect(saw_oom);
    try std.testing.expect(saw_success);
}

pub fn constructCollectionFromVm(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    kind: u32,
    args: []const core.Value,
) !core.Value {
    const prototype = try constructorPrototypeObject(ctx.runtime, constructor);
    return constructCollectionWithPrototypeFromVm(ctx, output, global, kind, args, prototype);
}

pub fn constructCollectionWithPrototypeFromVm(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    kind: u32,
    args: []const core.Value,
    prototype: ?*core.Object,
) !core.Value {
    const collection_value = try builtins.collection.constructWithPrototype(ctx.runtime, kind, prototype);
    errdefer collection_value.free(ctx.runtime);
    if (args.len == 0 or args[0].isUndefined() or args[0].isNull()) return collection_value;

    const adder_name: []const u8 = if (kind == 1 or kind == 3) "set" else "add";
    const adder_key = try ctx.runtime.internAtom(adder_name);
    defer ctx.runtime.atoms.free(adder_key);
    const adder = try getValueProperty(ctx, output, global, collection_value, adder_key, null, null);
    defer adder.free(ctx.runtime);
    if (!isCallableValue(adder)) return error.TypeError;

    const source = property_ops.expectObject(args[0]) catch null;
    if (source) |source_object| {
        if (source_object.is_array) {
            try addCollectionEntriesFromArray(ctx, output, global, collection_value, kind, source_object, adder);
            return collection_value;
        }
    }

    try addCollectionEntriesFromIterator(ctx, output, global, collection_value, kind, args[0], adder);
    return collection_value;
}

pub fn constructorPrototypeObject(rt: *core.Runtime, constructor: core.Value) !?*core.Object {
    if (!constructor.isObject()) return null;
    if (objectFromValue(constructor)) |object| {
        if (object.getOwnDataObjectBorrowed(core.atom.ids.prototype)) |prototype| return prototype;
    }
    const prototype_value = try property_ops.getPropertyValue(rt, constructor, core.atom.ids.prototype);
    defer prototype_value.free(rt);
    if (!prototype_value.isObject()) return null;
    const header = prototype_value.refHeader() orelse return null;
    return @fieldParentPtr("header", header);
}

pub fn addCollectionEntriesFromArray(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    collection_value: core.Value,
    kind: u32,
    source: *core.Object,
    adder: core.Value,
) !void {
    var index: u32 = 0;
    while (index < source.length) : (index += 1) {
        const entry_value = try getValueProperty(ctx, output, global, source.value(), core.atom.atomFromUInt32(index), null, null);
        defer entry_value.free(ctx.runtime);
        if (kind == 1 or kind == 3) {
            const entry = property_ops.expectObject(entry_value) catch return error.TypeError;
            const key = try getValueProperty(ctx, output, global, entry.value(), core.atom.atomFromUInt32(0), null, null);
            defer key.free(ctx.runtime);
            const value = try getValueProperty(ctx, output, global, entry.value(), core.atom.atomFromUInt32(1), null, null);
            defer value.free(ctx.runtime);
            try callCollectionAdderFromVm(ctx, output, global, collection_value, adder, &.{ key, value });
        } else {
            try callCollectionAdderFromVm(ctx, output, global, collection_value, adder, &.{entry_value});
        }
    }
}

pub fn addCollectionEntriesFromIterator(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    collection_value: core.Value,
    kind: u32,
    iterable_value: core.Value,
    adder: core.Value,
) !void {
    const iterator_method = try getIteratorMethod(ctx, output, global, iterable_value);
    defer iterator_method.free(ctx.runtime);
    if (!isCallableValue(iterator_method)) return error.TypeError;
    const iterator_value = try callValueOrBytecode(ctx, output, global, iterable_value, iterator_method, &.{}, null, null);
    defer iterator_value.free(ctx.runtime);
    _ = try property_ops.expectObject(iterator_value);

    while (true) {
        const step = iteratorStepValue(ctx, output, global, iterator_value) catch |err| {
            return iteratorCloseWithCompletionAndPropagate(ctx, output, global, iterator_value, err, null, null);
        };
        defer step.value.free(ctx.runtime);
        if (step.done) return;

        if (kind == 1 or kind == 3) {
            const entry = property_ops.expectObject(step.value) catch {
                return iteratorCloseWithCompletionAndPropagate(ctx, output, global, iterator_value, error.TypeError, null, null);
            };
            const key = getValueProperty(ctx, output, global, entry.value(), core.atom.atomFromUInt32(0), null, null) catch |err| {
                return iteratorCloseWithCompletionAndPropagate(ctx, output, global, iterator_value, err, null, null);
            };
            defer key.free(ctx.runtime);
            const value = getValueProperty(ctx, output, global, entry.value(), core.atom.atomFromUInt32(1), null, null) catch |err| {
                return iteratorCloseWithCompletionAndPropagate(ctx, output, global, iterator_value, err, null, null);
            };
            defer value.free(ctx.runtime);
            callCollectionAdderFromVm(ctx, output, global, collection_value, adder, &.{ key, value }) catch |err| {
                return iteratorCloseWithCompletionAndPropagate(ctx, output, global, iterator_value, err, null, null);
            };
        } else {
            callCollectionAdderFromVm(ctx, output, global, collection_value, adder, &.{step.value}) catch |err| {
                return iteratorCloseWithCompletionAndPropagate(ctx, output, global, iterator_value, err, null, null);
            };
        }
    }
}

pub fn callCollectionAdderFromVm(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    collection_value: core.Value,
    adder: core.Value,
    args: []const core.Value,
) !void {
    const out = try callValueOrBytecode(ctx, output, global, collection_value, adder, args, null, null);
    out.free(ctx.runtime);
}

pub fn closeIteratorFromVm(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
) !void {
    try closeIteratorFromVmImpl(ctx, output, global, iterator_value);
}

pub fn closeForAwaitIteratorFromVm(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
) !void {
    // QuickJS OP_iterator_close uses ordinary IteratorClose for for-await
    // records too; it does not await a promise returned by return().
    try closeIteratorFromVmImpl(ctx, output, global, iterator_value);
}

fn closeIteratorFromVmImpl(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
) !void {
    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = try getValueProperty(ctx, output, global, iterator_value, return_key, null, null);
    defer return_method.free(ctx.runtime);
    if (return_method.isUndefined() or return_method.isNull()) return;
    if (!isCallableValue(return_method)) return error.TypeError;
    const out = try callValueOrBytecode(ctx, output, global, iterator_value, return_method, &.{}, null, null);
    defer out.free(ctx.runtime);
    if (!out.isObject()) return error.TypeError;
}

pub fn collectionConstructorId(name: []const u8) ?u32 {
    if (std.mem.eql(u8, name, "Map")) return 1;
    if (std.mem.eql(u8, name, "Set")) return 2;
    if (std.mem.eql(u8, name, "WeakMap")) return 3;
    if (std.mem.eql(u8, name, "WeakSet")) return 4;
    return null;
}

pub fn isBuiltinConstructorName(name: []const u8) bool {
    return std.mem.eql(u8, name, "Object") or
        std.mem.eql(u8, name, "Function") or
        std.mem.eql(u8, name, "AsyncFunction") or
        std.mem.eql(u8, name, "GeneratorFunction") or
        std.mem.eql(u8, name, "AsyncGeneratorFunction") or
        std.mem.eql(u8, name, "Array") or
        std.mem.eql(u8, name, "String") or
        std.mem.eql(u8, name, "Number") or
        std.mem.eql(u8, name, "Boolean") or
        std.mem.eql(u8, name, "Symbol") or
        std.mem.eql(u8, name, "BigInt") or
        std.mem.eql(u8, name, "Date") or
        std.mem.eql(u8, name, "RegExp") or
        std.mem.eql(u8, name, "Error") or
        std.mem.eql(u8, name, "AggregateError") or
        std.mem.eql(u8, name, "SuppressedError") or
        std.mem.eql(u8, name, "EvalError") or
        std.mem.eql(u8, name, "RangeError") or
        std.mem.eql(u8, name, "ReferenceError") or
        std.mem.eql(u8, name, "SyntaxError") or
        std.mem.eql(u8, name, "TypeError") or
        std.mem.eql(u8, name, "URIError") or
        std.mem.eql(u8, name, "Test262Error") or
        std.mem.eql(u8, name, "Iterator") or
        std.mem.eql(u8, name, "DisposableStack") or
        std.mem.eql(u8, name, "AsyncDisposableStack") or
        std.mem.eql(u8, name, "Promise") or
        std.mem.eql(u8, name, "Test262Error") or
        std.mem.eql(u8, name, "Map") or
        std.mem.eql(u8, name, "Set") or
        std.mem.eql(u8, name, "WeakMap") or
        std.mem.eql(u8, name, "WeakSet") or
        std.mem.eql(u8, name, "WeakRef") or
        std.mem.eql(u8, name, "ArrayBuffer") or
        std.mem.eql(u8, name, "SharedArrayBuffer") or
        std.mem.eql(u8, name, "FinalizationRegistry") or
        std.mem.eql(u8, name, "DataView") or
        std.mem.eql(u8, name, "TypedArray") or
        std.mem.eql(u8, name, "Int8Array") or
        std.mem.eql(u8, name, "Uint8Array") or
        std.mem.eql(u8, name, "Uint8ClampedArray") or
        std.mem.eql(u8, name, "Int16Array") or
        std.mem.eql(u8, name, "Uint16Array") or
        std.mem.eql(u8, name, "Int32Array") or
        std.mem.eql(u8, name, "Uint32Array") or
        std.mem.eql(u8, name, "Float16Array") or
        std.mem.eql(u8, name, "Float32Array") or
        std.mem.eql(u8, name, "Float64Array") or
        std.mem.eql(u8, name, "BigInt64Array") or
        std.mem.eql(u8, name, "BigUint64Array") or
        std.mem.eql(u8, name, "Proxy");
}

pub fn createConstructorInstance(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    new_target: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const prototype = try reflectConstructPrototypeVm(ctx, output, global, "Object", new_target, caller_function, caller_frame);
    const instance = try core.Object.create(ctx.runtime, core.class.ids.object, prototype);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &instance.header);
    return instance.value();
}

pub fn constructFunctionFromSource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    return constructDynamicFunctionFromSource(ctx, output, global, constructor, constructor, args, .normal, caller_function, caller_frame);
}

pub fn constructAsyncFunctionFromSource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    return constructDynamicFunctionFromSource(ctx, output, global, constructor, constructor, args, .async_function, caller_function, caller_frame);
}

pub fn constructGeneratorFunctionFromSource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    return constructDynamicFunctionFromSource(ctx, output, global, constructor, constructor, args, .generator, caller_function, caller_frame);
}

pub fn constructAsyncGeneratorFunctionFromSource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    return constructDynamicFunctionFromSource(ctx, output, global, constructor, constructor, args, .async_generator, caller_function, caller_frame);
}

const DynamicFunctionKind = enum {
    normal,
    async_function,
    generator,
    async_generator,
};

fn dynamicFunctionKindFromName(name: []const u8) ?DynamicFunctionKind {
    if (std.mem.eql(u8, name, "Function")) return .normal;
    if (std.mem.eql(u8, name, "AsyncFunction")) return .async_function;
    if (std.mem.eql(u8, name, "GeneratorFunction")) return .generator;
    if (std.mem.eql(u8, name, "AsyncGeneratorFunction")) return .async_generator;
    return null;
}

pub fn constructDynamicFunctionFromSource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor: core.Value,
    new_target: core.Value,
    args: []const core.Value,
    kind: DynamicFunctionKind,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    var params = std.ArrayList(u8).empty;
    defer params.deinit(ctx.runtime.memory.allocator);
    var body = std.ArrayList(u8).empty;
    defer body.deinit(ctx.runtime.memory.allocator);

    if (args.len > 0) {
        for (args[0 .. args.len - 1], 0..) |arg, idx| {
            if (idx != 0) try params.append(ctx.runtime.memory.allocator, ',');
            const string_value = try toStringForAnnexB(ctx, output, global, arg, caller_function, caller_frame);
            defer string_value.free(ctx.runtime);
            try appendSourceStringUtf8(ctx.runtime, &params, string_value);
        }
        const body_value = try toStringForAnnexB(ctx, output, global, args[args.len - 1], caller_function, caller_frame);
        defer body_value.free(ctx.runtime);
        try appendSourceStringUtf8(ctx.runtime, &body, body_value);
    }
    const function_global = dynamicFunctionRealmGlobal(constructor) orelse global;
    if ((kind == .async_function or kind == .async_generator) and try parameterSourceContainsAwait(ctx.runtime, params.items)) {
        return throwSyntaxErrorMessage(ctx, function_global, "invalid syntax");
    }

    var source = std.ArrayList(u8).empty;
    defer source.deinit(ctx.runtime.memory.allocator);
    const prefix = switch (kind) {
        .normal => "(function anonymous(",
        .async_function => "(async function anonymous(",
        .generator => "(function* anonymous(",
        .async_generator => "(async function* anonymous(",
    };
    try source.appendSlice(ctx.runtime.memory.allocator, prefix);
    try source.appendSlice(ctx.runtime.memory.allocator, params.items);
    try source.appendSlice(ctx.runtime.memory.allocator, "\n) {\n");
    if (if (kind == .normal) nativeTypedArraySubclassBase(body.items) else null) |base_name| {
        try source.appendSlice(ctx.runtime.memory.allocator, "return ");
        try source.appendSlice(ctx.runtime.memory.allocator, base_name);
        try source.append(ctx.runtime.memory.allocator, ';');
    } else {
        try source.appendSlice(ctx.runtime.memory.allocator, body.items);
    }
    try source.appendSlice(ctx.runtime.memory.allocator, "\n})");

    const filename = switch (kind) {
        .normal => "Function",
        .async_function => "AsyncFunction",
        .generator => "GeneratorFunction",
        .async_generator => "AsyncGeneratorFunction",
    };
    var compiled = try frontend.parser.parse(ctx.runtime, source.items, .{ .mode = .eval_direct, .filename = filename, .strict = false });
    defer compiled.deinit();
    if (compiled.syntax_error != null) return throwSyntaxErrorMessage(ctx, function_global, "invalid syntax");
    var nested_stack = stack_mod.Stack.init(&ctx.runtime.memory, ctx.runtime.stack_size);
    defer nested_stack.deinit(ctx.runtime);
    const result = try runWithArgs(ctx, &nested_stack, &compiled.function, function_global.value(), &.{}, &.{}, output, function_global, true, false, false, &.{}, &.{}, &.{}, &.{});
    errdefer result.free(ctx.runtime);
    if (functionObjectFromValue(result)) |function_object| {
        const prototype = try dynamicFunctionNewTargetPrototype(ctx, output, global, new_target, kind, caller_function, caller_frame);
        try function_object.setPrototype(ctx.runtime, prototype);
        clearFunctionEvalCaptures(ctx.runtime, function_object);
        try copyRealmPrototypeKeys(ctx.runtime, constructor, function_object);
        if (function_global != global) {
            const next_global = function_global.value().dup();
            const old_global = function_object.functionRealmGlobalSlot().*;
            function_object.functionRealmGlobalSlot().* = next_global;
            if (old_global) |old| old.free(ctx.runtime);
        }
    }
    return result;
}

pub fn dynamicFunctionNewTargetPrototype(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    new_target: core.Value,
    kind: DynamicFunctionKind,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?*core.Object {
    const prototype_value = try getValueProperty(ctx, output, global, new_target, core.atom.ids.prototype, caller_function, caller_frame);
    defer prototype_value.free(ctx.runtime);
    if (prototype_value.isObject()) return objectFromValue(prototype_value);
    const fallback_global = if (objectFromValue(new_target)) |new_target_object| blk: {
        if (isRevokedProxy(new_target_object)) return error.TypeError;
        break :blk functionRealmGlobal(new_target_object) orelse global;
    } else global;
    return dynamicFunctionDefaultPrototype(ctx, fallback_global, kind);
}

fn parameterSourceContainsAwait(rt: *core.Runtime, source: []const u8) !bool {
    var lexer = frontend.qjs_lexer.Lexer.init(rt.memory.allocator, &rt.atoms, source);
    lexer.is_strict_mode = true;
    while (true) {
        var token = try lexer.next();
        defer lexer.freeToken(&token);
        if (token.val == frontend.qjs_token.TOK_AWAIT) return true;
        if (token.val == frontend.qjs_token.TOK_EOF) return false;
    }
}

pub fn dynamicFunctionDefaultPrototype(
    ctx: *core.Context,
    global: *core.Object,
    kind: DynamicFunctionKind,
) !?*core.Object {
    return switch (kind) {
        .normal => functionPrototypeFromGlobal(ctx.runtime, global),
        .async_function => try asyncFunctionPrototypeFromGlobal(ctx.runtime, global),
        .generator => try generatorFunctionPrototypeFromGlobal(ctx.runtime, global),
        .async_generator => try asyncGeneratorFunctionPrototypeFromGlobal(ctx.runtime, global),
    };
}

pub fn dynamicFunctionRealmGlobal(constructor: core.Value) ?*core.Object {
    const constructor_object = property_ops.expectObject(constructor) catch return null;
    return objectRealmGlobal(constructor_object);
}

pub fn objectRealmGlobal(object: *core.Object) ?*core.Object {
    if (object.class_id == core.class.ids.bound_function) {
        const target_value = object.boundTarget() orelse return null;
        const target_object = objectFromValue(target_value) orelse return null;
        return objectRealmGlobal(target_object);
    }
    if (object.functionRealmGlobalPtr()) |realm_global| return realm_global;
    const realm_value = object.functionRealmGlobal() orelse return null;
    return property_ops.expectObject(realm_value) catch null;
}

fn isRevokedProxy(object: *core.Object) bool {
    return object.is_proxy and object.proxyHandler() == null;
}

fn functionRealmGlobal(object: *core.Object) ?*core.Object {
    if (object.proxyTarget()) |target_value| {
        const target_object = objectFromValue(target_value) orelse return null;
        return functionRealmGlobal(target_object);
    }
    return objectRealmGlobal(object);
}

pub fn nativeTypedArraySubclassBase(source: []const u8) ?[]const u8 {
    if (std.mem.indexOf(u8, source, "class ") == null or std.mem.indexOf(u8, source, " extends ") == null) return null;
    const names = [_][]const u8{
        "Uint8Array",
        "Int8Array",
        "Uint8ClampedArray",
        "Uint16Array",
        "Int16Array",
        "Uint32Array",
        "Int32Array",
        "Float16Array",
        "Float32Array",
        "Float64Array",
        "BigUint64Array",
        "BigInt64Array",
    };
    for (names) |name| {
        var pattern_buf: [32]u8 = undefined;
        const pattern = std.fmt.bufPrint(&pattern_buf, " extends {s}", .{name}) catch unreachable;
        if (std.mem.indexOf(u8, source, pattern) != null) return name;
    }
    return null;
}

pub fn copyRealmPrototypeKeys(rt: *core.Runtime, constructor: core.Value, function_object: *core.Object) !void {
    const constructor_object = property_ops.expectObject(constructor) catch return;
    const realm_keys = [_][]const u8{
        "__realm_Object_proto",
        "__realm_Number_proto",
        "__realm_Boolean_proto",
        "__realm_Array_proto",
        "__realm_Iterator_proto",
        "__realm_Map_proto",
        "__realm_Set_proto",
        "__realm_WeakMap_proto",
        "__realm_WeakSet_proto",
        "__realm_RegExp_proto",
    };
    for (realm_keys) |key_name| {
        const key = try rt.internAtom(key_name);
        defer rt.atoms.free(key);
        const value = constructor_object.getProperty(key);
        defer value.free(rt);
        if (!value.isUndefined()) {
            try function_object.defineOwnProperty(rt, key, core.Descriptor.data(value, true, false, true));
        }
    }
}

pub fn clearFunctionEvalCaptures(rt: *core.Runtime, function_object: *core.Object) void {
    const old_names = function_object.functionEvalLocalNamesSlot().*;
    const old_refs = function_object.functionEvalLocalRefsSlot().*;
    function_object.functionEvalLocalNamesSlot().* = &.{};
    function_object.functionEvalLocalRefsSlot().* = &.{};
    for (old_names) |atom_id| rt.atoms.free(atom_id);
    if (old_names.len != 0) rt.memory.free(core.Atom, old_names);
    freeValueSlice(rt, old_refs);
}

pub fn qjsAssertThrows(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (args.len < 2) return error.TypeError;
    const expected = try property_ops.expectObject(args[0]);
    const expected_name = try call_mod.nativeFunctionNameForVm(ctx.runtime, expected);
    defer ctx.runtime.memory.allocator.free(expected_name);
    const result = callAssertThrowsCallback(ctx, output, global, args[1], caller_function, caller_frame) catch |err| {
        if (exception_ops.pendingExceptionMatchesError(ctx, err)) {
            if (try consumePendingExceptionIfMatchesConstructor(ctx, expected_name)) {
                return core.Value.undefinedValue();
            }
            return error.Test262Error;
        }
        if (call_mod.errorNameMatchesConstructorForVm(err, expected_name)) {
            ctx.clearException();
            return core.Value.undefinedValue();
        }
        return error.Test262Error;
    };
    defer result.free(ctx.runtime);
    return error.Test262Error;
}

fn consumePendingExceptionIfMatchesConstructor(ctx: *core.Context, expected_name: []const u8) !bool {
    const thrown_value = ctx.exception_slot.value;
    const matches = try thrownValueMatchesConstructor(ctx.runtime, thrown_value, expected_name);
    ctx.clearException();
    return matches;
}

test "assert throws keeps pending exception if matching allocation fails" {
    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
    const rt = try core.Runtime.create(failing.allocator());
    const ctx = try core.Context.create(rt);
    const thrown = try core.Object.create(rt, core.class.ids.error_, null);
    defer {
        failing.fail_index = std.math.maxInt(usize);
        thrown.value().free(rt);
        ctx.destroy();
        rt.destroy();
    }

    const name_value = try value_ops.createStringValue(rt, "TypeError");
    defer name_value.free(rt);
    try defineDataProperty(rt, thrown, "name", name_value, true, false, true);

    _ = ctx.throwValue(thrown.value().dup());
    failing.fail_index = failing.alloc_index;
    try std.testing.expectError(
        error.OutOfMemory,
        consumePendingExceptionIfMatchesConstructor(ctx, "TypeError"),
    );
    failing.fail_index = std.math.maxInt(usize);

    try std.testing.expect(ctx.hasException());
    ctx.clearException();
}

pub fn thrownValueMatchesConstructor(rt: *core.Runtime, thrown_value: core.Value, expected_name: []const u8) !bool {
    if (!thrown_value.isObject()) return false;
    const thrown_object = property_ops.expectObject(thrown_value) catch return false;
    const ctor_value = thrown_object.getProperty(core.atom.ids.constructor);
    defer ctor_value.free(rt);
    if (ctor_value.isObject()) {
        const ctor = property_ops.expectObject(ctor_value) catch null;
        if (ctor) |ctor_object| {
            const name = try call_mod.nativeFunctionNameForVm(rt, ctor_object);
            defer rt.memory.allocator.free(name);
            if (std.mem.eql(u8, name, expected_name)) return true;
        }
    }
    const name_value = thrown_object.getProperty(core.atom.ids.name);
    defer name_value.free(rt);
    if (!name_value.isString()) return false;
    var name_bytes = std.ArrayList(u8).empty;
    defer name_bytes.deinit(rt.memory.allocator);
    try value_ops.appendRawString(rt, &name_bytes, name_value);
    return std.mem.eql(u8, name_bytes.items, expected_name);
}

pub fn callAssertThrowsCallback(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    callback: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const caller = caller_function orelse return callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), callback, &.{}, caller_function, caller_frame);
    const frame = caller_frame orelse return callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), callback, &.{}, caller_function, caller_frame);
    if (functionObjectFromValue(callback)) |function_object| {
        const function_value = function_object.functionBytecodeSlot().* orelse return error.TypeError;
        var extra_names: []core.Atom = &.{};
        var extra_refs: []core.Value = &.{};
        defer {
            for (extra_refs) |value| value.free(ctx.runtime);
            if (extra_names.len != 0) ctx.runtime.memory.free(core.Atom, extra_names);
            if (extra_refs.len != 0) ctx.runtime.memory.free(core.Value, extra_refs);
        }
        try collectCallerEvalRefs(ctx, caller, frame, &extra_names, &extra_refs);
        if (extra_names.len == 0 or extra_refs.len == 0) {
            return callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), callback, &.{}, caller_function, caller_frame);
        }
        return callFunctionBytecode(ctx, function_value, callback, core.Value.undefinedValue(), &.{}, function_object.functionCapturesSlot().*, output, global, extra_names, extra_refs);
    }
    return callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), callback, &.{}, caller_function, caller_frame);
}

pub fn collectCallerEvalRefs(
    ctx: *core.Context,
    caller: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    names_out: *[]core.Atom,
    refs_out: *[]core.Value,
) !void {
    const var_ref_count = @min(caller.var_ref_names.len, frame.var_refs.len);
    const local_count = @min(caller.var_names.len, frame.locals.len);
    const total = var_ref_count + local_count;
    if (total == 0) return;

    const names = try ctx.runtime.memory.alloc(core.Atom, total);
    errdefer ctx.runtime.memory.free(core.Atom, names);
    const refs = try ctx.runtime.memory.alloc(core.Value, total);
    var initialized: usize = 0;
    errdefer {
        for (refs[0..initialized]) |value| value.free(ctx.runtime);
        ctx.runtime.memory.free(core.Value, refs);
    }

    for (caller.var_ref_names[0..var_ref_count], 0..) |atom_id, idx| {
        names[initialized] = atom_id;
        refs[initialized] = frame.var_refs[idx].dup();
        initialized += 1;
    }
    for (caller.var_names[0..local_count], 0..) |atom_id, idx| {
        names[initialized] = atom_id;
        refs[initialized] = try ensureVarRefCell(ctx, &frame.locals[idx]);
        initialized += 1;
    }

    names_out.* = names;
    refs_out.* = refs;
}

pub fn qjsArrayForEachCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
) !?core.Value {
    if (args.len < 1 or !isCallableValue(args[0])) return null;
    const object = property_ops.expectObject(receiver) catch return null;
    if (!object.is_array) return null;
    const function_object = callableObjectFromValue(func) orelse return null;
    if (!isArrayPrototypeRecord(function_object, @intFromEnum(builtins.array.PrototypeMethod.for_each))) {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        if (!std.mem.eql(u8, name, "forEach")) return null;
    }

    const callback_this = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    var index: u32 = 0;
    while (index < object.length) : (index += 1) {
        const item = object.getProperty(core.atom.atomFromUInt32(index));
        defer item.free(ctx.runtime);
        const index_value = core.Value.int32(@intCast(index));
        const callback_result = try callValueOrBytecode(ctx, output, global, callback_this, args[0], &.{ item, index_value, receiver }, null, null);
        callback_result.free(ctx.runtime);
    }
    return core.Value.undefinedValue();
}

pub fn qjsArrayAtCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    const typed_array_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    if (!isArrayPrototypeRecord(function_object, @intFromEnum(builtins.array.PrototypeMethod.at))) {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        if (!std.mem.eql(u8, name, "at")) return null;
    }

    if (receiver.isNull() or receiver.isUndefined()) {
        return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "Cannot convert undefined or null to object"));
    }
    const receiver_object_value = if (objectFromValue(receiver)) |_| receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    defer receiver_object_value.free(ctx.runtime);
    const object = objectFromValue(receiver_object_value) orelse return null;
    const is_typed_array = builtins.buffer.isTypedArrayObject(object);
    if (typed_array_method) {
        if (!is_typed_array) return error.TypeError;
        if (try builtins.buffer.typedArrayDetached(object)) return error.TypeError;
        if (try builtins.buffer.typedArrayOutOfBounds(object)) return error.TypeError;
    }
    const length = if (is_typed_array)
        @as(usize, @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, object)))
    else if (object.is_array)
        @as(usize, @intCast(object.length))
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, receiver_object_value, core.atom.ids.length, null, null);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };

    const index_arg = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const primitive = try toPrimitiveForNumber(ctx, output, global, index_arg);
    defer primitive.free(ctx.runtime);
    const index_number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
    defer index_number_value.free(ctx.runtime);
    const index_number = value_ops.numberValue(index_number_value) orelse std.math.nan(f64);
    var relative_index: isize = 0;
    if (!std.math.isNan(index_number)) {
        if (std.math.isNegativeInf(index_number)) {
            return core.Value.undefinedValue();
        } else if (std.math.isPositiveInf(index_number)) {
            return core.Value.undefinedValue();
        } else {
            relative_index = @intFromFloat(@trunc(index_number));
        }
    }
    const actual_index = if (relative_index >= 0)
        @as(isize, @intCast(relative_index))
    else
        @as(isize, @intCast(length)) + relative_index;
    if (actual_index < 0 or actual_index >= @as(isize, @intCast(length))) return core.Value.undefinedValue();

    const key = try propertyAtomFromLengthIndex(ctx.runtime, @intCast(actual_index));
    defer key.deinit(ctx.runtime);
    return try getValueProperty(ctx, output, global, receiver_object_value, key.atom, null, null);
}

const ArrayIterationMode = enum {
    for_each,
    map,
    filter,
    some,
    every,
    find,
    find_index,
    find_last,
    find_last_index,
};

pub fn qjsArrayIterationCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    if (collection_vm.collectionMethodOwnerClass(function_object)) |owner_class| {
        if (owner_class == core.class.ids.map or owner_class == core.class.ids.set) return null;
    }
    const mode: ArrayIterationMode = if (arrayPrototypeRecordId(function_object)) |record_id|
        switch (record_id) {
            @intFromEnum(builtins.array.PrototypeMethod.for_each) => .for_each,
            @intFromEnum(builtins.array.PrototypeMethod.map) => .map,
            @intFromEnum(builtins.array.PrototypeMethod.filter) => .filter,
            @intFromEnum(builtins.array.PrototypeMethod.some) => .some,
            @intFromEnum(builtins.array.PrototypeMethod.every) => .every,
            @intFromEnum(builtins.array.PrototypeMethod.find) => .find,
            @intFromEnum(builtins.array.PrototypeMethod.find_index) => .find_index,
            @intFromEnum(builtins.array.PrototypeMethod.find_last) => .find_last,
            @intFromEnum(builtins.array.PrototypeMethod.find_last_index) => .find_last_index,
            else => return null,
        }
    else blk: {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        break :blk if (std.mem.eql(u8, name, "forEach"))
            .for_each
        else if (std.mem.eql(u8, name, "map"))
            .map
        else if (std.mem.eql(u8, name, "filter"))
            .filter
        else if (std.mem.eql(u8, name, "some"))
            .some
        else if (std.mem.eql(u8, name, "every"))
            .every
        else if (std.mem.eql(u8, name, "find"))
            .find
        else if (std.mem.eql(u8, name, "findIndex"))
            .find_index
        else if (std.mem.eql(u8, name, "findLast"))
            .find_last
        else if (std.mem.eql(u8, name, "findLastIndex"))
            .find_last_index
        else
            return null;
    };

    const receiver_object_value = if (objectFromValue(receiver)) |_| receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    defer receiver_object_value.free(ctx.runtime);
    const object = objectFromValue(receiver_object_value) orelse return null;
    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    if (is_typed_method and !builtins.buffer.isTypedArrayObject(object)) return error.TypeError;
    const is_typed_array = builtins.buffer.isTypedArrayObject(object);
    const length = if (is_typed_array)
        try arrayMethodTypedArrayLength(ctx.runtime, object, is_typed_method)
    else if (object.is_array)
        @as(usize, @intCast(object.length))
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, receiver_object_value, core.atom.ids.length, caller_function, caller_frame);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };
    if (args.len < 1 or !isCallableValue(args[0])) return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "not a function"));
    const callback_this = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    if (mode == .map and length > std.math.maxInt(u32)) return error.RangeError;
    if (is_typed_method and (mode == .map or mode == .filter)) {
        return try qjsTypedArrayMapFilter(ctx, output, global, receiver_object_value, object, length, mode, args[0], callback_this, caller_function, caller_frame);
    }

    var out_value: core.Value = core.Value.undefinedValue();
    var out: ?*core.Object = null;
    var out_index: usize = 0;
    var dense_map_output = false;
    if (mode == .map or mode == .filter) {
        out_value = try arraySpeciesCreate(ctx, output, global, receiver_object_value, if (mode == .map) length else 0, caller_function, caller_frame);
        errdefer out_value.free(ctx.runtime);
        out = objectFromValue(out_value) orelse return error.TypeError;
        dense_map_output = mode == .map and out.?.canDefineDenseArrayDataPropertiesUnchecked();
    }
    if (mode == .map and !is_typed_array and dense_map_output) {
        if (simpleNumericArg0Callback(args[0])) |simple| {
            if (try qjsDenseArrayMapSimpleNumericArg0(ctx.runtime, object, length, simple, out_value, out.?)) |value| return value;
        }
    }

    var cursor: usize = 0;
    while (cursor < length) : (cursor += 1) {
        const index = switch (mode) {
            .find_last, .find_last_index => length - 1 - cursor,
            else => cursor,
        };
        const is_find_family = mode == .find or mode == .find_index or mode == .find_last or mode == .find_last_index;
        if (!is_typed_array and !is_find_family and index > std.math.maxInt(u32)) break;
        const item = if (is_typed_array) blk: {
            if (!is_typed_method and !is_find_family) {
                const current_length = try arrayMethodTypedArrayLength(ctx.runtime, object, false);
                if (index >= current_length) continue;
            }
            break :blk try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(index));
        } else if (object.is_array and object.arrayElementStorageMode() == .dense and index <= std.math.maxInt(u32)) blk: {
            if (object.getDenseArrayElementValue(@intCast(index))) |dense_item| break :blk dense_item;
            const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
            defer key.deinit(ctx.runtime);
            if (!is_find_family and
                !try hasValueProperty(ctx, output, global, receiver_object_value, object, key.atom, null, null))
            {
                continue;
            }
            break :blk try getValueProperty(ctx, output, global, receiver_object_value, key.atom, caller_function, caller_frame);
        } else blk: {
            const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
            defer key.deinit(ctx.runtime);
            if (!is_find_family and
                !try hasValueProperty(ctx, output, global, receiver_object_value, object, key.atom, null, null))
            {
                continue;
            }
            break :blk try getValueProperty(ctx, output, global, receiver_object_value, key.atom, caller_function, caller_frame);
        };
        defer item.free(ctx.runtime);
        const index_value = lengthIndexValue(index);
        const callback_result = try callValueOrBytecode(ctx, output, global, callback_this, args[0], &.{ item, index_value, receiver_object_value }, caller_function, caller_frame);
        defer callback_result.free(ctx.runtime);

        switch (mode) {
            .for_each => {},
            .map => {
                if (dense_map_output and index <= std.math.maxInt(u32) and out.?.canDefineDenseArrayDataPropertiesUnchecked()) {
                    try out.?.defineDenseArrayDataPropertyUnchecked(ctx.runtime, @intCast(index), callback_result);
                    continue;
                }
                dense_map_output = false;
                if (index <= std.math.maxInt(u32) and try out.?.defineDenseArrayDataProperty(ctx.runtime, @intCast(index), callback_result)) {
                    continue;
                }
                const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
                defer key.deinit(ctx.runtime);
                try createDataPropertyOrThrow(ctx, output, global, out_value, out.?, key.atom, callback_result, caller_function, caller_frame);
            },
            .filter => {
                if (valueTruthy(callback_result)) {
                    const out_key = try propertyAtomFromLengthIndex(ctx.runtime, out_index);
                    defer out_key.deinit(ctx.runtime);
                    try createDataPropertyOrThrow(ctx, output, global, out_value, out.?, out_key.atom, item, caller_function, caller_frame);
                    out_index += 1;
                }
            },
            .some => if (valueTruthy(callback_result)) return core.Value.boolean(true),
            .every => if (!valueTruthy(callback_result)) return core.Value.boolean(false),
            .find => if (valueTruthy(callback_result)) return item.dup(),
            .find_index => if (valueTruthy(callback_result)) return lengthIndexValue(index),
            .find_last => if (valueTruthy(callback_result)) return item.dup(),
            .find_last_index => if (valueTruthy(callback_result)) return lengthIndexValue(index),
        }
    }

    return switch (mode) {
        .for_each => core.Value.undefinedValue(),
        .map, .filter => out_value,
        .some => core.Value.boolean(false),
        .every => core.Value.boolean(true),
        .find, .find_last => core.Value.undefinedValue(),
        .find_index => core.Value.int32(-1),
        .find_last_index => core.Value.int32(-1),
    };
}

fn simpleNumericArg0Callback(callback: core.Value) ?SimpleNumericArg0Bytecode {
    if (callback.isFunctionBytecode()) {
        const fb = functionBytecodeFromValue(callback) orelse return null;
        return cachedSimpleNumericArg0Bytecode(fb) orelse simpleNumericArg0Bytecode(fb);
    }
    const function_object = functionObjectFromValue(callback) orelse return null;
    if (function_object.functionCapturesSlot().*.len != 0) return null;
    const function_value = function_object.functionBytecodeSlot().* orelse return null;
    const fb = functionBytecodeFromValue(function_value) orelse return null;
    return cachedSimpleNumericArg0Bytecode(fb) orelse simpleNumericArg0Bytecode(fb);
}

fn qjsDenseArrayMapSimpleNumericArg0(
    rt: *core.Runtime,
    source: *core.Object,
    length: usize,
    simple: SimpleNumericArg0Bytecode,
    out_value: core.Value,
    out: *core.Object,
) !?core.Value {
    if (!source.is_array or source.arrayElementStorageMode() != .dense) return null;
    if (length > std.math.maxInt(u32)) return null;
    const elements = source.arrayElements();
    if (length > elements.len) return null;

    var index: usize = 0;
    while (index < length) : (index += 1) {
        const item = elements[index] orelse return null;
        if (!item.isNumber()) return null;
    }

    index = 0;
    while (index < length) : (index += 1) {
        const item = elements[index].?;
        const mapped = try simpleNumericBinary(rt, simple.binop, item, core.Value.int32(simple.rhs));
        defer mapped.free(rt);
        try out.defineDenseArrayDataPropertyUnchecked(rt, @intCast(index), mapped);
    }
    return out_value;
}

pub fn qjsArrayMapSimpleNumericArg0DefaultSpeciesFastCall(
    rt: *core.Runtime,
    global: *core.Object,
    receiver: core.Value,
    callback: core.Value,
) !?core.Value {
    const source = objectFromValue(receiver) orelse return null;
    if (!source.is_array or source.proxyTarget() != null or source.exotic != null) return null;
    if (source.arrayElementStorageMode() != .dense) return null;
    const length: usize = @intCast(source.length);
    if (length > std.math.maxInt(u32)) return null;
    const simple = simpleNumericArg0Callback(callback) orelse return null;

    const elements = source.arrayElements();
    if (length > elements.len) return null;
    var index: usize = 0;
    while (index < length) : (index += 1) {
        const item = elements[index] orelse return null;
        if (!item.isNumber()) return null;
    }

    const out_value = try defaultArraySpeciesCreate(rt, global, source, length) orelse return null;
    errdefer out_value.free(rt);
    const out = objectFromValue(out_value) orelse return error.TypeError;
    if (!out.canDefineDenseArrayDataPropertiesUnchecked()) {
        out_value.free(rt);
        return null;
    }
    if (try qjsDenseArrayMapSimpleNumericArg0(rt, source, length, simple, out_value, out)) |mapped| return mapped;
    out_value.free(rt);
    return null;
}

pub fn qjsTypedArrayMapFilter(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    object: *core.Object,
    length: usize,
    mode: ArrayIterationMode,
    callback: core.Value,
    callback_this: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (mode == .map) {
        const constructor_value = try typedArraySpeciesConstructorForObject(ctx, output, global, receiver_value, object, caller_function, caller_frame);
        defer constructor_value.free(ctx.runtime);
        const out_value = try qjsTypedArrayCreateWithLength(ctx, output, global, constructor_value, length, caller_function, caller_frame);
        errdefer out_value.free(ctx.runtime);
        const out = objectFromValue(out_value) orelse return error.TypeError;
        var index: usize = 0;
        while (index < length) : (index += 1) {
            const item = try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(index));
            defer item.free(ctx.runtime);
            const mapped = try callValueOrBytecode(ctx, output, global, callback_this, callback, &.{ item, lengthIndexValue(index), receiver_value }, caller_function, caller_frame);
            defer mapped.free(ctx.runtime);
            _ = try builtins.buffer.typedArraySetIndex(ctx.runtime, out, @intCast(index), mapped);
        }
        return out_value;
    }

    const kept = try ctx.runtime.memory.alloc(core.Value, length);
    errdefer ctx.runtime.memory.free(core.Value, kept);
    var kept_count: usize = 0;
    errdefer {
        var free_index: usize = 0;
        while (free_index < kept_count) : (free_index += 1) kept[free_index].free(ctx.runtime);
    }
    var index: usize = 0;
    while (index < length) : (index += 1) {
        const item = try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(index));
        const selected = try callValueOrBytecode(ctx, output, global, callback_this, callback, &.{ item, lengthIndexValue(index), receiver_value }, caller_function, caller_frame);
        defer selected.free(ctx.runtime);
        if (valueTruthy(selected)) {
            kept[kept_count] = item;
            kept_count += 1;
        } else {
            item.free(ctx.runtime);
        }
    }

    const constructor_value = try typedArraySpeciesConstructorForObject(ctx, output, global, receiver_value, object, caller_function, caller_frame);
    defer constructor_value.free(ctx.runtime);
    const out_value = try qjsTypedArrayCreateWithLength(ctx, output, global, constructor_value, kept_count, caller_function, caller_frame);
    errdefer out_value.free(ctx.runtime);
    const out = objectFromValue(out_value) orelse return error.TypeError;
    index = 0;
    while (index < kept_count) : (index += 1) {
        defer kept[index].free(ctx.runtime);
        _ = try builtins.buffer.typedArraySetIndex(ctx.runtime, out, @intCast(index), kept[index]);
    }
    ctx.runtime.memory.free(core.Value, kept);
    return out_value;
}

fn qjsTypedArrayCreateWithLength(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor_value: core.Value,
    requested_length: usize,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const out_value = try constructValueOrBytecode(ctx, output, global, constructor_value, &.{lengthIndexValue(requested_length)}, caller_function, caller_frame);
    errdefer out_value.free(ctx.runtime);
    const out = objectFromValue(out_value) orelse return error.TypeError;
    if (!builtins.buffer.isTypedArrayObject(out)) return error.TypeError;
    if (@as(usize, @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, out))) < requested_length) return error.TypeError;
    try builtins.buffer.typedArrayRejectImmutableBuffer(ctx.runtime, out);
    return out_value;
}

pub fn qjsArrayReduceCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
    from_right: bool,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    const expected_id = if (from_right)
        @intFromEnum(builtins.array.PrototypeMethod.reduce_right)
    else
        @intFromEnum(builtins.array.PrototypeMethod.reduce);
    if (!isArrayPrototypeRecord(function_object, expected_id)) {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        if (!std.mem.eql(u8, name, if (from_right) "reduceRight" else "reduce")) return null;
    }

    if (receiver.isNull() or receiver.isUndefined()) {
        return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "Cannot convert undefined or null to object"));
    }
    const receiver_object_value = if (objectFromValue(receiver)) |_| receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    defer receiver_object_value.free(ctx.runtime);
    const object = objectFromValue(receiver_object_value) orelse return null;
    const is_typed_array = builtins.buffer.isTypedArrayObject(object);
    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    if (is_typed_method and !is_typed_array) return error.TypeError;
    const length = if (is_typed_array)
        try arrayMethodTypedArrayLength(ctx.runtime, object, is_typed_method)
    else if (object.is_array)
        @as(usize, @intCast(object.length))
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, receiver_object_value, core.atom.ids.length, null, null);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };
    if (args.len < 1 or !isCallableValue(args[0])) return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "not a function"));

    var accumulator: core.Value = undefined;
    var accumulator_set = false;
    if (args.len >= 2) {
        accumulator = args[1].dup();
        accumulator_set = true;
    }
    errdefer if (accumulator_set) accumulator.free(ctx.runtime);
    if (from_right and length > std.math.maxInt(u32)) {
        accumulator_set = false;
        return try qjsArrayReduceRightSparseLarge(ctx, output, global, object, receiver_object_value, args[0], args.len >= 2, accumulator, length);
    }

    if (from_right) {
        var cursor = length;
        while (cursor > 0) {
            cursor -= 1;
            const item = if (is_typed_array) blk: {
                if (!is_typed_method and !try builtins.buffer.typedArrayIndexValid(ctx.runtime, object, @intCast(cursor))) continue;
                break :blk try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(cursor));
            } else blk: {
                const key = try propertyAtomFromLengthIndex(ctx.runtime, cursor);
                defer key.deinit(ctx.runtime);
                if (!try hasValueProperty(ctx, output, global, receiver_object_value, object, key.atom, null, null)) continue;
                break :blk try getValueProperty(ctx, output, global, receiver_object_value, key.atom, null, null);
            };
            defer item.free(ctx.runtime);
            if (!accumulator_set) {
                accumulator = item.dup();
                accumulator_set = true;
                continue;
            }
            const index_value = lengthIndexValue(cursor);
            const next = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), args[0], &.{ accumulator, item, index_value, receiver_object_value }, null, null);
            accumulator.free(ctx.runtime);
            accumulator = next;
        }
    } else {
        var cursor: usize = 0;
        while (cursor < length) : (cursor += 1) {
            const item = if (is_typed_array) blk: {
                if (!is_typed_method and !try builtins.buffer.typedArrayIndexValid(ctx.runtime, object, @intCast(cursor))) continue;
                break :blk try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(cursor));
            } else blk: {
                const key = try propertyAtomFromLengthIndex(ctx.runtime, cursor);
                defer key.deinit(ctx.runtime);
                if (!try hasValueProperty(ctx, output, global, receiver_object_value, object, key.atom, null, null)) continue;
                break :blk try getValueProperty(ctx, output, global, receiver_object_value, key.atom, null, null);
            };
            defer item.free(ctx.runtime);
            if (!accumulator_set) {
                accumulator = item.dup();
                accumulator_set = true;
                continue;
            }
            const index_value = lengthIndexValue(cursor);
            const next = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), args[0], &.{ accumulator, item, index_value, receiver_object_value }, null, null);
            accumulator.free(ctx.runtime);
            accumulator = next;
        }
    }

    if (!accumulator_set) return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "empty array"));
    accumulator_set = false;
    return accumulator;
}

const SparseIndexKey = struct {
    atom_id: core.Atom,
    index: usize,
};

pub fn qjsArrayReduceRightSparseLarge(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    receiver: core.Value,
    callback: core.Value,
    has_initial: bool,
    initial: core.Value,
    length: usize,
) !core.Value {
    const keys = try object.ownKeys(ctx.runtime);
    defer core.Object.freeKeys(ctx.runtime, keys);
    var indexed = std.ArrayList(SparseIndexKey).empty;
    defer indexed.deinit(ctx.runtime.memory.allocator);
    for (keys) |key| {
        const index = propertyIndexFromLengthKey(ctx.runtime, key) orelse continue;
        if (index >= length) continue;
        try indexed.append(ctx.runtime.memory.allocator, .{ .atom_id = key, .index = index });
    }
    std.mem.sort(SparseIndexKey, indexed.items, {}, struct {
        fn lessThan(_: void, a: SparseIndexKey, b: SparseIndexKey) bool {
            return a.index > b.index;
        }
    }.lessThan);

    var accumulator = if (has_initial) initial else core.Value.undefinedValue();
    var accumulator_set = has_initial;
    errdefer if (accumulator_set) accumulator.free(ctx.runtime);
    for (indexed.items) |entry| {
        const item = object.getProperty(entry.atom_id);
        defer item.free(ctx.runtime);
        if (!accumulator_set) {
            accumulator = item.dup();
            accumulator_set = true;
            continue;
        }
        const index_value = lengthIndexValue(entry.index);
        const next = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), callback, &.{ accumulator, item, index_value, receiver }, null, null);
        accumulator.free(ctx.runtime);
        accumulator = next;
    }
    if (!accumulator_set) return error.TypeError;
    accumulator_set = false;
    return accumulator;
}

pub fn propertyIndexFromLengthKey(rt: *core.Runtime, atom_id: core.Atom) ?usize {
    if (core.array.arrayIndexFromAtom(&rt.atoms, atom_id)) |index| return index;
    if (rt.atoms.kind(atom_id) != .string) return null;
    const name = rt.atoms.name(atom_id) orelse return null;
    if (name.len == 0) return null;
    for (name) |ch| {
        if (ch < '0' or ch > '9') return null;
    }
    return std.fmt.parseUnsigned(usize, name, 10) catch null;
}

fn arrayMethodTypedArrayLength(rt: *core.Runtime, object: *core.Object, is_typed_method: bool) !usize {
    if (try builtins.buffer.typedArrayDetached(object)) return error.TypeError;
    if (try builtins.buffer.typedArrayOutOfBounds(object)) {
        if (is_typed_method) return error.TypeError;
        return 0;
    }
    return @intCast(try builtins.buffer.typedArrayLength(rt, object));
}

pub fn lengthIndexValue(index: usize) core.Value {
    if (index <= @as(usize, @intCast(std.math.maxInt(i32)))) return core.Value.int32(@intCast(index));
    return core.Value.float64(@floatFromInt(index));
}

pub fn qjsArraySearchCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    const mode: enum { index_of, last_index_of, includes } = if (arrayPrototypeRecordId(function_object)) |record_id|
        switch (record_id) {
            @intFromEnum(builtins.array.PrototypeMethod.last_index_of) => .last_index_of,
            @intFromEnum(builtins.array.PrototypeMethod.index_of) => .index_of,
            @intFromEnum(builtins.array.PrototypeMethod.includes) => .includes,
            else => return null,
        }
    else blk: {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        break :blk if (std.mem.eql(u8, name, "lastIndexOf"))
            .last_index_of
        else if (std.mem.eql(u8, name, "indexOf"))
            .index_of
        else if (std.mem.eql(u8, name, "includes"))
            .includes
        else
            return null;
    };

    if (receiver.isNull() or receiver.isUndefined()) {
        return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "Cannot convert undefined or null to object"));
    }
    const receiver_object_value = if (objectFromValue(receiver)) |_| receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    defer receiver_object_value.free(ctx.runtime);
    const object = objectFromValue(receiver_object_value) orelse return null;
    const is_typed_array = builtins.buffer.isTypedArrayObject(object);
    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    if (is_typed_method and !is_typed_array) return error.TypeError;
    const array_proto = arrayPrototypeFromGlobal(ctx.runtime, global) orelse return null;
    if (arrayPrototypeRecordId(function_object) == null) {
        const name = switch (mode) {
            .index_of => "indexOf",
            .last_index_of => "lastIndexOf",
            .includes => "includes",
        };
        const method_atom = try ctx.runtime.internAtom(name);
        defer ctx.runtime.atoms.free(method_atom);
        const array_method = array_proto.getProperty(method_atom);
        defer array_method.free(ctx.runtime);
        if (objectFromValue(array_method) != function_object and !is_typed_array) return null;
    }
    const length = if (is_typed_array)
        try arrayMethodTypedArrayLength(ctx.runtime, object, is_typed_method)
    else if (object.is_array)
        @as(usize, @intCast(object.length))
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, receiver_object_value, core.atom.ids.length, null, null);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };
    if (length == 0) return if (mode == .includes) core.Value.boolean(false) else core.Value.int32(-1);

    const search_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    if (mode == .last_index_of and length > 1_000_000) {
        return try qjsArrayLastIndexSparseLarge(ctx, output, global, object, receiver_object_value, args, length, search_value);
    }
    if (mode == .last_index_of) {
        var cursor = try arrayLastIndexStart(ctx, output, global, args, length);
        while (cursor > 0) {
            cursor -= 1;
            const item = if (is_typed_array) blk: {
                const current_length = @as(usize, @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, object)));
                if (cursor >= current_length) continue;
                break :blk try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(cursor));
            } else blk: {
                const key = try propertyAtomFromLengthIndex(ctx.runtime, cursor);
                defer key.deinit(ctx.runtime);
                if (!try hasValueProperty(ctx, output, global, receiver_object_value, object, key.atom, null, null)) continue;
                break :blk try getValueProperty(ctx, output, global, receiver_object_value, key.atom, null, null);
            };
            defer item.free(ctx.runtime);
            if (try valuesStrictEqual(ctx.runtime, item, search_value)) return lengthIndexValue(cursor);
        }
    } else {
        var cursor = try arrayFirstIndexStart(ctx, output, global, args, length);
        while (cursor < length) : (cursor += 1) {
            const item = if (is_typed_array) blk: {
                if (mode != .includes) {
                    const current_length = @as(usize, @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, object)));
                    if (cursor >= current_length) continue;
                }
                break :blk try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(cursor));
            } else blk: {
                const key = try propertyAtomFromLengthIndex(ctx.runtime, cursor);
                defer key.deinit(ctx.runtime);
                if (mode != .includes and !try hasValueProperty(ctx, output, global, receiver_object_value, object, key.atom, null, null)) continue;
                break :blk try getValueProperty(ctx, output, global, receiver_object_value, key.atom, null, null);
            };
            defer item.free(ctx.runtime);
            if (mode == .includes) {
                if (builtins.collection.sameValueZero(item, search_value)) return core.Value.boolean(true);
                continue;
            }
            if (try valuesStrictEqual(ctx.runtime, item, search_value)) return lengthIndexValue(cursor);
        }
    }
    return if (mode == .includes) core.Value.boolean(false) else core.Value.int32(-1);
}

pub fn qjsArrayLastIndexSparseLarge(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    receiver: core.Value,
    args: []const core.Value,
    length: usize,
    search_value: core.Value,
) !core.Value {
    const start_exclusive = try arrayLastIndexStart(ctx, output, global, args, length);
    const keys = try object.ownKeys(ctx.runtime);
    defer core.Object.freeKeys(ctx.runtime, keys);
    var indexed = std.ArrayList(SparseIndexKey).empty;
    defer indexed.deinit(ctx.runtime.memory.allocator);
    for (keys) |key| {
        const index = propertyIndexFromLengthKey(ctx.runtime, key) orelse continue;
        if (index >= start_exclusive or index >= length) continue;
        try indexed.append(ctx.runtime.memory.allocator, .{ .atom_id = key, .index = index });
    }
    std.mem.sort(SparseIndexKey, indexed.items, {}, struct {
        fn lessThan(_: void, a: SparseIndexKey, b: SparseIndexKey) bool {
            return a.index > b.index;
        }
    }.lessThan);
    for (indexed.items) |entry| {
        const item = try getValueProperty(ctx, output, global, receiver, entry.atom_id, null, null);
        defer item.free(ctx.runtime);
        if (try valuesStrictEqual(ctx.runtime, item, search_value)) return lengthIndexValue(entry.index);
    }
    return core.Value.int32(-1);
}

pub fn arrayFirstIndexStart(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    length: usize,
) !usize {
    if (args.len < 2) return 0;
    const n = try toIntegerOrInfinityForArrayByCopy(ctx, output, global, args[1]);
    if (std.math.isNan(n)) return 0;
    if (std.math.isPositiveInf(n)) return length;
    if (std.math.isNegativeInf(n)) return 0;
    if (n >= @as(f64, @floatFromInt(length))) return length;
    if (n >= 0) return @intFromFloat(@trunc(n));
    const offset = @as(f64, @floatFromInt(length)) + @trunc(n);
    if (offset <= 0) return 0;
    return @intFromFloat(offset);
}

pub fn arrayLastIndexStart(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    length: usize,
) !usize {
    if (args.len < 2) return length;
    const n = try toIntegerOrInfinityForArrayByCopy(ctx, output, global, args[1]);
    if (std.math.isNan(n)) return length;
    if (std.math.isNegativeInf(n)) return 0;
    if (std.math.isPositiveInf(n)) return length;
    const upper = @as(f64, @floatFromInt(length - 1));
    if (n >= upper) return length;
    if (n >= 0) return @as(usize, @intFromFloat(@trunc(n))) + 1;
    const offset = @as(f64, @floatFromInt(length)) + @trunc(n);
    if (offset < 0) return 0;
    return @as(usize, @intFromFloat(offset)) + 1;
}

pub fn valuesStrictEqual(rt: *core.Runtime, a: core.Value, b: core.Value) !bool {
    if (a.isNumber() and b.isNumber()) {
        const av = value_ops.numberValue(a) orelse return false;
        const bv = value_ops.numberValue(b) orelse return false;
        if (std.math.isNan(av) or std.math.isNan(bv)) return false;
        return av == bv;
    }
    if (a.asBool()) |ab| {
        if (b.asBool()) |bb| return ab == bb;
    }
    if (a.isNull() or a.isUndefined()) return a.same(b);
    if (a.isBigInt() and b.isBigInt()) return builtins.object.sameValue(a, b);
    if (a.isString() and b.isString()) {
        if (a.same(b)) return true;
        var a_bytes = std.ArrayList(u8).empty;
        defer a_bytes.deinit(rt.memory.allocator);
        var b_bytes = std.ArrayList(u8).empty;
        defer b_bytes.deinit(rt.memory.allocator);
        try value_ops.appendRawString(rt, &a_bytes, a);
        try value_ops.appendRawString(rt, &b_bytes, b);
        return std.mem.eql(u8, a_bytes.items, b_bytes.items);
    }
    return a.same(b);
}

pub fn qjsArraySliceCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    if (getStringPrototypeMethodId(ctx.runtime, function_object) != null) return null;
    if (!isArrayPrototypeRecord(function_object, @intFromEnum(builtins.array.PrototypeMethod.slice))) {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        if (!std.mem.eql(u8, name, "slice")) return null;
    }

    if (receiver.isNull() or receiver.isUndefined()) return error.TypeError;
    const primitive_non_string_receiver = !receiver.isObject() and !receiver.isString();
    const receiver_object_value = if (objectFromValue(receiver)) |_| receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    defer receiver_object_value.free(ctx.runtime);
    const object = objectFromValue(receiver_object_value) orelse return null;
    if (object.class_id == core.class.ids.string) return null;
    if (!primitive_non_string_receiver and
        !object.is_array and
        !object.is_proxy and
        object.class_id != core.class.ids.object and
        object.class_id != core.class.ids.arguments and
        object.class_id != core.class.ids.mapped_arguments and
        !builtins.buffer.isTypedArrayObject(object)) return null;
    const length = if (primitive_non_string_receiver)
        0
    else if (object.is_array and !object.is_proxy)
        @as(usize, @intCast(object.length))
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, receiver_object_value, core.atom.ids.length, null, null);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };

    const start = try arrayRelativeIndex(ctx, output, global, args, 0, length, 0);
    const end = if (args.len >= 2 and !args[1].isUndefined())
        try arrayRelativeIndex(ctx, output, global, args, 1, length, length)
    else
        length;
    const count = if (end > start) end - start else 0;
    if (count > std.math.maxInt(u32)) return error.RangeError;

    const out_value = try arraySpeciesCreate(ctx, output, global, receiver_object_value, count, null, null);
    errdefer out_value.free(ctx.runtime);
    const out = try property_ops.expectObject(out_value);
    const set_initial_length = try setValueProperty(ctx, output, global, out_value, core.atom.ids.length, lengthIndexValue(count), null, null);
    set_initial_length.free(ctx.runtime);

    var from = start;
    var to: usize = 0;
    while (from < end and to < count) : ({
        from += 1;
        to += 1;
    }) {
        const from_key = try propertyAtomFromLengthIndex(ctx.runtime, from);
        defer from_key.deinit(ctx.runtime);
        if (!try hasValueProperty(ctx, output, global, receiver_object_value, object, from_key.atom, null, null)) continue;
        const item = try getValueProperty(ctx, output, global, receiver_object_value, from_key.atom, null, null);
        defer item.free(ctx.runtime);
        const to_key = try propertyAtomFromLengthIndex(ctx.runtime, to);
        defer to_key.deinit(ctx.runtime);
        try createDataPropertyOrThrow(ctx, output, global, out_value, out, to_key.atom, item, null, null);
    }

    return out_value;
}

pub fn qjsTypedArraySliceSubarrayCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
    defer ctx.runtime.memory.allocator.free(name);
    const is_slice = std.mem.eql(u8, name, "slice");
    const is_subarray = std.mem.eql(u8, name, "subarray");
    if (!is_slice and !is_subarray) return null;
    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    const object = objectFromValue(receiver) orelse return if (is_typed_method) error.TypeError else null;
    if (!builtins.buffer.isTypedArrayObject(object)) return if (is_typed_method) error.TypeError else null;
    if (is_slice and (try builtins.buffer.typedArrayDetached(object) or try builtins.buffer.typedArrayOutOfBounds(object))) return error.TypeError;
    const length = @as(usize, @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, object)));
    const start = try arrayRelativeIndex(ctx, output, global, args, 0, length, 0);
    const end = if (args.len >= 2 and !args[1].isUndefined())
        try arrayRelativeIndex(ctx, output, global, args, 1, length, length)
    else
        length;
    const count = if (end > start) end - start else 0;
    if (count > std.math.maxInt(i32)) return error.RangeError;

    const constructor_value = try typedArraySpeciesConstructorForObject(ctx, output, global, receiver, object, null, null);
    defer constructor_value.free(ctx.runtime);

    const result = if (is_subarray) blk: {
        const buffer_value = (object.typedArrayBuffer() orelse return error.TypeError).dup();
        defer buffer_value.free(ctx.runtime);
        const buffer = objectFromValue(buffer_value) orelse return error.TypeError;
        if (buffer.class_id != core.class.ids.array_buffer and buffer.class_id != core.class.ids.shared_array_buffer) {
            return error.TypeError;
        }
        const src_byte_offset = object.typedArrayByteOffset();
        if (src_byte_offset > buffer.byteStorage().len) return error.RangeError;
        if (src_byte_offset == buffer.byteStorage().len and count > 0) return error.RangeError;
        const begin_byte_offset = src_byte_offset + start * object.typedArrayElementSize();
        if (object.typedArrayFixedLength() == null and (args.len < 2 or args[1].isUndefined())) {
            break :blk try constructValueOrBytecode(ctx, output, global, constructor_value, &.{ buffer_value, lengthIndexValue(begin_byte_offset) }, null, null);
        }
        break :blk try constructValueOrBytecode(ctx, output, global, constructor_value, &.{ buffer_value, lengthIndexValue(begin_byte_offset), lengthIndexValue(count) }, null, null);
    } else try qjsTypedArrayCreateWithLength(ctx, output, global, constructor_value, count, null, null);
    errdefer result.free(ctx.runtime);
    const result_object = objectFromValue(result) orelse return error.TypeError;
    if (!builtins.buffer.isTypedArrayObject(result_object)) return error.TypeError;

    if (is_slice and count > 0) {
        if (try builtins.buffer.typedArrayDetached(object) or try builtins.buffer.typedArrayOutOfBounds(object)) return error.TypeError;
        const current_length = @as(usize, @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, object)));
        const copy_count = if (current_length > start)
            @min(count, current_length - start)
        else
            0;
        var index: usize = 0;
        while (index < copy_count) : (index += 1) {
            const item = try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(start + index));
            defer item.free(ctx.runtime);
            _ = try builtins.buffer.typedArraySetIndex(ctx.runtime, result_object, @intCast(index), item);
        }
    }
    return result;
}

pub fn typedArrayConstructorForObject(rt: *core.Runtime, global: *core.Object, object: *core.Object) !core.Value {
    const name = typedArrayNameFromKind(object.typedArrayKind()) orelse return error.TypeError;
    const key = try rt.internAtom(name);
    defer rt.atoms.free(key);
    const constructor = global.getProperty(key);
    if (!constructor.isObject()) {
        constructor.free(rt);
        return error.TypeError;
    }
    return constructor;
}

pub fn typedArraySpeciesConstructorForObject(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const default_constructor = try typedArrayConstructorForObject(ctx.runtime, global, object);
    errdefer default_constructor.free(ctx.runtime);
    const constructor_value = try getValueProperty(ctx, output, global, receiver, core.atom.ids.constructor, caller_function, caller_frame);
    defer constructor_value.free(ctx.runtime);
    if (constructor_value.isUndefined()) return default_constructor;
    if (!constructor_value.isObject()) return error.TypeError;
    const species_atom = core.atom.predefinedId("Symbol.species", .symbol) orelse return error.TypeError;
    const species_value = try getValueProperty(ctx, output, global, constructor_value, species_atom, caller_function, caller_frame);
    if (species_value.isUndefined() or species_value.isNull()) {
        species_value.free(ctx.runtime);
        return default_constructor;
    }
    default_constructor.free(ctx.runtime);
    return species_value;
}

pub fn qjsArraySpliceCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    if (!isArrayPrototypeRecord(function_object, @intFromEnum(builtins.array.PrototypeMethod.splice))) {
