    if (fixed_length) |length| {
        if (length > @as(usize, @intCast(std.math.maxInt(u32)))) return error.RangeError;
        if (out.is_array) out.length = @intCast(length);
    }

    var index: usize = 0;
    while (true) : (index += 1) {
        const length = if (fixed_length) |length_value|
            length_value
        else if (objectFromValue(source)) |source_object|
            @as(usize, @intCast(source_object.length))
        else
            0;
        if (index >= length) break;
        if (index > std.math.maxInt(u32)) return error.RangeError;
        const key = core.atom.atomFromUInt32(@intCast(index));
        var item = try getValueProperty(ctx, output, global, source, key, caller_function, caller_frame);
        defer item.free(ctx.runtime);
        if (map_fn) |mapper| {
            const mapped = try callValueOrBytecode(ctx, output, global, this_arg, mapper, &.{ item, core.Value.int32(@intCast(index)) }, caller_function, caller_frame);
            item.free(ctx.runtime);
            item = mapped;
        }
        try qjsCreateArrayDataOrTypedArrayElement(ctx.runtime, out, key, item);
    }
    if (index > @as(usize, @intCast(std.math.maxInt(u32)))) return error.RangeError;
    if (!builtins.buffer.isTypedArrayObject(out)) {
        const set_result = try setValueProperty(ctx, output, global, out.value(), core.atom.ids.length, core.Value.int32(@intCast(index)), caller_function, caller_frame);
        set_result.free(ctx.runtime);
    }
    return out_value;
}

fn qjsCollectIteratorValues(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const iterator = objectFromValue(iterator_value) orelse return error.TypeError;
    const values = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
    const values_value = values.value();
    errdefer values_value.free(ctx.runtime);
    const next_key = try ctx.runtime.internAtom("next");
    defer ctx.runtime.atoms.free(next_key);
    const next_method = try getValueProperty(ctx, output, global, iterator.value(), next_key, caller_function, caller_frame);
    defer next_method.free(ctx.runtime);
    if (!isCallableValue(next_method)) return error.TypeError;

    var index: u32 = 0;
    while (true) : (index += 1) {
        const next = callValueOrBytecode(ctx, output, global, iterator.value(), next_method, &.{}, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return err;
        };
        defer next.free(ctx.runtime);
        const next_object = objectFromValue(next) orelse {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return error.TypeError;
        };
        const done = getValueProperty(ctx, output, global, next_object.value(), core.atom.predefinedId("done", .string).?, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return err;
        };
        defer done.free(ctx.runtime);
        if (done.asBool() == true) break;
        const item = getValueProperty(ctx, output, global, next_object.value(), core.atom.predefinedId("value", .string).?, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return err;
        };
        defer item.free(ctx.runtime);
        values.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(index), core.Descriptor.data(item, true, true, true)) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return err;
        };
    }
    values.length = index;
    return values_value;
}

pub fn qjsArrayFromIteratorLike(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor_value: core.Value,
    iterator_value: core.Value,
    map_fn: ?core.Value,
    this_arg: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    var out_value = if (try isConstructorForArrayOf(ctx.runtime, constructor_value))
        try constructValueOrBytecode(ctx, output, global, constructor_value, &.{}, caller_function, caller_frame)
    else
        (try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global))).value();
    errdefer out_value.free(ctx.runtime);
    const out = objectFromValue(out_value) orelse return error.TypeError;
    const iterator = objectFromValue(iterator_value) orelse return error.TypeError;
    const next_key = try ctx.runtime.internAtom("next");
    defer ctx.runtime.atoms.free(next_key);
    const next_method = try getValueProperty(ctx, output, global, iterator.value(), next_key, caller_function, caller_frame);
    defer next_method.free(ctx.runtime);
    if (!isCallableValue(next_method)) return error.TypeError;

    var index: u32 = 0;
    while (true) : (index += 1) {
        const next = callValueOrBytecode(ctx, output, global, iterator.value(), next_method, &.{}, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return err;
        };
        defer next.free(ctx.runtime);
        const next_object = objectFromValue(next) orelse {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return error.TypeError;
        };
        const done = getValueProperty(ctx, output, global, next_object.value(), core.atom.predefinedId("done", .string).?, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return err;
        };
        defer done.free(ctx.runtime);
        if (done.asBool() == true) break;
        var item = getValueProperty(ctx, output, global, next_object.value(), core.atom.predefinedId("value", .string).?, caller_function, caller_frame) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return err;
        };
        defer item.free(ctx.runtime);
        if (map_fn) |mapper| {
            const mapped = callValueOrBytecode(ctx, output, global, this_arg, mapper, &.{ item, core.Value.int32(@intCast(index)) }, caller_function, caller_frame) catch |err| {
                try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
                return err;
            };
            item.free(ctx.runtime);
            item = mapped;
        }
        qjsCreateArrayDataOrTypedArrayElement(ctx.runtime, out, core.atom.atomFromUInt32(index), item) catch |err| {
            try qjsIteratorClose(ctx, output, global, iterator.value(), caller_function, caller_frame);
            return err;
        };
    }
    if (!builtins.buffer.isTypedArrayObject(out)) {
        const set_result = try setValueProperty(ctx, output, global, out.value(), core.atom.ids.length, core.Value.int32(@intCast(index)), caller_function, caller_frame);
        set_result.free(ctx.runtime);
    }
    return out_value;
}

pub fn qjsIteratorClose(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = try getValueProperty(ctx, output, global, iterator_value, return_key, caller_function, caller_frame);
    defer return_method.free(ctx.runtime);
    if (return_method.isUndefined() or return_method.isNull()) return;
    if (!isCallableValue(return_method)) return error.TypeError;
    const result = try callValueOrBytecode(ctx, output, global, iterator_value, return_method, &.{}, caller_function, caller_frame);
    result.free(ctx.runtime);
}

pub fn qjsArrayOfCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor_value: core.Value,
    func: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    if (typedArrayStaticMethodId(ctx.runtime, function_object)) |method_id| {
        if (method_id != 2) return null;
        return try qjsTypedArrayOfStaticCall(ctx, output, global, constructor_value, args, caller_function, caller_frame);
    }
    if (!isArrayStaticRecord(function_object, @intFromEnum(builtins.array.StaticMethod.of))) {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        if (!std.mem.eql(u8, name, "of")) return null;
    }
    if (args.len > @as(usize, @intCast(std.math.maxInt(i32)))) return error.RangeError;

    const length_value = core.Value.int32(@intCast(args.len));
    var out_value = if (try isConstructorForArrayOf(ctx.runtime, constructor_value))
        try constructValueOrBytecode(ctx, output, global, constructor_value, &.{length_value}, caller_function, caller_frame)
    else blk: {
        const out = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
        errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
        out.length = @intCast(args.len);
        break :blk out.value();
    };
    errdefer out_value.free(ctx.runtime);
    const out = objectFromValue(out_value) orelse return error.TypeError;

    for (args, 0..) |arg, index| {
        const key = core.atom.atomFromUInt32(@intCast(index));
        try createDataPropertyOrThrow(ctx, output, global, out.value(), out, key, arg, caller_function, caller_frame);
    }
    if (!builtins.buffer.isTypedArrayObject(out)) {
        const set_result = try setValueProperty(ctx, output, global, out.value(), core.atom.ids.length, length_value, caller_function, caller_frame);
        set_result.free(ctx.runtime);
    }
    return out_value;
}

fn isArrayStaticRecord(function_object: *core.Object, method_id: u32) bool {
    const native_ref = core.function.decodeNativeBuiltinId(function_object.nativeFunctionId()) orelse return false;
    return native_ref.domain == .array and native_ref.id == method_id;
}

fn isDateConstructorRecord(function_object: *core.Object) bool {
    const native_ref = core.function.decodeNativeBuiltinId(function_object.nativeFunctionId()) orelse return false;
    return native_ref.domain == .date and native_ref.id == @intFromEnum(builtins.date.ConstructorMethod.construct);
}

fn arrayPrototypeRecordId(function_object: *core.Object) ?u32 {
    const native_ref = core.function.decodeNativeBuiltinId(function_object.nativeFunctionId()) orelse return null;
    if (native_ref.domain != .array) return null;
    if (builtins.array.decodePrototypeMethodId(native_ref.id) == null and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.to_string) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.to_locale_string) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.map) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.for_each) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.reduce_right) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.copy_within) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.fill) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.shift) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.unshift) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.join) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.flat) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.flat_map) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.to_reversed) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.to_sorted) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.to_spliced) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.with_) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.find) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.find_index) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.find_last) and
        native_ref.id != @intFromEnum(builtins.array.PrototypeMethod.find_last_index))
    {
        return null;
    }
    return native_ref.id;
}

fn isArrayPrototypeRecord(function_object: *core.Object, method_id: u32) bool {
    return arrayPrototypeRecordId(function_object) == method_id;
}

fn qjsTypedArrayOfStaticCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    constructor_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (!try isConstructorForArrayOf(ctx.runtime, constructor_value)) return error.TypeError;
    if (args.len > std.math.maxInt(u32)) return error.RangeError;

    const out_value = try qjsTypedArrayCreateWithLength(ctx, output, global, constructor_value, args.len, caller_function, caller_frame);
    errdefer out_value.free(ctx.runtime);
    const out = objectFromValue(out_value) orelse return error.TypeError;
    for (args, 0..) |arg, index| {
        try qjsTypedArraySetElementValue(ctx, output, global, out, index, arg);
    }
    return out_value;
}

pub fn createDataPropertyOrThrow(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    if (object.proxyTarget() != null) {
        try proxyCreateDataPropertyOrThrow(ctx, output, global, receiver_value, object, atom_id, value, caller_function, caller_frame);
        return;
    }
    try qjsCreateArrayDataOrTypedArrayElement(ctx.runtime, object, atom_id, value);
}

pub fn qjsCreateArrayDataOrTypedArrayElement(
    rt: *core.Runtime,
    object: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
) !void {
    if (builtins.buffer.isTypedArrayObject(object)) {
        const index = core.array.arrayIndexFromAtom(&rt.atoms, atom_id) orelse return error.TypeError;
        const ok = try builtins.buffer.typedArraySetIndex(rt, object, index, value);
        if (!ok) return error.TypeError;
        return;
    }
    if (rt.atoms.kind(atom_id) == .private and object.hasOwnProperty(atom_id)) return error.TypeError;
    if (core.array.arrayIndexFromAtom(&rt.atoms, atom_id)) |index| {
        if (try object.appendDenseArrayIndex(rt, index, atom_id, value)) return;
    }
    object.defineOwnProperty(rt, atom_id, core.Descriptor.data(value, true, true, true)) catch |err| switch (err) {
        error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
        else => return err,
    };
}

pub fn typedArrayConstructorObject(value: core.Value) ?*core.Object {
    const object = objectFromValue(value) orelse return null;
    if (object.typedArrayElementSize() == 0 or object.typedArrayKind() == 0) return null;
    return object;
}

pub fn proxyCreateDataPropertyOrThrow(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    proxy: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const target_value = proxy.proxyTarget() orelse return error.TypeError;
    const target = property_ops.expectObject(target_value) catch return error.TypeError;
    const handler_value = proxy.proxyHandler() orelse return error.TypeError;
    const trap_atom = try ctx.runtime.internAtom("defineProperty");
    defer ctx.runtime.atoms.free(trap_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        target.defineOwnProperty(ctx.runtime, atom_id, core.Descriptor.data(value, true, true, true)) catch |err| switch (err) {
            error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
            else => return err,
        };
        return;
    }
    if (!isCallableValue(trap)) return error.TypeError;

    const key_value = try proxyTrapKeyValue(ctx.runtime, atom_id);
    defer key_value.free(ctx.runtime);
    const desc_object = try core.Object.create(ctx.runtime, core.class.ids.object, objectPrototypeFromGlobal(ctx.runtime, global));
    const desc_value = desc_object.value();
    defer desc_value.free(ctx.runtime);
    try defineValueProperty(ctx.runtime, desc_object, "value", value);
    try defineValueProperty(ctx.runtime, desc_object, "writable", core.Value.boolean(true));
    try defineValueProperty(ctx.runtime, desc_object, "enumerable", core.Value.boolean(true));
    try defineValueProperty(ctx.runtime, desc_object, "configurable", core.Value.boolean(true));
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, key_value, desc_value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    if (!value_ops.isTruthy(result)) return error.TypeError;
    _ = receiver_value;
}

pub fn isConstructorForArrayOf(rt: *core.Runtime, value: core.Value) !bool {
    if (functionBytecodeFromValue(value)) |fb| {
        return !fb.is_arrow_function and fb.has_prototype and fb.func_kind != .generator and fb.func_kind != .async_generator;
    }
    if (functionObjectFromValue(value)) |function_object| {
        const function_value = function_object.functionBytecodeSlot().* orelse return false;
        const fb = functionBytecodeFromValue(function_value) orelse return false;
        return !fb.is_arrow_function and fb.has_prototype and fb.func_kind != .generator and fb.func_kind != .async_generator;
    }
    const object = callableObjectFromValue(value) orelse return false;
    if (object.class_id == core.class.ids.bound_function) {
        const target = object.boundTarget() orelse return false;
        return isConstructorForArrayOf(rt, target);
    }
    if (object.class_id == core.class.ids.c_function) {
        const native_name = try call_mod.nativeFunctionNameForVm(rt, object);
        defer rt.memory.allocator.free(native_name);
        return isBuiltinConstructorName(native_name);
    }
    return object.class_id == core.class.ids.c_closure;
}

pub fn qjsObjectIsPrototypeOf(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (args.len == 0) return core.Value.boolean(false);
    var current = objectFromValue(args[0]) orelse return core.Value.boolean(false);
    const this_object = objectFromValue(this_value) orelse return error.TypeError;
    while (try qjsObjectGetPrototypeOfStep(ctx, output, global, current, caller_function, caller_frame)) |prototype| {
        if (prototype == this_object) return core.Value.boolean(true);
        current = prototype;
    }
    return core.Value.boolean(false);
}

pub fn qjsObjectGetPrototypeOfStep(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?*core.Object {
    if (!object.is_proxy) {
        if (isThrowTypeErrorIntrinsicObject(object)) {
            if (object.getPrototype()) |prototype| return prototype;
            return functionPrototypeFromGlobal(ctx.runtime, objectRealmGlobal(object) orelse global);
        }
        return object.getPrototype();
    }
    if (object.proxyHandler() == null) return error.TypeError;
    const target_value = object.proxyTarget() orelse return error.TypeError;
    const target = objectFromValue(target_value) orelse return error.TypeError;
    const handler_value = object.proxyHandler().?;
    const trap_key = try ctx.runtime.internAtom("getPrototypeOf");
    defer ctx.runtime.atoms.free(trap_key);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_key, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) return qjsObjectGetPrototypeOfStep(ctx, output, global, target, caller_function, caller_frame);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{target_value}, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    const result_proto = if (result.isNull()) null else objectFromValue(result) orelse return error.TypeError;
    if (!try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame)) {
        const target_proto = try qjsObjectGetPrototypeOfStep(ctx, output, global, target, caller_function, caller_frame);
        if (target_proto != result_proto) return error.TypeError;
    }
    return result_proto;
}

pub fn qjsObjectGetPrototypeOfValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (!object.is_proxy) {
        if (isThrowTypeErrorIntrinsicObject(object)) {
            if (object.getPrototype()) |prototype| return prototype.value().dup();
            if (functionPrototypeFromGlobal(ctx.runtime, objectRealmGlobal(object) orelse global)) |prototype| return prototype.value().dup();
            return core.Value.nullValue();
        }
        if (object.getPrototype()) |prototype| return prototype.value().dup();
        return core.Value.nullValue();
    }
    if (object.proxyHandler() == null) return error.TypeError;
    const target_value = object.proxyTarget() orelse return error.TypeError;
    const target = objectFromValue(target_value) orelse return error.TypeError;
    const handler_value = object.proxyHandler().?;
    const trap_key = try ctx.runtime.internAtom("getPrototypeOf");
    defer ctx.runtime.atoms.free(trap_key);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_key, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) return qjsObjectGetPrototypeOfValue(ctx, output, global, target, caller_function, caller_frame);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{target_value}, caller_function, caller_frame);
    errdefer result.free(ctx.runtime);
    if (!result.isNull() and objectFromValue(result) == null) return error.TypeError;
    if (!try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame)) {
        const target_proto = try qjsObjectGetPrototypeOfStep(ctx, output, global, target, caller_function, caller_frame);
        const same = if (result.isNull())
            target_proto == null
        else if (objectFromValue(result)) |result_object|
            target_proto != null and target_proto.? == result_object
        else
            false;
        if (!same) return error.TypeError;
    }
    return result;
}

pub fn qjsArrayMapCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
) !?core.Value {
    if (args.len != 1 or !isCallableValue(args[0])) return null;
    const object = property_ops.expectObject(receiver) catch return null;
    if (!object.is_array) return null;
    const function_object = callableObjectFromValue(func) orelse return null;
    if (!isArrayPrototypeRecord(function_object, @intFromEnum(builtins.array.PrototypeMethod.map))) {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        if (!std.mem.eql(u8, name, "map")) return null;
    }

    const mapped = try core.Object.createArray(ctx.runtime, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &mapped.header);
    var index: u32 = 0;
    while (index < object.length) : (index += 1) {
        const item = object.getProperty(core.atom.atomFromUInt32(index));
        defer item.free(ctx.runtime);
        const mapped_value = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), args[0], &.{item}, null, null);
        defer mapped_value.free(ctx.runtime);
        try mapped.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(index), core.Descriptor.data(mapped_value, true, true, true));
    }
    return mapped.value();
}

const ArraySortEntry = struct {
    value: core.Value,
    order: usize,
};

pub fn qjsArraySortCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    if (!isArrayPrototypeRecord(function_object, @intFromEnum(builtins.array.PrototypeMethod.sort))) {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        if (!std.mem.eql(u8, name, "sort")) return null;
    }
    const comparator = if (args.len >= 1 and !args[0].isUndefined()) args[0] else core.Value.undefinedValue();
    if (!comparator.isUndefined() and !isCallableValue(comparator)) return error.TypeError;

    const receiver_object_value = if (objectFromValue(receiver)) |_| receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    errdefer receiver_object_value.free(ctx.runtime);
    const object = objectFromValue(receiver_object_value) orelse return error.TypeError;

    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    const is_typed_array = builtins.buffer.isTypedArrayObject(object);
    if (is_typed_method and !is_typed_array) return error.TypeError;
    if (is_typed_method) {
        if (try builtins.buffer.typedArrayDetached(object) or try builtins.buffer.typedArrayOutOfBounds(object)) return error.TypeError;
        try builtins.buffer.typedArrayRejectImmutableBuffer(ctx.runtime, object);
    }
    const length = if (is_typed_array)
        try arrayMethodTypedArrayLength(ctx.runtime, object, is_typed_method)
    else if (object.is_array)
        @as(usize, @intCast(object.length))
    else if (!receiver.isObject() and !receiver.isString())
        @as(usize, 0)
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, receiver_object_value, core.atom.ids.length, caller_function, caller_frame);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };

    var entries = std.ArrayList(ArraySortEntry).empty;
    defer {
        for (entries.items) |entry| entry.value.free(ctx.runtime);
        entries.deinit(ctx.runtime.memory.allocator);
    }

    var undefined_count: usize = 0;
    var index: usize = 0;
    while (index < length) : (index += 1) {
        const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
        defer key.deinit(ctx.runtime);
        if (!try hasValueProperty(ctx, output, global, receiver_object_value, object, key.atom, null, null)) continue;
        const value = try getValueProperty(ctx, output, global, receiver_object_value, key.atom, caller_function, caller_frame);
        if (value.isUndefined()) {
            value.free(ctx.runtime);
            undefined_count += 1;
            continue;
        }
        var value_owned = true;
        errdefer if (value_owned) value.free(ctx.runtime);
        try entries.append(ctx.runtime.memory.allocator, .{ .value = value, .order = index });
        value_owned = false;
    }

    try stableArraySortEntries(ctx, output, global, is_typed_method, comparator, entries.items, caller_function, caller_frame);

    index = 0;
    for (entries.items, 0..) |entry, sorted_index| {
        const key = try propertyAtomFromLengthIndex(ctx.runtime, sorted_index);
        defer key.deinit(ctx.runtime);
        const result = try setValueProperty(ctx, output, global, receiver_object_value, key.atom, entry.value, caller_function, caller_frame);
        result.free(ctx.runtime);
        index += 1;
    }
    while (index < entries.items.len + undefined_count) : (index += 1) {
        const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
        defer key.deinit(ctx.runtime);
        const result = try setValueProperty(ctx, output, global, receiver_object_value, key.atom, core.Value.undefinedValue(), caller_function, caller_frame);
        result.free(ctx.runtime);
    }
    while (index < length) : (index += 1) {
        const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
        defer key.deinit(ctx.runtime);
        try deleteValuePropertyOrThrow(ctx, output, global, receiver_object_value, object, key.atom);
    }
    return receiver_object_value;
}

pub fn arraySortCompare(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    comparator: core.Value,
    lhs: ArraySortEntry,
    rhs: ArraySortEntry,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !i32 {
    const result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), comparator, &.{ lhs.value, rhs.value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    const number_value = try toNumberForDateMethod(ctx, output, global, result, caller_function, caller_frame);
    defer number_value.free(ctx.runtime);
    const number = value_ops.numberValue(number_value) orelse std.math.nan(f64);
    if (std.math.isNan(number) or number == 0) {
        if (lhs.order < rhs.order) return -1;
        if (lhs.order > rhs.order) return 1;
        return 0;
    }
    return if (number < 0) -1 else 1;
}

pub fn stableArraySortEntries(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    typed_numeric_default: bool,
    comparator: core.Value,
    entries: []ArraySortEntry,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    if (entries.len < 2) return;
    const temp = try ctx.runtime.memory.allocator.alloc(ArraySortEntry, entries.len);
    defer ctx.runtime.memory.allocator.free(temp);

    var width: usize = 1;
    while (width < entries.len) : (width *= 2) {
        var start: usize = 0;
        while (start < entries.len) : (start += width * 2) {
            const mid = @min(start + width, entries.len);
            const end = @min(start + width * 2, entries.len);
            var left = start;
            var right = mid;
            var out_index = start;
            while (left < mid and right < end) : (out_index += 1) {
                if (try arrayByCopySortCompare(ctx, output, global, typed_numeric_default, comparator, entries[right], entries[left], caller_function, caller_frame) < 0) {
                    temp[out_index] = entries[right];
                    right += 1;
                } else {
                    temp[out_index] = entries[left];
                    left += 1;
                }
            }
            while (left < mid) : ({
                left += 1;
                out_index += 1;
            }) {
                temp[out_index] = entries[left];
            }
            while (right < end) : ({
                right += 1;
                out_index += 1;
            }) {
                temp[out_index] = entries[right];
            }
            @memcpy(entries[start..end], temp[start..end]);
        }
    }
}

pub fn qjsArrayByCopyCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    const mode: enum { to_reversed, to_sorted, to_spliced, with_ } = if (arrayPrototypeRecordId(function_object)) |record_id|
        switch (record_id) {
            @intFromEnum(builtins.array.PrototypeMethod.to_reversed) => .to_reversed,
            @intFromEnum(builtins.array.PrototypeMethod.to_sorted) => .to_sorted,
            @intFromEnum(builtins.array.PrototypeMethod.to_spliced) => .to_spliced,
            @intFromEnum(builtins.array.PrototypeMethod.with_) => .with_,
            else => return null,
        }
    else blk: {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        break :blk if (std.mem.eql(u8, name, "toReversed"))
            .to_reversed
        else if (std.mem.eql(u8, name, "toSorted"))
            .to_sorted
        else if (std.mem.eql(u8, name, "toSpliced"))
            .to_spliced
        else if (std.mem.eql(u8, name, "with"))
            .with_
        else
            return null;
    };

    if (mode == .to_sorted and args.len >= 1 and !args[0].isUndefined() and !isCallableValue(args[0])) {
        return error.TypeError;
    }

    const receiver_object_value = if (objectFromValue(receiver)) |_| receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    defer receiver_object_value.free(ctx.runtime);
    const object = objectFromValue(receiver_object_value) orelse return null;
    if (object.class_id == core.class.ids.string) return null;
    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    if (is_typed_method and !builtins.buffer.isTypedArrayObject(object)) return error.TypeError;
    if (is_typed_method) {
        const name = switch (mode) {
            .to_reversed => "toReversed",
            .to_sorted => "toSorted",
            .to_spliced => "toSpliced",
            .with_ => "with",
        };
        if (try qjsTypedArrayByCopyCall(ctx, output, global, object, name, args, caller_function, caller_frame)) |value| return value;
    }

    const length = if (object.is_array)
        @as(usize, @intCast(object.length))
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, receiver_object_value, core.atom.ids.length, caller_function, caller_frame);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };
    const is_to_spliced = mode == .to_spliced;
    if (!is_to_spliced and length > core.array.max_array_length) return error.RangeError;

    if (mode == .to_reversed) {
        const out = try createArrayByCopyOutput(ctx.runtime, global, length);
        errdefer out.value().free(ctx.runtime);
        var index: usize = 0;
        while (index < length) : (index += 1) {
            const from_key = try propertyAtomFromLengthIndex(ctx.runtime, length - index - 1);
            defer from_key.deinit(ctx.runtime);
            const item = try getValueProperty(ctx, output, global, receiver_object_value, from_key.atom, caller_function, caller_frame);
            defer item.free(ctx.runtime);
            try defineArrayByCopyElement(ctx.runtime, out, index, item);
        }
        return out.value();
    }

    if (mode == .to_sorted) {
        const comparator = if (args.len >= 1 and !args[0].isUndefined()) args[0] else core.Value.undefinedValue();
        const out = try createArrayByCopyOutput(ctx.runtime, global, length);
        errdefer out.value().free(ctx.runtime);
        var entries = std.ArrayList(ArraySortEntry).empty;
        defer {
            for (entries.items) |entry| entry.value.free(ctx.runtime);
            entries.deinit(ctx.runtime.memory.allocator);
        }
        var undefined_count: usize = 0;
        var index: usize = 0;
        while (index < length) : (index += 1) {
            const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
            defer key.deinit(ctx.runtime);
            const item = try getValueProperty(ctx, output, global, receiver_object_value, key.atom, caller_function, caller_frame);
            if (item.isUndefined()) {
                item.free(ctx.runtime);
                undefined_count += 1;
            } else {
                var item_owned = true;
                errdefer if (item_owned) item.free(ctx.runtime);
                try entries.append(ctx.runtime.memory.allocator, .{ .value = item, .order = @intCast(index) });
                item_owned = false;
            }
        }
        try stableArraySortEntries(ctx, output, global, false, comparator, entries.items, caller_function, caller_frame);
        for (entries.items, 0..) |entry, sorted_index| {
            try defineArrayByCopyElement(ctx.runtime, out, sorted_index, entry.value);
        }
        index = entries.items.len;
        while (index < entries.items.len + undefined_count) : (index += 1) {
            try defineArrayByCopyElement(ctx.runtime, out, index, core.Value.undefinedValue());
        }
        return out.value();
    }

    if (mode == .with_) {
        const relative_index = try toIntegerOrInfinityForArrayByCopy(ctx, output, global, if (args.len >= 1) args[0] else core.Value.undefinedValue());
        const actual_index = if (relative_index < 0) @as(f64, @floatFromInt(length)) + relative_index else relative_index;
        if (actual_index < 0 or actual_index >= @as(f64, @floatFromInt(length)) or !std.math.isFinite(actual_index)) return error.RangeError;
        const replace_index: usize = @intFromFloat(actual_index);
        const replacement = if (args.len >= 2) args[1] else core.Value.undefinedValue();
        const out = try createArrayByCopyOutput(ctx.runtime, global, length);
        errdefer out.value().free(ctx.runtime);
        var index: usize = 0;
        while (index < length) : (index += 1) {
            if (index == replace_index) {
                try defineArrayByCopyElement(ctx.runtime, out, index, replacement);
                continue;
            }
            const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
            defer key.deinit(ctx.runtime);
            const item = try getValueProperty(ctx, output, global, receiver_object_value, key.atom, caller_function, caller_frame);
            defer item.free(ctx.runtime);
            try defineArrayByCopyElement(ctx.runtime, out, index, item);
        }
        return out.value();
    }

    const actual_start = if (args.len >= 1) try arrayRelativeIndex(ctx, output, global, args, 0, length, 0) else 0;
    const actual_delete_count = if (args.len == 0)
        @as(usize, 0)
    else if (args.len == 1)
        length - actual_start
    else blk: {
        const delete_count_number = try toIntegerOrInfinityForArrayByCopy(ctx, output, global, args[1]);
        if (std.math.isNan(delete_count_number) or delete_count_number <= 0) break :blk @as(usize, 0);
        const remaining = length - actual_start;
        if (std.math.isPositiveInf(delete_count_number) or delete_count_number >= @as(f64, @floatFromInt(remaining))) break :blk remaining;
        break :blk @as(usize, @intFromFloat(@trunc(delete_count_number)));
    };
    const insert_count = if (args.len > 2) args.len - 2 else 0;
    const kept_length = length - actual_delete_count;
    const max_safe_length: usize = 9007199254740991;
    if (insert_count > max_safe_length - kept_length) return error.TypeError;
    const new_length = kept_length + insert_count;
    if (new_length > core.array.max_array_length) return error.RangeError;
    const out = try createArrayByCopyOutput(ctx.runtime, global, new_length);
    errdefer out.value().free(ctx.runtime);
    var write_index: usize = 0;
    while (write_index < actual_start) : (write_index += 1) {
        const key = try propertyAtomFromLengthIndex(ctx.runtime, write_index);
        defer key.deinit(ctx.runtime);
        const item = try getValueProperty(ctx, output, global, receiver_object_value, key.atom, caller_function, caller_frame);
        defer item.free(ctx.runtime);
        try defineArrayByCopyElement(ctx.runtime, out, write_index, item);
    }
    if (args.len > 2) {
        for (args[2..], 0..) |item, item_index| {
            try defineArrayByCopyElement(ctx.runtime, out, actual_start + item_index, item);
        }
    }
    write_index = actual_start + insert_count;
    var read_index = actual_start + actual_delete_count;
    while (read_index < length) : ({
        read_index += 1;
        write_index += 1;
    }) {
        const key = try propertyAtomFromLengthIndex(ctx.runtime, read_index);
        defer key.deinit(ctx.runtime);
        const item = try getValueProperty(ctx, output, global, receiver_object_value, key.atom, caller_function, caller_frame);
        defer item.free(ctx.runtime);
        try defineArrayByCopyElement(ctx.runtime, out, write_index, item);
    }
    return out.value();
}

fn qjsTypedArrayByCopyCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    name: []const u8,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!builtins.buffer.isTypedArrayObject(object)) return null;
    if (try builtins.buffer.typedArrayDetached(object)) return error.TypeError;
    if (try builtins.buffer.typedArrayOutOfBounds(object)) return error.TypeError;

    const length = @as(usize, @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, object)));

    if (std.mem.eql(u8, name, "toReversed")) {
        const out_value = try qjsTypedArrayCreateSameType(ctx, output, global, object, length, caller_function, caller_frame);
        errdefer out_value.free(ctx.runtime);
        const out = objectFromValue(out_value) orelse return error.TypeError;
        var index: usize = 0;
        while (index < length) : (index += 1) {
            const item = try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(length - index - 1));
            defer item.free(ctx.runtime);
            _ = try builtins.buffer.typedArraySetIndex(ctx.runtime, out, @intCast(index), item);
        }
        return out_value;
    }

    if (std.mem.eql(u8, name, "toSorted")) {
        const comparator = if (args.len >= 1 and !args[0].isUndefined()) args[0] else core.Value.undefinedValue();
        var entries = std.ArrayList(ArraySortEntry).empty;
        defer {
            for (entries.items) |entry| entry.value.free(ctx.runtime);
            entries.deinit(ctx.runtime.memory.allocator);
        }

        var index: usize = 0;
        while (index < length) : (index += 1) {
            const item = try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(index));
            var item_owned = true;
            errdefer if (item_owned) item.free(ctx.runtime);
            try entries.append(ctx.runtime.memory.allocator, .{ .value = item, .order = @intCast(index) });
            item_owned = false;
        }
        try stableArraySortEntries(ctx, output, global, true, comparator, entries.items, caller_function, caller_frame);

        const out_value = try qjsTypedArrayCreateSameType(ctx, output, global, object, length, caller_function, caller_frame);
        errdefer out_value.free(ctx.runtime);
        const out = objectFromValue(out_value) orelse return error.TypeError;
        for (entries.items, 0..) |entry, sorted_index| {
            _ = try builtins.buffer.typedArraySetIndex(ctx.runtime, out, @intCast(sorted_index), entry.value);
        }
        return out_value;
    }

    if (std.mem.eql(u8, name, "with")) {
        const relative_index = try toIntegerOrInfinityForArrayByCopy(ctx, output, global, if (args.len >= 1) args[0] else core.Value.undefinedValue());
        const actual_index = if (relative_index < 0) @as(f64, @floatFromInt(length)) + relative_index else relative_index;
        const replacement = try qjsTypedArrayByCopyCoerceValue(ctx, output, global, object, if (args.len >= 2) args[1] else core.Value.undefinedValue());
        defer replacement.free(ctx.runtime);

        const current_length = @as(usize, @intCast(try builtins.buffer.typedArrayLength(ctx.runtime, object)));
        if (actual_index < 0 or actual_index >= @as(f64, @floatFromInt(current_length)) or !std.math.isFinite(actual_index)) return error.RangeError;
        const replace_index: usize = @intFromFloat(actual_index);

        const out_value = try qjsTypedArrayCreateSameType(ctx, output, global, object, length, caller_function, caller_frame);
        errdefer out_value.free(ctx.runtime);
        const out = objectFromValue(out_value) orelse return error.TypeError;
        var index: usize = 0;
        while (index < length) : (index += 1) {
            const item = if (index == replace_index)
                replacement
            else
                try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(index));
            defer if (index != replace_index) item.free(ctx.runtime);
            _ = try builtins.buffer.typedArraySetIndex(ctx.runtime, out, @intCast(index), item);
        }
        return out_value;
    }

    return null;
}

pub fn qjsArrayFlatCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    func: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const function_object = callableObjectFromValue(func) orelse return null;
    const is_flat_map = if (arrayPrototypeRecordId(function_object)) |record_id|
        switch (record_id) {
            @intFromEnum(builtins.array.PrototypeMethod.flat_map) => true,
            @intFromEnum(builtins.array.PrototypeMethod.flat) => false,
            else => return null,
        }
    else blk: {
        const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
        defer ctx.runtime.memory.allocator.free(name);
        break :blk if (std.mem.eql(u8, name, "flatMap"))
            true
        else if (std.mem.eql(u8, name, "flat"))
            false
        else
            return null;
    };

    const receiver_object_value = if (objectFromValue(receiver)) |_| receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    defer receiver_object_value.free(ctx.runtime);
    const source = objectFromValue(receiver_object_value) orelse return null;
    const source_length = if (source.is_array)
        @as(usize, @intCast(source.length))
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, receiver_object_value, core.atom.ids.length, caller_function, caller_frame);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };

    const mapper = if (is_flat_map) blk: {
        const mapper_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
        if (!isCallableValue(mapper_value)) return error.TypeError;
        break :blk mapper_value;
    } else core.Value.undefinedValue();
    const this_arg = if (is_flat_map and args.len >= 2) args[1] else core.Value.undefinedValue();
    const depth: usize = if (is_flat_map)
        1
    else if (args.len >= 1 and !args[0].isUndefined()) blk: {
        const depth_number = try toIntegerOrInfinityForArrayByCopy(ctx, output, global, args[0]);
        if (std.math.isNan(depth_number) or depth_number <= 0) break :blk 0;
        if (std.math.isPositiveInf(depth_number)) break :blk std.math.maxInt(usize);
        break :blk @intFromFloat(@trunc(depth_number));
    } else 1;

    const out_value = try arraySpeciesCreate(ctx, output, global, receiver_object_value, 0, caller_function, caller_frame);
    errdefer out_value.free(ctx.runtime);
    const out = objectFromValue(out_value) orelse return error.TypeError;
    const written = try flattenIntoArray(ctx, output, global, out_value, out, receiver_object_value, source, source_length, 0, depth, mapper, this_arg, caller_function, caller_frame);
    if (out.is_array) {
        const set_length = try setValueProperty(ctx, output, global, out_value, core.atom.ids.length, lengthIndexValue(written), caller_function, caller_frame);
        set_length.free(ctx.runtime);
    }
    return out_value;
}

pub fn flattenIntoArray(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target_value: core.Value,
    target: *core.Object,
    source_value: core.Value,
    source: *core.Object,
    source_length: usize,
    start: usize,
    depth: usize,
    mapper: core.Value,
    this_arg: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !usize {
    var target_index = start;
    var source_index: usize = 0;
    while (source_index < source_length) : (source_index += 1) {
        const source_key = try propertyAtomFromLengthIndex(ctx.runtime, source_index);
        defer source_key.deinit(ctx.runtime);
        if (!try hasValueProperty(ctx, output, global, source_value, source, source_key.atom, null, null)) continue;

        var element = try getValueProperty(ctx, output, global, source_value, source_key.atom, caller_function, caller_frame);
        defer element.free(ctx.runtime);
        if (!mapper.isUndefined()) {
            const index_value = lengthIndexValue(source_index);
            const mapped = try callValueOrBytecode(ctx, output, global, this_arg, mapper, &.{ element, index_value, source_value }, caller_function, caller_frame);
            element.free(ctx.runtime);
            element = mapped;
        }

        const element_object = objectFromValue(element);
        if (depth > 0 and element_object != null and try arraySpeciesOriginalIsArray(element_object.?)) {
            const element_length = if (element_object.?.is_array)
                @as(usize, @intCast(element_object.?.length))
            else blk: {
                const length_value = try getValueProperty(ctx, output, global, element, core.atom.ids.length, caller_function, caller_frame);
                defer length_value.free(ctx.runtime);
                break :blk try toLengthIndex(ctx, output, global, length_value);
            };
            const next_depth = if (depth == std.math.maxInt(usize)) depth else depth - 1;
            target_index = try flattenIntoArray(ctx, output, global, target_value, target, element, element_object.?, element_length, target_index, next_depth, core.Value.undefinedValue(), core.Value.undefinedValue(), caller_function, caller_frame);
            continue;
        }

        if (target_index > core.array.max_array_length) return error.TypeError;
        const target_key = try propertyAtomFromLengthIndex(ctx.runtime, target_index);
        defer target_key.deinit(ctx.runtime);
        try createDataPropertyOrThrow(ctx, output, global, target_value, target, target_key.atom, element, caller_function, caller_frame);
        target_index += 1;
    }
    return target_index;
}

pub fn createArrayByCopyOutput(rt: *core.Runtime, global: *core.Object, length: usize) !*core.Object {
    if (length > core.array.max_array_length) return error.RangeError;
    const out = try core.Object.createArray(rt, arrayPrototypeFromGlobal(rt, global));
    out.length = @intCast(length);
    return out;
}

fn qjsTypedArrayCreateSameType(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    length: usize,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const constructor_value = try typedArrayConstructorForObject(ctx.runtime, global, object);
    defer constructor_value.free(ctx.runtime);
    return constructValueOrBytecode(ctx, output, global, constructor_value, &.{lengthIndexValue(length)}, caller_function, caller_frame);
}

fn qjsTypedArrayByCopyCoerceValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    value: core.Value,
) !core.Value {
    const primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer primitive.free(ctx.runtime);

    if (object.typedArrayKind() == 11 or object.typedArrayKind() == 12) {
        var bigint = try value_ops.toBigIntValue(ctx.runtime, primitive);
        defer bigint.deinit();
        return value_ops.createBigIntValue(ctx.runtime, bigint);
    }

    if (primitive.isBigInt()) return error.TypeError;
    return value_ops.toNumberValue(ctx.runtime, primitive);
}

pub fn defineArrayByCopyElement(rt: *core.Runtime, out: *core.Object, index: usize, value: core.Value) !void {
    const key = core.atom.atomFromUInt32(@intCast(index));
    try out.defineOwnProperty(rt, key, core.Descriptor.data(value, true, true, true));
}

pub fn toIntegerOrInfinityForArrayByCopy(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
) !f64 {
    const primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer primitive.free(ctx.runtime);
    if (primitive.isBigInt()) return error.TypeError;
    const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
    defer number_value.free(ctx.runtime);
    const number = value_ops.numberValue(number_value) orelse std.math.nan(f64);
    if (std.math.isNan(number) or number == 0) return 0;
    if (!std.math.isFinite(number)) return number;
    return @trunc(number);
}

pub fn arrayByCopySortCompare(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    typed_numeric_default: bool,
    comparator: core.Value,
    lhs: ArraySortEntry,
    rhs: ArraySortEntry,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !i32 {
    if (!comparator.isUndefined()) {
        return arraySortCompare(ctx, output, global, comparator, lhs, rhs, caller_function, caller_frame);
    }
    if (typed_numeric_default) return typedArrayDefaultSortCompare(ctx.runtime, lhs, rhs);
    const lhs_string = try toStringForAnnexB(ctx, output, global, lhs.value, caller_function, caller_frame);
    defer lhs_string.free(ctx.runtime);
    const rhs_string = try toStringForAnnexB(ctx, output, global, rhs.value, caller_function, caller_frame);
    defer rhs_string.free(ctx.runtime);
    var lhs_bytes = std.ArrayList(u8).empty;
    defer lhs_bytes.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendRawString(ctx.runtime, &lhs_bytes, lhs_string);
    var rhs_bytes = std.ArrayList(u8).empty;
    defer rhs_bytes.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendRawString(ctx.runtime, &rhs_bytes, rhs_string);
    const order = std.mem.order(u8, lhs_bytes.items, rhs_bytes.items);
    if (order == .lt) return -1;
    if (order == .gt) return 1;
    if (lhs.order < rhs.order) return -1;
    if (lhs.order > rhs.order) return 1;
    return 0;
}

fn typedArrayDefaultSortCompare(rt: *core.Runtime, lhs: ArraySortEntry, rhs: ArraySortEntry) !i32 {
    if (value_ops.numberValue(lhs.value)) |lhs_number| {
        const rhs_number = value_ops.numberValue(rhs.value) orelse return error.TypeError;
        const lhs_nan = std.math.isNan(lhs_number);
        const rhs_nan = std.math.isNan(rhs_number);
        if (lhs_nan or rhs_nan) {
            if (lhs_nan and rhs_nan) return stableSortTieBreak(lhs, rhs);
            return if (lhs_nan) 1 else -1;
        }
        if (lhs_number < rhs_number) return -1;
        if (lhs_number > rhs_number) return 1;
        if (lhs_number == 0 and rhs_number == 0) {
            const lhs_bits: u64 = @bitCast(lhs_number);
            const rhs_bits: u64 = @bitCast(rhs_number);
            if (lhs_bits == 0x8000000000000000 and rhs_bits == 0) return -1;
            if (lhs_bits == 0 and rhs_bits == 0x8000000000000000) return 1;
        }
        return stableSortTieBreak(lhs, rhs);
    }

    const less = try value_ops.compare(rt, bytecode.opcode.op.lt, lhs.value, rhs.value);
    defer less.free(rt);
    if (less.asBool() == true) return -1;
    const greater = try value_ops.compare(rt, bytecode.opcode.op.gt, lhs.value, rhs.value);
    defer greater.free(rt);
    if (greater.asBool() == true) return 1;
    return stableSortTieBreak(lhs, rhs);
}

fn stableSortTieBreak(lhs: ArraySortEntry, rhs: ArraySortEntry) i32 {
    if (lhs.order < rhs.order) return -1;
    if (lhs.order > rhs.order) return 1;
    return 0;
}

const destructuring_iterator_state_kind: u8 = 0xf0;
const destructuring_iterator_state_mask: u8 = 0xfc;
const destructuring_iterator_done_bit: u8 = 0x01;
const destructuring_iterator_closing_bit: u8 = 0x02;

fn destructuringIteratorStateFromValue(value: core.Value) ?*core.Object {
    const object = property_ops.expectObject(value) catch return null;
    return if (isDestructuringIteratorState(object)) object else null;
}

fn isDestructuringIteratorState(object: *core.Object) bool {
    return object.class_id == core.class.ids.iterator_wrap and
        ((object.iteratorKindSlot().*) & destructuring_iterator_state_mask) == destructuring_iterator_state_kind;
}

fn createDestructuringIteratorState(rt: *core.Runtime, iterator_value: core.Value) !*core.Object {
    const state = try core.Object.create(rt, core.class.ids.iterator_wrap, null);
    errdefer core.Object.destroyFromHeader(rt, &state.header);
    state.iteratorKindSlot().* = destructuring_iterator_state_kind;
    state.iteratorIndexSlot().* = 0;
    state.iteratorTargetSlot().* = iterator_value;
    return state;
}

fn destructuringIteratorStateDone(state: *core.Object) bool {
    return ((state.iteratorKindSlot().*) & destructuring_iterator_done_bit) != 0;
}

fn setDestructuringIteratorStateDone(state: *core.Object) void {
    state.iteratorKindSlot().* |= destructuring_iterator_done_bit;
}

fn destructuringIteratorStateClosing(state: *core.Object) bool {
    return ((state.iteratorKindSlot().*) & destructuring_iterator_closing_bit) != 0;
}

fn setDestructuringIteratorStateClosing(state: *core.Object) void {
    state.iteratorKindSlot().* |= destructuring_iterator_closing_bit;
}

pub fn qjsDestructuringGet(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 2) return error.TypeError;
    const target_index: u32 = @intCast(args[1].asInt32() orelse return error.TypeError);
    if (destructuringIteratorStateFromValue(args[0])) |state| {
        const current_index: u32 = @intCast(state.iteratorIndexSlot().*);
        var index = current_index;
        var value = core.Value.undefinedValue();
        var has_value = false;
        while (index <= target_index) : (index += 1) {
            if (has_value) value.free(ctx.runtime);
            const step = destructuringIteratorStep(ctx, output, global, state) catch |err| {
                try clearDestructuringIteratorState(ctx.runtime, state);
                return err;
            };
            value = step.value;
            has_value = true;
            state.iteratorIndexSlot().* = index + 1;
        }
        return value;
    }
    if (args[0].isString()) {
        const atom_id = core.atom.atomFromUInt32(target_index);
        if (try getStringIndexValue(ctx.runtime, args[0], atom_id)) |value| return value;
        return core.Value.undefinedValue();
    }
    const object = property_ops.expectObject(args[0]) catch return error.TypeError;
    if (try arrayUsesDefaultIterator(ctx, output, global, args[0], object)) {
        return object.getProperty(core.atom.atomFromUInt32(target_index));
    }

    return error.TypeError;
}

pub fn internalSpecialObjectValue(rt: *core.Runtime, subtype: u8) !?core.Value {
    return try call_mod.internalDestructuringHelperFunction(rt, subtype);
}

pub fn qjsDestructuringElide(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 2) return error.TypeError;
    const target_index: u32 = @intCast(args[1].asInt32() orelse return error.TypeError);
    if (destructuringIteratorStateFromValue(args[0])) |state| {
        const current_index: u32 = @intCast(state.iteratorIndexSlot().*);
        var index = current_index;
        while (index <= target_index) : (index += 1) {
            const step = destructuringIteratorStep(ctx, output, global, state) catch |err| {
                try clearDestructuringIteratorState(ctx.runtime, state);
                return err;
            };
            state.iteratorIndexSlot().* = index + 1;
            step.value.free(ctx.runtime);
            if (step.done) break;
        }
        return core.Value.undefinedValue();
    }
    if (args[0].isString()) return core.Value.undefinedValue();
    const object = property_ops.expectObject(args[0]) catch return error.TypeError;
    if (try arrayUsesDefaultIterator(ctx, output, global, args[0], object)) return core.Value.undefinedValue();

    return error.TypeError;
}

pub fn qjsDestructuringRest(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 2) return error.TypeError;
    const start_index: u32 = @intCast(args[1].asInt32() orelse return error.TypeError);
    if (destructuringIteratorStateFromValue(args[0])) |state| {
        var current_index: u32 = @intCast(state.iteratorIndexSlot().*);
        while (current_index < start_index) : (current_index += 1) {
            const skipped = destructuringIteratorStep(ctx, output, global, state) catch |err| {
                try clearDestructuringIteratorState(ctx.runtime, state);
                return err;
            };
            state.iteratorIndexSlot().* = current_index + 1;
            skipped.value.free(ctx.runtime);
            if (skipped.done) break;
        }

        const out = try core.Object.createArray(ctx.runtime, null);
        errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
        var out_value = out.value();
        var value = core.Value.undefinedValue();
        var root_values = [_]core.runtime.ValueRootValue{
            .{ .value = &out_value },
            .{ .value = &value },
        };
        const root_frame = core.runtime.ValueRootFrame{
            .previous = ctx.runtime.active_value_roots,
            .values = &root_values,
        };
        ctx.runtime.active_value_roots = &root_frame;
        defer ctx.runtime.active_value_roots = root_frame.previous;
        defer value.free(ctx.runtime);

        while (true) {
            const step = destructuringIteratorStep(ctx, output, global, state) catch |err| {
                try clearDestructuringIteratorState(ctx.runtime, state);
                return err;
            };
            value = step.value;
            if (step.done) {
                value.free(ctx.runtime);
                value = core.Value.undefinedValue();
                break;
            }
            try out.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(out.length), core.Descriptor.data(value, true, true, true));
            value.free(ctx.runtime);
            value = core.Value.undefinedValue();
            current_index += 1;
            state.iteratorIndexSlot().* = current_index;
        }
        return out_value;
    }
    const object = property_ops.expectObject(args[0]) catch return error.TypeError;
    if (try arrayUsesDefaultIterator(ctx, output, global, args[0], object)) {
        const out = try core.Object.createArray(ctx.runtime, null);
        errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
        var out_value = out.value();
        var value = core.Value.undefinedValue();
        var root_values = [_]core.runtime.ValueRootValue{
            .{ .value = &out_value },
            .{ .value = &value },
        };
        const root_frame = core.runtime.ValueRootFrame{
            .previous = ctx.runtime.active_value_roots,
            .values = &root_values,
        };
        ctx.runtime.active_value_roots = &root_frame;
        defer ctx.runtime.active_value_roots = root_frame.previous;
        defer value.free(ctx.runtime);

        var index = start_index;
        while (index < object.length) : (index += 1) {
            value = object.getProperty(core.atom.atomFromUInt32(index));
            try out.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(out.length), core.Descriptor.data(value, true, true, true));
            value.free(ctx.runtime);
            value = core.Value.undefinedValue();
        }
        return out_value;
    }
    return error.TypeError;
}

pub fn qjsDestructuringObjectRest(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 1) return error.TypeError;
    var source_value = try value_vm.toObjectForWith(ctx.runtime, args[0]);
    defer source_value.free(ctx.runtime);
    const source = try property_ops.expectObject(source_value);

    var out_value = core.Value.undefinedValue();
    var value = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &source_value },
        .{ .value = &out_value },
        .{ .value = &value },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;
    defer value.free(ctx.runtime);

    const out = try core.Object.create(ctx.runtime, core.class.ids.object, objectPrototypeFromGlobal(ctx.runtime, global));
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    out_value = out.value();
    const keys = try objectRestOwnKeys(ctx, output, global, source);
    defer core.Object.freeKeys(ctx.runtime, keys);

    for (keys) |key| {
        if (source.class_id == core.class.ids.string and key == core.atom.ids.length) continue;
        if (try objectRestKeyExcluded(ctx, args[1..], key)) continue;
        const desc = try objectRestOwnPropertyDescriptor(ctx, output, global, source, key) orelse continue;
        defer desc.destroy(ctx.runtime);
        if (desc.enumerable != true) continue;
        value = getValueProperty(ctx, output, global, args[0], key, null, null) catch |err| return err;
        try out.defineOwnProperty(ctx.runtime, key, core.Descriptor.data(value, true, true, true));
        value.free(ctx.runtime);
        value = core.Value.undefinedValue();
    }
    return out_value;
}

test "qjsDestructuringRest roots direct symbol values while creating rest array" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try qjs_vm.ensureContextGlobal(ctx);

    const source = try core.Object.createArray(rt, arrayPrototypeFromGlobal(rt, global));
    var source_alive = true;
    defer if (source_alive) source.value().free(rt);
    const symbol_atom = try rt.atoms.newValueSymbol("gc-destructuring-rest-symbol");
    try source.defineOwnProperty(rt, core.atom.atomFromUInt32(0), core.Descriptor.data(core.Value.symbol(symbol_atom), true, true, true));
    source.length = 1;

    const args = [_]core.Value{ source.value(), core.Value.int32(0) };
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const rest_value = try qjsDestructuringRest(ctx, null, global, &args);
    var rest_alive = true;
    defer if (rest_alive) rest_value.free(rt);
    const rest = try property_ops.expectObject(rest_value);

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    {
        const stored = rest.getProperty(core.atom.atomFromUInt32(0));
        defer stored.free(rt);
        try std.testing.expect(stored.same(core.Value.symbol(symbol_atom)));
    }

    rest_value.free(rt);
    rest_alive = false;
    source.value().free(rt);
    source_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

test "qjsDestructuringObjectRest roots direct symbol values while creating rest object" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try qjs_vm.ensureContextGlobal(ctx);

    const source = try core.Object.create(rt, core.class.ids.object, objectPrototypeFromGlobal(rt, global));
    var source_alive = true;
    defer if (source_alive) source.value().free(rt);
    const key = try rt.internAtom("kept");
    defer rt.atoms.free(key);
    const symbol_atom = try rt.atoms.newValueSymbol("gc-destructuring-object-rest-symbol");
    try source.defineOwnProperty(rt, key, core.Descriptor.data(core.Value.symbol(symbol_atom), true, true, true));

    const args = [_]core.Value{source.value()};
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const rest_value = try qjsDestructuringObjectRest(ctx, null, global, &args);
    var rest_alive = true;
    defer if (rest_alive) rest_value.free(rt);
    const rest = try property_ops.expectObject(rest_value);

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    {
        const stored = rest.getProperty(key);
        defer stored.free(rt);
        try std.testing.expect(stored.same(core.Value.symbol(symbol_atom)));
    }

    rest_value.free(rt);
    rest_alive = false;
    source.value().free(rt);
    source_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

pub fn objectRestOwnKeys(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source: *core.Object,
) HostError![]core.Atom {
    if (source.proxyTarget() == null and builtins.buffer.isTypedArrayObject(source)) {
        return try typedArrayOwnKeys(ctx.runtime, source);
    }
    if (source.proxyTarget() == null) {
        return try source.ownKeys(ctx.runtime);
    }
    const target_value = source.proxyTarget() orelse return source.ownKeys(ctx.runtime);
    const handler_value = source.proxyHandler() orelse return error.TypeError;
    const own_keys_atom = try ctx.runtime.internAtom("ownKeys");
    defer ctx.runtime.atoms.free(own_keys_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, own_keys_atom, null, null);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        const target = try property_ops.expectObject(target_value);
        return objectRestOwnKeys(ctx, output, global, target);
    }
    const trap_result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{target_value}, null, null);
    defer trap_result.free(ctx.runtime);
    _ = try property_ops.expectObject(trap_result);
    var out: []core.Atom = &.{};
    errdefer core.Object.freeKeys(ctx.runtime, out);
    const length_value = try getValueProperty(ctx, output, global, trap_result, core.atom.ids.length, null, null);
    defer length_value.free(ctx.runtime);
    const length = try toLengthIndex(ctx, output, global, length_value);
    var index: usize = 0;
    while (index < length) : (index += 1) {
        const index_key = try propertyAtomFromLengthIndex(ctx.runtime, index);
        defer index_key.deinit(ctx.runtime);
        const key_value = try getValueProperty(ctx, output, global, trap_result, index_key.atom, null, null);
        defer key_value.free(ctx.runtime);
        if (!key_value.isString() and !key_value.isSymbol()) return error.TypeError;
        const atom_id = try property_ops.propertyKeyAtom(ctx.runtime, key_value);
        errdefer ctx.runtime.atoms.free(atom_id);
        if (atomListContains(out, atom_id)) return error.TypeError;
        try appendOwnedAtom(ctx.runtime, &out, atom_id);
    }
    try validateProxyOwnKeysResult(ctx, output, global, target_value, out);
    return out;
}

pub fn appendOwnedAtom(rt: *core.Runtime, keys: *[]core.Atom, atom_id: core.Atom) !void {
    const next = try rt.memory.alloc(core.Atom, keys.*.len + 1);
    errdefer rt.memory.free(core.Atom, next);
    @memcpy(next[0..keys.*.len], keys.*);
    next[keys.*.len] = atom_id;
    const old = keys.*;
    keys.* = next;
    if (old.len != 0) rt.memory.free(core.Atom, old);
}

pub fn typedArrayOwnKeys(rt: *core.Runtime, source: *core.Object) ![]core.Atom {
    var keys: []core.Atom = &[_]core.Atom{};
    errdefer core.Object.freeKeys(rt, keys);
    const length = try builtins.buffer.typedArrayLength(rt, source);
    var index: u32 = 0;
    while (index < length) : (index += 1) {
        try appendAtom(rt, &keys, core.atom.atomFromUInt32(index));
    }

    const ordinary = try source.ownKeys(rt);
    defer core.Object.freeKeys(rt, ordinary);
    for (ordinary) |key| {
        if (rt.atoms.kind(key) == .symbol) continue;
        if (try typedArrayCanonicalNumericIndex(rt, key) != .none) continue;
        if (isTypedArrayInternalOwnKey(rt, key)) continue;
        if (atomListContains(keys, key)) continue;
        try appendAtom(rt, &keys, key);
    }
    for (ordinary) |key| {
        if (rt.atoms.kind(key) != .symbol) continue;
        if (atomListContains(keys, key)) continue;
        try appendAtom(rt, &keys, key);
    }
    return keys;
}

pub fn isTypedArrayInternalOwnKey(rt: *core.Runtime, atom_id: core.Atom) bool {
    _ = rt;
    return atom_id == atom_buffer or
        atom_id == core.atom.ids.length or
        atom_id == atom_byte_length or
        atom_id == atom_byte_offset;
}

pub fn validateProxyOwnKeysResult(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target_value: core.Value,
    result_keys: []const core.Atom,
) HostError!void {
    const rt = ctx.runtime;
    const target = try property_ops.expectObject(target_value);
    const target_keys = try objectRestOwnKeys(ctx, output, global, target);
    defer core.Object.freeKeys(rt, target_keys);
    const target_extensible = target.isExtensible();

    for (target_keys) |target_key| {
        const desc = target.getOwnProperty(target_key) orelse continue;
        defer desc.destroy(rt);
        if (desc.configurable == false or !target_extensible) {
            if (!atomListContains(result_keys, target_key)) return error.TypeError;
        }
    }
    if (!target_extensible) {
        for (result_keys) |result_key| {
            if (!atomListContains(target_keys, result_key)) return error.TypeError;
        }
    }
}

pub fn objectRestOwnPropertyDescriptor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source: *core.Object,
    key: core.Atom,
) !?core.Descriptor {
    return try proxyAwareOwnPropertyDescriptor(ctx, output, global, source, key, null, null);
}

pub fn proxyAwareOwnPropertyDescriptor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source: *core.Object,
    key: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Descriptor {
    if (source.proxyTarget() == null) {
        if (try typedArrayCanonicalOwnDescriptor(ctx.runtime, source, key)) |desc| return desc;
        if (source.moduleNamespaceOwnBindingValue(key)) |binding_value| {
            defer binding_value.free(ctx.runtime);
            if (binding_value.isUninitialized()) return error.ReferenceError;
        }
        return source.getOwnProperty(key);
    }
    const target_value = source.proxyTarget() orelse return error.TypeError;
    const target = try property_ops.expectObject(target_value);
    const handler_value = source.proxyHandler() orelse return error.TypeError;
    const trap_atom = try ctx.runtime.internAtom("getOwnPropertyDescriptor");
    defer ctx.runtime.atoms.free(trap_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        return try proxyAwareOwnPropertyDescriptor(ctx, output, global, target, key, caller_function, caller_frame);
    }
    if (!isCallableValue(trap)) return error.TypeError;
    const key_value = try proxyTrapKeyValue(ctx.runtime, key);
    defer key_value.free(ctx.runtime);
    const desc_value = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, key_value }, caller_function, caller_frame);
    defer desc_value.free(ctx.runtime);
    const target_desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, target, key, caller_function, caller_frame);
    defer if (target_desc) |item| item.destroy(ctx.runtime);
    const target_extensible = try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame);
    if (desc_value.isUndefined()) {
        if (target_desc) |item| {
            if (item.configurable == false or !target_extensible) return error.TypeError;
        }
        return null;
    }
    const desc_object = property_ops.expectObject(desc_value) catch return error.TypeError;
    var result_desc = try qjsDescriptorFromObject(ctx, output, global, desc_value, desc_object, target, key, caller_function, caller_frame);
    errdefer result_desc.destroy(ctx.runtime);
    var complete_desc = try completeProxyDescriptor(ctx.runtime, result_desc);
    errdefer complete_desc.destroy(ctx.runtime);
    if (!try isCompatibleProxyDescriptor(target_extensible, target_desc, complete_desc)) return error.TypeError;
    if (complete_desc.configurable == false) {
        if (target_desc) |item| {
            if (item.configurable != false) return error.TypeError;
            if (complete_desc.kind == .data and complete_desc.writable == false and item.kind == .data and item.writable == true) return error.TypeError;
        } else {
            return error.TypeError;
        }
    }
    result_desc.destroy(ctx.runtime);
    return complete_desc;
}

pub fn proxyAwareIsExtensible(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    if (object.proxyTarget() == null) return object.isExtensible();
    const target_value = object.proxyTarget() orelse return error.TypeError;
    const target = try property_ops.expectObject(target_value);
    const handler_value = object.proxyHandler() orelse return error.TypeError;
    const trap_atom = try ctx.runtime.internAtom("isExtensible");
    defer ctx.runtime.atoms.free(trap_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) return try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame);
    if (!isCallableValue(trap)) return error.TypeError;
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{target_value}, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    const extensible = valueTruthy(result);
    if (extensible != try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame)) return error.TypeError;
    return extensible;
}

pub fn proxyAwarePreventExtensions(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    const target_value = object.proxyTarget() orelse {
        object.preventExtensions();
        return true;
    };
    const target = try property_ops.expectObject(target_value);
    const handler_value = object.proxyHandler() orelse return error.TypeError;
    const trap_atom = try ctx.runtime.internAtom("preventExtensions");
    defer ctx.runtime.atoms.free(trap_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) return proxyAwarePreventExtensions(ctx, output, global, target, caller_function, caller_frame);
    if (!isCallableValue(trap)) return error.TypeError;
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{target_value}, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    if (!valueTruthy(result)) return false;
    if (try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame)) return error.TypeError;
    return true;
}

pub fn proxyAwareSetPrototypeOf(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    prototype: ?*core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    const target_value = object.proxyTarget() orelse {
        object.setPrototype(ctx.runtime, prototype) catch |err| switch (err) {
            error.PrototypeCycle, error.NotExtensible => return false,
            else => return err,
        };
        return true;
    };
    const target = try property_ops.expectObject(target_value);
    const handler_value = object.proxyHandler() orelse return error.TypeError;
    const trap_atom = try ctx.runtime.internAtom("setPrototypeOf");
    defer ctx.runtime.atoms.free(trap_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    const proto_value = if (prototype) |proto| proto.value() else core.Value.nullValue();
    if (trap.isUndefined() or trap.isNull()) return proxyAwareSetPrototypeOf(ctx, output, global, target, prototype, caller_function, caller_frame);
    if (!isCallableValue(trap)) return error.TypeError;
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, proto_value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    if (!valueTruthy(result)) return false;
    if (!try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame)) {
        const target_proto = try qjsObjectGetPrototypeOfStep(ctx, output, global, target, caller_function, caller_frame);
        if (target_proto != prototype) return error.TypeError;
    }
    return true;
}

pub fn completeProxyDescriptor(rt: *core.Runtime, desc: core.Descriptor) !core.Descriptor {
    _ = rt;
    return switch (desc.kind) {
        .generic, .data => core.Descriptor.data(
            if (desc.value_present) desc.value.dup() else core.Value.undefinedValue(),
            desc.writable orelse false,
            desc.enumerable orelse false,
            desc.configurable orelse false,
        ),
        .accessor => core.Descriptor.accessor(
            if (desc.getter_present) desc.getter.dup() else core.Value.undefinedValue(),
            if (desc.setter_present) desc.setter.dup() else core.Value.undefinedValue(),
            desc.enumerable orelse false,
            desc.configurable orelse false,
        ),
    };
}

pub fn isCompatibleProxyDescriptor(extensible: bool, current: ?core.Descriptor, desc: core.Descriptor) !bool {
    const current_desc = current orelse return extensible;
    if (current_desc.configurable orelse false) return true;
    if (desc.configurable orelse false) return false;
    if (desc.enumerable) |enumerable| {
        if (enumerable != (current_desc.enumerable orelse false)) return false;
    }
    if (desc.kind == .generic) return true;

    const current_is_accessor = current_desc.kind == .accessor;
    if ((desc.kind == .accessor) != current_is_accessor) return false;
    if (!current_is_accessor and !(current_desc.writable orelse false)) {
        if (desc.writable orelse false) return false;
        if (desc.kind == .data and desc.value_present and !builtins.object.sameValue(current_desc.value, desc.value)) return false;
    }
    if (current_is_accessor and desc.kind == .accessor) {
        if (desc.getter_present and !builtins.object.sameValue(current_desc.getter, desc.getter)) return false;
        if (desc.setter_present and !builtins.object.sameValue(current_desc.setter, desc.setter)) return false;
    }
    return true;
}

pub fn objectRestKeyExcluded(ctx: *core.Context, excluded: []const core.Value, key: core.Atom) !bool {
    for (excluded) |value| {
        const excluded_key = try property_ops.propertyKeyAtom(ctx.runtime, value);
        defer ctx.runtime.atoms.free(excluded_key);
        if (excluded_key == key) return true;
    }
    return false;
}

pub fn arrayUsesDefaultIterator(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source_value: core.Value,
    source: *core.Object,
) !bool {
    if (!source.is_array) return false;
    const iterator_method = try getIteratorMethod(ctx, output, global, source_value);
    defer iterator_method.free(ctx.runtime);
    if (!isCallableValue(iterator_method)) return error.TypeError;
    const function_object = callableObjectFromValue(iterator_method) orelse return false;
    const name = try call_mod.nativeFunctionNameForVm(ctx.runtime, function_object);
    defer ctx.runtime.memory.allocator.free(name);
    return std.mem.eql(u8, name, "values");
}

pub fn qjsDestructuringClose(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 1) return core.Value.undefinedValue();
    const state = destructuringIteratorStateFromValue(args[0]) orelse return core.Value.undefinedValue();
    const iterator_value = (state.iteratorTargetSlot().*) orelse return core.Value.undefinedValue();
    if (destructuringIteratorStateDone(state)) {
        try clearDestructuringIteratorState(ctx.runtime, state);
        return core.Value.undefinedValue();
    }
    const iterator = try property_ops.expectObject(iterator_value);
    errdefer clearDestructuringIteratorState(ctx.runtime, state) catch {};
    setDestructuringIteratorStateClosing(state);
    setDestructuringIteratorStateDone(state);
    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = try getValueProperty(ctx, output, global, iterator.value(), return_key, null, null);
    defer return_method.free(ctx.runtime);
    if (!isCallableValue(return_method)) {
        try clearDestructuringIteratorState(ctx.runtime, state);
        return core.Value.undefinedValue();
    }
    const result = try callValueOrBytecode(ctx, output, global, iterator.value(), return_method, &.{}, null, null);
    defer result.free(ctx.runtime);
    if (!result.isObject()) {
        try clearDestructuringIteratorState(ctx.runtime, state);
        return error.TypeError;
    }
    try clearDestructuringIteratorState(ctx.runtime, state);
    return core.Value.undefinedValue();
}

pub fn qjsDestructuringRequireIterator(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 1) return error.TypeError;
    if (destructuringIteratorStateFromValue(args[0])) |_| return args[0].dup();

    var iterator_value = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &iterator_value },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;
    defer iterator_value.free(ctx.runtime);

    const source = property_ops.expectObject(args[0]) catch {
        const iterator_method = try getIteratorMethod(ctx, output, global, args[0]);
        defer iterator_method.free(ctx.runtime);
        if (!isCallableValue(iterator_method)) return error.TypeError;
        iterator_value = try callValueOrBytecode(ctx, output, global, args[0], iterator_method, &.{}, null, null);
        _ = try property_ops.expectObject(iterator_value);
        try cacheDestructuringIteratorNextMethod(ctx, output, global, iterator_value);
        const state = try createDestructuringIteratorState(ctx.runtime, iterator_value.dup());
        return state.value();
    };
    if (try arrayUsesDefaultIterator(ctx, output, global, args[0], source)) return args[0].dup();
    if (source.class_id == core.class.ids.generator or source.class_id == core.class.ids.async_generator) {
        try cacheDestructuringIteratorNextMethod(ctx, output, global, source.value());
        const state = try createDestructuringIteratorState(ctx.runtime, source.value().dup());
        return state.value();
    }
    const iterator_method = try getIteratorMethod(ctx, output, global, args[0]);
    defer iterator_method.free(ctx.runtime);
    if (!isCallableValue(iterator_method)) return error.TypeError;
    iterator_value = try callValueOrBytecode(ctx, output, global, args[0], iterator_method, &.{}, null, null);
    _ = try property_ops.expectObject(iterator_value);
    try cacheDestructuringIteratorNextMethod(ctx, output, global, iterator_value);
    const state = try createDestructuringIteratorState(ctx.runtime, iterator_value.dup());
    return state.value();
}

pub fn getIteratorMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source_value: core.Value,
) !core.Value {
    const symbol_key = core.atom.predefinedId("Symbol.iterator", .symbol) orelse return error.TypeError;
    return getValueProperty(ctx, output, global, source_value, symbol_key, null, null);
}

pub fn iteratorForValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (source_value.isString()) return builtins.string.iterator(ctx.runtime, source_value);
    const source_object = property_ops.expectObject(source_value) catch null;
    if (source_object != null and source_object.?.class_id == core.class.ids.string) return builtins.string.iterator(ctx.runtime, source_value);
    if (source_object != null and
        (source_object.?.class_id == core.class.ids.array_iterator or
            source_object.?.class_id == core.class.ids.string_iterator or
            source_object.?.class_id == core.class.ids.generator or
            source_object.?.class_id == core.class.ids.async_generator))
    {
        return source_value.dup();
    }
    const iterator_method = try getIteratorMethod(ctx, output, global, source_value);
    defer iterator_method.free(ctx.runtime);
    if (!isCallableValue(iterator_method)) return error.TypeError;
    const iterator_value = try callValueOrBytecode(ctx, output, global, source_value, iterator_method, &.{}, caller_function, caller_frame);
    errdefer iterator_value.free(ctx.runtime);
    _ = property_ops.expectObject(iterator_value) catch return error.TypeError;
    try cacheIteratorNextMethod(ctx, output, global, iterator_value);
    return iterator_value;
}

pub fn cacheIteratorNextMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
) !void {
    try cacheIteratorNextMethodMode(ctx, output, global, iterator_value, true);
}

fn cacheDestructuringIteratorNextMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
) !void {
    try cacheIteratorNextMethodMode(ctx, output, global, iterator_value, false);
}

fn cacheIteratorNextMethodMode(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
    require_callable: bool,
) !void {
    const iterator = try property_ops.expectObject(iterator_value);
    const next_key = try ctx.runtime.internAtom("next");
    defer ctx.runtime.atoms.free(next_key);
    const next_method = try getValueProperty(ctx, output, global, iterator_value, next_key, null, null);
    defer next_method.free(ctx.runtime);
    if (require_callable and !isCallableValue(next_method)) return error.TypeError;
    const cached = iterator.cachedIteratorNextSlot();
    const next_cached = next_method.dup();
    const old_cached = cached.*;
    cached.* = next_cached;
    if (old_cached) |stored| stored.free(ctx.runtime);
}

const DestructuringIteratorStep = struct {
    value: core.Value,
    done: bool,
};

pub const IteratorStepResult = struct {
    result: core.Value,
    value: core.Value,
    done: bool,
};

pub fn destructuringIteratorStep(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    state: *core.Object,
) !DestructuringIteratorStep {
    const iterator_value = (state.iteratorTargetSlot().*) orelse
        return .{ .value = core.Value.undefinedValue(), .done = true };
    const iterator = try property_ops.expectObject(iterator_value);
    const next_method = if (iterator.cachedIteratorNext()) |stored| stored.dup() else blk: {
        const next_key = try ctx.runtime.internAtom("next");
        defer ctx.runtime.atoms.free(next_key);
        break :blk try getValueProperty(ctx, output, global, iterator_value, next_key, null, null);
    };
    defer next_method.free(ctx.runtime);
    if (!isCallableValue(next_method)) return error.TypeError;
    var next_result_value = try callValueOrBytecode(ctx, output, global, iterator_value, next_method, &.{}, null, null);
    defer next_result_value.free(ctx.runtime);
    if (objectFromValue(next_result_value)) |promise| {
        if (promise.class_id == core.class.ids.promise) {
            if (promise.promiseIsRejected()) {
                const reason = if (promise.promiseResult()) |stored| stored.dup() else core.Value.undefinedValue();
                _ = ctx.throwValue(reason);
                return error.Test262Error;
            }
            const fulfilled = if (promise.promiseResult()) |stored| stored.dup() else core.Value.undefinedValue();
            next_result_value.free(ctx.runtime);
            next_result_value = fulfilled;
        }
    }
    const next_result = property_ops.expectObject(next_result_value) catch return error.TypeError;
    if (next_result.class_id == core.class.ids.regexp) {
        return .{ .value = core.Value.undefinedValue(), .done = false };
    }
    const done_key = core.atom.predefinedId("done", .string).?;
    const done = try getValueProperty(ctx, output, global, next_result.value(), done_key, null, null);
    defer done.free(ctx.runtime);
    if (value_ops.isTruthy(done)) {
        setDestructuringIteratorStateDone(state);
        return .{ .value = core.Value.undefinedValue(), .done = true };
    }
    const value_key = core.atom.predefinedId("value", .string).?;
    return .{ .value = try getValueProperty(ctx, output, global, next_result.value(), value_key, null, null), .done = false };
}

pub fn appendIteratorValues(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target: *core.Object,
    source_value: core.Value,
    start_index: i32,
) !i32 {
    const source_object = property_ops.expectObject(source_value) catch null;
    const iterator_value = if (source_object != null and
        (source_object.?.class_id == core.class.ids.generator or source_object.?.class_id == core.class.ids.async_generator))
        source_value.dup()
    else blk: {
        const iterator_method = try getIteratorMethod(ctx, output, global, source_value);
        defer iterator_method.free(ctx.runtime);
        if (!isCallableValue(iterator_method)) return error.TypeError;
        break :blk try callValueOrBytecode(ctx, output, global, source_value, iterator_method, &.{}, null, null);
    };
    defer iterator_value.free(ctx.runtime);
    if (!iterator_value.isObject()) return error.TypeError;
    var index = start_index;
    while (true) {
        const step = try iteratorStepValue(ctx, output, global, iterator_value);
        if (step.done) {
            step.value.free(ctx.runtime);
            break;
        }
        try property_ops.defineDataProperty(ctx.runtime, target, core.atom.atomFromUInt32(@intCast(index)), step.value);
        step.value.free(ctx.runtime);
        index += 1;
    }
    return index;
}

pub fn iteratorStepValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
) !DestructuringIteratorStep {
    const iterator = try property_ops.expectObject(iterator_value);
    const next_method = if (iterator.cachedIteratorNext()) |stored| stored.dup() else blk: {
        const next_key = try ctx.runtime.internAtom("next");
        defer ctx.runtime.atoms.free(next_key);
        break :blk try getValueProperty(ctx, output, global, iterator_value, next_key, null, null);
    };
    defer next_method.free(ctx.runtime);
    if (!isCallableValue(next_method)) return error.TypeError;
    var next_result_value = try callValueOrBytecode(ctx, output, global, iterator_value, next_method, &.{}, null, null);
    defer next_result_value.free(ctx.runtime);
    if (objectFromValue(next_result_value)) |promise| {
        if (promise.class_id == core.class.ids.promise) {
            if (promise.promiseIsRejected()) {
                const reason = if (promise.promiseResult()) |stored| stored.dup() else core.Value.undefinedValue();
                _ = ctx.throwValue(reason);
                return error.Test262Error;
            }
            const fulfilled = if (promise.promiseResult()) |stored| stored.dup() else core.Value.undefinedValue();
            next_result_value.free(ctx.runtime);
            next_result_value = fulfilled;
        }
    }
    const next_result = property_ops.expectObject(next_result_value) catch return error.TypeError;
    if (next_result.class_id == core.class.ids.regexp) {
        return .{ .value = core.Value.undefinedValue(), .done = false };
    }
    const done_key = core.atom.predefinedId("done", .string).?;
    const done = try getValueProperty(ctx, output, global, next_result.value(), done_key, null, null);
    defer done.free(ctx.runtime);
    if (value_ops.isTruthy(done)) return .{ .value = core.Value.undefinedValue(), .done = true };
    const value_key = core.atom.predefinedId("value", .string).?;
    return .{ .value = try getValueProperty(ctx, output, global, next_result.value(), value_key, null, null), .done = false };
}

pub fn iteratorStepResult(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
    next_arg: core.Value,
) !IteratorStepResult {
    const iterator = try property_ops.expectObject(iterator_value);
    const next_method = if (iterator.cachedIteratorNext()) |stored| stored.dup() else blk: {
        const next_key = try ctx.runtime.internAtom("next");
        defer ctx.runtime.atoms.free(next_key);
        break :blk try getValueProperty(ctx, output, global, iterator_value, next_key, null, null);
    };
    defer next_method.free(ctx.runtime);
    if (!isCallableValue(next_method)) return error.TypeError;
    const next_result_value = try callValueOrBytecode(ctx, output, global, iterator_value, next_method, &.{next_arg}, null, null);
    errdefer next_result_value.free(ctx.runtime);
    const next_result = property_ops.expectObject(next_result_value) catch return error.TypeError;
    const done_key = core.atom.predefinedId("done", .string).?;
    const done = try getValueProperty(ctx, output, global, next_result.value(), done_key, null, null);
    defer done.free(ctx.runtime);
    const is_done = valueTruthy(done);
    const value = if (is_done) blk: {
        const value_key = core.atom.predefinedId("value", .string).?;
        break :blk try getValueProperty(ctx, output, global, next_result.value(), value_key, null, null);
    } else core.Value.undefinedValue();
    errdefer value.free(ctx.runtime);
    return .{ .result = next_result_value, .value = value, .done = is_done };
}

pub fn clearDestructuringIteratorState(rt: *core.Runtime, state: *core.Object) !void {
    if (!isDestructuringIteratorState(state)) return;
    state.clearIteratorTarget(rt);
    state.iteratorIndexSlot().* = 0;
    state.iteratorKindSlot().* = 0;
}

pub fn isCallableValue(value: core.Value) bool {
    return value.isFunctionBytecode() or functionObjectFromValue(value) != null or callableObjectFromValue(value) != null or proxyTargetIsCallable(value);
}

pub fn qjsReflectCallForNativeRecord(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const reflect_mod = builtins.reflect_proxy;
    return switch (id) {
        @intFromEnum(reflect_mod.StaticMethod.define_property) => (try qjsDefinePropertyWithKind(ctx, output, global, args, 2, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.get_own_property_descriptor) => (try qjsReflectGetOwnPropertyDescriptorCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.delete_property) => (try qjsReflectDeletePropertyCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.get) => (try qjsReflectGetCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.get_prototype_of) => (try qjsReflectGetPrototypeOfCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.set) => (try qjsReflectSetCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.set_prototype_of) => (try qjsReflectSetPrototypeOfCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.is_extensible) => (try qjsReflectIsExtensibleCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.prevent_extensions) => (try qjsReflectPreventExtensionsCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.has) => (try qjsReflectHasCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.own_keys) => (try qjsReflectOwnKeysCall(ctx, output, global, args)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.construct) => (try qjsReflectConstructCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(reflect_mod.StaticMethod.apply) => try qjsReflectApplyCall(ctx, output, global, args, caller_function, caller_frame),
        else => error.TypeError,
    };
}

pub fn qjsObjectCallForNativeRecord(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const object_mod = builtins.object;
    return switch (id) {
        @intFromEnum(object_mod.StaticMethod.assign) => (try qjsObjectAssignCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.create) => (try qjsObjectCreateCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.define_property) => (try qjsDefinePropertyWithKind(ctx, output, global, args, 1, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.define_properties) => (try qjsDefinePropertiesCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.get_own_property_descriptor) => (try qjsGetOwnPropertyDescriptorCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.get_own_property_descriptors) => (try qjsGetOwnPropertyDescriptorsCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.get_own_property_names) => (try qjsObjectOwnPropertyKeysCall(ctx, output, global, args, .string, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.get_own_property_symbols) => (try qjsObjectOwnPropertyKeysCall(ctx, output, global, args, .symbol, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.get_prototype_of) => (try qjsObjectGetPrototypeOfCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.has_own) => (try qjsObjectHasOwnCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.is_extensible) => (try qjsObjectIsExtensibleCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.keys) => (try qjsObjectEnumerableOwnPropertiesCall(ctx, output, global, args, .keys, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.prevent_extensions) => (try qjsObjectPreventExtensionsCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.seal) => (try qjsObjectSetIntegrityCall(ctx, output, global, args, .sealed, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.is_sealed) => (try qjsObjectTestIntegrityCall(ctx, output, global, args, .sealed)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.is_frozen) => (try qjsObjectTestIntegrityCall(ctx, output, global, args, .frozen)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.set_prototype_of) => (try qjsObjectSetPrototypeOfCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.values) => (try qjsObjectEnumerableOwnPropertiesCall(ctx, output, global, args, .values, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.entries) => (try qjsObjectEnumerableOwnPropertiesCall(ctx, output, global, args, .entries, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.is) => {
            const lhs = if (args.len >= 1) args[0] else core.Value.undefinedValue();
            const rhs = if (args.len >= 2) args[1] else core.Value.undefinedValue();
            return core.Value.boolean(object_mod.sameValue(lhs, rhs));
        },
        @intFromEnum(object_mod.StaticMethod.freeze) => (try qjsObjectSetIntegrityCall(ctx, output, global, args, .frozen, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.from_entries) => (try qjsObjectFromEntriesCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.StaticMethod.group_by) => (try qjsObjectGroupByCall(ctx, output, global, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.PrototypeMethod.to_string) => try qjsObjectToStringCall(ctx, output, global, this_value, caller_function, caller_frame),
        @intFromEnum(object_mod.PrototypeMethod.to_locale_string) => try qjsObjectToLocaleStringCall(ctx, output, global, this_value, caller_function, caller_frame),
        @intFromEnum(object_mod.PrototypeMethod.value_of) => try qjsObjectValueOfCall(ctx.runtime, global, this_value),
        @intFromEnum(object_mod.PrototypeMethod.has_own_property) => (try qjsObjectPrototypeOwnPropertyCall(ctx, output, global, this_value, id, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.PrototypeMethod.is_prototype_of) => try qjsObjectIsPrototypeOf(ctx, output, global, this_value, args, caller_function, caller_frame),
        @intFromEnum(object_mod.PrototypeMethod.property_is_enumerable) => (try qjsObjectPrototypeOwnPropertyCall(ctx, output, global, this_value, id, args, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.PrototypeMethod.define_getter) => (try qjsObjectPrototypeDefineAccessorCall(ctx, output, global, this_value, args, true, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.PrototypeMethod.define_setter) => (try qjsObjectPrototypeDefineAccessorCall(ctx, output, global, this_value, args, false, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.PrototypeMethod.lookup_getter) => (try qjsObjectPrototypeLookupAccessorCall(ctx, output, global, this_value, args, true, caller_function, caller_frame)) orelse error.TypeError,
        @intFromEnum(object_mod.PrototypeMethod.lookup_setter) => (try qjsObjectPrototypeLookupAccessorCall(ctx, output, global, this_value, args, false, caller_function, caller_frame)) orelse error.TypeError,
        else => error.TypeError,
    };
}

const AtomicsReadModifyOp = enum {
    add,
    @"and",
    compareExchange,
    exchange,
    load,
    @"or",
    sub,
    xor,
};

const AtomicsWaiterKey = struct {
    store: ?*core.object.SharedBufferStore = null,
    offset_or_ptr: usize,
};

const AtomicsWaiter = struct {
    key: AtomicsWaiterKey,
    notified: bool = false,
    linked: bool = false,
    cond: std.Io.Condition = .init,
    promise: ?core.Value = null,
    ctx: ?*core.Context = null,
    deadline: ?std.Io.Timestamp = null,
    next: ?*AtomicsWaiter = null,
};

var atomics_waiter_mutex: std.Io.Mutex = .init;
var atomics_waiters: ?*AtomicsWaiter = null;

pub fn qjsAtomicsCallForNativeRecord(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const atomics_mod = builtins.atomics;
    return switch (id) {
        @intFromEnum(atomics_mod.StaticMethod.is_lock_free) => try qjsAtomicsIsLockFree(ctx, output, global, args, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.pause) => try qjsAtomicsPause(ctx, output, global, args, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.notify) => try qjsAtomicsNotify(ctx, output, global, args, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.wait) => try qjsAtomicsWait(ctx, output, global, args, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.wait_async) => try qjsAtomicsWaitAsync(ctx, output, global, args, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.store) => try qjsAtomicsStore(ctx, output, global, args, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.load) => try qjsAtomicsReadModifyWrite(ctx, output, global, args, .load, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.add) => try qjsAtomicsReadModifyWrite(ctx, output, global, args, .add, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.@"and") => try qjsAtomicsReadModifyWrite(ctx, output, global, args, .@"and", caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.@"or") => try qjsAtomicsReadModifyWrite(ctx, output, global, args, .@"or", caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.sub) => try qjsAtomicsReadModifyWrite(ctx, output, global, args, .sub, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.xor) => try qjsAtomicsReadModifyWrite(ctx, output, global, args, .xor, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.exchange) => try qjsAtomicsReadModifyWrite(ctx, output, global, args, .exchange, caller_function, caller_frame),
        @intFromEnum(atomics_mod.StaticMethod.compare_exchange) => try qjsAtomicsReadModifyWrite(ctx, output, global, args, .compareExchange, caller_function, caller_frame),
        else => error.TypeError,
    };
}

pub fn qjsAtomicsIsLockFree(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const size_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const size = try toInt32ForAtomics(ctx, output, global, size_value, caller_function, caller_frame);
    return core.Value.boolean(size == 1 or size == 2 or size == 4 or size == 8);
}

pub fn qjsAtomicsPause(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    _ = ctx;
    _ = output;
    _ = global;
    _ = caller_function;
    _ = caller_frame;
    if (args.len >= 1 and !args[0].isUndefined()) {
        if (!args[0].isNumber()) return error.TypeError;
        const number = value_ops.numberValue(args[0]) orelse std.math.nan(f64);
        if (!std.math.isFinite(number) or @trunc(number) != number) return error.TypeError;
    }
    return core.Value.undefinedValue();
}

pub fn qjsAtomicsReadModifyWrite(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    atomic_op: AtomicsReadModifyOp,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const view_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const view = try atomicsTypedArray(view_value, false);
    if (atomic_op != .load) try builtins.buffer.typedArrayRejectImmutableBuffer(ctx.runtime, view);
    const index_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const index = try toIndexForAtomics(ctx, output, global, index_value, caller_function, caller_frame);
    try atomicsValidateIndex(ctx.runtime, view, index);

    const is_bigint = atomicsTypedArrayIsBigInt(view);
    const value_arg = if (args.len >= 3) args[2] else core.Value.undefinedValue();
    const replacement_arg = if (args.len >= 4) args[3] else core.Value.undefinedValue();
    const operand = if (atomic_op == .load) @as(u64, 0) else if (is_bigint)
        try toBigIntBitsForAtomics(ctx, output, global, value_arg, caller_function, caller_frame)
    else
        try toUint32ForAtomics(ctx, output, global, value_arg, caller_function, caller_frame);
    const replacement = if (atomic_op == .compareExchange) blk: {
        break :blk if (is_bigint)
            try toBigIntBitsForAtomics(ctx, output, global, replacement_arg, caller_function, caller_frame)
        else
            try toUint32ForAtomics(ctx, output, global, replacement_arg, caller_function, caller_frame);
    } else @as(u64, 0);
    try atomicsValidateIndex(ctx.runtime, view, index);

    const bytes = try atomicsElementBytes(view, index);
    const old = atomicsReadBits(view, bytes);
    const next = switch (atomic_op) {
        .load => old,
        .add => old +% operand,
        .@"and" => old & operand,
        .@"or" => old | operand,
        .sub => old -% operand,
        .xor => old ^ operand,
        .exchange => operand,
        .compareExchange => if (old == atomicsMaskBits(view, operand)) replacement else old,
    };
    if (atomic_op != .load) atomicsWriteBits(view, bytes, next);
    return atomicsValueFromBits(ctx.runtime, view, old);
}

pub fn qjsAtomicsStore(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const view_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const view = try atomicsTypedArray(view_value, false);
    try builtins.buffer.typedArrayRejectImmutableBuffer(ctx.runtime, view);
    const index_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const index = try toIndexForAtomics(ctx, output, global, index_value, caller_function, caller_frame);
    try atomicsValidateIndex(ctx.runtime, view, index);

    const value_arg = if (args.len >= 3) args[2] else core.Value.undefinedValue();
    const is_bigint = atomicsTypedArrayIsBigInt(view);
    const stored_value = if (is_bigint)
        try toBigIntValueForAtomics(ctx, output, global, value_arg, caller_function, caller_frame)
    else
        try toIntegerValueForAtomics(ctx, output, global, value_arg, caller_function, caller_frame);
    errdefer stored_value.free(ctx.runtime);
    const bits = if (is_bigint)
        try bigintBitsForAtomics(ctx.runtime, stored_value)
    else
        try uint32FromIntegerValueForAtomics(ctx.runtime, stored_value);
    try atomicsValidateIndex(ctx.runtime, view, index);
    const bytes = try atomicsElementBytes(view, index);
    atomicsWriteBits(view, bytes, bits);
    return stored_value;
}

pub fn qjsAtomicsNotify(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const view_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const view = try atomicsTypedArray(view_value, true);
    const buffer = try atomicsBufferObject(view);
    if (buffer.class_id != core.class.ids.shared_array_buffer and buffer.arrayBufferDetached()) return error.TypeError;
    const index_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const index = try atomicsValidateAccess(ctx, output, global, view, index_value, caller_function, caller_frame);
    const count = try atomicsNotifyCount(ctx, output, global, args, caller_function, caller_frame);
    if (buffer.class_id != core.class.ids.shared_array_buffer or count == 0) return core.Value.int32(0);
    try atomicsValidateIndex(ctx.runtime, view, index);
    const bytes = try atomicsElementBytes(view, index);
    const key = try atomicsWaiterKey(view, bytes);
    return core.Value.int32(@intCast(atomicsWakeWaiters(key, count)));
}

pub fn qjsAtomicsWait(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const view_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const view = try atomicsTypedArray(view_value, true);
    if ((try atomicsBufferObject(view)).class_id != core.class.ids.shared_array_buffer) return error.TypeError;
    const index_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const index = try atomicsValidateAccess(ctx, output, global, view, index_value, caller_function, caller_frame);
    const expected_arg = if (args.len >= 3) args[2] else core.Value.undefinedValue();
    const expected = if (atomicsTypedArrayIsBigInt(view))
        try toBigIntBitsForAtomics(ctx, output, global, expected_arg, caller_function, caller_frame)
    else
        try toInt32BitsForAtomics(ctx, output, global, expected_arg, caller_function, caller_frame);
    const timeout_arg = if (args.len >= 4) args[3] else core.Value.float64(std.math.inf(f64));
    const timeout = try toNumberForAtomics(ctx, output, global, timeout_arg, caller_function, caller_frame);
    try atomicsValidateIndex(ctx.runtime, view, index);
    const bytes = try atomicsElementBytes(view, index);
    const current = atomicsReadBits(view, bytes);
    if (current != atomicsMaskBits(view, expected)) return value_ops.createStringValue(ctx.runtime, "not-equal");
    if (!ctx.runtime.canBlock()) return error.TypeError;
    const wait_ms = atomicsWaitTimeoutMilliseconds(timeout);
    if (wait_ms == 0) return value_ops.createStringValue(ctx.runtime, "timed-out");
    const key = try atomicsWaiterKey(view, bytes);
    return atomicsWaitForNotification(ctx.runtime, key, wait_ms);
}

fn atomicsNotifyCount(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !usize {
    if (args.len < 3 or args[2].isUndefined()) return std.math.maxInt(usize);
    const count_value = try toIntegerValueForAtomics(ctx, output, global, args[2], caller_function, caller_frame);
    defer count_value.free(ctx.runtime);
    const count_number = value_ops.numberValue(count_value) orelse return 0;
    if (std.math.isNan(count_number) or count_number <= 0) return 0;
    if (!std.math.isFinite(count_number)) return std.math.maxInt(usize);
    return @intFromFloat(@min(count_number, @as(f64, @floatFromInt(std.math.maxInt(i32)))));
}

fn atomicsWaitTimeoutMilliseconds(timeout: f64) ?i64 {
    if (std.math.isNan(timeout) or !std.math.isFinite(timeout)) return null;
    if (timeout <= 0) return 0;
    return @intFromFloat(@min(timeout, @as(f64, @floatFromInt(std.math.maxInt(i64)))));
}

fn atomicsWaiterKey(view: *core.Object, bytes: []const u8) !AtomicsWaiterKey {
    const buffer = try atomicsBufferObject(view);
    if (buffer.class_id == core.class.ids.shared_array_buffer) {
        if (buffer.sharedByteStorageStore()) |store| {
            const base = @intFromPtr(buffer.byteStorage().ptr);
            const ptr = @intFromPtr(bytes.ptr);
            return .{ .store = store, .offset_or_ptr = ptr - base };
        }
    }
    return .{ .offset_or_ptr = @intFromPtr(bytes.ptr) };
}

fn atomicsWaiterKeysEqual(a: AtomicsWaiterKey, b: AtomicsWaiterKey) bool {
    return a.store == b.store and a.offset_or_ptr == b.offset_or_ptr;
}

fn atomicsRetainWaiterKey(key: AtomicsWaiterKey) void {
    if (key.store) |store| store.retain();
}

fn atomicsReleaseWaiterKey(key: *AtomicsWaiterKey) void {
    if (key.store) |store| {
        store.release();
        key.store = null;
    }
}

fn atomicsDestroyAsyncWaiter(waiter: *AtomicsWaiter) void {
    const ctx = waiter.ctx.?;
    if (waiter.promise) |promise| promise.free(ctx.runtime);
    atomicsReleaseWaiterKey(&waiter.key);
    ctx.runtime.memory.destroy(AtomicsWaiter, waiter);
}

fn atomicsWakeWaiters(key: AtomicsWaiterKey, count: usize) usize {
    const io = atomicsWaiterIo();
    atomics_waiter_mutex.lockUncancelable(io);
    defer atomics_waiter_mutex.unlock(io);

    var woken: usize = 0;
    var previous: ?*AtomicsWaiter = null;
    var cursor = atomics_waiters;
    while (cursor) |waiter| {
        const next = waiter.next;
        if (!atomicsWaiterKeysEqual(waiter.key, key) or waiter.notified) {
            previous = waiter;
            cursor = next;
            continue;
        }
        waiter.notified = true;
        if (waiter.promise) |promise| {
            atomicsSettleAsyncWaiter(waiter, promise, "ok") catch {};
            if (previous) |prev| {
                prev.next = next;
            } else {
                atomics_waiters = next;
            }
            waiter.linked = false;
            waiter.next = null;
            atomicsDestroyAsyncWaiter(waiter);
        } else {
            waiter.cond.signal(io);
            previous = waiter;
        }
        woken += 1;
        if (woken == count) break;
        cursor = next;
    }
    return woken;
}

fn atomicsSettleAsyncWaiter(waiter: *AtomicsWaiter, promise: core.Value, result: []const u8) !void {
    const ctx = waiter.ctx orelse return;
    const promise_object = objectFromValue(promise) orelse return error.TypeError;
    if (promise_object.class_id != core.class.ids.promise) return error.TypeError;
    if (promise_object.promiseResultSlot().* != null) return;
    const result_value = try value_ops.createStringValue(ctx.runtime, result);
    var result_value_owned = true;
    errdefer if (result_value_owned) result_value.free(ctx.runtime);
    try ctx.ensurePendingPromiseJobCapacity(ctx.pending_promise_jobs.len + 1);
    promise_object.promiseResultSlot().* = result_value;
    result_value_owned = false;
    promise_object.promiseIsRejectedSlot().* = false;
    if (promise_object.promiseReactionCallback() != null and promise_object.promiseReactionArg() == null) {
        promise_object.promiseReactionArgSlot().* = result_value.dup();
    }
    try enqueuePendingPromiseJob(ctx, promise);
}

fn processExpiredAtomicsWaiters(ctx: *core.Context) !void {
    const io = atomicsWaiterIo();
    const now = std.Io.Timestamp.now(io, .awake);
    atomics_waiter_mutex.lockUncancelable(io);
    defer atomics_waiter_mutex.unlock(io);

    var previous: ?*AtomicsWaiter = null;
    var cursor = atomics_waiters;
    while (cursor) |waiter| {
        const next = waiter.next;
        const expired = waiter.ctx == ctx and waiter.promise != null and waiter.deadline != null and now.nanoseconds >= waiter.deadline.?.nanoseconds;
        if (!expired) {
            previous = waiter;
            cursor = next;
            continue;
        }
        try atomicsSettleAsyncWaiter(waiter, waiter.promise.?, "timed-out");
        if (previous) |prev| {
            prev.next = next;
        } else {
            atomics_waiters = next;
        }
        waiter.linked = false;
        waiter.next = null;
        atomicsDestroyAsyncWaiter(waiter);
        cursor = next;
    }
}

pub fn cleanupAtomicsWaitersForContext(ctx: *core.Context) void {
    const io = atomicsWaiterIo();
    atomics_waiter_mutex.lockUncancelable(io);
    defer atomics_waiter_mutex.unlock(io);

    var previous: ?*AtomicsWaiter = null;
    var cursor = atomics_waiters;
    while (cursor) |waiter| {
        const next = waiter.next;
        if (waiter.ctx != ctx) {
            previous = waiter;
            cursor = next;
            continue;
        }
        if (previous) |prev| {
            prev.next = next;
        } else {
            atomics_waiters = next;
        }
        waiter.linked = false;
        waiter.next = null;
        atomicsDestroyAsyncWaiter(waiter);
        cursor = next;
    }
}

fn atomicsWaitForNotification(rt: *core.Runtime, key: AtomicsWaiterKey, timeout_ms: ?i64) !core.Value {
    atomicsRetainWaiterKey(key);
    var retained_key = key;
    defer atomicsReleaseWaiterKey(&retained_key);

    var waiter = AtomicsWaiter{ .key = retained_key };
    const io = atomicsWaiterIo();
    atomics_waiter_mutex.lockUncancelable(io);
    defer atomics_waiter_mutex.unlock(io);
    atomicsLinkWaiter(&waiter);
    defer atomicsUnlinkWaiter(&waiter);

    if (timeout_ms == null) {
        while (!waiter.notified) waiter.cond.waitUncancelable(io, &atomics_waiter_mutex);
        return value_ops.createStringValue(rt, "ok");
    }

    const deadline = std.Io.Timestamp.now(io, .awake).addDuration(std.Io.Duration.fromMilliseconds(timeout_ms.?));
    while (!waiter.notified) {
        const now = std.Io.Timestamp.now(io, .awake);
        if (now.nanoseconds >= deadline.nanoseconds) break;
        atomics_waiter_mutex.unlock(io);
        std.Io.sleep(io, std.Io.Duration.fromMilliseconds(1), .awake) catch {};
        atomics_waiter_mutex.lockUncancelable(io);
    }
    return value_ops.createStringValue(rt, if (waiter.notified) "ok" else "timed-out");
}

fn atomicsLinkWaiter(waiter: *AtomicsWaiter) void {
    waiter.linked = true;
    waiter.next = null;
    if (atomics_waiters == null) {
        atomics_waiters = waiter;
        return;
    }
    var tail = atomics_waiters.?;
    while (tail.next) |next| tail = next;
    tail.next = waiter;
}

fn atomicsUnlinkWaiter(waiter: *AtomicsWaiter) void {
    if (!waiter.linked) return;
    var previous: ?*AtomicsWaiter = null;
    var cursor = atomics_waiters;
    while (cursor) |current| : (cursor = current.next) {
        if (current != waiter) {
            previous = current;
            continue;
        }
        if (previous) |prev| {
            prev.next = current.next;
        } else {
            atomics_waiters = current.next;
        }
        current.next = null;
        current.linked = false;
        return;
    }
}

fn atomicsWaiterIo() std.Io {
    return std.Io.Threaded.global_single_threaded.io();
}

pub fn qjsAtomicsWaitAsync(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const view_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const view = try atomicsTypedArray(view_value, true);
    if ((try atomicsBufferObject(view)).class_id != core.class.ids.shared_array_buffer) return error.TypeError;
    const index_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const index = try atomicsValidateAccess(ctx, output, global, view, index_value, caller_function, caller_frame);
    const expected_arg = if (args.len >= 3) args[2] else core.Value.undefinedValue();
    const expected = if (atomicsTypedArrayIsBigInt(view))
        try toBigIntBitsForAtomics(ctx, output, global, expected_arg, caller_function, caller_frame)
    else
        try toInt32BitsForAtomics(ctx, output, global, expected_arg, caller_function, caller_frame);
    const timeout_arg = if (args.len >= 4) args[3] else core.Value.float64(std.math.nan(f64));
    const timeout = try toNumberForAtomics(ctx, output, global, timeout_arg, caller_function, caller_frame);
    try atomicsValidateIndex(ctx.runtime, view, index);
    const bytes = try atomicsElementBytes(view, index);
    const current = atomicsReadBits(view, bytes);
    if (current != atomicsMaskBits(view, expected)) {
        const result = try value_ops.createStringValue(ctx.runtime, "not-equal");
        defer result.free(ctx.runtime);
        return atomicsWaitAsyncResult(ctx, false, result);
    }
    if (timeout <= 0 and !std.math.isNan(timeout)) {
        const result = try value_ops.createStringValue(ctx.runtime, "timed-out");
        defer result.free(ctx.runtime);
        return atomicsWaitAsyncResult(ctx, false, result);
    }

    const promise = try builtins.promise.constructWithPrototype(ctx.runtime, promisePrototypeFromGlobal(ctx.runtime, global));
    defer promise.free(ctx.runtime);
    if (objectFromValue(promise)) |promise_object| {
        promise_object.promiseAtomicsWaitAsyncSlot().* = true;
    }
    const deadline = if (atomicsWaitTimeoutMilliseconds(timeout)) |timeout_ms|
        std.Io.Timestamp.now(atomicsWaiterIo(), .awake).addDuration(std.Io.Duration.fromMilliseconds(timeout_ms))
    else
        null;
    const waiter = try ctx.runtime.memory.create(AtomicsWaiter);
    const key = try atomicsWaiterKey(view, bytes);
    atomicsRetainWaiterKey(key);
    waiter.* = .{
        .key = key,
        .promise = promise.dup(),
        .ctx = ctx,
        .deadline = deadline,
    };
    atomicsLinkAsyncWaiter(waiter);
    return atomicsWaitAsyncResult(ctx, true, promise);
}

fn atomicsLinkAsyncWaiter(waiter: *AtomicsWaiter) void {
    const io = atomicsWaiterIo();
    atomics_waiter_mutex.lockUncancelable(io);
    defer atomics_waiter_mutex.unlock(io);
    atomicsLinkWaiter(waiter);
}

fn atomicsWaitAsyncResult(ctx: *core.Context, is_async: bool, value: core.Value) !core.Value {
    var rooted_value = value;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_value },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    const result = try core.Object.create(ctx.runtime, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &result.header);
    try defineValueProperty(ctx.runtime, result, "async", core.Value.boolean(is_async));
    try defineValueProperty(ctx.runtime, result, "value", rooted_value);
    return result.value();
}

test "atomicsWaitAsyncResult roots direct function bytecode value while creating result object" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();

    const fb_slice = try rt.memory.alloc(bytecode.FunctionBytecode, 1);
    const fb = &fb_slice[0];
    fb.* = bytecode.FunctionBytecode.init(&rt.memory, &rt.atoms, core.atom.ids.empty_string);
    try rt.gc.add(&fb.header);
    fb.header.destroy_fn = bytecode.function.destroyFunctionBytecode;
    fb.header.destroy_ctx = @ptrCast(rt);

    const symbol_atom = try rt.atoms.newValueSymbol("gc-atomics-wait-async-result-bytecode-symbol");
    fb.cpool = try rt.memory.alloc(core.Value, 1);
    fb.cpool[0] = core.Value.symbol(symbol_atom);
    fb.cpool_count = 1;

    var result_payload = core.Value.functionBytecode(&fb.header);
    var payload_alive = true;
    defer if (payload_alive) result_payload.free(rt);

    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const result_value = try atomicsWaitAsyncResult(ctx, true, result_payload);
    var result_alive = true;
    defer if (result_alive) result_value.free(rt);
    const result = objectFromValue(result_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    const value_key = try rt.internAtom("value");
    defer rt.atoms.free(value_key);
    const stored = result.getProperty(value_key);
    defer stored.free(rt);
    try std.testing.expect(stored.same(result_payload));

    result_value.free(rt);
    result_alive = false;
    result_payload.free(rt);
    payload_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

pub fn atomicsValidateAccess(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    index_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !usize {
    const length = try builtins.buffer.typedArrayLength(ctx.runtime, object);
    const index = try toIndexForAtomics(ctx, output, global, index_value, caller_function, caller_frame);
    if (index >= length) return error.RangeError;
    return index;
}

pub fn atomicsTypedArray(value: core.Value, waitable: bool) !*core.Object {
    const object = property_ops.expectObject(value) catch return error.TypeError;
    if (!builtins.buffer.isTypedArrayObject(object)) return error.TypeError;
    const kind = object.typedArrayKind();
    const ok = if (waitable)
        kind == 6 or kind == 11
    else
        kind == 1 or kind == 2 or kind == 4 or kind == 5 or kind == 6 or kind == 7 or kind == 11 or kind == 12;
    if (!ok) return error.TypeError;
    return object;
}

pub fn atomicsTypedArrayIsBigInt(object: *core.Object) bool {
    return object.typedArrayKind() == 11 or object.typedArrayKind() == 12;
}

pub fn atomicsValidateIndex(rt: *core.Runtime, object: *core.Object, index: usize) !void {
    const length = try builtins.buffer.typedArrayLength(rt, object);
    if (index >= length) return error.RangeError;
}

pub fn atomicsBufferObject(object: *core.Object) !*core.Object {
    const buffer_value = object.typedArrayBuffer() orelse return error.TypeError;
    return property_ops.expectObject(buffer_value);
}

pub fn atomicsElementBytes(object: *core.Object, index: usize) ![]u8 {
    const buffer = try atomicsBufferObject(object);
    if (buffer.arrayBufferDetached()) return error.TypeError;
    const offset = object.typedArrayByteOffset() + index * object.typedArrayElementSize();
    if (offset + object.typedArrayElementSize() > buffer.byteStorage().len) return error.RangeError;
    return buffer.byteStorage()[offset..][0..object.typedArrayElementSize()];
}

pub fn atomicsReadBits(object: *core.Object, bytes: []const u8) u64 {
    return switch (object.typedArrayElementSize()) {
        1 => bytes[0],
        2 => std.mem.readInt(u16, bytes[0..2], .little),
        4 => std.mem.readInt(u32, bytes[0..4], .little),
        8 => std.mem.readInt(u64, bytes[0..8], .little),
        else => 0,
    };
}

pub fn atomicsWriteBits(object: *core.Object, bytes: []u8, value: u64) void {
    switch (object.typedArrayElementSize()) {
        1 => bytes[0] = @truncate(value),
        2 => std.mem.writeInt(u16, bytes[0..2], @truncate(value), .little),
        4 => std.mem.writeInt(u32, bytes[0..4], @truncate(value), .little),
        8 => std.mem.writeInt(u64, bytes[0..8], value, .little),
        else => {},
    }
}

pub fn atomicsMaskBits(object: *core.Object, value: u64) u64 {
    return switch (object.typedArrayElementSize()) {
        1 => value & 0xff,
        2 => value & 0xffff,
        4 => value & 0xffff_ffff,
        else => value,
    };
}

pub fn atomicsValueFromBits(rt: *core.Runtime, object: *core.Object, bits: u64) !core.Value {
    return switch (object.typedArrayKind()) {
        1 => core.Value.int32(@as(i8, @bitCast(@as(u8, @truncate(bits))))),
        2 => core.Value.int32(@as(u8, @truncate(bits))),
        4 => core.Value.int32(@as(i16, @bitCast(@as(u16, @truncate(bits))))),
        5 => core.Value.int32(@as(u16, @truncate(bits))),
        6 => core.Value.int32(@as(i32, @bitCast(@as(u32, @truncate(bits))))),
        7 => atomicsNumberResult(@floatFromInt(@as(u32, @truncate(bits)))),
        11 => value_ops.createBigIntI128(rt, @as(i64, @bitCast(bits))),
        12 => value_ops.createBigIntI128(rt, @as(i128, bits)),
        else => error.TypeError,
    };
}

pub fn toIndexForAtomics(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !usize {
    const number = try toNumberForAtomics(ctx, output, global, value, caller_function, caller_frame);
    if (std.math.isNan(number)) return 0;
    if (!std.math.isFinite(number)) return error.RangeError;
    const truncated = @trunc(number);
    if (truncated < 0) return error.RangeError;
    return @intFromFloat(truncated);
}

pub fn toNumberForAtomics(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !f64 {
    _ = caller_function;
    _ = caller_frame;
    const primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer primitive.free(ctx.runtime);
    if (primitive.isBigInt()) return error.TypeError;
    const number_value = try value_ops.toNumberValue(ctx.runtime, primitive);
    defer number_value.free(ctx.runtime);
    return value_ops.numberValue(number_value) orelse std.math.nan(f64);
}

pub fn toInt32ForAtomics(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !i32 {
    const bits = try toUint32ForAtomics(ctx, output, global, value, caller_function, caller_frame);
    return @bitCast(@as(u32, @truncate(bits)));
}

pub fn toInt32BitsForAtomics(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !u64 {
    const int_value = try toInt32ForAtomics(ctx, output, global, value, caller_function, caller_frame);
    return @as(u32, @bitCast(int_value));
}

pub fn toUint32ForAtomics(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !u64 {
    const number = try toNumberForAtomics(ctx, output, global, value, caller_function, caller_frame);
    if (!std.math.isFinite(number) or std.math.isNan(number)) return 0;
    const two32 = 4294967296.0;
    var modulo = @mod(@trunc(number), two32);
    if (modulo < 0) modulo += two32;
    return @intFromFloat(modulo);
}

pub fn toIntegerValueForAtomics(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const number = try toNumberForAtomics(ctx, output, global, value, caller_function, caller_frame);
    if (std.math.isNan(number) or number == 0) return core.Value.int32(0);
    if (!std.math.isFinite(number)) return core.Value.float64(number);
    return atomicsNumberResult(@trunc(number));
}

pub fn uint32FromIntegerValueForAtomics(rt: *core.Runtime, value: core.Value) !u64 {
    _ = rt;
    const number = value_ops.numberValue(value) orelse return 0;
    if (!std.math.isFinite(number) or std.math.isNan(number)) return 0;
    const two32 = 4294967296.0;
    var modulo = @mod(@trunc(number), two32);
    if (modulo < 0) modulo += two32;
    return @intFromFloat(modulo);
}

pub fn toBigIntValueForAtomics(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    _ = caller_function;
    _ = caller_frame;
    const primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer primitive.free(ctx.runtime);
    var big = try value_ops.toBigIntValue(ctx.runtime, primitive);
    defer big.deinit();
    return value_ops.createBigIntValue(ctx.runtime, big);
}

pub fn toBigIntBitsForAtomics(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !u64 {
    const bigint_value = try toBigIntValueForAtomics(ctx, output, global, value, caller_function, caller_frame);
    defer bigint_value.free(ctx.runtime);
    return bigintBitsForAtomics(ctx.runtime, bigint_value);
}

pub fn atomicsNumberResult(value: f64) core.Value {
    if (std.math.isFinite(value) and @floor(value) == value and value >= @as(f64, @floatFromInt(std.math.minInt(i32))) and value <= @as(f64, @floatFromInt(std.math.maxInt(i32))) and !std.math.isNegativeZero(value)) {
        return core.Value.int32(@intFromFloat(value));
    }
    return core.Value.float64(value);
}

pub fn bigintBitsForAtomics(rt: *core.Runtime, value: core.Value) !u64 {
    var big = try value_ops.toBigIntValue(rt, value);
    defer big.deinit();
    var low: u64 = 0;
    if (big.limbs.len >= 1) low |= big.limbs[0];
    if (big.limbs.len >= 2) low |= @as(u64, big.limbs[1]) << 32;
    return if (big.negative) 0 -% low else low;
}

pub fn qjsUint8ArrayCodecCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    name: []const u8,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (std.mem.eql(u8, name, "fromHex")) {
        var bytes = try uint8ArrayStringBytes(ctx.runtime, if (args.len >= 1) args[0] else core.Value.undefinedValue());
        defer bytes.deinit(ctx.runtime.memory.allocator);
        var decoded = try decodeHexBytes(ctx.runtime, bytes.items, true);
        defer decoded.deinit(ctx.runtime.memory.allocator);
        return try createUint8ArrayFromBytes(ctx.runtime, global, decoded.items);
    }
    if (std.mem.eql(u8, name, "fromBase64")) {
        var bytes = try uint8ArrayStringBytes(ctx.runtime, if (args.len >= 1) args[0] else core.Value.undefinedValue());
        defer bytes.deinit(ctx.runtime.memory.allocator);
        const options = if (args.len >= 2) args[1] else core.Value.undefinedValue();
        const alphabet = try uint8ArrayBase64Alphabet(ctx, output, global, options, caller_function, caller_frame);
        const last_chunk_handling = try uint8ArrayBase64LastChunkHandling(ctx, output, global, options, caller_function, caller_frame);
        var decoded = try decodeBase64Bytes(ctx.runtime, bytes.items, alphabet, last_chunk_handling);
        defer decoded.deinit(ctx.runtime.memory.allocator);
        return try createUint8ArrayFromBytes(ctx.runtime, global, decoded.items);
    }
    if (std.mem.eql(u8, name, "toHex")) {
        const object = try expectUint8ArrayObject(this_value);
        const bytes = try uint8ArrayViewBytes(ctx.runtime, object);
        var encoded = try encodeHexBytes(ctx.runtime, bytes);
        defer encoded.deinit(ctx.runtime.memory.allocator);
        return try value_ops.createStringValue(ctx.runtime, encoded.items);
    }
    if (std.mem.eql(u8, name, "toBase64")) {
        const object = try expectUint8ArrayObject(this_value);
        const options = if (args.len >= 1) args[0] else core.Value.undefinedValue();
        const alphabet = try uint8ArrayBase64Alphabet(ctx, output, global, options, caller_function, caller_frame);
        const omit_padding = try uint8ArrayOmitPadding(ctx, output, global, options, caller_function, caller_frame);
        const bytes = try uint8ArrayViewBytes(ctx.runtime, object);
        var encoded = try encodeBase64Bytes(ctx.runtime, bytes, alphabet, omit_padding);
        defer encoded.deinit(ctx.runtime.memory.allocator);
        return try value_ops.createStringValue(ctx.runtime, encoded.items);
    }
    if (std.mem.eql(u8, name, "setFromHex")) {
        const object = try expectUint8ArrayObject(this_value);
        try builtins.buffer.typedArrayRejectImmutableBuffer(ctx.runtime, object);
        var source = try uint8ArrayStringBytes(ctx.runtime, if (args.len >= 1) args[0] else core.Value.undefinedValue());
        defer source.deinit(ctx.runtime.memory.allocator);
        const target = try uint8ArrayViewBytes(ctx.runtime, object);
        const result = try decodeHexInto(source.items, target);
        return try uint8ArrayCodecResult(ctx.runtime, result.read, result.written);
    }
    if (std.mem.eql(u8, name, "setFromBase64")) {
        const object = try expectUint8ArrayObject(this_value);
        try builtins.buffer.typedArrayRejectImmutableBuffer(ctx.runtime, object);
        var source = try uint8ArrayStringBytes(ctx.runtime, if (args.len >= 1) args[0] else core.Value.undefinedValue());
        defer source.deinit(ctx.runtime.memory.allocator);
        const options = if (args.len >= 2) args[1] else core.Value.undefinedValue();
        const alphabet = try uint8ArrayBase64Alphabet(ctx, output, global, options, caller_function, caller_frame);
        const last_chunk_handling = try uint8ArrayBase64LastChunkHandling(ctx, output, global, options, caller_function, caller_frame);
        const target = try uint8ArrayViewBytes(ctx.runtime, object);
        const result = try decodeBase64Into(ctx.runtime, source.items, alphabet, last_chunk_handling, target);
        return try uint8ArrayCodecResult(ctx.runtime, result.read, result.written);
    }
    return null;
}

pub const Uint8ArrayBase64Alphabet = enum { base64, base64url };
pub const Uint8ArrayBase64LastChunkHandling = enum { loose, strict, stop_before_partial };
const Uint8ArrayCodecProgress = struct { read: usize, written: usize };

pub fn expectUint8ArrayObject(value: core.Value) !*core.Object {
    const object = property_ops.expectObject(value) catch return error.TypeError;
    if (!builtins.buffer.isTypedArrayObject(object) or object.typedArrayKind() != 2) return error.TypeError;
    return object;
}

pub fn uint8ArrayStringBytes(rt: *core.Runtime, value: core.Value) !std.ArrayList(u8) {
    if (!value.isString()) return error.TypeError;
    var bytes = std.ArrayList(u8).empty;
    errdefer bytes.deinit(rt.memory.allocator);
    try value_ops.appendRawString(rt, &bytes, value);
    return bytes;
}

pub fn uint8ArrayBase64Alphabet(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    options: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !Uint8ArrayBase64Alphabet {
    const rt = ctx.runtime;
    if (!options.isObject()) return .base64;
    const key = try rt.internAtom("alphabet");
    defer rt.atoms.free(key);
    const value = try getValueProperty(ctx, output, global, options, key, caller_function, caller_frame);
    defer value.free(rt);
    if (value.isUndefined()) return .base64;
    var text = try uint8ArrayStringBytes(rt, value);
    defer text.deinit(rt.memory.allocator);
    if (std.mem.eql(u8, text.items, "base64")) return .base64;
    if (std.mem.eql(u8, text.items, "base64url")) return .base64url;
    return error.TypeError;
}

pub fn uint8ArrayBase64LastChunkHandling(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    options: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !Uint8ArrayBase64LastChunkHandling {
    const rt = ctx.runtime;
    if (!options.isObject()) return .loose;
    const key = try rt.internAtom("lastChunkHandling");
    defer rt.atoms.free(key);
    const value = try getValueProperty(ctx, output, global, options, key, caller_function, caller_frame);
    defer value.free(rt);
    if (value.isUndefined()) return .loose;
    var text = try uint8ArrayStringBytes(rt, value);
    defer text.deinit(rt.memory.allocator);
    if (std.mem.eql(u8, text.items, "loose")) return .loose;
    if (std.mem.eql(u8, text.items, "strict")) return .strict;
    if (std.mem.eql(u8, text.items, "stop-before-partial")) return .stop_before_partial;
    return error.TypeError;
}

pub fn uint8ArrayOmitPadding(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    options: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    const rt = ctx.runtime;
    if (!options.isObject()) return false;
    const key = try rt.internAtom("omitPadding");
    defer rt.atoms.free(key);
    const value = try getValueProperty(ctx, output, global, options, key, caller_function, caller_frame);
    defer value.free(rt);
    return valueTruthy(value);
}

pub fn createUint8ArrayFromBytes(rt: *core.Runtime, global: *core.Object, bytes: []const u8) !core.Value {
    const buffer_proto = constructorPrototypeFromGlobalAtom(rt, global, core.atom.predefinedId("ArrayBuffer", .string).?);
    const buffer_value = try builtins.buffer.arrayBufferConstructLength(rt, bytes.len, null, buffer_proto);
    var buffer_owned = true;
    errdefer if (buffer_owned) buffer_value.free(rt);
    const buffer = try property_ops.expectObject(buffer_value);
    if (bytes.len != 0) @memcpy(buffer.byteStorage()[0..bytes.len], bytes);
    const proto = try uint8ArrayConstructorPrototypeObject(rt, global, "Uint8Array");
    buffer_owned = false;
    return try builtins.buffer.typedArrayConstructFullBufferOwned(rt, 1, 2, buffer_value, buffer, proto);
}

pub fn uint8ArrayConstructorPrototypeObject(rt: *core.Runtime, global: *core.Object, name: []const u8) !?*core.Object {
    const key = try rt.internAtom(name);
    defer rt.atoms.free(key);
    const ctor_value = global.getProperty(key);
    defer ctor_value.free(rt);
    const ctor = property_ops.expectObject(ctor_value) catch return null;
    const proto_value = ctor.getProperty(core.atom.ids.prototype);
    defer proto_value.free(rt);
    return property_ops.expectObject(proto_value) catch null;
}

pub fn uint8ArrayViewBytes(rt: *core.Runtime, object: *core.Object) ![]u8 {
    const length = try builtins.buffer.typedArrayLength(rt, object);
    const buffer = try atomicsBufferObject(object);
    if (buffer.arrayBufferDetached()) return error.TypeError;
    const start = object.typedArrayByteOffset();
    return buffer.byteStorage()[start..][0..length];
}

pub fn writeUint8ArrayPrefix(rt: *core.Runtime, object: *core.Object, bytes: []const u8) !usize {
    const target = try uint8ArrayViewBytes(rt, object);
    const count = @min(target.len, bytes.len);
    if (count != 0) @memcpy(target[0..count], bytes[0..count]);
    return count;
}

pub fn uint8ArrayCodecResult(rt: *core.Runtime, read: usize, written: usize) !core.Value {
    const object = try core.Object.create(rt, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(rt, &object.header);
    try defineValueProperty(rt, object, "read", core.Value.int32(@intCast(read)));
    try defineValueProperty(rt, object, "written", core.Value.int32(@intCast(written)));
    return object.value();
}

pub fn decodeHexBytes(rt: *core.Runtime, source: []const u8, reject_odd: bool) !std.ArrayList(u8) {
    if (reject_odd and source.len % 2 != 0) return error.SyntaxError;
    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(rt.memory.allocator);
    var index: usize = 0;
    while (index + 1 < source.len) : (index += 2) {
        const hi = hexNibble(source[index]) orelse return error.SyntaxError;
        const lo = hexNibble(source[index + 1]) orelse return error.SyntaxError;
        try out.append(rt.memory.allocator, (hi << 4) | lo);
    }
    return out;
}

pub fn decodeHexInto(source: []const u8, target: []u8) !Uint8ArrayCodecProgress {
    if (source.len % 2 != 0) return error.SyntaxError;
    var read: usize = 0;
    var written: usize = 0;
    while (read < source.len and written < target.len) {
        const hi = hexNibble(source[read]) orelse return error.SyntaxError;
        const lo = hexNibble(source[read + 1]) orelse return error.SyntaxError;
        target[written] = (hi << 4) | lo;
        read += 2;
        written += 1;
    }
    return .{ .read = read, .written = written };
}

pub fn encodeHexBytes(rt: *core.Runtime, bytes: []const u8) !std.ArrayList(u8) {
    const alphabet = "0123456789abcdef";
    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(rt.memory.allocator);
    for (bytes) |byte| {
        try out.append(rt.memory.allocator, alphabet[byte >> 4]);
        try out.append(rt.memory.allocator, alphabet[byte & 0x0f]);
    }
    return out;
}

pub fn hexNibble(byte: u8) ?u8 {
    if (byte >= '0' and byte <= '9') return byte - '0';
    if (byte >= 'a' and byte <= 'f') return byte - 'a' + 10;
    if (byte >= 'A' and byte <= 'F') return byte - 'A' + 10;
    return null;
}

const Base64Chunk = struct {
    bytes: [3]u8 = .{ 0, 0, 0 },
    len: usize = 0,
};

pub fn decodeBase64Bytes(
    rt: *core.Runtime,
    source: []const u8,
    alphabet: Uint8ArrayBase64Alphabet,
    last_chunk_handling: Uint8ArrayBase64LastChunkHandling,
) !std.ArrayList(u8) {
    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(rt.memory.allocator);
    _ = try decodeBase64Internal(rt, source, alphabet, last_chunk_handling, &out, null);
    return out;
}

pub fn decodeBase64Into(
    rt: *core.Runtime,
    source: []const u8,
    alphabet: Uint8ArrayBase64Alphabet,
    last_chunk_handling: Uint8ArrayBase64LastChunkHandling,
    target: []u8,
) !Uint8ArrayCodecProgress {
    if (target.len == 0) return .{ .read = 0, .written = 0 };
    return decodeBase64Internal(rt, source, alphabet, last_chunk_handling, null, target);
}

fn decodeBase64Internal(
    rt: *core.Runtime,
    source: []const u8,
    alphabet: Uint8ArrayBase64Alphabet,
    last_chunk_handling: Uint8ArrayBase64LastChunkHandling,
    out: ?*std.ArrayList(u8),
    target: ?[]u8,
) !Uint8ArrayCodecProgress {
    var chunk: [4]u8 = .{ 0, 0, 0, 0 };
    var chunk_len: usize = 0;
    var read_pos: usize = 0;
    var last_read: usize = 0;
    var written: usize = 0;
    var saw_padded_chunk = false;
    var pending_padded_chunk: ?Base64Chunk = null;
    var pending_padded_read: usize = 0;

    for (source, 0..) |byte, index| {
        if (isAsciiWhitespace(byte)) continue;
        read_pos = index + 1;
        if (saw_padded_chunk) return error.SyntaxError;
        if (byte != '=' and base64Value(byte, alphabet) == null) return error.SyntaxError;
        chunk[chunk_len] = byte;
        chunk_len += 1;
        if (chunk_len == 4) {
            const decoded = try decodeBase64Chunk(chunk, 4, alphabet, last_chunk_handling, false);
            if (chunk[2] == '=' or chunk[3] == '=') {
                pending_padded_chunk = decoded;
                pending_padded_read = read_pos;
                saw_padded_chunk = true;
                chunk_len = 0;
                continue;
            }
            if (target) |bytes| {
                if (decoded.len > bytes.len - written) return .{ .read = last_read, .written = written };
                if (decoded.len != 0) @memcpy(bytes[written..][0..decoded.len], decoded.bytes[0..decoded.len]);
            } else if (out) |list| {
                try list.appendSlice(rt.memory.allocator, decoded.bytes[0..decoded.len]);
            }
            written += decoded.len;
            last_read = read_pos;
            chunk_len = 0;
            if (target) |bytes| {
                if (written == bytes.len) return .{ .read = last_read, .written = written };
            }
        }
    }

    if (pending_padded_chunk) |decoded| {
        if (target) |bytes| {
            if (decoded.len > bytes.len - written) return .{ .read = last_read, .written = written };
            if (decoded.len != 0) @memcpy(bytes[written..][0..decoded.len], decoded.bytes[0..decoded.len]);
        } else if (out) |list| {
            try list.appendSlice(rt.memory.allocator, decoded.bytes[0..decoded.len]);
        }
        written += decoded.len;
        return .{ .read = pending_padded_read, .written = written };
    }
    if (chunk_len == 0) return .{ .read = last_read, .written = written };
    const decoded = try decodeBase64Chunk(chunk, chunk_len, alphabet, last_chunk_handling, true);
    if (decoded.len == 0 and last_chunk_handling == .stop_before_partial) return .{ .read = last_read, .written = written };
    if (target) |bytes| {
        if (decoded.len > bytes.len - written) return .{ .read = last_read, .written = written };
        if (decoded.len != 0) @memcpy(bytes[written..][0..decoded.len], decoded.bytes[0..decoded.len]);
    } else if (out) |list| {
        try list.appendSlice(rt.memory.allocator, decoded.bytes[0..decoded.len]);
    }
    written += decoded.len;
    return .{ .read = read_pos, .written = written };
}

fn decodeBase64Chunk(
    chunk: [4]u8,
    chunk_len: usize,
    alphabet: Uint8ArrayBase64Alphabet,
    last_chunk_handling: Uint8ArrayBase64LastChunkHandling,
    is_final: bool,
) !Base64Chunk {
    if (chunk_len == 0) return .{};
    if (chunk_len < 4) {
        var first_padding: ?usize = null;
        var i: usize = 0;
        while (i < chunk_len) : (i += 1) {
            if (chunk[i] == '=') {
                if (first_padding == null) first_padding = i;
            } else if (first_padding != null) {
                return error.SyntaxError;
            }
        }
        if (first_padding) |padding_index| {
            if (padding_index < 2) return error.SyntaxError;
            if (last_chunk_handling == .stop_before_partial and is_final) return .{};
            return error.SyntaxError;
        }
        if (chunk_len == 1) {
            if (last_chunk_handling == .stop_before_partial and is_final) return .{};
            return error.SyntaxError;
        }
        if (last_chunk_handling == .stop_before_partial and is_final) return .{};
        if (last_chunk_handling == .strict) return error.SyntaxError;
        const a = base64Value(chunk[0], alphabet) orelse return error.SyntaxError;
        const b = base64Value(chunk[1], alphabet) orelse return error.SyntaxError;
        var result = Base64Chunk{ .bytes = .{ (a << 2) | (b >> 4), 0, 0 }, .len = 1 };
        if (chunk_len == 3) {
            const c = base64Value(chunk[2], alphabet) orelse return error.SyntaxError;
            result.bytes[1] = ((b & 0x0f) << 4) | (c >> 2);
            result.len = 2;
        }
        return result;
    }

    if (chunk[0] == '=' or chunk[1] == '=') return error.SyntaxError;
    const a = base64Value(chunk[0], alphabet) orelse return error.SyntaxError;
    const b = base64Value(chunk[1], alphabet) orelse return error.SyntaxError;
    if (chunk[2] == '=') {
        if (chunk[3] != '=') return error.SyntaxError;
        if (last_chunk_handling == .strict and (b & 0x0f) != 0) return error.SyntaxError;
        return .{ .bytes = .{ (a << 2) | (b >> 4), 0, 0 }, .len = 1 };
    }
    const c = base64Value(chunk[2], alphabet) orelse return error.SyntaxError;
    if (chunk[3] == '=') {
        if (last_chunk_handling == .strict and (c & 0x03) != 0) return error.SyntaxError;
        return .{ .bytes = .{ (a << 2) | (b >> 4), ((b & 0x0f) << 4) | (c >> 2), 0 }, .len = 2 };
    }
    const d = base64Value(chunk[3], alphabet) orelse return error.SyntaxError;
    return .{ .bytes = .{ (a << 2) | (b >> 4), ((b & 0x0f) << 4) | (c >> 2), ((c & 0x03) << 6) | d }, .len = 3 };
}

pub fn encodeBase64Bytes(rt: *core.Runtime, bytes: []const u8, alphabet: Uint8ArrayBase64Alphabet, omit_padding: bool) !std.ArrayList(u8) {
    const table = if (alphabet == .base64) "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/" else "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";
    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(rt.memory.allocator);
    var index: usize = 0;
    while (index < bytes.len) : (index += 3) {
        const rem = bytes.len - index;
        const b0 = bytes[index];
        const b1 = if (rem > 1) bytes[index + 1] else 0;
        const b2 = if (rem > 2) bytes[index + 2] else 0;
        try out.append(rt.memory.allocator, table[b0 >> 2]);
        try out.append(rt.memory.allocator, table[((b0 & 0x03) << 4) | (b1 >> 4)]);
        if (rem > 1) {
            try out.append(rt.memory.allocator, table[((b1 & 0x0f) << 2) | (b2 >> 6)]);
        } else if (!omit_padding) {
            try out.append(rt.memory.allocator, '=');
        }
        if (rem > 2) {
            try out.append(rt.memory.allocator, table[b2 & 0x3f]);
        } else if (!omit_padding) {
            try out.append(rt.memory.allocator, '=');
        }
    }
    return out;
}

pub fn base64Value(byte: u8, alphabet: Uint8ArrayBase64Alphabet) ?u8 {
    if (byte >= 'A' and byte <= 'Z') return byte - 'A';
    if (byte >= 'a' and byte <= 'z') return byte - 'a' + 26;
    if (byte >= '0' and byte <= '9') return byte - '0' + 52;
    if (alphabet == .base64 and byte == '+') return 62;
    if (alphabet == .base64 and byte == '/') return 63;
    if (alphabet == .base64url and byte == '-') return 62;
    if (alphabet == .base64url and byte == '_') return 63;
    return null;
}

pub fn isAsciiWhitespace(byte: u8) bool {
    return byte == ' ' or byte == '\t' or byte == '\n' or byte == '\r' or byte == 0x0b or byte == 0x0c;
}

pub fn isTypedArrayPrototypeMethod(rt: *core.Runtime, function_object: *core.Object) bool {
    _ = rt;
    return function_object.typedArrayBuiltinMarker() == .prototype_method;
}

pub fn typedArrayStaticMethodId(rt: *core.Runtime, function_object: *core.Object) ?i32 {
    _ = rt;
    return switch (function_object.typedArrayBuiltinMarker()) {
        .static_from => 1,
        .static_of => 2,
        else => null,
    };
}

pub fn isIteratorIdentityFunction(rt: *core.Runtime, function_object: *core.Object) bool {
    _ = rt;
    return function_object.isIteratorIdentityFunction();
}

pub fn importMetaObject(
    ctx: *core.Context,
    global: *core.Object,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
) !core.Value {
    _ = global;
    if (objectFromValue(frame.current_function)) |function_object| {
        if (function_object.functionImportMeta()) |value| return value.dup();
    }

    if (!function.flags.is_module) return error.SyntaxError;
    const record = ctx.runtime.modules.find(function.name) orelse return error.ModuleNotFound;
    if (record.import_meta) |value| return value.dup();

    const object = try core.Object.create(ctx.runtime, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
    const url = try importMetaUrlValue(ctx.runtime, record);
    defer url.free(ctx.runtime);
    try defineValueProperty(ctx.runtime, object, "url", url);
    try defineValueProperty(ctx.runtime, object, "main", core.Value.boolean(record.import_meta_main));
    const value = object.value();
    record.import_meta = value.dup();
    return value;
}

fn importMetaUrlValue(rt: *core.Runtime, record: *core.module.ModuleRecord) !core.Value {
    const name = rt.atoms.name(record.module_name) orelse "";
    if (std.mem.startsWith(u8, name, "/") or std.mem.indexOfScalar(u8, name, '/') != null) {
        const path = if (std.mem.startsWith(u8, name, "/"))
            try rt.memory.allocator.dupe(u8, name)
        else
            try std.fs.path.resolve(rt.memory.allocator, &.{name});
        defer rt.memory.allocator.free(path);
        const url = try std.fmt.allocPrint(rt.memory.allocator, "file://{s}", .{path});
        defer rt.memory.allocator.free(url);
        return value_ops.createStringValue(rt, url);
    }
    return value_ops.createStringValue(rt, name);
}

pub fn globalLexicalEnv(rt: *core.Runtime, global: *core.Object) !*core.Object {
    if (global.global_lexical_env) |env| return env;
    const env = try core.Object.create(rt, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(rt, &env.header);
    errdefer {
        if (global.global_lexical_env == env) global.global_lexical_env = null;
    }
    global.global_lexical_env = env;
    return env;
}

pub fn existingGlobalLexicalEnv(rt: *core.Runtime, global: *core.Object) ?*core.Object {
    if (global.global_lexical_env) |env| return env;
    _ = rt;
    return null;
}

pub fn globalLexicalHas(rt: *core.Runtime, global: *core.Object, atom_id: core.Atom) bool {
    const env = existingGlobalLexicalEnv(rt, global) orelse return false;
    return env.hasOwnProperty(atom_id);
}

pub fn globalLexicalValue(rt: *core.Runtime, global: *core.Object, atom_id: core.Atom) ?core.Value {
    const env = existingGlobalLexicalEnv(rt, global) orelse return null;
    if (env.getOwnDataPropertyValue(atom_id)) |value| return value;
    if (!env.hasOwnProperty(atom_id)) return null;
    return env.getProperty(atom_id);
}

pub fn defineGlobalLexicalValue(rt: *core.Runtime, global: *core.Object, atom_id: core.Atom, value: core.Value, is_const: bool) !void {
    const env = try globalLexicalEnv(rt, global);
    if (!env.hasOwnProperty(atom_id)) {
        try env.defineOwnPropertyAssumingNew(rt, atom_id, core.Descriptor.data(value, !is_const, false, false));
    }
}

pub fn setGlobalLexicalValue(rt: *core.Runtime, global: *core.Object, atom_id: core.Atom, value: core.Value) !bool {
    const env = existingGlobalLexicalEnv(rt, global) orelse return false;
    if (!env.hasOwnProperty(atom_id)) return false;
    if (initializeGlobalLexicalValue(rt, env, atom_id, value)) return true;
    if (try env.setOwnWritableDataProperty(rt, atom_id, value)) return true;
    env.setProperty(rt, atom_id, value) catch |err| switch (err) {
        error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
        else => return err,
    };
    return true;
}

pub fn initializeGlobalLexicalValue(rt: *core.Runtime, env: *core.Object, atom_id: core.Atom, value: core.Value) bool {
    for (env.properties) |*entry| {
        if (entry.atom_id == core.atom.null_atom) continue;
        if (!atomIdOrNameEql(rt, entry.atom_id, atom_id)) continue;
        switch (entry.slot) {
            .data => |*stored| {
                if (!stored.isUninitialized()) return false;
                const next = value.dup();
                const old_value = stored.*;
                stored.* = next;
                old_value.free(rt);
                return true;
            },
            else => return false,
        }
    }
    return false;
}

pub fn withObjectBindingValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    with_object_value: core.Value,
    atom_id: core.Atom,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
) !?core.Value {
    if (with_object_value.isUndefined()) return null;
    _ = property_ops.expectObject(with_object_value) catch return null;
    const has_binding = try hasPropertyForWith(ctx, output, global, with_object_value, atom_id, function, frame);
    if (!has_binding) return null;
    if (try isBlockedByUnscopables(ctx, output, global, with_object_value, atom_id, function, frame)) return null;
    return try getValueProperty(ctx, output, global, with_object_value, atom_id, function, frame);
}

pub fn directEvalWithObject(
    rt: *core.Runtime,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) core.Value {
    const function = caller_function orelse return core.Value.undefinedValue();
    const frame = caller_frame orelse return core.Value.undefinedValue();
    const count = @min(function.var_names.len, frame.locals.len);
    var idx = count;
    while (idx > 0) {
        idx -= 1;
        const name = rt.atoms.name(function.var_names[idx]) orelse continue;
        if (!std.mem.startsWith(u8, name, "__active_with_obj_")) continue;
        const value = slotValueDup(frame.locals[idx]);
        if (objectFromValue(value) != null) return value;
        value.free(rt);
    }
    return core.Value.undefinedValue();
}

pub fn directEval(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
    eval_in_class_field_initializer: bool,
    eval_in_parameter_initializer: bool,
) !core.Value {
    if (args.len == 0) return core.Value.undefinedValue();
    if (!args[0].isString()) return args[0].dup();
    var source = std.ArrayList(u8).empty;
    defer source.deinit(ctx.runtime.memory.allocator);
    try appendSourceStringUtf8(ctx.runtime, &source, args[0]);
    if (try simpleEvalRegExpLiteral(ctx, global, source.items)) |value| return value;
    if (try evalSimpleCallerExpression(ctx, source.items, caller_function, caller_frame)) |value| return value;
    const caller_strict = if (caller_function) |outer_function| outer_function.flags.is_strict else false;
    if (caller_function) |outer_function| {
        if (!outer_function.flags.has_simple_parameter_list) {
            if (simpleVarDeclarationName(source.items)) |name| {
                const caller_has_arguments_binding = if (caller_frame) |outer_frame|
                    directEvalShouldExposeImplicitArguments(outer_frame)
                else
                    false;
                if ((std.mem.eql(u8, name, "arguments") and caller_has_arguments_binding) or
                    callerFunctionHasArg(ctx.runtime, outer_function, name))
                {
                    return error.SyntaxError;
                }
            }
        }
        if (!caller_strict) if (simpleVarDeclarationName(source.items)) |name| {
            if (!eval_in_parameter_initializer and callerFunctionHasLexicalLocal(ctx.runtime, outer_function, name)) return error.SyntaxError;
        };
    }
    const eval_global_var_bindings = if (caller_frame) |outer_frame|
        outer_frame.current_function.isUndefined()
    else
        true;
    const eval_allows_new_target = directEvalCallerAllowsNewTarget(caller_frame, eval_in_class_field_initializer);
    const eval_allows_super_property = directEvalCallerAllowsSuperProperty(caller_frame, eval_in_class_field_initializer);
    const eval_class_static_field_this_atom = classStaticThisAtom(ctx.runtime, caller_function, caller_frame);
    const eval_private_bound_names = try directEvalPrivateBoundNames(ctx.runtime, caller_function, caller_frame);
    defer if (eval_private_bound_names.len != 0) ctx.runtime.memory.free(core.Atom, eval_private_bound_names);
    var compiled = try frontend.parser.parse(ctx.runtime, source.items, .{
        .mode = .eval_direct,
        .filename = "<eval>",
        .strict = caller_strict,
        .eval_global_var_bindings = eval_global_var_bindings,
        .eval_in_class_field_initializer = eval_in_class_field_initializer,
        .eval_allows_new_target = eval_allows_new_target,
        .eval_allows_super_property = eval_allows_super_property,
        .eval_class_static_field_this_atom = eval_class_static_field_this_atom,
        .eval_private_bound_names = eval_private_bound_names,
    });
    defer compiled.deinit();
    if (compiled.syntax_error != null) return error.SyntaxError;
    const eval_strict = compiled.function.flags.is_strict;
    if (eval_global_var_bindings and !eval_strict) {
        try validateGlobalEvalFunctionDeclarations(ctx, global, source.items, false);
    }
    var nested_stack = stack_mod.Stack.init(&ctx.runtime.memory, ctx.runtime.stack_size);
    defer nested_stack.deinit(ctx.runtime);
    var empty_locals: [0]core.Value = .{};
    const inherited_local_names = if (caller_frame) |outer_frame| outer_frame.eval_local_names else &.{};
    const inherited_locals = if (caller_frame) |outer_frame| outer_frame.eval_local_slots else empty_locals[0..];
    const inherited_ref_names = if (caller_frame) |outer_frame| outer_frame.eval_var_ref_names else &.{};
    const inherited_refs = if (caller_frame) |outer_frame| outer_frame.eval_var_refs else &.{};
    const outer_refs = if (caller_frame) |outer_frame| outer_frame.var_refs else &.{};
    const outer_names = if (caller_function) |outer_function| outer_function.var_ref_names else &.{};
    const base_outer_local_names = if (caller_function) |outer_function| outer_function.var_names else &.{};
    const base_outer_locals = if (caller_frame) |outer_frame| outer_frame.locals else empty_locals[0..];
    var direct_eval_local_names: []core.Atom = &.{};
    var direct_eval_local_slots: []core.Value = &.{};
    defer freeAtomSlice(ctx.runtime, direct_eval_local_names);
    defer freeValueSlice(ctx.runtime, direct_eval_local_slots);
    if (caller_function) |outer_function| {
        if (caller_frame) |outer_frame| {
            const bindings = try createDirectEvalVisibleLocalBindings(ctx, global, outer_function, outer_frame, eval_in_parameter_initializer, eval_global_var_bindings);
            direct_eval_local_names = bindings.names;
            direct_eval_local_slots = bindings.slots;
        }
    }
    const outer_local_names = if (direct_eval_local_names.len != 0) direct_eval_local_names else if (eval_global_var_bindings) &.{} else base_outer_local_names;
    const outer_locals = if (direct_eval_local_names.len != 0) direct_eval_local_slots else if (eval_global_var_bindings) empty_locals[0..] else base_outer_locals;
    var eval_function_names: []core.Atom = &.{};
    if (!eval_strict) {
        if (try evalFunctionDeclarationNames(ctx.runtime, source.items)) |names| {
            eval_function_names = names;
        }
    }
    defer freeAtomSlice(ctx.runtime, eval_function_names);
    var eval_var_names: []core.Atom = &.{};
    if (!eval_strict) {
        eval_var_names = try directEvalVarDeclarationNames(ctx.runtime, global, &compiled.function, source.items, caller_function, eval_function_names, eval_global_var_bindings);
    }
    defer if (!eval_strict) freeAtomSlice(ctx.runtime, eval_var_names);
    const eval_var_refs = try createDirectEvalVarRefCells(ctx, eval_var_names, caller_function, caller_frame, eval_in_parameter_initializer);
    defer freeValueSlice(ctx.runtime, eval_var_refs);
    var combined_eval_local_names: []core.Atom = &.{};
    var combined_eval_local_slots: []core.Value = &.{};
    defer freeAtomSlice(ctx.runtime, combined_eval_local_names);
    defer freeValueSlice(ctx.runtime, combined_eval_local_slots);
    if (eval_var_names.len != 0) {
        const outer_count = @min(outer_local_names.len, outer_locals.len);
        const eval_count = @min(eval_var_names.len, eval_var_refs.len);
        if (outer_count + eval_count != 0) {
            combined_eval_local_names = try ctx.runtime.memory.alloc(core.Atom, outer_count + eval_count);
            errdefer {
                ctx.runtime.memory.free(core.Atom, combined_eval_local_names);
                combined_eval_local_names = &.{};
            }
            combined_eval_local_slots = try ctx.runtime.memory.alloc(core.Value, outer_count + eval_count);
            errdefer {
                ctx.runtime.memory.free(core.Value, combined_eval_local_slots);
                combined_eval_local_slots = &.{};
            }
            var combined_idx: usize = 0;
            errdefer {
                for (combined_eval_local_names[0..combined_idx]) |atom_id| ctx.runtime.atoms.free(atom_id);
                for (combined_eval_local_slots[0..combined_idx]) |value| value.free(ctx.runtime);
            }
            for (outer_local_names[0..outer_count], 0..) |atom_id, idx| {
                combined_eval_local_names[combined_idx] = ctx.runtime.atoms.dup(atom_id);
                combined_eval_local_slots[combined_idx] = outer_locals[idx].dup();
                combined_idx += 1;
            }
            for (eval_var_names[0..eval_count], 0..) |atom_id, idx| {
                combined_eval_local_names[combined_idx] = ctx.runtime.atoms.dup(atom_id);
                combined_eval_local_slots[combined_idx] = eval_var_refs[idx].dup();
                combined_idx += 1;
            }
        }
    }
    const run_eval_local_names = if (combined_eval_local_names.len != 0) combined_eval_local_names else outer_local_names;
    const run_eval_local_slots = if (combined_eval_local_names.len != 0) combined_eval_local_slots else outer_locals;
    const eval_this = directEvalThisValue(ctx.runtime, caller_function, caller_frame);
    const eval_new_target = if (eval_allows_new_target) blk: {
        if (caller_frame) |outer_frame| break :blk outer_frame.new_target;
        break :blk core.Value.undefinedValue();
    } else core.Value.undefinedValue();
    const eval_current_function = blk: {
        if (caller_frame) |outer_frame| break :blk outer_frame.current_function;
        break :blk core.Value.undefinedValue();
    };
    const eval_with_object = directEvalWithObject(ctx.runtime, caller_function, caller_frame);
    defer eval_with_object.free(ctx.runtime);
    const result = try runWithArgsState(ctx, &nested_stack, &compiled.function, eval_this, &.{}, eval_var_refs, output, global, false, eval_strict, false, run_eval_local_names, run_eval_local_slots, outer_names, outer_refs, inherited_local_names, inherited_locals, inherited_ref_names, inherited_refs, null, null, null, eval_current_function, eval_new_target, core.Value.undefinedValue(), eval_global_var_bindings, true, eval_with_object, false, false);
    errdefer result.free(ctx.runtime);
    try publishDirectEvalVarRefs(ctx, global, caller_frame, eval_var_names, eval_var_refs, eval_in_parameter_initializer, eval_global_var_bindings);
    return result;
}

pub fn validateGlobalEvalFunctionDeclarations(
    ctx: *core.Context,
    global: *core.Object,
    source: []const u8,
    ignore_global_lexical: bool,
) !void {
    var search_start: usize = 0;
    while (std.mem.indexOf(u8, source[search_start..], "function")) |rel| {
        const keyword_index = search_start + rel;
        if (!looksLikeStatementFunctionKeyword(source, keyword_index)) {
            search_start = keyword_index + "function".len;
            continue;
        }
        var cursor = skipAsciiWhitespace(source, keyword_index + "function".len);
        if (cursor < source.len and source[cursor] == '*') {
            cursor = skipAsciiWhitespace(source, cursor + 1);
        }
        if (cursor >= source.len or !isIdentifierStartByte(source[cursor])) {
            search_start = keyword_index + "function".len;
            continue;
        }
        const name_start = cursor;
        cursor += 1;
        while (cursor < source.len and isIdentifierPartByte(source[cursor])) : (cursor += 1) {}
        const atom_id = try ctx.runtime.internAtom(source[name_start..cursor]);
        defer ctx.runtime.atoms.free(atom_id);
        if (!canDeclareGlobalFunction(ctx.runtime, global, atom_id, ignore_global_lexical)) return error.TypeError;
        search_start = cursor;
    }
}

pub fn looksLikeStatementFunctionKeyword(source: []const u8, keyword_index: usize) bool {
    if (keyword_index > 0 and isIdentifierPartByte(source[keyword_index - 1])) return false;
    const after = keyword_index + "function".len;
    if (after < source.len and isIdentifierPartByte(source[after])) return false;
    if (keyword_index == 0) return true;
    var cursor = keyword_index;
    while (cursor > 0) {
        cursor -= 1;
        const ch = source[cursor];
        if (std.ascii.isWhitespace(ch)) continue;
        return ch == ';' or ch == '{' or ch == '}';
    }
    return true;
}

pub fn canDeclareGlobalFunction(rt: *core.Runtime, global: *core.Object, atom_id: core.Atom, ignore_global_lexical: bool) bool {
    if (!ignore_global_lexical and globalLexicalHas(rt, global, atom_id)) return false;
    const desc = global.getOwnProperty(atom_id) orelse return global.isExtensible();
    defer desc.destroy(rt);
    if (desc.configurable == true) return true;
    if (desc.kind != .data) return false;
    return desc.writable == true and desc.enumerable == true;
}

pub fn isIdentifierStartByte(ch: u8) bool {
    return std.ascii.isAlphabetic(ch) or ch == '_' or ch == '$';
}

pub fn isIdentifierPartByte(ch: u8) bool {
    return std.ascii.isAlphanumeric(ch) or ch == '_' or ch == '$';
}

pub fn directEvalThisValue(
    rt: *core.Runtime,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) core.Value {
    const outer_frame = caller_frame orelse return core.Value.undefinedValue();
    if (classStaticThisAtom(rt, caller_function, caller_frame)) |atom_id| {
        if (classStaticThisValue(caller_function, outer_frame, atom_id)) |value| return value;
    }
    return outer_frame.this_value;
}

pub fn classStaticThisAtom(
    rt: *core.Runtime,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) ?core.Atom {
    const function = caller_function orelse return null;
    const frame = caller_frame orelse return null;
    const count = @min(function.var_names.len, frame.locals.len);
    var idx = count;
    while (idx > 0) {
        idx -= 1;
        const atom_id = function.var_names[idx];
        const name = rt.atoms.name(atom_id) orelse continue;
        if (!std.mem.startsWith(u8, name, "__class_static_this_")) continue;
        if (frame.locals[idx].isUninitialized()) continue;
        return atom_id;
    }
    return null;
}

pub fn classStaticThisValue(
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: *frame_mod.Frame,
    atom_id: core.Atom,
) ?core.Value {
    const function = caller_function orelse return null;
    const count = @min(function.var_names.len, caller_frame.locals.len);
    for (function.var_names[0..count], 0..) |name, idx| {
        if (name != atom_id) continue;
        const value = caller_frame.locals[idx];
        if (value.isUninitialized()) continue;
        return value;
    }
    return null;
}

test "direct eval private bound names release preserves memory account" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const function_name = try rt.internAtom("privateBoundCaller");
    defer rt.atoms.free(function_name);
    const private_name = try rt.atoms.newSymbol("privateBoundName", .private);
    defer rt.atoms.free(private_name);

    var function = bytecode.Bytecode.init(&rt.memory, &rt.atoms, function_name);
    defer function.deinit(rt);
    function.private_bound_names = try rt.memory.alloc(core.Atom, 1);
    function.private_bound_names[0] = rt.atoms.dup(private_name);

    const before_bytes = rt.memory.allocated_bytes;
    const before_allocations = rt.memory.allocation_count;
    const names = try directEvalPrivateBoundNames(rt, &function, null);
    if (names.len != 0) rt.memory.free(core.Atom, names);
    try std.testing.expectEqual(before_bytes, rt.memory.allocated_bytes);
    try std.testing.expectEqual(before_allocations, rt.memory.allocation_count);
}

test "eval function declaration names release preserves memory account" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const warm = try rt.internAtom("evalMemoryAccountName");
    rt.atoms.free(warm);

    const before_bytes = rt.memory.allocated_bytes;
    const before_allocations = rt.memory.allocation_count;
    const names = (try evalFunctionDeclarationNames(rt, "function evalMemoryAccountName() {}")).?;
    freeAtomSlice(rt, names);
    try std.testing.expectEqual(before_bytes, rt.memory.allocated_bytes);
    try std.testing.expectEqual(before_allocations, rt.memory.allocation_count);
}

test "eval function declaration names OOM releases pending atom" {
    const function_name = "evalPendingFunctionName";
    var saw_oom = false;
    var saw_success = false;

    var fail_offset: usize = 0;
    while (fail_offset < 120) : (fail_offset += 1) {
        var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
        const rt = try core.Runtime.create(failing.allocator());
        defer rt.destroy();

        failing.fail_index = failing.alloc_index + fail_offset;
        const result = evalFunctionDeclarationNames(rt, "function evalPendingFunctionName() {}");
        failing.fail_index = std.math.maxInt(usize);

        if (result) |maybe_names| {
            saw_success = true;
            if (maybe_names) |names| freeAtomSlice(rt, names);
        } else |err| switch (err) {
            error.OutOfMemory => saw_oom = true,
            else => |unexpected| return unexpected,
        }

        const probe = try rt.internAtom(function_name);
        rt.atoms.free(probe);
        try std.testing.expect(rt.atoms.name(probe) == null);
    }

    try std.testing.expect(saw_oom);
    try std.testing.expect(saw_success);
}

pub fn directEvalPrivateBoundNames(
    rt: *core.Runtime,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) ![]core.Atom {
    var atoms = std.ArrayList(core.Atom).empty;
    errdefer atoms.deinit(rt.memory.allocator);
    if (caller_function) |function| {
        for (function.private_bound_names) |atom_id| {
            try appendPrivateBoundName(rt, &atoms, atom_id);
        }
        for (function.atom_operands) |atom_id| {
            try appendPrivateBoundName(rt, &atoms, atom_id);
        }
    }
    if (caller_frame) |frame| {
        try appendPrivateBoundNamesFromValue(rt, &atoms, frame.this_value);
        if (objectFromValue(frame.current_function)) |function_object| {
            if (function_object.functionHomeObjectSlot().*) |home_object| {
                try appendPrivateBoundNamesFromObject(rt, &atoms, home_object);
            }
        }
    }
    return try atomListToMemorySlice(rt, &atoms);
}

pub fn appendPrivateBoundNamesFromValue(
    rt: *core.Runtime,
    atoms: *std.ArrayList(core.Atom),
    value: core.Value,
) !void {
    const object = objectFromValue(value) orelse return;
    try appendPrivateBoundNamesFromObject(rt, atoms, object);
}

pub fn appendPrivateBoundNamesFromObject(
    rt: *core.Runtime,
    atoms: *std.ArrayList(core.Atom),
    object: *core.Object,
) !void {
    for (object.properties) |entry| {
        try appendPrivateBoundName(rt, atoms, entry.atom_id);
    }
}

pub fn appendPrivateBoundName(
    rt: *core.Runtime,
    atoms: *std.ArrayList(core.Atom),
    atom_id: core.Atom,
) !void {
    if (rt.atoms.kind(atom_id) != .private) return;
    for (atoms.items) |existing| {
        if (existing == atom_id or privateAtomNamesMatch(rt, existing, atom_id)) return;
    }
    try atoms.append(rt.memory.allocator, atom_id);
}

pub fn privateAtomNamesMatch(rt: *core.Runtime, left: core.Atom, right: core.Atom) bool {
    const left_name = rt.atoms.name(left) orelse return false;
    const right_name = rt.atoms.name(right) orelse return false;
    return std.mem.eql(u8, left_name, right_name);
}

pub fn evalFunctionDeclarationNames(rt: *core.Runtime, source: []const u8) !?[]core.Atom {
    var atoms = std.ArrayList(core.Atom).empty;
    errdefer {
        for (atoms.items) |atom_id| rt.atoms.free(atom_id);
        atoms.deinit(rt.memory.allocator);
    }
    var search_start: usize = 0;
    while (std.mem.indexOf(u8, source[search_start..], "function")) |rel| {
        const keyword_index = search_start + rel;
        if (!looksLikeStatementFunctionKeyword(source, keyword_index)) {
            search_start = keyword_index + "function".len;
            continue;
        }
        if (braceDepthBefore(source, keyword_index) != 0) {
            search_start = keyword_index + "function".len;
            continue;
        }
        if (try evalFunctionDeclarationNameAt(rt, source, keyword_index)) |atom_id| {
            var duplicate = false;
            for (atoms.items) |existing| {
                if (atomIdOrNameEql(rt, existing, atom_id)) {
                    duplicate = true;
                    break;
                }
            }
            if (duplicate) {
                rt.atoms.free(atom_id);
            } else {
                errdefer rt.atoms.free(atom_id);
                try atoms.append(rt.memory.allocator, atom_id);
            }
        }
        search_start = keyword_index + "function".len;
    }
    if (atoms.items.len == 0) return null;
    return try atomListToMemorySlice(rt, &atoms);
}

fn atomListToMemorySlice(rt: *core.Runtime, atoms: *std.ArrayList(core.Atom)) ![]core.Atom {
    if (atoms.items.len == 0) return &.{};
    const out = try rt.memory.alloc(core.Atom, atoms.items.len);
    @memcpy(out, atoms.items);
    atoms.clearAndFree(rt.memory.allocator);
    return out;
}

pub fn braceDepthBefore(source: []const u8, end: usize) usize {
    var depth: usize = 0;
    var index: usize = 0;
    while (index < end and index < source.len) : (index += 1) {
        switch (source[index]) {
            '{' => depth += 1,
            '}' => if (depth > 0) {
                depth -= 1;
            },
            else => {},
        }
    }
    return depth;
}

pub fn evalFunctionDeclarationNameAt(rt: *core.Runtime, source: []const u8, keyword_index: usize) !?core.Atom {
    var index = keyword_index + "function".len;
    index = skipAsciiWhitespace(source, index);
    if (index < source.len and source[index] == '*') {
        index += 1;
        index = skipAsciiWhitespace(source, index);
    }
    var name_bytes = std.ArrayList(u8).empty;
    defer name_bytes.deinit(rt.memory.allocator);
    while (index < source.len) {
        const b = source[index];
        if (b == '(' or std.ascii.isWhitespace(b)) break;
        if (b == '\\' and index + 1 < source.len and source[index + 1] == 'u') {
            try appendIdentifierEscape(rt, &name_bytes, source, &index);
            continue;
        }
        if (!isIdentifierPartByte(b)) return null;
        try name_bytes.append(rt.memory.allocator, b);
        index += 1;
    }
    if (name_bytes.items.len == 0) return null;
    const after_name = skipAsciiWhitespace(source, index);
    if (after_name >= source.len or source[after_name] != '(') return null;
    return try rt.internAtom(name_bytes.items);
}

pub fn simpleEvalFunctionDeclarationNames(rt: *core.Runtime, source: []const u8) !?[]core.Atom {
    var index = skipAsciiWhitespace(source, 0);
    if (!startsWithKeyword(source[index..], "function")) return null;
    index += "function".len;
    index = skipAsciiWhitespace(source, index);
    if (index < source.len and source[index] == '*') {
        index += 1;
        index = skipAsciiWhitespace(source, index);
    }
    var name_bytes = std.ArrayList(u8).empty;
    defer name_bytes.deinit(rt.memory.allocator);
    while (index < source.len) {
        const b = source[index];
        if (b == '(' or std.ascii.isWhitespace(b)) break;
        if (b == '\\' and index + 1 < source.len and source[index + 1] == 'u') {
            try appendIdentifierEscape(rt, &name_bytes, source, &index);
            continue;
        }
        try name_bytes.append(rt.memory.allocator, b);
        index += 1;
    }
    if (name_bytes.items.len == 0) return null;
    const after_name = skipAsciiWhitespace(source, index);
    if (after_name >= source.len or source[after_name] != '(') return null;
    const names = try rt.memory.alloc(core.Atom, 1);
    errdefer rt.memory.free(core.Atom, names);
    names[0] = try rt.internAtom(name_bytes.items);
    return names;
}

pub fn skipAsciiWhitespace(source: []const u8, start: usize) usize {
    var index = start;
    while (index < source.len and std.ascii.isWhitespace(source[index])) : (index += 1) {}
    return index;
}

pub fn startsWithKeyword(source: []const u8, keyword: []const u8) bool {
    if (!std.mem.startsWith(u8, source, keyword)) return false;
    if (source.len == keyword.len) return true;
    const next = source[keyword.len];
    return !std.ascii.isAlphanumeric(next) and next != '_' and next != '$';
}

pub fn appendIdentifierEscape(rt: *core.Runtime, out: *std.ArrayList(u8), source: []const u8, index: *usize) !void {
    if (index.* + 6 > source.len) return error.SyntaxError;
    const hex = source[index.* + 2 .. index.* + 6];
    const code = std.fmt.parseInt(u21, hex, 16) catch return error.SyntaxError;
    var buf: [4]u8 = undefined;
    const len = try std.unicode.utf8Encode(code, &buf);
    index.* += 6;
    try out.appendSlice(rt.memory.allocator, buf[0..len]);
}

pub fn createEvalVarRefCells(ctx: *core.Context, len: usize) ![]core.Value {
    if (len == 0) return &.{};
    const refs = try ctx.runtime.memory.alloc(core.Value, len);
    var initialized: usize = 0;
    errdefer {
        for (refs[0..initialized]) |value| value.free(ctx.runtime);
        ctx.runtime.memory.free(core.Value, refs);
    }
    while (initialized < len) : (initialized += 1) {
        const object = try core.Object.create(ctx.runtime, core.class.ids.object, null);
        errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
        try object.initVarRefPayload(ctx.runtime, core.Value.undefinedValue());
        refs[initialized] = object.value();
    }
    return refs;
}

pub fn createDirectEvalVarRefCells(
    ctx: *core.Context,
    names: []const core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
    eval_in_parameter_initializer: bool,
) ![]core.Value {
    if (names.len == 0) return &.{};
    const refs = try ctx.runtime.memory.alloc(core.Value, names.len);
    var initialized: usize = 0;
    errdefer {
        for (refs[0..initialized]) |value| value.free(ctx.runtime);
        ctx.runtime.memory.free(core.Value, refs);
    }
    while (initialized < names.len) : (initialized += 1) {
        if (caller_function) |function| {
            if (caller_frame) |frame| {
                if (callerArgIndex(ctx.runtime, function, names[initialized])) |arg_idx| {
                    if (arg_idx < frame.args.len) {
                        refs[initialized] = try ensureVarRefCell(ctx, &frame.args[arg_idx]);
                        continue;
                    }
                }
                if (!eval_in_parameter_initializer) {
                    if (callerLocalIndex(ctx.runtime, function, names[initialized])) |local_idx| {
                        if (local_idx < frame.locals.len) {
                            refs[initialized] = try ensureVarRefCell(ctx, &frame.locals[local_idx]);
                            continue;
                        }
                    }
                }
            }
        }
        const object = try core.Object.create(ctx.runtime, core.class.ids.object, null);
        errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
        try object.initVarRefPayload(ctx.runtime, core.Value.undefinedValue());
        object.varRefIsDeletableSlot().* = true;
        refs[initialized] = object.value();
    }
    return refs;
}

const DirectEvalVisibleLocalBindings = struct {
    names: []core.Atom,
    slots: []core.Value,
};

pub fn createDirectEvalVisibleLocalBindings(
    ctx: *core.Context,
    global: *core.Object,
    caller_function: *const bytecode.Bytecode,
    caller_frame: *frame_mod.Frame,
    eval_in_parameter_initializer: bool,
    eval_global_var_bindings: bool,
) !DirectEvalVisibleLocalBindings {
    const arg_count = @min(caller_function.arg_names.len, caller_frame.args.len);
    const local_count = if (eval_in_parameter_initializer) 0 else @min(caller_function.var_names.len, caller_frame.locals.len);
    const include_implicit_arguments =
        directEvalShouldExposeImplicitArguments(caller_frame) and
        !functionHasArgOrLocal(caller_function, core.atom.ids.arguments, arg_count, local_count);
    const count = arg_count + local_count + @as(usize, if (include_implicit_arguments) 1 else 0);
    if (count == 0) return .{ .names = &.{}, .slots = &.{} };
    const names = try ctx.runtime.memory.alloc(core.Atom, count);
    errdefer ctx.runtime.memory.free(core.Atom, names);
    const slots = try ctx.runtime.memory.alloc(core.Value, count);
    errdefer ctx.runtime.memory.free(core.Value, slots);
    var initialized: usize = 0;
    var initialized_names: usize = 0;
    errdefer {
        for (names[0..initialized_names]) |atom_id| ctx.runtime.atoms.free(atom_id);
        for (slots[0..initialized]) |value| value.free(ctx.runtime);
    }
    var local_index = local_count;
    while (local_index > 0) {
        local_index -= 1;
        const atom_id = caller_function.var_names[local_index];
        if (atom_id == core.atom.null_atom) continue;
        if (directEvalVisibleBindingExists(ctx.runtime, names[0..initialized], atom_id)) continue;
        if (eval_global_var_bindings and
            globalLexicalHas(ctx.runtime, global, atom_id) and
            directEvalVisibleLocalNameCount(ctx.runtime, caller_function.var_names[0..local_count], atom_id) == 1)
        {
            continue;
        }
        names[initialized] = ctx.runtime.atoms.dup(atom_id);
        initialized_names += 1;
        slots[initialized] = try ensureVarRefCell(ctx, &caller_frame.locals[local_index]);
        initialized += 1;
    }
    var arg_index = arg_count;
    while (arg_index > 0) {
        arg_index -= 1;
        const atom_id = caller_function.arg_names[arg_index];
        if (atom_id == core.atom.null_atom) continue;
        if (directEvalVisibleBindingExists(ctx.runtime, names[0..initialized], atom_id)) continue;
        names[initialized] = ctx.runtime.atoms.dup(atom_id);
        initialized_names += 1;
        slots[initialized] = try ensureVarRefCell(ctx, &caller_frame.args[arg_index]);
        initialized += 1;
    }
    if (include_implicit_arguments) {
        names[initialized] = ctx.runtime.atoms.dup(core.atom.ids.arguments);
        initialized_names += 1;
        slots[initialized] = try frameArgumentsObject(ctx, global, caller_frame);
        initialized += 1;
    }
    if (initialized == 0) {
        ctx.runtime.memory.free(core.Atom, names);
        ctx.runtime.memory.free(core.Value, slots);
        return .{ .names = &.{}, .slots = &.{} };
    }
    if (initialized != count) {
        const compact_names = try ctx.runtime.memory.alloc(core.Atom, initialized);
        errdefer ctx.runtime.memory.free(core.Atom, compact_names);
        const compact_slots = try ctx.runtime.memory.alloc(core.Value, initialized);
        errdefer ctx.runtime.memory.free(core.Value, compact_slots);
        @memcpy(compact_names, names[0..initialized]);
        @memcpy(compact_slots, slots[0..initialized]);
        ctx.runtime.memory.free(core.Atom, names);
        ctx.runtime.memory.free(core.Value, slots);
        return .{ .names = compact_names, .slots = compact_slots };
    }
    return .{ .names = names, .slots = slots };
}

pub fn directEvalVisibleBindingExists(rt: *core.Runtime, names: []const core.Atom, atom_id: core.Atom) bool {
    for (names) |existing| {
        if (atomIdOrNameEql(rt, existing, atom_id)) return true;
    }
    return false;
}

pub fn directEvalVisibleLocalNameCount(rt: *core.Runtime, names: []const core.Atom, atom_id: core.Atom) usize {
    var count: usize = 0;
    for (names) |existing| {
        if (atomIdOrNameEql(rt, existing, atom_id)) count += 1;
    }
    return count;
}

pub fn directEvalShouldExposeImplicitArguments(caller_frame: *frame_mod.Frame) bool {
    if (caller_frame.current_function.isUndefined()) return false;
    if (functionBytecodeFromValue(caller_frame.current_function)) |fb| return !fb.is_arrow_function;
    if (objectFromValue(caller_frame.current_function)) |function_object| {
        const stored = function_object.functionBytecodeSlot().* orelse return false;
        const fb = functionBytecodeFromValue(stored) orelse return false;
        return !fb.is_arrow_function;
    }
    return false;
}

pub fn frameCurrentFunctionIsArrow(caller_frame: *frame_mod.Frame) bool {
    if (functionBytecodeFromValue(caller_frame.current_function)) |fb| return fb.is_arrow_function;
    if (objectFromValue(caller_frame.current_function)) |function_object| {
        const stored = function_object.functionBytecodeSlot().* orelse return false;
        const fb = functionBytecodeFromValue(stored) orelse return false;
        return fb.is_arrow_function;
    }
    return false;
}

pub fn directEvalCallerAllowsNewTarget(caller_frame: ?*frame_mod.Frame, eval_in_class_field_initializer: bool) bool {
    if (eval_in_class_field_initializer) return true;
    const outer_frame = caller_frame orelse return false;
    if (outer_frame.current_function.isUndefined()) return false;
    if (functionBytecodeFromValue(outer_frame.current_function)) |fb| return fb.new_target_allowed;
    if (objectFromValue(outer_frame.current_function)) |function_object| {
        const stored = function_object.functionBytecodeSlot().* orelse return false;
        const fb = functionBytecodeFromValue(stored) orelse return false;
        return fb.new_target_allowed;
    }
    return false;
}

pub fn directEvalCallerAllowsSuperProperty(caller_frame: ?*frame_mod.Frame, eval_in_class_field_initializer: bool) bool {
    if (eval_in_class_field_initializer) return true;
    const outer_frame = caller_frame orelse return false;
    if (outer_frame.current_function.isUndefined()) return false;
    if (functionBytecodeFromValue(outer_frame.current_function)) |fb| return fb.super_allowed;
    if (objectFromValue(outer_frame.current_function)) |function_object| {
        const stored = function_object.functionBytecodeSlot().* orelse return false;
        const fb = functionBytecodeFromValue(stored) orelse return false;
        return fb.super_allowed;
    }
    return false;
}

pub fn functionHasArgOrLocal(
    function: *const bytecode.Bytecode,
    atom_id: core.Atom,
    arg_count: usize,
    local_count: usize,
) bool {
    for (function.arg_names[0..arg_count]) |name| {
        if (name == atom_id) return true;
    }
    for (function.var_names[0..local_count]) |name| {
        if (name == atom_id) return true;
    }
    return false;
}

pub fn callerArgIndex(rt: *core.Runtime, function: *const bytecode.Bytecode, atom_id: core.Atom) ?usize {
    for (function.arg_names, 0..) |name, idx| {
        if (atomIdOrNameEql(rt, name, atom_id)) return idx;
    }
    return null;
}

pub fn callerLocalIndex(rt: *core.Runtime, function: *const bytecode.Bytecode, atom_id: core.Atom) ?usize {
    const count = @min(function.var_names.len, function.var_is_lexical.len);
    for (function.var_names[0..count], 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id)) continue;
        if (function.var_is_lexical[idx]) continue;
        return idx;
    }
    return null;
}

pub fn directEvalVarDeclarationNames(
    rt: *core.Runtime,
    global: *core.Object,
    function: *const bytecode.Bytecode,
    source: []const u8,
    caller_function: ?*const bytecode.Bytecode,
    function_decl_names: []const core.Atom,
    eval_global_var_bindings: bool,
) ![]core.Atom {
    const simple_var_name = if (simpleVarDeclarationName(source)) |name| try rt.internAtom(name) else core.atom.null_atom;
    defer if (simple_var_name != core.atom.null_atom) rt.atoms.free(simple_var_name);
    const count = blk: {
        var n: usize = 0;
        const local_count = @min(function.var_names.len, function.var_is_lexical.len);
        for (function.var_names[0..local_count], 0..) |atom_id, idx| {
            if (atom_id == core.atom.null_atom) continue;
            if (atom_id == eval_ret_atom) continue;
            if (directEvalVarNameIsNonLeadingFunctionCallerArg(rt, source, caller_function, atom_id)) continue;
            if (directEvalSourceHasLexicalDeclarationName(rt, source, atom_id)) continue;
            const is_lexical = function.var_is_lexical[idx];
            if (!is_lexical and eval_global_var_bindings and !directEvalVarDeclarationShouldCreateRef(rt, global, atom_id)) continue;
            if (!is_lexical) n += 1;
        }
        for (function_decl_names) |atom_id| {
            if (atom_id == eval_ret_atom) continue;
            if (directEvalSourceHasLexicalDeclarationName(rt, source, atom_id)) continue;
            if (!functionHasNonLexicalLocal(rt, function, atom_id)) n += 1;
        }
        if (simple_var_name != core.atom.null_atom and
            simple_var_name != eval_ret_atom and
            directEvalGlobalDataVarNeedsTemporaryRef(rt, global, simple_var_name) and
            !functionHasNonLexicalLocal(rt, function, simple_var_name) and
            !atomSliceContains(rt, function_decl_names, simple_var_name) and
            !directEvalSourceHasLexicalDeclarationName(rt, source, simple_var_name))
        {
            n += 1;
        }
        break :blk n;
    };
    if (count == 0) return &.{};
    const names = try rt.memory.alloc(core.Atom, count);
    errdefer rt.memory.free(core.Atom, names);
    var out_idx: usize = 0;
    const local_count = @min(function.var_names.len, function.var_is_lexical.len);
    for (function.var_names[0..local_count], 0..) |atom_id, idx| {
        if (atom_id == core.atom.null_atom) continue;
        if (atom_id == eval_ret_atom) continue;
        if (directEvalVarNameIsNonLeadingFunctionCallerArg(rt, source, caller_function, atom_id)) continue;
        if (directEvalSourceHasLexicalDeclarationName(rt, source, atom_id)) continue;
        if (function.var_is_lexical[idx]) continue;
        if (eval_global_var_bindings and !directEvalVarDeclarationShouldCreateRef(rt, global, atom_id)) continue;
        names[out_idx] = rt.atoms.dup(atom_id);
        out_idx += 1;
    }
    for (function_decl_names) |atom_id| {
        if (atom_id == eval_ret_atom) continue;
        if (directEvalSourceHasLexicalDeclarationName(rt, source, atom_id)) continue;
        if (functionHasNonLexicalLocal(rt, function, atom_id)) continue;
        names[out_idx] = rt.atoms.dup(atom_id);
        out_idx += 1;
    }
    if (simple_var_name != core.atom.null_atom and
        simple_var_name != eval_ret_atom and
        directEvalGlobalDataVarNeedsTemporaryRef(rt, global, simple_var_name) and
        !functionHasNonLexicalLocal(rt, function, simple_var_name) and
        !atomSliceContains(rt, function_decl_names, simple_var_name) and
        !directEvalSourceHasLexicalDeclarationName(rt, source, simple_var_name))
    {
        names[out_idx] = rt.atoms.dup(simple_var_name);
        out_idx += 1;
    }
    return names;
}

fn atomSliceContains(rt: *core.Runtime, names: []const core.Atom, atom_id: core.Atom) bool {
    for (names) |name| {
        if (atomIdOrNameEql(rt, name, atom_id)) return true;
    }
    return false;
}

pub fn directEvalVarNameIsNonLeadingFunctionCallerArg(
    rt: *core.Runtime,
    source: []const u8,
    caller_function: ?*const bytecode.Bytecode,
    atom_id: core.Atom,
) bool {
    const function = caller_function orelse return false;
    const name = rt.atoms.name(atom_id) orelse return false;
    if (!callerFunctionHasArg(rt, function, name)) return false;
    const first = skipAsciiWhitespace(source, 0);
    if (startsWithKeyword(source[first..], "function")) return false;

    var search_start: usize = 0;
    while (std.mem.indexOf(u8, source[search_start..], "function")) |rel| {
        const idx = search_start + rel;
        if (idx > 0) {
            const prev = source[idx - 1];
            if (std.ascii.isAlphanumeric(prev) or prev == '_' or prev == '$') {
                search_start = idx + "function".len;
                continue;
            }
        }
        var cursor = skipAsciiWhitespace(source, idx + "function".len);
        if (cursor < source.len and source[cursor] == '*') {
            cursor = skipAsciiWhitespace(source, cursor + 1);
        }
        if (source.len >= cursor + name.len and std.mem.eql(u8, source[cursor..][0..name.len], name)) {
            const after = cursor + name.len;
            if (after >= source.len or source[after] == '(' or std.ascii.isWhitespace(source[after])) return true;
        }
        search_start = idx + "function".len;
    }
    return false;
}

pub fn directEvalSourceHasLexicalDeclarationName(rt: *core.Runtime, source: []const u8, atom_id: core.Atom) bool {
    const name = rt.atoms.name(atom_id) orelse return false;
    var search_start: usize = 0;
    while (search_start < source.len) {
        const let_pos = std.mem.indexOf(u8, source[search_start..], "let");
        const const_pos = std.mem.indexOf(u8, source[search_start..], "const");
        const class_pos = std.mem.indexOf(u8, source[search_start..], "class");
        const rel = minOptionalIndex(let_pos, const_pos, class_pos) orelse return false;
        const keyword_index = search_start + rel.index;
        if (!looksLikeIdentifierKeyword(source, keyword_index, rel.keyword)) {
            search_start = keyword_index + rel.keyword.len;
            continue;
        }
        const cursor = skipAsciiWhitespace(source, keyword_index + rel.keyword.len);
        if (source.len >= cursor + name.len and std.mem.eql(u8, source[cursor..][0..name.len], name)) {
            const after = cursor + name.len;
            if (after >= source.len or !isIdentifierPartByte(source[after])) return true;
        }
        search_start = keyword_index + rel.keyword.len;
    }
    return false;
}

const KeywordMatch = struct {
    index: usize,
    keyword: []const u8,
};

pub fn minOptionalIndex(let_pos: ?usize, const_pos: ?usize, class_pos: ?usize) ?KeywordMatch {
    var best: ?KeywordMatch = null;
    if (let_pos) |index| best = .{ .index = index, .keyword = "let" };
    if (const_pos) |index| {
        if (best == null or index < best.?.index) best = .{ .index = index, .keyword = "const" };
    }
    if (class_pos) |index| {
        if (best == null or index < best.?.index) best = .{ .index = index, .keyword = "class" };
    }
    return best;
}

pub fn looksLikeIdentifierKeyword(source: []const u8, keyword_index: usize, keyword: []const u8) bool {
    if (keyword_index > 0 and isIdentifierPartByte(source[keyword_index - 1])) return false;
    const after = keyword_index + keyword.len;
    if (after < source.len and isIdentifierPartByte(source[after])) return false;
    return true;
}

pub fn functionHasNonLexicalLocal(rt: *core.Runtime, function: *const bytecode.Bytecode, atom_id: core.Atom) bool {
    const local_count = @min(function.var_names.len, function.var_is_lexical.len);
    for (function.var_names[0..local_count], 0..) |name, idx| {
        if (atomIdOrNameEql(rt, name, atom_id) and !function.var_is_lexical[idx]) return true;
    }
    return false;
}

pub fn freeAtomSlice(rt: *core.Runtime, atoms: []core.Atom) void {
    for (atoms) |atom_id| rt.atoms.free(atom_id);
    if (atoms.len != 0) rt.memory.free(core.Atom, atoms);
}

pub fn freeValueSlice(rt: *core.Runtime, values: []core.Value) void {
    for (values) |value| value.free(rt);
    if (values.len != 0) rt.memory.free(core.Value, values);
}

pub fn publishDirectEvalVarRefs(
    ctx: *core.Context,
    global: *core.Object,
    caller_frame: ?*frame_mod.Frame,
    names: []const core.Atom,
    refs: []const core.Value,
    eval_in_parameter_initializer: bool,
    eval_global_var_bindings: bool,
) !void {
    const count = @min(names.len, refs.len);
    if (count == 0) return;
    if (!eval_global_var_bindings) {
        if (caller_frame) |frame| {
            if (objectFromValue(frame.current_function)) |function_object| {
                var index: usize = 0;
                while (index < count) : (index += 1) {
                    try appendFunctionEvalLocal(ctx, function_object, names[index], refs[index]);
                    if (!eval_in_parameter_initializer) {
                        replaceFrameVarRefBinding(ctx.runtime, frame, names[index], refs[index]);
                    }
                }
                frame.eval_var_ref_names = function_object.functionEvalLocalNamesSlot().*;
                frame.eval_var_refs = function_object.functionEvalLocalRefsSlot().*;
            }
        }
        return;
    }
    var index: usize = 0;
    while (index < count) : (index += 1) {
        const value = if (varRefCellFromValue(refs[index])) |cell|
            if (cell.varRefValueSlot().*) |stored| stored.dup() else core.Value.undefinedValue()
        else
            refs[index].dup();
        defer value.free(ctx.runtime);
        if (directEvalGlobalVarPublishBlocked(ctx.runtime, global, names[index])) continue;
        try defineGlobalFunctionBindingValue(ctx.runtime, global, names[index], value, true);
    }
}

fn directEvalGlobalVarPublishBlocked(rt: *core.Runtime, global: *core.Object, atom_id: core.Atom) bool {
    const desc = global.getOwnProperty(atom_id) orelse return false;
    defer desc.destroy(rt);
    return switch (desc.kind) {
        .generic => false,
        .data => desc.writable != true,
        .accessor => desc.setter.isUndefined(),
    };
}

fn directEvalVarDeclarationShouldCreateRef(rt: *core.Runtime, global: *core.Object, atom_id: core.Atom) bool {
    const desc = global.getOwnProperty(atom_id) orelse return true;
    defer desc.destroy(rt);
    return desc.kind != .accessor;
}

fn directEvalGlobalDataVarNeedsTemporaryRef(rt: *core.Runtime, global: *core.Object, atom_id: core.Atom) bool {
    const desc = global.getOwnProperty(atom_id) orelse return false;
    defer desc.destroy(rt);
    return desc.kind == .data and desc.writable != true;
}

pub fn qjsTest262EvalScript(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    function_object: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len == 0) return core.Value.undefinedValue();
    if (!args[0].isString()) return error.TypeError;
    const eval_global = objectRealmGlobal(function_object) orelse global;
    var source = std.ArrayList(u8).empty;
    defer source.deinit(ctx.runtime.memory.allocator);
    try appendSourceStringUtf8(ctx.runtime, &source, args[0]);
    return qjsEvalGlobalScriptSource(ctx, output, eval_global, source.items, "<evalScript>");
}

pub fn qjsEvalGlobalScriptSource(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source: []const u8,
    filename: []const u8,
) !core.Value {
    var compiled = try frontend.parser.parse(ctx.runtime, source, .{ .mode = .script, .filename = filename, .strict = false, .return_completion = true });
    defer compiled.deinit();
    if (compiled.syntax_error != null) return error.SyntaxError;
    var nested_stack = stack_mod.Stack.init(&ctx.runtime.memory, ctx.runtime.stack_size);
    defer nested_stack.deinit(ctx.runtime);
    return runWithArgsState(ctx, &nested_stack, &compiled.function, global.value(), &.{}, &.{}, output, global, true, false, false, &.{}, &.{}, &.{}, &.{}, &.{}, &.{}, &.{}, &.{}, null, null, null, core.Value.undefinedValue(), core.Value.undefinedValue(), core.Value.undefinedValue(), false, false, core.Value.undefinedValue(), true, false) catch |err| {
        return normalizeEvalRuntimeError(err);
    };
}

const Test262Agent = struct {
    source: []u8,
    broadcast_store: ?*core.object.SharedBufferStore = null,
    broadcast_max_byte_length: ?usize = null,
    done: bool = false,
    thread_done: bool = false,
};

const Test262AgentCoordinator = struct {
    mutex: std.Io.Mutex = .init,
    cond: std.Io.Condition = .init,
    agents: []*Test262Agent = &.{},
    agents_capacity: usize = 0,
    reports: [][]u8 = &.{},
    reports_capacity: usize = 0,
};

var test262_agents = Test262AgentCoordinator{};
threadlocal var current_test262_agent: ?*Test262Agent = null;

const WorkerMessage = union(enum) {
    undefined,
    null,
    boolean: bool,
    int32: i32,
    float64: f64,
    string: []u8,
    shared_array_buffer: struct {
        store: *core.object.SharedBufferStore,
        max_byte_length: ?usize,
    },

    fn deinit(self: WorkerMessage, allocator: std.mem.Allocator) void {
        switch (self) {
            .string => |bytes| allocator.free(bytes),
            .shared_array_buffer => |entry| entry.store.release(),
            else => {},
        }
    }
};

const QjsWorker = struct {
    id: i32,
    path: []u8,
    owner_runtime: *core.Runtime,
    object: ?core.Value = null,
    to_worker: []WorkerMessage = &.{},
    to_worker_capacity: usize = 0,
    to_parent: []WorkerMessage = &.{},
    to_parent_capacity: usize = 0,
    closing: bool = false,
    done: bool = false,
};

const WorkerPostTarget = enum(i32) {
    worker = 1,
    parent = 2,
};

const QjsWorkerCoordinator = struct {
    mutex: std.Io.Mutex = .init,
    cond: std.Io.Condition = .init,
    next_id: i32 = 1,
    workers: []*QjsWorker = &.{},
    workers_capacity: usize = 0,
};

var qjs_workers = QjsWorkerCoordinator{};
threadlocal var current_qjs_worker: ?*QjsWorker = null;
threadlocal var current_qjs_worker_parent: ?core.Value = null;

fn test262PageAllocator() std.mem.Allocator {
    return std.heap.page_allocator;
}

fn test262AgentIo() std.Io {
    return std.Io.Threaded.global_single_threaded.io();
}

fn qjsWorkerIo() std.Io {
    return std.Io.Threaded.global_single_threaded.io();
}

fn test262AgentStringArg(rt: *core.Runtime, value: core.Value) ![]u8 {
    var bytes = std.ArrayList(u8).empty;
    errdefer bytes.deinit(rt.memory.allocator);
    try value_ops.appendValueString(rt, &bytes, value);
    return bytes.toOwnedSlice(rt.memory.allocator);
}

fn test262AgentStringValue(rt: *core.Runtime, value: core.Value) ![]u8 {
    const local = try test262AgentStringArg(rt, value);
    defer rt.memory.allocator.free(local);
    return try test262PageAllocator().dupe(u8, local);
}

fn test262AgentAppend(agent: *Test262Agent) !void {
    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    defer test262_agents.mutex.unlock(io);
    _ = test262AgentSweepCompletedLocked();
    try test262AgentEnsureAgentCapacityLocked(test262_agents.agents.len + 1);
    test262_agents.agents = test262_agents.agents.ptr[0 .. test262_agents.agents.len + 1];
    test262_agents.agents[test262_agents.agents.len - 1] = agent;
}

fn test262AgentEnqueueReport(bytes: []u8) !void {
    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    defer test262_agents.mutex.unlock(io);
    try test262AgentEnsureReportCapacityLocked(test262_agents.reports.len + 1);
    test262_agents.reports = test262_agents.reports.ptr[0 .. test262_agents.reports.len + 1];
    test262_agents.reports[test262_agents.reports.len - 1] = bytes;
    test262_agents.cond.broadcast(io);
}

fn test262AgentDestroy(agent: *Test262Agent) void {
    const allocator = test262PageAllocator();
    allocator.free(agent.source);
    if (agent.broadcast_store) |store| {
        store.release();
        agent.broadcast_store = null;
    }
    allocator.destroy(agent);
}

fn test262AgentEnsureAgentCapacityLocked(min_capacity: usize) !void {
    if (test262_agents.agents_capacity >= min_capacity) return;
    const allocator = test262PageAllocator();
    var next_capacity = if (test262_agents.agents_capacity == 0) @as(usize, 4) else test262_agents.agents_capacity * 2;
    while (next_capacity < min_capacity) : (next_capacity *= 2) {}
    const next = try allocator.alloc(*Test262Agent, next_capacity);
    @memcpy(next[0..test262_agents.agents.len], test262_agents.agents);
    if (test262_agents.agents_capacity != 0) allocator.free(test262_agents.agents.ptr[0..test262_agents.agents_capacity]);
    test262_agents.agents = next[0..test262_agents.agents.len];
    test262_agents.agents_capacity = next_capacity;
}

fn test262AgentEnsureReportCapacityLocked(min_capacity: usize) !void {
    if (test262_agents.reports_capacity >= min_capacity) return;
    const allocator = test262PageAllocator();
    var next_capacity = if (test262_agents.reports_capacity == 0) @as(usize, 4) else test262_agents.reports_capacity * 2;
    while (next_capacity < min_capacity) : (next_capacity *= 2) {}
    const next = try allocator.alloc([]u8, next_capacity);
    @memcpy(next[0..test262_agents.reports.len], test262_agents.reports);
    if (test262_agents.reports_capacity != 0) allocator.free(test262_agents.reports.ptr[0..test262_agents.reports_capacity]);
    test262_agents.reports = next[0..test262_agents.reports.len];
    test262_agents.reports_capacity = next_capacity;
}

fn test262AgentRemoveAtLocked(index: usize) void {
    std.debug.assert(index < test262_agents.agents.len);
    const agent = test262_agents.agents[index];
    const old_len = test262_agents.agents.len;
    if (index + 1 < old_len) {
        @memmove(test262_agents.agents[index .. old_len - 1], test262_agents.agents[index + 1 .. old_len]);
    }
    test262_agents.agents = test262_agents.agents.ptr[0 .. old_len - 1];
    if (test262_agents.agents.len == 0 and test262_agents.agents_capacity != 0) {
        const allocator = test262PageAllocator();
        allocator.free(test262_agents.agents.ptr[0..test262_agents.agents_capacity]);
        test262_agents.agents = &.{};
        test262_agents.agents_capacity = 0;
    }
    test262AgentDestroy(agent);
}

fn test262AgentRemove(agent: *Test262Agent) void {
    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    defer test262_agents.mutex.unlock(io);
    var index: usize = 0;
    while (index < test262_agents.agents.len) : (index += 1) {
        if (test262_agents.agents[index] != agent) continue;
        test262AgentRemoveAtLocked(index);
        return;
    }
}

fn test262AgentSweepCompletedLocked() usize {
    var removed: usize = 0;
    var index: usize = 0;
    while (index < test262_agents.agents.len) {
        if (!test262_agents.agents[index].thread_done) {
            index += 1;
            continue;
        }
        test262AgentRemoveAtLocked(index);
        removed += 1;
    }
    return removed;
}

fn test262AgentTakeReportLocked() ?[]u8 {
    if (test262_agents.reports.len == 0) return null;
    const report = test262_agents.reports[0];
    const old_len = test262_agents.reports.len;
    if (old_len == 1) {
        const allocator = test262PageAllocator();
        allocator.free(test262_agents.reports.ptr[0..test262_agents.reports_capacity]);
        test262_agents.reports = &.{};
        test262_agents.reports_capacity = 0;
        return report;
    }
    @memmove(test262_agents.reports[0 .. old_len - 1], test262_agents.reports[1..old_len]);
    test262_agents.reports = test262_agents.reports.ptr[0 .. old_len - 1];
    return report;
}

pub fn cleanupTest262Agents() usize {
    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    defer test262_agents.mutex.unlock(io);
    return test262AgentSweepCompletedLocked();
}

pub fn test262AgentRecordCountForTests() usize {
    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    defer test262_agents.mutex.unlock(io);
    return test262_agents.agents.len;
}

fn test262AgentRun(agent: *Test262Agent) void {
    current_test262_agent = agent;
    defer current_test262_agent = null;
    defer {
        const io = test262AgentIo();
        test262_agents.mutex.lockUncancelable(io);
        agent.done = true;
        agent.thread_done = true;
        if (agent.broadcast_store) |store| {
            store.release();
            agent.broadcast_store = null;
        }
        test262_agents.cond.broadcast(io);
        test262_agents.mutex.unlock(io);
    }

    const allocator = test262PageAllocator();
    const rt = core.Runtime.create(allocator) catch return;
    defer rt.destroy();
    rt.setCanBlock(true);
    const ctx = core.Context.create(rt) catch return;
    defer ctx.destroy();
    defer qjs_vm.cleanupAtomicsWaitersForContext(ctx);
    const global = qjs_vm.ensureContextGlobal(ctx) catch return;
    var compiled = frontend.parser.parse(rt, agent.source, .{ .mode = .script, .filename = "<test262-agent>" }) catch return;
    defer compiled.deinit();
    if (compiled.syntax_error != null) return;
    var stack = stack_mod.Stack.init(&rt.memory, rt.stack_size);
    defer stack.deinit(rt);
    const result = qjs_vm.runWithOutput(ctx, &stack, &compiled.function, null) catch return;
    result.free(rt);
    drainPendingPromiseJobs(ctx, null, global) catch {};
    while (!test262AgentIsDone(agent)) {
        std.Io.sleep(test262AgentIo(), std.Io.Duration.fromMilliseconds(1), .awake) catch {};
        drainPendingPromiseJobs(ctx, null, global) catch return;
    }
}

fn test262AgentIsDone(agent: *Test262Agent) bool {
    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    defer test262_agents.mutex.unlock(io);
    return agent.done;
}

pub fn qjsTest262AgentStart(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: ?*core.Object,
    args: []const core.Value,
) !core.Value {
    _ = output;
    _ = global;
    if (args.len == 0) return error.TypeError;
    const source = try test262AgentStringValue(ctx.runtime, args[0]);
    var source_owned = true;
    errdefer if (source_owned) test262PageAllocator().free(source);
    const agent = try test262PageAllocator().create(Test262Agent);
    agent.* = .{ .source = source };
    source_owned = false;
    var agent_owned = true;
    var agent_registered = false;
    errdefer if (agent_registered) {
        test262AgentRemove(agent);
    } else if (agent_owned) {
        test262AgentDestroy(agent);
    };
    try test262AgentAppend(agent);
    agent_registered = true;
    const thread = try std.Thread.spawn(.{}, test262AgentRun, .{agent});
    thread.detach();
    agent_owned = false;
    agent_registered = false;
    return core.Value.undefinedValue();
}

pub fn qjsTest262AgentBroadcast(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: ?*core.Object,
    args: []const core.Value,
) !core.Value {
    _ = ctx;
    _ = output;
    _ = global;
    if (args.len == 0) return error.TypeError;
    const buffer = objectFromValue(args[0]) orelse return error.TypeError;
    if (buffer.class_id != core.class.ids.shared_array_buffer) return error.TypeError;
    const store = buffer.sharedByteStorageStore() orelse return error.TypeError;
    const max_byte_length = buffer.arrayBufferMaxByteLength();
    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    defer test262_agents.mutex.unlock(io);
    _ = test262AgentSweepCompletedLocked();
    for (test262_agents.agents) |agent| {
        if (agent.done) continue;
        if (agent.broadcast_store) |old| old.release();
        store.retain();
        agent.broadcast_store = store;
        agent.broadcast_max_byte_length = max_byte_length;
    }
    test262_agents.cond.broadcast(io);
    return core.Value.undefinedValue();
}

pub fn qjsTest262AgentReceiveBroadcast(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: ?*core.Object,
    args: []const core.Value,
) !core.Value {
    const agent = current_test262_agent orelse return error.TypeError;
    if (args.len == 0 or !isCallableValue(args[0])) return error.TypeError;

    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    while (agent.broadcast_store == null and !agent.done) {
        test262_agents.cond.waitUncancelable(io, &test262_agents.mutex);
    }
    const store = agent.broadcast_store orelse {
        test262_agents.mutex.unlock(io);
        return core.Value.undefinedValue();
    };
    const max_byte_length = agent.broadcast_max_byte_length;
    agent.broadcast_store = null;
    agent.broadcast_max_byte_length = null;
    test262_agents.mutex.unlock(io);
    defer store.release();

    const sab = try builtins.buffer.sharedArrayBufferFromStore(ctx.runtime, store, max_byte_length, null);
    defer sab.free(ctx.runtime);
    const callback_result = try callValueOrBytecode(ctx, output, global orelse try qjs_vm.ensureContextGlobal(ctx), core.Value.undefinedValue(), args[0], &.{sab}, null, null);
    callback_result.free(ctx.runtime);
    return core.Value.undefinedValue();
}

pub fn qjsTest262AgentReport(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: ?*core.Object,
    args: []const core.Value,
) !core.Value {
    _ = output;
    _ = global;
    const value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const bytes = try test262AgentStringValue(ctx.runtime, value);
    errdefer test262PageAllocator().free(bytes);
    try test262AgentEnqueueReport(bytes);
    return core.Value.undefinedValue();
}

pub fn qjsTest262AgentGetReport(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: ?*core.Object,
    args: []const core.Value,
) !core.Value {
    _ = output;
    _ = global;
    _ = args;
    const allocator = test262PageAllocator();
    const io = test262AgentIo();
    test262_agents.mutex.lockUncancelable(io);
    _ = test262AgentSweepCompletedLocked();
    const report = test262AgentTakeReportLocked() orelse {
        test262_agents.mutex.unlock(io);
        return core.Value.nullValue();
    };
    test262_agents.mutex.unlock(io);
    defer allocator.free(report);
    return value_ops.createStringValue(ctx.runtime, report);
}

pub fn qjsTest262AgentLeaving(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: ?*core.Object,
    args: []const core.Value,
) !core.Value {
    _ = ctx;
    _ = output;
    _ = global;
    _ = args;
    if (current_test262_agent) |agent| {
        const io = test262AgentIo();
        test262_agents.mutex.lockUncancelable(io);
        agent.done = true;
        test262_agents.cond.broadcast(io);
        test262_agents.mutex.unlock(io);
    }
    return core.Value.undefinedValue();
}

pub fn qjsTest262AgentSleep(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: ?*core.Object,
    args: []const core.Value,
) !core.Value {
    _ = output;
    _ = global;
    const value = if (args.len >= 1) args[0] else core.Value.int32(0);
    const number = value_ops.numberValue(value) orelse 0;
    if (number > 0) {
        const ms: i64 = @intFromFloat(@min(number, 60_000));
        std.Io.sleep(test262AgentIo(), std.Io.Duration.fromMilliseconds(ms), .awake) catch {};
    }
    _ = ctx;
    return core.Value.undefinedValue();
}

pub fn qjsTest262AgentMonotonicNow(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: ?*core.Object,
    args: []const core.Value,
) !core.Value {
    _ = ctx;
    _ = output;
    _ = global;
    _ = args;
    const now = std.Io.Timestamp.now(test262AgentIo(), .awake);
    return core.Value.float64(@as(f64, @floatFromInt(now.nanoseconds)) / std.time.ns_per_ms);
}

pub fn createOsModuleNativeFunction(rt: *core.Runtime, name: []const u8) ?core.Value {
    if (std.mem.eql(u8, name, "Worker")) return qjsWorkerNativeFunction(rt, "Worker", 1, null) catch null;
    if (std.mem.eql(u8, name, "poll")) return qjsWorkerNativeFunction(rt, "poll", 0, null) catch null;
    if (std.mem.eql(u8, name, "sleep")) return qjsWorkerNativeFunction(rt, "sleep", 1, null) catch null;
    return null;
}

const WorkerObjectInitError = std.mem.Allocator.Error || error{
    IncompatibleDescriptor,
    InvalidLength,
    InvalidUtf8,
    NotExtensible,
    ReadOnly,
    TypeError,
};

fn qjsWorkerNativeFunction(rt: *core.Runtime, name: []const u8, length: i32, post_target: ?WorkerPostTarget) WorkerObjectInitError!core.Value {
    const value = try builtins.function.nativeFunction(rt, name, length);
    errdefer value.free(rt);
    if (objectFromValue(value)) |object| {
        if (post_target) |target| object.functionWorkerPostTargetSlot().* = @intCast(@intFromEnum(target));
        if (current_qjs_worker != null and std.mem.eql(u8, name, "Worker")) {
            const parent = try qjsWorkerParentObject(rt);
            defer parent.free(rt);
            try defineValueProperty(rt, object, "parent", parent);
        }
    }
    return value;
}

fn qjsWorkerObjectId(rt: *core.Runtime, value: core.Value) !i32 {
    _ = rt;
    const object = objectFromValue(value) orelse return error.TypeError;
    return object.workerId() orelse error.TypeError;
}

fn qjsWorkerParentObject(rt: *core.Runtime) WorkerObjectInitError!core.Value {
    const worker = current_qjs_worker orelse return core.Value.undefinedValue();
    if (current_qjs_worker_parent) |parent| return parent.dup();
    const parent = try core.Object.create(rt, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(rt, &parent.header);
    (try parent.workerIdSlot(rt)).* = worker.id;
    const post = try qjsWorkerNativeFunction(rt, "postMessage", 1, .parent);
    defer post.free(rt);
    try defineValueProperty(rt, parent, "postMessage", post);
    try defineValueProperty(rt, parent, "onmessage", core.Value.nullValue());
    _ = try rt.registerExternalValueSymbolRoot(parent.value());
    current_qjs_worker_parent = parent.value();
    return parent.value().dup();
}

pub fn qjsWorkerFunctionCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    _ = output;
    _ = global;
    if (current_qjs_worker != null) return error.TypeError;
    if (args.len == 0 or !args[0].isString()) return error.TypeError;
    var path_bytes = std.ArrayList(u8).empty;
    defer path_bytes.deinit(ctx.runtime.memory.allocator);
    try appendSourceStringUtf8(ctx.runtime, &path_bytes, args[0]);

    const allocator = test262PageAllocator();
    const worker = try allocator.create(QjsWorker);
    var raw_worker_owned = true;
    errdefer if (raw_worker_owned) allocator.destroy(worker);
    const owned_path = try allocator.dupe(u8, path_bytes.items);
    var raw_path_owned = true;
    errdefer if (raw_path_owned) allocator.free(owned_path);

    const object = try core.Object.create(ctx.runtime, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);

    const worker_id = blk: {
        const io = qjsWorkerIo();
        qjs_workers.mutex.lockUncancelable(io);
        defer qjs_workers.mutex.unlock(io);
        const id = qjs_workers.next_id;
        qjs_workers.next_id += 1;
        break :blk id;
    };
    worker.* = .{
        .id = worker_id,
        .path = owned_path,
        .owner_runtime = ctx.runtime,
    };
    raw_path_owned = false;
    raw_worker_owned = false;
    var worker_record_owned = true;
    errdefer if (worker_record_owned) qjsWorkerDestroyRecord(worker);
    var worker_registered = false;
    errdefer if (worker_registered) qjsWorkerRemoveRecord(worker);

    {
        const io = qjsWorkerIo();
        qjs_workers.mutex.lockUncancelable(io);
        errdefer qjs_workers.mutex.unlock(io);
        try qjsWorkerEnsureRecordCapacity(qjs_workers.workers.len + 1);
        qjs_workers.workers = qjs_workers.workers.ptr[0 .. qjs_workers.workers.len + 1];
        qjs_workers.workers[qjs_workers.workers.len - 1] = worker;
        worker_registered = true;
        qjs_workers.mutex.unlock(io);
    }

    (try object.workerIdSlot(ctx.runtime)).* = worker_id;
    const post = try qjsWorkerNativeFunction(ctx.runtime, "postMessage", 1, .worker);
    defer post.free(ctx.runtime);
    try defineValueProperty(ctx.runtime, object, "postMessage", post);
    try defineValueProperty(ctx.runtime, object, "onmessage", core.Value.nullValue());
    worker.object = object.value().dup();

    const thread = try std.Thread.spawn(.{}, qjsWorkerThreadMain, .{worker});
    thread.detach();
    worker_record_owned = false;
    worker_registered = false;
    return object.value();
}

fn qjsWorkerCloseRecord(worker: *QjsWorker, wait: bool) void {
    const io = qjsWorkerIo();
    qjs_workers.mutex.lockUncancelable(io);
    worker.closing = true;
    qjs_workers.cond.broadcast(io);
    while (wait and !worker.done) qjs_workers.cond.waitUncancelable(io, &qjs_workers.mutex);
    qjs_workers.mutex.unlock(io);
}

pub fn cleanupWorkersForRuntime(rt: *core.Runtime) void {
    const io = qjsWorkerIo();

    qjs_workers.mutex.lockUncancelable(io);
    for (qjs_workers.workers) |worker| {
        if (worker.owner_runtime != rt) continue;
        worker.closing = true;
    }
    qjs_workers.cond.broadcast(io);
    qjs_workers.mutex.unlock(io);

    while (true) {
        qjs_workers.mutex.lockUncancelable(io);
        var target: ?*QjsWorker = null;
        for (qjs_workers.workers) |worker| {
            if (worker.owner_runtime != rt) continue;
            target = worker;
            break;
        }
        qjs_workers.mutex.unlock(io);
        const worker = target orelse break;

        qjsWorkerCloseRecord(worker, true);

        qjs_workers.mutex.lockUncancelable(io);
        var index: usize = 0;
        while (index < qjs_workers.workers.len) : (index += 1) {
            if (qjs_workers.workers[index] != worker) continue;
            qjsWorkerRemoveRecordAtLocked(index);
            break;
        }
        qjs_workers.mutex.unlock(io);

        qjsWorkerDestroyRecord(worker);
    }
}

fn qjsWorkerDestroyRecord(worker: *QjsWorker) void {
    const allocator = test262PageAllocator();
    allocator.free(worker.path);
    qjsWorkerFreeMessageQueue(allocator, worker.to_worker, worker.to_worker_capacity);
    qjsWorkerFreeMessageQueue(allocator, worker.to_parent, worker.to_parent_capacity);
    if (worker.object) |value| value.free(worker.owner_runtime);
    allocator.destroy(worker);
}

fn qjsWorkerThreadMain(worker: *QjsWorker) void {
    current_qjs_worker = worker;
    defer {
        current_qjs_worker = null;
    }
    defer {
        const io = qjsWorkerIo();
        qjs_workers.mutex.lockUncancelable(io);
        worker.done = true;
        qjs_workers.cond.broadcast(io);
        qjs_workers.mutex.unlock(io);
    }

    const allocator = test262PageAllocator();
    const rt = core.Runtime.create(allocator) catch return;
    defer rt.destroy();
    defer {
        if (current_qjs_worker_parent) |parent| {
            rt.unregisterExternalValueSymbolRoot(parent);
            parent.free(rt);
            current_qjs_worker_parent = null;
        }
    }
    rt.setCanBlock(true);
    const ctx = core.Context.create(rt) catch return;
    defer ctx.destroy();
    defer qjs_vm.cleanupAtomicsWaitersForContext(ctx);
    const global = qjs_vm.ensureContextGlobal(ctx) catch return;
    const parent = qjsWorkerParentObject(rt) catch return;
    defer parent.free(rt);
    const worker_ns = core.Object.create(rt, core.class.ids.object, null) catch return;
    defer worker_ns.value().free(rt);
    defineValueProperty(rt, worker_ns, "parent", parent) catch return;
    defineValueProperty(rt, global, "Worker", worker_ns.value()) catch return;

    const io = qjsWorkerIo();
    const source = std.Io.Dir.cwd().readFileAlloc(io, worker.path, allocator, .limited(64 * 1024 * 1024)) catch return;
    defer allocator.free(source);
    const result = qjsWorkerEvalModuleGraph(ctx, global, source, worker.path, io, allocator, 64 * 1024 * 1024) catch return;
    result.free(rt);

    while (!qjsWorkerShouldClose(worker)) {
        const delivered = qjsWorkerDispatchOne(ctx, null, global, parent, .worker) catch false;
        drainPendingPromiseJobs(ctx, null, global) catch return;
        if (!delivered) std.Io.sleep(qjsWorkerIo(), std.Io.Duration.fromMilliseconds(1), .awake) catch {};
    }
}

const WorkerModuleEvalStep = union(enum) {
    completed: core.Value,
    suspended: struct {
        continuation: core.Value,
        awaited: core.Value,
    },
};

fn qjsWorkerRegisterModuleEvalStepSymbolRoots(rt: *core.Runtime, step: WorkerModuleEvalStep) !u2 {
    var mask: u2 = 0;
    errdefer qjsWorkerUnregisterModuleEvalStepSymbolRoots(rt, step, mask);
    switch (step) {
        .completed => |value| {
            if (try rt.registerExternalValueSymbolRoot(value)) mask |= 0b01;
        },
        .suspended => |suspended| {
            if (try rt.registerExternalValueSymbolRoot(suspended.continuation)) mask |= 0b01;
            if (try rt.registerExternalValueSymbolRoot(suspended.awaited)) mask |= 0b10;
        },
    }
    return mask;
}

fn qjsWorkerUnregisterModuleEvalStepSymbolRoots(rt: *core.Runtime, step: WorkerModuleEvalStep, mask: u2) void {
    switch (step) {
        .completed => |value| {
            if ((mask & 0b01) != 0) rt.unregisterExternalValueSymbolRoot(value);
        },
        .suspended => |suspended| {
            if ((mask & 0b01) != 0) rt.unregisterExternalValueSymbolRoot(suspended.continuation);
            if ((mask & 0b10) != 0) rt.unregisterExternalValueSymbolRoot(suspended.awaited);
        },
    }
}

test "WorkerModuleEvalStep roots direct symbol values until unregister" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const completed_symbol = try rt.atoms.newValueSymbol("gc-worker-step-completed-symbol");
    const completed_step = WorkerModuleEvalStep{ .completed = core.Value.symbol(completed_symbol) };
    const completed_mask = try qjsWorkerRegisterModuleEvalStepSymbolRoots(rt, completed_step);
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(completed_symbol) != null);
    qjsWorkerUnregisterModuleEvalStepSymbolRoots(rt, completed_step, completed_mask);
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(completed_symbol) == null);

    const continuation_symbol = try rt.atoms.newValueSymbol("gc-worker-step-continuation-symbol");
    const awaited_symbol = try rt.atoms.newValueSymbol("gc-worker-step-awaited-symbol");
    const suspended_step = WorkerModuleEvalStep{ .suspended = .{
        .continuation = core.Value.symbol(continuation_symbol),
        .awaited = core.Value.symbol(awaited_symbol),
    } };
    const suspended_mask = try qjsWorkerRegisterModuleEvalStepSymbolRoots(rt, suspended_step);
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(continuation_symbol) != null);
    try std.testing.expect(rt.atoms.name(awaited_symbol) != null);
    qjsWorkerUnregisterModuleEvalStepSymbolRoots(rt, suspended_step, suspended_mask);
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(continuation_symbol) == null);
    try std.testing.expect(rt.atoms.name(awaited_symbol) == null);
}

const WorkerModuleContinuation = struct {
    source: []const u8,
    path: []const u8,
    continuation: core.Value,
    awaited: core.Value,
    keep_result: bool,
    completed: bool = false,
    symbol_root_mask: u2 = 0,

    fn registerSymbolRoots(self: *WorkerModuleContinuation, rt: *core.Runtime) !void {
        std.debug.assert(self.symbol_root_mask == 0);
        errdefer self.unregisterSymbolRoots(rt);
        if (try rt.registerExternalValueSymbolRoot(self.continuation)) self.symbol_root_mask |= 0b01;
        if (try rt.registerExternalValueSymbolRoot(self.awaited)) self.symbol_root_mask |= 0b10;
    }

    fn unregisterSymbolRoots(self: *WorkerModuleContinuation, rt: *core.Runtime) void {
        if ((self.symbol_root_mask & 0b01) != 0) rt.unregisterExternalValueSymbolRoot(self.continuation);
        if ((self.symbol_root_mask & 0b10) != 0) rt.unregisterExternalValueSymbolRoot(self.awaited);
        self.symbol_root_mask = 0;
    }
};

fn qjsWorkerEvalModuleGraph(
    ctx: *core.Context,
    global: *core.Object,
    source_text: []const u8,
    filename: []const u8,
    io: std.Io,
    allocator: std.mem.Allocator,
    max_source_size: usize,
) !core.Value {
    const normalized_filename = try std.fs.path.resolve(allocator, &.{filename});
    defer allocator.free(normalized_filename);

    var module_postorder = std.ArrayList([]const u8).empty;
    defer {
        for (module_postorder.items) |path| allocator.free(path);
        module_postorder.deinit(allocator);
    }
    try module_mod.preloadFileModuleGraphWithOrder(io, allocator, ctx.runtime, source_text, normalized_filename, max_source_size, &module_postorder);
    const root_module_name = try ctx.runtime.internAtom(normalized_filename);
    defer ctx.runtime.atoms.free(root_module_name);
    ctx.runtime.modules.linkModule(ctx.runtime, root_module_name) catch |err| return qjsWorkerModuleResolutionError(err);
    try qjsWorkerInitializeSyntheticFileModules(ctx, global, io, allocator, max_source_size);
    try qjsWorkerInitializePreloadedModuleFunctionDeclarations(ctx, global, source_text, normalized_filename, io, allocator, max_source_size, module_postorder.items);

    var continuations = std.ArrayList(WorkerModuleContinuation).empty;
    defer qjsWorkerFreeModuleContinuations(ctx.runtime, allocator, &continuations);
    for (module_postorder.items) |path| {
        if (std.mem.eql(u8, path, normalized_filename)) continue;
        try qjsWorkerDrainModuleContinuationsForDependencies(ctx, global, null, allocator, &continuations, path);
        const dep_source = try std.Io.Dir.cwd().readFileAlloc(io, path, allocator, .limited(max_source_size));
        defer allocator.free(dep_source);
        const dep_step = try qjsWorkerEvalPreloadedFileModuleStep(ctx, null, dep_source, path, null, null);
        try qjsWorkerHandleModuleEvalStep(ctx.runtime, allocator, &continuations, dep_step, dep_source, path, false);
        try drainPendingPromiseJobs(ctx, null, global);
        if (ctx.hasException()) return error.UnhandledPromiseRejection;
    }
    try qjsWorkerDrainModuleContinuationsForDependencies(ctx, global, null, allocator, &continuations, normalized_filename);
    const root_step = try qjsWorkerEvalPreloadedFileModuleStep(ctx, null, source_text, normalized_filename, null, null);
    try qjsWorkerHandleModuleEvalStep(ctx.runtime, allocator, &continuations, root_step, source_text, normalized_filename, true);
    return qjsWorkerDrainModuleContinuations(ctx, global, null, allocator, &continuations);
}

fn qjsWorkerInitializePreloadedModuleFunctionDeclarations(
    ctx: *core.Context,
    global: *core.Object,
    root_source: []const u8,
    root_path: []const u8,
    io: std.Io,
    allocator: std.mem.Allocator,
    max_source_size: usize,
    postorder: []const []const u8,
) !void {
    for (postorder) |path| {
        const module_source = if (std.mem.eql(u8, path, root_path))
            root_source
        else
            try std.Io.Dir.cwd().readFileAlloc(io, path, allocator, .limited(max_source_size));
        defer if (!std.mem.eql(u8, path, root_path)) allocator.free(module_source);

        var compiled = try frontend.parser.parse(ctx.runtime, module_source, .{ .mode = .module, .filename = path });
        defer compiled.deinit();
        if (compiled.syntax_error != null) return error.SyntaxError;
        const module_name = try ctx.runtime.internAtom(path);
        defer ctx.runtime.atoms.free(module_name);
        try module_mod.initializeModuleFunctionDeclarations(ctx, global, module_name, &compiled.function);
    }
}

fn qjsWorkerInitializeSyntheticFileModules(
    ctx: *core.Context,
    global: *core.Object,
    io: std.Io,
    allocator: std.mem.Allocator,
    max_source_size: usize,
) !void {
    for (ctx.runtime.modules.modules) |record| {
        if (record.synthetic_kind == .none) continue;
        if (record.synthetic_kind == .native_std or record.synthetic_kind == .native_os) {
            _ = try module_mod.initializeSyntheticFileModule(ctx, global, record.module_name, "");
            continue;
        }
        const path = ctx.runtime.atoms.name(record.module_name) orelse return error.InvalidAtom;
        const source_path = module_mod.syntheticModuleFilePath(path);
        const module_source = try std.Io.Dir.cwd().readFileAlloc(io, source_path, allocator, .limited(max_source_size));
        defer allocator.free(module_source);
        _ = try module_mod.initializeSyntheticFileModule(ctx, global, record.module_name, module_source);
    }
}

fn qjsWorkerEvalPreloadedFileModuleStep(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    source_text: []const u8,
    filename: []const u8,
    continuation_value: ?core.Value,
    resume_value: ?core.Value,
) !WorkerModuleEvalStep {
    var input_continuation = continuation_value;
    errdefer if (input_continuation) |value| value.free(ctx.runtime);

    var compiled = try frontend.parser.parse(ctx.runtime, source_text, .{ .mode = .module, .filename = filename });
    defer compiled.deinit();
    if (compiled.syntax_error != null) return error.SyntaxError;

    const module_name = try ctx.runtime.internAtom(filename);
    defer ctx.runtime.atoms.free(module_name);
    if (ctx.runtime.modules.find(module_name) == null) return error.ModuleNotFound;
    ctx.runtime.modules.linkModule(ctx.runtime, module_name) catch |err| return qjsWorkerModuleResolutionError(err);

    const module_var_refs = try module_mod.buildModuleVarRefs(ctx, module_name, &compiled.function);
    defer module_mod.freeModuleVarRefs(ctx.runtime, module_var_refs);
    var owned_continuation = if (input_continuation) |value| blk: {
        input_continuation = null;
        break :blk value;
    } else blk: {
        const object = try core.Object.create(ctx.runtime, core.class.ids.generator, null);
        break :blk object.value();
    };
    errdefer owned_continuation.free(ctx.runtime);
    const continuation = try property_ops.expectObject(owned_continuation);
    var stack = stack_mod.Stack.init(&ctx.runtime.memory, ctx.stack_limit);
    defer stack.deinit(ctx.runtime);
    const result = qjs_vm.runModuleWithOutputAndVarRefsState(ctx, &stack, &compiled.function, output, module_var_refs, continuation, resume_value) catch |err| return qjsWorkerModuleResolutionError(err);
    if (continuation.generatorJustYielded() and !continuation.generatorDone()) {
        return .{ .suspended = .{
            .continuation = owned_continuation,
            .awaited = result,
        } };
    }
    owned_continuation.free(ctx.runtime);
    return .{ .completed = result };
}

fn qjsWorkerHandleModuleEvalStep(
    rt: *core.Runtime,
    allocator: std.mem.Allocator,
    continuations: *std.ArrayList(WorkerModuleContinuation),
    step: WorkerModuleEvalStep,
    source_text: []const u8,
    filename: []const u8,
    keep_result: bool,
) !void {
    switch (step) {
        .completed => |value| {
            if (keep_result) {
                errdefer value.free(rt);
                const source_copy = try allocator.dupe(u8, source_text);
                errdefer allocator.free(source_copy);
                const path_copy = try allocator.dupe(u8, filename);
                errdefer allocator.free(path_copy);
                var continuation = WorkerModuleContinuation{
                    .source = source_copy,
                    .path = path_copy,
                    .continuation = core.Value.undefinedValue(),
                    .awaited = value,
                    .keep_result = true,
                    .completed = true,
                };
                try continuation.registerSymbolRoots(rt);
                errdefer continuation.unregisterSymbolRoots(rt);
                try continuations.append(allocator, continuation);
            } else {
                value.free(rt);
            }
        },
        .suspended => |suspended| {
            errdefer suspended.continuation.free(rt);
            errdefer suspended.awaited.free(rt);
            const source_copy = try allocator.dupe(u8, source_text);
            errdefer allocator.free(source_copy);
            const path_copy = try allocator.dupe(u8, filename);
            errdefer allocator.free(path_copy);
            var continuation = WorkerModuleContinuation{
                .source = source_copy,
                .path = path_copy,
                .continuation = suspended.continuation,
                .awaited = suspended.awaited,
                .keep_result = keep_result,
            };
            try continuation.registerSymbolRoots(rt);
            errdefer continuation.unregisterSymbolRoots(rt);
            try continuations.append(allocator, continuation);
        },
    }
}

fn qjsWorkerDrainModuleContinuations(
    ctx: *core.Context,
    global: *core.Object,
    output: ?*std.Io.Writer,
    allocator: std.mem.Allocator,
    continuations: *std.ArrayList(WorkerModuleContinuation),
) !core.Value {
    var kept_result: core.Value = core.Value.undefinedValue();
    var has_kept_result = false;
    var kept_result_symbol_rooted = false;
    errdefer if (has_kept_result) kept_result.free(ctx.runtime);
    defer if (kept_result_symbol_rooted) ctx.runtime.unregisterExternalValueSymbolRoot(kept_result);
    while (continuations.items.len != 0) {
        if (try qjsWorkerDrainOneModuleContinuation(ctx, global, output, allocator, continuations)) |value| {
            errdefer value.free(ctx.runtime);
            const value_symbol_rooted = try ctx.runtime.registerExternalValueSymbolRoot(value);
            if (has_kept_result) {
                if (kept_result_symbol_rooted) ctx.runtime.unregisterExternalValueSymbolRoot(kept_result);
                kept_result_symbol_rooted = false;
                kept_result.free(ctx.runtime);
            }
            kept_result = value;
            kept_result_symbol_rooted = value_symbol_rooted;
            has_kept_result = true;
        }
    }
    if (has_kept_result) return kept_result;
    return core.Value.undefinedValue();
}

fn qjsWorkerDrainModuleContinuationsForDependencies(
    ctx: *core.Context,
    global: *core.Object,
    output: ?*std.Io.Writer,
    allocator: std.mem.Allocator,
    continuations: *std.ArrayList(WorkerModuleContinuation),
    filename: []const u8,
) !void {
    while (try qjsWorkerHasActiveAsyncDependency(ctx, continuations, filename)) {
        if (try qjsWorkerDrainOneModuleContinuation(ctx, global, output, allocator, continuations)) |value| value.free(ctx.runtime);
    }
}

fn qjsWorkerDrainOneModuleContinuation(
    ctx: *core.Context,
    global: *core.Object,
    output: ?*std.Io.Writer,
    allocator: std.mem.Allocator,
    continuations: *std.ArrayList(WorkerModuleContinuation),
) !?core.Value {
    var current = continuations.orderedRemove(0);
    var current_roots_registered = true;
    errdefer if (current_roots_registered) current.unregisterSymbolRoots(ctx.runtime);
    defer allocator.free(current.source);
    defer allocator.free(current.path);
    if (current.completed) {
        current.unregisterSymbolRoots(ctx.runtime);
        current_roots_registered = false;
        if (current.keep_result) return current.awaited;
        current.awaited.free(ctx.runtime);
        return null;
    }
    const awaited_value = current.awaited;
    var awaited_owned = true;
    errdefer if (awaited_owned) awaited_value.free(ctx.runtime);
    const continuation = current.continuation;
    var continuation_owned = true;
    errdefer if (continuation_owned) continuation.free(ctx.runtime);
    const module_source = current.source;
    const path = current.path;
    const keep_result = current.keep_result;
    try drainPendingPromiseJobs(ctx, output, global);
    continuation_owned = false;
    const step = try qjsWorkerEvalPreloadedFileModuleStep(ctx, output, module_source, path, continuation, awaited_value);
    awaited_value.free(ctx.runtime);
    awaited_owned = false;
    current.unregisterSymbolRoots(ctx.runtime);
    current_roots_registered = false;
    var step_owned = true;
    errdefer if (step_owned) qjsWorkerFreeModuleEvalStep(ctx.runtime, step);
    const step_symbol_root_mask = try qjsWorkerRegisterModuleEvalStepSymbolRoots(ctx.runtime, step);
    var step_roots_registered = true;
    errdefer if (step_roots_registered) qjsWorkerUnregisterModuleEvalStepSymbolRoots(ctx.runtime, step, step_symbol_root_mask);
    try drainPendingPromiseJobs(ctx, output, global);
    if (ctx.hasException()) return error.UnhandledPromiseRejection;
    qjsWorkerUnregisterModuleEvalStepSymbolRoots(ctx.runtime, step, step_symbol_root_mask);
    step_roots_registered = false;
    step_owned = false;
    try qjsWorkerHandleModuleEvalStep(ctx.runtime, allocator, continuations, step, module_source, path, keep_result);
    return null;
}

fn qjsWorkerHasActiveAsyncDependency(
    ctx: *core.Context,
    continuations: *const std.ArrayList(WorkerModuleContinuation),
    filename: []const u8,
) !bool {
    const module_name = try ctx.runtime.internAtom(filename);
    defer ctx.runtime.atoms.free(module_name);
    const record = ctx.runtime.modules.find(module_name) orelse return false;
    var visited = std.ArrayList(core.Atom).empty;
    defer visited.deinit(ctx.runtime.memory.allocator);
    return qjsWorkerRecordHasActiveAsyncDependency(ctx, continuations, record, &visited);
}

fn qjsWorkerRecordHasActiveAsyncDependency(
    ctx: *core.Context,
    continuations: *const std.ArrayList(WorkerModuleContinuation),
    record: *const core.module.ModuleRecord,
    visited: *std.ArrayList(core.Atom),
) !bool {
    for (visited.items) |seen| {
        if (seen == record.module_name) return false;
    }
    try visited.append(ctx.runtime.memory.allocator, record.module_name);
    for (record.requested_modules) |request| {
        const request_name = ctx.runtime.atoms.name(request) orelse continue;
        for (continuations.items) |continuation| {
            if (!continuation.completed and std.mem.eql(u8, continuation.path, request_name)) return true;
        }
        const requested_record = ctx.runtime.modules.find(request) orelse continue;
        if (try qjsWorkerRecordHasActiveAsyncDependency(ctx, continuations, requested_record, visited)) return true;
    }
    return false;
}

fn qjsWorkerFreeModuleContinuations(
    rt: *core.Runtime,
    allocator: std.mem.Allocator,
    continuations: *std.ArrayList(WorkerModuleContinuation),
) void {
    for (continuations.items) |*entry| {
        allocator.free(entry.source);
        allocator.free(entry.path);
        entry.unregisterSymbolRoots(rt);
        if (!entry.completed) entry.continuation.free(rt);
        entry.awaited.free(rt);
    }
    continuations.deinit(allocator);
}

fn qjsWorkerFreeModuleEvalStep(rt: *core.Runtime, step: WorkerModuleEvalStep) void {
    switch (step) {
        .completed => |value| value.free(rt),
        .suspended => |suspended| {
            suspended.continuation.free(rt);
            suspended.awaited.free(rt);
        },
    }
}

fn qjsWorkerModuleResolutionError(err: anytype) (@TypeOf(err) || error{SyntaxError}) {
    return switch (err) {
        error.MissingExport, error.AmbiguousExport => error.SyntaxError,
        else => err,
    };
}

fn qjsWorkerShouldClose(worker: *QjsWorker) bool {
    const io = qjsWorkerIo();
    qjs_workers.mutex.lockUncancelable(io);
    defer qjs_workers.mutex.unlock(io);
    return worker.closing;
}

pub fn qjsWorkerPostMessage(ctx: *core.Context, this_value: core.Value, args: []const core.Value, target: WorkerPostTarget) !core.Value {
    var rooted_this = this_value;
    var rooted_payload = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_this },
        .{ .value = &rooted_payload },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    const worker_id = try qjsWorkerObjectId(ctx.runtime, rooted_this);
    const payload = try qjsWorkerMessageFromValue(ctx.runtime, rooted_payload);
    errdefer payload.deinit(test262PageAllocator());
    const io = qjsWorkerIo();
    qjs_workers.mutex.lockUncancelable(io);
    defer qjs_workers.mutex.unlock(io);
    const worker = qjsWorkerByIdLocked(worker_id) orelse return error.TypeError;
    const queue = switch (target) {
        .worker => &worker.to_worker,
        .parent => &worker.to_parent,
    };
    const capacity = switch (target) {
        .worker => &worker.to_worker_capacity,
        .parent => &worker.to_parent_capacity,
    };
    try qjsWorkerAppendMessage(queue, capacity, payload);
    qjs_workers.cond.broadcast(io);
    return core.Value.undefinedValue();
}

pub fn qjsWorkerPoll(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object) !core.Value {
    var delivered: i32 = 0;
    while (try qjsWorkerDispatchAnyForRuntime(ctx, output, global)) delivered += 1;
    return core.Value.int32(delivered);
}

pub fn qjsWorkerSleep(args: []const core.Value) !core.Value {
    const value = if (args.len >= 1) args[0] else core.Value.int32(0);
    const number = value_ops.numberValue(value) orelse 0;
    if (number > 0) {
        const ms: i64 = @intFromFloat(@min(number, 60_000));
        std.Io.sleep(qjsWorkerIo(), std.Io.Duration.fromMilliseconds(ms), .awake) catch {};
    }
    return core.Value.undefinedValue();
}

fn qjsWorkerDispatchAnyForRuntime(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object) !bool {
    const io = qjsWorkerIo();
    qjs_workers.mutex.lockUncancelable(io);
    var selected: ?*QjsWorker = null;
    var object_value: core.Value = core.Value.undefinedValue();
    for (qjs_workers.workers) |worker| {
        if (worker.owner_runtime != ctx.runtime or worker.to_parent.len == 0) continue;
        if (worker.object) |stored| {
            object_value = stored.dup();
            selected = worker;
            break;
        }
    }
    qjs_workers.mutex.unlock(io);
    if (selected == null) return false;
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return false;
    const handler_key = try ctx.runtime.internAtom("onmessage");
    defer ctx.runtime.atoms.free(handler_key);
    const handler = object.getProperty(handler_key);
    if (!isCallableValue(handler)) {
        handler.free(ctx.runtime);
        return false;
    }
    handler.free(ctx.runtime);
    return qjsWorkerDispatchOne(ctx, output, global, object_value, .parent);
}

fn qjsWorkerDispatchOne(ctx: *core.Context, output: ?*std.Io.Writer, global: *core.Object, endpoint_value: core.Value, endpoint: WorkerPostTarget) !bool {
    var rooted_endpoint_value = endpoint_value;
    var handler = core.Value.undefinedValue();
    var data = core.Value.undefinedValue();
    var event_value = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_endpoint_value },
        .{ .value = &handler },
        .{ .value = &data },
        .{ .value = &event_value },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    const endpoint_object = objectFromValue(rooted_endpoint_value) orelse return false;
    const handler_key = try ctx.runtime.internAtom("onmessage");
    defer ctx.runtime.atoms.free(handler_key);
    handler = endpoint_object.getProperty(handler_key);
    defer {
        const owned_handler = handler;
        handler = core.Value.undefinedValue();
        owned_handler.free(ctx.runtime);
    }
    if (!isCallableValue(handler)) return false;
    const worker_id = try qjsWorkerObjectId(ctx.runtime, rooted_endpoint_value);
    const message = qjsWorkerPopMessage(worker_id, endpoint) orelse return false;
    defer message.deinit(test262PageAllocator());
    data = try qjsWorkerMessageToValue(ctx.runtime, message);
    defer {
        const owned_data = data;
        data = core.Value.undefinedValue();
        owned_data.free(ctx.runtime);
    }
    const event = try core.Object.create(ctx.runtime, core.class.ids.object, null);
    event_value = event.value();
    defer {
        const owned_event = event_value;
        event_value = core.Value.undefinedValue();
        owned_event.free(ctx.runtime);
    }
    try defineValueProperty(ctx.runtime, event, "data", data);
    const result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), handler, &.{event_value}, null, null);
    result.free(ctx.runtime);
    return true;
}

fn qjsWorkerByIdLocked(id: i32) ?*QjsWorker {
    for (qjs_workers.workers) |worker| {
        if (worker.id == id) return worker;
    }
    return null;
}

fn qjsWorkerEnsureRecordCapacity(min_capacity: usize) !void {
    if (qjs_workers.workers_capacity >= min_capacity) return;
    const allocator = test262PageAllocator();
    var next_capacity = if (qjs_workers.workers_capacity == 0) @as(usize, 4) else qjs_workers.workers_capacity * 2;
    while (next_capacity < min_capacity) : (next_capacity *= 2) {}
    const next = try allocator.alloc(*QjsWorker, next_capacity);
    @memcpy(next[0..qjs_workers.workers.len], qjs_workers.workers);
    if (qjs_workers.workers_capacity != 0) allocator.free(qjs_workers.workers.ptr[0..qjs_workers.workers_capacity]);
    qjs_workers.workers = next[0..qjs_workers.workers.len];
    qjs_workers.workers_capacity = next_capacity;
}

fn qjsWorkerRemoveRecordAtLocked(index: usize) void {
    std.debug.assert(index < qjs_workers.workers.len);
    const old_len = qjs_workers.workers.len;
    if (index + 1 < old_len) {
        @memmove(qjs_workers.workers[index .. old_len - 1], qjs_workers.workers[index + 1 .. old_len]);
    }
    qjs_workers.workers = qjs_workers.workers.ptr[0 .. old_len - 1];
    if (qjs_workers.workers.len == 0 and qjs_workers.workers_capacity != 0) {
        const allocator = test262PageAllocator();
        allocator.free(qjs_workers.workers.ptr[0..qjs_workers.workers_capacity]);
        qjs_workers.workers = &.{};
        qjs_workers.workers_capacity = 0;
    }
}

fn qjsWorkerRemoveRecord(worker: *QjsWorker) void {
    const io = qjsWorkerIo();
    qjs_workers.mutex.lockUncancelable(io);
    defer qjs_workers.mutex.unlock(io);
    var index: usize = 0;
    while (index < qjs_workers.workers.len) : (index += 1) {
        if (qjs_workers.workers[index] != worker) continue;
        qjsWorkerRemoveRecordAtLocked(index);
        return;
    }
}

fn qjsWorkerFreeMessageQueue(allocator: std.mem.Allocator, queue: []WorkerMessage, capacity: usize) void {
    for (queue) |message| message.deinit(allocator);
    if (capacity != 0) allocator.free(queue.ptr[0..capacity]);
}

fn qjsWorkerEnsureMessageCapacity(queue: *[]WorkerMessage, capacity: *usize, min_capacity: usize) !void {
    const allocator = test262PageAllocator();
    if (capacity.* >= min_capacity) return;
    var next_capacity = if (capacity.* == 0) @as(usize, 4) else capacity.* * 2;
    while (next_capacity < min_capacity) : (next_capacity *= 2) {}
    const next = try allocator.alloc(WorkerMessage, next_capacity);
    @memcpy(next[0..queue.*.len], queue.*);
    const old_capacity = capacity.*;
    const old = if (old_capacity != 0) queue.*.ptr[0..old_capacity] else queue.*[0..0];
    queue.* = next[0..queue.*.len];
    capacity.* = next_capacity;
    if (old_capacity != 0) allocator.free(old);
}

fn qjsWorkerAppendMessage(queue: *[]WorkerMessage, capacity: *usize, message: WorkerMessage) !void {
    const index = queue.*.len;
    try qjsWorkerEnsureMessageCapacity(queue, capacity, index + 1);
    queue.* = queue.*.ptr[0 .. index + 1];
    queue.*[index] = message;
}

fn qjsWorkerPopMessage(id: i32, endpoint: WorkerPostTarget) ?WorkerMessage {
    const allocator = test262PageAllocator();
    const io = qjsWorkerIo();
    qjs_workers.mutex.lockUncancelable(io);
    defer qjs_workers.mutex.unlock(io);
    const worker = qjsWorkerByIdLocked(id) orelse return null;
    const queue = switch (endpoint) {
        .worker => &worker.to_worker,
        .parent => &worker.to_parent,
    };
    const capacity = switch (endpoint) {
        .worker => &worker.to_worker_capacity,
        .parent => &worker.to_parent_capacity,
    };
    if (queue.*.len == 0) return null;
    const message = queue.*[0];
    const old_len = queue.*.len;
    if (old_len == 1) {
        const old = queue.*.ptr[0..capacity.*];
        queue.* = &.{};
        capacity.* = 0;
        allocator.free(old);
    } else {
        @memmove(queue.*[0 .. old_len - 1], queue.*[1..old_len]);
        queue.* = queue.*.ptr[0 .. old_len - 1];
    }
    return message;
}

fn qjsWorkerMessageFromValue(rt: *core.Runtime, value: core.Value) !WorkerMessage {
    var rooted_value = value;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_value },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    if (rooted_value.isUndefined()) return .undefined;
    if (rooted_value.isNull()) return .null;
    if (rooted_value.asBool()) |bool_value| return .{ .boolean = bool_value };
    if (rooted_value.asInt32()) |int_value| return .{ .int32 = int_value };
    if (value_ops.numberValue(rooted_value)) |number| return .{ .float64 = number };
    if (rooted_value.isString()) {
        var bytes = std.ArrayList(u8).empty;
        defer bytes.deinit(rt.memory.allocator);
        try appendSourceStringUtf8(rt, &bytes, rooted_value);
        return .{ .string = try test262PageAllocator().dupe(u8, bytes.items) };
    }
    if (objectFromValue(rooted_value)) |object| {
        if (object.class_id == core.class.ids.shared_array_buffer) {
            const store = object.sharedByteStorageStore() orelse return error.TypeError;
            store.retain();
            return .{ .shared_array_buffer = .{ .store = store, .max_byte_length = object.arrayBufferMaxByteLength() } };
        }
    }
    return error.TypeError;
}

fn qjsWorkerMessageToValue(rt: *core.Runtime, message: WorkerMessage) !core.Value {
    return switch (message) {
        .undefined => core.Value.undefinedValue(),
        .null => core.Value.nullValue(),
        .boolean => |value| core.Value.boolean(value),
        .int32 => |value| core.Value.int32(value),
        .float64 => |value| core.Value.float64(value),
        .string => |bytes| value_ops.createStringValue(rt, bytes),
        .shared_array_buffer => |entry| builtins.buffer.sharedArrayBufferFromStore(rt, entry.store, entry.max_byte_length, null),
    };
}

pub fn replaceFrameVarRefBinding(rt: *core.Runtime, frame: *frame_mod.Frame, atom_id: core.Atom, value: core.Value) void {
    const count = @min(frame.function.var_ref_names.len, frame.var_refs.len);
    for (frame.function.var_ref_names[0..count], 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id)) continue;
        const next = value.dup();
        const old_value = frame.var_refs[idx];
        frame.var_refs[idx] = next;
        old_value.free(rt);
        return;
    }
}

pub fn indirectEval(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    eval_global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len == 0) return core.Value.undefinedValue();
    if (!args[0].isString()) return args[0].dup();
    var source = std.ArrayList(u8).empty;
    defer source.deinit(ctx.runtime.memory.allocator);
    try appendSourceStringUtf8(ctx.runtime, &source, args[0]);
    if (try simpleEvalRegExpLiteral(ctx, eval_global, source.items)) |value| return value;
    var compiled = try frontend.parser.parse(ctx.runtime, source.items, .{ .mode = .eval_indirect, .filename = "<eval>", .strict = false });
    defer compiled.deinit();
    if (compiled.syntax_error != null) return error.SyntaxError;
    if (!compiled.function.flags.is_strict) {
        try validateGlobalEvalFunctionDeclarations(ctx, eval_global, source.items, true);
    }
    var nested_stack = stack_mod.Stack.init(&ctx.runtime.memory, ctx.runtime.stack_size);
    defer nested_stack.deinit(ctx.runtime);
    return runWithArgsState(ctx, &nested_stack, &compiled.function, eval_global.value(), &.{}, &.{}, output, eval_global, true, false, false, &.{}, &.{}, &.{}, &.{}, &.{}, &.{}, &.{}, &.{}, null, null, null, core.Value.undefinedValue(), core.Value.undefinedValue(), core.Value.undefinedValue(), true, true, core.Value.undefinedValue(), false, false) catch |err| {
        return normalizeEvalRuntimeError(err);
    };
}

pub fn appendSourceStringUtf8(rt: *core.Runtime, buffer: *std.ArrayList(u8), value: core.Value) !void {
    const header = value.refHeader() orelse return error.TypeError;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    switch (string_value.resolveData()) {
        .latin1 => |bytes| {
            for (bytes) |byte| {
                if (byte < 0x80) {
                    try buffer.append(rt.memory.allocator, byte);
                } else {
                    try appendCodepointUtf8(rt, buffer, byte);
                }
            }
        },
        .utf16 => |units| {
            for (units) |unit| try appendCodepointUtf8(rt, buffer, unit);
        },
    }
}

pub fn appendCodepointUtf8(rt: *core.Runtime, buffer: *std.ArrayList(u8), codepoint: u21) !void {
    if (codepoint <= 0x7f) {
        try buffer.append(rt.memory.allocator, @intCast(codepoint));
    } else if (codepoint <= 0x7ff) {
        try buffer.append(rt.memory.allocator, @intCast(0xc0 | (codepoint >> 6)));
        try buffer.append(rt.memory.allocator, @intCast(0x80 | (codepoint & 0x3f)));
    } else if (codepoint <= 0xffff) {
        try buffer.append(rt.memory.allocator, @intCast(0xe0 | (codepoint >> 12)));
        try buffer.append(rt.memory.allocator, @intCast(0x80 | ((codepoint >> 6) & 0x3f)));
        try buffer.append(rt.memory.allocator, @intCast(0x80 | (codepoint & 0x3f)));
    } else {
        try buffer.append(rt.memory.allocator, @intCast(0xf0 | (codepoint >> 18)));
        try buffer.append(rt.memory.allocator, @intCast(0x80 | ((codepoint >> 12) & 0x3f)));
        try buffer.append(rt.memory.allocator, @intCast(0x80 | ((codepoint >> 6) & 0x3f)));
        try buffer.append(rt.memory.allocator, @intCast(0x80 | (codepoint & 0x3f)));
    }
}

pub fn simpleEvalRegExpLiteral(ctx: *core.Context, global: *core.Object, source: []const u8) !?core.Value {
    const trimmed = std.mem.trim(u8, source, " \t\r\n");
    if (trimmed.len == 0 or trimmed[0] != '/') return null;
    if (trimmed.len >= 2 and (trimmed[1] == '*' or trimmed[1] == '/')) return null;
    const literal = frontend.regexp_literal.scan(trimmed, 0) catch return null;
    if (literal.end_offset != trimmed.len) return null;
    if (containsUtf8LineSeparator(literal.pattern)) return null;
    return try builtins.regexp.constructLiteral(ctx.runtime, literal.pattern, literal.flags, constructorPrototypeFromGlobal(ctx.runtime, global, "RegExp"));
}

pub fn containsUtf8LineSeparator(bytes: []const u8) bool {
    var index: usize = 0;
    while (index + 2 < bytes.len) : (index += 1) {
        if (bytes[index] == 0xe2 and bytes[index + 1] == 0x80 and
            (bytes[index + 2] == 0xa8 or bytes[index + 2] == 0xa9)) return true;
    }
    return false;
}

pub fn evalSimpleCallerExpression(
    ctx: *core.Context,
    source: []const u8,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const frame = caller_frame orelse return null;
    const trimmed = std.mem.trim(u8, source, " \t\r\n");
    if (simpleEvalStringLiteral(ctx.runtime, trimmed)) |value| return value;
    if (std.mem.eql(u8, trimmed, "this")) return directEvalThisValue(ctx.runtime, caller_function, caller_frame).dup();
    if (std.mem.startsWith(u8, trimmed, "delete ")) {
        const ident = std.mem.trim(u8, trimmed["delete ".len..], " \t\r\n");
        if (isSimpleIdentifierName(ident) and callerFunctionHasBinding(ctx.runtime, caller_function, frame, ident)) {
            return core.Value.boolean(false);
        }
        return null;
    }
    if (std.mem.indexOfScalar(u8, trimmed, '=')) |eq| {
        const lhs = std.mem.trim(u8, trimmed[0..eq], " \t\r\n");
        const rhs = std.mem.trim(u8, trimmed[eq + 1 ..], " \t\r\n");
        if (isSimpleIdentifierName(lhs) and isSimpleIntegerLiteral(rhs) and callerFunctionNameEql(ctx.runtime, caller_function, lhs)) {
            if (caller_function) |function| {
                if (function.flags.is_strict) return error.TypeError;
            }
            return core.Value.undefinedValue();
        }
    }
    return null;
}

pub fn simpleEvalStringLiteral(rt: *core.Runtime, source: []const u8) ?core.Value {
    if (source.len < 2 or source[0] != '"' or source[source.len - 1] != '"') return null;
    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(rt.memory.allocator);
    var index: usize = 1;
    while (index + 1 < source.len) : (index += 1) {
        const ch = source[index];
        if (ch == '\\') {
            index += 1;
            if (index + 1 >= source.len) return null;
            const escaped = switch (source[index]) {
                '"', '\\', '/' => source[index],
                'b' => 0x08,
                'f' => 0x0c,
                'n' => '\n',
                'r' => '\r',
                't' => '\t',
                else => return null,
            };
            bytes.append(rt.memory.allocator, escaped) catch return null;
            continue;
        }
        bytes.append(rt.memory.allocator, ch) catch return null;
    }
    return value_ops.createStringValue(rt, bytes.items) catch null;
}

pub fn isSimpleIdentifierName(name: []const u8) bool {
    if (name.len == 0) return false;
    if (!(std.ascii.isAlphabetic(name[0]) or name[0] == '_' or name[0] == '$')) return false;
    for (name[1..]) |ch| {
        if (!(std.ascii.isAlphanumeric(ch) or ch == '_' or ch == '$')) return false;
    }
    return true;
}

pub fn isSimpleIntegerLiteral(text: []const u8) bool {
    _ = std.fmt.parseInt(i32, text, 10) catch return false;
    return true;
}

pub fn callerFunctionNameEql(rt: *core.Runtime, caller_function: ?*const bytecode.Bytecode, name: []const u8) bool {
    const function = caller_function orelse return false;
    const function_name = rt.atoms.name(function.name) orelse return false;
    return std.mem.eql(u8, function_name, name);
}

pub fn simpleVarDeclarationName(source: []const u8) ?[]const u8 {
    const trimmed = std.mem.trim(u8, source, " \t\r\n");
    if (!std.mem.startsWith(u8, trimmed, "var ")) return null;
    const rest = std.mem.trim(u8, trimmed["var ".len..], " \t\r\n");
    var end: usize = 0;
    while (end < rest.len and (std.ascii.isAlphanumeric(rest[end]) or rest[end] == '_' or rest[end] == '$')) : (end += 1) {}
    if (end == 0) return null;
    const name = rest[0..end];
    const tail = std.mem.trim(u8, rest[end..], " \t\r\n");
    if (tail.len != 0 and tail[0] != '=' and tail[0] != ';') return null;
    return if (isSimpleIdentifierName(name)) name else null;
}

pub fn callerFunctionHasArg(rt: *core.Runtime, function: *const bytecode.Bytecode, name: []const u8) bool {
    for (function.arg_names) |atom_id| {
        const arg_name = rt.atoms.name(atom_id) orelse continue;
        if (std.mem.eql(u8, arg_name, name)) return true;
    }
    return false;
}

pub fn callerFunctionHasLexicalLocal(rt: *core.Runtime, function: *const bytecode.Bytecode, name: []const u8) bool {
    const local_count = @min(function.var_names.len, function.var_is_lexical.len);
    for (function.var_names[0..local_count], 0..) |atom_id, idx| {
        if (!function.var_is_lexical[idx]) continue;
        const local_name = rt.atoms.name(atom_id) orelse continue;
        if (std.mem.eql(u8, local_name, name)) return true;
    }
    return false;
}

pub fn callerFunctionHasBinding(
    rt: *core.Runtime,
    caller_function: ?*const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    name: []const u8,
) bool {
    const function = caller_function orelse return false;
    const local_count = @min(function.var_names.len, frame.locals.len);
    for (function.var_names[0..local_count]) |atom_id| {
        if (value_ops.atomNameEql(rt, atom_id, name)) return true;
    }
    const ref_count = @min(function.var_ref_names.len, frame.var_refs.len);
    for (function.var_ref_names[0..ref_count]) |atom_id| {
        if (value_ops.atomNameEql(rt, atom_id, name)) return true;
    }
    return false;
}

pub fn functionHasFrameBinding(
    rt: *core.Runtime,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    atom_id: core.Atom,
) bool {
    const local_count = @min(function.var_names.len, frame.locals.len);
    for (function.var_names[0..local_count]) |binding| {
        if (binding == atom_id or atomNamesEqual(rt, binding, atom_id)) return true;
    }
    const ref_count = @min(function.var_ref_names.len, frame.var_refs.len);
    for (function.var_ref_names[0..ref_count]) |binding| {
        if (binding == atom_id or atomNamesEqual(rt, binding, atom_id)) return true;
    }
    return false;
}

pub fn atomNamesEqual(rt: *core.Runtime, a: core.Atom, b: core.Atom) bool {
    const a_name = rt.atoms.name(a) orelse return false;
    const b_name = rt.atoms.name(b) orelse return false;
    return std.mem.eql(u8, a_name, b_name);
}

pub fn putDenseArrayElementFast(rt: *core.Runtime, object_value: core.Value, key: core.Value, value: core.Value) !bool {
    const object = property_ops.expectObject(object_value) catch return false;
    if (!object.is_array) return false;
    const number = value_ops.numberValue(key) orelse return false;
    if (std.math.isNan(number) or !std.math.isFinite(number) or number < 0 or number > core.array.max_array_index or @trunc(number) != number) return false;
    const index: u32 = @intFromFloat(number);
    if (index > core.atom.max_int_atom) return false;
    const atom_id = core.atom.atomFromUInt32(index);
    return try object.appendDenseArrayIndex(rt, index, atom_id, value);
}

pub fn argsFromArray(rt: *core.Runtime, array_value: core.Value) ![]core.Value {
    const array = try property_ops.expectObject(array_value);
    if (!array.is_array) return error.TypeError;
    if (array.length == 0) return &.{};
    const args = try rt.memory.alloc(core.Value, array.length);
    errdefer rt.memory.free(core.Value, args);
    var initialized: usize = 0;
    errdefer {
        for (args[0..initialized]) |value| value.free(rt);
    }
    var index: u32 = 0;
    while (index < array.length) : (index += 1) {
        args[index] = array.getProperty(core.atom.atomFromUInt32(index));
        initialized += 1;
    }
    return args;
}

pub fn argsFromArrayLike(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    array_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) ![]core.Value {
    const object = objectFromValue(array_value) orelse return error.TypeError;
    if (object.is_array) return argsFromArray(ctx.runtime, array_value);

    const length_value = try getValueProperty(ctx, output, global, array_value, core.atom.ids.length, caller_function, caller_frame);
    defer length_value.free(ctx.runtime);
    const length = try toLengthIndex(ctx, output, global, length_value);
    if (length == 0) return &.{};
    const args = try ctx.runtime.memory.alloc(core.Value, length);
    errdefer ctx.runtime.memory.free(core.Value, args);
    var initialized: usize = 0;
    errdefer {
        for (args[0..initialized]) |value| value.free(ctx.runtime);
    }
    var index: usize = 0;
    while (index < length) : (index += 1) {
        const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
        defer key.deinit(ctx.runtime);
        args[index] = try getValueProperty(ctx, output, global, array_value, key.atom, caller_function, caller_frame);
        initialized += 1;
    }
    return args;
}

pub fn freeArgs(rt: *core.Runtime, args: []core.Value) void {
    for (args) |arg| arg.free(rt);
    if (args.len != 0) rt.memory.free(core.Value, args);
}

pub fn callFunctionBytecode(
    ctx: *core.Context,
    func: core.Value,
    current_function_value: core.Value,
    this_value: core.Value,
    args: []const core.Value,
    var_refs: []const core.Value,
    output: ?*std.Io.Writer,
    global: *core.Object,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
) !core.Value {
    return callFunctionBytecodeMode(ctx, func, current_function_value, this_value, args, var_refs, output, global, eval_var_ref_names, eval_var_refs, true);
}

pub fn callFunctionBytecodeConstruct(
    ctx: *core.Context,
    func: core.Value,
    current_function_value: core.Value,
    this_value: core.Value,
    args: []const core.Value,
    var_refs: []const core.Value,
    output: ?*std.Io.Writer,
    global: *core.Object,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    new_target_value: core.Value,
    constructor_this_value: core.Value,
) !core.Value {
    return callFunctionBytecodeModeState(ctx, func, current_function_value, this_value, args, var_refs, output, global, eval_var_ref_names, eval_var_refs, true, null, null, null, new_target_value, constructor_this_value);
}

pub fn callFunctionBytecodeMode(
    ctx: *core.Context,
    func: core.Value,
    current_function_value: core.Value,
    this_value: core.Value,
    args: []const core.Value,
    var_refs: []const core.Value,
    output: ?*std.Io.Writer,
    global: *core.Object,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    defer_generators: bool,
) !core.Value {
    return callFunctionBytecodeModeState(ctx, func, current_function_value, this_value, args, var_refs, output, global, eval_var_ref_names, eval_var_refs, defer_generators, null, null, null, core.Value.undefinedValue(), core.Value.undefinedValue());
}

pub fn callFunctionBytecodeModeState(
    ctx: *core.Context,
    func: core.Value,
    current_function_value: core.Value,
    this_value: core.Value,
    args: []const core.Value,
    var_refs: []const core.Value,
    output: ?*std.Io.Writer,
    global: *core.Object,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    defer_generators: bool,
    generator_state: ?*core.Object,
    resume_value: ?core.Value,
    stop_before_pc: ?usize,
    new_target_value: core.Value,
    constructor_this_value: core.Value,
) HostError!core.Value {
    const fb = functionBytecodeFromValue(func) orelse return error.TypeError;
    if (defer_generators and (fb.func_kind == .generator or fb.func_kind == .async_generator)) {
        return createGeneratorObject(ctx, func, current_function_value, this_value, args, var_refs, output, global, eval_var_ref_names, eval_var_refs, fb.func_kind == .async_generator);
    }

    var nested = fb.asBytecodeView(ctx.runtime);

    var combined_var_refs: []const core.Value = var_refs;
    var allocated_combined_refs: []core.Value = &.{};
    defer if (allocated_combined_refs.len != 0) ctx.runtime.memory.free(core.Value, allocated_combined_refs);
    var allocated_var_ref_names: []core.Atom = &.{};
    defer {
        for (allocated_var_ref_names) |atom_id| ctx.runtime.atoms.free(atom_id);
        if (allocated_var_ref_names.len != 0) ctx.runtime.memory.free(core.Atom, allocated_var_ref_names);
    }
    if (eval_var_ref_names.len > 0 and eval_var_refs.len > 0) {
        const old_name_len = nested.var_ref_names.len;
        const add_len = @min(eval_var_ref_names.len, eval_var_refs.len);
        const names = try ctx.runtime.memory.alloc(core.Atom, old_name_len + add_len);
        var names_transferred = false;
        errdefer if (!names_transferred) ctx.runtime.memory.free(core.Atom, names);
        var initialized_names: usize = 0;
        errdefer if (!names_transferred) {
            for (names[0..initialized_names]) |atom_id| ctx.runtime.atoms.free(atom_id);
        };
        for (nested.var_ref_names, 0..) |atom_id, idx| {
            names[idx] = ctx.runtime.atoms.dup(atom_id);
            initialized_names += 1;
        }
        for (eval_var_ref_names[0..add_len], 0..) |atom_id, idx| names[old_name_len + idx] = ctx.runtime.atoms.dup(atom_id);
        initialized_names += add_len;

        const refs = try ctx.runtime.memory.alloc(core.Value, var_refs.len + add_len);
        var refs_transferred = false;
        errdefer if (!refs_transferred) ctx.runtime.memory.free(core.Value, refs);
        for (var_refs, 0..) |value, idx| refs[idx] = value;
        for (eval_var_refs[0..add_len], 0..) |value, idx| refs[var_refs.len + idx] = value;

        nested.var_ref_names = names;
        allocated_var_ref_names = names;
        names_transferred = true;
        combined_var_refs = refs;
        allocated_combined_refs = refs;
        refs_transferred = true;
    }

    var nested_stack = stack_mod.Stack.init(&ctx.runtime.memory, ctx.runtime.stack_size);
    defer nested_stack.deinit(ctx.runtime);
    var boxed_this: ?core.Value = null;
    defer if (boxed_this) |value| value.free(ctx.runtime);
    const fb_runtime_strict = fb.is_strict_mode or fb.runtime_strict_mode;
    const effective_this = if (!fb_runtime_strict) blk: {
        if (this_value.isUndefined() or this_value.isNull()) break :blk global.value();
        if (!this_value.isObject()) {
            boxed_this = try primitiveObjectForAccess(ctx.runtime, global, this_value);
            break :blk boxed_this.?;
        }
        break :blk this_value;
    } else this_value;
    if (fb.func_kind == .async and generator_state == null) {
        return qjsAsyncFunctionStart(ctx, func, current_function_value, effective_this, args, combined_var_refs, output, global, eval_var_ref_names, eval_var_refs);
    }
    const stop_on_yield = fb.func_kind == .generator or fb.func_kind == .async_generator;
    const result = runWithArgsState(ctx, &nested_stack, &nested, effective_this, args, combined_var_refs, output, global, false, fb_runtime_strict, stop_on_yield, &.{}, &.{}, eval_var_ref_names, eval_var_refs, &.{}, &.{}, &.{}, &.{}, generator_state, resume_value, stop_before_pc, current_function_value, new_target_value, constructor_this_value, false, false, core.Value.undefinedValue(), false, false) catch |err| {
        if (fb.func_kind == .async_generator) {
            return rejectedPromiseForRuntimeError(ctx, global, err, promisePrototypeFromGlobal(ctx.runtime, global));
        }
        return err;
    };
    if (fb.func_kind == .async_generator) {
        defer result.free(ctx.runtime);
        return builtins.promise.fulfilledWithPrototype(ctx.runtime, result, promisePrototypeFromGlobal(ctx.runtime, global));
    }
    return result;
}

fn qjsAsyncFunctionStart(
    ctx: *core.Context,
    func: core.Value,
    current_function_value: core.Value,
    this_value: core.Value,
    args: []const core.Value,
    var_refs: []const core.Value,
    output: ?*std.Io.Writer,
    global: *core.Object,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
) HostError!core.Value {
    const promise = try builtins.promise.constructWithPrototype(ctx.runtime, promisePrototypeFromGlobal(ctx.runtime, global));
    errdefer promise.free(ctx.runtime);

    const continuation_value = try createGeneratorObject(ctx, func, current_function_value, this_value, args, var_refs, output, global, eval_var_ref_names, eval_var_refs, false);
    defer continuation_value.free(ctx.runtime);
    const continuation = objectFromValue(continuation_value) orelse return error.TypeError;
    continuation.generatorAsyncPromiseSlot().* = promise.dup();

    try qjsAsyncFunctionRunAndSettle(ctx, output, global, continuation, null, false);
    return promise;
}

fn qjsAsyncFunctionRunState(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    continuation: *core.Object,
    resume_value: ?core.Value,
    resume_rejected: bool,
) HostError!core.Value {
    if (continuation.generatorExecuting()) return error.TypeError;
    const function_value = continuation.functionBytecodeSlot().* orelse return error.TypeError;
    const fb = functionBytecodeFromValue(function_value) orelse return error.TypeError;
    var nested = fb.asBytecodeView(ctx.runtime);
    var nested_stack = stack_mod.Stack.init(&ctx.runtime.memory, ctx.runtime.stack_size);
    defer nested_stack.deinit(ctx.runtime);

    try setGeneratorResumeCompletionType(ctx.runtime, continuation, if (resume_rejected) 2 else 0);
    continuation.generatorExecutingSlot().* = true;
    defer continuation.generatorExecutingSlot().* = false;

    const async_global = objectRealmGlobal(continuation) orelse global;
    const current_function_value = continuation.generatorCurrentFunction() orelse continuation.value();
    const fb_runtime_strict = fb.is_strict_mode or fb.runtime_strict_mode;
    return runWithArgsState(ctx, &nested_stack, &nested, continuation.generatorThis() orelse core.Value.undefinedValue(), continuation.generatorArgs(), continuation.functionCapturesSlot().*, output, async_global, false, fb_runtime_strict, false, &.{}, &.{}, continuation.functionEvalLocalNamesSlot().*, continuation.functionEvalLocalRefsSlot().*, &.{}, &.{}, &.{}, &.{}, continuation, resume_value, null, current_function_value, core.Value.undefinedValue(), core.Value.undefinedValue(), false, false, core.Value.undefinedValue(), false, true);
}

fn qjsAsyncFunctionRunAndSettle(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    continuation: *core.Object,
    resume_value: ?core.Value,
    resume_rejected: bool,
) HostError!void {
    const async_global = objectRealmGlobal(continuation) orelse global;
    const result = qjsAsyncFunctionRunState(ctx, output, async_global, continuation, resume_value, resume_rejected) catch |err| {
        continuation.generatorDoneSlot().* = true;
        const reason = try qjsPromiseErrorValue(ctx, async_global, err);
        defer reason.free(ctx.runtime);
        try qjsAsyncFunctionSettle(ctx, output, async_global, continuation, reason, true, null, null);
        clearHandledRejectionException(ctx);
        qjsAsyncFunctionClearPromise(ctx.runtime, continuation);
        return;
    };
    defer result.free(ctx.runtime);

    if (continuation.generatorJustYielded() and !continuation.generatorDone()) {
        try qjsAsyncFunctionAwaitOrReject(ctx, output, async_global, continuation, result, null, null);
        return;
    }

    continuation.generatorDoneSlot().* = true;
    try qjsAsyncFunctionSettle(ctx, output, async_global, continuation, result, false, null, null);
    qjsAsyncFunctionClearPromise(ctx.runtime, continuation);
}

fn qjsAsyncFunctionAwaitOrReject(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    continuation: *core.Object,
    awaited_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!void {
    qjsAsyncFunctionAwait(ctx, output, global, continuation, awaited_value, caller_function, caller_frame) catch |err| {
        continuation.generatorDoneSlot().* = true;
        const reason = try qjsPromiseErrorValue(ctx, global, err);
        defer reason.free(ctx.runtime);
        try qjsAsyncFunctionSettle(ctx, output, global, continuation, reason, true, caller_function, caller_frame);
        clearHandledRejectionException(ctx);
        qjsAsyncFunctionClearPromise(ctx.runtime, continuation);
    };
}

fn clearHandledRejectionException(ctx: *core.Context) void {
    if (!ctx.hasUnhandledRejection() and ctx.hasException()) ctx.clearException();
}

fn qjsAsyncFunctionAwait(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    continuation: *core.Object,
    awaited_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!void {
    const promise_constructor = try qjsPromiseDefaultConstructor(ctx, global);
    defer promise_constructor.free(ctx.runtime);
    const awaited = try qjsPromiseStaticCall(ctx, output, global, promise_constructor, &.{awaited_value}, .resolve, caller_function, caller_frame);
    defer awaited.free(ctx.runtime);

    const on_fulfilled = try qjsAsyncFunctionResumeCallback(ctx.runtime, global, continuation, false);
    defer on_fulfilled.free(ctx.runtime);
    const on_rejected = try qjsAsyncFunctionResumeCallback(ctx.runtime, global, continuation, true);
    defer on_rejected.free(ctx.runtime);

    const then_atom = try ctx.runtime.internAtom("then");
    defer ctx.runtime.atoms.free(then_atom);
    const then_value = try getValueProperty(ctx, output, global, awaited, then_atom, caller_function, caller_frame);
    defer then_value.free(ctx.runtime);
    if (!isCallableValue(then_value)) return error.TypeError;
    const then_result = try callValueOrBytecode(ctx, output, global, awaited, then_value, &.{ on_fulfilled, on_rejected }, caller_function, caller_frame);
    then_result.free(ctx.runtime);
}

fn qjsAsyncFunctionResumeCallback(
    rt: *core.Runtime,
    global: *core.Object,
    continuation: *core.Object,
    rejected: bool,
) !core.Value {
    const callback = try qjsCreateBuiltinFunction(rt, global, "", 1);
    errdefer callback.free(rt);
    const callback_object = objectFromValue(callback) orelse return error.TypeError;
    callback_object.functionAsyncContinuationSlot().* = continuation.value().dup();
    callback_object.functionAsyncContinuationRejectedSlot().* = rejected;
    return callback;
}

fn qjsAsyncFunctionResumeCallbackCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    function_object: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!?core.Value {
    const continuation_value = function_object.functionAsyncContinuation() orelse return null;
    const continuation = objectFromValue(continuation_value) orelse return error.TypeError;
    const rejected = function_object.functionAsyncContinuationRejected();
    const resume_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    try qjsAsyncFunctionRunAndSettle(ctx, output, objectRealmGlobal(continuation) orelse global, continuation, resume_value, rejected);
    _ = caller_function;
    _ = caller_frame;
    return core.Value.undefinedValue();
}

fn qjsAsyncFunctionSettle(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    continuation: *core.Object,
    value: core.Value,
    rejected: bool,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!void {
    var rooted_value = value;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_value },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    const promise_value = continuation.generatorAsyncPromise() orelse return error.TypeError;
    const resolving = try createPromiseResolvingPair(ctx.runtime, global, promise_value);
    defer resolving.resolve.free(ctx.runtime);
    defer resolving.reject.free(ctx.runtime);
    const settle = if (rejected) resolving.reject else resolving.resolve;
    const result = try callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), settle, &.{rooted_value}, caller_function, caller_frame);
    result.free(ctx.runtime);
}

test "qjsAsyncFunctionSettle roots direct symbol result before promise stores it" {
    const rt = try core.Runtime.create(std.testing.allocator);
    const ctx = try core.Context.create(rt);
    const global = try core.Object.create(rt, core.class.ids.object, null);
    const continuation = try core.Object.create(rt, core.class.ids.generator, null);
    defer {
        continuation.value().free(rt);
        global.value().free(rt);
        ctx.destroy();
        rt.destroy();
    }

    const promise = try builtins.promise.constructWithPrototype(rt, promisePrototypeFromGlobal(rt, global));
    defer promise.free(rt);
    continuation.generatorAsyncPromiseSlot().* = promise.dup();

    const symbol_atom = try rt.atoms.newValueSymbol("gc-async-settle-symbol");
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);
    try qjsAsyncFunctionSettle(ctx, null, global, continuation, core.Value.symbol(symbol_atom), false, null, null);

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    const promise_object = objectFromValue(promise) orelse return error.TypeError;
    const result = promise_object.promiseResult() orelse return error.TypeError;
    try std.testing.expect(result.same(core.Value.symbol(symbol_atom)));

    promise_object.promiseResultSlot().* = null;
    result.free(rt);
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

fn qjsAsyncFunctionClearPromise(rt: *core.Runtime, continuation: *core.Object) void {
    const slot = continuation.generatorAsyncPromiseSlot();
    const old_promise = slot.*;
    slot.* = null;
    if (old_promise) |stored| stored.free(rt);
}
pub fn createGeneratorObject(
    ctx: *core.Context,
    func: core.Value,
    current_function_value: core.Value,
    this_value: core.Value,
    args: []const core.Value,
    var_refs: []const core.Value,
    output: ?*std.Io.Writer,
    global: *core.Object,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    is_async: bool,
) !core.Value {
    var rooted_func = func;
    var rooted_current = current_function_value;
    var rooted_this = this_value;
    var rooted_boxed_this = core.Value.undefinedValue();
    defer rooted_boxed_this.free(ctx.runtime);

    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_func },
        .{ .value = &rooted_current },
        .{ .value = &rooted_this },
        .{ .value = &rooted_boxed_this },
    };
    var root_slices = [_]core.runtime.ValueRootSlice{
        .{ .constant = &args },
        .{ .constant = &var_refs },
        .{ .constant = &eval_var_refs },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
        .slices = &root_slices,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    const fb = functionBytecodeFromValue(rooted_func) orelse return error.TypeError;
    const class_id = if (is_async) core.class.ids.async_generator else core.class.ids.generator;
    const object = try core.Object.create(ctx.runtime, class_id, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
    object.functionBytecodeSlot().* = rooted_func.dup();
    if (property_ops.expectObject(rooted_current)) |function_object| {
        object.generatorCurrentFunctionSlot().* = rooted_current.dup();
        object.setFunctionHomeObject(ctx.runtime, function_object.functionHomeObject());
        try object.setFunctionRealmGlobalPtr(ctx.runtime, objectRealmGlobal(function_object) orelse global);
    } else |_| {}
    try object.setFunctionRealmGlobalPtrIfNull(ctx.runtime, global);
    const fb_runtime_strict = fb.is_strict_mode or fb.runtime_strict_mode;
    const effective_this = if (!fb_runtime_strict) blk: {
        if (rooted_this.isUndefined() or rooted_this.isNull()) break :blk global.value();
        if (!rooted_this.isObject()) {
            rooted_boxed_this = try primitiveObjectForAccess(ctx.runtime, global, rooted_this);
            break :blk rooted_boxed_this;
        }
        break :blk rooted_this;
    } else rooted_this;
    object.generatorThisSlot().* = effective_this.dup();
    if (var_refs.len > 0) {
        object.functionCapturesSlot().* = try ctx.runtime.memory.alloc(core.Value, var_refs.len);
        var initialized: usize = 0;
        errdefer {
            const captures = object.functionCapturesSlot().*;
            object.functionCapturesSlot().* = &.{};
            for (captures[0..initialized]) |stored| stored.free(ctx.runtime);
            ctx.runtime.memory.free(core.Value, captures);
        }
        for (var_refs, 0..) |value, idx| {
            object.functionCapturesSlot().*[idx] = value.dup();
            initialized += 1;
        }
    }

    if (args.len > 0) {
        object.generatorArgsSlot().* = try ctx.runtime.memory.alloc(core.Value, args.len);
        var initialized: usize = 0;
        errdefer {
            const generator_args = object.generatorArgs();
            object.generatorArgsSlot().* = &.{};
            for (generator_args[0..initialized]) |stored| stored.free(ctx.runtime);
            ctx.runtime.memory.free(core.Value, generator_args);
        }
        for (args, 0..) |value, idx| {
            object.generatorArgsSlot().*[idx] = value.dup();
            initialized += 1;
        }
    }

    if (eval_var_ref_names.len > 0) {
        const names = try ctx.runtime.memory.alloc(core.Atom, eval_var_ref_names.len);
        var locals_transferred = false;
        var refs_allocated = false;
        errdefer if (!refs_allocated and !locals_transferred) ctx.runtime.memory.free(core.Atom, names);
        const refs = try ctx.runtime.memory.alloc(core.Value, eval_var_ref_names.len);
        refs_allocated = true;
        var initialized: usize = 0;
        errdefer if (!locals_transferred) {
            for (names) |atom_id| ctx.runtime.atoms.free(atom_id);
            for (refs[0..initialized]) |stored| stored.free(ctx.runtime);
            ctx.runtime.memory.free(core.Atom, names);
            ctx.runtime.memory.free(core.Value, refs);
        };
        for (eval_var_ref_names, 0..) |atom_id, idx| {
            names[idx] = ctx.runtime.atoms.dup(atom_id);
            if (idx < eval_var_refs.len) {
                refs[idx] = eval_var_refs[idx].dup();
            } else {
                refs[idx] = core.Value.undefinedValue();
            }
            initialized += 1;
        }
        object.functionEvalLocalNamesSlot().* = names;
        object.functionEvalLocalRefsSlot().* = refs;
        locals_transferred = true;
    }

    if (fb.generator_body_pc != 0) {
        const init_result = try runGeneratorParameterInit(ctx, fb, object, current_function_value, effective_this, args, object.functionCapturesSlot().*, output, global);
        init_result.free(ctx.runtime);
    }

    const prototype = generatorObjectPrototype(ctx.runtime, global, current_function_value, is_async) catch null;
    try object.setPrototype(ctx.runtime, prototype);

    const next = try builtins.function.nativeFunction(ctx.runtime, "next", 0);
    defer next.free(ctx.runtime);
    try defineValueProperty(ctx.runtime, object, "next", next);
    const return_fn = try builtins.function.nativeFunction(ctx.runtime, "return", 1);
    defer return_fn.free(ctx.runtime);
    try defineValueProperty(ctx.runtime, object, "return", return_fn);
    const slice = try builtins.function.nativeFunction(ctx.runtime, "slice", 1);
    defer slice.free(ctx.runtime);
    try defineValueProperty(ctx.runtime, object, "slice", slice);
    return object.value();
}

pub fn generatorObjectPrototype(rt: *core.Runtime, global: *core.Object, function_value: core.Value, is_async: bool) !?*core.Object {
    const fallback = if (is_async) try asyncGeneratorPrototypeFromGlobal(rt, global) else try generatorPrototypeFromGlobal(rt, global);
    const function_object = property_ops.expectObject(function_value) catch return fallback;
    const prototype_value = function_object.getProperty(core.atom.ids.prototype);
    defer prototype_value.free(rt);
    return property_ops.expectObject(prototype_value) catch fallback;
}

pub fn runGeneratorParameterInit(
    ctx: *core.Context,
    fb: *const bytecode.FunctionBytecode,
    object: *core.Object,
    current_function_value: core.Value,
    this_value: core.Value,
    args: []const core.Value,
    var_refs: []const core.Value,
    output: ?*std.Io.Writer,
    global: *core.Object,
) !core.Value {
    var nested = bytecode.Bytecode.init(&ctx.runtime.memory, &ctx.runtime.atoms, fb.func_name);
    defer nested.deinit(ctx.runtime);
    nested.atoms.replace(&nested.filename, fb.filename);
    nested.line_num = fb.line_num;
    nested.col_num = fb.col_num;
    nested.arg_count = fb.arg_count;
    nested.var_count = fb.var_count;
    nested.stack_size = fb.stack_size;
    nested.flags.is_strict = fb.is_strict_mode;
    nested.flags.runtime_strict = fb.runtime_strict_mode;
    nested.flags.has_simple_parameter_list = fb.has_simple_parameter_list;
    try nested.setCode(fb.byte_code);
    for (fb.atom_operands) |atom_id| {
        try nested.retainAtomOperand(atom_id);
    }
    if (fb.arg_names.len > 0) {
        nested.arg_names = try ctx.runtime.memory.alloc(core.Atom, fb.arg_names.len);
        for (fb.arg_names, 0..) |atom_id, idx| {
            nested.arg_names[idx] = ctx.runtime.atoms.dup(atom_id);
        }
    }
    if (fb.var_names.len > 0) {
        nested.var_names = try ctx.runtime.memory.alloc(core.Atom, fb.var_names.len);
        for (fb.var_names, 0..) |atom_id, idx| {
            nested.var_names[idx] = ctx.runtime.atoms.dup(atom_id);
        }
    }
    if (fb.var_is_lexical.len > 0) {
        nested.var_is_lexical = try ctx.runtime.memory.alloc(bool, fb.var_is_lexical.len);
        @memcpy(nested.var_is_lexical, fb.var_is_lexical);
    }
    if (fb.var_is_const.len > 0) {
        nested.var_is_const = try ctx.runtime.memory.alloc(bool, fb.var_is_const.len);
        @memcpy(nested.var_is_const, fb.var_is_const);
    }
    if (fb.var_ref_names.len > 0) {
        nested.var_ref_names = try ctx.runtime.memory.alloc(core.Atom, fb.var_ref_names.len);
        for (fb.var_ref_names, 0..) |atom_id, idx| {
            nested.var_ref_names[idx] = ctx.runtime.atoms.dup(atom_id);
        }
    }
    for (fb.cpool) |value| {
        _ = try nested.addConstant(value);
    }

    var nested_stack = stack_mod.Stack.init(&ctx.runtime.memory, ctx.runtime.stack_size);
    defer nested_stack.deinit(ctx.runtime);
    return runWithArgsState(ctx, &nested_stack, &nested, this_value, args, var_refs, output, global, false, true, false, &.{}, &.{}, object.functionEvalLocalNamesSlot().*, object.functionEvalLocalRefsSlot().*, &.{}, &.{}, &.{}, &.{}, object, null, fb.generator_body_pc, current_function_value, core.Value.undefinedValue(), core.Value.undefinedValue(), false, false, core.Value.undefinedValue(), false, false);
}

pub fn qjsGeneratorNext(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    args: []const core.Value,
) !?core.Value {
    if (!receiver.isObject()) return null;
    const object = property_ops.expectObject(receiver) catch return null;
    if (object.class_id != core.class.ids.generator and object.class_id != core.class.ids.async_generator) return null;
    if (object.generatorExecuting()) return error.TypeError;
    const generator_global = objectRealmGlobal(object) orelse global;
    if (object.generatorDone()) {
        const done_result = try createIteratorResult(ctx.runtime, generator_global, core.Value.undefinedValue(), true);
        defer done_result.free(ctx.runtime);
        if (object.class_id == core.class.ids.async_generator) {
            return try builtins.promise.fulfilledWithPrototype(ctx.runtime, done_result, promisePrototypeFromGlobal(ctx.runtime, generator_global));
        }
        return done_result.dup();
    }
    const function_value = object.functionBytecodeSlot().* orelse return error.TypeError;
    const stored_current_function = if (object.generatorCurrentFunction()) |value| value.dup() else null;
    defer if (stored_current_function) |value| value.free(ctx.runtime);
    const current_function_value = stored_current_function orelse receiver;
    const resume_value = if (object.generatorPc() != 0 and args.len > 0) args[0] else core.Value.undefinedValue();
    object.generatorExecutingSlot().* = true;
    defer object.generatorExecutingSlot().* = false;
    const result = callFunctionBytecodeModeState(
        ctx,
        function_value,
        current_function_value,
        object.generatorThis() orelse core.Value.undefinedValue(),
        object.generatorArgs(),
        object.functionCapturesSlot().*,
        output,
        generator_global,
        object.functionEvalLocalNamesSlot().*,
        object.functionEvalLocalRefsSlot().*,
        false,
        object,
        resume_value,
        null,
        core.Value.undefinedValue(),
        core.Value.undefinedValue(),
    ) catch |err| {
        object.generatorDoneSlot().* = true;
        if (object.class_id == core.class.ids.async_generator) {
            return try rejectedPromiseForRuntimeError(ctx, generator_global, err, promisePrototypeFromGlobal(ctx.runtime, generator_global));
        }
        return err;
    };
    if (object.class_id == core.class.ids.async_generator) {
        defer result.free(ctx.runtime);
        const promise = objectFromValue(result) orelse return error.TypeError;
        if (promise.class_id != core.class.ids.promise) return error.TypeError;
        if (promise.promiseIsRejected()) {
            object.generatorDoneSlot().* = true;
            return result.dup();
        }
        const done = !object.generatorJustYielded();
        if (promise.promiseResult() == null) {
            return try asyncGeneratorIteratorResultFromPromise(ctx, output, generator_global, result, done);
        }
        const value = if (promise.promiseResult()) |stored| stored.dup() else core.Value.undefinedValue();
        defer value.free(ctx.runtime);
        if (objectFromValue(value)) |inner_promise| {
            if (inner_promise.class_id == core.class.ids.promise and inner_promise.promiseIsRejected()) {
                object.generatorDoneSlot().* = true;
                if (ctx.hasException()) ctx.clearException();
                return value.dup();
            }
        }
        const iterator_result = try createIteratorResult(ctx.runtime, generator_global, value, done);
        defer iterator_result.free(ctx.runtime);
        return try builtins.promise.fulfilledWithPrototype(ctx.runtime, iterator_result, promisePrototypeFromGlobal(ctx.runtime, generator_global));
    }
    defer result.free(ctx.runtime);
    if (object.generatorJustYielded() and
        (object.generatorYieldStarIterator() != null or generatorYieldStarSuspended(ctx.runtime, object)))
    {
        return result.dup();
    }
    return try createIteratorResult(ctx.runtime, generator_global, result, !object.generatorJustYielded());
}

fn isAsyncGeneratorPrototypeMethod(rt: *core.Runtime, function_object: *core.Object) bool {
    _ = rt;
    return function_object.isAsyncGeneratorPrototypeMethod();
}

fn isAsyncGeneratorReceiver(value: core.Value) bool {
    const object = objectFromValue(value) orelse return false;
    return object.class_id == core.class.ids.async_generator;
}

fn asyncGeneratorRejectedTypeError(ctx: *core.Context, global: *core.Object) !core.Value {
    return rejectedPromiseForRuntimeError(ctx, global, error.TypeError, promisePrototypeFromGlobal(ctx.runtime, global));
}

fn qjsAsyncIteratorAsyncDispose(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    function_object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!function_object.isAsyncIteratorAsyncDisposeFunction()) return null;

    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = getValueProperty(ctx, output, global, receiver, return_key, caller_function, caller_frame) catch |err| {
        return try rejectedPromiseForRuntimeError(ctx, global, err, promisePrototypeFromGlobal(ctx.runtime, global));
    };
    defer return_method.free(ctx.runtime);
    if (return_method.isUndefined() or return_method.isNull()) {
        return try builtins.promise.fulfilledWithPrototype(ctx.runtime, core.Value.undefinedValue(), promisePrototypeFromGlobal(ctx.runtime, global));
    }
    if (!isCallableValue(return_method)) {
        return try rejectedPromiseForRuntimeError(ctx, global, error.TypeError, promisePrototypeFromGlobal(ctx.runtime, global));
    }

    const result = callValueOrBytecode(ctx, output, global, receiver, return_method, &.{core.Value.undefinedValue()}, caller_function, caller_frame) catch |err| {
        return try rejectedPromiseForRuntimeError(ctx, global, err, promisePrototypeFromGlobal(ctx.runtime, global));
    };
    defer result.free(ctx.runtime);
    const result_object = objectFromValue(result) orelse {
        return try rejectedPromiseForRuntimeError(ctx, global, error.TypeError, promisePrototypeFromGlobal(ctx.runtime, global));
    };
    if (result_object.class_id == core.class.ids.promise) {
        try settlePendingPromiseReaction(ctx, output, global, result_object);
        if (result_object.promiseResult() == null) try awaitPendingPromise(ctx, output, global, result_object);
        if (result_object.promiseIsRejected()) {
            const reason = if (result_object.promiseResult()) |stored| stored.dup() else core.Value.undefinedValue();
            defer reason.free(ctx.runtime);
            return try builtins.promise.rejectedWithPrototype(ctx.runtime, reason, promisePrototypeFromGlobal(ctx.runtime, global));
        }
    }
    return try builtins.promise.fulfilledWithPrototype(ctx.runtime, core.Value.undefinedValue(), promisePrototypeFromGlobal(ctx.runtime, global));
}

fn asyncGeneratorFulfilledIteratorResult(ctx: *core.Context, global: *core.Object, value: core.Value, done: bool) !core.Value {
    const iterator_result = try createIteratorResult(ctx.runtime, global, value, done);
    defer iterator_result.free(ctx.runtime);
    return builtins.promise.fulfilledWithPrototype(ctx.runtime, iterator_result, promisePrototypeFromGlobal(ctx.runtime, global));
}

fn asyncGeneratorIteratorResultFromPromise(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    promise_value: core.Value,
    done: bool,
) !core.Value {
    const promise = try builtins.promise.constructWithPrototype(ctx.runtime, promisePrototypeFromGlobal(ctx.runtime, global));
    errdefer promise.free(ctx.runtime);
    const resolving = try createPromiseResolvingPair(ctx.runtime, global, promise);
    defer resolving.resolve.free(ctx.runtime);
    defer resolving.reject.free(ctx.runtime);

    const unwrap = try qjsAsyncFromSyncIteratorUnwrap(ctx.runtime, global, done);
    defer unwrap.free(ctx.runtime);
    try qjsPerformPromiseThen(ctx, output, global, promise_value, unwrap, core.Value.undefinedValue(), resolving.resolve, resolving.reject);
    return promise;
}

pub fn generatorYieldStarSuspended(rt: *core.Runtime, object: *core.Object) bool {
    _ = rt;
    return object.generatorYieldStarSuspended();
}

pub fn setGeneratorYieldStarSuspended(rt: *core.Runtime, object: *core.Object, value: bool) !void {
    _ = rt;
    object.generatorYieldStarSuspendedSlot().* = value;
}

pub fn generatorResumeCompletionType(rt: *core.Runtime, object: *core.Object) i32 {
    _ = rt;
    return object.generatorResumeCompletionType();
}

pub fn setGeneratorResumeCompletionType(rt: *core.Runtime, object: *core.Object, value: i32) !void {
    _ = rt;
    object.generatorResumeCompletionTypeSlot().* = value;
}

fn resumeGeneratorYieldStarCompletion(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    resume_value: core.Value,
    completion_type: i32,
) !core.Value {
    const function_value = object.functionBytecodeSlot().* orelse return error.TypeError;
    try setGeneratorResumeCompletionType(ctx.runtime, object, completion_type);
    object.generatorExecutingSlot().* = true;
    defer object.generatorExecutingSlot().* = false;
    const result = callFunctionBytecodeModeState(
        ctx,
        function_value,
        receiver,
        object.generatorThis() orelse core.Value.undefinedValue(),
        object.generatorArgs(),
        object.functionCapturesSlot().*,
        output,
        global,
        object.functionEvalLocalNamesSlot().*,
        object.functionEvalLocalRefsSlot().*,
        false,
        object,
        resume_value,
        null,
        core.Value.undefinedValue(),
        core.Value.undefinedValue(),
    ) catch |err| {
        object.generatorDoneSlot().* = true;
        if (object.class_id == core.class.ids.async_generator) {
            return try rejectedPromiseForRuntimeError(ctx, global, err, promisePrototypeFromGlobal(ctx.runtime, global));
        }
        return err;
    };
    defer result.free(ctx.runtime);
    if (object.class_id == core.class.ids.async_generator) {
        const promise = objectFromValue(result) orelse return error.TypeError;
        if (promise.class_id != core.class.ids.promise) return error.TypeError;
        if (promise.promiseIsRejected()) {
            object.generatorDoneSlot().* = true;
            return result.dup();
        }
        const done = !object.generatorJustYielded();
        if (promise.promiseResult() == null) {
            if (done) object.generatorDoneSlot().* = true;
            return try asyncGeneratorIteratorResultFromPromise(ctx, output, global, result, done);
        }
        const value = if (promise.promiseResult()) |stored| stored.dup() else core.Value.undefinedValue();
        defer value.free(ctx.runtime);
        if (done) object.generatorDoneSlot().* = true;
        return try asyncGeneratorFulfilledIteratorResult(ctx, global, value, done);
    }
    const done = !object.generatorJustYielded();
    if (done) object.generatorDoneSlot().* = true;
    if (object.generatorJustYielded() and generatorYieldStarSuspended(ctx.runtime, object)) return result.dup();
    return try createIteratorResult(ctx.runtime, global, result, done);
}

pub fn qjsGeneratorReturn(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    args: []const core.Value,
) !?core.Value {
    if (!receiver.isObject()) return null;
    const object = property_ops.expectObject(receiver) catch return null;
    if (object.class_id != core.class.ids.generator and object.class_id != core.class.ids.async_generator) return null;
    if (object.generatorExecuting()) return error.TypeError;
    const generator_global = objectRealmGlobal(object) orelse global;
    try closeGeneratorDestructuringIterators(ctx, output, generator_global, object);
    var return_value = if (args.len > 0) args[0].dup() else core.Value.undefinedValue();
    defer return_value.free(ctx.runtime);
    if (generatorYieldStarSuspended(ctx.runtime, object)) {
        return try resumeGeneratorYieldStarCompletion(ctx, output, generator_global, receiver, object, return_value, 1);
    }
    if (object.generatorYieldStarIterator() != null) {
        const step = qjsGeneratorYieldStarReturnStep(ctx, output, generator_global, object, return_value) catch |err| {
            if (try resumeGeneratorCatchForRuntimeError(ctx, output, generator_global, receiver, object, err)) |handled| return handled;
            return err;
        };
        switch (step) {
            .yield_result => |result| {
                if (object.class_id == core.class.ids.async_generator) {
                    defer result.free(ctx.runtime);
                    const promise = try builtins.promise.fulfilledWithPrototype(ctx.runtime, result, promisePrototypeFromGlobal(ctx.runtime, generator_global));
                    return promise;
                }
                return result;
            },
            .complete => |value| {
                return_value.free(ctx.runtime);
                return_value = value;
            },
        }
    }
    if (object.generatorPc() != 0) {
        const function_value = object.functionBytecodeSlot().* orelse return error.TypeError;
        const fb = functionBytecodeFromValue(function_value) orelse return error.TypeError;
        if (findGeneratorReturnFinallyTarget(fb, @intCast(object.generatorPc()))) |finally_range| {
            object.generatorPcSlot().* = finally_range.start;
            object.generatorJustYieldedSlot().* = false;
            const result = callFunctionBytecodeModeState(
                ctx,
                function_value,
                receiver,
                object.generatorThis() orelse core.Value.undefinedValue(),
                object.generatorArgs(),
                object.functionCapturesSlot().*,
                output,
                generator_global,
                object.functionEvalLocalNamesSlot().*,
                object.functionEvalLocalRefsSlot().*,
                false,
                object,
                core.Value.undefinedValue(),
                finally_range.stop,
                core.Value.undefinedValue(),
                core.Value.undefinedValue(),
            ) catch |err| {
                object.generatorDoneSlot().* = true;
                return err;
            };
            defer result.free(ctx.runtime);
            const done = !object.generatorJustYielded();
            if (done) object.generatorDoneSlot().* = true;
            const iterator_value = if (done and result.isUndefined()) return_value else result;
            if (object.class_id == core.class.ids.async_generator) {
                const promise = try asyncGeneratorFulfilledIteratorResult(ctx, generator_global, iterator_value, done);
                return promise;
            }
            return try createIteratorResult(ctx.runtime, generator_global, iterator_value, done);
        }
    }
    object.generatorDoneSlot().* = true;
    if (object.class_id == core.class.ids.async_generator) {
        const promise = try asyncGeneratorFulfilledIteratorResult(ctx, generator_global, return_value, true);
        return promise;
    }
    return try createIteratorResult(ctx.runtime, generator_global, return_value, true);
}

fn resumeGeneratorCatchForRuntimeError(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    err: anytype,
) !?core.Value {
    if (object.class_id == core.class.ids.async_generator) return null;
    if (object.generatorPc() == 0 or !object.generatorStarted()) return null;
    const function_value = object.functionBytecodeSlot().* orelse return null;
    const fb = functionBytecodeFromValue(function_value) orelse return null;
    const catch_target = findEnclosingCatchTarget(fb, @intCast(object.generatorPc())) orelse return null;
    const thrown = try exception_ops.runtimeErrorValueForGeneratorCatch(ctx, global, err);
    defer thrown.free(ctx.runtime);
    object.generatorPcSlot().* = catch_target;
    object.generatorJustYieldedSlot().* = false;
    const result = callFunctionBytecodeModeState(
        ctx,
        function_value,
        receiver,
        object.generatorThis() orelse core.Value.undefinedValue(),
        object.generatorArgs(),
        object.functionCapturesSlot().*,
        output,
        global,
        object.functionEvalLocalNamesSlot().*,
        object.functionEvalLocalRefsSlot().*,
        false,
        object,
        thrown,
        null,
        core.Value.undefinedValue(),
        core.Value.undefinedValue(),
    ) catch |resume_err| {
        object.generatorDoneSlot().* = true;
        return resume_err;
    };
    defer result.free(ctx.runtime);
    const done = !object.generatorJustYielded();
    if (done) object.generatorDoneSlot().* = true;
    const result_value = generatorCatchResumeResultValue(result);
    return try createIteratorResult(ctx.runtime, global, result_value, done);
}

const GeneratorYieldStarReturnStep = union(enum) {
    yield_result: core.Value,
    complete: core.Value,
};

const GeneratorYieldStarThrowStep = union(enum) {
    yield_result: core.Value,
    complete: core.Value,
};

fn qjsGeneratorYieldStarReturnStep(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    generator: *core.Object,
    return_arg: core.Value,
) !GeneratorYieldStarReturnStep {
    const iterator_value = (generator.generatorYieldStarIterator() orelse return error.TypeError).dup();
    defer iterator_value.free(ctx.runtime);
    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = try getValueProperty(ctx, output, global, iterator_value, return_key, null, null);
    defer return_method.free(ctx.runtime);

    if (return_method.isUndefined() or return_method.isNull()) {
        const old_iterator = generator.generatorYieldStarIterator();
        generator.generatorYieldStarIteratorSlot().* = null;
        if (old_iterator) |stored| stored.free(ctx.runtime);
        return .{ .complete = return_arg.dup() };
    }
    if (!isCallableValue(return_method)) return error.TypeError;

    const result_value = try callValueOrBytecode(ctx, output, global, iterator_value, return_method, &.{return_arg}, null, null);
    errdefer result_value.free(ctx.runtime);
    const result = property_ops.expectObject(result_value) catch return error.TypeError;

    const done_key = core.atom.predefinedId("done", .string).?;
    const done_value = try getValueProperty(ctx, output, global, result.value(), done_key, null, null);
    defer done_value.free(ctx.runtime);
    const is_done = value_ops.isTruthy(done_value);

    if (!is_done) {
        generator.generatorJustYieldedSlot().* = true;
        return .{ .yield_result = result_value };
    }

    const value_key = core.atom.predefinedId("value", .string).?;
    const value = try getValueProperty(ctx, output, global, result.value(), value_key, null, null);
    errdefer value.free(ctx.runtime);
    result_value.free(ctx.runtime);
    const old_iterator = generator.generatorYieldStarIterator();
    generator.generatorYieldStarIteratorSlot().* = null;
    if (old_iterator) |stored| stored.free(ctx.runtime);
    return .{ .complete = value };
}

fn qjsGeneratorYieldStarThrowStep(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    generator: *core.Object,
    thrown: core.Value,
) !GeneratorYieldStarThrowStep {
    const iterator_value = (generator.generatorYieldStarIterator() orelse return error.TypeError).dup();
    defer iterator_value.free(ctx.runtime);
    const throw_key = try ctx.runtime.internAtom("throw");
    defer ctx.runtime.atoms.free(throw_key);
    const throw_method = try getValueProperty(ctx, output, global, iterator_value, throw_key, null, null);
    defer throw_method.free(ctx.runtime);

    if (throw_method.isUndefined() or throw_method.isNull()) {
        try qjsGeneratorYieldStarCloseForMissingThrow(ctx, output, global, iterator_value);
        const old_iterator = generator.generatorYieldStarIterator();
        generator.generatorYieldStarIteratorSlot().* = null;
        if (old_iterator) |stored| stored.free(ctx.runtime);
        return error.TypeError;
    }
    if (!isCallableValue(throw_method)) return error.TypeError;

    const result_value = try callValueOrBytecode(ctx, output, global, iterator_value, throw_method, &.{thrown}, null, null);
    errdefer result_value.free(ctx.runtime);
    const result = property_ops.expectObject(result_value) catch return error.TypeError;

    const done_key = core.atom.predefinedId("done", .string).?;
    const done_value = try getValueProperty(ctx, output, global, result.value(), done_key, null, null);
    defer done_value.free(ctx.runtime);
    const is_done = value_ops.isTruthy(done_value);

    if (!is_done) {
        generator.generatorJustYieldedSlot().* = true;
        return .{ .yield_result = result_value };
    }

    const value_key = core.atom.predefinedId("value", .string).?;
    const value = try getValueProperty(ctx, output, global, result.value(), value_key, null, null);
    errdefer value.free(ctx.runtime);
    result_value.free(ctx.runtime);
    const old_iterator = generator.generatorYieldStarIterator();
    generator.generatorYieldStarIteratorSlot().* = null;
    if (old_iterator) |stored| stored.free(ctx.runtime);
    return .{ .complete = value };
}

fn qjsGeneratorYieldStarCloseForMissingThrow(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
) !void {
    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = try getValueProperty(ctx, output, global, iterator_value, return_key, null, null);
    defer return_method.free(ctx.runtime);
    if (return_method.isUndefined() or return_method.isNull()) return;
    if (!isCallableValue(return_method)) return error.TypeError;
    const result = try callValueOrBytecode(ctx, output, global, iterator_value, return_method, &.{}, null, null);
    defer result.free(ctx.runtime);
    _ = property_ops.expectObject(result) catch return error.TypeError;
}

pub fn qjsGeneratorYieldStarReturn(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    generator: *core.Object,
    args: []const core.Value,
) !core.Value {
    const return_arg = if (args.len > 0) args[0] else core.Value.undefinedValue();
    const step = try qjsGeneratorYieldStarReturnStep(ctx, output, global, generator, return_arg);
    switch (step) {
        .yield_result => |result| return result,
        .complete => |value| {
            defer value.free(ctx.runtime);
            generator.generatorDoneSlot().* = true;
            return try createIteratorResult(ctx.runtime, global, value, true);
        },
    }
}

pub fn qjsGeneratorThrow(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    args: []const core.Value,
) !?core.Value {
    const object = property_ops.expectObject(receiver) catch return null;
    if (object.class_id != core.class.ids.generator and object.class_id != core.class.ids.async_generator) return null;
    if (object.generatorExecuting()) return error.TypeError;
    const generator_global = objectRealmGlobal(object) orelse global;
    const thrown = if (args.len > 0) args[0] else core.Value.undefinedValue();

    if (generatorYieldStarSuspended(ctx.runtime, object)) {
        return try resumeGeneratorYieldStarCompletion(ctx, output, generator_global, receiver, object, thrown, 2);
    }

    if (object.class_id == core.class.ids.async_generator) {
        object.generatorDoneSlot().* = true;
        return try builtins.promise.rejectedWithPrototype(ctx.runtime, thrown, promisePrototypeFromGlobal(ctx.runtime, generator_global));
    }

    if (object.generatorYieldStarIterator() != null) {
        const step = qjsGeneratorYieldStarThrowStep(ctx, output, generator_global, object, thrown) catch |err| {
            if (try resumeGeneratorCatchForRuntimeError(ctx, output, generator_global, receiver, object, err)) |handled| return handled;
            object.generatorDoneSlot().* = true;
            return err;
        };
        switch (step) {
            .yield_result => |result| return result,
            .complete => |value| {
                defer value.free(ctx.runtime);
                const function_value = object.functionBytecodeSlot().* orelse return error.TypeError;
                const fb = functionBytecodeFromValue(function_value) orelse return error.TypeError;
                object.generatorPcSlot().* = generatorPcAfterYieldStar(fb, object.generatorPc()) orelse return error.InvalidBytecode;
                object.generatorJustYieldedSlot().* = false;
                const result = callFunctionBytecodeModeState(
                    ctx,
                    function_value,
                    receiver,
                    object.generatorThis() orelse core.Value.undefinedValue(),
                    object.generatorArgs(),
                    object.functionCapturesSlot().*,
                    output,
                    generator_global,
                    object.functionEvalLocalNamesSlot().*,
                    object.functionEvalLocalRefsSlot().*,
                    false,
                    object,
                    value,
                    null,
                    core.Value.undefinedValue(),
                    core.Value.undefinedValue(),
                ) catch |err| {
                    object.generatorDoneSlot().* = true;
                    return err;
                };
                defer result.free(ctx.runtime);
                const done = !object.generatorJustYielded();
                if (done) object.generatorDoneSlot().* = true;
                return try createIteratorResult(ctx.runtime, generator_global, result, done);
            },
        }
    }

    if (object.generatorPc() != 0 and object.generatorStarted()) {
        const function_value = object.functionBytecodeSlot().* orelse return error.TypeError;
        const fb = functionBytecodeFromValue(function_value) orelse return error.TypeError;
        if (findEnclosingCatchTarget(fb, @intCast(object.generatorPc()))) |catch_target| {
            object.generatorPcSlot().* = catch_target;
            object.generatorJustYieldedSlot().* = false;
            const result = callFunctionBytecodeModeState(
                ctx,
                function_value,
                receiver,
                object.generatorThis() orelse core.Value.undefinedValue(),
                object.generatorArgs(),
                object.functionCapturesSlot().*,
                output,
                generator_global,
                object.functionEvalLocalNamesSlot().*,
                object.functionEvalLocalRefsSlot().*,
                false,
                object,
                thrown,
                null,
                core.Value.undefinedValue(),
                core.Value.undefinedValue(),
            ) catch |err| {
                object.generatorDoneSlot().* = true;
                return err;
            };
            defer result.free(ctx.runtime);
            const done = !object.generatorJustYielded();
            if (done) object.generatorDoneSlot().* = true;
            const result_value = generatorCatchResumeResultValue(result);
            return try createIteratorResult(ctx.runtime, generator_global, result_value, done);
        }
    }

    object.generatorDoneSlot().* = true;
    _ = ctx.throwValue(thrown.dup());
    return error.Test262Error;
}

fn generatorCatchResumeResultValue(result: core.Value) core.Value {
    return if (result.isCatchOffset()) core.Value.undefinedValue() else result;
}

fn generatorPcAfterYieldStar(fb: *const bytecode.FunctionBytecode, pc: usize) ?usize {
    if (pc >= fb.byte_code.len) return null;
    const op_id = fb.byte_code[pc];
    if (op_id != op.yield_star and op_id != op.async_yield_star) return null;
    const size = bytecode.opcode.sizeOf(op_id);
    if (size == 0 or pc + size > fb.byte_code.len) return null;
    return pc + size;
}

const GeneratorReturnFinallyRange = struct {
    start: usize,
    stop: usize,
};

pub fn findGeneratorReturnFinallyTarget(fb: *const bytecode.FunctionBytecode, start_pc: u32) ?GeneratorReturnFinallyRange {
    var pc: usize = 0;
    var found: ?GeneratorReturnFinallyRange = null;
    while (pc < start_pc and pc < fb.byte_code.len) {
        const op_id = fb.byte_code[pc];
        if (op_id == op.@"catch") {
            if (pc + 5 > fb.byte_code.len) return found;
            const operand_pc = pc + 1;
            const diff = readInt(i32, fb.byte_code[operand_pc..][0..4]);
            const target = @as(i64, @intCast(operand_pc)) + @as(i64, diff);
            if (target > start_pc and target <= fb.byte_code.len) {
                if (findGeneratorReturnFinallyTargetFromCatch(fb, @intCast(target))) |candidate| {
                    if (found == null or candidate.stop > found.?.stop) {
                        found = candidate;
                    }
                }
            }
        }
        const size = bytecode.opcode.sizeOf(op_id);
        if (size == 0) return found;
        pc += size;
    }
    return found;
}

fn findGeneratorReturnFinallyTargetFromCatch(fb: *const bytecode.FunctionBytecode, catch_target: usize) ?GeneratorReturnFinallyRange {
    const rethrow_pc = findThrowFrom(fb, catch_target) orelse return null;
    if (rethrow_pc <= catch_target) return null;
    if (findForwardGotoTargetInRange(fb, catch_target, rethrow_pc)) |normal_finally_target| {
        if (normal_finally_target > rethrow_pc) {
            return .{ .start = normal_finally_target, .stop = fb.byte_code.len };
        }
    }
    return .{ .start = catch_target, .stop = rethrow_pc };
}

fn findForwardGotoTargetInRange(fb: *const bytecode.FunctionBytecode, start_pc: usize, end_pc: usize) ?usize {
    var pc = start_pc;
    var found: ?usize = null;
    while (pc < end_pc and pc < fb.byte_code.len) {
        const op_id = fb.byte_code[pc];
        if (forwardGotoTarget(fb, pc)) |target| {
            if (target > pc and target <= fb.byte_code.len) found = @intCast(target);
        }
        const size = bytecode.opcode.sizeOf(op_id);
        if (size == 0) return found;
        pc += size;
    }
    return found;
}

pub fn findEnclosingCatchTarget(fb: *const bytecode.FunctionBytecode, start_pc: u32) ?usize {
    var pc: usize = 0;
    var found: ?usize = null;
    while (pc < start_pc and pc < fb.byte_code.len) {
        const op_id = fb.byte_code[pc];
        if (op_id == op.@"catch") {
            if (pc + 5 > fb.byte_code.len) return found;
            const operand_pc = pc + 1;
            const diff = readInt(i32, fb.byte_code[operand_pc..][0..4]);
            const target = @as(i64, @intCast(operand_pc)) + @as(i64, diff);
            if (target > start_pc and target <= fb.byte_code.len) found = @intCast(target);
        }
        const size = bytecode.opcode.sizeOf(op_id);
        if (size == 0) return null;
        pc += size;
    }
    return found;
}

pub fn findThrowFrom(fb: *const bytecode.FunctionBytecode, start_pc: usize) ?usize {
    var pc = start_pc;
    while (pc < fb.byte_code.len) {
        const op_id = fb.byte_code[pc];
        if (op_id == op.throw) return pc;
        const size = bytecode.opcode.sizeOf(op_id);
        if (size == 0) return null;
        pc += size;
    }
    return null;
}

pub fn forwardGotoTarget(fb: *const bytecode.FunctionBytecode, pc: usize) ?u32 {
    const op_id = fb.byte_code[pc];
    return switch (op_id) {
        op.goto8 => blk: {
            if (pc + 1 >= fb.byte_code.len) break :blk null;
            const operand_pc = pc + 1;
            const diff: i8 = @bitCast(fb.byte_code[operand_pc]);
            const target = @as(i64, @intCast(operand_pc)) + @as(i64, diff);
            break :blk if (target > @as(i64, @intCast(pc)) and target <= @as(i64, @intCast(fb.byte_code.len))) @as(u32, @intCast(target)) else null;
        },
        op.goto16 => blk: {
            if (pc + 3 > fb.byte_code.len) break :blk null;
            const operand_pc = pc + 1;
            const diff = readInt(i16, fb.byte_code[operand_pc..][0..2]);
            const target = @as(i64, @intCast(operand_pc)) + @as(i64, diff);
            break :blk if (target > @as(i64, @intCast(pc)) and target <= @as(i64, @intCast(fb.byte_code.len))) @as(u32, @intCast(target)) else null;
        },
        op.goto => blk: {
            if (pc + 5 > fb.byte_code.len) break :blk null;
            const operand_pc = pc + 1;
            const diff = readInt(i32, fb.byte_code[operand_pc..][0..4]);
            const target = @as(i64, @intCast(operand_pc)) + @as(i64, diff);
            break :blk if (target > @as(i64, @intCast(pc)) and target <= @as(i64, @intCast(fb.byte_code.len))) @as(u32, @intCast(target)) else null;
        },
        else => null,
    };
}

pub fn closeGeneratorDestructuringIterators(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    generator: *core.Object,
) !void {
    try closeDestructuringIteratorsInValues(ctx, output, global, generator.generatorStack());
    try closeDestructuringIteratorsInValues(ctx, output, global, generator.generatorFrameLocals());
    try closeDestructuringIteratorsInValues(ctx, output, global, generator.generatorFrameArgs());
    try closeDestructuringIteratorsInValues(ctx, output, global, generator.generatorFrameVarRefs());
}

pub fn closeDestructuringIteratorsInValues(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    values: []const core.Value,
) !void {
    for (values) |value| {
        const object = property_ops.expectObject(value) catch continue;
        if (!isDestructuringIteratorState(object)) continue;
        if (destructuringIteratorStateClosing(object)) continue;
        const close_arg = value.dup();
        defer close_arg.free(ctx.runtime);
        const close_result = try qjsDestructuringClose(ctx, output, global, &.{close_arg});
        close_result.free(ctx.runtime);
    }
}

pub fn closeDestructuringIteratorsInValuesForAbruptCompletion(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    values: []const core.Value,
) void {
    for (values) |value| {
        const object = property_ops.expectObject(value) catch continue;
        if (!isDestructuringIteratorState(object)) continue;
        if (destructuringIteratorStateClosing(object)) continue;
        const close_arg = value.dup();
        defer close_arg.free(ctx.runtime);
        const pending_exception = if (ctx.hasException()) ctx.takeException() else null;
        defer if (pending_exception) |pending| pending.free(ctx.runtime);
        const close_result = qjsDestructuringClose(ctx, output, global, &.{close_arg}) catch {
            if (ctx.hasException()) ctx.clearException();
            if (pending_exception) |pending| _ = ctx.throwValue(pending.dup());
            clearDestructuringIteratorState(ctx.runtime, object) catch {};
            continue;
        };
        close_result.free(ctx.runtime);
        if (ctx.hasException()) ctx.clearException();
        if (pending_exception) |pending| _ = ctx.throwValue(pending.dup());
    }
}

pub fn qjsGeneratorSlice(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    args: []const core.Value,
) !?core.Value {
    if (!receiver.isObject()) return null;
    const object = property_ops.expectObject(receiver) catch return null;
    if (object.class_id != core.class.ids.generator) return null;

    const start = if (args.len > 0) args[0].asInt32() orelse 0 else 0;
    const out = try core.Object.createArray(ctx.runtime, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    var skipped: i32 = 0;
    while (true) {
        const next_result = (try qjsGeneratorNext(ctx, output, global, receiver, &.{})) orelse break;
        defer next_result.free(ctx.runtime);
        const next_object = try property_ops.expectObject(next_result);
        const done = next_object.getProperty(core.atom.predefinedId("done", .string).?);
        defer done.free(ctx.runtime);
        if (done.asBool() == true) break;
        const value = next_object.getProperty(core.atom.predefinedId("value", .string).?);
        defer value.free(ctx.runtime);
        if (skipped < start) {
            skipped += 1;
            continue;
        }
        try out.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(out.length), core.Descriptor.data(value, true, true, true));
    }
    return out.value();
}

pub fn qjsArrayIteratorMethod(ctx: *core.Context, global: *core.Object, receiver: core.Value, function_object: *core.Object) !?core.Value {
    return iter_vm.arrayIteratorMethod(ctx, global, receiver, function_object, primitiveObjectForAccess, isTypedArrayPrototypeMethod, arrayIteratorPrototypeFromContext);
}

pub fn qjsArrayIteratorMethodRecord(ctx: *core.Context, global: *core.Object, receiver: core.Value, function_object: *core.Object, method_id: u32) !?core.Value {
    const kind: u8 = switch (method_id) {
        @intFromEnum(builtins.array.PrototypeMethod.keys) => 1,
        @intFromEnum(builtins.array.PrototypeMethod.values) => 2,
        @intFromEnum(builtins.array.PrototypeMethod.entries) => 3,
        else => return null,
    };
    if (receiver.isNull() or receiver.isUndefined()) return error.TypeError;
    const object_value = if (receiver.isObject()) receiver.dup() else try primitiveObjectForAccess(ctx.runtime, global, receiver);
    errdefer object_value.free(ctx.runtime);
    const object = property_ops.expectObject(object_value) catch {
        object_value.free(ctx.runtime);
        return null;
    };
    if (isTypedArrayPrototypeMethod(ctx.runtime, function_object)) {
        if (!builtins.buffer.isTypedArrayObject(object)) return error.TypeError;
        if (try builtins.buffer.typedArrayDetached(object)) return error.TypeError;
        if (try builtins.buffer.typedArrayOutOfBounds(object)) return error.TypeError;
    }
    const prototype = try arrayIteratorPrototypeFromContext(ctx, global);
    const iterator = try core.Object.create(ctx.runtime, core.class.ids.array_iterator, prototype);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &iterator.header);
    iterator.iteratorTargetSlot().* = object_value;
    iterator.iteratorIndexSlot().* = 0;
    iterator.iteratorKindSlot().* = kind;
    return iterator.value();
}

pub fn qjsIteratorPrototypeAccessor(ctx: *core.Context, global: *core.Object, receiver: core.Value, args: []const core.Value, id: u32) !core.Value {
    if (id == @intFromEnum(builtins.iterator.AccessorMethod.constructor_setter)) {
        if (args.len > 0) {
            if (!args[0].isObject()) return throwTypeErrorMessage(ctx, global, "not an object");
            if (!receiver.isObject()) return throwTypeErrorMessage(ctx, global, "not an object");
        }
    } else if (id == @intFromEnum(builtins.iterator.AccessorMethod.to_string_tag_setter)) {
        const receiver_object = property_ops.expectObject(receiver) catch return throwTypeErrorMessage(ctx, global, "not an object");
        if (iteratorPrototypeFromGlobal(ctx.runtime, global)) |home| {
            if (receiver_object == home) return throwTypeErrorMessage(ctx, global, "Cannot assign to read only property");
        }
    }
    return iter_vm.qjsIteratorPrototypeAccessor(ctx, global, receiver, args, id);
}

pub fn qjsIteratorPrototypeAccessorSet(ctx: *core.Context, global: *core.Object, receiver: core.Value, atom_id: core.Atom, value: core.Value) !core.Value {
    if (atom_id == core.atom.ids.constructor) {
        if (!value.isObject()) return throwTypeErrorMessage(ctx, global, "not an object");
        if (!receiver.isObject()) return throwTypeErrorMessage(ctx, global, "not an object");
    } else if (atom_id == (core.atom.predefinedId("Symbol.toStringTag", .symbol) orelse return error.TypeError)) {
        const receiver_object = property_ops.expectObject(receiver) catch return throwTypeErrorMessage(ctx, global, "not an object");
        if (iteratorPrototypeFromGlobal(ctx.runtime, global)) |home| {
            if (receiver_object == home) return throwTypeErrorMessage(ctx, global, "Cannot assign to read only property");
        }
    }
    return iter_vm.qjsIteratorPrototypeAccessorSet(ctx, global, receiver, atom_id, value);
}

pub fn qjsIteratorCallForNativeRecord(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    switch (id) {
        @intFromEnum(builtins.iterator.AccessorMethod.constructor_getter),
        @intFromEnum(builtins.iterator.AccessorMethod.constructor_setter),
        @intFromEnum(builtins.iterator.AccessorMethod.to_string_tag_getter),
        @intFromEnum(builtins.iterator.AccessorMethod.to_string_tag_setter),
        => return @as(?core.Value, try qjsIteratorPrototypeAccessor(ctx, global, receiver, args, id)),
        else => {},
    }
    if (try qjsIteratorStaticCall(ctx, output, global, args, id, caller_function, caller_frame)) |value| return value;
    return qjsIteratorPrototypeMethodCall(ctx, output, global, receiver, args, id, caller_function, caller_frame);
}

pub fn qjsIteratorStaticCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    method_id: u32,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    return switch (method_id) {
        @intFromEnum(builtins.iterator.StaticMethod.from) => try qjsIteratorFromCall(ctx, output, global, args, caller_function, caller_frame),
        @intFromEnum(builtins.iterator.StaticMethod.concat) => try qjsIteratorConcatCall(ctx, output, global, args),
        @intFromEnum(builtins.iterator.StaticMethod.zip) => try qjsIteratorZipCall(ctx, output, global, args, false, caller_function, caller_frame),
        @intFromEnum(builtins.iterator.StaticMethod.zip_keyed) => try qjsIteratorZipCall(ctx, output, global, args, true, caller_function, caller_frame),
        else => null,
    };
}

