pub fn iteratorFlattenableForIteratorFrom(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (objectFromValue(source)) |source_object| {
        if (isDirectIteratorClass(source_object.class_id)) {
            try cacheIteratorNextMethod(ctx, output, global, source);
            return source.dup();
        }
    }

    const iterator_method = try getIteratorMethod(ctx, output, global, source);
    defer iterator_method.free(ctx.runtime);
    if (!iterator_method.isUndefined() and !iterator_method.isNull()) {
        if (!isCallableValue(iterator_method)) return error.TypeError;
        const iterator = try callValueOrBytecode(ctx, output, global, source, iterator_method, &.{}, caller_function, caller_frame);
        errdefer iterator.free(ctx.runtime);
        _ = objectFromValue(iterator) orelse return error.TypeError;
        try cacheIteratorNextMethod(ctx, output, global, iterator);
        return iterator;
    }

    const iterator_object = objectFromValue(source) orelse return error.TypeError;
    const next_key = try ctx.runtime.internAtom("next");
    defer ctx.runtime.atoms.free(next_key);
    const next_method = try getValueProperty(ctx, output, global, iterator_object.value(), next_key, caller_function, caller_frame);
    defer next_method.free(ctx.runtime);
    if (next_method.isUndefined() or next_method.isNull()) return iterator_object.value().dup();
    if (!isCallableValue(next_method)) return error.TypeError;
    const cached = iterator_object.cachedIteratorNextSlot();
    const next_cached = next_method.dup();
    const old_cached = cached.*;
    cached.* = next_cached;
    if (old_cached) |stored| stored.free(ctx.runtime);
    return iterator_object.value().dup();
}

pub fn iteratorFromSourceForIteratorFrom(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    source: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !iter_vm.IteratorFromResult {
    if (source.isString()) {
        const iterator_method = try getIteratorMethod(ctx, output, global, source);
        defer iterator_method.free(ctx.runtime);
        const iterator = try callValueOrBytecode(ctx, output, global, source, iterator_method, &.{}, caller_function, caller_frame);
        errdefer iterator.free(ctx.runtime);
        return .{ .iterator = iterator };
    }

    const source_object = objectFromValue(source) orelse return error.TypeError;
    if (iteratorIsOnIteratorPrototypeChain(ctx.runtime, global, source)) {
        return .{ .iterator = source.dup() };
    }

    const iterator_method = try getIteratorMethod(ctx, output, global, source);
    defer iterator_method.free(ctx.runtime);
    if (!iterator_method.isUndefined() and !iterator_method.isNull()) {
        if (!isCallableValue(iterator_method)) return error.TypeError;
        const iterator = try callValueOrBytecode(ctx, output, global, source, iterator_method, &.{}, caller_function, caller_frame);
        errdefer iterator.free(ctx.runtime);
        _ = objectFromValue(iterator) orelse return error.TypeError;
        return .{ .iterator = iterator };
    }

    const next_key = try ctx.runtime.internAtom("next");
    defer ctx.runtime.atoms.free(next_key);
    const next_method = try getValueProperty(ctx, output, global, source, next_key, caller_function, caller_frame);
    errdefer next_method.free(ctx.runtime);
    return .{ .iterator = source_object.value().dup(), .next_method = next_method, .wrap = true };
}

pub fn isDirectIteratorClass(class_id: core.class.ClassId) bool {
    return class_id == core.class.ids.array_iterator or
        class_id == core.class.ids.string_iterator or
        class_id == core.class.ids.map_iterator or
        class_id == core.class.ids.set_iterator or
        class_id == core.class.ids.regexp_string_iterator or
        class_id == core.class.ids.generator or
        class_id == core.class.ids.iterator_wrap;
}

pub fn iteratorIsOnIteratorPrototypeChain(rt: *core.Runtime, global: *core.Object, value: core.Value) bool {
    const iterator = objectFromValue(value) orelse return false;
    const iterator_proto = iteratorPrototypeFromGlobal(rt, global) orelse return false;
    var prototype = iterator.getPrototype();
    while (prototype) |proto| {
        if (proto == iterator_proto) return true;
        prototype = proto.getPrototype();
    }
    return false;
}

pub fn wrapIteratorFromIterator(ctx: *core.Context, global: *core.Object, iterator: core.Value, next_method: ?core.Value) !core.Value {
    var rooted_iterator = iterator;
    var rooted_next_method = next_method orelse core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_iterator },
        .{ .value = &rooted_next_method },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    const iterator_object = objectFromValue(rooted_iterator) orelse return error.TypeError;
    const prototype = try wrapForValidIteratorPrototype(ctx.runtime, global);
    const wrapper = try core.Object.create(ctx.runtime, core.class.ids.iterator_wrap, prototype);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &wrapper.header);
    wrapper.iteratorTargetSlot().* = rooted_iterator.dup();
    if (next_method != null) {
        wrapper.iteratorNextSlot().* = rooted_next_method.dup();
        return wrapper.value();
    }
    if (iterator_object.cachedIteratorNext()) |cached_next_method| {
        wrapper.iteratorNextSlot().* = cached_next_method.dup();
        iterator_object.clearCachedIteratorNext(ctx.runtime);
    }
    return wrapper.value();
}

test "wrapIteratorFromIterator roots direct function bytecode next method while creating wrapper" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try core.Object.create(rt, core.class.ids.object, null);
    defer global.value().free(rt);
    const iterator = try core.Object.create(rt, core.class.ids.object, null);
    defer iterator.value().free(rt);

    const prototype = try core.Object.create(rt, core.class.ids.object, null);
    defer prototype.value().free(rt);
    try storeRealmValue(rt, global, .wrap_for_valid_iterator_prototype, prototype.value());

    const fb_slice = try rt.memory.alloc(bytecode.FunctionBytecode, 1);
    const fb = &fb_slice[0];
    fb.* = bytecode.FunctionBytecode.init(&rt.memory, &rt.atoms, core.atom.ids.empty_string);
    fb.func_kind = .generator;
    try rt.gc.add(&fb.header);
    fb.header.destroy_fn = bytecode.function.destroyFunctionBytecode;
    fb.header.destroy_ctx = @ptrCast(rt);

    const symbol_atom = try rt.atoms.newValueSymbol("gc-wrap-iterator-next-bytecode-symbol");
    fb.cpool = try rt.memory.alloc(core.Value, 1);
    fb.cpool[0] = core.Value.symbol(symbol_atom);
    fb.cpool_count = 1;

    var next_method = core.Value.functionBytecode(&fb.header);
    var next_method_alive = true;
    defer if (next_method_alive) next_method.free(rt);

    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const wrapper_value = try wrapIteratorFromIterator(ctx, global, iterator.value(), next_method);
    var wrapper_alive = true;
    defer if (wrapper_alive) wrapper_value.free(rt);
    const wrapper = objectFromValue(wrapper_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    const stored = wrapper.iteratorNext() orelse return error.TypeError;
    try std.testing.expect(stored.same(next_method));

    wrapper_value.free(rt);
    wrapper_alive = false;
    next_method.free(rt);
    next_method_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

pub fn wrapForValidIteratorPrototype(rt: *core.Runtime, global: *core.Object) !*core.Object {
    if (cachedRealmObject(global, .wrap_for_valid_iterator_prototype)) |stored| return stored;

    const proto = try core.Object.create(rt, core.class.ids.object, iteratorPrototypeFromGlobal(rt, global));
    var proto_raw_owned = true;
    errdefer if (proto_raw_owned) core.Object.destroyFromHeader(rt, &proto.header);
    try defineNativeDataMethod(rt, proto, "next", 0);
    try tagIteratorWrapPrototypeMethod(rt, global, proto, "next", 1);
    try defineNativeDataMethod(rt, proto, "return", 0);
    try tagIteratorWrapPrototypeMethod(rt, global, proto, "return", 2);
    const value = proto.value();
    proto_raw_owned = false;
    defer value.free(rt);
    try storeRealmValue(rt, global, .wrap_for_valid_iterator_prototype, value);
    return proto;
}

pub fn tagIteratorWrapPrototypeMethod(rt: *core.Runtime, global: *core.Object, proto: *core.Object, name: []const u8, method_id: i32) !void {
    const key = try rt.internAtom(name);
    defer rt.atoms.free(key);
    const method = proto.getProperty(key);
    defer method.free(rt);
    const method_object = objectFromValue(method) orelse return;
    method_object.functionIteratorWrapMethodSlot().* = @intCast(method_id);
    if (functionPrototypeFromGlobal(rt, global)) |function_proto| {
        try method_object.setPrototype(rt, function_proto);
    }
}

pub fn qjsIteratorWrapNext(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    function_object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (function_object.functionIteratorWrapMethod() != 1) return null;
    const wrapper = objectFromValue(receiver) orelse return error.TypeError;
    if (wrapper.class_id != core.class.ids.iterator_wrap) return error.TypeError;
    const iterator = (wrapper.iteratorTargetSlot().*) orelse return error.TypeError;
    const next_method = if (wrapper.iteratorNext()) |stored| stored.dup() else blk: {
        const next_key = try ctx.runtime.internAtom("next");
        defer ctx.runtime.atoms.free(next_key);
        const method = try getValueProperty(ctx, output, global, iterator, next_key, caller_function, caller_frame);
        errdefer method.free(ctx.runtime);
        if (!isCallableValue(method)) return error.TypeError;
        break :blk method;
    };
    defer next_method.free(ctx.runtime);
    const result = try callValueOrBytecode(ctx, output, global, iterator, next_method, &.{}, caller_function, caller_frame);
    errdefer result.free(ctx.runtime);
    _ = objectFromValue(result) orelse return error.TypeError;
    return result;
}

pub fn qjsIteratorWrapReturn(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    function_object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (function_object.functionIteratorWrapMethod() != 2) return null;
    const wrapper = objectFromValue(receiver) orelse return error.TypeError;
    if (wrapper.class_id != core.class.ids.iterator_wrap) return error.TypeError;
    const iterator = (wrapper.iteratorTargetSlot().*) orelse return error.TypeError;
    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = try getValueProperty(ctx, output, global, iterator, return_key, caller_function, caller_frame);
    defer return_method.free(ctx.runtime);
    if (return_method.isUndefined() or return_method.isNull()) {
        return try createIteratorResult(ctx.runtime, global, core.Value.undefinedValue(), true);
    }
    if (!isCallableValue(return_method)) return error.TypeError;
    const result = try callValueOrBytecode(ctx, output, global, iterator, return_method, &.{}, caller_function, caller_frame);
    errdefer result.free(ctx.runtime);
    _ = objectFromValue(result) orelse return error.TypeError;
    return result;
}

pub fn qjsAsyncFromSyncIteratorMethodCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    function_object: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const method_id = function_object.asyncFromSyncIteratorMethod();
    if (method_id == 0) return null;
    const wrapper = objectFromValue(receiver) orelse return error.TypeError;
    if (wrapper.class_id != core.class.ids.async_from_sync_iterator) return error.TypeError;
    const sync_iterator = (wrapper.iteratorTargetSlot().*) orelse return error.TypeError;
    return switch (method_id) {
        1 => try qjsAsyncFromSyncIteratorNext(ctx, output, global, receiver, wrapper, sync_iterator, args, caller_function, caller_frame),
        2 => try qjsAsyncFromSyncIteratorReturn(ctx, output, global, wrapper, sync_iterator, args, caller_function, caller_frame),
        else => null,
    };
}

fn qjsAsyncFromSyncIteratorNext(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    wrapper: *core.Object,
    sync_iterator: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const next_method = if (wrapper.iteratorNext()) |stored| stored.dup() else blk: {
        const next_key = try ctx.runtime.internAtom("next");
        defer ctx.runtime.atoms.free(next_key);
        const method = try getValueProperty(ctx, output, global, sync_iterator, next_key, caller_function, caller_frame);
        errdefer method.free(ctx.runtime);
        if (!isCallableValue(method)) return error.TypeError;
        break :blk method;
    };
    defer next_method.free(ctx.runtime);
    const result = if (args.len > 0)
        callValueOrBytecode(ctx, output, global, sync_iterator, next_method, args[0..1], caller_function, caller_frame)
    else
        callValueOrBytecode(ctx, output, global, sync_iterator, next_method, &.{}, caller_function, caller_frame);
    const next_result = result catch |err| {
        return rejectedPromiseForRuntimeError(ctx, global, err, promisePrototypeFromGlobal(ctx.runtime, global));
    };
    defer next_result.free(ctx.runtime);
    _ = receiver;
    return qjsAsyncFromSyncIteratorContinuation(ctx, output, global, next_result, caller_function, caller_frame);
}

fn qjsAsyncFromSyncIteratorReturn(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    wrapper: *core.Object,
    sync_iterator: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    _ = wrapper;
    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = try getValueProperty(ctx, output, global, sync_iterator, return_key, caller_function, caller_frame);
    defer return_method.free(ctx.runtime);
    if (return_method.isUndefined() or return_method.isNull()) {
        const done_result = try createIteratorResult(ctx.runtime, global, core.Value.undefinedValue(), true);
        defer done_result.free(ctx.runtime);
        return builtins.promise.fulfilledWithPrototype(ctx.runtime, done_result, promisePrototypeFromGlobal(ctx.runtime, global));
    }
    if (!isCallableValue(return_method)) return error.TypeError;
    const result = if (args.len > 0)
        callValueOrBytecode(ctx, output, global, sync_iterator, return_method, args[0..1], caller_function, caller_frame)
    else
        callValueOrBytecode(ctx, output, global, sync_iterator, return_method, &.{}, caller_function, caller_frame);
    const return_result = result catch |err| {
        return rejectedPromiseForRuntimeError(ctx, global, err, promisePrototypeFromGlobal(ctx.runtime, global));
    };
    defer return_result.free(ctx.runtime);
    return qjsAsyncFromSyncIteratorContinuation(ctx, output, global, return_result, caller_function, caller_frame);
}

fn qjsAsyncFromSyncIteratorContinuation(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    result: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    var capability = try qjsDefaultPromiseCapability(ctx, output, global, caller_function, caller_frame);
    errdefer capability.deinit(ctx.runtime);

    const result_object = property_ops.expectObject(result) catch |err| {
        try qjsPromiseRejectCapabilityForError(ctx, output, global, capability.reject, err, caller_function, caller_frame);
        return capability.releaseCallbacks(ctx.runtime);
    };
    const done_key = core.atom.predefinedId("done", .string) orelse return error.TypeError;
    const done_value = getValueProperty(ctx, output, global, result_object.value(), done_key, caller_function, caller_frame) catch |err| {
        try qjsPromiseRejectCapabilityForError(ctx, output, global, capability.reject, err, caller_function, caller_frame);
        return capability.releaseCallbacks(ctx.runtime);
    };
    defer done_value.free(ctx.runtime);
    const done = valueTruthy(done_value);

    const value_key = core.atom.predefinedId("value", .string) orelse return error.TypeError;
    const value = getValueProperty(ctx, output, global, result_object.value(), value_key, caller_function, caller_frame) catch |err| {
        try qjsPromiseRejectCapabilityForError(ctx, output, global, capability.reject, err, caller_function, caller_frame);
        return capability.releaseCallbacks(ctx.runtime);
    };
    defer value.free(ctx.runtime);

    const promise_constructor = try qjsPromiseDefaultConstructor(ctx, global);
    defer promise_constructor.free(ctx.runtime);
    const value_wrapper_promise = qjsPromiseStaticCall(ctx, output, global, promise_constructor, &.{value}, .resolve, caller_function, caller_frame) catch |err| {
        try qjsPromiseRejectCapabilityForError(ctx, output, global, capability.reject, err, caller_function, caller_frame);
        return capability.releaseCallbacks(ctx.runtime);
    };
    defer value_wrapper_promise.free(ctx.runtime);

    const unwrap = try qjsAsyncFromSyncIteratorUnwrap(ctx.runtime, global, done);
    defer unwrap.free(ctx.runtime);

    qjsPerformPromiseThen(
        ctx,
        output,
        global,
        value_wrapper_promise,
        unwrap,
        core.Value.undefinedValue(),
        capability.resolve,
        capability.reject,
    ) catch |err| {
        try qjsPromiseRejectCapabilityForError(ctx, output, global, capability.reject, err, caller_function, caller_frame);
        return capability.releaseCallbacks(ctx.runtime);
    };
    return capability.releaseCallbacks(ctx.runtime);
}

fn qjsAsyncFromSyncIteratorUnwrap(
    rt: *core.Runtime,
    global: *core.Object,
    done: bool,
) !core.Value {
    const callback = try qjsCreateBuiltinFunction(rt, global, "", 1);
    errdefer callback.free(rt);
    const callback_object = objectFromValue(callback) orelse return error.TypeError;
    callback_object.functionAsyncFromSyncUnwrapDoneSlot().* = if (done) 2 else 1;
    return callback;
}

fn qjsAsyncFromSyncIteratorUnwrapCall(
    ctx: *core.Context,
    global: *core.Object,
    function_object: *core.Object,
    args: []const core.Value,
) !?core.Value {
    const mode = function_object.functionAsyncFromSyncUnwrapDone();
    if (mode == 0) return null;
    if (mode != 1 and mode != 2) return error.TypeError;
    const payload = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    return try createIteratorResult(ctx.runtime, global, payload, mode == 2);
}

