pub fn createArgumentsObject(ctx: *core.Context, global: *core.Object, frame: *frame_mod.Frame, mapped_override: ?bool) !core.Value {
    const mapped = if (mapped_override) |requested|
        requested and frame.function.flags.has_simple_parameter_list
    else
        !currentFrameFunctionIsStrict(frame) and frame.function.flags.has_simple_parameter_list;
    const args = if (mapped)
        frame.args[0..@min(frame.actual_arg_count, frame.args.len)]
    else if (frame.original_args.len != 0)
        frame.original_args[0..@min(frame.actual_arg_count, frame.original_args.len)]
    else
        frame.args[0..@min(frame.actual_arg_count, frame.args.len)];
    const object = try core.Object.create(ctx.runtime, if (mapped) core.class.ids.mapped_arguments else core.class.ids.arguments, objectPrototypeFromGlobal(ctx.runtime, global));
    errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
    try object.defineOwnProperty(ctx.runtime, core.atom.ids.length, core.Descriptor.data(core.Value.int32(@intCast(args.len)), true, false, true));
    if (try arrayPrototypeValuesFromGlobal(ctx.runtime, global)) |values| {
        defer values.free(ctx.runtime);
        const iterator_key = core.atom.predefinedId("Symbol.iterator", .symbol) orelse return error.TypeError;
        try object.defineOwnProperty(ctx.runtime, iterator_key, core.Descriptor.data(values, true, false, true));
    }
    const callee_key = try ctx.runtime.internAtom("callee");
    defer ctx.runtime.atoms.free(callee_key);
    if (mapped) {
        try object.defineOwnProperty(ctx.runtime, callee_key, core.Descriptor.data(frame.current_function, true, false, true));
    } else {
        const thrower = try throwTypeErrorIntrinsicForGlobal(ctx.runtime, global);
        defer thrower.free(ctx.runtime);
        try object.defineOwnProperty(ctx.runtime, callee_key, core.Descriptor.accessor(thrower, thrower, false, false));
    }
    if (mapped and args.len > 0) {
        const refs = object.argumentsVarRefsSlot();
        refs.* = try ctx.runtime.memory.alloc(core.Value, args.len);
        errdefer ctx.runtime.memory.free(core.Value, refs.*);
        @memset(refs.*, core.Value.undefinedValue());
    }
    for (args, 0..) |arg, index| {
        const refs = object.argumentsVarRefsSlot();
        if (mapped and index < refs.*.len and index < frame.args.len) {
            refs.*[index] = try ensureVarRefCell(ctx, &frame.args[index]);
        }
        const arg_value = slotValueDup(arg);
        defer arg_value.free(ctx.runtime);
        try object.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(@intCast(index)), core.Descriptor.data(arg_value, true, true, true));
    }
    return object.value();
}

pub fn throwTypeErrorIntrinsicForGlobal(rt: *core.Runtime, global: *core.Object) !core.Value {
    if (global.cachedThrowTypeErrorIntrinsic()) |stored| return stored.dup();

    const thrower = try builtins.function.nativeFunction(rt, "", 0);
    errdefer thrower.free(rt);
    const thrower_object = try property_ops.expectObject(thrower);
    try thrower_object.setFunctionRealmGlobalPtr(rt, global);
    if (functionPrototypeFromGlobal(rt, global)) |function_prototype| {
        try thrower_object.setPrototype(rt, function_prototype);
    }

    try thrower_object.defineOwnProperty(rt, core.atom.ids.length, core.Descriptor.data(core.Value.int32(0), false, false, false));
    const empty_name = try value_ops.createStringValue(rt, "");
    defer empty_name.free(rt);
    try thrower_object.defineOwnProperty(rt, core.atom.ids.name, core.Descriptor.data(empty_name, false, false, false));
    if (!thrower_object.addThrowTypeErrorIntrinsicFunction()) return error.TypeError;
    try thrower_object.freeze(rt);

    try installFunctionPrototypeThrowTypeErrorAccessors(rt, global, thrower);
    const cached_thrower = try global.cachedThrowTypeErrorIntrinsicSlot(rt);
    cached_thrower.* = thrower.dup();
    return thrower;
}

pub fn installFunctionPrototypeThrowTypeErrorAccessors(rt: *core.Runtime, global: *core.Object, thrower: core.Value) !void {
    const function_prototype = functionPrototypeFromGlobal(rt, global) orelse return;
    const arguments_key = core.atom.ids.arguments;
    try function_prototype.defineOwnProperty(rt, arguments_key, core.Descriptor.accessor(thrower, thrower, false, true));
    const caller_key = core.atom.predefinedId("caller", .string).?;
    try function_prototype.defineOwnProperty(rt, caller_key, core.Descriptor.accessor(thrower, thrower, false, true));
}

pub fn qjsThrowTypeErrorIntrinsic(ctx: *core.Context, global: *core.Object, function_object: *core.Object) !core.Value {
    const error_global = objectRealmGlobal(function_object) orelse global;
    const error_value = try createNamedError(ctx.runtime, error_global, "TypeError", "invalid property access");
    _ = ctx.throwValue(error_value);
    return error.Test262Error;
}

pub fn isThrowTypeErrorIntrinsicObject(object: *core.Object) bool {
    return object.isThrowTypeErrorIntrinsicFunction();
}

pub fn currentFrameFunctionIsStrict(frame: *frame_mod.Frame) bool {
    if (frame.function.flags.is_strict or frame.function.flags.runtime_strict) return true;
    const fb = if (functionBytecodeFromValue(frame.current_function)) |bytecode_value|
        bytecode_value
    else if (objectFromValue(frame.current_function)) |function_object|
        if (function_object.functionBytecodeSlot().*) |stored| functionBytecodeFromValue(stored) else null
    else
        null;
    if (fb) |function_bytecode| return function_bytecode.is_strict_mode or function_bytecode.runtime_strict_mode;
    return false;
}

pub fn frameArgumentsObject(ctx: *core.Context, global: *core.Object, frame: *frame_mod.Frame) !core.Value {
    if (frame.arguments_object) |value| return value.dup();
    const value = try createArgumentsObject(ctx, global, frame, null);
    frame.arguments_object = value.dup();
    return value;
}

pub fn frameArgumentsObjectForSpecialObject(ctx: *core.Context, global: *core.Object, frame: *frame_mod.Frame, subtype: u8) !core.Value {
    if (frame.arguments_object) |value| return value.dup();
    const mapped_override: ?bool = switch (subtype) {
        0 => false,
        1 => true,
        else => null,
    };
    const value = try createArgumentsObject(ctx, global, frame, mapped_override);
    frame.arguments_object = value.dup();
    return value;
}

pub fn arrayPrototypeValuesFromGlobal(rt: *core.Runtime, global: *core.Object) !?core.Value {
    const prototype = arrayPrototypeFromGlobal(rt, global) orelse return null;
    const values_key = try rt.internAtom("values");
    defer rt.atoms.free(values_key);
    return prototype.getProperty(values_key);
}

pub fn functionBytecodeFromValue(value: core.Value) ?*const bytecode.FunctionBytecode {
    const header = value.objectHeader() orelse return null;
    return @fieldParentPtr("header", header);
}

pub fn functionObjectFromValue(value: core.Value) ?*core.Object {
    if (!value.isObject()) return null;
    const header = value.refHeader() orelse return null;
    const object: *core.Object = @fieldParentPtr("header", header);
    if (object.class_id != core.class.ids.bytecode_function) return null;
    return object;
}

pub fn objectFromValue(value: core.Value) ?*core.Object {
    if (!value.isObject()) return null;
    const header = value.refHeader() orelse return null;
    return @fieldParentPtr("header", header);
}

pub fn isFunctionLikeClass(class_id: core.class.ClassId) bool {
    return class_id == core.class.ids.c_function or
        class_id == core.class.ids.c_closure or
        class_id == core.class.ids.bytecode_function or
        class_id == core.class.ids.bound_function;
}

pub fn callableObjectFromValue(value: core.Value) ?*core.Object {
    if (!value.isObject()) return null;
    const header = value.refHeader() orelse return null;
    const object: *core.Object = @fieldParentPtr("header", header);
    if (object.class_id != core.class.ids.c_function and
        object.class_id != core.class.ids.c_closure and
        object.class_id != core.class.ids.bound_function) return null;
    return object;
}

pub fn proxyTargetIsCallable(value: core.Value) bool {
    const object = objectFromValue(value) orelse return false;
    const target = object.proxyTarget() orelse return false;
    return target.isFunctionBytecode() or functionObjectFromValue(target) != null or callableObjectFromValue(target) != null or proxyTargetIsCallable(target);
}

pub fn proxyTargetIsConstructor(ctx: *core.Context, value: core.Value) bool {
    const object = objectFromValue(value) orelse return false;
    const target = object.proxyTarget() orelse return false;
    return isConstructorLike(ctx, target);
}

pub fn isConstructorLike(ctx: *core.Context, value: core.Value) bool {
    if (value.isFunctionBytecode()) {
        const fb = functionBytecodeFromValue(value) orelse return false;
        return !fb.is_arrow_function and fb.has_prototype and fb.func_kind != .generator and fb.func_kind != .async_generator;
    }
    if (functionObjectFromValue(value)) |function_object| {
        const function_value = function_object.functionBytecodeSlot().* orelse return false;
        const fb = functionBytecodeFromValue(function_value) orelse return false;
        return !fb.is_arrow_function and fb.has_prototype and fb.func_kind != .generator and fb.func_kind != .async_generator;
    }
    if (callableObjectFromValue(value)) |function_object| {
        if (function_object.class_id == core.class.ids.bound_function) {
            const target = function_object.boundTarget() orelse return false;
            return isConstructorLike(ctx, target);
        }
        if (isDateConstructorRecord(function_object)) return true;
        if (function_object.class_id == core.class.ids.c_closure) return true;
        const name = call_mod.nativeFunctionNameForVm(ctx.runtime, function_object) catch return false;
        defer ctx.runtime.memory.allocator.free(name);
        return isBuiltinConstructorName(name);
    }
    return proxyTargetIsConstructor(ctx, value);
}

pub fn createArrayFromArgs(rt: *core.Runtime, global: *core.Object, args: []const core.Value) !core.Value {
    const rooted_args = args;
    var root_slices = [_]core.runtime.ValueRootSlice{
        .{ .constant = &rooted_args },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .slices = &root_slices,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    const array = try core.Object.createArray(rt, arrayPrototypeFromGlobal(rt, global));
    errdefer core.Object.destroyFromHeader(rt, &array.header);
    try array.reserveDenseArrayElements(rt, @intCast(rooted_args.len));
    for (rooted_args, 0..) |arg, index| {
        const atom_id = core.atom.atomFromUInt32(@intCast(index));
        if (try array.appendDenseArrayIndex(rt, @intCast(index), atom_id, arg)) continue;
        try array.defineOwnProperty(rt, atom_id, core.Descriptor.data(arg, true, true, true));
    }
    return array.value();
}

test "createArrayFromArgs roots direct function bytecode args while creating array" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

