    array_value.free(rt);
    array_alive = false;
    arg_value.free(rt);
    arg_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

pub fn callProxyApply(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    proxy_value: core.Value,
    proxy: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    _ = proxy_value;
    const target_value = proxy.proxyTarget() orelse return error.TypeError;
    const handler_value = proxy.proxyHandler() orelse return error.TypeError;
    const apply_atom = try ctx.runtime.internAtom("apply");
    defer ctx.runtime.atoms.free(apply_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, apply_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        return callValueOrBytecode(ctx, output, global, this_value, target_value, args, caller_function, caller_frame);
    }
    if (!isCallableValue(trap)) return error.TypeError;
    const arg_array = try createArrayFromArgs(ctx.runtime, global, args);
    defer arg_array.free(ctx.runtime);
    return callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, this_value, arg_array }, caller_function, caller_frame);
}

pub fn constructProxy(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    proxy_value: core.Value,
    proxy: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
    new_target_value: core.Value,
) !core.Value {
    if (!proxyTargetIsConstructor(ctx, proxy_value)) return error.TypeError;
    const target_value = proxy.proxyTarget() orelse return error.TypeError;
    const handler_value = proxy.proxyHandler() orelse return error.TypeError;
    const construct_atom = try ctx.runtime.internAtom("construct");
    defer ctx.runtime.atoms.free(construct_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, construct_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        if (try qjsReflectConstructGenericCallable(ctx, output, global, target_value, new_target_value, args, caller_function, caller_frame)) |value| return value;
        return constructValueOrBytecode(ctx, output, global, target_value, args, caller_function, caller_frame);
    }
    if (!isCallableValue(trap)) return error.TypeError;
    const arg_array = try createArrayFromArgs(ctx.runtime, global, args);
    defer arg_array.free(ctx.runtime);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, arg_array, new_target_value }, caller_function, caller_frame);
    if (!result.isObject()) {
        result.free(ctx.runtime);
        return error.TypeError;
    }
    return result;
}

pub fn callBoundFunction(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const target = object.boundTarget() orelse return error.TypeError;
    const bound_this = object.boundThis() orelse return error.TypeError;
    const combined = try boundFunctionArgs(ctx.runtime, object, args);
    defer freeArgs(ctx.runtime, combined);
    return callValueOrBytecode(ctx, output, global, bound_this, target, combined, caller_function, caller_frame);
}

pub fn boundFunctionArgs(rt: *core.Runtime, object: *core.Object, args: []const core.Value) ![]core.Value {
    const bound_args = object.boundArgs();
    const bound_count = bound_args.len;
    const combined = try rt.memory.alloc(core.Value, bound_count + args.len);
    errdefer rt.memory.free(core.Value, combined);
    var filled: usize = 0;
    errdefer {
        var index: usize = 0;
        while (index < filled) : (index += 1) combined[index].free(rt);
    }
    for (bound_args, 0..) |arg, index| {
        combined[index] = arg.dup();
        filled += 1;
    }
    for (args, 0..) |arg, arg_index| {
        combined[bound_count + arg_index] = arg.dup();
        filled += 1;
    }
    return combined;
}

pub fn toPropertyKeyValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (!value.isObject()) return value.dup();
    return toPrimitiveForString(ctx, output, global, value, caller_function, caller_frame);
}

pub fn toPropertyKeyAtom(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Atom {
    const key_value = try toPropertyKeyValue(ctx, output, global, value, caller_function, caller_frame);
    defer key_value.free(ctx.runtime);
    return property_ops.propertyKeyAtom(ctx.runtime, key_value);
}

pub fn callObjectToPrimitiveMethod(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    name: []const u8,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const atom_id = try ctx.runtime.internAtom(name);
    defer ctx.runtime.atoms.free(atom_id);
    const object = try property_ops.expectObject(receiver);
    const method = try getMethodPropertyForOrdinaryToPrimitive(ctx, output, global, receiver, object, atom_id, caller_function, caller_frame);
    defer method.free(ctx.runtime);
    if (method.isUndefined() or method.isNull()) return null;
    if (!isCallableValue(method)) return null;
    const result = try callValueOrBytecode(ctx, output, global, receiver, method, &.{}, caller_function, caller_frame);
    if (result.isObject()) {
        result.free(ctx.runtime);
        return null;
    }
    return result;
}

pub fn getMethodPropertyForOrdinaryToPrimitive(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (object.proxyTarget() != null) return getProxyProperty(ctx, output, global, receiver, object, atom_id, caller_function, caller_frame);
    if (try findPropertyDescriptor(object, atom_id)) |desc| {
        defer desc.destroy(ctx.runtime);
        switch (desc.kind) {
            .data => return desc.value.dup(),
            .accessor => {
                if (desc.getter.isUndefined()) return core.Value.undefinedValue();
                return callValueOrBytecode(ctx, output, global, receiver, desc.getter, &.{}, caller_function, caller_frame);
            },
            .generic => return core.Value.undefinedValue(),
        }
    }
    return getValueProperty(ctx, output, global, receiver, atom_id, caller_function, caller_frame);
}

pub fn getValueProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const rt = ctx.runtime;
    if (value.isObject()) {
        const object = try property_ops.expectObject(value);
        if (rt.atoms.kind(atom_id) == .private) {
            const effective_atom = remapPrivateAtomForOperation(rt, caller_frame, object, atom_id);
            return getPrivateValueProperty(ctx, output, global, value, object, effective_atom, caller_function, caller_frame);
        }
        if (object.proxyTarget() != null) {
            return getProxyProperty(ctx, output, global, value, object, atom_id, caller_function, caller_frame);
        }
        if (mappedArgumentsValue(ctx.runtime, object, atom_id)) |mapped_value| return mapped_value;
        if (builtins.buffer.isTypedArrayObject(object)) {
            if (try typedArrayCanonicalGet(ctx.runtime, object, atom_id)) |indexed| return indexed;
            if (atom_id == core.atom.ids.length) return core.Value.int32(@intCast(try builtins.buffer.typedArrayLength(rt, object)));
            if (atom_id == atom_byte_length) return core.Value.int32(@intCast(try builtins.buffer.typedArrayByteLength(rt, object)));
            if (atom_id == atom_byte_offset) return core.Value.int32(@intCast(try builtins.buffer.typedArrayByteOffset(object)));
        }
        if (object.exotic == null) {
            if (object.is_array) {
                if (atom_id == core.atom.ids.length) return value_ops.length(rt, value);
                if (core.atom.isTaggedInt(atom_id)) {
                    const index = core.atom.atomToUInt32(atom_id);
                    if (object.getDenseArrayElementValue(index)) |element| return element;
                }
                if (object.getOwnDataPropertyValue(atom_id)) |own_data| return own_data;
            } else if (object.class_id == core.class.ids.object) {
                if (object.getOwnDataPropertyValue(atom_id)) |own_data| return own_data;
            }
        }
        if (try functionCallerArgumentsProperty(ctx, output, global, value, object, atom_id, caller_function, caller_frame)) |function_value| {
            return function_value;
        }
        if (try getAccessorDescriptorValue(ctx, output, global, value, object, atom_id, caller_function, caller_frame)) |accessor_value| {
            return accessor_value;
        }
        if (object.moduleNamespaceOwnBindingValue(atom_id)) |binding_value| {
            if (binding_value.isUninitialized()) {
                binding_value.free(rt);
                return error.ReferenceError;
            }
            return binding_value;
        }
        if (object.class_id == core.class.ids.dataview and
            (atom_id == atom_buffer or
                atom_id == atom_byte_length or
                atom_id == atom_byte_offset))
        {
            if (atom_id == atom_buffer) return (object.typedArrayBuffer() orelse return error.TypeError).dup();
            if (atom_id == atom_byte_length) return core.Value.int32(@intCast(try builtins.buffer.dataViewByteLength(rt, object)));
            return core.Value.int32(@intCast(try builtins.buffer.dataViewByteOffset(rt, object)));
        }
        if (object.getOwnProperty(atom_id)) |own_desc| {
            defer own_desc.destroy(rt);
            switch (own_desc.kind) {
                .data => return own_desc.value.dup(),
                .generic => return core.Value.undefinedValue(),
                .accessor => {
                    if (own_desc.getter.isUndefined()) return core.Value.undefinedValue();
                    return callValueOrBytecode(ctx, output, global, value, own_desc.getter, &.{}, caller_function, caller_frame);
                },
            }
        }
        if (try getPrototypePropertyValue(ctx, output, global, value, object, atom_id, caller_function, caller_frame)) |prototype_value| {
            return prototype_value;
        }
        const direct = object.getProperty(atom_id);
        if (!direct.isUndefined()) return direct;
        direct.free(rt);
        if (rt.atoms.kind(atom_id) == .private) return error.TypeError;
        if (object.is_array and atom_id == core.atom.ids.length) return value_ops.length(rt, value);
        if (object.class_id == core.class.ids.string) {
            if (object.objectData()) |string_data| {
                if (try getStringIndexValue(rt, string_data, atom_id)) |indexed| return indexed;
            }
        }
        if (object.is_array) return getPrototypeMethodWithFallback(rt, global, "Array", atom_id, "Object");
        if (object.class_id == core.class.ids.object) {
            if (object.null_prototype) return core.Value.undefinedValue();
            return getPrototypeMethod(rt, global, "Object", atom_id);
        }
        if (object.class_id == core.class.ids.string) return getPrototypeMethod(rt, global, "String", atom_id);
        if (object.class_id == core.class.ids.number) return getPrototypeMethod(rt, global, "Number", atom_id);
        if (object.class_id == core.class.ids.boolean) return getPrototypeMethod(rt, global, "Boolean", atom_id);
        if (object.class_id == core.class.ids.big_int) return getPrototypeMethod(rt, global, "BigInt", atom_id);
        if (object.class_id == core.class.ids.symbol) return getPrototypeMethod(rt, global, "Symbol", atom_id);
        if (isFunctionLikeClass(object.class_id)) {
            return getPrototypeMethodWithFallback(rt, global, "Function", atom_id, "Object");
        }
        if (object.class_id == core.class.ids.date) return getPrototypeMethod(rt, global, "Date", atom_id);
        if (object.class_id == core.class.ids.regexp) return getPrototypeMethodWithFallback(rt, global, "RegExp", atom_id, "Object");
        if (object.class_id == core.class.ids.promise) return getPrototypeMethod(rt, global, "Promise", atom_id);
        if (object.class_id == core.class.ids.array_buffer) return getPrototypeMethod(rt, global, "ArrayBuffer", atom_id);
        if (object.class_id == core.class.ids.shared_array_buffer) return getPrototypeMethod(rt, global, "SharedArrayBuffer", atom_id);
        if (object.class_id == core.class.ids.weak_ref) return getPrototypeMethod(rt, global, "WeakRef", atom_id);
        if (object.class_id == core.class.ids.finalization_registry) return getPrototypeMethod(rt, global, "FinalizationRegistry", atom_id);
        if (object.class_id == core.class.ids.disposable_stack) return getPrototypeMethod(rt, global, "DisposableStack", atom_id);
        if (object.class_id == core.class.ids.async_disposable_stack) return getPrototypeMethod(rt, global, "AsyncDisposableStack", atom_id);
        if (object.class_id == core.class.ids.dataview) return getPrototypeMethod(rt, global, "DataView", atom_id);
        return core.Value.undefinedValue();
    }
    if (rt.atoms.kind(atom_id) == .private) return error.TypeError;
    if (value.isString()) {
        if (atom_id == core.atom.ids.length) return value_ops.length(rt, value);
        if (try getStringIndexValue(rt, value, atom_id)) |indexed| return indexed;
        return getPrimitiveProperty(ctx, output, global, value, atom_id, caller_function, caller_frame);
    }
    if (value.isNumber() or value.isBool() or value.isBigInt() or value.isSymbol()) {
        return getPrimitiveProperty(ctx, output, global, value, atom_id, caller_function, caller_frame);
    }
    if (value.isNull() or value.isUndefined()) {
        return throwNullishPropertyTypeError(ctx, global, value, atom_id);
    }
    return error.TypeError;
}

fn functionCallerArgumentsProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!isFunctionLikeClass(object.class_id)) return null;
    if (!value_ops.atomNameEql(ctx.runtime, atom_id, "caller") and !value_ops.atomNameEql(ctx.runtime, atom_id, "arguments")) return null;
    if (object.getOwnProperty(atom_id)) |own_desc| {
        defer own_desc.destroy(ctx.runtime);
        switch (own_desc.kind) {
            .data => return own_desc.value.dup(),
            .generic => return core.Value.undefinedValue(),
            .accessor => {
                if (own_desc.getter.isUndefined()) return core.Value.undefinedValue();
                return try callValueOrBytecode(ctx, output, global, receiver, own_desc.getter, &.{}, caller_function, caller_frame);
            },
        }
    }
    if (object.functionBytecode()) |fb_value| {
        const fb = functionBytecodeFromValue(fb_value) orelse return core.Value.undefinedValue();
        if (fb.is_strict_mode or fb.runtime_strict_mode or fb.is_arrow_function or fb.func_kind == .generator or fb.func_kind == .async_generator) return error.TypeError;
        return core.Value.undefinedValue();
    }
    return error.TypeError;
}

pub fn getPrivateValueProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (object.getOwnProperty(atom_id)) |desc| {
        defer desc.destroy(ctx.runtime);
        switch (desc.kind) {
            .data => return desc.value.dup(),
            .generic => return error.TypeError,
            .accessor => {
                if (desc.getter.isUndefined()) return error.TypeError;
                return callValueOrBytecode(ctx, output, global, receiver, desc.getter, &.{}, caller_function, caller_frame);
            },
        }
    }
    return throwPrivateBrandTypeError(ctx, global, atom_id, caller_frame);
}

pub fn setPrivateValueProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    if (object.getOwnProperty(atom_id)) |desc| {
        defer desc.destroy(ctx.runtime);
        switch (desc.kind) {
            .data => {
                if (!(desc.writable orelse false)) return error.TypeError;
                if (!try object.setOwnWritableDataProperty(ctx.runtime, atom_id, value)) return error.TypeError;
                return;
            },
            .generic => return error.TypeError,
            .accessor => {
                if (desc.setter.isUndefined()) return error.TypeError;
                const result = try callValueOrBytecode(ctx, output, global, receiver, desc.setter, &.{value}, caller_function, caller_frame);
                result.free(ctx.runtime);
                return;
            },
        }
    }
    _ = try throwPrivateBrandTypeError(ctx, global, atom_id, caller_frame);
    return;
}

pub fn throwPrivateBrandTypeError(
    ctx: *core.Context,
    global: *core.Object,
    atom_id: core.Atom,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const error_global = if (caller_frame) |frame| blk: {
        const function_object = objectFromValue(frame.current_function) orelse break :blk global;
        break :blk objectRealmGlobal(function_object) orelse global;
    } else global;
    const atom_name = ctx.runtime.atoms.name(atom_id) orelse "";
    const message = try std.fmt.allocPrint(
        ctx.runtime.memory.allocator,
        "private class field '{s}' does not exist",
        .{atom_name},
    );
    defer ctx.runtime.memory.allocator.free(message);
    return throwTypeErrorMessage(ctx, error_global, message);
}

pub fn getPrimitiveProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (try getFastStringPrimitiveDataProperty(ctx, global, receiver, atom_id)) |value| return value;
    if (try getFastNumberPrimitiveDataProperty(ctx, global, receiver, atom_id)) |value| return value;

    const object_value = try primitiveObjectForAccess(ctx.runtime, global, receiver);
    defer object_value.free(ctx.runtime);
    const object = try property_ops.expectObject(object_value);
    if (try findPropertyDescriptor(object, atom_id)) |desc| {
        defer desc.destroy(ctx.runtime);
        switch (desc.kind) {
            .data => return desc.value.dup(),
            .accessor => {
                if (desc.getter.isUndefined()) return core.Value.undefinedValue();
                return callValueOrBytecode(ctx, output, global, receiver, desc.getter, &.{}, caller_function, caller_frame);
            },
            .generic => return core.Value.undefinedValue(),
        }
    }
    return core.Value.undefinedValue();
}

fn getFastStringPrimitiveDataProperty(
    ctx: *core.Context,
    global: *core.Object,
    receiver: core.Value,
    atom_id: core.Atom,
) !?core.Value {
    if (!receiver.isString()) return null;
    if (!isStandardStringPrototypeMethodAtom(ctx.runtime, atom_id)) return null;

    const proto = constructorPrototypeFromGlobal(ctx.runtime, global, "String") orelse return null;
    return ownDataOrAutoInitPropertyValue(proto, atom_id);
}

fn isStandardStringPrototypeMethodAtom(rt: *core.Runtime, atom_id: core.Atom) bool {
    const name = rt.atoms.name(atom_id) orelse return false;
    return builtins.string.prototypeMethodId(name) != null;
}

fn ownDataOrAutoInitPropertyValue(object: *core.Object, atom_id: core.Atom) ?core.Value {
    if (object.exotic != null) return null;
    for (object.properties) |entry| {
        if (entry.flags.deleted or entry.atom_id != atom_id) continue;
        if (entry.flags.accessor) return null;
        return switch (entry.slot) {
            .data => |stored| stored.dup(),
            .auto_init => object.getProperty(atom_id),
            .accessor, .deleted => null,
        };
    }
    return null;
}

fn getFastNumberPrimitiveDataProperty(
    ctx: *core.Context,
    global: *core.Object,
    receiver: core.Value,
    atom_id: core.Atom,
) !?core.Value {
    if (!receiver.isNumber()) return null;
    if (!isStandardNumberPrototypeMethodAtom(ctx.runtime, atom_id)) return null;

    const proto = constructorPrototypeFromGlobal(ctx.runtime, global, "Number") orelse return null;
    const desc = (try findPropertyDescriptor(proto, atom_id)) orelse return core.Value.undefinedValue();
    defer desc.destroy(ctx.runtime);
    return switch (desc.kind) {
        .data => desc.value.dup(),
        .generic => core.Value.undefinedValue(),
        .accessor => null,
    };
}

fn isStandardNumberPrototypeMethodAtom(rt: *core.Runtime, atom_id: core.Atom) bool {
    return value_ops.atomNameEql(rt, atom_id, "toString") or
        value_ops.atomNameEql(rt, atom_id, "toLocaleString") or
        value_ops.atomNameEql(rt, atom_id, "toFixed") or
        value_ops.atomNameEql(rt, atom_id, "toExponential") or
        value_ops.atomNameEql(rt, atom_id, "toPrecision");
}

pub fn getProxyProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    proxy: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!core.Value {
    const target_value = (proxy.proxyTarget() orelse return error.TypeError).dup();
    defer target_value.free(ctx.runtime);
    const handler_value = (proxy.proxyHandler() orelse return error.TypeError).dup();
    defer handler_value.free(ctx.runtime);
    const get_atom = try ctx.runtime.internAtom("get");
    defer ctx.runtime.atoms.free(get_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, get_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    const target = try property_ops.expectObject(target_value);
    if (trap.isUndefined() or trap.isNull()) return getValuePropertyWithReceiver(ctx, output, global, target_value, target, receiver_value, atom_id, caller_function, caller_frame);
    const key_value = try proxyTrapKeyValue(ctx.runtime, atom_id);
    defer key_value.free(ctx.runtime);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, key_value, receiver_value }, caller_function, caller_frame);
    errdefer result.free(ctx.runtime);
    try validateProxyGetResult(ctx, output, global, target, atom_id, result, caller_function, caller_frame);
    return result;
}

fn getValuePropertyWithReceiver(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target_value: core.Value,
    target: *core.Object,
    receiver_value: core.Value,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    var current: ?*core.Object = target;
    while (current) |object| : (current = object.getPrototype()) {
        if (object.proxyTarget() != null) return getProxyProperty(ctx, output, global, receiver_value, object, atom_id, caller_function, caller_frame);
        if (object.getOwnProperty(atom_id)) |desc| {
            defer desc.destroy(ctx.runtime);
            switch (desc.kind) {
                .data => return desc.value.dup(),
                .generic => return core.Value.undefinedValue(),
                .accessor => {
                    if (desc.getter.isUndefined()) return core.Value.undefinedValue();
                    return callValueOrBytecode(ctx, output, global, receiver_value, desc.getter, &.{}, caller_function, caller_frame);
                },
            }
        }
    }
    return getValueProperty(ctx, output, global, target_value, atom_id, caller_function, caller_frame);
}

fn validateProxyGetResult(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target: *core.Object,
    atom_id: core.Atom,
    result: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const target_desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, target, atom_id, caller_function, caller_frame) orelse return;
    defer target_desc.destroy(ctx.runtime);
    if (target_desc.configurable != false) return;
    switch (target_desc.kind) {
        .data => {
            if (target_desc.writable == false and !builtins.object.sameValue(result, target_desc.value)) return error.TypeError;
        },
        .accessor => {
            if (target_desc.getter.isUndefined() and !result.isUndefined()) return error.TypeError;
        },
        .generic => {},
    }
}

pub fn primitiveObjectForAccess(rt: *core.Runtime, global: *core.Object, primitive: core.Value) !core.Value {
    var rooted_primitive = primitive;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_primitive },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    if (rooted_primitive.isString()) {
        const prototype = constructorPrototypeFromGlobal(rt, global, "String") orelse return error.TypeError;
        const object = try core.Object.create(rt, core.class.ids.string, prototype);
        errdefer core.Object.destroyFromHeader(rt, &object.header);
        object.objectDataSlot().* = rooted_primitive.dup();
        const header = rooted_primitive.refHeader() orelse return error.TypeError;
        const string_value: *core.string.String = @fieldParentPtr("header", header);
        var index: u32 = 0;
        while (index < string_value.len()) : (index += 1) {
            try defineStringWrapperIndexProperty(rt, object, index, string_value.codeUnitAt(index));
        }
        try object.defineOwnProperty(rt, core.atom.ids.length, core.Descriptor.data(core.Value.int32(@intCast(string_value.len())), false, false, false));
        return object.value();
    }
    const class_id: core.class.ClassId = if (rooted_primitive.isNumber())
        core.class.ids.number
    else if (rooted_primitive.isBool())
        core.class.ids.boolean
    else if (rooted_primitive.isBigInt())
        core.class.ids.big_int
    else if (rooted_primitive.isSymbol())
        core.class.ids.symbol
    else
        return error.TypeError;
    const constructor_name = if (rooted_primitive.isNumber())
        "Number"
    else if (rooted_primitive.isBool())
        "Boolean"
    else if (rooted_primitive.isBigInt())
        "BigInt"
    else
        "Symbol";
    const prototype = constructorPrototypeFromGlobal(rt, global, constructor_name) orelse return error.TypeError;
    const object = try core.Object.create(rt, class_id, prototype);
    errdefer core.Object.destroyFromHeader(rt, &object.header);
    object.objectDataSlot().* = rooted_primitive.dup();
    return object.value();
}

test "primitiveObjectForAccess roots direct symbol while creating wrapper" {
    const rt = try core.Runtime.create(std.testing.allocator);
    const global = try core.Object.create(rt, core.class.ids.object, null);
    const symbol_constructor = try core.Object.create(rt, core.class.ids.object, null);
    const symbol_prototype = try core.Object.create(rt, core.class.ids.object, null);
    defer {
        symbol_prototype.value().free(rt);
        symbol_constructor.value().free(rt);
        global.value().free(rt);
        rt.destroy();
    }

    try symbol_constructor.defineOwnProperty(
        rt,
        core.atom.ids.prototype,
        core.Descriptor.data(symbol_prototype.value(), true, true, true),
    );
    const symbol_ctor_atom = try rt.internAtom("Symbol");
    defer rt.atoms.free(symbol_ctor_atom);
    try global.defineOwnProperty(
        rt,
        symbol_ctor_atom,
        core.Descriptor.data(symbol_constructor.value(), true, true, true),
    );

    const symbol_atom = try rt.atoms.newValueSymbol("gc-primitive-wrapper-symbol");
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const wrapper_value = try primitiveObjectForAccess(rt, global, core.Value.symbol(symbol_atom));
    var wrapper_alive = true;
    defer if (wrapper_alive) wrapper_value.free(rt);
    const wrapper = objectFromValue(wrapper_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    const stored = wrapper.objectData() orelse return error.TypeError;
    try std.testing.expect(stored.same(core.Value.symbol(symbol_atom)));

    wrapper_value.free(rt);
    wrapper_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

pub fn defineStringWrapperIndexProperty(rt: *core.Runtime, object: *core.Object, index: u32, unit: u16) !void {
    const value = if (unit <= 0xff) blk: {
        const units: [1]u16 = .{unit};
        break :blk (try core.string.String.createUtf16(rt, &units)).value();
    } else blk: {
        const units: [1]u16 = .{unit};
        break :blk (try core.string.String.createUtf16(rt, &units)).value();
    };
    defer value.free(rt);
    try object.defineOwnProperty(rt, core.atom.atomFromUInt32(index), core.Descriptor.data(value, false, true, false));
}

pub fn getStringIndexValue(rt: *core.Runtime, value: core.Value, atom_id: core.Atom) !?core.Value {
    const index = core.array.arrayIndexFromAtom(&rt.atoms, atom_id) orelse return null;
    const header = value.refHeader() orelse return null;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    if (index >= string_value.len()) return core.Value.undefinedValue();
    const unit = string_value.codeUnitAt(index);
    if (unit <= 0x7f) {
        // ASCII fast path: reuse the runtime's cached single-byte
        // strings. Hot loops like `decimalToPercentHexString` (test262's
        // URI sweep) hit this path thousands of times per inner
        // iteration, and avoiding the per-call header+bytes allocation
        // pair is a major speedup.
        const cached = (try rt.singleByteString(@intCast(unit))).?;
        const out = cached.value();
        return out.dup();
    }
    if (unit <= 0xff) {
        const units: [1]u16 = .{unit};
        const out = try core.string.String.createUtf16(rt, &units);
        return out.value();
    }
    const units: [1]u16 = .{unit};
    const out = try core.string.String.createUtf16(rt, &units);
    return out.value();
}

pub fn setValueProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object_value: core.Value,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!core.Value {
    const throw_on_set_failure = setFailureShouldThrow(caller_function);
    if (ctx.runtime.atoms.kind(atom_id) == .private) {
        if (!object_value.isObject()) return error.TypeError;
        const object = try property_ops.expectObject(object_value);
        const effective_atom = remapPrivateAtomForOperation(ctx.runtime, caller_frame, object, atom_id);
        try setPrivateValueProperty(ctx, output, global, object_value, object, effective_atom, value, caller_function, caller_frame);
        return core.Value.undefinedValue();
    }
    const is_strict = if (caller_function) |func| functionRuntimeStrict(func) else false;
    if (!object_value.isObject()) {
        if (object_value.isNull() or object_value.isUndefined()) return error.TypeError;
        const boxed_value = try primitiveObjectForAccess(ctx.runtime, global, object_value);
        defer boxed_value.free(ctx.runtime);
        const boxed = try property_ops.expectObject(boxed_value);
        const succeeded = try ordinarySetWithReceiver(ctx, output, global, boxed_value, boxed, object_value, atom_id, value, caller_function, caller_frame);
        if (!succeeded and throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.TypeError);
        return core.Value.undefinedValue();
    }
    const object = try property_ops.expectObject(object_value);
    if (object.proxyTarget() != null) {
        const ok = try proxySetValueProperty(ctx, output, global, object_value, object, atom_id, value, caller_function, caller_frame);
        if (!ok and throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.TypeError);
        return core.Value.undefinedValue();
    }
    if (object.is_with_environment and is_strict and !object.hasProperty(atom_id)) return error.ReferenceError;
    if (setMappedArgumentsValue(ctx, object, atom_id, value)) return core.Value.undefinedValue();
    if (builtins.buffer.isTypedArrayObject(object)) {
        if (try typedArrayCanonicalSet(ctx, output, global, object, atom_id, value)) {
            return core.Value.undefinedValue();
        }
    }
    if (object.is_array and atom_id == core.atom.ids.length) {
        const value_to_set = try arrayLengthAssignmentValue(ctx, output, global, object, atom_id, value, caller_function, caller_frame);
        defer if (!value_to_set.same(value)) value_to_set.free(ctx.runtime);
        object.setProperty(ctx.runtime, atom_id, value_to_set) catch |err| switch (err) {
            error.InvalidLength => return error.RangeError,
            error.ReadOnly => {
                if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.ReadOnly);
                return core.Value.undefinedValue();
            },
            error.AccessorWithoutSetter => {
                if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.AccessorWithoutSetter);
                return core.Value.undefinedValue();
            },
            error.NotExtensible => {
                if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.NotExtensible);
                return core.Value.undefinedValue();
            },
            error.IncompatibleDescriptor => {
                if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.IncompatibleDescriptor);
                return core.Value.undefinedValue();
            },
            else => return err,
        };
        return core.Value.undefinedValue();
    }
    if (object.is_array) {
        if (core.array.arrayIndexFromAtom(&ctx.runtime.atoms, atom_id)) |index| {
            if (try object.appendDenseArrayIndex(ctx.runtime, index, atom_id, value)) return core.Value.undefinedValue();
        }
    }
    if (try object.setOwnWritableDataProperty(ctx.runtime, atom_id, value)) return core.Value.undefinedValue();
    if (try object.defineNewOwnDataPropertyForSimpleSet(ctx.runtime, atom_id, value)) return core.Value.undefinedValue();
    if (try typedArrayPrototypeSet(ctx, output, global, object_value, object, object.getPrototype(), atom_id, value, caller_function, caller_frame)) |ok| {
        if (!ok and throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.TypeError);
        return core.Value.undefinedValue();
    }
    const called_setter = callAccessorSetter(ctx, output, global, object_value, object, atom_id, value, caller_function, caller_frame) catch |err| switch (err) {
        error.AccessorWithoutSetter => {
            if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.AccessorWithoutSetter);
            return core.Value.undefinedValue();
        },
        else => return err,
    };
    if (called_setter) return core.Value.undefinedValue();
    if (try firstProxyInPrototypeSetPath(ctx.runtime, object, atom_id)) |prototype_proxy| {
        const ok = try proxySetValueProperty(ctx, output, global, object_value, prototype_proxy, atom_id, value, caller_function, caller_frame);
        if (!ok and throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.TypeError);
        return core.Value.undefinedValue();
    }
    if (ctx.runtime.atoms.kind(atom_id) == .private) return error.TypeError;
    const value_to_set = try arrayLengthAssignmentValue(ctx, output, global, object, atom_id, value, caller_function, caller_frame);
    defer if (!value_to_set.same(value)) value_to_set.free(ctx.runtime);
    object.setProperty(ctx.runtime, atom_id, value_to_set) catch |err| switch (err) {
        error.InvalidLength => return error.RangeError,
        error.ReadOnly => {
            if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.ReadOnly);
            return core.Value.undefinedValue();
        },
        error.AccessorWithoutSetter => {
            if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.AccessorWithoutSetter);
            return core.Value.undefinedValue();
        },
        error.NotExtensible => {
            if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.NotExtensible);
            return core.Value.undefinedValue();
        },
        error.IncompatibleDescriptor => {
            if (throw_on_set_failure) return throwSetFailureTypeError(ctx, global, atom_id, error.IncompatibleDescriptor);
            return core.Value.undefinedValue();
        },
        else => return err,
    };
    return core.Value.undefinedValue();
}

const SetFailureError = error{
    AccessorWithoutSetter,
    IncompatibleDescriptor,
    NotExtensible,
    ReadOnly,
    TypeError,
};

fn throwSetFailureTypeError(ctx: *core.Context, global: *core.Object, atom_id: core.Atom, reason: SetFailureError) !core.Value {
    const static_message = switch (reason) {
        error.AccessorWithoutSetter => "no setter for property",
        error.NotExtensible => "object is not extensible",
        else => null,
    };
    if (static_message) |message| return throwTypeErrorMessage(ctx, global, message);

    if (ctx.runtime.atoms.name(atom_id)) |name| {
        const message = try std.fmt.allocPrint(ctx.runtime.memory.allocator, "'{s}' is read-only", .{name});
        defer ctx.runtime.memory.allocator.free(message);
        return throwTypeErrorMessage(ctx, global, message);
    }
    return throwTypeErrorMessage(ctx, global, "property is read-only");
}

fn setFailureShouldThrow(caller_function: ?*const bytecode.Bytecode) bool {
    if (caller_function) |function| return functionRuntimeStrict(function);
    return false;
}

fn functionRuntimeStrict(function: *const bytecode.Bytecode) bool {
    return function.flags.is_strict or function.flags.runtime_strict;
}

fn firstProxyInPrototypeSetPath(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom) !?*core.Object {
    var current = object.getPrototype();
    while (current) |prototype| : (current = prototype.getPrototype()) {
        if (prototype.proxyTarget() != null) return prototype;
        if (prototype.getOwnProperty(atom_id)) |desc| {
            desc.destroy(rt);
            return null;
        }
    }
    return null;
}

pub fn proxySetValueProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    proxy: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!bool {
    const target_value = proxy.proxyTarget() orelse return error.TypeError;
    const handler_value = proxy.proxyHandler() orelse return error.TypeError;
    const set_atom = try ctx.runtime.internAtom("set");
    defer ctx.runtime.atoms.free(set_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, set_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        const target = try property_ops.expectObject(target_value);
        return ordinarySetWithReceiver(ctx, output, global, target_value, target, receiver_value, atom_id, value, caller_function, caller_frame);
    }
    if (!isCallableValue(trap)) return error.TypeError;
    const key_value = try proxyTrapKeyValue(ctx.runtime, atom_id);
    defer key_value.free(ctx.runtime);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, key_value, value, receiver_value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    if (!valueTruthy(result)) return false;
    const target = try property_ops.expectObject(target_value);
    try validateProxySetResult(ctx, output, global, target, atom_id, value, caller_function, caller_frame);
    return true;
}

fn validateProxySetResult(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const target_desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, target, atom_id, caller_function, caller_frame) orelse return;
    defer target_desc.destroy(ctx.runtime);
    if (target_desc.configurable != false) return;
    switch (target_desc.kind) {
        .data => {
            if (target_desc.writable == false and !builtins.object.sameValue(value, target_desc.value)) return error.TypeError;
        },
        .accessor => {
            if (target_desc.setter.isUndefined()) return error.TypeError;
        },
        .generic => {},
    }
}

fn ordinarySetWithReceiver(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target_value: core.Value,
    target: *core.Object,
    receiver_value: core.Value,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!bool {
    _ = target_value;
    if (target.proxyTarget() != null) {
        return proxySetValueProperty(ctx, output, global, receiver_value, target, atom_id, value, caller_function, caller_frame);
    }
    const receiver_object = objectFromValue(receiver_value) orelse target;
    if (try typedArrayPrototypeSet(ctx, output, global, receiver_value, receiver_object, target.getPrototype(), atom_id, value, caller_function, caller_frame)) |ok| return ok;
    if (value_ops.atomNameEql(ctx.runtime, atom_id, "__proto__")) {
        _ = try qjsObjectProtoSetterCall(ctx, output, global, receiver_value, value, caller_function, caller_frame);
        return true;
    }
    if (target.getOwnProperty(atom_id)) |own_desc| {
        defer own_desc.destroy(ctx.runtime);
        return setWithOwnDescriptor(ctx, output, global, receiver_value, atom_id, value, own_desc, caller_function, caller_frame);
    }
    if (target.getPrototype()) |prototype| {
        return ordinarySetWithReceiver(ctx, output, global, prototype.value(), prototype, receiver_value, atom_id, value, caller_function, caller_frame);
    }
    return setWithOwnDescriptor(ctx, output, global, receiver_value, atom_id, value, core.Descriptor.data(core.Value.undefinedValue(), true, true, true), caller_function, caller_frame);
}

fn setWithOwnDescriptor(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    atom_id: core.Atom,
    value: core.Value,
    own_desc: core.Descriptor,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!bool {
    switch (own_desc.kind) {
        .accessor => {
            if (own_desc.setter.isUndefined()) return false;
            const result = try callValueOrBytecode(ctx, output, global, receiver_value, own_desc.setter, &.{value}, caller_function, caller_frame);
            result.free(ctx.runtime);
            return true;
        },
        .data, .generic => {
            if (own_desc.kind == .data and own_desc.writable == false) return false;
            const receiver = objectFromValue(receiver_value) orelse return false;
            const receiver_desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, receiver, atom_id, caller_function, caller_frame);
            defer if (receiver_desc) |desc| desc.destroy(ctx.runtime);
            if (receiver_desc) |desc| {
                if (desc.kind == .accessor) return false;
                if (desc.kind == .data and desc.writable == false) return false;
                const update_desc = core.Descriptor{
                    .kind = .data,
                    .value = value,
                    .value_present = true,
                };
                if (receiver.proxyTarget() != null) return try proxyDefineOwnProperty(ctx, output, global, receiver, atom_id, update_desc, caller_function, caller_frame);
                receiver.defineOwnProperty(ctx.runtime, atom_id, update_desc) catch |err| switch (err) {
                    error.ReadOnly, error.NotExtensible, error.IncompatibleDescriptor => return false,
                    error.InvalidLength => return error.RangeError,
                    else => return err,
                };
                return true;
            }
            const create_desc = core.Descriptor.data(value, true, true, true);
            if (receiver.proxyTarget() != null) return try proxyDefineOwnProperty(ctx, output, global, receiver, atom_id, create_desc, caller_function, caller_frame);
            receiver.defineOwnProperty(ctx.runtime, atom_id, create_desc) catch |err| switch (err) {
                error.ReadOnly, error.NotExtensible, error.IncompatibleDescriptor => return false,
                error.InvalidLength => return error.RangeError,
                else => return err,
            };
            return true;
        },
    }
}

pub fn arrayLengthAssignmentValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (!object.is_array or atom_id != core.atom.ids.length or value.isNumber()) return value;
    const first_primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer first_primitive.free(ctx.runtime);
    const first_number = try value_ops.toNumberValue(ctx.runtime, first_primitive);
    defer first_number.free(ctx.runtime);
    _ = caller_function;
    _ = caller_frame;
    const second_primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer second_primitive.free(ctx.runtime);
    return value_ops.toNumberValue(ctx.runtime, second_primitive);
}

fn typedArrayReflectSetReceiverOwn(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    receiver_object: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    if (receiver_object.proxyTarget() != null) {
        try proxyDefineValueForReflectSet(ctx, output, global, receiver_value, receiver_object, atom_id, value, caller_function, caller_frame);
        return true;
    }

    if (builtins.buffer.isTypedArrayObject(receiver_object)) {
        const typed_array_desc = core.Descriptor{
            .kind = .data,
            .value = value,
            .value_present = true,
        };
        if (try typedArrayDefineOwnPropertyVm(ctx, output, global, receiver_object, atom_id, typed_array_desc)) |ok| return ok;
    }

    if (receiver_object.getOwnProperty(atom_id)) |current| {
        defer current.destroy(ctx.runtime);
        if (current.kind == .accessor) return false;
        if (current.writable == false) return false;

        const update_desc = core.Descriptor{
            .kind = .data,
            .value = value,
            .value_present = true,
        };
        receiver_object.defineOwnProperty(ctx.runtime, atom_id, update_desc) catch |err| switch (err) {
            error.ReadOnly, error.NotExtensible, error.IncompatibleDescriptor => return false,
            error.InvalidLength => return error.RangeError,
            else => return err,
        };
        return true;
    }

    receiver_object.defineOwnProperty(ctx.runtime, atom_id, core.Descriptor.data(value, true, true, true)) catch |err| switch (err) {
        error.ReadOnly, error.NotExtensible, error.IncompatibleDescriptor => return false,
        error.InvalidLength => return error.RangeError,
        else => return err,
    };
    return true;
}

fn typedArrayPrototypeSet(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    receiver_object: *core.Object,
    prototype: ?*core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?bool {
    var current = prototype;
    while (current) |object| : (current = object.getPrototype()) {
        if (!builtins.buffer.isTypedArrayObject(object)) continue;
        switch (try typedArrayCanonicalNumericIndex(ctx.runtime, atom_id)) {
            .none => return null,
            .invalid => {
                if (sameObjectIdentity(receiver_value, object.value())) {
                    const coerced = try coerceTypedArrayElementInput(ctx, output, global, value);
                    defer coerced.free(ctx.runtime);
                    try builtins.buffer.typedArrayCoerceElementValue(ctx.runtime, object, coerced);
                }
                return true;
            },
            .index => |index| {
                if (sameObjectIdentity(receiver_value, object.value())) {
                    const coerced = try coerceTypedArrayElementForSet(ctx, output, global, object, value);
                    defer coerced.free(ctx.runtime);
                    if (!try builtins.buffer.typedArrayIndexValid(ctx.runtime, object, index)) return true;
                    if (try builtins.buffer.typedArrayImmutableBuffer(ctx.runtime, object)) return false;
                    _ = try builtins.buffer.typedArraySetElement(ctx.runtime, object, index, coerced);
                    return true;
                }
                if (!try builtins.buffer.typedArrayIndexValid(ctx.runtime, object, index)) return true;
                return try typedArrayReflectSetReceiverOwn(
                    ctx,
                    output,
                    global,
                    receiver_value,
                    receiver_object,
                    atom_id,
                    value,
                    caller_function,
                    caller_frame,
                );
            },
        }
    }
    return null;
}

pub fn qjsReflectSetCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    const set_value = if (args.len >= 3) args[2] else core.Value.undefinedValue();
    const object = property_ops.expectObject(args[0]) catch return error.TypeError;
    const key_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const atom_id = try toPropertyKeyAtom(ctx, output, global, key_value, caller_function, caller_frame);
    defer ctx.runtime.atoms.free(atom_id);
    if (object.class_id == core.class.ids.module_ns) return core.Value.boolean(false);
    if (!object.is_array or atom_id != core.atom.ids.length) {
        const receiver_value = if (args.len >= 4) args[3] else args[0];
        if (object.proxyTarget() != null) {
            const ok = try proxySetValueProperty(ctx, output, global, receiver_value, object, atom_id, set_value, caller_function, caller_frame);
            return core.Value.boolean(ok);
        }
        if (builtins.buffer.isTypedArrayObject(object)) {
            switch (try typedArrayCanonicalNumericIndex(ctx.runtime, atom_id)) {
                .none => {},
                .invalid => {
                    if (sameObjectIdentity(receiver_value, args[0])) {
                        const coerced = try coerceTypedArrayElementInput(ctx, output, global, set_value);
                        defer coerced.free(ctx.runtime);
                        try builtins.buffer.typedArrayCoerceElementValue(ctx.runtime, object, coerced);
                    }
                    return core.Value.boolean(true);
                },
                .index => |index| {
                    if (sameObjectIdentity(receiver_value, args[0])) {
                        const coerced = try coerceTypedArrayElementForSet(ctx, output, global, object, set_value);
                        defer coerced.free(ctx.runtime);
                        if (!try builtins.buffer.typedArrayIndexValid(ctx.runtime, object, index)) return core.Value.boolean(true);
                        if (try builtins.buffer.typedArrayImmutableBuffer(ctx.runtime, object)) return core.Value.boolean(false);
                        _ = try builtins.buffer.typedArraySetElement(ctx.runtime, object, index, coerced);
                        return core.Value.boolean(true);
                    }
                    if (!try builtins.buffer.typedArrayIndexValid(ctx.runtime, object, index)) return core.Value.boolean(true);
                    const receiver_object = objectFromValue(receiver_value) orelse return core.Value.boolean(false);
                    const ok = try typedArrayReflectSetReceiverOwn(ctx, output, global, receiver_value, receiver_object, atom_id, set_value, caller_function, caller_frame);
                    return core.Value.boolean(ok);
                },
            }
        }
        if (objectFromValue(receiver_value)) |receiver_object| {
            if (try typedArrayPrototypeSet(ctx, output, global, receiver_value, receiver_object, object.getPrototype(), atom_id, set_value, caller_function, caller_frame)) |ok| {
                return core.Value.boolean(ok);
            }
        }
        const ok = try ordinarySetWithReceiver(ctx, output, global, args[0], object, receiver_value, atom_id, set_value, caller_function, caller_frame);
        return core.Value.boolean(ok);
    }
    const value_to_set = try arrayLengthAssignmentValue(ctx, output, global, object, atom_id, set_value, caller_function, caller_frame);
    defer if (!value_to_set.same(set_value)) value_to_set.free(ctx.runtime);
    object.setProperty(ctx.runtime, atom_id, value_to_set) catch |err| switch (err) {
        error.ReadOnly, error.AccessorWithoutSetter, error.NotExtensible, error.IncompatibleDescriptor => return core.Value.boolean(false),
        error.InvalidLength => return error.RangeError,
        else => return err,
    };
    return core.Value.boolean(true);
}

pub fn proxyDefineValueForReflectSet(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver_value: core.Value,
    proxy: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    var rooted_value = value;
    var key_value = core.Value.undefinedValue();
    var desc_value = core.Value.undefinedValue();
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &rooted_value },
        .{ .value = &key_value },
        .{ .value = &desc_value },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    const target_value = proxy.proxyTarget() orelse return error.TypeError;
    const handler_value = proxy.proxyHandler() orelse return error.TypeError;
    key_value = try proxyTrapKeyValue(ctx.runtime, atom_id);
    defer key_value.free(ctx.runtime);

    const get_desc_atom = try ctx.runtime.internAtom("getOwnPropertyDescriptor");
    defer ctx.runtime.atoms.free(get_desc_atom);
    const get_desc = try getValueProperty(ctx, output, global, handler_value, get_desc_atom, caller_function, caller_frame);
    defer get_desc.free(ctx.runtime);
    if (!get_desc.isUndefined() and !get_desc.isNull()) {
        if (!isCallableValue(get_desc)) return error.TypeError;
        const result = try callValueOrBytecode(ctx, output, global, handler_value, get_desc, &.{ target_value, key_value }, caller_function, caller_frame);
        result.free(ctx.runtime);
    }

    const define_atom = try ctx.runtime.internAtom("defineProperty");
    defer ctx.runtime.atoms.free(define_atom);
    const define = try getValueProperty(ctx, output, global, handler_value, define_atom, caller_function, caller_frame);
    defer define.free(ctx.runtime);
    if (define.isUndefined() or define.isNull()) {
        const target = try property_ops.expectObject(target_value);
        target.defineOwnProperty(ctx.runtime, atom_id, core.Descriptor.data(rooted_value, true, true, true)) catch |err| switch (err) {
            error.InvalidLength => return error.RangeError,
            error.ReadOnly, error.NotExtensible, error.IncompatibleDescriptor => return error.TypeError,
            else => return err,
        };
        return;
    }
    if (!isCallableValue(define)) return error.TypeError;
    const desc_object = try core.Object.create(ctx.runtime, core.class.ids.object, objectPrototypeFromGlobal(ctx.runtime, global));
    desc_value = desc_object.value();
    defer desc_value.free(ctx.runtime);
    try defineValueProperty(ctx.runtime, desc_object, "value", rooted_value);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, define, &.{ target_value, key_value, desc_value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    if (!valueTruthy(result)) return error.TypeError;
    _ = receiver_value;
}

pub fn qjsArrayToStringCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    function_object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!isArrayPrototypeRecord(function_object, @intFromEnum(builtins.array.PrototypeMethod.to_string))) {
        if (function_object.arrayBuiltinMarker() != .to_string) return null;
    }
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const object_value = if (this_value.isObject()) this_value.dup() else try primitiveObjectForAccess(ctx.runtime, global, this_value);
    defer object_value.free(ctx.runtime);
    const join_atom = try ctx.runtime.internAtom("join");
    defer ctx.runtime.atoms.free(join_atom);
    const join_value = try getValueProperty(ctx, output, global, object_value, join_atom, caller_function, caller_frame);
    defer join_value.free(ctx.runtime);
    if (isCallableValue(join_value)) {
        return try callValueOrBytecode(ctx, output, global, object_value, join_value, &.{}, caller_function, caller_frame);
    }
    return try qjsObjectToStringIntrinsic(ctx, output, global, object_value, caller_function, caller_frame);
}

pub fn qjsArrayJoinCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    function_object: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const object_value = if (this_value.isObject()) this_value.dup() else try primitiveObjectForAccess(ctx.runtime, global, this_value);
    defer object_value.free(ctx.runtime);
    const object = property_ops.expectObject(object_value) catch return null;
    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    const is_typed_array = builtins.buffer.isTypedArrayObject(object);
    if (is_typed_method and !is_typed_array) return error.TypeError;
    if (!is_typed_method and !is_typed_array) {
        if (try qjsFastDensePrimitiveArrayJoin(ctx.runtime, object, args)) |joined| return joined;
    }
    const length = if (is_typed_array)
        try arrayMethodTypedArrayLength(ctx.runtime, object, is_typed_method)
    else if (object.is_array)
        @as(usize, @intCast(object.length))
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, object_value, core.atom.ids.length, caller_function, caller_frame);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };
    const separator_value = if (args.len >= 1 and !args[0].isUndefined()) args[0] else try value_ops.createStringValue(ctx.runtime, ",");
    defer if (args.len < 1 or args[0].isUndefined()) separator_value.free(ctx.runtime);
    const separator_string = try toStringForAnnexB(ctx, output, global, separator_value, caller_function, caller_frame);
    defer separator_string.free(ctx.runtime);
    var separator = std.ArrayList(u8).empty;
    defer separator.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendRawString(ctx.runtime, &separator, separator_string);

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(ctx.runtime.memory.allocator);
    var index: usize = 0;
    while (index < length) : (index += 1) {
        if (index != 0) try bytes.appendSlice(ctx.runtime.memory.allocator, separator.items);
        const item = if (is_typed_array) blk: {
            if (!is_typed_method and index >= try arrayMethodTypedArrayLength(ctx.runtime, object, false)) break :blk core.Value.undefinedValue();
            break :blk try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(index));
        } else blk: {
            const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
            defer key.deinit(ctx.runtime);
            break :blk try getValueProperty(ctx, output, global, object_value, key.atom, caller_function, caller_frame);
        };
        defer item.free(ctx.runtime);
        if (!item.isUndefined() and !item.isNull()) {
            const string_item = try toStringForAnnexB(ctx, output, global, item, caller_function, caller_frame);
            defer string_item.free(ctx.runtime);
            try value_ops.appendRawString(ctx.runtime, &bytes, string_item);
        }
    }
    return try value_ops.createStringValue(ctx.runtime, bytes.items);
}

fn qjsFastDensePrimitiveArrayJoin(
    rt: *core.Runtime,
    object: *core.Object,
    args: []const core.Value,
) !?core.Value {
    if (!object.is_array or object.exotic != null or object.arrayElementStorageMode() != .dense) return null;
    if (object.properties.len != 0) return null;

    const length: usize = @intCast(object.length);
    const elements = object.arrayElements();
    if (length > elements.len) return null;

    var separator = std.ArrayList(u8).empty;
    defer separator.deinit(rt.memory.allocator);
    if (args.len == 0 or args[0].isUndefined()) {
        try separator.append(rt.memory.allocator, ',');
    } else if (args[0].isString()) {
        try value_ops.appendRawString(rt, &separator, args[0]);
    } else {
        return null;
    }

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(rt.memory.allocator);
    var index: usize = 0;
    while (index < length) : (index += 1) {
        const item = elements[index] orelse return null;
        if (!qjsCanFastJoinPrimitive(item)) return null;
        if (index != 0) try bytes.appendSlice(rt.memory.allocator, separator.items);
        if (!item.isUndefined() and !item.isNull()) try value_ops.appendValueString(rt, &bytes, item);
    }
    return try value_ops.createStringValue(rt, bytes.items);
}

fn qjsCanFastJoinPrimitive(value: core.Value) bool {
    return value.isUndefined() or
        value.isNull() or
        value.isString() or
        value.isNumber() or
        value.isBool() or
        value.isBigInt();
}

pub fn qjsArrayToLocaleStringCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    function_object: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (!isArrayPrototypeRecord(function_object, @intFromEnum(builtins.array.PrototypeMethod.to_locale_string))) {
        if (function_object.arrayBuiltinMarker() != .to_locale_string) return null;
    }
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const object_value = if (this_value.isObject()) this_value.dup() else try primitiveObjectForAccess(ctx.runtime, global, this_value);
    defer object_value.free(ctx.runtime);
    const object = property_ops.expectObject(object_value) catch return null;
    const is_typed_method = isTypedArrayPrototypeMethod(ctx.runtime, function_object);
    const is_typed_array = builtins.buffer.isTypedArrayObject(object);
    if (is_typed_method and !is_typed_array) return error.TypeError;
    const length = if (is_typed_array)
        try arrayMethodTypedArrayLength(ctx.runtime, object, is_typed_method)
    else blk: {
        const length_value = try getValueProperty(ctx, output, global, object_value, core.atom.ids.length, caller_function, caller_frame);
        defer length_value.free(ctx.runtime);
        break :blk try toLengthIndex(ctx, output, global, length_value);
    };
    const to_locale_key = try ctx.runtime.internAtom("toLocaleString");
    defer ctx.runtime.atoms.free(to_locale_key);

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(ctx.runtime.memory.allocator);
    var index: usize = 0;
    while (index < length) : (index += 1) {
        if (index != 0) try bytes.append(ctx.runtime.memory.allocator, ',');
        const item = if (is_typed_array) blk: {
            if (!is_typed_method and index >= try arrayMethodTypedArrayLength(ctx.runtime, object, false)) break :blk core.Value.undefinedValue();
            break :blk try builtins.buffer.typedArrayGetIndex(ctx.runtime, object, @intCast(index));
        } else blk: {
            const key = try propertyAtomFromLengthIndex(ctx.runtime, index);
            defer key.deinit(ctx.runtime);
            break :blk try getValueProperty(ctx, output, global, object_value, key.atom, caller_function, caller_frame);
        };
        defer item.free(ctx.runtime);
        if (!item.isUndefined() and !item.isNull()) {
            const method = try getValueProperty(ctx, output, global, item, to_locale_key, caller_function, caller_frame);
            defer method.free(ctx.runtime);
            const locale_value = try callValueOrBytecode(ctx, output, global, item, method, &.{}, caller_function, caller_frame);
            defer locale_value.free(ctx.runtime);
            const locale_string = try toStringForAnnexB(ctx, output, global, locale_value, caller_function, caller_frame);
            defer locale_string.free(ctx.runtime);
            try value_ops.appendRawString(ctx.runtime, &bytes, locale_string);
