    return try value_ops.createStringValue(ctx.runtime, bytes.items);
}

pub fn qjsObjectToLocaleStringCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const to_string_key = try ctx.runtime.internAtom("toString");
    defer ctx.runtime.atoms.free(to_string_key);
    const method = try getValueProperty(ctx, output, global, this_value, to_string_key, caller_function, caller_frame);
    defer method.free(ctx.runtime);
    return try callValueOrBytecode(ctx, output, global, this_value, method, &.{}, caller_function, caller_frame);
}

pub fn qjsObjectToStringCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isUndefined()) return try qjsObjectTagString(ctx.runtime, "Undefined");
    if (this_value.isNull()) return try qjsObjectTagString(ctx.runtime, "Null");
    const object_value = if (this_value.isObject()) this_value.dup() else try primitiveObjectForAccess(ctx.runtime, global, this_value);
    defer object_value.free(ctx.runtime);
    return try qjsObjectToStringIntrinsic(ctx, output, global, object_value, caller_function, caller_frame);
}

pub fn qjsObjectValueOfCall(rt: *core.Runtime, global: *core.Object, this_value: core.Value) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    if (this_value.isObject()) return this_value.dup();
    return primitiveObjectForAccess(rt, global, this_value);
}

pub fn qjsObjectToStringIntrinsic(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    const object = try property_ops.expectObject(object_value);
    const builtin_tag = try defaultObjectToStringTag(object);
    const tag_atom = core.atom.predefinedId("Symbol.toStringTag", .symbol) orelse return try qjsObjectTagString(ctx.runtime, "Object");
    const tag_value = try getValueProperty(ctx, output, global, object_value, tag_atom, caller_function, caller_frame);
    defer tag_value.free(ctx.runtime);
    if (tag_value.isString()) {
        var tag = std.ArrayList(u8).empty;
        defer tag.deinit(ctx.runtime.memory.allocator);
        try value_ops.appendRawString(ctx.runtime, &tag, tag_value);
        return try qjsObjectTagString(ctx.runtime, tag.items);
    }
    return try qjsObjectTagString(ctx.runtime, builtin_tag);
}

pub fn qjsObjectTagString(rt: *core.Runtime, tag: []const u8) !core.Value {
    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(rt.memory.allocator);
    try bytes.appendSlice(rt.memory.allocator, "[object ");
    try bytes.appendSlice(rt.memory.allocator, tag);
    try bytes.appendSlice(rt.memory.allocator, "]");
    return value_ops.createStringValue(rt, bytes.items);
}

pub fn defaultObjectToStringTag(object: *core.Object) ![]const u8 {
    if (object.is_proxy) {
        if (object.proxyHandler() == null) return error.TypeError;
        if (object.proxyTarget()) |target_value| {
            if (objectFromValue(target_value)) |target| {
                if (try objectIsArrayForToString(target)) return "Array";
                if (proxyTargetIsCallableObject(target)) return "Function";
            }
        }
        return "Object";
    }
    if (object.is_array) return "Array";
    return switch (object.class_id) {
        core.class.ids.arguments, core.class.ids.mapped_arguments => "Arguments",
        core.class.ids.error_ => "Error",
        core.class.ids.generator_function => "GeneratorFunction",
        core.class.ids.async_function => "AsyncFunction",
        core.class.ids.bytecode_function => bytecodeFunctionObjectTag(object),
        core.class.ids.c_function,
        core.class.ids.bound_function,
        core.class.ids.c_function_data,
        core.class.ids.c_closure,
        => "Function",
        core.class.ids.boolean => "Boolean",
        core.class.ids.number => "Number",
        core.class.ids.string => "String",
        core.class.ids.date => "Date",
        core.class.ids.regexp => "RegExp",
        core.class.ids.array_buffer => "ArrayBuffer",
        else => "Object",
    };
}

pub fn objectIsArrayForToString(object: *core.Object) !bool {
    if (object.is_array) return true;
    if (!object.is_proxy) return false;
    if (object.proxyHandler() == null) return error.TypeError;
    const target_value = object.proxyTarget() orelse return false;
    const target = objectFromValue(target_value) orelse return false;
    return objectIsArrayForToString(target);
}

pub fn proxyTargetIsCallableObject(object: *core.Object) bool {
    if (isFunctionLikeClass(object.class_id)) return true;
    if (!object.is_proxy) return false;
    const target = object.proxyTarget() orelse return false;
    return target.isFunctionBytecode() or functionObjectFromValue(target) != null or callableObjectFromValue(target) != null or proxyTargetIsCallable(target);
}

pub fn bytecodeFunctionObjectTag(object: *core.Object) []const u8 {
    const function_value = object.functionBytecodeSlot().* orelse return "Function";
    const function_bytecode = functionBytecodeFromValue(function_value) orelse return "Function";
    if (function_bytecode.func_kind == .async or function_bytecode.func_kind == .async_generator) return "AsyncFunction";
    if (function_bytecode.func_kind == .generator) return "GeneratorFunction";
    return "Function";
}

fn qjsDefinePropertyWithKind(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    kind: i32,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    const object = property_ops.expectObject(args[0]) catch return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "not an object"));
    if (args.len < 2) return error.TypeError;
    const atom_id = try toPropertyKeyAtom(ctx, output, global, args[1], caller_function, caller_frame);
    defer ctx.runtime.atoms.free(atom_id);
    if (args.len < 3) return error.TypeError;
    const desc_object = property_ops.expectObject(args[2]) catch return error.TypeError;
    const desc = try qjsDescriptorFromObject(ctx, output, global, args[2], desc_object, object, atom_id, caller_function, caller_frame);
    defer desc.destroy(ctx.runtime);
    const defined = if (object.proxyTarget() != null)
        proxyDefineOwnProperty(ctx, output, global, object, atom_id, desc, caller_function, caller_frame) catch |err| switch (err) {
            error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => {
                if (kind == 2) return core.Value.boolean(false);
                return error.TypeError;
            },
            error.InvalidLength => return error.RangeError,
            else => return err,
        }
    else blk: {
        if (try typedArrayDefineOwnPropertyVm(ctx, output, global, object, atom_id, desc)) |ok| {
            break :blk ok;
        } else {
            object.defineOwnProperty(ctx.runtime, atom_id, desc) catch |err| switch (err) {
                error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => {
                    if (kind == 2) return core.Value.boolean(false);
                    return error.TypeError;
                },
                error.InvalidLength => return error.RangeError,
                else => return err,
            };
            break :blk true;
        }
    };
    if (!defined) {
        if (kind == 2) return core.Value.boolean(false);
        return error.TypeError;
    }
    if (kind == 2) return core.Value.boolean(true);
    return args[0].dup();
}

pub fn proxyDefineOwnProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    proxy: *core.Object,
    atom_id: core.Atom,
    desc: core.Descriptor,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    const target_value = proxy.proxyTarget() orelse return error.TypeError;
    const target = property_ops.expectObject(target_value) catch return error.TypeError;
    const handler_value = proxy.proxyHandler() orelse return error.TypeError;
    const trap_atom = try ctx.runtime.internAtom("defineProperty");
    defer ctx.runtime.atoms.free(trap_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        if (target.proxyTarget() != null) return try proxyDefineOwnProperty(ctx, output, global, target, atom_id, desc, caller_function, caller_frame);
        target.defineOwnProperty(ctx.runtime, atom_id, desc) catch |err| switch (err) {
            error.ReadOnly, error.NotExtensible, error.IncompatibleDescriptor => return false,
            error.InvalidLength => return error.RangeError,
            else => return err,
        };
        return true;
    }
    if (!isCallableValue(trap)) return error.TypeError;
    const key_value = try proxyTrapKeyValue(ctx.runtime, atom_id);
    defer key_value.free(ctx.runtime);
    const desc_value = try descriptorObjectFromDescriptor(ctx.runtime, global, desc);
    defer desc_value.free(ctx.runtime);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, key_value, desc_value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    if (!valueTruthy(result)) return false;
    const target_desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, target, atom_id, caller_function, caller_frame);
    defer if (target_desc) |item| item.destroy(ctx.runtime);
    const target_extensible = try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame);
    if (!try isCompatibleProxyDescriptor(target_extensible, target_desc, desc)) return error.TypeError;
    const setting_config_false = desc.configurable == false;
    if (setting_config_false) {
        if (target_desc) |item| {
            if (item.configurable != false) return error.TypeError;
        } else {
            return error.TypeError;
        }
    }
    if (target_desc) |item| {
        if (item.configurable == false and item.kind == .data and item.writable == true and desc.kind == .data and desc.writable == false) return error.TypeError;
    }
    return true;
}

const PendingPropertyDescriptor = struct {
    atom_id: core.Atom,
    desc: core.Descriptor,

    fn destroy(self: PendingPropertyDescriptor, rt: *core.Runtime) void {
        rt.atoms.free(self.atom_id);
        self.desc.destroy(rt);
    }
};

pub fn qjsDefinePropertiesCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 2) return error.TypeError;
    const target = property_ops.expectObject(args[0]) catch return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "not an object"));
    try qjsDefinePropertiesOnTarget(ctx, output, global, target, args[1], caller_function, caller_frame);
    return args[0].dup();
}

pub fn qjsObjectCreateCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    const prototype: ?*core.Object = if (args[0].isNull())
        null
    else
        objectFromValue(args[0]) orelse return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "object prototype may only be an Object or null"));
    const object = try core.Object.create(ctx.runtime, core.class.ids.object, prototype);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
    object.null_prototype = args[0].isNull();
    if (args.len >= 2 and !args[1].isUndefined()) {
        try qjsDefinePropertiesOnTarget(ctx, output, global, object, args[1], caller_function, caller_frame);
    }
    return object.value();
}

pub fn qjsObjectAssignCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    if (args[0].isNull() or args[0].isUndefined()) return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "Cannot convert undefined or null to object"));
    const target_value = if (objectFromValue(args[0])) |_| args[0].dup() else try primitiveObjectForAccess(ctx.runtime, global, args[0]);
    errdefer target_value.free(ctx.runtime);
    _ = objectFromValue(target_value) orelse return error.TypeError;

    for (args[1..]) |source_arg| {
        if (source_arg.isNull() or source_arg.isUndefined()) continue;
        const source_value = if (objectFromValue(source_arg)) |_| source_arg.dup() else try primitiveObjectForAccess(ctx.runtime, global, source_arg);
        defer source_value.free(ctx.runtime);
        const source = objectFromValue(source_value) orelse return error.TypeError;
        const keys = try objectRestOwnKeys(ctx, output, global, source);
        defer core.Object.freeKeys(ctx.runtime, keys);
        if (source.proxyTarget() != null) {
            try qjsObjectAssignKeys(ctx, output, global, target_value, source_value, source, keys, null, caller_function, caller_frame);
        } else {
            try qjsObjectAssignKeys(ctx, output, global, target_value, source_value, source, keys, false, caller_function, caller_frame);
            try qjsObjectAssignKeys(ctx, output, global, target_value, source_value, source, keys, true, caller_function, caller_frame);
        }
    }

    return target_value;
}

pub fn qjsObjectAssignKeys(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target_value: core.Value,
    source_value: core.Value,
    source: *core.Object,
    keys: []const core.Atom,
    symbol_pass: ?bool,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    for (keys) |key| {
        const is_symbol = ctx.runtime.atoms.kind(key) == .symbol;
        if (symbol_pass) |pass| {
            if (is_symbol != pass) continue;
        }
        const desc = try objectRestOwnPropertyDescriptor(ctx, output, global, source, key) orelse continue;
        defer desc.destroy(ctx.runtime);
        if (desc.enumerable != true) continue;
        const value = try getValueProperty(ctx, output, global, source_value, key, caller_function, caller_frame);
        defer value.free(ctx.runtime);
        try setValuePropertyStrict(ctx, output, global, target_value, key, value, caller_function, caller_frame);
    }
}

pub fn qjsObjectEnumerableOwnPropertiesCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    mode: builtins.object.EntriesMode,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    if (args[0].isNull() or args[0].isUndefined()) return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "Cannot convert undefined or null to object"));

    var object_value = if (objectFromValue(args[0])) |_| args[0].dup() else try primitiveObjectForAccess(ctx.runtime, global, args[0]);
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return error.TypeError;
    const keys = try objectRestOwnKeys(ctx, output, global, object);
    defer core.Object.freeKeys(ctx.runtime, keys);

    const out = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    var out_value = out.value();

    var element = core.Value.undefinedValue();
    defer element.free(ctx.runtime);

    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &object_value },
        .{ .value = &out_value },
        .{ .value = &element },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    for (keys) |key| {
        if (ctx.runtime.atoms.kind(key) == .symbol) continue;
        const desc = try objectRestOwnPropertyDescriptor(ctx, output, global, object, key) orelse continue;
        defer desc.destroy(ctx.runtime);
        if (desc.enumerable != true) continue;

        element = switch (mode) {
            .keys => try ctx.runtime.atoms.toStringValue(ctx.runtime, key),
            .values => try getValueProperty(ctx, output, global, object_value, key, caller_function, caller_frame),
            .entries => try qjsObjectEntryArrayValue(ctx, output, global, object_value, key, caller_function, caller_frame),
        };
        errdefer {
            element.free(ctx.runtime);
            element = core.Value.undefinedValue();
        }
        try createDataPropertyOrThrow(ctx, output, global, out_value, out, core.atom.atomFromUInt32(out.length), element, caller_function, caller_frame);
        element.free(ctx.runtime);
        element = core.Value.undefinedValue();
    }
    return out_value;
}

pub fn qjsObjectEntryArrayValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object_value: core.Value,
    key: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    var value = core.Value.undefinedValue();
    defer value.free(ctx.runtime);
    var entry_value = core.Value.undefinedValue();
    errdefer entry_value.free(ctx.runtime);
    var key_value = core.Value.undefinedValue();
    defer key_value.free(ctx.runtime);

    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &value },
        .{ .value = &entry_value },
        .{ .value = &key_value },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = ctx.runtime.active_value_roots,
        .values = &root_values,
    };
    ctx.runtime.active_value_roots = &root_frame;
    defer ctx.runtime.active_value_roots = root_frame.previous;

    value = try getValueProperty(ctx, output, global, object_value, key, caller_function, caller_frame);

    const entry = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
    entry_value = entry.value();

    key_value = try ctx.runtime.atoms.toStringValue(ctx.runtime, key);

    try createDataPropertyOrThrow(ctx, output, global, entry_value, entry, core.atom.atomFromUInt32(0), key_value, caller_function, caller_frame);
    try createDataPropertyOrThrow(ctx, output, global, entry_value, entry, core.atom.atomFromUInt32(1), value, caller_function, caller_frame);

    return entry_value;
}

test "qjsObjectEntryArrayValue roots direct symbol value while creating entry array" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try qjs_vm.ensureContextGlobal(ctx);

    const source = try core.Object.create(rt, core.class.ids.object, objectPrototypeFromGlobal(rt, global));
    var source_alive = true;
    defer if (source_alive) source.value().free(rt);
    const key = try rt.internAtom("entry");
    defer rt.atoms.free(key);
    const symbol_atom = try rt.atoms.newValueSymbol("gc-qjs-object-entry-symbol");
    try source.defineOwnProperty(rt, key, core.Descriptor.data(core.Value.symbol(symbol_atom), true, true, true));

    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const entry_value = try qjsObjectEntryArrayValue(ctx, null, global, source.value(), key, null, null);
    var entry_alive = true;
    defer if (entry_alive) entry_value.free(rt);
    const entry = try property_ops.expectObject(entry_value);

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    {
        const stored = entry.getProperty(core.atom.atomFromUInt32(1));
        defer stored.free(rt);
        try std.testing.expect(stored.same(core.Value.symbol(symbol_atom)));
    }

    entry_value.free(rt);
    entry_alive = false;
    source.value().free(rt);
    source_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

test "qjsObjectEnumerableOwnPropertiesCall roots direct symbol values while creating output array" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();
    const global = try qjs_vm.ensureContextGlobal(ctx);

    const source = try core.Object.create(rt, core.class.ids.object, objectPrototypeFromGlobal(rt, global));
    var source_alive = true;
    defer if (source_alive) source.value().free(rt);
    const key = try rt.internAtom("value");
    defer rt.atoms.free(key);
    const symbol_atom = try rt.atoms.newValueSymbol("gc-qjs-object-values-symbol");
    try source.defineOwnProperty(rt, key, core.Descriptor.data(core.Value.symbol(symbol_atom), true, true, true));

    const args = [_]core.Value{source.value()};
    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const out_value = (try qjsObjectEnumerableOwnPropertiesCall(ctx, null, global, &args, .values, null, null)) orelse return error.TypeError;
    var out_alive = true;
    defer if (out_alive) out_value.free(rt);
    const out = try property_ops.expectObject(out_value);

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    {
        const stored = out.getProperty(core.atom.atomFromUInt32(0));
        defer stored.free(rt);
        try std.testing.expect(stored.same(core.Value.symbol(symbol_atom)));
    }

    out_value.free(rt);
    out_alive = false;
    source.value().free(rt);
    source_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

pub fn qjsObjectHasOwnCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return null;
    if (args[0].isNull() or args[0].isUndefined()) return error.TypeError;
    const object_value = if (objectFromValue(args[0])) |_| args[0].dup() else try primitiveObjectForAccess(ctx.runtime, global, args[0]);
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return error.TypeError;
    const key_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const atom_id = try toPropertyKeyAtom(ctx, output, global, key_value, caller_function, caller_frame);
    defer ctx.runtime.atoms.free(atom_id);
    const desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, object, atom_id, caller_function, caller_frame) orelse return core.Value.boolean(false);
    desc.destroy(ctx.runtime);
    return core.Value.boolean(true);
}

pub fn qjsObjectPrototypeOwnPropertyCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    method_id: u32,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const object_mod = builtins.object;
    if (method_id != @intFromEnum(object_mod.PrototypeMethod.has_own_property) and method_id != @intFromEnum(object_mod.PrototypeMethod.property_is_enumerable)) return null;

    const key_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const atom_id = try toPropertyKeyAtom(ctx, output, global, key_value, caller_function, caller_frame);
    defer ctx.runtime.atoms.free(atom_id);

    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const object_value = if (objectFromValue(this_value)) |_| this_value.dup() else try primitiveObjectForAccess(ctx.runtime, global, this_value);
    defer object_value.free(ctx.runtime);
    const object = property_ops.expectObject(object_value) catch return error.TypeError;
    const desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, object, atom_id, caller_function, caller_frame) orelse return core.Value.boolean(false);
    defer desc.destroy(ctx.runtime);
    if (method_id == @intFromEnum(object_mod.PrototypeMethod.property_is_enumerable)) return core.Value.boolean(desc.enumerable orelse false);
    return core.Value.boolean(true);
}

pub fn qjsObjectPrototypeDefineAccessorCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    getter: bool,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const object_value = if (objectFromValue(this_value)) |_| this_value.dup() else try primitiveObjectForAccess(ctx.runtime, global, this_value);
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return error.TypeError;
    const accessor_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    if (!isCallableValue(accessor_value)) return error.TypeError;
    const key_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const key = try toPropertyKeyAtom(ctx, output, global, key_value, caller_function, caller_frame);
    defer ctx.runtime.atoms.free(key);

    const desc = if (getter) core.Descriptor{
        .kind = .accessor,
        .getter = accessor_value.dup(),
        .getter_present = true,
        .enumerable = true,
        .configurable = true,
    } else core.Descriptor{
        .kind = .accessor,
        .setter = accessor_value.dup(),
        .setter_present = true,
        .enumerable = true,
        .configurable = true,
    };
    defer desc.destroy(ctx.runtime);
    const defined = if (object.proxyTarget() != null)
        proxyDefineOwnProperty(ctx, output, global, object, key, desc, caller_function, caller_frame) catch |err| switch (err) {
            error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
            error.InvalidLength => return error.RangeError,
            else => return err,
        }
    else blk: {
        object.defineOwnProperty(ctx.runtime, key, desc) catch |err| switch (err) {
            error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
            error.InvalidLength => return error.RangeError,
            else => return err,
        };
        break :blk true;
    };
    if (!defined) return error.TypeError;
    return core.Value.undefinedValue();
}

pub fn qjsObjectPrototypeLookupAccessorCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    args: []const core.Value,
    getter: bool,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const object_value = if (objectFromValue(this_value)) |_| this_value.dup() else try primitiveObjectForAccess(ctx.runtime, global, this_value);
    defer object_value.free(ctx.runtime);
    var object = objectFromValue(object_value) orelse return error.TypeError;
    const key_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const key = try toPropertyKeyAtom(ctx, output, global, key_value, caller_function, caller_frame);
    defer ctx.runtime.atoms.free(key);

    while (true) {
        const desc = try objectRestOwnPropertyDescriptor(ctx, output, global, object, key);
        if (desc) |item| {
            defer item.destroy(ctx.runtime);
            if (item.kind != .accessor) return core.Value.undefinedValue();
            if (getter) return if (item.getter_present) item.getter.dup() else core.Value.undefinedValue();
            return if (item.setter_present) item.setter.dup() else core.Value.undefinedValue();
        }
        object = (try qjsObjectGetPrototypeOfStep(ctx, output, global, object, caller_function, caller_frame)) orelse return core.Value.undefinedValue();
    }
}

pub fn qjsObjectProtoGetterCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    const object_value = if (objectFromValue(this_value)) |_| this_value.dup() else try primitiveObjectForAccess(ctx.runtime, global, this_value);
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return error.TypeError;
    return qjsObjectGetPrototypeOfValue(ctx, output, global, object, caller_function, caller_frame);
}

pub fn qjsObjectProtoSetterCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    this_value: core.Value,
    prototype_value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (this_value.isNull() or this_value.isUndefined()) return error.TypeError;
    if (!prototype_value.isNull() and objectFromValue(prototype_value) == null) return core.Value.undefinedValue();
    if (objectFromValue(this_value) == null) return core.Value.undefinedValue();
    var args = [_]core.Value{ this_value, prototype_value };
    if (try qjsObjectSetPrototypeOfCall(ctx, output, global, &args, caller_function, caller_frame)) |value| {
        value.free(ctx.runtime);
        return core.Value.undefinedValue();
    }
    return core.Value.undefinedValue();
}

pub fn qjsObjectFromEntriesCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    const out = try core.Object.create(ctx.runtime, core.class.ids.object, objectPrototypeFromGlobal(ctx.runtime, global));
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    const out_value = out.value();

    const iterator_value = try iteratorForValue(ctx, output, global, args[0], caller_function, caller_frame);
    defer iterator_value.free(ctx.runtime);

    while (true) {
        const step = try iteratorStepValue(ctx, output, global, iterator_value);
        defer step.value.free(ctx.runtime);
        if (step.done) return out_value;

        const entry = objectFromValue(step.value) orelse {
            try closeIteratorForFromEntriesAbrupt(ctx, output, global, iterator_value);
            return error.TypeError;
        };
        const key_value = getValueProperty(ctx, output, global, entry.value(), core.atom.atomFromUInt32(0), caller_function, caller_frame) catch |err| {
            try closeIteratorForFromEntriesAbrupt(ctx, output, global, iterator_value);
            return err;
        };
        defer key_value.free(ctx.runtime);
        const value = getValueProperty(ctx, output, global, entry.value(), core.atom.atomFromUInt32(1), caller_function, caller_frame) catch |err| {
            try closeIteratorForFromEntriesAbrupt(ctx, output, global, iterator_value);
            return err;
        };
        defer value.free(ctx.runtime);
        const key = toPropertyKeyAtom(ctx, output, global, key_value, caller_function, caller_frame) catch |err| {
            try closeIteratorForFromEntriesAbrupt(ctx, output, global, iterator_value);
            return err;
        };
        defer ctx.runtime.atoms.free(key);
        createDataPropertyOrThrow(ctx, output, global, out_value, out, key, value, caller_function, caller_frame) catch |err| {
            try closeIteratorForFromEntriesAbrupt(ctx, output, global, iterator_value);
            return err;
        };
    }
}

pub fn qjsObjectGroupByCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 2) return error.TypeError;
    if (!isCallableValue(args[1])) return error.TypeError;
    const out = try core.Object.create(ctx.runtime, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    out.null_prototype = true;
    const out_value = out.value();

    const iterator_value = try iteratorForValue(ctx, output, global, args[0], caller_function, caller_frame);
    defer iterator_value.free(ctx.runtime);

    var index: usize = 0;
    while (true) {
        const max_safe_integer: usize = 9007199254740991;
        if (index >= max_safe_integer) {
            try closeIteratorForFromEntriesAbrupt(ctx, output, global, iterator_value);
            return error.TypeError;
        }
        const step = try iteratorStepValue(ctx, output, global, iterator_value);
        defer step.value.free(ctx.runtime);
        if (step.done) return out_value;

        const index_value = value_ops.numberToValue(@floatFromInt(index));
        const raw_key = callValueOrBytecode(ctx, output, global, core.Value.undefinedValue(), args[1], &.{ step.value, index_value }, caller_function, caller_frame) catch |err| {
            try closeIteratorForFromEntriesAbrupt(ctx, output, global, iterator_value);
            return err;
        };
        defer raw_key.free(ctx.runtime);
        const key = toPropertyKeyAtom(ctx, output, global, raw_key, caller_function, caller_frame) catch |err| {
            try closeIteratorForFromEntriesAbrupt(ctx, output, global, iterator_value);
            return err;
        };
        defer ctx.runtime.atoms.free(key);
        try appendObjectGroupByValue(ctx, output, global, out_value, out, key, step.value, caller_function, caller_frame);
        index += 1;
    }
}

pub fn qjsMathSumPrecise(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (args.len < 1) return error.TypeError;
    const iterator_value = try iteratorForValue(ctx, output, global, args[0], caller_function, caller_frame);
    defer iterator_value.free(ctx.runtime);

    var finite_values = std.ArrayList(f64).empty;
    defer finite_values.deinit(ctx.runtime.memory.allocator);
    var saw_nan = false;
    var saw_positive_inf = false;
    var saw_negative_inf = false;
    var saw_positive_zero = false;
    var saw_negative_zero = false;

    while (true) {
        const step = try iteratorStepValue(ctx, output, global, iterator_value);
        defer step.value.free(ctx.runtime);
        if (step.done) break;
        const number = value_ops.numberValue(step.value) orelse {
            try qjsIteratorClose(ctx, output, global, iterator_value, caller_function, caller_frame);
            return error.TypeError;
        };
        if (std.math.isNan(number)) {
            saw_nan = true;
        } else if (std.math.isPositiveInf(number)) {
            saw_positive_inf = true;
        } else if (std.math.isNegativeInf(number)) {
            saw_negative_inf = true;
        } else if (number == 0) {
            if (std.math.isNegativeZero(number)) {
                saw_negative_zero = true;
            } else {
                saw_positive_zero = true;
            }
        } else {
            try finite_values.append(ctx.runtime.memory.allocator, number);
        }
    }

    if (saw_nan or (saw_positive_inf and saw_negative_inf)) return core.Value.float64(std.math.nan(f64));
    if (saw_positive_inf) return core.Value.float64(std.math.inf(f64));
    if (saw_negative_inf) return core.Value.float64(-std.math.inf(f64));
    if (finite_values.items.len == 0) {
        return if (saw_positive_zero) core.Value.int32(0) else core.Value.float64(-0.0);
    }

    const rounded = try exactF64Sum(ctx.runtime.memory.allocator, finite_values.items);
    if (rounded == 0 and !saw_positive_zero and saw_negative_zero) return core.Value.float64(-0.0);
    return value_ops.numberToValue(rounded);
}

fn exactF64Sum(allocator: std.mem.Allocator, values: []const f64) !f64 {
    var total = bignum.BigInt{ .allocator = allocator };
    defer total.deinit();

    for (values) |number| {
        var term = try exactF64ScaledInteger(allocator, number);
        defer term.deinit();
        const next = try total.add(term);
        total.deinit();
        total = next;
    }

    return try scaledIntegerToF64(allocator, total);
}

fn exactF64ScaledInteger(allocator: std.mem.Allocator, number: f64) !bignum.BigInt {
    const bits: u64 = @bitCast(number);
    const sign = (bits >> 63) != 0;
    const exponent_bits: u16 = @intCast((bits >> 52) & 0x7ff);
    const fraction = bits & ((@as(u64, 1) << 52) - 1);
    const mantissa: u64 = if (exponent_bits == 0) fraction else ((@as(u64, 1) << 52) | fraction);
    const exponent: i32 = if (exponent_bits == 0) -1074 else @as(i32, exponent_bits) - 1023 - 52;
    var base = try bignum.BigInt.fromIntAlloc(allocator, if (sign) -@as(i128, @intCast(mantissa)) else @as(i128, @intCast(mantissa)));
    if (mantissa == 0) return base;
    const shift: usize = @intCast(exponent + 1074);
    const shifted = try base.shl(allocator, shift);
    base.deinit();
    return shifted;
}

fn scaledIntegerToF64(allocator: std.mem.Allocator, value: bignum.BigInt) !f64 {
    if (value.isZero()) return 0;
    var magnitude = try value.cloneWithAllocator(allocator);
    defer magnitude.deinit();
    const negative = magnitude.negative;
    magnitude.negative = false;

    const bit_len = magnitude.bitLengthAbs();
    if (bit_len <= 52) {
        const fraction: u64 = @intCast(magnitude.toUsize() orelse return error.TypeError);
        const bits = (@as(u64, @intFromBool(negative)) << 63) | fraction;
        return @bitCast(bits);
    }

    var exponent = @as(i32, @intCast(bit_len - 1)) - 1074;
    if (exponent > 1023) return if (negative) -std.math.inf(f64) else std.math.inf(f64);

    const shift = bit_len - 53;
    var top_int = if (shift == 0)
        try magnitude.cloneWithAllocator(allocator)
    else
        try magnitude.shr(allocator, shift);
    defer top_int.deinit();
    var significand: u64 = @intCast(top_int.toUsize() orelse return error.TypeError);

    if (shift > 0 and shouldRoundScaledIntegerUp(magnitude, shift, significand)) {
        significand += 1;
        if (significand == (@as(u64, 1) << 53)) {
            significand >>= 1;
            exponent += 1;
            if (exponent > 1023) return if (negative) -std.math.inf(f64) else std.math.inf(f64);
        }
    }

    const exponent_bits: u64 = @intCast(exponent + 1023);
    const fraction = significand & ((@as(u64, 1) << 52) - 1);
    const bits = (@as(u64, @intFromBool(negative)) << 63) | (exponent_bits << 52) | fraction;
    return @bitCast(bits);
}

fn shouldRoundScaledIntegerUp(magnitude: bignum.BigInt, shift: usize, significand: u64) bool {
    if (!magnitude.testBit(shift - 1)) return false;
    if ((significand & 1) != 0) return true;
    var bit: usize = 0;
    while (bit + 1 < shift) : (bit += 1) {
        if (magnitude.testBit(bit)) return true;
    }
    return false;
}

const IntegrityLevel = enum {
    sealed,
    frozen,
};

pub fn qjsObjectSetIntegrityCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    level: IntegrityLevel,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const target_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const object = objectFromValue(target_value) orelse return target_value.dup();
    if (level == .frozen and builtins.buffer.typedArrayBackedByResizableBuffer(object)) return error.TypeError;
    if (try qjsObjectPreventExtensionsCall(ctx, output, global, args, caller_function, caller_frame)) |prevented| {
        prevented.free(ctx.runtime);
    } else return error.TypeError;

    const keys = try objectRestOwnKeys(ctx, output, global, object);
    defer core.Object.freeKeys(ctx.runtime, keys);
    for (keys) |key| {
        const desc = if (level == .frozen)
            try objectRestOwnPropertyDescriptor(ctx, output, global, object, key)
        else
            null;
        defer if (desc) |item| item.destroy(ctx.runtime);

        const next_desc = switch (level) {
            .sealed => core.Descriptor.generic(null, false),
            .frozen => blk: {
                if (desc) |item| {
                    if (item.kind == .data) break :blk core.Descriptor{
                        .kind = .data,
                        .value_present = false,
                        .writable = false,
                        .configurable = false,
                    };
                }
                break :blk core.Descriptor.generic(null, false);
            },
        };
        const defined = if (object.proxyTarget() != null)
            try proxyDefineOwnProperty(ctx, output, global, object, key, next_desc, caller_function, caller_frame)
        else blk: {
            object.defineOwnProperty(ctx.runtime, key, next_desc) catch |err| switch (err) {
                error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
                error.InvalidLength => return error.RangeError,
                else => return err,
            };
            break :blk true;
        };
        if (!defined) return error.TypeError;
    }
    return target_value.dup();
}

pub fn qjsObjectTestIntegrityCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    level: IntegrityLevel,
) !?core.Value {
    const target_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const object = objectFromValue(target_value) orelse return core.Value.boolean(true);
    if (try objectIsExtensibleForIntegrity(ctx, output, global, object)) return core.Value.boolean(false);
    const keys = try objectRestOwnKeys(ctx, output, global, object);
    defer core.Object.freeKeys(ctx.runtime, keys);
    for (keys) |key| {
        const desc = try objectRestOwnPropertyDescriptor(ctx, output, global, object, key) orelse continue;
        defer desc.destroy(ctx.runtime);
        if (desc.configurable == true) return core.Value.boolean(false);
        if (level == .frozen and desc.kind == .data and desc.writable == true) return core.Value.boolean(false);
    }
    return core.Value.boolean(true);
}

pub fn objectIsExtensibleForIntegrity(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
) !bool {
    if (object.proxyTarget() == null) return object.isExtensible();
    const target_value = object.proxyTarget() orelse return object.isExtensible();
    const target = property_ops.expectObject(target_value) catch return error.TypeError;
    const handler_value = object.proxyHandler() orelse return error.TypeError;
    const trap_key = try ctx.runtime.internAtom("isExtensible");
    defer ctx.runtime.atoms.free(trap_key);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_key, null, null);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) return target.isExtensible();
    if (!isCallableValue(trap)) return error.TypeError;
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{target_value}, null, null);
    defer result.free(ctx.runtime);
    const extensible = valueTruthy(result);
    if (extensible != target.isExtensible()) return error.TypeError;
    return extensible;
}

pub fn appendObjectGroupByValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    out_value: core.Value,
    out: *core.Object,
    key: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    var group_value = getValueProperty(ctx, output, global, out_value, key, caller_function, caller_frame) catch core.Value.undefinedValue();
    defer group_value.free(ctx.runtime);
    if (group_value.isUndefined()) {
        group_value.free(ctx.runtime);
        const group = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
        group_value = group.value();
        try createDataPropertyOrThrow(ctx, output, global, out_value, out, key, group_value, caller_function, caller_frame);
    }
    const group = objectFromValue(group_value) orelse return error.TypeError;
    try createDataPropertyOrThrow(ctx, output, global, group_value, group, core.atom.atomFromUInt32(group.length), value, caller_function, caller_frame);
}

test "Object.groupBy new group define failure releases group once" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();
    const ctx = try core.Context.create(rt);
    defer ctx.destroy();

    const global = try core.Object.create(rt, core.class.ids.object, null);
    defer global.value().free(rt);
    const out = try core.Object.create(rt, core.class.ids.object, null);
    defer out.value().free(rt);
    out.preventExtensions();

    const key = try rt.internAtom("group");
    defer rt.atoms.free(key);

    try std.testing.expectError(
        error.TypeError,
        appendObjectGroupByValue(ctx, null, global, out.value(), out, key, core.Value.int32(1), null, null),
    );
    try std.testing.expectEqual(@as(usize, 2), rt.gc.liveCount());
}

pub fn qjsObjectPreventExtensionsCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const target_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const object = objectFromValue(target_value) orelse return target_value.dup();
    if (object.proxyTarget() != null) {
        if (!try proxyAwarePreventExtensions(ctx, output, global, object, caller_function, caller_frame)) return error.TypeError;
        return target_value.dup();
    }
    object.preventExtensions();
    return target_value.dup();
}

pub fn qjsObjectIsExtensibleCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    const target_value = if (args.len >= 1) args[0] else core.Value.undefinedValue();
    const object = objectFromValue(target_value) orelse return core.Value.boolean(false);
    if (object.proxyTarget() == null) return core.Value.boolean(object.isExtensible());
    const proxy_target_value = object.proxyTarget() orelse return core.Value.boolean(object.isExtensible());
    const target = objectFromValue(proxy_target_value) orelse return error.TypeError;
    const handler_value = object.proxyHandler() orelse return error.TypeError;
    const trap_key = try ctx.runtime.internAtom("isExtensible");
    defer ctx.runtime.atoms.free(trap_key);
    const trap = try getValueProperty(ctx, output, global, handler_value, trap_key, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) return core.Value.boolean(try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame));
    if (!isCallableValue(trap)) return error.TypeError;
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{proxy_target_value}, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    const extensible = valueTruthy(result);
    if (extensible != try proxyAwareIsExtensible(ctx, output, global, target, caller_function, caller_frame)) return error.TypeError;
    return core.Value.boolean(extensible);
}

pub fn qjsReflectIsExtensibleCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    if (!args[0].isObject()) return error.TypeError;
    return qjsObjectIsExtensibleCall(ctx, output, global, args, caller_function, caller_frame);
}

pub fn qjsReflectPreventExtensionsCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    const object = objectFromValue(args[0]) orelse return error.TypeError;
    if (object.proxyTarget() != null) {
        return core.Value.boolean(try proxyAwarePreventExtensions(ctx, output, global, object, caller_function, caller_frame));
    }
    object.preventExtensions();
    return core.Value.boolean(true);
}

pub fn qjsObjectSetPrototypeOfCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 2) return error.TypeError;
    if (args[0].isNull() or args[0].isUndefined()) return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "not an object"));
    const prototype: ?*core.Object = if (args[1].isNull())
        null
    else
        objectFromValue(args[1]) orelse return error.TypeError;
    const object = objectFromValue(args[0]) orelse return args[0].dup();
    if (object.proxyTarget() == null and objectHasImmutablePrototype(ctx.runtime, object) and object.getPrototype() != prototype) return error.TypeError;
    if (object.proxyTarget() != null) {
        if (!try proxyAwareSetPrototypeOf(ctx, output, global, object, prototype, caller_function, caller_frame)) return error.TypeError;
        return args[0].dup();
    }
    object.setPrototype(ctx.runtime, prototype) catch |err| switch (err) {
        error.PrototypeCycle, error.NotExtensible => return error.TypeError,
        else => return err,
    };
    return args[0].dup();
}

pub fn qjsReflectSetPrototypeOfCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 2) return null;
    const object = objectFromValue(args[0]) orelse return error.TypeError;
    const prototype: ?*core.Object = if (args[1].isNull())
        null
    else
        objectFromValue(args[1]) orelse return error.TypeError;
    if (object.proxyTarget() == null and objectHasImmutablePrototype(ctx.runtime, object) and object.getPrototype() != prototype) return core.Value.boolean(false);
    if (object.proxyTarget() != null) {
        return core.Value.boolean(try proxyAwareSetPrototypeOf(ctx, output, global, object, prototype, caller_function, caller_frame));
    }
    object.setPrototype(ctx.runtime, prototype) catch |err| switch (err) {
        error.PrototypeCycle, error.NotExtensible => return core.Value.boolean(false),
        else => return err,
    };
    return core.Value.boolean(true);
}

pub fn qjsReflectConstructCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 2 or !isConstructorLike(ctx, args[0])) return error.TypeError;
    const new_target = if (args.len >= 3) args[2] else args[0];
    if (!isConstructorLike(ctx, new_target)) return error.TypeError;
    var empty_construct_args: [0]core.Value = .{};
    const construct_args = if (args.len >= 2)
        try argsFromArrayLike(ctx, output, global, args[1], caller_function, caller_frame)
    else
        empty_construct_args[0..];
    defer if (args.len >= 2) freeArgs(ctx.runtime, construct_args);
    if (objectFromValue(args[0])) |target| {
        if (target.proxyTarget() == null) {
            const target_name = try call_mod.nativeFunctionNameForVm(ctx.runtime, target);
            defer ctx.runtime.memory.allocator.free(target_name);
            if (construct_mod.typedArrayElement(target_name) != null) {
                try qjsTypedArrayValidateConstructArgsPreAllocate(ctx, output, global, construct_args);
            }
        }
    }
    return try constructValueOrBytecodeWithNewTarget(ctx, output, global, args[0], construct_args, caller_function, caller_frame, new_target);
}

const ReflectConstructResolution = struct {
    target: core.Value,
    new_target: core.Value,
    args: []const core.Value,
    owned_args: []core.Value = &.{},
};

fn qjsReflectConstructResolveBound(
    rt: *core.Runtime,
    target_value: core.Value,
    new_target_value: core.Value,
    args: []const core.Value,
) !ReflectConstructResolution {
    var target = target_value;
    var effective_new_target = new_target_value;
    var current_args: []const core.Value = args;
    var owned_args: []core.Value = &.{};
    errdefer if (owned_args.len != 0) freeArgs(rt, owned_args);

    while (callableObjectFromValue(target)) |function_object| {
        if (function_object.class_id != core.class.ids.bound_function) break;
        const combined = try boundFunctionArgs(rt, function_object, current_args);
        if (owned_args.len != 0) freeArgs(rt, owned_args);
        owned_args = combined;
        current_args = owned_args;
        const next_target = function_object.boundTarget() orelse return error.TypeError;
        if (builtins.object.sameValue(target, effective_new_target)) {
            effective_new_target = next_target;
        }
        target = next_target;
    }

    return .{
        .target = target,
        .new_target = effective_new_target,
        .args = current_args,
        .owned_args = owned_args,
    };
}

fn qjsReflectConstructGenericCallable(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target_value: core.Value,
    new_target_value: core.Value,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!?core.Value {
    const resolved = try qjsReflectConstructResolveBound(ctx.runtime, target_value, new_target_value, args);
    defer if (resolved.owned_args.len != 0) freeArgs(ctx.runtime, resolved.owned_args);

    if (objectFromValue(resolved.target)) |target_object| {
        const target_name = call_mod.nativeFunctionNameForVm(ctx.runtime, target_object) catch "";
        defer if (target_name.len != 0) ctx.runtime.memory.allocator.free(target_name);
        if (std.mem.eql(u8, target_name, "Array")) {
            const prototype = try reflectConstructPrototypeVm(ctx, output, global, "Array", resolved.new_target, caller_function, caller_frame);
            return try builtins.array.constructConstructorWithPrototype(ctx.runtime, resolved.args, prototype);
        }
    }

    const prototype = try reflectConstructPrototypeVm(ctx, output, global, "Object", resolved.new_target, caller_function, caller_frame);

    if (objectFromValue(resolved.target)) |proxy| {
        if (proxy.proxyTarget() != null) {
            return try constructProxy(ctx, output, global, resolved.target, proxy, resolved.args, caller_function, caller_frame, resolved.new_target);
        }
    }

    if (resolved.target.isFunctionBytecode()) {
        const fb = functionBytecodeFromValue(resolved.target) orelse return error.TypeError;
        if (fb.is_arrow_function or !fb.has_prototype or fb.func_kind == .generator or fb.func_kind == .async_generator) {
            return error.TypeError;
        }
        const instance_object = try core.Object.create(ctx.runtime, core.class.ids.object, prototype);
        const instance = instance_object.value();
        errdefer instance.free(ctx.runtime);
        if (!fb.is_derived_class_constructor) {
            try initializeClassInstanceElements(ctx, output, global, resolved.target, instance, fb, caller_function, caller_frame);
        }
        const initial_this = if (fb.is_derived_class_constructor) core.Value.uninitialized() else instance;
        const constructor_this = if (fb.is_derived_class_constructor) instance else core.Value.undefinedValue();
        const result = try callFunctionBytecodeConstruct(ctx, resolved.target, resolved.target, initial_this, resolved.args, &.{}, output, global, &.{}, &.{}, resolved.new_target, constructor_this);
        defer result.free(ctx.runtime);
        if (result.isObject()) {
            instance.free(ctx.runtime);
            return result.dup();
        }
        return instance;
    }

    if (functionObjectFromValue(resolved.target)) |function_object| {
        const function_value = function_object.functionBytecodeSlot().* orelse return error.TypeError;
        const fb = functionBytecodeFromValue(function_value) orelse return error.TypeError;
        if (fb.is_arrow_function or !fb.has_prototype or fb.func_kind == .generator or fb.func_kind == .async_generator) {
            return error.TypeError;
        }
        const instance_object = try core.Object.create(ctx.runtime, core.class.ids.object, prototype);
        const instance = instance_object.value();
        errdefer instance.free(ctx.runtime);
        if (!fb.is_derived_class_constructor) {
            try initializeClassInstanceElements(ctx, output, global, resolved.target, instance, fb, caller_function, caller_frame);
        }
        const function_global = objectRealmGlobal(function_object) orelse global;
        const initial_this = if (fb.is_derived_class_constructor) core.Value.uninitialized() else instance;
        const constructor_this = if (fb.is_derived_class_constructor) instance else core.Value.undefinedValue();
        const result = try callFunctionBytecodeConstruct(ctx, function_value, resolved.target, initial_this, resolved.args, function_object.functionCapturesSlot().*, output, function_global, function_object.functionEvalLocalNamesSlot().*, function_object.functionEvalLocalRefsSlot().*, resolved.new_target, constructor_this);
        defer result.free(ctx.runtime);
        if (result.isObject()) {
            instance.free(ctx.runtime);
            return result.dup();
        }
        return instance;
    }

    return null;
}

pub fn qjsReflectHasCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 2) return error.TypeError;
    const object = objectFromValue(args[0]) orelse return error.TypeError;
    const key = try toPropertyKeyAtom(ctx, output, global, args[1], caller_function, caller_frame);
    defer ctx.runtime.atoms.free(key);
    const found = if (object.proxyTarget() != null)
        try hasValueProperty(ctx, output, global, args[0], object, key, caller_function, caller_frame)
    else
        try ordinaryHasValueProperty(ctx, output, global, object, key, false, caller_function, caller_frame);
    return core.Value.boolean(found);
}

fn qjsTypedArrayValidateConstructArgsPreAllocate(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !void {
    if (args.len < 1) return;
    const first = args[0];
    if (!first.isObject()) {
        _ = try qjsTypedArrayConstructToIndex(ctx, output, global, first);
        return;
    }
    const source_object = objectFromValue(first) orelse return error.TypeError;
    if (source_object.class_id != core.class.ids.array_buffer and source_object.class_id != core.class.ids.shared_array_buffer) return;
    if (args.len >= 2 and !args[1].isUndefined()) {
        _ = try qjsTypedArrayConstructToIndex(ctx, output, global, args[1]);
    }
    if (args.len >= 3 and !args[2].isUndefined()) {
        _ = try qjsTypedArrayConstructToIndex(ctx, output, global, args[2]);
    }
}

pub fn qjsReflectApplyCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    if (args.len < 3 or !isCallableValue(args[0])) return error.TypeError;
    const apply_args = try argsFromArrayLike(ctx, output, global, args[2], caller_function, caller_frame);
    defer freeArgs(ctx.runtime, apply_args);
    return callValueOrBytecode(ctx, output, global, args[1], args[0], apply_args, caller_function, caller_frame);
}

pub fn reflectConstructPrototypeVm(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target_name: []const u8,
    new_target: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?*core.Object {
    const prototype_value = try getValueProperty(ctx, output, global, new_target, core.atom.ids.prototype, caller_function, caller_frame);
    defer prototype_value.free(ctx.runtime);
    if (prototype_value.isObject()) return objectFromValue(prototype_value);
    if (try reflectConstructRealmPrototype(ctx, output, global, target_name, new_target, caller_function, caller_frame)) |prototype| return prototype;
    const fallback_global = if (objectFromValue(new_target)) |new_target_object|
        functionRealmGlobal(new_target_object) orelse global
    else
        global;
    return constructorPrototypeFromGlobal(ctx.runtime, fallback_global, target_name);
}

fn reflectConstructRealmPrototype(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target_name: []const u8,
    new_target: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?*core.Object {
    const realm_key_name = try std.fmt.allocPrint(ctx.runtime.memory.allocator, "__realm_{s}_proto", .{target_name});
    defer ctx.runtime.memory.allocator.free(realm_key_name);
    const realm_key = try ctx.runtime.internAtom(realm_key_name);
    defer ctx.runtime.atoms.free(realm_key);
    const realm_proto_value = try getValueProperty(ctx, output, global, new_target, realm_key, caller_function, caller_frame);
    defer realm_proto_value.free(ctx.runtime);
    if (!realm_proto_value.isObject()) return null;
    return objectFromValue(realm_proto_value);
}

pub fn objectHasImmutablePrototype(rt: *core.Runtime, object: *core.Object) bool {
    _ = rt;
    return object.hasImmutablePrototype();
}

pub fn closeIteratorForFromEntriesAbrupt(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    iterator_value: core.Value,
) !void {
    const return_key = try ctx.runtime.internAtom("return");
    defer ctx.runtime.atoms.free(return_key);
    const return_method = try getValueProperty(ctx, output, global, iterator_value, return_key, null, null);
    defer return_method.free(ctx.runtime);
    if (return_method.isUndefined() or return_method.isNull()) return;
    if (!isCallableValue(return_method)) return error.TypeError;
    const out = try callValueOrBytecode(ctx, output, global, iterator_value, return_method, &.{}, null, null);
    out.free(ctx.runtime);
}

pub fn qjsDefinePropertiesOnTarget(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    target: *core.Object,
    properties_arg: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    if (properties_arg.isNull() or properties_arg.isUndefined()) return error.TypeError;
    const properties_value = if (objectFromValue(properties_arg)) |_| properties_arg.dup() else try primitiveObjectForAccess(ctx.runtime, global, properties_arg);
    defer properties_value.free(ctx.runtime);
    const properties = objectFromValue(properties_value) orelse return error.TypeError;

    const keys = try objectRestOwnKeys(ctx, output, global, properties);
    defer core.Object.freeKeys(ctx.runtime, keys);

    var pending = std.ArrayList(PendingPropertyDescriptor).empty;
    defer {
        for (pending.items) |item| item.destroy(ctx.runtime);
        pending.deinit(ctx.runtime.memory.allocator);
    }

    for (keys) |key| {
        const prop_desc = try objectRestOwnPropertyDescriptor(ctx, output, global, properties, key) orelse continue;
        defer prop_desc.destroy(ctx.runtime);
        if (prop_desc.enumerable != true) continue;

        const desc_value = try getValueProperty(ctx, output, global, properties_value, key, caller_function, caller_frame);
        defer desc_value.free(ctx.runtime);
        const desc_object = objectFromValue(desc_value) orelse return error.TypeError;
        const desc = try qjsDescriptorFromObject(ctx, output, global, desc_value, desc_object, target, key, caller_function, caller_frame);
        errdefer desc.destroy(ctx.runtime);
        const pending_key = ctx.runtime.atoms.dup(key);
        var pending_key_owned = true;
        errdefer if (pending_key_owned) ctx.runtime.atoms.free(pending_key);
        try pending.append(ctx.runtime.memory.allocator, .{ .atom_id = pending_key, .desc = desc });
        pending_key_owned = false;
    }

    for (pending.items) |item| {
        const defined = if (target.proxyTarget() != null)
            proxyDefineOwnProperty(ctx, output, global, target, item.atom_id, item.desc, caller_function, caller_frame) catch |err| switch (err) {
                error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
                error.InvalidLength => return error.RangeError,
                else => return err,
            }
        else blk: {
            if (try builtins.buffer.typedArrayDefineOwnProperty(ctx.runtime, target, item.atom_id, item.desc)) |ok| {
                break :blk ok;
            } else {
                target.defineOwnProperty(ctx.runtime, item.atom_id, item.desc) catch |err| switch (err) {
                    error.IncompatibleDescriptor, error.NotExtensible, error.ReadOnly => return error.TypeError,
                    error.InvalidLength => return error.RangeError,
                    else => return err,
                };
                break :blk true;
            }
        };
        if (!defined) return error.TypeError;
    }
}

pub fn qjsGetOwnPropertyDescriptorCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return null;
    if (args[0].isNull() or args[0].isUndefined()) return error.TypeError;
    const object_value = if (objectFromValue(args[0])) |_| args[0].dup() else try primitiveObjectForAccess(ctx.runtime, global, args[0]);
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return error.TypeError;
    const key_value = if (args.len >= 2) args[1] else core.Value.undefinedValue();
    const atom_id = try toPropertyKeyAtom(ctx, output, global, key_value, caller_function, caller_frame);
    defer ctx.runtime.atoms.free(atom_id);
    var desc = try proxyAwareOwnPropertyDescriptor(ctx, output, global, object, atom_id, caller_function, caller_frame) orelse return core.Value.undefinedValue();
    try call_mod.materializeMappedArgumentsDescriptorValueForVm(ctx.runtime, object, atom_id, &desc);
    defer desc.destroy(ctx.runtime);
    const desc_value = try descriptorObjectFromDescriptor(ctx.runtime, global, desc);
    return desc_value;
}

pub fn qjsObjectGetPrototypeOfCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return null;
    if (args[0].isNull() or args[0].isUndefined()) return @as(?core.Value, try throwTypeErrorMessage(ctx, global, "not an object"));
    const object_value = if (objectFromValue(args[0])) |_| args[0].dup() else try primitiveObjectForAccess(ctx.runtime, global, args[0]);
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return error.TypeError;
    if (try qjsObjectPrototypeMethodFunctionPrototype(ctx, global, object)) |prototype| return prototype.value().dup();
    return try qjsObjectGetPrototypeOfValue(ctx, output, global, object, caller_function, caller_frame);
}

pub fn qjsObjectPrototypeMethodFunctionPrototype(
    ctx: *core.Context,
    global: *core.Object,
    object: *core.Object,
) !?*core.Object {
    if (object.class_id != core.class.ids.c_function) return null;
    if (!isObjectPrototypeNativeRecord(object, @intFromEnum(builtins.object.PrototypeMethod.is_prototype_of))) return null;
    return functionPrototypeFromGlobal(ctx.runtime, global);
}

fn isObjectPrototypeNativeRecord(object: *core.Object, id: u32) bool {
    const native_ref = core.function.decodeNativeBuiltinId(object.nativeFunctionIdSlot().*) orelse return false;
    return native_ref.domain == .object and native_ref.id == id;
}

pub fn qjsGetOwnPropertyDescriptorsCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return null;
    if (args[0].isNull() or args[0].isUndefined()) return error.TypeError;
    const object_value = if (objectFromValue(args[0])) |_| args[0].dup() else try primitiveObjectForAccess(ctx.runtime, global, args[0]);
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return error.TypeError;
    const keys = try objectRestOwnKeys(ctx, output, global, object);
    defer core.Object.freeKeys(ctx.runtime, keys);

    const out = try core.Object.create(ctx.runtime, core.class.ids.object, objectPrototypeFromGlobal(ctx.runtime, global));
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    for (keys) |key| {
        var desc = (try objectRestOwnPropertyDescriptor(ctx, output, global, object, key)) orelse continue;
        try call_mod.materializeMappedArgumentsDescriptorValueForVm(ctx.runtime, object, key, &desc);
        defer desc.destroy(ctx.runtime);
        const desc_value = try descriptorObjectFromDescriptor(ctx.runtime, global, desc);
        defer desc_value.free(ctx.runtime);
        try createDataPropertyOrThrow(ctx, output, global, out.value(), out, key, desc_value, caller_function, caller_frame);
    }
    return out.value();
}

const OwnPropertyKeyFilter = enum {
    string,
    symbol,
};

pub fn qjsObjectOwnPropertyKeysCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
    filter: OwnPropertyKeyFilter,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    if (args[0].isNull() or args[0].isUndefined()) return error.TypeError;
    const object_value = if (objectFromValue(args[0])) |_| args[0].dup() else try primitiveObjectForAccess(ctx.runtime, global, args[0]);
    defer object_value.free(ctx.runtime);
    const object = objectFromValue(object_value) orelse return error.TypeError;
    const keys = try objectRestOwnKeys(ctx, output, global, object);
    defer core.Object.freeKeys(ctx.runtime, keys);

    const out = try core.Object.createArray(ctx.runtime, arrayPrototypeFromGlobal(ctx.runtime, global));
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    for (keys) |key| {
        const is_symbol = ctx.runtime.atoms.kind(key) == .symbol;
        switch (filter) {
            .string => {
                if (is_symbol) continue;
                const name_value = try ctx.runtime.atoms.toStringValue(ctx.runtime, key);
                defer name_value.free(ctx.runtime);
                try createDataPropertyOrThrow(ctx, output, global, out.value(), out, core.atom.atomFromUInt32(out.length), name_value, caller_function, caller_frame);
            },
            .symbol => {
                if (!is_symbol) continue;
                try createDataPropertyOrThrow(ctx, output, global, out.value(), out, core.atom.atomFromUInt32(out.length), core.Value.symbol(key), caller_function, caller_frame);
            },
        }
    }
    return out.value();
}

