pub fn qjsReflectOwnKeysCall(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !?core.Value {
    if (args.len < 1) return error.TypeError;
    const object = property_ops.expectObject(args[0]) catch return error.TypeError;
    const keys = try objectRestOwnKeys(ctx, output, global, object);
    defer core.Object.freeKeys(ctx.runtime, keys);
    const out = try core.Object.createArray(ctx.runtime, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &out.header);
    for (keys) |key| {
        const key_value = try proxyTrapKeyValue(ctx.runtime, key);
        defer key_value.free(ctx.runtime);
        try out.defineOwnProperty(ctx.runtime, core.atom.atomFromUInt32(out.length), core.Descriptor.data(key_value, true, true, true));
    }
    return out.value();
}

pub fn descriptorObjectFromDescriptor(rt: *core.Runtime, global: *core.Object, desc: core.Descriptor) !core.Value {
    var desc_value = desc.value;
    var desc_getter = desc.getter;
    var desc_setter = desc.setter;
    var root_values = [_]core.runtime.ValueRootValue{
        .{ .value = &desc_value },
        .{ .value = &desc_getter },
        .{ .value = &desc_setter },
    };
    const root_frame = core.runtime.ValueRootFrame{
        .previous = rt.active_value_roots,
        .values = &root_values,
    };
    rt.active_value_roots = &root_frame;
    defer rt.active_value_roots = root_frame.previous;

    const object = try core.Object.create(rt, core.class.ids.object, objectPrototypeFromGlobal(rt, global));
    errdefer core.Object.destroyFromHeader(rt, &object.header);
    if (desc.kind == .data and desc.value_present) {
        try defineValueProperty(rt, object, "value", desc_value);
    } else if (desc.kind == .accessor) {
        if (desc.getter_present) try defineValueProperty(rt, object, "get", desc_getter);
        if (desc.setter_present) try defineValueProperty(rt, object, "set", desc_setter);
    }
    if (desc.writable) |writable| try defineValueProperty(rt, object, "writable", core.Value.boolean(writable));
    if (desc.enumerable) |enumerable| try defineValueProperty(rt, object, "enumerable", core.Value.boolean(enumerable));
    if (desc.configurable) |configurable| try defineValueProperty(rt, object, "configurable", core.Value.boolean(configurable));
    return object.value();
}

test "descriptorObjectFromDescriptor roots direct function bytecode value while creating descriptor object" {
    const rt = try core.Runtime.create(std.testing.allocator);
    defer rt.destroy();

    const global = try core.Object.create(rt, core.class.ids.object, null);
    defer global.value().free(rt);

    const fb_slice = try rt.memory.alloc(bytecode.FunctionBytecode, 1);
    const fb = &fb_slice[0];
    fb.* = bytecode.FunctionBytecode.init(&rt.memory, &rt.atoms, core.atom.ids.empty_string);
    try rt.gc.add(&fb.header);
    fb.header.destroy_fn = bytecode.function.destroyFunctionBytecode;
    fb.header.destroy_ctx = @ptrCast(rt);

    const symbol_atom = try rt.atoms.newValueSymbol("gc-descriptor-object-value-bytecode-symbol");
    fb.cpool = try rt.memory.alloc(core.Value, 1);
    fb.cpool[0] = core.Value.symbol(symbol_atom);
    fb.cpool_count = 1;

    var desc_value = core.Value.functionBytecode(&fb.header);
    var desc_value_alive = true;
    defer if (desc_value_alive) desc_value.free(rt);

    const old_threshold = rt.gcThreshold();
    rt.setGCThreshold(0);
    defer rt.setGCThreshold(old_threshold);

    const descriptor_value = try descriptorObjectFromDescriptor(
        rt,
        global,
        core.Descriptor.data(desc_value, true, true, true),
    );
    var descriptor_alive = true;
    defer if (descriptor_alive) descriptor_value.free(rt);
    const descriptor = objectFromValue(descriptor_value) orelse return error.TypeError;

    try std.testing.expect(rt.atoms.name(symbol_atom) != null);
    const value_key = try rt.internAtom("value");
    defer rt.atoms.free(value_key);
    const stored = descriptor.getProperty(value_key);
    defer stored.free(rt);
    try std.testing.expect(stored.same(desc_value));

    descriptor_value.free(rt);
    descriptor_alive = false;
    desc_value.free(rt);
    desc_value_alive = false;
    _ = rt.runObjectCycleRemoval();
    try std.testing.expect(rt.atoms.name(symbol_atom) == null);
}

pub fn qjsDescriptorFromObject(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    desc_value: core.Value,
    desc_object: *core.Object,
    target: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Descriptor {
    const value_key = try ctx.runtime.internAtom("value");
    defer ctx.runtime.atoms.free(value_key);
    const writable_key = try ctx.runtime.internAtom("writable");
    defer ctx.runtime.atoms.free(writable_key);
    const get_key = try ctx.runtime.internAtom("get");
    defer ctx.runtime.atoms.free(get_key);
    const set_key = try ctx.runtime.internAtom("set");
    defer ctx.runtime.atoms.free(set_key);
    const enumerable_key = try ctx.runtime.internAtom("enumerable");
    defer ctx.runtime.atoms.free(enumerable_key);
    const configurable_key = try ctx.runtime.internAtom("configurable");
    defer ctx.runtime.atoms.free(configurable_key);

    const enumerable = try qjsOptionalBoolDescriptorProperty(ctx, output, global, desc_value, desc_object, enumerable_key, caller_function, caller_frame);
    const configurable = try qjsOptionalBoolDescriptorProperty(ctx, output, global, desc_value, desc_object, configurable_key, caller_function, caller_frame);

    const has_value = try hasValueProperty(ctx, output, global, desc_value, desc_object, value_key, null, null);
    var data_value: ?core.Value = null;
    errdefer if (data_value) |stored| stored.free(ctx.runtime);
    if (has_value) data_value = try getValueProperty(ctx, output, global, desc_value, value_key, caller_function, caller_frame);

    const has_writable = try hasValueProperty(ctx, output, global, desc_value, desc_object, writable_key, null, null);
    const writable = if (has_writable) blk: {
        const writable_value = try getValueProperty(ctx, output, global, desc_value, writable_key, caller_function, caller_frame);
        defer writable_value.free(ctx.runtime);
        break :blk valueTruthy(writable_value);
    } else null;

    const has_get = try hasValueProperty(ctx, output, global, desc_value, desc_object, get_key, null, null);
    var getter_value: ?core.Value = null;
    errdefer if (getter_value) |stored| stored.free(ctx.runtime);
    if (has_get) {
        const value = try getValueProperty(ctx, output, global, desc_value, get_key, caller_function, caller_frame);
        if (!value.isUndefined() and !isCallableValue(value)) {
            value.free(ctx.runtime);
            return error.TypeError;
        }
        getter_value = value;
    }

    const has_set = try hasValueProperty(ctx, output, global, desc_value, desc_object, set_key, null, null);
    var setter_value: ?core.Value = null;
    errdefer if (setter_value) |stored| stored.free(ctx.runtime);
    if (has_set) {
        const value = try getValueProperty(ctx, output, global, desc_value, set_key, caller_function, caller_frame);
        if (!value.isUndefined() and !isCallableValue(value)) {
            value.free(ctx.runtime);
            return error.TypeError;
        }
        setter_value = value;
    }

    if ((has_get or has_set) and (has_value or has_writable)) return error.TypeError;
    if (has_get or has_set) {
        const getter = getter_value orelse core.Value.undefinedValue();
        getter_value = null;
        const setter = setter_value orelse core.Value.undefinedValue();
        setter_value = null;
        return .{
            .kind = .accessor,
            .getter = getter,
            .getter_present = has_get,
            .setter = setter,
            .setter_present = has_set,
            .enumerable = enumerable,
            .configurable = configurable,
        };
    }
    if (has_value or has_writable) {
        var value = data_value orelse core.Value.undefinedValue();
        data_value = null;
        errdefer value.free(ctx.runtime);
        if (has_value and target.is_array and atom_id == core.atom.ids.length and !value.isNumber()) {
            const coerced = try arrayLengthDefineValue(ctx, output, global, value);
            value.free(ctx.runtime);
            value = coerced;
        }
        return .{
            .kind = .data,
            .value = value,
            .value_present = has_value,
            .writable = writable,
            .enumerable = enumerable,
            .configurable = configurable,
        };
    }
    return core.Descriptor.generic(enumerable, configurable);
}

pub fn qjsOptionalBoolDescriptorProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    desc_value: core.Value,
    desc_object: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?bool {
    if (!try hasValueProperty(ctx, output, global, desc_value, desc_object, atom_id, null, null)) return null;
    const value = try getValueProperty(ctx, output, global, desc_value, atom_id, caller_function, caller_frame);
    defer value.free(ctx.runtime);
    return valueTruthy(value);
}

pub fn arrayLengthDefineValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
) !core.Value {
    const first_primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer first_primitive.free(ctx.runtime);
    const first_number = try value_ops.toNumberValue(ctx.runtime, first_primitive);
    defer first_number.free(ctx.runtime);
    const second_primitive = try toPrimitiveForNumber(ctx, output, global, value);
    defer second_primitive.free(ctx.runtime);
    return value_ops.toNumberValue(ctx.runtime, second_primitive);
}

pub fn getAccessorDescriptorValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    if (try findPropertyDescriptor(object, atom_id)) |desc| {
        defer desc.destroy(ctx.runtime);
        if (desc.kind != .accessor) return null;
        if (desc.getter.isUndefined()) return core.Value.undefinedValue();
        return try callValueOrBytecode(ctx, output, global, receiver, desc.getter, &.{}, caller_function, caller_frame);
    }
    return null;
}

fn getPrototypePropertyValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !?core.Value {
    var current = object.getPrototype();
    while (current) |prototype| : (current = prototype.getPrototype()) {
        if (prototype.proxyTarget() != null) {
            return try getProxyProperty(ctx, output, global, receiver, prototype, atom_id, caller_function, caller_frame);
        }
        if (prototype.getOwnProperty(atom_id)) |desc| {
            defer desc.destroy(ctx.runtime);
            switch (desc.kind) {
                .data => return desc.value.dup(),
                .generic => return core.Value.undefinedValue(),
                .accessor => {
                    if (desc.getter.isUndefined()) return core.Value.undefinedValue();
                    return try callValueOrBytecode(ctx, output, global, receiver, desc.getter, &.{}, caller_function, caller_frame);
                },
            }
        }
    }
    return null;
}

pub fn getSuperPropertyValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    prototype: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !core.Value {
    var current: ?*core.Object = prototype;
    while (current) |object| {
        if (try findPropertyDescriptor(object, atom_id)) |desc| {
            defer desc.destroy(ctx.runtime);
            switch (desc.kind) {
                .accessor => {
                    if (desc.getter.isUndefined()) return core.Value.undefinedValue();
                    return callValueOrBytecode(ctx, output, global, receiver, desc.getter, &.{}, caller_function, caller_frame);
                },
                .data => return desc.value.dup(),
                .generic => {},
            }
        }
        current = object.getPrototype();
    }
    return core.Value.undefinedValue();
}

pub fn setSuperPropertyValue(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    prototype: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    if (try findPropertyDescriptor(prototype, atom_id)) |desc| {
        defer desc.destroy(ctx.runtime);
        switch (desc.kind) {
            .accessor => {
                if (desc.setter.isUndefined()) return error.AccessorWithoutSetter;
                const result = try callValueOrBytecode(ctx, output, global, receiver, desc.setter, &.{value}, caller_function, caller_frame);
                result.free(ctx.runtime);
                return;
            },
            .data => {
                if (try rejectModuleNamespaceSuperSet(ctx, receiver, atom_id)) return;
                const result = try setValueProperty(ctx, output, global, receiver, atom_id, value, caller_function, caller_frame);
                result.free(ctx.runtime);
                return;
            },
            .generic => {},
        }
    }
    if (try rejectModuleNamespaceSuperSet(ctx, receiver, atom_id)) return;
    const result = try setValueProperty(ctx, output, global, receiver, atom_id, value, caller_function, caller_frame);
    result.free(ctx.runtime);
}

fn rejectModuleNamespaceSuperSet(ctx: *core.Context, receiver: core.Value, atom_id: core.Atom) !bool {
    const receiver_object = objectFromValue(receiver) orelse return false;
    if (receiver_object.class_id != core.class.ids.module_ns) return false;
    if (receiver_object.moduleNamespaceOwnBindingValue(atom_id)) |binding_value| {
        defer binding_value.free(ctx.runtime);
        if (binding_value.isUninitialized()) return error.ReferenceError;
        return error.TypeError;
    }
    return error.TypeError;
}

pub fn callAccessorSetter(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    if (try findPropertyDescriptor(object, atom_id)) |desc| {
        defer desc.destroy(ctx.runtime);
        if (desc.kind != .accessor) return false;
        if (desc.setter.isUndefined()) return error.AccessorWithoutSetter;
        const result = try callValueOrBytecode(ctx, output, global, receiver, desc.setter, &.{value}, caller_function, caller_frame);
        result.free(ctx.runtime);
        return true;
    }
    return false;
}

pub fn findPropertyDescriptor(object: *core.Object, atom_id: core.Atom) !?core.Descriptor {
    if (object.getOwnProperty(atom_id)) |desc| return desc;
    if (object.prototype) |proto| return findPropertyDescriptor(proto, atom_id);
    return null;
}

pub fn popDuplicateConstructorTarget(rt: *core.Runtime, stack: *stack_mod.Stack, func: core.Value) !void {
    const top = stack.peek() orelse return;
    defer top.free(rt);
    if (!sameObjectIdentity(top, func)) return;
    const duplicate = try stack.pop();
    duplicate.free(rt);
}

pub fn sameObjectIdentity(a: core.Value, b: core.Value) bool {
    if (!a.isObject() or !b.isObject()) return false;
    const a_header = a.refHeader() orelse return false;
    const b_header = b.refHeader() orelse return false;
    return a_header == b_header;
}

pub fn clearPrivateNameRemap(rt: *core.Runtime, object: *core.Object) void {
    if (object.privateRemapFrom().len == 0 and object.privateRemapTo().len == 0) return;
    const from_slot = object.privateRemapFromSlot();
    const to_slot = object.privateRemapToSlot();
    const old_from = from_slot.*;
    const old_to = to_slot.*;
    from_slot.* = &.{};
    to_slot.* = &.{};
    for (old_from) |atom_id| rt.atoms.free(atom_id);
    if (old_from.len != 0) rt.memory.free(core.Atom, old_from);
    for (old_to) |atom_id| rt.atoms.free(atom_id);
    if (old_to.len != 0) rt.memory.free(core.Atom, old_to);
}

const PrivateNameRemapSnapshot = struct {
    from: []core.Atom = &.{},
    to: []core.Atom = &.{},

    fn capture(rt: *core.Runtime, object: *const core.Object) !PrivateNameRemapSnapshot {
        const old_from = object.privateRemapFrom();
        const old_to = object.privateRemapTo();
        std.debug.assert(old_from.len == old_to.len);
        if (old_from.len == 0) return .{};

        const from = try rt.memory.alloc(core.Atom, old_from.len);
        errdefer rt.memory.free(core.Atom, from);
        const to = try rt.memory.alloc(core.Atom, old_to.len);
        errdefer rt.memory.free(core.Atom, to);

        for (old_from, 0..) |atom_id, index| from[index] = rt.atoms.dup(atom_id);
        for (old_to, 0..) |atom_id, index| to[index] = rt.atoms.dup(atom_id);
        return .{ .from = from, .to = to };
    }

    fn restore(self: *PrivateNameRemapSnapshot, rt: *core.Runtime, object: *core.Object) void {
        clearPrivateNameRemap(rt, object);
        if (self.from.len != 0) {
            object.privateRemapFromSlot().* = self.from;
            object.privateRemapToSlot().* = self.to;
            self.from = &.{};
            self.to = &.{};
        }
    }

    fn deinit(self: *PrivateNameRemapSnapshot, rt: *core.Runtime) void {
        for (self.from) |atom_id| rt.atoms.free(atom_id);
        if (self.from.len != 0) rt.memory.free(core.Atom, self.from);
        for (self.to) |atom_id| rt.atoms.free(atom_id);
        if (self.to.len != 0) rt.memory.free(core.Atom, self.to);
        self.from = &.{};
        self.to = &.{};
    }
};

pub fn appendPrivateNameRemap(rt: *core.Runtime, object: *core.Object, from_atom: core.Atom, to_atom: core.Atom) !void {
    const from_slot = try object.privateRemapFromSlotEnsured(rt);
    const to_slot = try object.privateRemapToSlotEnsured(rt);
    for (from_slot.*, 0..) |existing, idx| {
        if (existing != from_atom) continue;
        const retained = rt.atoms.dup(to_atom);
        const old = to_slot.*[idx];
        to_slot.*[idx] = retained;
        rt.atoms.free(old);
        return;
    }

    const new_len = from_slot.*.len + 1;
    const from = try rt.memory.alloc(core.Atom, new_len);
    errdefer rt.memory.free(core.Atom, from);
    const to = try rt.memory.alloc(core.Atom, new_len);
    errdefer rt.memory.free(core.Atom, to);
    @memcpy(from[0..from_slot.*.len], from_slot.*);
    @memcpy(to[0..to_slot.*.len], to_slot.*);
    from[new_len - 1] = rt.atoms.dup(from_atom);
    to[new_len - 1] = rt.atoms.dup(to_atom);
    const old_from = from_slot.*;
    const old_to = to_slot.*;
    from_slot.* = from;
    to_slot.* = to;
    if (old_from.len != 0) rt.memory.free(core.Atom, old_from);
    if (old_to.len != 0) rt.memory.free(core.Atom, old_to);
}

pub fn installLexicalPrivateNameRemap(
    rt: *core.Runtime,
    object: *core.Object,
    caller_frame: ?*frame_mod.Frame,
    bound_names: []const core.Atom,
) !void {
    if (bound_names.len == 0) return;
    var snapshot = try PrivateNameRemapSnapshot.capture(rt, object);
    defer snapshot.deinit(rt);
    errdefer snapshot.restore(rt, object);

    for (bound_names) |atom_id| {
        const mapped = remapPrivateAtomFromFrame(rt, caller_frame, atom_id);
        if (mapped != atom_id) try appendPrivateNameRemap(rt, object, atom_id, mapped);
    }
}

pub fn installFreshPrivateNameRemap(rt: *core.Runtime, object: *core.Object, old_names: []const core.Atom) !void {
    if (old_names.len == 0) return;
    var snapshot = try PrivateNameRemapSnapshot.capture(rt, object);
    defer snapshot.deinit(rt);
    errdefer snapshot.restore(rt, object);

    for (old_names) |old_atom| {
        const name = rt.atoms.name(old_atom) orelse return error.TypeError;
        const fresh_atom = try rt.atoms.newSymbol(name, .private);
        defer rt.atoms.free(fresh_atom);
        try appendPrivateNameRemap(rt, object, old_atom, fresh_atom);
    }
}

pub fn copyPrivateNameRemap(rt: *core.Runtime, dst: *core.Object, src: *const core.Object) !void {
    if (src.privateRemapFrom().len == 0) return;
    const from = try rt.memory.alloc(core.Atom, src.privateRemapFrom().len);
    errdefer rt.memory.free(core.Atom, from);
    const to = try rt.memory.alloc(core.Atom, src.privateRemapTo().len);
    errdefer rt.memory.free(core.Atom, to);
    var initialized: usize = 0;
    errdefer {
        for (from[0..initialized]) |atom_id| rt.atoms.free(atom_id);
        for (to[0..initialized]) |atom_id| rt.atoms.free(atom_id);
    }
    for (src.privateRemapFrom(), 0..) |atom_id, idx| {
        from[idx] = rt.atoms.dup(atom_id);
        to[idx] = rt.atoms.dup(src.privateRemapTo()[idx]);
        initialized += 1;
    }
    const from_slot = try dst.privateRemapFromSlotEnsured(rt);
    const to_slot = try dst.privateRemapToSlotEnsured(rt);
    const old_from = from_slot.*;
    const old_to = to_slot.*;
    from_slot.* = from;
    to_slot.* = to;
    for (old_from) |atom_id| rt.atoms.free(atom_id);
    if (old_from.len != 0) rt.memory.free(core.Atom, old_from);
    for (old_to) |atom_id| rt.atoms.free(atom_id);
    if (old_to.len != 0) rt.memory.free(core.Atom, old_to);
}

test "copyPrivateNameRemap OOM preserves destination remap" {
    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
    const rt = try core.Runtime.create(failing.allocator());
    const dst = try core.Object.create(rt, core.class.ids.object, null);
    const src = try core.Object.create(rt, core.class.ids.object, null);
    const dst_from = try rt.atoms.newSymbol("dstFrom", .private);
    const dst_to = try rt.atoms.newSymbol("dstTo", .private);
    const src_from = try rt.atoms.newSymbol("srcFrom", .private);
    const src_to = try rt.atoms.newSymbol("srcTo", .private);
    defer {
        failing.fail_index = std.math.maxInt(usize);
        rt.atoms.free(src_to);
        rt.atoms.free(src_from);
        rt.atoms.free(dst_to);
        rt.atoms.free(dst_from);
        src.value().free(rt);
        dst.value().free(rt);
        rt.destroy();
    }

    try appendPrivateNameRemap(rt, dst, dst_from, dst_to);
    try appendPrivateNameRemap(rt, src, src_from, src_to);

    failing.fail_index = failing.alloc_index;
    try std.testing.expectError(error.OutOfMemory, copyPrivateNameRemap(rt, dst, src));
    failing.fail_index = std.math.maxInt(usize);

    try std.testing.expectEqual(@as(usize, 1), dst.privateRemapFrom().len);
    try std.testing.expectEqual(dst_from, dst.privateRemapFrom()[0]);
    try std.testing.expectEqual(dst_to, dst.privateRemapTo()[0]);
}

test "installFreshPrivateNameRemap OOM preserves existing remap" {
    var saw_oom = false;
    var saw_success = false;

    var fail_offset: usize = 0;
    while (fail_offset < 180) : (fail_offset += 1) {
        var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
        const rt = try core.Runtime.create(failing.allocator());
        const object = try core.Object.create(rt, core.class.ids.object, null);
        const existing_from = try rt.atoms.newSymbol("existingFrom", .private);
        const existing_to = try rt.atoms.newSymbol("existingTo", .private);
        const old_a = try rt.atoms.newSymbol("oldA", .private);
        const old_b = try rt.atoms.newSymbol("oldB", .private);
        defer {
            failing.fail_index = std.math.maxInt(usize);
            rt.atoms.free(old_b);
            rt.atoms.free(old_a);
            rt.atoms.free(existing_to);
            rt.atoms.free(existing_from);
            object.value().free(rt);
            rt.destroy();
        }

        try appendPrivateNameRemap(rt, object, existing_from, existing_to);

        failing.fail_index = failing.alloc_index + fail_offset;
        const result = installFreshPrivateNameRemap(rt, object, &.{ old_a, old_b });
        failing.fail_index = std.math.maxInt(usize);

        if (result) {
            saw_success = true;
            try std.testing.expectEqual(@as(usize, 3), object.privateRemapFrom().len);
        } else |err| switch (err) {
            error.OutOfMemory => {
                saw_oom = true;
                try std.testing.expectEqual(@as(usize, 1), object.privateRemapFrom().len);
                try std.testing.expectEqual(existing_from, object.privateRemapFrom()[0]);
                try std.testing.expectEqual(existing_to, object.privateRemapTo()[0]);
            },
            else => |unexpected| return unexpected,
        }

        if (saw_oom and saw_success) return;
    }

    try std.testing.expect(saw_oom);
    try std.testing.expect(saw_success);
}

pub fn remapPrivateAtomFromObject(rt: *core.Runtime, object: *const core.Object, atom_id: core.Atom) core.Atom {
    if (rt.atoms.kind(atom_id) != .private) return atom_id;
    for (object.privateRemapFrom(), 0..) |old_atom, idx| {
        if (old_atom == atom_id) return object.privateRemapTo()[idx];
    }
    return atom_id;
}

pub fn remapPrivateAtomFromFrame(rt: *core.Runtime, caller_frame: ?*frame_mod.Frame, atom_id: core.Atom) core.Atom {
    if (rt.atoms.kind(atom_id) != .private) return atom_id;
    const frame = caller_frame orelse return atom_id;
    const function_object = objectFromValue(frame.current_function) orelse return atom_id;
    const function_atom = remapPrivateAtomFromObject(rt, function_object, atom_id);
    if (function_atom != atom_id) return function_atom;
    const home_object = function_object.functionHomeObjectSlot().* orelse return atom_id;
    return remapPrivateAtomFromObject(rt, home_object, atom_id);
}

pub fn remapPrivateAtomForOperation(
    rt: *core.Runtime,
    caller_frame: ?*frame_mod.Frame,
    object: ?*const core.Object,
    atom_id: core.Atom,
) core.Atom {
    const frame_atom = remapPrivateAtomFromFrame(rt, caller_frame, atom_id);
    if (frame_atom != atom_id) return frame_atom;
    if (object) |target| return remapPrivateAtomFromObject(rt, target, atom_id);
    return atom_id;
}

pub fn stringObjectHasIndexProperty(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom) bool {
    if (object.class_id != core.class.ids.string) return false;
    const string_data = object.objectData() orelse return false;
    const index = core.array.arrayIndexFromAtom(&rt.atoms, atom_id) orelse return false;
    const header = string_data.refHeader() orelse return false;
    const string_value: *core.string.String = @fieldParentPtr("header", header);
    return index < string_value.len();
}

pub fn getPrototypeMethodWithFallback(rt: *core.Runtime, global: *core.Object, constructor_name: []const u8, atom_id: core.Atom, fallback_constructor_name: []const u8) !core.Value {
    const value = try getPrototypeMethod(rt, global, constructor_name, atom_id);
    if (!value.isUndefined()) return value;
    value.free(rt);
    return getPrototypeMethod(rt, global, fallback_constructor_name, atom_id);
}

pub fn inOp(
    ctx: *core.Context,
    stack: *stack_mod.Stack,
    output: ?*std.Io.Writer,
    global: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const rhs = try stack.pop();
    defer rhs.free(ctx.runtime);
    const lhs = try stack.pop();
    defer lhs.free(ctx.runtime);
    const object = property_ops.expectObject(rhs) catch return error.TypeError;
    const key = try toPropertyKeyAtom(ctx, output, global, lhs, caller_function, caller_frame);
    defer ctx.runtime.atoms.free(key);
    const has_builtin_object_proto = value_ops.atomNameEql(ctx.runtime, key, "toString") and (object.class_id == core.class.ids.object or object.is_array);
    const found = if (object.proxyTarget() != null)
        try hasValueProperty(ctx, output, global, rhs, object, key, caller_function, caller_frame)
    else
        try ordinaryHasValueProperty(ctx, output, global, object, key, has_builtin_object_proto, caller_function, caller_frame);
    try stack.pushOwned(core.Value.boolean(found));
}

pub fn instanceofOp(
    ctx: *core.Context,
    stack: *stack_mod.Stack,
    output: ?*std.Io.Writer,
    global: *core.Object,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !void {
    const rhs = try stack.pop();
    defer rhs.free(ctx.runtime);
    const lhs = try stack.pop();
    defer lhs.free(ctx.runtime);
    const ctor = property_ops.expectObject(rhs) catch return error.TypeError;
    const has_instance_atom = core.atom.predefinedId("Symbol.hasInstance", .symbol) orelse return error.TypeError;
    const has_instance = try getValueProperty(ctx, output, global, rhs, has_instance_atom, caller_function, caller_frame);
    defer has_instance.free(ctx.runtime);
    if (!has_instance.isUndefined() and !has_instance.isNull()) {
        const result = try callValueOrBytecode(ctx, output, global, rhs, has_instance, &.{lhs}, caller_function, caller_frame);
        defer result.free(ctx.runtime);
        try stack.pushOwned(core.Value.boolean(valueTruthy(result)));
        return;
    }
    if (!isCallableValue(rhs)) return error.TypeError;
    if (!lhs.isObject()) {
        try stack.pushOwned(core.Value.boolean(false));
        return;
    }
    const object = try property_ops.expectObject(lhs);
    if (try constructorNameEqlLocal(ctx.runtime, ctor, "Array")) {
        try stack.pushOwned(core.Value.boolean(object.is_array));
        return;
    }
    const proto_value = try getValueProperty(ctx, output, global, rhs, core.atom.ids.prototype, caller_function, caller_frame);
    defer proto_value.free(ctx.runtime);
    if (!proto_value.isObject()) {
        return error.TypeError;
    }
    const proto = try property_ops.expectObject(proto_value);
    var current = try qjsObjectGetPrototypeOfStep(ctx, output, global, object, caller_function, caller_frame);
    while (current) |candidate| {
        if (candidate == proto) {
            try stack.pushOwned(core.Value.boolean(true));
            return;
        }
        current = try qjsObjectGetPrototypeOfStep(ctx, output, global, candidate, caller_function, caller_frame);
    }
    try stack.pushOwned(core.Value.boolean(false));
}

pub fn constructorNameEqlLocal(rt: *core.Runtime, object: *core.Object, expected: []const u8) !bool {
    const name_value = nativeFunctionNameValueLocal(rt, object) catch return false;
    defer name_value.free(rt);
    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(rt.memory.allocator);
    try value_ops.appendRawString(rt, &bytes, name_value);
    return std.mem.eql(u8, bytes.items, expected);
}

pub fn nativeFunctionNameValueLocal(rt: *core.Runtime, object: *core.Object) !core.Value {
    const dispatch_atom = object.nativeDispatchName();
    if (dispatch_atom != core.atom.null_atom) {
        const dispatch_name = try rt.atoms.toStringValue(rt, dispatch_atom);
        if (dispatch_name.isString()) return dispatch_name;
        dispatch_name.free(rt);
    }
    const name_value = object.getProperty(core.atom.ids.name);
    if (!name_value.isString()) {
        name_value.free(rt);
        return error.TypeError;
    }
    return name_value;
}

pub fn getPrototypeMethod(rt: *core.Runtime, global: *core.Object, constructor_name: []const u8, atom_id: core.Atom) !core.Value {
    const ctor_key = try rt.internAtom(constructor_name);
    defer rt.atoms.free(ctor_key);
    const ctor_value = global.getProperty(ctor_key);
    defer ctor_value.free(rt);
    const ctor = try property_ops.expectObject(ctor_value);
    const proto_value = ctor.getProperty(core.atom.ids.prototype);
    defer proto_value.free(rt);
    const proto = try property_ops.expectObject(proto_value);
    return proto.getProperty(atom_id);
}

pub fn isBlockedByUnscopables(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object_value: core.Value,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    const unscopables_atom = core.atom.predefinedId("Symbol.unscopables", .symbol) orelse return false;
    const unscopables = try getValueProperty(ctx, output, global, object_value, unscopables_atom, caller_function, caller_frame);
    defer unscopables.free(ctx.runtime);
    if (!unscopables.isObject()) return false;
    const blocked = try getValueProperty(ctx, output, global, unscopables, atom_id, caller_function, caller_frame);
    defer blocked.free(ctx.runtime);
    return valueTruthy(blocked);
}

pub fn hasPropertyForWith(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object_value: core.Value,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    const object = try property_ops.expectObject(object_value);
    const target_value = object.proxyTarget() orelse return ordinaryHasValueProperty(ctx, output, global, object, atom_id, false, caller_function, caller_frame);
    const target = try property_ops.expectObject(target_value);
    const handler_value = object.proxyHandler() orelse return error.TypeError;
    const has_atom = try ctx.runtime.internAtom("has");
    defer ctx.runtime.atoms.free(has_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, has_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        return hasPropertyForWith(ctx, output, global, target_value, atom_id, caller_function, caller_frame);
    }
    const key_value = try proxyTrapKeyValue(ctx.runtime, atom_id);
    defer key_value.free(ctx.runtime);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, key_value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    return try validateProxyHasResult(ctx.runtime, target, atom_id, valueTruthy(result));
}

pub fn hasValueProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) HostError!bool {
    _ = receiver;
    const target_value = object.proxyTarget() orelse return ordinaryHasValueProperty(ctx, output, global, object, atom_id, false, caller_function, caller_frame);
    const target = try property_ops.expectObject(target_value);
    const handler_value = object.proxyHandler() orelse return error.TypeError;
    const has_atom = try ctx.runtime.internAtom("has");
    defer ctx.runtime.atoms.free(has_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, has_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        return hasValueProperty(ctx, output, global, target_value, target, atom_id, caller_function, caller_frame);
    }
    const key_value = try proxyTrapKeyValue(ctx.runtime, atom_id);
    defer key_value.free(ctx.runtime);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, key_value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    return try validateProxyHasResult(ctx.runtime, target, atom_id, valueTruthy(result));
}

fn ordinaryHasValueProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    atom_id: core.Atom,
    has_builtin_object_proto: bool,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    if (typedArrayCanonicalHas(ctx.runtime, object, atom_id)) |has| return has;
    if (indexedExoticHasProperty(ctx.runtime, object, atom_id)) return true;
    if (object.getOwnProperty(atom_id)) |desc| {
        desc.destroy(ctx.runtime);
        return true;
    }

    var current = object.getPrototype();
    while (current) |proto| : (current = proto.getPrototype()) {
        if (proto.proxyTarget() != null) {
            return try hasValueProperty(ctx, output, global, proto.value(), proto, atom_id, caller_function, caller_frame);
        }
        if (typedArrayCanonicalHas(ctx.runtime, proto, atom_id)) |has| return has;
        if (indexedExoticHasProperty(ctx.runtime, proto, atom_id)) return true;
        if (proto.getOwnProperty(atom_id)) |desc| {
            desc.destroy(ctx.runtime);
            return true;
        }
    }
    return has_builtin_object_proto;
}

pub fn validateProxyHasResult(rt: *core.Runtime, target: *core.Object, atom_id: core.Atom, result: bool) !bool {
    if (result) return true;
    if (target.getOwnProperty(atom_id)) |desc| {
        defer desc.destroy(rt);
        if (desc.configurable == false) return error.TypeError;
        if (!target.isExtensible()) return error.TypeError;
    }
    return false;
}

pub fn indexedExoticHasProperty(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom) bool {
    if (stringObjectHasIndexProperty(rt, object, atom_id)) return true;
    if (!builtins.buffer.isTypedArrayObject(object)) return false;
    return typedArrayCanonicalHas(rt, object, atom_id) orelse false;
}

const TypedArrayCanonicalIndex = union(enum) {
    none,
    invalid,
    index: u32,
};

pub fn typedArrayCanonicalGet(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom) !?core.Value {
    switch (try typedArrayCanonicalNumericIndex(rt, atom_id)) {
        .none => return null,
        .invalid => return core.Value.undefinedValue(),
        .index => |index| return try builtins.buffer.typedArrayGetIndex(rt, object, index),
    }
}

pub fn typedArrayCanonicalOwnDescriptor(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom) !?core.Descriptor {
    if (!builtins.buffer.isTypedArrayObject(object)) return null;
    switch (try typedArrayCanonicalNumericIndex(rt, atom_id)) {
        .none => return null,
        .invalid => return null,
        .index => |index| {
            const length = try builtins.buffer.typedArrayLength(rt, object);
            if (index >= length) return null;
            const value = try builtins.buffer.typedArrayGetIndex(rt, object, index);
            return core.Descriptor.data(value, true, true, true);
        },
    }
}

fn coerceTypedArrayElementInput(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    value: core.Value,
) !core.Value {
    return if (value.isObject())
        try toPrimitiveForNumber(ctx, output, global, value)
    else
        value.dup();
}

fn coerceTypedArrayElementForSet(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    value: core.Value,
) !core.Value {
    const coerced = try coerceTypedArrayElementInput(ctx, output, global, value);
    errdefer coerced.free(ctx.runtime);
    try builtins.buffer.typedArrayCoerceElementValue(ctx.runtime, object, coerced);
    return coerced;
}

fn typedArrayDefineOwnPropertyVm(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    atom_id: core.Atom,
    desc: core.Descriptor,
) !?bool {
    if (!builtins.buffer.isTypedArrayObject(object)) return null;
    switch (try typedArrayCanonicalNumericIndex(ctx.runtime, atom_id)) {
        .none => return null,
        .invalid => return false,
        .index => |index| {
            if (desc.kind == .accessor) return false;
            if (desc.configurable) |configurable| {
                if (!configurable) return false;
            }
            if (desc.enumerable) |enumerable| {
                if (!enumerable) return false;
            }
            if (desc.writable) |writable| {
                if (!writable) return false;
            }
            if (!try builtins.buffer.typedArrayIndexValid(ctx.runtime, object, index)) return false;
            if (desc.value_present) {
                if (try builtins.buffer.typedArrayImmutableBuffer(ctx.runtime, object)) return false;
                const coerced = try coerceTypedArrayElementInput(ctx, output, global, desc.value);
                defer coerced.free(ctx.runtime);
                if (!try builtins.buffer.typedArraySetElement(ctx.runtime, object, index, coerced)) return false;
            }
            return true;
        },
    }
}

pub fn typedArrayCanonicalSet(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    object: *core.Object,
    atom_id: core.Atom,
    value: core.Value,
) !bool {
    switch (try typedArrayCanonicalNumericIndex(ctx.runtime, atom_id)) {
        .none => return false,
        .invalid => {
            const coerced = try coerceTypedArrayElementInput(ctx, output, global, value);
            defer coerced.free(ctx.runtime);
            try builtins.buffer.typedArrayCoerceElementValue(ctx.runtime, object, coerced);
            return true;
        },
        .index => |index| {
            const coerced = try coerceTypedArrayElementForSet(ctx, output, global, object, value);
            defer coerced.free(ctx.runtime);
            if (!try builtins.buffer.typedArrayIndexValid(ctx.runtime, object, index)) return true;
            if (try builtins.buffer.typedArrayImmutableBuffer(ctx.runtime, object)) return false;
            _ = try builtins.buffer.typedArraySetElement(ctx.runtime, object, index, coerced);
            return true;
        },
    }
}

pub fn typedArrayCanonicalHas(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom) ?bool {
    if (!builtins.buffer.isTypedArrayObject(object)) return null;
    switch (typedArrayCanonicalNumericIndex(rt, atom_id) catch return false) {
        .none => return null,
        .invalid => return false,
        .index => |index| {
            const length = builtins.buffer.typedArrayLength(rt, object) catch return false;
            return index < length;
        },
    }
}

pub fn typedArrayCanonicalDelete(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom) !?bool {
    if (!builtins.buffer.isTypedArrayObject(object)) return null;
    switch (try typedArrayCanonicalNumericIndex(rt, atom_id)) {
        .none => return null,
        .invalid => return true,
        .index => |index| {
            const length = builtins.buffer.typedArrayLength(rt, object) catch return true;
            return index >= length;
        },
    }
}

pub fn typedArrayCanonicalNumericIndex(rt: *core.Runtime, atom_id: core.Atom) !TypedArrayCanonicalIndex {
    if (core.array.arrayIndexFromAtom(&rt.atoms, atom_id)) |index| return .{ .index = index };
    if (rt.atoms.kind(atom_id) != .string) return .none;
    const name = rt.atoms.name(atom_id) orelse return .none;
    if (name.len == 0) return .none;
    if (std.mem.eql(u8, name, "-0")) return .invalid;

    const number: f64 = if (std.mem.eql(u8, name, "NaN"))
        std.math.nan(f64)
    else if (std.mem.eql(u8, name, "Infinity"))
        std.math.inf(f64)
    else if (std.mem.eql(u8, name, "-Infinity"))
        -std.math.inf(f64)
    else
        std.fmt.parseFloat(f64, name) catch return .none;

    var buffer: [64]u8 = undefined;
    const printed = if (std.math.isNan(number))
        "NaN"
    else if (std.math.isPositiveInf(number))
        "Infinity"
    else if (std.math.isNegativeInf(number))
        "-Infinity"
    else
        try value_ops.formatFiniteNumber(&buffer, number);
    if (!std.mem.eql(u8, name, printed)) return .none;
    if (!std.math.isFinite(number) or @trunc(number) != number or number < 0 or number > @as(f64, @floatFromInt(std.math.maxInt(u32)))) return .invalid;
    return .{ .index = @intFromFloat(number) };
}

pub fn deleteValuePropertyOrThrow(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
) !void {
    if (!try deleteValueProperty(ctx, output, global, receiver, object, atom_id, null, null)) return error.TypeError;
}

pub fn deleteValueProperty(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    receiver: core.Value,
    object: *core.Object,
    atom_id: core.Atom,
    caller_function: ?*const bytecode.Bytecode,
    caller_frame: ?*frame_mod.Frame,
) !bool {
    _ = receiver;
    const target_value = object.proxyTarget() orelse {
        return object.deleteProperty(ctx.runtime, atom_id);
    };
    const target = try property_ops.expectObject(target_value);
    const handler_value = object.proxyHandler() orelse return error.TypeError;
    const delete_atom = try ctx.runtime.internAtom("deleteProperty");
    defer ctx.runtime.atoms.free(delete_atom);
    const trap = try getValueProperty(ctx, output, global, handler_value, delete_atom, caller_function, caller_frame);
    defer trap.free(ctx.runtime);
    if (trap.isUndefined() or trap.isNull()) {
        return deleteValueProperty(ctx, output, global, target_value, target, atom_id, caller_function, caller_frame);
    }
    const key_value = try proxyTrapKeyValue(ctx.runtime, atom_id);
    defer key_value.free(ctx.runtime);
    const result = try callValueOrBytecode(ctx, output, global, handler_value, trap, &.{ target_value, key_value }, caller_function, caller_frame);
    defer result.free(ctx.runtime);
    if (!valueTruthy(result)) return false;
    if (target.getOwnProperty(atom_id)) |desc| {
        defer desc.destroy(ctx.runtime);
        if (desc.configurable == false) return error.TypeError;
        if (!target.isExtensible()) return error.TypeError;
    }
    return true;
}

pub fn proxyTrapKeyValue(rt: *core.Runtime, atom_id: core.Atom) !core.Value {
    if (rt.atoms.kind(atom_id) == .symbol) return core.Value.symbol(atom_id);
    return rt.atoms.toStringValue(rt, atom_id);
}

pub fn lookupFrameVarRef(rt: *core.Runtime, function: *const bytecode.Bytecode, frame: *frame_mod.Frame, atom_id: core.Atom) ?core.Value {
    return lookupNamedVarRef(rt, function.var_ref_names, frame.var_refs, atom_id);
}

pub fn lookupFrameLocalValue(rt: *core.Runtime, function: *const bytecode.Bytecode, frame: *frame_mod.Frame, atom_id: core.Atom) ?core.Value {
    const count = @min(function.var_names.len, frame.locals.len);
    for (function.var_names[0..count], 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id)) continue;
        return slotValueDup(frame.locals[idx]);
    }
    return null;
}

pub fn lookupEvalBindingValue(
    rt: *core.Runtime,
    eval_local_names: []const core.Atom,
    eval_local_slots: []core.Value,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    frame: *frame_mod.Frame,
    atom_id: core.Atom,
) ?core.Value {
    if (lookupNamedSlotValue(rt, eval_local_names, eval_local_slots, atom_id)) |value| return value;
    if (lookupNamedVarRef(rt, eval_var_ref_names, eval_var_refs, atom_id)) |value| return value;
    if (lookupNamedSlotValue(rt, frame.eval_local_names, frame.eval_local_slots, atom_id)) |value| return value;
    if (lookupNamedVarRef(rt, frame.eval_var_ref_names, frame.eval_var_refs, atom_id)) |value| return value;
    return null;
}

pub fn lookupFrameFirstEvalBindingValue(
    rt: *core.Runtime,
    eval_local_names: []const core.Atom,
    eval_local_slots: []core.Value,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    frame: *frame_mod.Frame,
    atom_id: core.Atom,
) ?core.Value {
    if (lookupNamedSlotValue(rt, frame.eval_local_names, frame.eval_local_slots, atom_id)) |value| return value;
    if (lookupNamedVarRef(rt, frame.eval_var_ref_names, frame.eval_var_refs, atom_id)) |value| return value;
    if (lookupNamedSlotValue(rt, eval_local_names, eval_local_slots, atom_id)) |value| return value;
    if (lookupNamedVarRef(rt, eval_var_ref_names, eval_var_refs, atom_id)) |value| return value;
    return null;
}

pub fn lookupParentFunctionEvalBindingValue(
    rt: *core.Runtime,
    frame: *frame_mod.Frame,
    atom_id: core.Atom,
) ?core.Value {
    const function_object = objectFromValue(frame.current_function) orelse return null;
    const parent_value = function_object.functionEvalParentFunction() orelse return null;
    const parent_object = objectFromValue(parent_value) orelse return null;
    return lookupNamedVarRef(rt, parent_object.functionEvalLocalNamesSlot().*, parent_object.functionEvalLocalRefsSlot().*, atom_id);
}

pub fn capturedArgumentsObject(
    rt: *core.Runtime,
    eval_local_names: []const core.Atom,
    eval_local_slots: []core.Value,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    frame: *frame_mod.Frame,
) ?core.Value {
    if (lookupNamedSlotValue(rt, eval_local_names, eval_local_slots, core.atom.ids.arguments)) |value| return value;
    if (lookupNamedVarRef(rt, eval_var_ref_names, eval_var_refs, core.atom.ids.arguments)) |value| return value;
    if (lookupNamedSlotValue(rt, frame.eval_local_names, frame.eval_local_slots, core.atom.ids.arguments)) |value| return value;
    if (lookupNamedVarRef(rt, frame.eval_var_ref_names, frame.eval_var_refs, core.atom.ids.arguments)) |value| return value;
    return null;
}

pub fn atomIdOrNameEql(rt: *core.Runtime, left: core.Atom, right: core.Atom) bool {
    if (left == right) return true;
    const left_name = rt.atoms.name(left) orelse return false;
    const right_name = rt.atoms.name(right) orelse return false;
    return std.mem.eql(u8, left_name, right_name);
}

pub fn lookupNamedVarRef(rt: *core.Runtime, names: []const core.Atom, refs: []const core.Value, atom_id: core.Atom) ?core.Value {
    for (names, 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id) or idx >= refs.len) continue;
        if (varRefSlotIsDeleted(refs[idx])) return core.Value.uninitialized();
        return slotValueDup(refs[idx]);
    }
    return null;
}

pub fn deleteEvalBinding(
    rt: *core.Runtime,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    eval_local_names: []const core.Atom,
    eval_local_slots: []core.Value,
    eval_var_ref_names: []const core.Atom,
    eval_var_refs: []const core.Value,
    atom_id: core.Atom,
) ?bool {
    if (value_ops.atomNameEql(rt, function.name, "<eval>")) {
        if (deleteFrameLocalBinding(rt, function, frame, atom_id)) |deleted| return deleted;
    }
    if (deleteNamedSlotBinding(rt, eval_local_names, eval_local_slots, atom_id)) |deleted| return deleted;
    if (deleteNamedVarRefBinding(rt, eval_var_ref_names, eval_var_refs, atom_id)) |deleted| return deleted;
    if (deleteNamedSlotBinding(rt, frame.eval_local_names, frame.eval_local_slots, atom_id)) |deleted| return deleted;
    if (deleteNamedVarRefBinding(rt, frame.eval_var_ref_names, frame.eval_var_refs, atom_id)) |deleted| return deleted;
    return null;
}

pub fn deleteFrameLocalBinding(
    rt: *core.Runtime,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    atom_id: core.Atom,
) ?bool {
    const count = @min(@min(function.var_names.len, function.var_is_lexical.len), frame.locals.len);
    for (function.var_names[0..count], 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id)) continue;
        if (function.var_is_lexical[idx]) return false;
        return deleteVarRefSlot(rt, frame.locals[idx]);
    }
    return null;
}

pub fn deleteNamedSlotBinding(rt: *core.Runtime, names: []const core.Atom, slots: []const core.Value, atom_id: core.Atom) ?bool {
    for (names, 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id) or idx >= slots.len) continue;
        return deleteVarRefSlot(rt, slots[idx]);
    }
    return null;
}

pub fn deleteNamedVarRefBinding(rt: *core.Runtime, names: []const core.Atom, refs: []const core.Value, atom_id: core.Atom) ?bool {
    for (names, 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id) or idx >= refs.len) continue;
        return deleteVarRefSlot(rt, refs[idx]);
    }
    return null;
}

pub fn deleteVarRefSlot(rt: *core.Runtime, slot: core.Value) ?bool {
    const cell = varRefCellFromValue(slot) orelse return false;
    if (cell.varRefIsDeletedSlot().*) return null;
    if (!cell.varRefIsDeletableSlot().*) return false;
    const old_value = cell.varRefValueSlot().*;
    cell.varRefValueSlot().* = core.Value.undefinedValue();
    cell.varRefIsDeletedSlot().* = true;
    if (old_value) |stored| stored.free(rt);
    return true;
}

pub fn lookupNamedSlotValue(rt: *core.Runtime, names: []const core.Atom, slots: []const core.Value, atom_id: core.Atom) ?core.Value {
    for (names, 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id) or idx >= slots.len) continue;
        if (varRefSlotIsDeleted(slots[idx])) return core.Value.uninitialized();
        return slotValueDup(slots[idx]);
    }
    return null;
}

pub fn lookupNamedRawSlotValue(rt: *core.Runtime, names: []const core.Atom, slots: []const core.Value, atom_id: core.Atom) ?core.Value {
    for (names, 0..) |name, idx| {
        if (!atomIdOrNameEql(rt, name, atom_id) or idx >= slots.len) continue;
        if (varRefSlotIsDeleted(slots[idx])) continue;
        return slots[idx].dup();
    }
    return null;
}

pub fn initializeEvalFrameLocals(
    ctx: *core.Context,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    names: []const core.Atom,
    slots: []const core.Value,
) void {
    const count = @min(function.var_names.len, frame.locals.len);
    for (function.var_names[0..count], 0..) |atom_id, idx| {
        if (idx < function.var_is_lexical.len and function.var_is_lexical[idx]) continue;
        const value = lookupNamedRawSlotValue(ctx.runtime, names, slots, atom_id) orelse continue;
        const old_value = frame.locals[idx];
        frame.locals[idx] = value;
        old_value.free(ctx.runtime);
    }
}

pub fn setNamedSlotValue(ctx: *core.Context, names: []const core.Atom, slots: []core.Value, atom_id: core.Atom, value: core.Value) bool {
    for (names, 0..) |name, idx| {
        if (!atomIdOrNameEql(ctx.runtime, name, atom_id) or idx >= slots.len) continue;
        setSlotValue(ctx, &slots[idx], value);
        return true;
    }
    return false;
}

pub fn setFrameLocalValue(
    ctx: *core.Context,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    atom_id: core.Atom,
    value: core.Value,
) bool {
    const count = @min(function.var_names.len, frame.locals.len);
    for (function.var_names[0..count], 0..) |name, idx| {
        if (name != atom_id) continue;
        if (idx < function.var_is_lexical.len and function.var_is_lexical[idx]) continue;
        setSlotValue(ctx, &frame.locals[idx], value);
        return true;
    }
    return false;
}

pub fn setFrameVarRefValue(
    ctx: *core.Context,
    function: *const bytecode.Bytecode,
    frame: *frame_mod.Frame,
    atom_id: core.Atom,
    value: core.Value,
) !bool {
    for (function.var_ref_names, 0..) |name, idx| {
        if (name != atom_id) continue;
        if (idx >= frame.var_refs.len) try ensureVarRefsCapacity(ctx, frame, @intCast(idx));
        setSlotValue(ctx, &frame.var_refs[idx], value);
        return true;
    }
    return false;
}

pub fn setNamedVarRefValue(
    ctx: *core.Context,
    names: []const core.Atom,
    refs: []const core.Value,
    atom_id: core.Atom,
    value: core.Value,
    strict_assignment: bool,
    is_init: bool,
) !bool {
    for (names, 0..) |name, idx| {
        if (!atomIdOrNameEql(ctx.runtime, name, atom_id) or idx >= refs.len) continue;
        const slot = refs[idx];
        if (varRefCellFromValue(slot)) |cell| {
            if (cell.varRefIsConstSlot().* and !is_init) {
                value.free(ctx.runtime);
                if (cell.varRefIsFunctionNameSlot().* and !strict_assignment) return true;
                return error.TypeError;
            }
            const old_value = cell.varRefValueSlot().*;
            cell.varRefValueSlot().* = value;
            if (old_value) |stored| stored.free(ctx.runtime);
            return true;
        }
        return false;
    }
    return false;
}

pub fn defineValueProperty(rt: *core.Runtime, object: *core.Object, name: []const u8, value: core.Value) !void {
    const key = try rt.internAtom(name);
    defer rt.atoms.free(key);
    try object.defineOwnProperty(rt, key, core.Descriptor.data(value, true, true, true));
}

pub fn defineFunctionNameProperty(rt: *core.Runtime, object: *core.Object, value: core.Value) !void {
    if (objectHasNonEmptyName(rt, object)) return;
    const key = try rt.internAtom("name");
    defer rt.atoms.free(key);
    try object.defineOwnProperty(rt, key, core.Descriptor.data(value, false, false, true));
}

pub fn objectHasNonEmptyName(rt: *core.Runtime, object: *core.Object) bool {
    const existing = object.getOwnProperty(core.atom.ids.name) orelse return false;
    defer existing.destroy(rt);
    if (existing.kind != .data or !existing.value.isString()) return false;
    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(rt.memory.allocator);
    value_ops.appendRawString(rt, &bytes, existing.value) catch return false;
    return bytes.items.len != 0;
}

pub fn functionNameValueFromAtom(rt: *core.Runtime, atom_id: core.Atom, prefix: ?[]const u8) !core.Value {
    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(rt.memory.allocator);
    if (prefix) |text| {
        try bytes.appendSlice(rt.memory.allocator, text);
        try bytes.append(rt.memory.allocator, ' ');
    }
    if (core.atom.isTaggedInt(atom_id)) {
        var buf: [10]u8 = undefined;
        const text = try std.fmt.bufPrint(&buf, "{d}", .{core.atom.atomToUInt32(atom_id)});
        try bytes.appendSlice(rt.memory.allocator, text);
        return value_ops.createStringValue(rt, bytes.items);
    }
    const atom_name = rt.atoms.name(atom_id) orelse "";
    if (rt.atoms.kind(atom_id) == .symbol) {
        if (builtins.symbol.description(&rt.atoms, atom_id)) |description| {
            try bytes.append(rt.memory.allocator, '[');
            try bytes.appendSlice(rt.memory.allocator, description);
            try bytes.append(rt.memory.allocator, ']');
        }
    } else {
        try bytes.appendSlice(rt.memory.allocator, atom_name);
    }
    return value_ops.createStringValue(rt, bytes.items);
}

pub fn mappedArgumentsValue(rt: *core.Runtime, object: *core.Object, atom_id: core.Atom) ?core.Value {
    if (object.class_id != core.class.ids.mapped_arguments) return null;
    const index = core.array.arrayIndexFromAtom(&rt.atoms, atom_id) orelse return null;
    const refs = object.argumentsVarRefs();
    if (index >= refs.len) return null;
    if (refs[index].isUninitialized()) return null;
    if (!object.hasOwnProperty(atom_id)) return null;
    const cell = varRefCellFromValue(refs[index]) orelse return refs[index].dup();
    return if (cell.varRefValueSlot().*) |value| value.dup() else core.Value.undefinedValue();
}

pub fn setMappedArgumentsValue(ctx: *core.Context, object: *core.Object, atom_id: core.Atom, value: core.Value) bool {
    if (object.class_id != core.class.ids.mapped_arguments) return false;
    const index = core.array.arrayIndexFromAtom(&ctx.runtime.atoms, atom_id) orelse return false;
    const refs = object.argumentsVarRefsSlot();
    if (index >= refs.*.len) return false;
    if (refs.*[index].isUninitialized()) return false;
    if (!object.hasOwnProperty(atom_id)) {
        const old_value = refs.*[index];
        refs.*[index] = core.Value.uninitialized();
        old_value.free(ctx.runtime);
        return false;
    }
    if (varRefCellFromValue(refs.*[index])) |cell| {
        const next_value = value.dup();
        const old_value = cell.varRefValueSlot().*;
        cell.varRefValueSlot().* = next_value;
        if (old_value) |stored| stored.free(ctx.runtime);
        return true;
    }
    const next_value = value.dup();
    const old_value = refs.*[index];
    refs.*[index] = next_value;
    old_value.free(ctx.runtime);
    return true;
}

pub fn throwTypeErrorMessage(ctx: *core.Context, global: *core.Object, message: []const u8) !core.Value {
    const error_value = try createNamedError(ctx.runtime, global, "TypeError", message);
    var error_value_owned = true;
    errdefer if (error_value_owned) error_value.free(ctx.runtime);
    try attachStackToErrorValue(ctx, global, error_value);
    _ = ctx.throwValue(error_value);
    error_value_owned = false;
    return error.TypeError;
}

