fn attachStackToErrorValue(ctx: *core.Context, global: *core.Object, value: core.Value) !void {
    const object = property_ops.expectObject(value) catch return;
    try captureErrorStack(ctx, null, global, object);
}

pub fn qjsErrorCaptureStackTrace(
    ctx: *core.Context,
    output: ?*std.Io.Writer,
    global: *core.Object,
    args: []const core.Value,
) !core.Value {
    if (args.len < 1 or !args[0].isObject()) return throwTypeErrorMessage(ctx, global, "not an object");
    const target = try property_ops.expectObject(args[0]);
    const skip_name = if (args.len >= 2 and isCallableValue(args[1]))
        try exception_ops.functionNameBytes(ctx.runtime, args[1])
    else
        null;
    defer if (skip_name) |bytes| ctx.runtime.memory.allocator.free(bytes);
    const stack_value = try buildErrorStackValue(ctx, output, global, args[0], skip_name);
    defer stack_value.free(ctx.runtime);
    try defineDataProperty(ctx.runtime, target, "stack", stack_value, true, false, true);
    return core.Value.undefinedValue();
}

fn throwNullishPropertyTypeError(ctx: *core.Context, global: *core.Object, value: core.Value, atom_id: core.Atom) !core.Value {
    const property_name = try atomPropertyName(ctx.runtime, atom_id);
    defer ctx.runtime.memory.allocator.free(property_name);
    const base = if (value.isNull()) "null" else "undefined";
    const message = try std.fmt.allocPrint(
        ctx.runtime.memory.allocator,
        "cannot read property '{s}' of {s}",
        .{ property_name, base },
    );
    defer ctx.runtime.memory.allocator.free(message);
    return throwTypeErrorMessage(ctx, global, message);
}

pub fn throwNullishComputedPropertyTypeError(ctx: *core.Context, global: *core.Object, value: core.Value, key: core.Value) !core.Value {
    var property_name = std.ArrayList(u8).empty;
    defer property_name.deinit(ctx.runtime.memory.allocator);
    try value_ops.appendValueString(ctx.runtime, &property_name, key);
    const base = if (value.isNull()) "null" else "undefined";
    const message = try std.fmt.allocPrint(
        ctx.runtime.memory.allocator,
        "cannot read property '{s}' of {s}",
        .{ property_name.items, base },
    );
    defer ctx.runtime.memory.allocator.free(message);
    return throwTypeErrorMessage(ctx, global, message);
}

fn atomPropertyName(rt: *core.Runtime, atom_id: core.Atom) ![]const u8 {
    if (core.atom.isTaggedInt(atom_id)) {
        return try std.fmt.allocPrint(rt.memory.allocator, "{d}", .{core.atom.atomToUInt32(atom_id)});
    }
    const name = rt.atoms.name(atom_id) orelse "";
    return try rt.memory.allocator.dupe(u8, name);
}

pub fn ensureVarRefCell(ctx: *core.Context, slot: *core.Value) !core.Value {
    if (varRefCellFromValue(slot.*) != null) return slot.*.dup();
    const object = try core.Object.create(ctx.runtime, core.class.ids.object, null);
    errdefer core.Object.destroyFromHeader(ctx.runtime, &object.header);
    try object.initVarRefPayload(ctx.runtime, slot.*);
    slot.* = object.value();
    return slot.*.dup();
}

pub fn ensureLocalVarRefCell(ctx: *core.Context, frame: *frame_mod.Frame, idx: usize, is_lexical: bool) !core.Value {
    _ = is_lexical;
    if (idx < frame.locals_uninit.len and frame.localIsUninitialized(idx)) {
        if (varRefCellFromValue(frame.locals[idx])) |cell| {
            const old_value = cell.varRefValueSlot().*;
            cell.varRefValueSlot().* = core.Value.uninitialized();
            if (old_value) |stored| stored.free(ctx.runtime);
            return frame.locals[idx].dup();
        }
        const old_value = frame.locals[idx];
        frame.locals[idx] = core.Value.uninitialized();
        old_value.free(ctx.runtime);
    }
    return ensureVarRefCell(ctx, &frame.locals[idx]);
}

pub fn varRefCellFromValue(value: core.Value) ?*core.Object {
    if (!value.isObject()) return null;
    const header = value.refHeader() orelse return null;
    const object: *core.Object = @fieldParentPtr("header", header);
    if (object.class_payload_kind != .var_ref) return null;
    return object;
}

pub fn readInt(comptime T: type, bytes: []const u8) T {
    return std.mem.readInt(T, bytes[0..@sizeOf(T)], .little);
}
